  function localEvidenceModuleEntries() {
    return Object.entries(localEvidenceSummary?.modules ?? {});
  }

  function localEvidencePrimaryMetric(module: Record<string, unknown>) {
    if (typeof module.queueable_lesson_count === "number" || typeof module.queueable_attachment_count === "number") {
      const lessons = typeof module.queueable_lesson_count === "number" ? module.queueable_lesson_count : 0;
      const attachments = typeof module.queueable_attachment_count === "number" ? module.queueable_attachment_count : 0;
      return `queueable lessons: ${lessons} · attachments: ${attachments}`;
    }
    const preferredKeys = [
      "course_count",
      "item_count",
      "note_count",
      "track_count",
      "task_count",
      "cookie_bucket_count"
    ];
    for (const key of preferredKeys) {
      const value = module[key];
      if (typeof value === "number") {
        return `${key.replaceAll("_", " ")}: ${value}`;
      }
    }
    return "local evidence available";
  }

  function localEvidenceScope(module: Record<string, unknown>) {
    const scope = module.scope;
    return typeof scope === "string" ? scope : "Local metadata and implementation evidence summary.";
  }

