  async function handleSettingsChanged(event: SettingsChangedEvent) {
    syncAppearanceSettingsInputs(event.settings.appearance);
    syncDownloadsSettingsInputs(event.settings.downloads);
    syncAiSettingsInputs(event.settings.ai);
    syncAppShellSettingsInputs(event.settings.app_shell);
    syncAdvancedSettingsInputs(event.settings.advanced);
    maxConcurrencyInput = String(event.settings.downloads.max_concurrency);
    defaultOutputDirInput = event.settings.downloads.default_output_dir ?? "";
    organizeByPlatformInput = event.settings.downloads.organize_by_platform;
    filenameTemplateInput = event.settings.downloads.filename_template;
    skipExistingInput = event.settings.downloads.skip_existing;
    completedTaskCleanupInput = event.settings.downloads.completed_task_cleanup ?? "archive";
    archivedTaskRetentionDaysInput = event.settings.downloads.archived_task_retention_days
      ? String(event.settings.downloads.archived_task_retention_days)
      : "";
    defaultQualityInput = event.settings.downloads.default_quality;
    defaultAudioFormatInput = event.settings.downloads.default_audio_format;
    defaultUserAgentInput = event.settings.downloads.default_user_agent ?? "";
    defaultRefererInput = event.settings.downloads.default_referer ?? "";
    defaultProxyInput = event.settings.downloads.default_proxy ?? "";
    defaultRateLimitInput = event.settings.downloads.default_rate_limit ?? "";
    defaultLiveFromStartInput = event.settings.downloads.default_live_from_start;
    defaultConcurrentFragmentsInput = event.settings.downloads.default_concurrent_fragments
      ? String(event.settings.downloads.default_concurrent_fragments)
      : "";
    customYtdlpArgsInput = event.settings.downloads.custom_ytdlp_args ?? "";
    subtitleLanguagesInput = event.settings.downloads.subtitles.languages.join(", ");
    subtitleAutoInput = event.settings.downloads.subtitles.auto;
    subtitleEmbedInput = event.settings.downloads.subtitles.embed;
    subtitleKeepVttInput = event.settings.downloads.subtitles.keep_vtt;
    sponsorBlockEnabledInput = event.settings.downloads.sponsorblock.enabled;
    sponsorBlockCategoriesInput = event.settings.downloads.sponsorblock.categories.join(", ");
    embedMetadataInput = event.settings.downloads.metadata.embed_metadata;
    embedThumbnailInput = event.settings.downloads.metadata.embed_thumbnail;
    splitChaptersInput = event.settings.downloads.metadata.split_chapters;
    syncHomeTaskDefaultsFromDownloads(event.settings.downloads);

    const paths = new Set(event.changed_paths.map((path) => path.toLowerCase()));
    if (paths.has("auth") || paths.has("twitter_x_auth")) {
      await loadAuthSettings();
    }
    if (paths.has("update")) {
      await loadUpdateSettings();
    }
    if (paths.has("extension")) {
      await loadExtensionPairingStatus();
    }
    if (paths.has("channels")) {
      await loadChannels();
    }
    if (paths.has("dependencies") || paths.has("tools")) {
      await loadToolStatuses();
    }
    if (paths.has("reader") || paths.has("library")) {
      await loadLibraryReaderSettings();
    }
    if (paths.has("music") || Array.from(paths).some((path) => path.startsWith("music_"))) {
      await loadMusicState();
    }
    if (paths.has("appearance")) {
      await loadAppearanceThemeCatalog();
      await loadAppearanceLanguageCatalog();
    }
  }

  async function loadDownloadsSettings() {
    try {
      const settings = await getSettings();
      if (settings?.appearance) {
        syncAppearanceSettingsInputs(settings.appearance);
      } else {
        appearanceSettings = null;
      }
      if (settings?.downloads) {
        syncDownloadsSettingsInputs(settings.downloads);
      } else {
        downloadsSettings = null;
      }
      if (settings?.ai) {
        syncAiSettingsInputs(settings.ai);
      } else {
        aiSettings = null;
      }
      syncAppShellSettingsInputs(settings?.app_shell ?? null);
      syncAdvancedSettingsInputs(settings?.advanced ?? null);
      appearanceSettingsError = "";
      downloadsSettingsError = "";
      aiSettingsError = "";
      advancedSettingsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      appearanceSettingsError = message;
      downloadsSettingsError = message;
      aiSettingsError = message;
      advancedSettingsError = message;
    }
  }

