  async function queuePlatformRouteSamples(
    samples: Array<{ label: string; url: string; classification: UrlCandidateClassification | null }>,
    busyKey = "shown"
  ) {
    const queueableSamples = samples.filter((sample) => sample.classification);
    if (queueableSamples.length === 0) {
      pushToast(createToast("No route samples", "error", "No classified route samples are available to queue."));
      return;
    }

    await maybeAutoSelectToolsCookieBucket(queueableSamples[0].url);
    maybeAutoSelectToolsAuthorizationPayload(queueableSamples[0].url);
    platformRouteSampleQueueBusy = busyKey;
    try {
      const result = await createDownloadTaskItems(
        queueableSamples.map((sample) => ({
          sourceUrl: sample.url,
          titleOverride: sample.label,
          options: buildToolsCreateOptions(platformRouteSampleTaskKind(sample.classification))
        }))
      );
      if (result) {
        downloads = [...result.created, ...downloads.filter((task) => !result.created.some((item) => item.id === task.id))].sort(
          (first, second) => first.position - second.position
        );
        const failedMessage = result.failed.length > 0 ? `, ${result.failed.length} failed` : "";
        pushToast(createToast("Route samples queued", "success", `${result.created.length} created${failedMessage}`, firstTaskToastAction(result.created)));
      }
    } catch (error) {
      pushToast(createToast("Route sample queue failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      platformRouteSampleQueueBusy = "";
    }
  }

