  function syncCookieBuckets(nextBuckets: CookieBucket[]) {
    cookieBuckets = nextBuckets;
    cookieRenameInputs = Object.fromEntries(cookieBuckets.map((bucket) => [bucket.id, bucket.name]));
    cookieExportPathInputs = Object.fromEntries(
      cookieBuckets.map((bucket) => [bucket.id, `${bucket.name || bucket.id}.cookies.txt`])
    );
    const availableIds = new Set(cookieBuckets.map((bucket) => bucket.id));
    cookieSelectedIds = cookieSelectedIds.filter((id) => availableIds.has(id));
    cookieMatchedBuckets = cookieMatchedBuckets.filter((bucket) => availableIds.has(bucket.id));
    if (taskCookieBucketId && !availableIds.has(taskCookieBucketId)) {
      clearTaskCookieBucketSelection();
    }
    if (toolsCookieBucketId && !availableIds.has(toolsCookieBucketId)) {
      clearToolsCookieBucketSelection();
    }
  }

  async function handleCookieBucketsChanged(event: CookieBucketsChangedEvent) {
    syncCookieBuckets(event.buckets);
    await Promise.all([loadBilibiliImports(), refreshCookieAuthLocalSummary(false)]);
  }

  function syncExtensionPayloads(event: ExtensionPayloadsChangedEvent) {
    extensionCookiePayloads = event.cookie_payloads;
    extensionAuthPayloads = event.authorization_payloads;
    const cookieRefs = new Set(extensionCookiePayloads.map((payload) => payload.payload_ref));
    const authorizationRefs = new Set(extensionAuthPayloads.map((payload) => payload.payload_ref));
    if (cookieExtensionPayloadRef && !cookieRefs.has(cookieExtensionPayloadRef)) {
      cookieExtensionPayloadRef = "";
    }
    if (taskAuthPayloadRef && !authorizationRefs.has(taskAuthPayloadRef)) {
      clearTaskAuthorizationPayloadSelection();
    }
    if (toolsAuthPayloadRef && !authorizationRefs.has(toolsAuthPayloadRef)) {
      clearToolsAuthorizationPayloadSelection();
    }
  }

  function handleExtensionPayloadsChanged(event: ExtensionPayloadsChangedEvent) {
    syncExtensionPayloads(event);
    void refreshCookieAuthLocalSummary(false);
  }

  function handleExtensionPairingChanged(event: ExtensionPairingChangedEvent) {
    extensionPairingStatus = event.status;
    if (!event.status.token_required) {
      extensionPairingToken = null;
    }
  }

