  async function importAuthSettingsBackup() {
    const inputPath = authSettingsImportPath.trim();
    if (!inputPath) {
      cookieBucketsError = "Choose an auth settings JSON backup first.";
      pushToast(createToast("Auth settings backup missing", "error", cookieBucketsError));
      return;
    }

    authSettingsTransferBusy = "import";
    cookieBucketsError = "";
    try {
      const result = await importAuthSettings(inputPath);
      authSettingsImportResult = result;
      if (result?.settings) {
        authSettings = result.settings;
        twitterManualCookieEnabled = result.settings.twitter_x.manual_cookie_header_enabled;
      }
      twitterManualCookieHeaderInput = "";
      await refreshCookieAuthLocalSummary(false);
      const skipped = result?.skipped_secret_count ? ` · ${result.skipped_secret_count} secret value skipped` : "";
      pushToast(createToast(
        "Auth settings imported",
        "success",
        result ? `${result.imported_setting_count} public settings${skipped}` : "Safe settings restored",
        targetToastAction("Open", "cookies", { query: "Twitter/X" })
