  async function importCoursePlatformSample(sample: CoursePlatformSample) {
    coursePlatformSampleBusy = sample.platform_id;
    try {
      const course = await importCourse(sample.url, sample.title_hint, courseImportCookieBucketId || undefined);
      if (course) {
        courses = [course, ...courses.filter((item) => item.id !== course.id)];
        courseCookieBucketInputs = { ...courseCookieBucketInputs, [course.id]: course.cookie_bucket_id ?? "" };
        pushToast(createToast("Course sample imported", "success", `${sample.label} saved as a local candidate.`, targetToastAction("Open", "courses", { course_id: course.id })));
      }
    } catch (error) {
      pushToast(createToast("Course sample import failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      coursePlatformSampleBusy = "";
    }
  }

  async function importShownCoursePlatformSamples() {
    const samples = filteredCoursePlatformSamples;
    if (samples.length === 0) {
      pushToast(createToast("No course samples", "error", "No course platform samples match the current filter."));
      return;
    }

    coursePlatformSampleBusy = "import-shown";
    let imported = 0;
    let failed = 0;
    try {
      for (const sample of samples) {
        try {
          const course = await importCourse(sample.url, sample.title_hint, courseImportCookieBucketId || undefined);
          if (course) {
            courses = [course, ...courses.filter((item) => item.id !== course.id)];
            courseCookieBucketInputs = { ...courseCookieBucketInputs, [course.id]: course.cookie_bucket_id ?? "" };
            imported += 1;
          }
        } catch {
          failed += 1;
        }
      }
      const failedMessage = failed > 0 ? `, ${failed} failed` : "";
      pushToast(createToast("Course samples imported", "success", `${imported} local candidate${imported === 1 ? "" : "s"} saved${failedMessage}.`, targetToastAction("Open", "courses", { query: "sample" })));
    } finally {
      coursePlatformSampleBusy = "";
    }
  }

