  function navigate(route: AppRoute) {
    currentRoute = route;
    persistRoute(route);
    commandOpen = false;
    commandQuery = "";
  }

  function openChannelNotifications() {
    navigate("channels");
    channelHistoryStatusFilter = "pending";
    channelHistoryExpanded = true;
  }

  function normalizeShellOpenParam(params: Record<string, string> | undefined, keys: string[]): string {
    if (!params) {
      return "";
    }
    for (const key of keys) {
      const value = params[key]?.trim();
      if (value) {
        return value;
      }
    }
    return "";
  }

  type ShellOpenRoute =
    | RouteId
    | "advanced"
    | "bilibili"
    | "cookies"
    | "extension"
    | "library"
    | "music"
    | "p2p";

  function isShellOpenRoute(value: string): value is ShellOpenRoute {
    return isRouteId(value) || ["advanced", "bilibili", "cookies", "extension", "library", "music", "p2p"].includes(value);
  }

  function routeForShellOpen(route: ShellOpenRoute): AppRoute {
    switch (route) {
      case "advanced":
      case "bilibili":
      case "cookies":
      case "extension":
        return "settings";
      case "library":
      case "music":
      case "p2p":
        return "tools";
      default:
        return route;
    }
  }

  function handleShellOpenTarget(target: ShellOpenRequest["target"] | null | undefined): boolean {
    const route = target?.route?.trim();
    if (!route || !isShellOpenRoute(route)) {
      return false;
    }

    const params = target?.params ?? {};
    commandOpen = false;
    navigate(routeForShellOpen(route));

    if (route === "downloads") {
      const taskId = normalizeShellOpenParam(params, ["task_id", "task", "id"]);
      if (taskId) {
        void focusDownloadTaskById(taskId, "Deep link task");
        return true;
      }

      const view = normalizeDownloadViewMode(normalizeShellOpenParam(params, ["view", "view_mode", "mode"]));
      const status = normalizeDownloadStatusFilter(normalizeShellOpenParam(params, ["status", "filter"]));
      const kind = normalizeDownloadKindFilter(normalizeShellOpenParam(params, ["kind", "type"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      const platform = normalizeShellOpenParam(params, ["platform"]);
      if (view) {
        downloadViewMode = view;
      }
      if (status) {
        downloadStatusFilter = status;
        if (!view) {
          downloadViewMode = status === "archived" ? "history" : "active";
        }
      }
      if (kind) {
        downloadKindFilter = kind;
      }
      if (platform) {
        downloadPlatformFilter = platform;
      }
      if (query) {
        downloadSearchQuery = query;
      }
      pushToast(createToast("Downloads opened", "success", query || status || kind || platform || view || "Deep link route"));
      return true;
    }

    if (route === "channels") {
      const status = normalizeShellOpenParam(params, ["status", "notification_status", "filter"]);
      const query = normalizeShellOpenParam(params, ["query", "q", "search", "history_id"]);
      if (status) {
        channelHistoryStatusFilter = normalizeChannelHistoryStatus(status);
      }
      if (query) {
        channelHistorySearch = query;
      }
      if (status || query) {
        channelHistoryExpanded = true;
      }
      pushToast(createToast("Channels opened", "success", query || status || "Deep link route"));
      return true;
    }

    if (route === "courses") {
      const courseId = normalizeShellOpenParam(params, ["course_id", "course"]);
      const lessonId = normalizeShellOpenParam(params, ["lesson_id", "lesson"]);
      const attachmentId = normalizeShellOpenParam(params, ["attachment_id", "attachment"]);
      const taskId = normalizeShellOpenParam(params, ["task_id", "task"]);
      const query = normalizeShellOpenParam(params, ["query", "q", "search", "id"]);
      focusCoursesTarget({ courseId, lessonId, attachmentId, taskId, query });
      pushToast(createToast("Courses opened", "success", lessonId || attachmentId || courseId || taskId || query || "Deep link route"));
      return true;
    }

    if (route === "telegram") {
      const chatId = normalizeShellOpenParam(params, ["chat_id", "chat"]);
      const mediaId = normalizeShellOpenParam(params, ["media_id", "media"]);
      const taskId = normalizeShellOpenParam(params, ["task_id", "task"]);
      const query = normalizeShellOpenParam(params, ["query", "q", "search", "id"]);
      const mediaType = normalizeTelegramMediaType(normalizeShellOpenParam(params, ["media_type", "type", "kind"]));
      focusTelegramTarget({ chatId, mediaId, taskId, query, mediaType });
      pushToast(createToast("Telegram opened", "success", mediaId || chatId || taskId || query || mediaType || "Deep link route"));
      return true;
    }

    if (route === "plugins") {
      const pluginId = normalizeShellOpenParam(params, ["plugin_id", "plugin", "id"]);
      const state = normalizePluginStateFilter(normalizeShellOpenParam(params, ["state", "status", "filter"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      const marketplaceId = normalizeShellOpenParam(params, ["marketplace_id", "marketplace"]);
      focusPluginTarget({ pluginId, state, query, marketplaceId });
      pushToast(createToast("Plugins opened", "success", pluginId || marketplaceId || state || query || "Deep link route"));
      return true;
    }

    if (route === "bilibili") {
      const itemId = normalizeShellOpenParam(params, ["item_id", "item", "id"]);
      const taskId = normalizeShellOpenParam(params, ["task_id", "task"]);
      const collection = normalizeBilibiliCollection(normalizeShellOpenParam(params, ["collection", "list", "filter"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusBilibiliTarget({ itemId, taskId, collection, query });
      pushToast(createToast("Bilibili opened", "success", itemId || taskId || collection || query || "Deep link route"));
      return true;
    }

    if (route === "library") {
      const itemId = normalizeShellOpenParam(params, ["item_id", "item", "id"]);
      const format = normalizeLibraryFormatFilter(normalizeShellOpenParam(params, ["format", "type", "kind"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      const annotation = normalizeShellOpenParam(params, ["annotation_id", "annotation", "bookmark_id", "highlight_id"]);
      focusLibraryTarget({ itemId, format, query, annotation });
      pushToast(createToast("Library opened", "success", itemId || annotation || format || query || "Deep link route"));
      return true;
    }

    if (route === "music") {
      const trackId = normalizeShellOpenParam(params, ["track_id", "track", "id"]);
      const playlistId = normalizeShellOpenParam(params, ["playlist_id", "playlist"]);
      const format = normalizeMusicFormatFilter(normalizeShellOpenParam(params, ["format", "type", "kind"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusMusicTarget({ trackId, playlistId, format, query });
      pushToast(createToast("Music opened", "success", trackId || playlistId || format || query || "Deep link route"));
      return true;
    }

    if (route === "p2p") {
      const code = normalizeShellOpenParam(params, ["code", "short_code", "offer_id", "offer"]);
      const taskId = normalizeShellOpenParam(params, ["task_id", "task", "id"]);
      const status = normalizeP2pOfferStatus(normalizeShellOpenParam(params, ["status", "filter"]));
      const kind = normalizeTorrentP2pKind(normalizeShellOpenParam(params, ["kind", "type"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusP2pTarget({ code, taskId, status, kind, query });
      pushToast(createToast("Torrent/P2P opened", "success", code || taskId || status || kind || query || "Deep link route"));
      return true;
    }

    if (route === "cookies") {
      const bucketId = normalizeShellOpenParam(params, ["bucket_id", "bucket", "id"]);
      const health = normalizeCookieHealthFilter(normalizeShellOpenParam(params, ["health", "status", "filter"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusCookieTarget({ bucketId, health, query });
      pushToast(createToast("Cookies opened", "success", bucketId || health || query || "Deep link route"));
      return true;
    }

    if (route === "extension") {
      const payloadRef = normalizeShellOpenParam(params, ["payload_ref", "payload", "id"]);
      const kind = normalizeExtensionPayloadKind(normalizeShellOpenParam(params, ["kind", "type"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusExtensionTarget({ payloadRef, kind, query });
      pushToast(createToast("Extension opened", "success", payloadRef || kind || query || "Deep link route"));
      return true;
    }

    if (route === "advanced") {
      const file = normalizeShellOpenParam(params, ["file", "file_name", "path", "id"]);
      const kind = normalizeAdvancedFileKind(normalizeShellOpenParam(params, ["kind", "type", "filter"]));
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      focusAdvancedTarget({ file, kind, query });
      pushToast(createToast("Advanced opened", "success", file || kind || query || "Deep link route"));
      return true;
    }

    if (route === "settings") {
      const section = normalizeSettingsSection(normalizeShellOpenParam(params, ["section", "panel", "id"]));
      if (section) {
        void tick().then(() => focusSettingsSection(section));
      }
      pushToast(createToast("Settings opened", "success", section || "Deep link route"));
      return true;
    }

    if (route === "learning") {
      const sessionId = normalizeShellOpenParam(params, ["session_id", "session", "id"]);
      const query = normalizeShellOpenParam(params, ["query", "q", "search"]);
      if (sessionId || query) {
        pomodoroSessionSearch = sessionId || query;
        pomodoroSessionStatusFilter = "all";
        pomodoroSessionsExpanded = true;
      }
      pushToast(createToast("Learning opened", "success", sessionId || query || "Deep link route"));
      return true;
    }

    pushToast(createToast("Route opened", "success", route));
    return true;
  }

  function actionFromToastCommand(action: ToastAction | null | undefined): ToastMessage["action"] | undefined {
    if (!action?.command) {
      return undefined;
    }

    const command = action.command.trim();
    const target = toastCommandTarget(command);
    if (target) {
      return { label: action.label, onClick: () => handleShellOpenTarget(target) };
    }

    const route = command.startsWith("route:") ? command.slice("route:".length) : command;
    if (isRouteId(route)) {
      return { label: action.label, onClick: () => navigate(route) };
    }

    return undefined;
  }

  function targetToastAction(
    label: string,
    route: ShellOpenRoute,
    params: Record<string, string>
  ): ToastMessage["action"] {
    const cleanParams = Object.fromEntries(
      Object.entries(params)
        .map(([key, value]) => [key, value.trim()])
        .filter(([, value]) => value)
    );
    return {
      label,
      onClick: () => handleShellOpenTarget({ route, params: cleanParams })
    };
  }

  function advancedFileToastAction(path: string | null | undefined): ToastMessage["action"] | undefined {
    return path ? targetToastAction("Open", "advanced", { file: path }) : undefined;
  }

  function firstTaskToastAction(tasks: DownloadTask[] | null | undefined): ToastMessage["action"] | undefined {
    return tasks?.[0] ? targetToastAction("Task", "downloads", { task_id: tasks[0].id }) : undefined;
  }

  function downloadTaskToastAction(task: DownloadTask | null | undefined, label = "Task"): ToastMessage["action"] | undefined {
    return task ? targetToastAction(label, "downloads", { task_id: task.id }) : undefined;
  }

  function p2pOfferToastAction(offerOrCode: Pick<P2pOffer, "short_code"> | string | null | undefined): ToastMessage["action"] | undefined {
    const code = typeof offerOrCode === "string" ? offerOrCode : offerOrCode?.short_code;
    return code ? targetToastAction("Open", "p2p", { code }) : undefined;
  }

  function pluginToastAction(pluginOrId: Pick<PluginInfo, "id"> | string | null | undefined): ToastMessage["action"] | undefined {
    const pluginId = typeof pluginOrId === "string" ? pluginOrId : pluginOrId?.id;
    return pluginId ? targetToastAction("Open", "plugins", { plugin_id: pluginId, panel: "management" }) : undefined;
  }

  function settingsSectionToastAction(section: string, label = "Open"): ToastMessage["action"] | undefined {
    return section ? targetToastAction(label, "settings", { section }) : undefined;
  }

  function libraryItemToastAction(itemOrPath: Pick<LibraryItem, "path"> | string | null | undefined): ToastMessage["action"] | undefined {
    const path = typeof itemOrPath === "string" ? itemOrPath : itemOrPath?.path;
    return path ? targetToastAction("Open", "library", { item_id: path }) : undefined;
  }

  function musicTrackToastAction(trackOrPath: Pick<MusicTrack, "path"> | string | null | undefined): ToastMessage["action"] | undefined {
    const path = typeof trackOrPath === "string" ? trackOrPath : trackOrPath?.path;
    return path ? targetToastAction("Open", "music", { track_id: path }) : undefined;
  }

  function learningNoteToastAction(noteOrId: Pick<LearningNote, "id"> | string | null | undefined): ToastMessage["action"] | undefined {
    const noteId = typeof noteOrId === "string" ? noteOrId : noteOrId?.id;
    return noteId ? targetToastAction("Open", "learning", { query: noteId }) : undefined;
  }

  function courseToastAction(courseOrId: Pick<CourseEntry, "id"> | string | null | undefined): ToastMessage["action"] | undefined {
    const courseId = typeof courseOrId === "string" ? courseOrId : courseOrId?.id;
    return courseId ? targetToastAction("Open", "courses", { course_id: courseId }) : undefined;
  }

  function toastCommandTarget(command: string): ShellOpenRequest["target"] | null {
    const trimmed = command.trim();
    if (!trimmed) {
      return null;
    }

    const [head, query = ""] = trimmed.split("?", 2);
    const params = Object.fromEntries(new URLSearchParams(query).entries());
    const parts = head.split(":").map((part) => part.trim()).filter(Boolean);
    const route = parts[0] === "route" ? parts[1] : parts[0];
    const value = parts[0] === "route" ? parts[2] : parts[1];
    if (!route || !isShellOpenRoute(route)) {
      return null;
    }

    if (route === "downloads" && value) {
      if (normalizeDownloadStatusFilter(value)) {
        params.status = value;
      } else {
        params.task_id = value;
      }
    }

    if (route === "channels" && value) {
      if (normalizeChannelHistoryStatus(value) === "all" && value.toLowerCase() !== "all") {
        params.history_id = value;
      } else {
        params.status = value;
      }
    }

    if (route === "settings" && value) {
      params.section = value;
    }

    if (route === "learning" && value) {
      params.session_id = value;
    }

    if (route === "courses" && value) {
      params.id = value;
    }

    if (route === "telegram" && value) {
      params.id = value;
    }

    if (route === "plugins" && value) {
      if (normalizePluginStateFilter(value)) {
        params.state = value;
      } else {
        params.plugin_id = value;
      }
    }

    if (route === "bilibili" && value) {
      if (normalizeBilibiliCollection(value)) {
        params.collection = value;
      } else {
        params.item_id = value;
      }
    }

    if (route === "library" && value) {
      if (normalizeLibraryFormatFilter(value)) {
        params.format = value;
      } else {
        params.item_id = value;
      }
    }

    if (route === "music" && value) {
      if (normalizeMusicFormatFilter(value)) {
        params.format = value;
      } else {
        params.track_id = value;
      }
    }

    if (route === "p2p" && value) {
      if (normalizeP2pOfferStatus(value)) {
        params.status = value;
      } else if (normalizeTorrentP2pKind(value)) {
        params.kind = value;
      } else {
        params.code = value;
      }
    }

    if (route === "cookies" && value) {
      if (normalizeCookieHealthFilter(value)) {
        params.health = value;
      } else {
        params.bucket_id = value;
      }
    }

    if (route === "extension" && value) {
      if (normalizeExtensionPayloadKind(value)) {
        params.kind = value;
      } else {
        params.payload_ref = value;
      }
    }

    if (route === "advanced" && value) {
      if (normalizeAdvancedFileKind(value)) {
        params.kind = value;
      } else {
        params.file = value;
      }
    }

    return { route, params };
  }

  function restoreStoredRoute(): AppRoute {
    const storedRoute = window.localStorage.getItem(ROUTE_STORAGE_KEY) ?? "";
    if (isRouteId(storedRoute)) {
      return storedRoute;
    }
    return "home";
  }

  function persistRoute(route: AppRoute) {
    if (isRouteId(route)) {
      window.localStorage.setItem(ROUTE_STORAGE_KEY, route);
    }
  }

  function readStoredDownloadFilterPresets(): DownloadFilterPreset[] {
    try {
      const raw = window.localStorage.getItem(DOWNLOAD_FILTER_PRESETS_STORAGE_KEY);
      if (!raw) {
        return [];
      }
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) {
        return [];
      }
      return parsed
        .map((item) => normalizeDownloadFilterPresetRecord(item))
        .filter((item): item is DownloadFilterPreset => Boolean(item))
        .slice(0, 12);
    } catch {
      return [];
    }
  }

  function normalizeDownloadFilterPresetRecord(item: unknown): DownloadFilterPreset | null {
    if (!item || typeof item !== "object") {
      return null;
    }
    const record = item as Record<string, unknown>;
    const status = normalizeDownloadStatusFilter(String(record.status ?? "all")) || "all";
    const kind = normalizeDownloadKindFilter(String(record.kind ?? "all")) || "all";
    const operationalValue = record.operational;
    const operational = downloadOperationalFilters.some((option) => option.id === operationalValue)
      ? (operationalValue as DownloadOperationalFilter)
      : "all";
    const rawSortMode = record.sortMode ?? record.sort_mode;
    const sortMode = downloadSortModes.some((option) => option.id === rawSortMode)
      ? (rawSortMode as DownloadSortMode)
      : "queue";
    const rawViewMode = record.viewMode ?? record.view_mode;
    const viewMode = rawViewMode === "all" ? "all" : rawViewMode === "history" ? "history" : "active";
    const id = String(record.id ?? "").trim() || `preset-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const name = String(record.name ?? "").trim();
    if (!name) {
      return null;
    }

    const rawDateField = record.dateField ?? record.date_field;
    return {
      id,
      name,
      viewMode,
      status,
      kind,
      platform: String(record.platform ?? "all").trim() || "all",
      operational,
      query: String(record.query ?? ""),
      dateField: rawDateField === "updated" ? "updated" : "created",
      dateFrom: String(record.dateFrom ?? record.date_from ?? ""),
      dateTo: String(record.dateTo ?? record.date_to ?? ""),
      sortMode
    };
  }

  function persistDownloadFilterPresets(presets: DownloadFilterPreset[]) {
    downloadFilterPresets = presets.slice(0, 12);
    window.localStorage.setItem(DOWNLOAD_FILTER_PRESETS_STORAGE_KEY, JSON.stringify(downloadFilterPresets));
  }

  function currentDownloadFilterPreset(name: string): DownloadFilterPreset {
    return {
      id: `download-filter-${Date.now()}`,
      name,
      viewMode: downloadViewMode,
      status: downloadStatusFilter,
      kind: downloadKindFilter,
      platform: downloadPlatformFilter,
      operational: downloadOperationalFilter,
      query: downloadSearchQuery,
      dateField: downloadDateField,
      dateFrom: downloadDateFrom,
      dateTo: downloadDateTo,
      sortMode: downloadSortMode
    };
  }

  function saveCurrentDownloadFilterPreset() {
    const name = downloadFilterPresetName.trim();
    if (!name) {
      pushToast(createToast("Preset name required", "error", "Name the current download filter before saving."));
      return;
    }

    const preset = currentDownloadFilterPreset(name);
    const normalizedName = name.toLowerCase();
    const nextPresets = [
      preset,
      ...downloadFilterPresets.filter((item) => item.name.trim().toLowerCase() !== normalizedName)
    ].slice(0, 12);
    persistDownloadFilterPresets(nextPresets);
    downloadFilterPresetName = "";
    downloadFilterPresetSelection = preset.id;
    pushToast(createToast("Download filter saved", "success", name, targetToastAction("Open", "downloads", { query: name })));
  }

  function applyDownloadFilterPreset(id: string) {
    const preset = downloadFilterPresets.find((item) => item.id === id);
    if (!preset) {
      downloadFilterPresetSelection = "";
      return;
    }

    downloadViewMode = preset.viewMode;
    downloadStatusFilter = preset.status;
    downloadKindFilter = preset.kind;
    downloadPlatformFilter = downloadPlatformOptions.some((option) => option.id === preset.platform) ? preset.platform : "all";
    downloadOperationalFilter = preset.operational;
    downloadSearchQuery = preset.query;
    downloadDateField = preset.dateField;
    downloadDateFrom = preset.dateFrom;
    downloadDateTo = preset.dateTo;
    downloadSortMode = preset.sortMode;
    downloadFilterPresetSelection = preset.id;
    pushToast(createToast("Download filter applied", "success", preset.name, targetToastAction("Open", "downloads", { query: preset.query || preset.status })));
  }

  function deleteSelectedDownloadFilterPreset() {
    const preset = downloadFilterPresets.find((item) => item.id === downloadFilterPresetSelection);
    if (!preset) {
      return;
    }
    persistDownloadFilterPresets(downloadFilterPresets.filter((item) => item.id !== preset.id));
    downloadFilterPresetSelection = "";
    pushToast(createToast("Download filter removed", "success", preset.name));
  }

  function clearDownloadFilters() {
    downloadStatusFilter = "all";
    downloadViewMode = "active";
    downloadKindFilter = "all";
    downloadPlatformFilter = "all";
    downloadOperationalFilter = "all";
    downloadSearchQuery = "";
    downloadDateField = "created";
    downloadDateFrom = "";
    downloadDateTo = "";
    downloadFilterPresetSelection = "";
  }

  function focusDownloadStatus(status: DownloadStatusFilter, query = "") {
    downloadViewMode = ["completed", "failed", "canceled", "archived"].includes(status) ? "history" : "active";
    downloadStatusFilter = status;
    downloadKindFilter = "all";
    downloadPlatformFilter = "all";
    downloadOperationalFilter = "all";
    downloadSearchQuery = query;
    downloadDateField = "created";
    downloadDateFrom = "";
    downloadDateTo = "";
    downloadSortMode = status === "active" ? "updated_desc" : "queue";
    downloadFilterPresetSelection = "";
  }

  function focusDownloadOperationalFilter(operational: DownloadOperationalFilter) {
    downloadViewMode = "active";
    downloadStatusFilter = "all";
    downloadKindFilter = "all";
    downloadPlatformFilter = "all";
    downloadOperationalFilter = operational;
    downloadSearchQuery = "";
    downloadDateField = "created";
    downloadDateFrom = "";
    downloadDateTo = "";
    downloadSortMode = operational === "with_output" ? "updated_desc" : "queue";
    downloadFilterPresetSelection = "";
  }

  async function copyVisibleDownloadFields(
    kind:
      | "source"
      | "output"
      | "output-dir"
      | "id"
      | "title"
      | "status"
      | "kind"
      | "platform"
      | "progress"
      | "downloaded"
      | "size"
      | "speed"
      | "eta"
      | "files"
      | "error"
      | "error-category"
      | "retry"
      | "cookie"
      | "auth"
      | "thumbnail-url"
      | "thumbnail-path"
      | "user-agent"
      | "referer"
      | "proxy"
      | "rate-limit"
      | "live"
      | "slot"
      | "fragments"
      | "custom-args"
      | "clip"
      | "quality"
      | "audio-format"
      | "subtitles"
      | "sponsorblock"
      | "metadata"
      | "integrity"
      | "started"
      | "finished"
      | "created"
      | "updated"
  ) {
    const values =
      kind === "source"
        ? filteredDownloads.map((task) => task.source_url)
        : kind === "output"
          ? filteredDownloads.map((task) => task.output_path ?? task.output_dir ?? "")
          : kind === "output-dir"
            ? filteredDownloads.map((task) => task.output_dir ?? "")
            : kind === "id"
              ? filteredDownloads.map((task) => task.id)
              : kind === "title"
                ? filteredDownloads.map((task) => task.title)
                : kind === "status"
                  ? filteredDownloads.map((task) => `${task.title}: ${task.status}`)
                  : kind === "kind"
                    ? filteredDownloads.map((task) => `${task.title}: ${task.kind}`)
                    : kind === "platform"
                      ? filteredDownloads.map((task) => `${task.title}: ${task.platform}`)
                      : kind === "progress"
                        ? filteredDownloads.map((task) => `${task.title}: ${formatProgress(task)}`)
                        : kind === "downloaded"
                          ? filteredDownloads.map((task) => task.downloaded_bytes ? `${task.title}: ${formatBytes(task.downloaded_bytes)}` : "")
                          : kind === "size"
                            ? filteredDownloads.map((task) => task.total_bytes ? `${task.title}: ${formatBytes(task.total_bytes)}` : "")
                            : kind === "speed"
                              ? filteredDownloads.map((task) => task.speed_bytes_per_sec ? `${task.title}: ${formatBytes(task.speed_bytes_per_sec)}/s` : "")
                              : kind === "eta"
                                ? filteredDownloads.map((task) => task.eta_seconds ? `${task.title}: ${formatEta(task.eta_seconds)}` : "")
                                : kind === "files"
                                  ? filteredDownloads.map((task) => task.file_count ? `${task.title}: ${task.file_count} file${task.file_count === 1 ? "" : "s"}` : "")
                                  : kind === "error"
                                    ? filteredDownloads.map((task) => task.last_error ? `${task.title}: ${task.last_error}` : "")
                                    : kind === "error-category"
                                      ? filteredDownloads.map((task) => task.error_category ? `${task.title}: ${task.error_category}` : "")
                                      : kind === "retry"
                                        ? filteredDownloads.map((task) => `${task.title}: ${task.retry_count}${task.retryable === null || task.retryable === undefined ? "" : ` (${task.retryable ? "retryable" : "not retryable"})`}`)
                                        : kind === "cookie"
                                          ? filteredDownloads.map((task) => task.cookie_bucket_id ? `${task.title}: ${task.cookie_bucket_id}` : "")
                                          : kind === "auth"
                                            ? filteredDownloads.map((task) => task.auth_payload_ref ? `${task.title}: ${task.auth_payload_ref}` : "")
                                            : kind === "thumbnail-url"
                                              ? filteredDownloads.map((task) => task.thumbnail_url ?? "")
                                              : kind === "thumbnail-path"
                                                ? filteredDownloads.map((task) => task.thumbnail_path ?? "")
                                                : kind === "user-agent"
                                                  ? filteredDownloads.map((task) => task.user_agent ? `${task.title}: ${task.user_agent}` : "")
                                                  : kind === "referer"
                                                    ? filteredDownloads.map((task) => task.referer ? `${task.title}: ${task.referer}` : "")
                                                    : kind === "proxy"
                                                      ? filteredDownloads.map((task) => task.proxy ? `${task.title}: ${task.proxy}` : "")
                                                      : kind === "rate-limit"
                                                        ? filteredDownloads.map((task) => task.rate_limit ? `${task.title}: ${task.rate_limit}` : "")
                                                        : kind === "live"
                                                          ? filteredDownloads.map((task) => task.live_from_start === undefined ? "" : `${task.title}: ${task.live_from_start ? "live from start" : "live from current point"}`)
                                                          : kind === "slot"
                                                            ? filteredDownloads.map((task) => task.run_after_active_slot === undefined ? "" : `${task.title}: ${task.run_after_active_slot ? "run when active slot opens" : "manual start"}`)
                                                            : kind === "fragments"
                                                              ? filteredDownloads.map((task) => task.concurrent_fragments ? `${task.title}: ${task.concurrent_fragments}` : "")
                                                              : kind === "custom-args"
                                                                ? filteredDownloads.map((task) => task.custom_ytdlp_args ? `${task.title}: ${task.custom_ytdlp_args}` : "")
                                                                : kind === "clip"
                                                                  ? filteredDownloads.map((task) => (task.start_seconds !== null && task.start_seconds !== undefined) || (task.end_seconds !== null && task.end_seconds !== undefined) ? `${task.title}: ${task.start_seconds ?? "start"} -> ${task.end_seconds ?? "end"}` : "")
                                                                  : kind === "quality"
                                                                    ? filteredDownloads.map((task) => task.quality ? `${task.title}: ${task.quality}` : "")
                                                                    : kind === "audio-format"
                                                                      ? filteredDownloads.map((task) => task.audio_format ? `${task.title}: ${task.audio_format}` : "")
                                                                      : kind === "subtitles"
                                                                        ? filteredDownloads.map((task) => task.subtitles ? `${task.title}: ${task.subtitles.languages.join(", ") || "all"} · auto=${task.subtitles.auto} · embed=${task.subtitles.embed} · keep_vtt=${task.subtitles.keep_vtt}` : "")
                                                                        : kind === "sponsorblock"
                                                                            ? filteredDownloads.map((task) => task.sponsorblock ? `${task.title}: enabled=${task.sponsorblock.enabled} · ${task.sponsorblock.categories.join(", ") || "no categories"}` : "")
                                                                            : kind === "metadata"
                                                                              ? filteredDownloads.map((task) => task.metadata ? `${task.title}: embed=${task.metadata.embed_metadata} · thumbnail=${task.metadata.embed_thumbnail} · split_chapters=${task.metadata.split_chapters}` : "")
                                                                              : kind === "integrity"
                                                                                ? filteredDownloads.map((task) => {
                                                                                    const summary = taskIntegritySummary(task);
                                                                                    return summary ? `${task.title}: ${summary}` : "";
                                                                                  })
                                                                                : kind === "started"
                                                                                  ? filteredDownloads.map((task) => task.started_at ? `${task.title}: ${task.started_at}` : "")
                                                                                  : kind === "finished"
                                                                                    ? filteredDownloads.map((task) => task.finished_at ? `${task.title}: ${task.finished_at}` : "")
                                                                                    : kind === "created"
                                                                                      ? filteredDownloads.map((task) => `${task.title}: ${task.created_at}`)
                                                                                      : filteredDownloads.map((task) => `${task.title}: ${task.updated_at}`);
    const labels: Record<typeof kind, [string, string]> = {
      source: ["No source URLs", "Source URLs copied"],
      output: ["No output paths", "Output paths copied"],
      "output-dir": ["No output directories", "Output directories copied"],
      id: ["No download task ids", "Download task ids copied"],
      title: ["No download task titles", "Download task titles copied"],
      status: ["No download statuses", "Download statuses copied"],
      kind: ["No download kinds", "Download kinds copied"],
      platform: ["No download platforms", "Download platforms copied"],
      progress: ["No download progress values", "Download progress copied"],
      downloaded: ["No downloaded byte counts", "Downloaded byte counts copied"],
      size: ["No download total sizes", "Download total sizes copied"],
      speed: ["No download speed values", "Download speeds copied"],
      eta: ["No download ETA values", "Download ETAs copied"],
      files: ["No download file counts", "Download file counts copied"],
      error: ["No download errors", "Download errors copied"],
      "error-category": ["No download error categories", "Download error categories copied"],
      retry: ["No download retry counts", "Download retry counts copied"],
      cookie: ["No download Cookie bucket refs", "Download Cookie bucket refs copied"],
      auth: ["No download auth payload refs", "Download auth payload refs copied"],
      "thumbnail-url": ["No download thumbnail URLs", "Download thumbnail URLs copied"],
      "thumbnail-path": ["No download thumbnail paths", "Download thumbnail paths copied"],
      "user-agent": ["No download User-Agent values", "Download User-Agent values copied"],
      referer: ["No download Referer values", "Download Referer values copied"],
      proxy: ["No download proxy values", "Download proxy values copied"],
      "rate-limit": ["No download rate limits", "Download rate limits copied"],
      live: ["No download live settings", "Download live settings copied"],
      slot: ["No download slot scheduling settings", "Download slot scheduling copied"],
      fragments: ["No download fragment settings", "Download fragment settings copied"],
      "custom-args": ["No download custom yt-dlp args", "Download custom yt-dlp args copied"],
      clip: ["No download clip ranges", "Download clip ranges copied"],
      quality: ["No download quality values", "Download quality values copied"],
      "audio-format": ["No download audio formats", "Download audio formats copied"],
      subtitles: ["No download subtitle settings", "Download subtitle settings copied"],
      sponsorblock: ["No download SponsorBlock settings", "Download SponsorBlock settings copied"],
      metadata: ["No download metadata settings", "Download metadata settings copied"],
      integrity: ["No download SHA-256 integrity details", "Download SHA-256 integrity details copied"],
      started: ["No download start times", "Download start times copied"],
      finished: ["No download finish times", "Download finish times copied"],
      created: ["No download created times", "Download created times copied"],
      updated: ["No download updated times", "Download updated times copied"]
    };
    await copyLinesToClipboard(values, labels[kind][0], labels[kind][1]);
  }

  async function copyVisibleDownloadSummary() {
    const lines = filteredDownloads.map(downloadTaskSummaryLine);
    await copyLinesToClipboard(lines, "No visible download tasks", "Download task summary copied");
  }

  function downloadTaskSummaryLine(task: DownloadTask): string {
    const output = task.output_path ?? task.output_dir ?? "no output path";
    const progress = formatProgress(task);
    const options = taskOptionSummary(task);
    const optionPart = options ? ` · ${options}` : "";
    const integrity = taskIntegritySummary(task);
    const integrityPart = integrity ? ` · ${integrity}` : "";
    const error = task.last_error ? ` · error: ${task.last_error}` : "";
    return `${task.id} · ${task.status} · ${task.kind}/${task.platform} · ${task.title} · ${progress} · ${output}${optionPart}${integrityPart}${error}`;
  }

