    return {
      id: task.id,
      title: task.title,
      source_url: task.source_url,
      kind: task.kind,
      platform: task.platform,
      status: task.status,
      position: task.position,
      output_dir: task.output_dir ?? null,
      output_path: task.output_path ?? null,
      downloaded_bytes: task.downloaded_bytes ?? null,
      total_bytes: task.total_bytes ?? null,
      speed_bytes_per_sec: task.speed_bytes_per_sec ?? null,
      eta_seconds: task.eta_seconds ?? null,
      file_count: task.file_count ?? null,
      last_error: task.last_error ?? null,
      error_category: task.error_category ?? null,
      retryable: task.retryable ?? null,
      retry_count: task.retry_count,
      run_after_active_slot: task.run_after_active_slot ?? null,
      user_agent: task.user_agent ?? null,
      referer: task.referer ?? null,
      proxy: task.proxy ?? null,
      cookie_bucket_id: task.cookie_bucket_id ?? null,
      auth_payload_ref: task.auth_payload_ref ?? null,
      rate_limit: task.rate_limit ?? null,
      live_from_start: task.live_from_start ?? null,
      concurrent_fragments: task.concurrent_fragments ?? null,
      custom_ytdlp_args: task.custom_ytdlp_args ?? null,
      start_seconds: task.start_seconds ?? null,
      end_seconds: task.end_seconds ?? null,
      quality: task.quality ?? null,
      audio_format: task.audio_format ?? null,
      thumbnail_url: task.thumbnail_url ?? null,
      thumbnail_path: task.thumbnail_path ?? null,
      subtitles: task.subtitles ?? null,
      sponsorblock: task.sponsorblock ?? null,
      metadata: task.metadata ?? null,
