    };
  }

  async function copyDownloadTaskSummary(task: DownloadTask) {
    await copyLinesToClipboard([downloadTaskSummaryLine(task)], "No download task", "Download task summary copied");
  }

  async function copyDownloadTaskJson(task: DownloadTask) {
    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      task: downloadTaskJsonPayload(task)
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No download task", "Download task JSON copied");
  }

  async function copyVisibleDownloadJson() {
    if (filteredDownloads.length === 0) {
      await copyTextToClipboard("", "No visible download tasks", "Download tasks copied");
      return;
    }
    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      view: downloadViewMode,
      filters: {
        status: downloadStatusFilter,
        kind: downloadKindFilter,
        platform: downloadPlatformFilter,
        operational: downloadOperationalFilter,
        search: downloadSearchQuery,
        date_field: downloadDateField,
        created_from: downloadDateFrom,
        created_to: downloadDateTo,
        sort: downloadSortMode
      },
      tasks: filteredDownloads.map(downloadTaskJsonPayload)
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No visible download tasks", "Download task JSON copied");
  }

