      downloadsTasksTransferBusy = false;
    }
  }

  async function exportDownloadFilterPresetBackup() {
    if (downloadFilterPresets.length === 0) {
      pushToast(createToast("No filter presets to export", "error", "Save a Downloads filter preset before exporting."));
      return;
    }
    downloadFilterPresetsTransferBusy = "export";
    try {
      const result = await exportDownloadFilterPresets(
        downloadFilterPresets.map(toDownloadFilterPresetBackupItem),
        downloadFilterPresetsExportPath.trim() || undefined,
        downloadFilterPresetSelection || undefined
      );
      downloadFilterPresetsExportResult = result;
      downloadFilterPresetsImportResult = null;
      if (result?.output_path) {
        downloadFilterPresetsExportPath = result.output_path;
      }
      pushToast(createToast("Download filter presets exported", "success", result ? `${result.exported_preset_count} preset${result.exported_preset_count === 1 ? "" : "s"}` : "Exported", advancedFileToastAction(result?.output_path ?? "")));
    } catch (error) {
      downloadsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Download filter preset export failed", "error", downloadsError));
    } finally {
      downloadFilterPresetsTransferBusy = "";
    }
  }

  async function importDownloadFilterPresetBackup() {
    if (!downloadFilterPresetsImportPath.trim()) {
      pushToast(createToast("Filter preset backup path required", "error", "Choose a JSON backup before importing."));
      return;
    }
    downloadFilterPresetsTransferBusy = "import";
    try {
      const result = await importDownloadFilterPresets(downloadFilterPresetsImportPath.trim());
      downloadFilterPresetsImportResult = result;
      downloadFilterPresetsExportResult = null;
      if (result) {
        mergeImportedDownloadFilterPresets(result.presets, result.selected_preset_id);
      }
    } catch (error) {
      downloadsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Download filter preset import failed", "error", downloadsError));
    } finally {
      downloadFilterPresetsTransferBusy = "";
    }
  }

  async function exportDownloadsTaskBackup() {
    downloadsTasksTransferBusy = true;
    try {
      const result = await exportDownloadsTasks(downloadsTasksExportPath.trim() || undefined, true);
      downloadsTasksExportResult = result;
      downloadsTasksImportResult = null;
      if (result?.output_path) {
        downloadsTasksExportPath = result.output_path;
      }
      downloadsLocalSummary = await getDownloadsLocalSummary();
      pushToast(createToast("Download task backup exported", "success", result ? `${result.exported_task_count} task${result.exported_task_count === 1 ? "" : "s"}` : "Exported", advancedFileToastAction(result?.output_path ?? "")));
    } catch (error) {
      downloadsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Download task backup export failed", "error", downloadsError));
    } finally {
      downloadsTasksTransferBusy = false;
    }
  }

  async function importDownloadsTaskBackup() {
    if (!downloadsTasksImportPath.trim()) {
      pushToast(createToast("Download task backup path required", "error", "Choose a JSON backup before importing."));
      return;
    }
    downloadsTasksTransferBusy = true;
    try {
      const result = await importDownloadsTasks(downloadsTasksImportPath.trim());
      downloadsTasksImportResult = result;
      downloadsTasksExportResult = null;
      if (result) {
        downloads = result.tasks;
        activeTaskIds = new Set(result.tasks.filter((task) => task.status === "active").map((task) => task.id));
      }
      downloadsLocalSummary = await getDownloadsLocalSummary();
      pushToast(createToast("Download task backup imported", "success", result ? `${result.imported_task_count} imported · ${result.skipped_task_count} skipped` : "Imported", targetToastAction("Open", "downloads", { query: "" })));
    } catch (error) {
      downloadsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Download task backup import failed", "error", downloadsError));
    } finally {
      downloadsTasksTransferBusy = false;
    }
  }

