  function downloadFilterPresetSummary(preset: DownloadFilterPreset) {
    const parts = [
      preset.viewMode,
      `status ${preset.status}`,
      `kind ${preset.kind}`,
      `platform ${preset.platform}`,
      `operational ${preset.operational}`,
      `sort ${preset.sortMode}`
    ];
    if (preset.query) {
      parts.push(`query "${preset.query}"`);
    }
    if (preset.dateFrom || preset.dateTo) {
      parts.push(`${preset.dateField} ${preset.dateFrom || "any"} to ${preset.dateTo || "any"}`);
    }
    return `${preset.name}: ${parts.join(" · ")}`;
  }

  function toDownloadFilterPresetBackupItem(preset: DownloadFilterPreset): DownloadFilterPresetBackupItem {
    return {
      id: preset.id,
      name: preset.name,
      view_mode: preset.viewMode,
      status: preset.status,
      kind: preset.kind,
      platform: preset.platform,
      operational: preset.operational,
      query: preset.query,
      date_field: preset.dateField,
      date_from: preset.dateFrom,
      date_to: preset.dateTo,
      sort_mode: preset.sortMode
    };
  }

  function mergeImportedDownloadFilterPresets(items: unknown[], selectedPresetId?: string | null) {
    const imported = items
      .map((item) => normalizeDownloadFilterPresetRecord(item))
      .filter((item): item is DownloadFilterPreset => Boolean(item));
    if (imported.length === 0) {
      pushToast(createToast("No filter presets imported", "error", "The selected backup did not contain usable preset names."));
      return;
    }

    const importedNames = new Set<string>();
    const usedIds = new Set<string>();
    const uniqueImported: DownloadFilterPreset[] = [];
    for (const preset of imported) {
      const normalizedName = preset.name.trim().toLowerCase();
      if (!normalizedName || importedNames.has(normalizedName)) {
        continue;
      }
      importedNames.add(normalizedName);
      const id = usedIds.has(preset.id)
        ? `download-filter-${Date.now()}-${uniqueImported.length}`
        : preset.id;
      usedIds.add(id);
      uniqueImported.push({ ...preset, id });
    }

    const retainedExisting = downloadFilterPresets.filter(
      (preset) => !importedNames.has(preset.name.trim().toLowerCase())
    );
    const nextPresets = [...uniqueImported, ...retainedExisting]
      .map((preset, index) => {
        if (!usedIds.has(preset.id)) {
          usedIds.add(preset.id);
          return preset;
        }
        if (uniqueImported.some((item) => item.id === preset.id && item.name === preset.name)) {
          return preset;
        }
        const id = `download-filter-${Date.now()}-${index}`;
        usedIds.add(id);
        return { ...preset, id };
      })
      .slice(0, 12);
    persistDownloadFilterPresets(nextPresets);
    downloadFilterPresetSelection =
      selectedPresetId && nextPresets.some((preset) => preset.id === selectedPresetId)
        ? selectedPresetId
        : uniqueImported[0]?.id ?? "";
    pushToast(createToast("Download filter presets imported", "success", `${uniqueImported.length} preset${uniqueImported.length === 1 ? "" : "s"}`));
  }

