  async function refreshChannelsLocalSummary() {
    channelLocalSummaryBusy = true;
    try {
      const [summary, capabilityCatalog] = await Promise.all([
        getLocalChannelsSummary(),
        getChannelsCapabilityCatalog()
      ]);
      localChannelsSummary = summary;
      channelsCapabilityCatalog = capabilityCatalog;
      channelsError = "";
      if (localChannelsSummary) {
        pushToast(createToast("Channels summary refreshed", "success", `${localChannelsSummary.channel_count} channels · ${localChannelsSummary.history_count} history`));
      }
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channels summary failed", "error", channelsError));
    } finally {
      channelLocalSummaryBusy = false;
    }
  }

  async function refreshChannelsCapabilityCatalog() {
    channelLocalSummaryBusy = true;
    try {
      channelsCapabilityCatalog = await getChannelsCapabilityCatalog();
      channelsError = "";
      pushToast(createToast("Channels catalog refreshed", "success", `${channelsCapabilityCatalog?.capability_count ?? 0} capabilities`));
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channels catalog failed", "error", channelsError));
    } finally {
      channelLocalSummaryBusy = false;
    }
  }

