    const values =
      kind === "capability"
        ? channelsCapabilityCatalog?.capabilities.map((item) => `${item.capability}: ${item.status} · ${item.scope}`) ?? []
        : kind === "command"
          ? channelsCapabilityCatalog?.capabilities.flatMap((item) => item.commands.map((command) => `${item.capability}: ${command}`)) ?? []
          : kind === "ui"
            ? channelsCapabilityCatalog?.capabilities.flatMap((item) => item.desktop_ui.map((surface) => `${item.capability}: ${surface}`)) ?? []
            : kind === "file"
              ? channelsCapabilityCatalog?.storage_files ?? []
              : kind === "field"
                ? channelsCapabilityCatalog?.capabilities.flatMap((item) => item.record_fields.map((field) => `${item.capability}: ${field}`)) ?? []
                : kind === "event"
                  ? channelsCapabilityCatalog?.event_names ?? []
                  : kind === "limit"
                    ? channelsCapabilityCatalog?.capabilities.flatMap((item) => item.limitations.map((limitation) => `${item.capability}: ${limitation}`)) ?? []
                    : channelsCapabilityCatalog?.review_notes ?? [];
    await copyLinesToClipboard(values, "No Channels capability catalog fields", "Channels capability catalog fields copied");
  }

  async function chooseChannelsSummaryExportPath() {
    if (!isTauriRuntime()) {
      pushToast(createToast("Save dialog unavailable", "error", "Run the desktop app to choose a channels summary export path."));
      return;
    }
    channelLocalSummaryBusy = true;
    try {
      const selected = await save({
        title: "Choose channels summary export",
        defaultPath: channelLocalSummaryExportPath.trim() || "fetchdock-channels-summary.json",
        filters: [{ name: "FetchDock channels summary JSON", extensions: ["json"] }]
      });
      if (typeof selected === "string") {
        channelLocalSummaryExportPath = selected;
      }
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channels summary path failed", "error", channelsError));
    } finally {
      channelLocalSummaryBusy = false;
    }
  }

  async function exportChannelsSummary() {
    channelLocalSummaryBusy = true;
    try {
      const path = await exportChannelsLocalSummary(channelLocalSummaryExportPath.trim() || undefined);
      if (path) {
        channelLocalSummaryExportPath = path;
        channelLocalSummaryExportResult = path;
        await refreshChannelsLocalSummary();
        pushToast(createToast("Channels summary exported", "success", path, advancedFileToastAction(path)));
      }
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channels summary export failed", "error", channelsError));
    } finally {
      channelLocalSummaryBusy = false;
    }
  }

  async function exportChannelsCapabilityCatalogFile() {
    channelLocalSummaryBusy = true;
    try {
      const path = await exportChannelsCapabilityCatalog(channelsCapabilityCatalogExportPath.trim() || undefined);
      if (path) {
        channelsCapabilityCatalogExportPath = path;
        channelsCapabilityCatalogExportResult = path;
        channelsCapabilityCatalog = await getChannelsCapabilityCatalog();
        pushToast(createToast("Channels catalog exported", "success", path, advancedFileToastAction(path)));
      }
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channels catalog export failed", "error", channelsError));
    } finally {
      channelLocalSummaryBusy = false;
    }
  }

