  async function copyShownCourseSummary() {
    const lines = filteredCourses.map((course) => {
      const lessonProgress = course.lessons.length > 0
        ? Math.round(course.lessons.reduce((total, lesson) => total + lesson.progress_percent, 0) / course.lessons.length)
        : 0;
      const cookie = course.cookie_bucket_id ? ` · cookie ${course.cookie_bucket_id}` : "";
      const note = course.remote_extraction_note ? ` · ${course.remote_extraction_note}` : "";
      return `${course.id} · ${course.platform} · ${course.status} · ${course.title} · ${course.lesson_count} lessons · ${course.attachment_count} attachments · ${lessonProgress}% avg progress${cookie}${note} · ${course.source_url}`;
    });
    await copyLinesToClipboard(lines, "No visible courses", "Course summary copied");
  }

  async function copyShownCourseJson() {
    if (filteredCourses.length === 0) {
      await copyTextToClipboard("", "No visible courses", "Courses copied");
