    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      filters: {
        search: courseSearchQuery
      },
      courses: filteredCourses.map((course) => ({
        id: course.id,
        source_url: course.source_url,
        platform: course.platform,
        title: course.title,
        status: course.status,
        cookie_bucket_id: course.cookie_bucket_id ?? null,
        remote_extraction_note: course.remote_extraction_note ?? null,
        lesson_count: course.lesson_count,
        attachment_count: course.attachment_count,
        created_at: course.created_at,
        updated_at: course.updated_at,
        visible_lessons: visibleCourseLessons(course).map((lesson) => ({
          id: lesson.id,
          title: lesson.title,
          source_url: lesson.source_url ?? null,
          local_path: lesson.local_path ?? null,
          duration_seconds: lesson.duration_seconds ?? null,
          progress_percent: lesson.progress_percent,
          note_count: lesson.note_count,
          opened_at: lesson.opened_at ?? null
        })),
        visible_attachments: visibleCourseAttachments(course).map((attachment) => ({
          id: attachment.id,
          title: attachment.title,
          source_url: attachment.source_url ?? null,
          local_path: attachment.local_path ?? null,
          size_bytes: attachment.size_bytes,
          kind: attachment.kind
        }))
      }))
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No visible courses", "Course JSON copied");
  }

