              ? filteredLearningNotes.flatMap((note) => note.tags)
              : kind === "timestamp"
                ? filteredLearningNotes.map((note) => note.timestamp_seconds === null || note.timestamp_seconds === undefined ? "" : `${note.title}: ${formatTimestamp(note.timestamp_seconds)}`)
                : kind === "link"
                  ? filteredLearningNotes.flatMap((note) => note.outgoing_links.map((link) => `${note.title}: ${link}`))
                  : kind === "created"
                    ? filteredLearningNotes.map((note) => `${note.title}: ${note.created_at}`)
                    : kind === "updated"
                      ? filteredLearningNotes.map((note) => `${note.title}: ${note.updated_at}`)
                      : filteredLearningNotes.map((note) => `${note.title}: ${note.backlink_count}`);
    const labels: Record<typeof kind, [string, string]> = {
      source: ["No note source URLs", "Note source URLs copied"],
      id: ["No note ids", "Note ids copied"],
      title: ["No note titles", "Note titles copied"],
      tag: ["No note tags", "Note tags copied"],
      timestamp: ["No note timestamps", "Note timestamps copied"],
      link: ["No note links", "Note links copied"],
      created: ["No note created times", "Note created times copied"],
      updated: ["No note updated times", "Note updated times copied"],
      backlink: ["No note backlink counts", "Note backlink counts copied"]
    };
    await copyLinesToClipboard(values, labels[kind][0], labels[kind][1]);
  }

