        : visibleLearningGraphEdges(graph, 8).map((edge) => `${nodeTitle(edge.source_id)} -> ${nodeTitle(edge.target_id)}${edge.label ? ` [${edge.label}]` : ""}`),
      kind === "node" ? "No learning graph nodes" : "No learning graph links",
      kind === "node" ? "Learning graph nodes copied" : "Learning graph links copied"
    );
  }

  function filterSpacedReviewCards(cards: SpacedReviewCard[], query: string, dueOnly: boolean) {
    const needle = query.trim().toLowerCase();
    const now = new Date().toISOString();
    return cards.filter((card) => {
      if (dueOnly && card.due_at > now) {
        return false;
      }
      if (!needle) {
        return true;
      }
      return [card.id, card.note_id, card.prompt, card.answer, card.source_url ?? "", ...card.tags]
        .some((value) => value.toLowerCase().includes(needle));
    });
  }

  function spacedReviewSummaryLines(cards = filteredSpacedReviewCards) {
    return cards.map((card) => {
      const source = card.source_url ? ` · ${card.source_url}` : "";
      const reviewed = card.last_reviewed_at ? ` · last ${card.last_reviewed_at}` : " · new";
      return `${card.prompt} · due ${card.due_at} · interval ${card.interval_days}d · ease ${card.ease}${reviewed}${source}`;
    });
  }

  function learningNoteReviewDraft(note: LearningNote) {
    const body = note.body.trim().replace(/\s+/g, " ");
    const prompt = note.title.trim() || "Untitled note";
    const answer = body || prompt;
    return {
      prompt,
      answer: answer.length > 1200 ? `${answer.slice(0, 1200)}...` : answer,
      tags: Array.from(new Set(["note", ...note.tags])).filter(Boolean),
      sourceUrl: note.source_url ?? undefined
    };
  }

