  async function exportLearningSummary() {
    learningLocalSummaryBusy = true;
    learningError = "";
    try {
      const path = await exportLearningLocalSummary(learningSummaryExportPath.trim() || undefined);
      if (path) {
        learningSummaryExportPath = path;
        learningSummaryExportResult = path;
        pushToast(createToast("Learning summary exported", "success", path, advancedFileToastAction(path)));
      }
      learningLocalSummary = await getLearningLocalSummary();
      await loadAdvancedFiles();
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Learning summary export failed", "error", learningError));
    } finally {
      learningLocalSummaryBusy = false;
    }
  }

