  function pluginLogPluginSummary(plugin: PluginInfo) {
    return {
      id: plugin.id,
      display_name: plugin.display_name,
      version: plugin.version,
      state: plugin.state,
      preflight_status: plugin.preflight_status
    };
  }

  function pluginPayloadMetadata(payload: unknown) {
    const payloadKind = payload === null ? "null" : Array.isArray(payload) ? "array" : typeof payload;
    const keys =
      payload && typeof payload === "object" && !Array.isArray(payload)
        ? Object.keys(payload as Record<string, unknown>).sort()
        : [];
    return {
      kind: payloadKind,
      key_count: keys.length,
      keys,
      json_length: JSON.stringify(payload ?? null).length
    };
  }

  function pluginCommandLogCopyPayload(plugin: PluginInfo) {
    const response = pluginCommandLogs[plugin.id];
    const entries = filterPluginCommandLogEntries(response?.commands ?? [], pluginLogSearch);
    return {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      plugin: pluginLogPluginSummary(plugin),
      kind: "commands",
      filters: {
        search: pluginLogSearch.trim() || null
      },
      log_path: response?.log_path ?? null,
      loaded_count: response?.commands.length ?? 0,
      shown_count: entries.length,
      includes_payload_values: false,
      entries: entries.map((entry) => ({
        command: entry.command,
        status: entry.status,
        message: entry.message,
        created_at: entry.created_at,
        payload: pluginPayloadMetadata(entry.payload)
      })),
      copied_from_loaded_log_state: true
    };
  }

