  async function copyExtensionOptionFields(kind: "bridge" | "port" | "blocked" | "endpoint" | "pairing" | "summary") {
    const bridgeUrl = extensionBridgeUrlInput.trim() || extensionOptions?.bridge_url || "http://127.0.0.1:17654";
    const ports = normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput);
    const blockedHosts = parseExtensionBlockedHosts(extensionBlockedHostsInput);
    const values =
      kind === "bridge"
        ? [bridgeUrl]
        : kind === "port"
          ? ports.map(String)
          : kind === "blocked"
            ? blockedHosts
            : kind === "endpoint"
              ? [
                  "GET /health",
                  "POST /pair/start (manual compat)",
                  "POST /pair/complete (manual compat)",
                  "POST /v1/extension/download",
                  "POST /download/page (compat)",
                  "POST /download/media (compat)",
                  "POST /download/batch (compat)",
                  "POST /v1/extension/cookies",
                  "POST /cookies/import (compat)",
                  "POST /v1/extension/authorization"
                ]
              : kind === "pairing"
                ? [
                    `paired: ${extensionPairingStatus?.paired ? "yes" : "no"}`,
                    `token_required: ${extensionPairingStatus?.token_required ? "yes" : "no"}`,
                    `label: ${extensionPairingStatus?.label ?? extensionPairingLabel.trim() ?? ""}`,
                    `expires_at: ${extensionPairingStatus?.expires_at ?? ""}`
                  ]
                : [
                    `bridge: ${bridgeUrl}`,
                    `ports: ${ports.join(", ")}`,
                    `deep_link_fallback: ${extensionDeepLinkFallbackInput ? "enabled" : "disabled"}`,
                    `media_sniffer: ${extensionCaptureMediaInput ? "enabled" : "disabled"}`,
                    `header_capture: ${extensionCaptureHeadersInput ? "enabled" : "disabled"}`,
                    `blocked_hosts: ${blockedHosts.length}`,
                    `token_set: ${extensionOptions?.token_set || extensionPairingStatus?.token_required ? "yes" : "no"}`
                  ];
    const labels: Record<typeof kind, [string, string]> = {
