      `formats: ${libraryFormatCatalog.format_count}`,
      `file bodies included: ${libraryFormatCatalog.includes_file_bodies}`,
      `full renderer verified: ${libraryFormatCatalog.verifies_full_renderer}`,
      `manual reader matrix verified: ${libraryFormatCatalog.verifies_manual_reader_matrix}`,
      ...libraryFormatCatalog.formats.map((entry) => {
        const flags = [
          entry.scan_supported ? "scan" : "",
          entry.metadata_supported ? "metadata" : "",
          entry.cover_supported ? "cover" : "",
          entry.bounded_preview_supported ? "preview" : "",
          entry.reading_state_supported ? "reading-state" : "",
          entry.annotation_supported ? "annotations" : "",
          entry.export_supported ? "export" : ""
        ].filter(Boolean).join(", ");
        return `${entry.format}: ${entry.extensions.join(", ")} · ${flags}`;
      }),
      ...libraryFormatCatalog.review_notes.map((note) => `note: ${note}`)
    ];
  }

