  async function exportLibrarySummary() {
    libraryBusy = true;
    libraryBusyMode = "summary-export";
    libraryError = "";
    try {
      const path = await exportLibraryLocalSummary(librarySummaryExportPath.trim() || undefined);
      if (path) {
        librarySummaryExportPath = path;
        librarySummaryExportResult = path;
        pushToast(createToast("Library summary exported", "success", path, advancedFileToastAction(path)));
      }
      await refreshLibraryLocalSummary();
      await loadAdvancedFiles();
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Library summary export failed", "error", libraryError));
    } finally {
      libraryBusy = false;
      libraryBusyMode = "";
    }
  }

  async function exportLibraryFormatCatalogFile() {
