  function libraryPreviewSummaryJson(preview: LibraryOpenResponse) {
    const cbzPages = cbzPreviewPages(preview);
    const cbzImages = cbzPreviewImages(preview);
    const epubOrder = epubReadingOrder(preview);
    const epubTexts = epubTextPreviews(preview);
    const pdfSummary = pdfPreviewSummary(preview);
    return {
      path: preview.path,
      title: preview.title,
      format: preview.format,
      word_count: preview.word_count,
      modified_at: preview.modified_at ?? null,
      progress_percent: libraryReadingState?.progress_percent ?? null,
      bookmark_count: libraryReadingState?.bookmarks.length ?? 0,
      highlight_count: libraryReadingState?.highlights.length ?? 0,
      preview: {
        content_chars: preview.content.length,
        content_excerpt: libraryPreviewTextExcerpt(preview),
        pdf_summary: pdfSummary,
        cbz_page_count: cbzPages.length,
        cbz_cached_preview_count: cbzImages.length,
        epub_reading_order_count: epubOrder.length,
        epub_text_preview_count: epubTexts.length
      },
      extra_json: preview.extra_json ?? null
    };
  }

  function libraryPreviewSummaryLines(preview: LibraryOpenResponse): string[] {
    const lines = [
      `${preview.title} · ${preview.format.toUpperCase()} · ${preview.path}`,
      preview.modified_at ? `Modified: ${preview.modified_at}` : "Modified: unknown",
      preview.format === "pdf"
        ? `${preview.word_count || pdfPreviewSummary(preview).length} PDF preview signal${(preview.word_count || pdfPreviewSummary(preview).length) === 1 ? "" : "s"}`
        : preview.format === "cbz"
          ? `${cbzPreviewPages(preview).length} archive page${cbzPreviewPages(preview).length === 1 ? "" : "s"} · ${cbzPreviewImages(preview).length} cached preview${cbzPreviewImages(preview).length === 1 ? "" : "s"}`
          : preview.format === "epub"
            ? `${epubReadingOrder(preview).length} reading-order item${epubReadingOrder(preview).length === 1 ? "" : "s"} · ${epubTextPreviews(preview).length} text preview${epubTextPreviews(preview).length === 1 ? "" : "s"}`
            : `${preview.word_count} word${preview.word_count === 1 ? "" : "s"} · ${preview.content.length} chars`,
      libraryReadingState
        ? `${libraryReadingState.progress_percent}% read · ${libraryReadingState.bookmarks.length} bookmark${libraryReadingState.bookmarks.length === 1 ? "" : "s"} · ${libraryReadingState.highlights.length} highlight${libraryReadingState.highlights.length === 1 ? "" : "s"}`
        : "No local reading state loaded"
    ];
    if (preview.format === "pdf") {
      lines.push(...pdfPreviewSummary(preview));
    }
    if (preview.format === "epub") {
      lines.push(...epubPreviewSummary(preview));
    }
    return lines.filter(Boolean);
  }

  function libraryPreviewTextExcerpt(preview: LibraryOpenResponse): string {
    if (preview.format === "pdf" || preview.format === "cbz") {
      return "";
    }
    const text =
      preview.format === "html" || preview.format === "htm"
        ? htmlToPlainPreviewText(preview.content)
        : preview.content;
    return text.replace(/\s+/gu, " ").trim().slice(0, 4000);
  }

  function htmlToPlainPreviewText(html: string): string {
    if (typeof document === "undefined") {
      return html.replace(/<[^>]+>/gu, " ");
    }
    const template = document.createElement("template");
    template.innerHTML = html;
    return template.content.textContent ?? "";
  }

