  async function refreshP2pLocalSummary() {
    try {
      const [summary, catalog] = await Promise.all([
        getP2pLocalSummary(),
        getP2pCapabilityCatalog()
      ]);
      p2pLocalSummary = summary;
      p2pCapabilityCatalog = catalog;
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
    }
  }

  async function exportP2pCapabilityCatalogFile() {
    p2pBusy = "catalog-export";
    try {
      const path = await exportP2pCapabilityCatalog(p2pCapabilityCatalogExportPath.trim() || undefined);
      if (path) {
        p2pCapabilityCatalogExportResult = path;
        p2pCapabilityCatalogExportPath = path;
        pushToast(createToast("Torrent/P2P capability catalog exported", "success", path, targetToastAction("Open", "p2p", { query: "catalog" })));
      }
      p2pCapabilityCatalog = await getP2pCapabilityCatalog();
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Torrent/P2P capability catalog export failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  async function chooseP2pCapabilityCatalogExportPath() {
    if (!isTauriRuntime()) {
      pushToast(createToast("Save dialog unavailable", "error", "Run the desktop app to choose a Torrent/P2P capability catalog export path."));
      return;
    }
    p2pBusy = "catalog-choose";
    try {
      const selected = await save({
        title: "Choose Torrent/P2P capability catalog export",
        defaultPath: p2pCapabilityCatalogExportPath.trim() || "fetchdock-p2p-capability-catalog.json",
        filters: [{ name: "FetchDock Torrent/P2P capability catalog JSON", extensions: ["json"] }]
      });
      if (typeof selected === "string") {
        p2pCapabilityCatalogExportPath = selected;
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Torrent/P2P capability catalog path failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

