  async function copyShotMarkerSummary() {
    if (shotMarkers.length === 0) {
      await copyLinesToClipboard([], "No shot markers", "Shot marker summary copied");
      return;
    }
    const threshold = Number(shotThreshold);
    const lines = [
      `${shotMarkers.length} markers · threshold ${Number.isFinite(threshold) ? threshold : "default"} · source ${shotInputPath.trim() || "not set"}`,
      `output ${shotOutputPath.trim() || "not set"}`,
      ...visibleShotMarkers(shotMarkers).map((marker) => `${formatTimestamp(marker.timestamp_seconds)} · score ${marker.score.toFixed(3)}`)
    ];
    await copyLinesToClipboard(lines, "No shot markers", "Shot marker summary copied");
  }

  async function copyShotMarkerJson() {
    if (shotMarkers.length === 0) {
      await copyTextToClipboard("", "No shot markers", "Shot markers copied");
      return;
    }
    const threshold = Number(shotThreshold);
    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      source_path: shotInputPath.trim() || null,
      output_path: shotOutputPath.trim() || null,
      threshold: Number.isFinite(threshold) ? threshold : null,
      expanded: shotMarkersExpanded,
      marker_count: shotMarkers.length,
      visible_count: visibleShotMarkers(shotMarkers).length,
      markers: shotMarkers.map((marker) => ({
        timestamp_seconds: marker.timestamp_seconds,
        timestamp: formatTimestamp(marker.timestamp_seconds),
        score: marker.score
      }))
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No shot markers", "Shot marker JSON copied");
  }

