  function localAuditSummaryLines() {
    const lines: string[] = [];
    if (localSettingsSummary) {
      const downloadsConcurrency = localSettingsSummary.downloads.max_concurrency ?? "unknown";
      const channelCount = localSettingsSummary.channels.channel_count ?? localChannelsSummary?.channel_count ?? 0;
      const pluginCount = localSettingsSummary.plugins.plugin_count ?? localPluginsSummary?.plugin_count ?? 0;
      const aiProvider = localSettingsSummary.ai.provider ?? "unknown";
      const aiWhisperConfigured = localSettingsSummary.ai.whisper_configured ?? false;
      lines.push(`settings · generated ${localSettingsSummary.generated_at}`);
      lines.push(`settings · downloads concurrency ${downloadsConcurrency} · channels ${channelCount} · plugins ${pluginCount}`);
      lines.push(`settings · AI provider ${aiProvider} · Whisper configured ${aiWhisperConfigured ? "yes" : "no"} · executes workflows ${localSettingsSummary.ai.executes_ai_workflows ? "yes" : "no"}`);
      lines.push(...localSettingsSummary.safety_notes.map((note) => `settings note · ${note}`));
    }
    if (localChannelsSummary) {
      lines.push(
        `channels · ${localChannelsSummary.channel_count} total · ${localChannelsSummary.enabled_count} enabled · ${localChannelsSummary.history_count} history · ${localChannelsSummary.notification_pending_count} pending notifications`
      );
      lines.push(
        `channels · auto poll ${localChannelsSummary.settings.auto_poll_enabled ? "on" : "off"} every ${localChannelsSummary.settings.poll_interval_minutes} min`
      );
    }
    if (localPluginsSummary) {
      lines.push(
        `plugins · ${localPluginsSummary.plugin_count} installed · ${localPluginsSummary.enabled_count} enabled · ${localPluginsSummary.failed_count} failed · ${localPluginsSummary.marketplace_entry_count} marketplace`
      );
      lines.push(`plugins · execution ${localPluginsSummary.local_execution_status}`);
    }
    if (localPluginTrustSummary) {
      lines.push(
        `plugin trust · gate ${localPluginTrustSummary.release_gate_status} · ready ${localPluginTrustSummary.ready_local_count} · manifest only ${localPluginTrustSummary.manifest_only_count} · failed ${localPluginTrustSummary.failed_count} · incompatible ${localPluginTrustSummary.incompatible_count}`
      );
      lines.push(
        `plugin trust · unsigned ${localPluginTrustSummary.unsigned_count} · remote marketplace ${localPluginTrustSummary.remote_marketplace_count} · dynamic execution ${localPluginTrustSummary.dynamic_execution_enabled ? "enabled" : "disabled"}`
      );
      lines.push(
        `plugin trust · marketplace hashes ${localPluginTrustSummary.marketplace_hash_count} · signatures ${localPluginTrustSummary.marketplace_signature_count}`
      );
      lines.push(
        `plugin trust · permissions ${localPluginTrustSummary.permission_grant_count} · marketplace capabilities ${localPluginTrustSummary.marketplace_capability_count} · marketplace permissions ${localPluginTrustSummary.marketplace_permission_count}`
      );
      lines.push(...localPluginTrustSummary.review_notes.map((note) => `plugin trust note · ${note}`));
    }
    return lines;
  }

