  async function copyUpdateManifestFields(kind: "path" | "url" | "notes" | "version" | "checked" | "summary" | "due") {
    const values =
      kind === "path"
        ? [updateManifestResult?.manifest_path ?? updateManifestPathInput]
        : kind === "url"
          ? [updateManifestResult?.download_url ?? ""]
          : kind === "notes"
            ? [updateManifestResult?.release_notes ?? ""]
            : kind === "version"
              ? [`current ${updateManifestResult?.current_version ?? "unknown"} -> latest ${updateManifestResult?.latest_version ?? "unknown"}`]
              : kind === "checked"
                ? [updateManifestResult?.checked_at ?? updateSettings?.last_checked_at ?? ""]
                : kind === "due"
                  ? updateDueCheckResult
                    ? [
                        `status: ${updateDueCheckResult.status}`,
                        `checked: ${updateDueCheckResult.checked ? "yes" : "no"}`,
                        `due: ${updateDueCheckResult.due ? "yes" : "no"}`,
                        `next check: ${updateDueCheckResult.next_check_at ?? "unknown"}`,
                        updateDueCheckResult.reason ? `reason: ${updateDueCheckResult.reason}` : ""
                      ].filter(Boolean)
                    : [updateSettings?.last_checked_at ? `last checked: ${updateSettings.last_checked_at}` : "No due check state"]
                  : [
                    updateManifestResult
                      ? `${updateManifestResult.update_available ? "update available" : "no update"}: ${updateManifestResult.current_version} -> ${updateManifestResult.latest_version ?? "unknown"} (${updateManifestResult.source_kind})`
                      : updateSettings?.last_result ?? ""
                  ];
    const labels: Record<typeof kind, [string, string]> = {
      path: ["No update manifest path", "Update manifest path copied"],
      url: ["No update download URL", "Update download URL copied"],
      notes: ["No update release notes", "Update release notes copied"],
      version: ["No update version summary", "Update versions copied"],
      checked: ["No update check time", "Update check time copied"],
      summary: ["No update summary", "Update summary copied"],
      due: ["No update due state", "Update due state copied"]
    };
