  function proxyContainsCredentials(value: string) {
    const trimmed = value.trim();
    if (!trimmed) {
      return false;
    }
    try {
      const parsed = new URL(trimmed);
      return Boolean(parsed.username || parsed.password);
    } catch {
      return /^([^/@\s:]+):([^/@\s]+)@/.test(trimmed) || /:\/\/([^/@\s:]+):([^/@\s]+)@/i.test(trimmed);
    }
  }

  function redactProxyForCopy(value: string) {
    const trimmed = value.trim();
    if (!trimmed) {
      return "";
    }
    try {
      const parsed = new URL(trimmed);
      if (parsed.username || parsed.password) {
        parsed.username = "redacted";
        parsed.password = parsed.password ? "redacted" : "";
      }
      return parsed.toString();
    } catch {
      return trimmed
        .replace(/^([^/@\s:]+):([^/@\s]+)@/, "redacted:redacted@")
        .replace(/([a-z][a-z0-9+.-]*:\/\/)([^/@\s:]+):([^/@\s]+)@/i, "$1redacted:redacted@");
    }
  }

  function formatShortcutRegistrationState(value: boolean | null | undefined) {
    return value === null || value === undefined ? "unavailable" : value ? "registered" : "not registered";
  }

  function infrastructureCopyPayload() {
    const quickCaptureRegistered = appInfrastructureSummary?.quick_capture_registered ?? null;
    return {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      runtime: {
        desktop_runtime: isTauriRuntime(),
        app_version: status?.app_version ?? null,
        platform: status?.platform ?? null,
        arch: status?.arch ?? null,
        mode: status?.mode ?? null,
        database_migration: status?.database_migration ?? null
      },
      checks: {
        tray_shell: "desktop-runtime-check",
        portable_mode: status?.mode ?? "unknown",
        deep_link_scheme: "fetchdock://",
        quick_capture: quickCaptureEnabledInput ? "enabled" : "disabled",
        quick_capture_registered: quickCaptureRegistered,
        autostart: autostartEnabled
      },
      quick_capture: {
        enabled_input: quickCaptureEnabledInput,
        shortcut_input: quickCaptureShortcutInput.trim() || null,
        saved_enabled: appShellSettings?.quick_capture_enabled ?? null,
        saved_shortcut: appShellSettings?.quick_capture_shortcut ?? null,
        registered: quickCaptureRegistered,
        updated_at: appShellSettings?.updated_at ?? null
      },
      busy: Boolean(quickCaptureBusy || autostartBusy),
      errors: {
        quick_capture: quickCaptureError || null,
        autostart: autostartError || null,
        status: statusError || null
      }
    };
  }

