          `input ${payload.polling_inputs.enabled ? "enabled" : "disabled"} · ${payload.polling_inputs.interval_minutes || "unset"} min`,
          payload.settings
            ? `saved ${payload.settings.auto_poll_enabled ? "enabled" : "disabled"} · ${payload.settings.poll_interval_minutes} min · last ${payload.settings.last_poll_finished_at ?? "never"}`
            : "saved polling not loaded"
        ]
        : kind === "counts"
          ? Object.entries(payload.counts).map(([key, value]) => `${key}: ${value}`)
          : Object.entries(payload.filters).map(([key, value]) => `${key}: ${value || "all"}`);
    const labels: Record<typeof kind, [string, string]> = {
      polling: ["No channel polling state", "Channel polling state copied"],
      counts: ["No channel counts", "Channel counts copied"],
      filters: ["No channel filters", "Channel filters copied"]
    };
    await copyLinesToClipboard(values, labels[kind][0], labels[kind][1]);
  }

  function pluginSettingsCopyPayload() {
    const visibleMarketplace = visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries);
    const stateCounts = plugins.reduce<Record<string, number>>((counts, plugin) => {
      counts[plugin.state] = (counts[plugin.state] ?? 0) + 1;
      return counts;
    }, {});
    return {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      counts: {
        installed: plugins.length,
        filtered_plugins: filteredPlugins.length,
        marketplace_entries: pluginMarketplaceEntries.length,
        visible_marketplace_entries: visibleMarketplace.length,
        enabled_nav_entries: enabledPluginNavEntries.length,
        commands: filteredPlugins.reduce((total, plugin) => total + plugin.commands.length, 0),
        events: filteredPlugins.reduce((total, plugin) => total + plugin.events.length, 0),
        capabilities: filteredPlugins.reduce((total, plugin) => total + plugin.capabilities.length, 0),
        permissions: filteredPlugins.reduce((total, plugin) => total + plugin.permissions.length, 0),
        marketplace_capabilities: visibleMarketplace.reduce((total, entry) => total + entry.capabilities.length, 0),
        marketplace_permissions: visibleMarketplace.reduce((total, entry) => total + entry.permissions.length, 0),
        i18n_manifests: filteredPlugins.filter((plugin) => Boolean(pluginI18nSummary(plugin))).length
      },
      state_counts: stateCounts,
      filters: {
        plugin_search: pluginSearchQuery,
        plugin_state: pluginStateFilter,
        marketplace_search: pluginMarketplaceSearch,
        log_search: pluginLogSearch
      },
      paths: {
        plugins_dir: status?.paths.plugins_dir ?? null
      },
      busy: Boolean(pluginsBusy || pluginActionBusy || pluginSettingsBusy || pluginDataDirBusy || pluginCommandBusy || pluginEventBusy),
      errors: {
        plugins: pluginsError || null,
        marketplace: pluginsError || null,
        settings: pluginSettingsError || null,
        command: pluginCommandError || null,
        event: pluginEventError || null
      }
    };
  }

  async function copyPluginSettingsSummary() {
    const payload = pluginSettingsCopyPayload();
    const lines = [
      `${payload.counts.installed} plugins · ${payload.counts.filtered_plugins} shown · ${payload.counts.marketplace_entries} marketplace entries · ${payload.counts.enabled_nav_entries} nav entries`,
      `states: ${Object.entries(payload.state_counts).map(([state, count]) => `${state} ${count}`).join(", ") || "none"}`,
      `filtered capability refs: ${payload.counts.capabilities} · permission refs ${payload.counts.permissions} · command refs ${payload.counts.commands} · event refs ${payload.counts.events}`,
      `marketplace capability hints: ${payload.counts.marketplace_capabilities} · permission hints ${payload.counts.marketplace_permissions}`,
      `plugin i18n manifests: ${payload.counts.i18n_manifests}`,
      `plugins dir: ${payload.paths.plugins_dir ?? "desktop runtime only"}`,
      payload.errors.plugins ? `plugins error: ${payload.errors.plugins}` : "",
      payload.errors.marketplace ? `marketplace error: ${payload.errors.marketplace}` : ""
    ];
    await copyLinesToClipboard(lines, "No plugin settings state", "Plugin settings summary copied");
  }

