  async function copyPluginTrustFields(kind: "entry" | "marketplace" | "note") {
    const values =
      kind === "entry"
        ? (localPluginTrustSummary?.entries ?? []).map((entry) => `${entry.id}: ${entry.trust_status} · ${entry.preflight_status}`)
        : kind === "marketplace"
          ? (localPluginTrustSummary?.marketplace_entries ?? []).map((entry) => {
              const hash = entry.sha256 ? ` · sha256 ${entry.sha256}` : "";
              const signature = entry.signature || entry.signature_url ? " · signature metadata" : "";
              const reviewCounts = ` · capabilities ${entry.capability_count} · permissions ${entry.permission_count}`;
              return `${entry.id}: ${entry.source_kind} · installed ${entry.installed}${hash}${signature}${reviewCounts}`;
            })
          : localPluginTrustSummary?.review_notes ?? [];
    const labels: Record<typeof kind, [string, string]> = {
      entry: ["No plugin trust entries", "Plugin trust entries copied"],
      marketplace: ["No marketplace trust entries", "Marketplace trust entries copied"],
      note: ["No plugin trust notes", "Plugin trust notes copied"]
