  async function copyDependencyToolFields(kind: "id" | "path" | "version" | "source" | "hash") {
    await copyLinesToClipboard(
      kind === "id"
        ? toolStatuses.map((tool) => tool.id)
        : kind === "path"
          ? toolStatuses.map((tool) => toolPathInputs[tool.id] ?? tool.path ?? "")
          : kind === "version"
            ? toolStatuses.map((tool) => [tool.id, tool.version].filter(Boolean).join(" "))
            : kind === "source"
              ? toolDownloadSources.map((source) => source.url)
              : toolDownloadSources.map((source) => `${source.tool_id}: ${source.sha256}`),
      kind === "id"
        ? "No dependency tool ids"
        : kind === "path"
          ? "No dependency tool paths"
          : kind === "version"
            ? "No dependency tool versions"
            : kind === "source"
              ? "No dependency source URLs"
              : "No dependency source hashes",
      kind === "id"
        ? "Dependency tool ids copied"
        : kind === "path"
          ? "Dependency tool paths copied"
          : kind === "version"
            ? "Dependency tool versions copied"
            : kind === "source"
              ? "Dependency source URLs copied"
              : "Dependency source hashes copied"
    );
  }

  function dependencyToolSummaryJson(tool: ToolStatus) {
    const progress = toolInstallProgressById[tool.id];
    const updateCheck = toolUpdateCheckById[tool.id];
    const source = toolDownloadSources.find((candidate) => candidate.tool_id === tool.id);
    return {
      id: tool.id,
      state: tool.state,
      version: tool.version ?? null,
      path: toolPathInputs[tool.id] ?? tool.path ?? null,
      detected_path: tool.path ?? null,
      managed: tool.managed,
      updatable: tool.updatable,
      last_checked_at: tool.last_checked_at,
      error: tool.error ?? null,
      configured_source: source
        ? {
          url: source.url,
          sha256: source.sha256,
          archive_member: source.archive_member ?? null
        }
        : null,
      install_progress: progress
        ? {
          stage: progress.stage,
          message: progress.message,
          downloaded_bytes: progress.downloaded_bytes ?? null,
          total_bytes: progress.total_bytes ?? null,
          percent: progress.percent ?? null,
          error: progress.error ?? null,
          updated_at: progress.updated_at
        }
        : null,
      update_check: updateCheck
        ? {
          current_version: updateCheck.current_version ?? null,
          latest_version: updateCheck.latest_version ?? null,
          update_available: updateCheck.update_available ?? null,
          source_url: updateCheck.source_url ?? null,
          checked_at: updateCheck.checked_at,
          message: updateCheck.message
        }
        : null
    };
  }

  function dependencyStatusCounts() {
    return toolStatuses.reduce<Record<string, number>>((counts, tool) => {
      counts[tool.state] = (counts[tool.state] ?? 0) + 1;
      return counts;
    }, {});
  }

  async function copyDependencyToolSummary() {
    if (toolStatuses.length === 0) {
      await copyLinesToClipboard([], "No dependency tools", "Dependency summary copied");
      return;
    }
    const counts = dependencyStatusCounts();
    const sourceCount = toolDownloadSources.length;
    const lines = [
      `${toolStatuses.length} tools · installed ${counts.installed ?? 0} · missing ${counts.missing ?? 0} · error ${counts.error ?? 0} · configured sources ${sourceCount}`,
      ...toolStatuses.map((tool) => {
        const source = toolDownloadSources.find((candidate) => candidate.tool_id === tool.id);
        const version = tool.version ? ` · ${tool.version}` : "";
        const managed = tool.managed ? "managed" : "PATH / override";
        const sourceLabel = source ? ` · source ${source.url}` : "";
        const error = tool.error ? ` · error ${tool.error}` : "";
        return `${tool.id}: ${tool.state}${version} · ${managed} · ${toolPathInputs[tool.id] ?? tool.path ?? "no path"}${sourceLabel}${error}`;
      })
    ];
    await copyLinesToClipboard(lines, "No dependency tools", "Dependency summary copied");
  }

  async function copyDependencyToolJson() {
    if (toolStatuses.length === 0) {
      await copyTextToClipboard("", "No dependency tools", "Dependency tools copied");
      return;
    }
    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      busy: Boolean(toolStatusBusy || toolInstallBusy || toolPathBusy),
      status_counts: dependencyStatusCounts(),
      configured_source_count: toolDownloadSources.length,
      tools: toolStatuses.map(dependencyToolSummaryJson),
      configured_sources: toolDownloadSources.map((source) => ({
        tool_id: source.tool_id,
        url: source.url,
        sha256: source.sha256,
        archive_member: source.archive_member ?? null
      }))
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No dependency tools", "Dependency JSON copied");
  }

  async function exportToolsSummary() {
    toolStatusBusy = true;
    try {
      const outputPath = toolsSummaryExportPath.trim() || undefined;
      const path = await exportToolsLocalSummary(outputPath);
      if (path) {
        toolsSummaryExportPath = path;
      }
      toolsLocalSummary = await getToolsLocalSummary();
      pushToast(createToast("Tools summary exported", "success", path ?? "Available in Tauri runtime.", advancedFileToastAction(path)));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Tools summary export failed", "error", message));
    } finally {
      toolStatusBusy = false;
      advancedSettingsBusy = "";
    }
  }

  async function exportToolSettingsBackup() {
    toolStatusBusy = true;
    toolStatusError = "";
    try {
      const result = await exportToolSettings(toolSettingsExportPath.trim() || undefined);
      if (result) {
        toolSettingsExportResult = result;
        toolSettingsExportPath = result.output_path;
      }
      pushToast(createToast(
        "Tool settings exported",
        "success",
        result ? `${result.path_override_count} paths · ${result.download_source_count} sources` : "Export written",
        result ? advancedFileToastAction(result.output_path) : undefined
      ));
    } catch (error) {
      toolStatusError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Tool settings export failed", "error", toolStatusError));
    } finally {
      toolStatusBusy = false;
      advancedSettingsBusy = "";
    }
  }

  async function importToolSettingsBackup() {
    const inputPath = toolSettingsImportPath.trim();
    if (!inputPath) {
      toolStatusError = "Choose a tool settings JSON backup first.";
      pushToast(createToast("Tool settings backup missing", "error", toolStatusError));
      return;
    }

    toolStatusBusy = true;
    toolStatusError = "";
    try {
      const result = await importToolSettings(inputPath);
      if (result) {
        toolSettingsImportResult = result;
        await loadToolStatuses();
      }
      pushToast(createToast(
        "Tool settings imported",
        "success",
        result ? `${result.path_override_count} paths · ${result.download_source_count} sources · skipped ${result.skipped_path_override_count + result.skipped_download_source_count}` : "Import complete",
        settingsSectionToastAction("dependencies")
      ));
    } catch (error) {
      toolStatusError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Tool settings import failed", "error", toolStatusError));
    } finally {
      toolStatusBusy = false;
      advancedSettingsBusy = "";
    }
  }

