    const values = kind === "waveform"
      ? mediaToolsLocalSummary?.waveform_cache_files.map((file) => `${file.file_name} · ${formatBytes(file.size_bytes)} · ${file.path}`) ?? []
      : kind === "subtitle"
        ? mediaToolsLocalSummary?.subtitle_sidecar_files.map((file) => `${file.file_name} · ${formatBytes(file.size_bytes)} · ${file.path}`) ?? []
        : kind === "tool"
          ? mediaToolsLocalSummary?.tool_status_counts.map((entry) => `${entry.key}: ${entry.count}`) ?? []
          : mediaToolsLocalSummary?.review_notes ?? [];
    const labels: Record<typeof kind, [string, string]> = {
      waveform: ["No waveform cache files", "Media waveform cache copied"],
      subtitle: ["No subtitle sidecar files", "Media subtitle sidecars copied"],
      tool: ["No media tool status counts", "Media tool status counts copied"],
