  async function exportMediaToolsSummary() {
    mediaToolsSummaryBusy = "export";
    try {
      const outputPath = mediaToolsSummaryExportPath.trim() || undefined;
      const path = await exportMediaToolsLocalSummary(outputPath);
      if (path) {
        mediaToolsSummaryExportPath = path;
      }
      mediaToolsLocalSummary = await getMediaToolsLocalSummary();
      mediaToolsSummaryError = "";
      pushToast(createToast("Media summary exported", "success", path ?? "Available in Tauri runtime.", advancedFileToastAction(path)));
    } catch (error) {
      mediaToolsSummaryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Media summary export failed", "error", mediaToolsSummaryError));
    } finally {
      mediaToolsSummaryBusy = "";
    }
  }

  async function chooseMediaToolsSummaryExportPath() {
    if (!isTauriRuntime()) {
      pushToast(createToast("Save dialog unavailable", "error", "Run the desktop app to choose a media summary export path."));
      return;
    }
    mediaToolsSummaryBusy = "choose-export";
    try {
      const selected = await save({
        title: "Choose media tools summary export",
        defaultPath: mediaToolsSummaryExportPath.trim() || "fetchdock-media-tools-summary.json",
        filters: [{ name: "Media tools summary", extensions: ["json"] }]
      });
      if (typeof selected === "string") {
        mediaToolsSummaryExportPath = selected;
      }
    } catch (error) {
      mediaToolsSummaryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Media summary export path failed", "error", mediaToolsSummaryError));
    } finally {
      mediaToolsSummaryBusy = "";
    }
  }

