    const values =
      kind === "path"
        ? filteredMusicTracks.map((track) => track.path)
        : kind === "title"
          ? filteredMusicTracks.map((track) => track.title)
          : kind === "artist"
            ? filteredMusicTracks.map((track) => track.artist ?? "")
            : kind === "album"
              ? filteredMusicTracks.map((track) => track.album ?? "")
              : kind === "format"
                ? filteredMusicTracks.map((track) => `${track.title}: ${track.format.toUpperCase()}`)
                : kind === "size"
                  ? filteredMusicTracks.map((track) => `${track.title}: ${formatBytes(track.size_bytes)}`)
                  : kind === "cover"
                    ? filteredMusicTracks.map((track) => track.cover_path ?? "")
                    : kind === "modified"
                      ? filteredMusicTracks.map((track) => track.modified_at ? `${track.title}: ${track.modified_at}` : "")
                      : filteredMusicTracks.map((track) => {
                        const label = musicMetadataLabel(track);
                        return label ? `${track.title}: ${label}` : "";
                      });
    const labels: Record<typeof kind, [string, string]> = {
      path: ["No music track paths", "Music track paths copied"],
      title: ["No music track titles", "Music track titles copied"],
      artist: ["No music track artists", "Music track artists copied"],
      album: ["No music track albums", "Music track albums copied"],
      format: ["No music track formats", "Music track formats copied"],
      size: ["No music track sizes", "Music track sizes copied"],
      cover: ["No music cover paths", "Music cover paths copied"],
      metadata: ["No music metadata labels", "Music metadata labels copied"],
      modified: ["No music modified times", "Music modified times copied"]
    };
    await copyLinesToClipboard(values, labels[kind][0], labels[kind][1]);
  }

  function musicTrackSummaryJson(track: MusicTrack) {
    return {
      path: track.path,
      title: track.title,
      artist: track.artist ?? null,
      album: track.album ?? null,
      format: track.format,
      size_bytes: track.size_bytes,
      cover_path: track.cover_path ?? null,
      metadata_source: track.metadata_source ?? null,
      metadata_label: musicMetadataLabel(track) || null,
      modified_at: track.modified_at ?? null
    };
