  async function copyFilteredMusicTrackSummary() {
    const lines = filteredMusicTracks.map((track) => {
      const artist = track.artist ? ` · ${track.artist}` : "";
      const album = track.album ? ` · ${track.album}` : "";
      const metadata = musicMetadataLabel(track) ? ` · ${musicMetadataLabel(track)}` : "";
      return `${track.title} · ${track.format.toUpperCase()} · ${formatBytes(track.size_bytes)}${artist}${album}${metadata} · ${track.path}`;
    });
    await copyLinesToClipboard(lines, "No music tracks", "Music track summary copied");
  }

