  async function exportMusicFormatCatalogFile() {
    musicBusy = true;
    musicBusyMode = "format-catalog-export";
    musicError = "";
    try {
      const path = await exportMusicFormatCatalog(musicFormatCatalogExportPath.trim() || undefined);
      if (path) {
        musicFormatCatalogExportPath = path;
        musicFormatCatalogExportResult = path;
        pushToast(createToast("Music format catalog exported", "success", path, advancedFileToastAction(path)));
      }
      musicFormatCatalog = await getMusicFormatCatalog();
      await loadAdvancedFiles();
    } catch (error) {
      musicError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Music format catalog export failed", "error", musicError));
    } finally {
      musicBusy = false;
      musicBusyMode = "";
    }
  }

  async function exportMusicSummary() {
    musicBusy = true;
    musicBusyMode = "summary-export";
    musicError = "";
    try {
      const path = await exportMusicLocalSummary(musicSummaryExportPath.trim() || undefined);
      if (path) {
        musicSummaryExportPath = path;
        musicSummaryExportResult = path;
        pushToast(createToast("Music summary exported", "success", path, advancedFileToastAction(path)));
      }
      await refreshMusicLocalSummary();
      await loadAdvancedFiles();
    } catch (error) {
      musicError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Music summary export failed", "error", musicError));
    } finally {
      musicBusy = false;
      musicBusyMode = "";
    }
  }

