  async function copyVisibleMusicPlaybackSummary() {
    const stats = musicPlaybackStats;
    if (!stats) {
      await copyLinesToClipboard([], "No music playback stats", "Music playback summary copied");
      return;
    }
    const topLines = visibleMusicTopTracks(stats).map((item) => `${item.track.title} · ${item.play_count} plays · ${Math.round(item.played_seconds / 60)} min · last ${item.last_played_at}`);
    const recentLines = visibleMusicRecentPlays(stats).map((event) => `${event.track.title} · ${event.played_at} · ${event.played_seconds}s`);
    await copyLinesToClipboard([
      `${stats.play_count} plays · ${Math.round(stats.played_seconds / 60)} minutes recorded`,
      ...topLines,
      ...recentLines
    ], "No music playback stats", "Music playback summary copied");
  }

  async function copyVisibleMusicPlaybackJson() {
    const stats = musicPlaybackStats;
    if (!stats) {
      await copyTextToClipboard("", "No music playback stats", "Music playback copied");
      return;
    }
    const payload = {
      schema_version: 1,
      exported_at: new Date().toISOString(),
      play_count: stats.play_count,
      played_seconds: stats.played_seconds,
      top_tracks_expanded: musicTopTracksExpanded,
      recent_expanded: musicRecentPlaysExpanded,
      top_tracks: visibleMusicTopTracks(stats).map((item) => ({
        play_count: item.play_count,
        played_seconds: item.played_seconds,
        last_played_at: item.last_played_at,
        track: musicTrackSummaryJson(item.track)
      })),
      recent: visibleMusicRecentPlays(stats).map((event) => ({
        played_at: event.played_at,
        played_seconds: event.played_seconds,
        track: musicTrackSummaryJson(event.track)
      }))
    };
    await copyTextToClipboard(JSON.stringify(payload, null, 2), "No music playback stats", "Music playback JSON copied");
  }

  function setChannelHistoryQuickStatus(status: string) {
    channelHistoryStatusFilter = status;
    channelHistorySearch = "";
    channelHistoryExpanded = status !== "all";
  }

  function setBilibiliImportQuickCollection(collection: "all" | "watch_later" | "history") {
    bilibiliImportCollectionFilter = collection;
    bilibiliImportSearch = "";
    bilibiliImportsExpanded = collection !== "all";
  }

  function normalizeDownloadStatusFilter(value: string): DownloadStatusFilter | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    return downloadStatusFilters.some((filter) => filter.id === normalized) ? (normalized as DownloadStatusFilter) : "";
  }

  function normalizeDownloadKindFilter(value: string): DownloadKindFilter | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    return downloadKindFilters.some((filter) => filter.id === normalized) ? (normalized as DownloadKindFilter) : "";
  }

  function normalizeDownloadViewMode(value: string): "active" | "history" | "all" | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (normalized === "active" || normalized === "queue" || normalized === "queued") {
      return "active";
    }
    if (normalized === "history" || normalized === "historical" || normalized === "archive") {
      return "history";
    }
    if (normalized === "all" || normalized === "everything") {
      return "all";
    }
    return "";
  }

  function normalizeChannelHistoryStatus(value: string): string {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (["pending", "queued", "error", "ready", "all"].includes(normalized)) {
      return normalized;
    }
    return "all";
  }

  function normalizeSettingsSection(value: string): SettingsSearchResult["section_id"] | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    const sections: SettingsSearchResult["section_id"][] = [
      "paths",
      "infrastructure",
      "dependencies",
      "appearance",
      "downloads",
      "network",
      "cookies",
      "extension",
      "channels",
      "plugins",
      "ai",
      "advanced"
    ];
    return sections.includes(normalized as SettingsSearchResult["section_id"])
      ? (normalized as SettingsSearchResult["section_id"])
      : "";
  }

  function normalizeTelegramMediaType(value: string): TelegramMediaItem["media_type"] | "all" | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (normalized === "all") {
      return "all";
    }
    return telegramCloneMediaTypeOptions.includes(normalized as TelegramMediaItem["media_type"])
      ? (normalized as TelegramMediaItem["media_type"])
      : "";
  }

  function normalizePluginStateFilter(value: string): PluginInfo["state"] | "all" | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    const states: Array<PluginInfo["state"] | "all"> = ["all", "enabled", "disabled", "installed", "failed", "incompatible"];
    return states.includes(normalized as PluginInfo["state"] | "all")
      ? (normalized as PluginInfo["state"] | "all")
      : "";
  }

  function normalizeBilibiliCollection(value: string): "watch_later" | "history" | "all" | "" {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (normalized === "watch_later" || normalized === "history" || normalized === "all") {
      return normalized;
    }
    return "";
  }

  function normalizeLibraryFormatFilter(value: string): string {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (!normalized) {
      return "";
    }
    return libraryFormatOptions.includes(normalized) ? normalized : "";
  }

  function normalizeMusicFormatFilter(value: string): string {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (!normalized) {
      return "";
    }
    return musicFormatOptions.includes(normalized) ? normalized : "";
