  function normalizeP2pOfferStatus(value: string): string {
    const normalized = value.trim().toLowerCase().replaceAll("-", "_");
    if (["all", "waiting", "serving", "paused", "receive_ready", "completed", "canceled", "expired"].includes(normalized)) {
