  function focusCoursesTarget(target: {
    courseId?: string;
    lessonId?: string;
    attachmentId?: string;
    taskId?: string;
    query?: string;
  }) {
    const value = target.query || target.courseId || target.lessonId || target.attachmentId || "";
    const matchedCourse = courses.find(
      (course) =>
        course.id === target.courseId ||
        course.lessons.some((lesson) => lesson.id === target.lessonId || lesson.id === value) ||
        course.attachments.some((attachment) => attachment.id === target.attachmentId || attachment.id === value)
    );
    const lesson = matchedCourse?.lessons.find((item) => item.id === target.lessonId || item.id === value);
    const attachment = matchedCourse?.attachments.find((item) => item.id === target.attachmentId || item.id === value);

    if (matchedCourse) {
      courseSearchQuery = matchedCourse.id;
    } else if (target.taskId && !target.query) {
      courseTransferSearch = target.taskId;
      courseTransfersExpanded = true;
    } else if (value) {
      courseSearchQuery = value;
      courseTransferSearch = value;
    }

    if (target.taskId) {
      courseTransferSearch = target.taskId;
      courseTransfersExpanded = true;
    }

    if (matchedCourse && lesson) {
      courseSearchQuery = lesson.id;
      courseExpandedLessonIds = { ...courseExpandedLessonIds, [matchedCourse.id]: true };
      if (lesson.local_path && courseLessonPreviewKind(lesson)) {
        previewCourseLessonMedia(matchedCourse, lesson);
      }
    }

    if (matchedCourse && attachment) {
      courseSearchQuery = attachment.id;
      courseExpandedAttachmentIds = { ...courseExpandedAttachmentIds, [matchedCourse.id]: true };
      if (attachment.local_path && canPreviewCourseAttachment(attachment)) {
        previewCourseAttachment(matchedCourse, attachment);
      }
    }
  }

  function focusTelegramTarget(target: {
    chatId?: string;
    mediaId?: string;
    taskId?: string;
    query?: string;
    mediaType?: TelegramMediaItem["media_type"] | "all" | "";
  }) {
    if (target.mediaType) {
      telegramBrowserMediaType = target.mediaType;
    }

    const value = target.query || target.mediaId || target.chatId || "";
    const matchedChat = telegramChats.find(
      (chat) =>
        chat.id === target.chatId ||
        chat.id === value ||
        chat.media.some((media) => media.id === target.mediaId || media.id === value)
    );
    const media = matchedChat?.media.find((item) => item.id === target.mediaId || item.id === value);

    if (matchedChat) {
      telegramBrowserSearch = media?.id ?? matchedChat.id;
      telegramCloneChatId = matchedChat.id;
      telegramChatsExpanded = true;
      telegramExpandedMediaChatIds = { ...telegramExpandedMediaChatIds, [matchedChat.id]: true };
      if (matchedChat.kind === "channel" || matchedChat.kind === "group") {
        telegramChannelDrawerSelectedId = matchedChat.id;
        telegramChannelDrawerExpanded = true;
      }
    } else if (target.taskId && !target.query) {
      telegramTransferSearch = target.taskId;
      telegramTransfersExpanded = true;
    } else if (value) {
      telegramBrowserSearch = value;
      telegramTransferSearch = value;
    }

    if (target.taskId) {
      telegramTransferSearch = target.taskId;
      telegramTransfersExpanded = true;
    }

    if (media && canPreviewTelegramMedia(media)) {
      telegramPreviewMedia = media;
    }
  }

  function focusPluginTarget(target: {
    pluginId?: string;
    state?: PluginInfo["state"] | "all" | "";
    query?: string;
    marketplaceId?: string;
  }) {
    if (target.state) {
      pluginStateFilter = target.state;
    }

    const value = target.query || target.pluginId || target.marketplaceId || "";
    if (target.marketplaceId) {
      pluginMarketplaceSearch = target.marketplaceId;
      pluginMarketplaceExpanded = true;
      return;
    }

    if (target.pluginId || target.query) {
      pluginSearchQuery = value;
      const plugin = plugins.find((item) => item.id === value);
      if (plugin?.nav_items.length && plugin.state === "enabled") {
        navigate(`plugin:${plugin.id}:${plugin.nav_items[0].id}`);
      }
    }
  }

