  function upsertToolStatus(updated: ToolStatus | null) {
    if (!updated) {
      return;
    }

    toolStatuses = toolStatuses.map((tool) => (tool.id === updated.id ? updated : tool));
    toolPathInputs = { ...toolPathInputs, [updated.id]: updated.path ?? "" };
  }

  async function chooseToolExecutable(tool: ToolStatus) {
    if (!isTauriRuntime()) {
      pushToast(createToast("File picker unavailable", "error", "Run the desktop app to choose an executable."));
      return;
    }

    toolPathBusy = tool.id;
    try {
      const selected = await open({
        title: `Choose ${tool.id} executable`,
        directory: false,
        multiple: false,
        defaultPath: toolPathInputs[tool.id]?.trim() || tool.path || undefined
      });
      if (typeof selected === "string") {
        toolPathInputs = { ...toolPathInputs, [tool.id]: selected };
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Executable selection failed", "error", message));
    } finally {
      toolPathBusy = "";
    }
  }

  async function saveToolPath(tool: ToolStatus) {
    const path = toolPathInputs[tool.id]?.trim() ?? "";
    if (!path) {
      pushToast(createToast("Tool path required", "error", `Choose a path for ${tool.id}.`));
      return;
    }

    toolPathBusy = tool.id;
    try {
      const updated = await setToolPath(tool.id, path);
      upsertToolStatus(updated);
      toolStatusError = "";
      pushToast(createToast("Tool path saved", "success", tool.id, settingsSectionToastAction("dependencies")));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Tool path rejected", "error", message));
    } finally {
      toolPathBusy = "";
    }
  }

