    toolPathBusy = tool.id;
    try {
      const updated = await clearToolPath(tool.id);
      upsertToolStatus(updated);
      toolStatusError = "";
      pushToast(createToast("Tool path cleared", "success", tool.id, settingsSectionToastAction("dependencies")));
