  async function saveToolDownloadSource(tool: ToolStatus) {
    const url = toolSourceUrlInputs[tool.id]?.trim() ?? "";
    const sha256 = toolSourceSha256Inputs[tool.id]?.trim() ?? "";
    const archiveMember = toolSourceArchiveInputs[tool.id]?.trim() ?? "";
    if (!url || !sha256) {
      pushToast(createToast("Tool source incomplete", "error", `Add a URL and SHA-256 for ${tool.id}.`));
      return;
    }

    toolSourceBusy = tool.id;
    try {
      const saved = await setToolDownloadSource(tool.id, url, sha256, archiveMember || undefined);
      if (saved) {
        syncToolDownloadSources([
          ...toolDownloadSources.filter((source) => source.tool_id !== saved.tool_id),
          saved
        ]);
      }
      toolStatusError = "";
      await loadToolStatuses();
      pushToast(createToast("Tool source saved", "success", tool.id, settingsSectionToastAction("dependencies")));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Tool source rejected", "error", message));
    } finally {
      toolSourceBusy = "";
    }
  }

  async function clearSavedToolDownloadSource(tool: ToolStatus) {
    toolSourceBusy = tool.id;
    try {
      syncToolDownloadSources(await clearToolDownloadSource(tool.id));
      toolStatusError = "";
      await loadToolStatuses();
      pushToast(createToast("Tool source cleared", "success", tool.id, settingsSectionToastAction("dependencies")));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Tool source clear failed", "error", message));
    } finally {
      toolSourceBusy = "";
    }
