  async function checkToolUpdateStatus(tool: ToolStatus) {
    toolUpdateCheckBusy = tool.id;
    try {
      const result = await checkToolUpdate(tool.id);
      if (result) {
        toolUpdateCheckById = { ...toolUpdateCheckById, [tool.id]: result };
        pushToast(createToast(
          result.update_available ? "Tool update available" : "Tool checked",
          result.update_available ? "success" : "info",
          result.message,
          settingsSectionToastAction("dependencies")
        ));
      }
      toolStatusError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast("Tool update check failed", "error", message));
    } finally {
      toolUpdateCheckBusy = "";
    }
  }

  async function requestToolInstall(tool: ToolStatus) {
    toolInstallBusy = tool.id;
    const isUpdate = tool.state === "installed" && tool.managed && tool.updatable;
    toolInstallProgressById = {
      ...toolInstallProgressById,
      [tool.id]: {
        schema_version: 1,
        tool_id: tool.id,
        stage: "starting",
        message: `Starting dependency ${isUpdate ? "update" : "install"} for ${tool.id}.`,
        updated_at: new Date().toISOString()
      }
    };
    try {
      const updated = isUpdate ? await updateTool(tool.id) : await installTool(tool.id);
      upsertToolStatus(updated);
      toolStatusError = "";
      await loadToolStatuses();
      if (updated?.state === "installed") {
        pushToast(createToast(isUpdate ? "Tool updated" : "Tool installed", "success", updated.id, settingsSectionToastAction("dependencies")));
        return;
      }

      const message =
        updated?.error ?? `Automatic ${isUpdate ? "update" : "install"} did not produce an installed tool.`;
      pushToast(createToast(isUpdate ? "Update did not complete" : "Install did not complete", "error", message));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      toolStatusError = message;
      pushToast(createToast(isUpdate ? "Update request failed" : "Install request failed", "error", message));
    } finally {
      toolInstallBusy = "";
    }
  }

  async function runSettingsSearch() {
    const query = settingsQuery.trim();
    settingsSearchError = "";
    activeSettingsSectionId = "";
    if (!query) {
      settingsSearchResults = [];
      return;
    }

    settingsSearchBusy = true;
    try {
      settingsSearchResults = await searchSettings(query);
    } catch (error) {
      settingsSearchError = error instanceof Error ? error.message : String(error);
      settingsSearchResults = [];
    } finally {
      settingsSearchBusy = false;
    }
  }

  function focusSettingsSection(sectionId: SettingsSearchResult["section_id"]) {
    activeSettingsSectionId = sectionId;
    document.getElementById(`settings-${sectionId}`)?.scrollIntoView({
      block: "start",
      behavior: "smooth"
    });
  }

  function handleSettingsSearchKeydown(event: KeyboardEvent) {
    if (event.key === "Enter") {
      event.preventDefault();
      void runSettingsSearch();
    }
  }

  function handleToolInstallProgress(event: ToolInstallProgressEvent) {
    toolInstallProgressById = {
      ...toolInstallProgressById,
      [event.tool_id]: event
    };
  }

  function handleBilibiliImportsChanged(event: BilibiliImportsChangedEvent) {
    bilibiliImportedItems = event.items;
    bilibiliAccountStatus = event.account_status;
    void getBilibiliLocalSummary().then((summary) => {
      bilibiliLocalSummary = summary;
    });
  }

  function handleDiagnosticsFilesChanged(event: DiagnosticsFilesChangedEvent) {
    diagnosticsFiles = event.diagnostics;
    downloadLogFiles = event.logs;
    downloadLogListResponse = null;
    if (advancedFilePreview) {
      const paths = new Set([...diagnosticsFiles, ...downloadLogFiles].map((file) => file.path));
      if (!paths.has(advancedFilePreview.file.path)) {
        advancedFilePreview = null;
      }
    }
  }

  function handleKeydown(event: KeyboardEvent) {
    const commandKey = event.ctrlKey || event.metaKey;
    if (commandKey && event.key.toLowerCase() === "k") {
      event.preventDefault();
      commandOpen = true;
      return;
    }

    if (event.key === "Escape") {
      commandOpen = false;
    }
  }

  function pushToast(toast: ToastMessage) {
    toasts = [toast, ...toasts].slice(0, 4);
    window.setTimeout(() => {
      toasts = toasts.filter((item) => item.id !== toast.id);
    }, 4200);
  }

  function handleToastShow(event: ToastShowEvent) {
    pushToast(createToast(event.title, event.level, event.message ?? undefined, actionFromToastCommand(event.action)));
  }

  async function handleChannelNewItems(event: ChannelNewItemsEvent) {
    await loadChannels();
    pushToast(
      createToast(
        "Channel updated",
        "info",
        `${event.item_count} new item${event.item_count === 1 ? "" : "s"} found.`,
        { label: "Open history", onClick: openChannelNotifications }
      )
    );
  }

  function handleChannelsChanged(event: ChannelsChangedEvent) {
    syncChannels(event.channels, event.history, event.settings);
  }

  async function handleLibraryChanged(event: LibraryChangedEvent) {
    if (event.domain === "books") {
      await loadLibraryCatalog();
      if (event.reason.includes("reader_settings")) {
        await loadLibraryReaderSettings();
      }
      return;
    }

    if (event.domain === "music") {
      await loadMusicState();
      return;
    }

    if (event.domain === "courses") {
      await loadCourses();
      await loadLearning();
      return;
    }

    if (event.domain === "notes") {
      await loadLearning();
    }
  }

  function handleP2pOffersChanged(event: P2pOffersChangedEvent) {
    p2pOffers = event.offers;
    if (p2pActiveOffer) {
      p2pActiveOffer = p2pOffers.find((offer) => offer.short_code === p2pActiveOffer?.short_code) ?? null;
    }
  }

  function handleTelegramManifestChanged(event: TelegramManifestChangedEvent) {
    telegramChats = event.chats;
    telegramSyncStatus = event.sync_status;
    telegramSearchResults = null;
    if (telegramCloneChatId && !telegramChats.some((chat) => chat.id === telegramCloneChatId)) {
      telegramCloneChatId = telegramChats[0]?.id ?? "";
    } else if (!telegramCloneChatId && telegramChats.length > 0) {
      telegramCloneChatId = telegramChats[0].id;
    }
    void loadTelegramLocalSummary();
  }

  async function handleShellOpen(request: ShellOpenRequest) {
    if (handleShellOpenTarget(request.target)) {
      return;
    }

    navigate("home");
    commandOpen = false;

    const capturedUrl = request.url ? extractCapturedUrl(request.url) : "";
    if (capturedUrl) {
      const capturedKind = request.url ? extractCapturedKind(request.url) : null;
      const capturedTitle = request.url ? extractCapturedTitle(request.url) : "";
      homeUrl = capturedUrl;
      await createCapturedTask(
        capturedUrl,
        request.source === "deep_link" ? "Link captured" : "Shortcut captured",
        capturedKind,
        capturedTitle
      );
      return;
    }

    pushToast(
      createToast(
        request.source === "deep_link" ? "Link captured" : "Shortcut captured",
        "success",
        capturedUrl || request.message
      )
    );
  }

  async function submitHomeUrl() {
    await maybeAutoSelectCookieBucket(homeUrl);
    maybeAutoSelectTaskAuthorizationPayload(homeUrl);
    await createCapturedTask(homeUrl, "Link queued");
  }

  async function pasteClipboardUrl() {
    clipboardBusy = true;
    try {
      const text = await readClipboardText();
      const url = extractFirstHttpUrl(text ?? "");
      if (!url) {
        pushToast(createToast("No clipboard URL", "error", "Clipboard text does not contain an http or https URL."));
        return;
      }

      homeUrl = url;
      await maybeAutoSelectCookieBucket(url);
      maybeAutoSelectTaskAuthorizationPayload(url);
      pushToast(createToast("Clipboard URL pasted", "success", url, targetToastAction("Open", "home", { query: url })));
    } catch (error) {
      pushToast(createToast("Clipboard read failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      clipboardBusy = false;
    }
  }

  async function pasteClipboardBatchUrls() {
    clipboardBusy = true;
    try {
      const text = await readClipboardText();
      const urls = extractBatchUrls(text ?? "");
      if (urls.length === 0) {
        pushToast(createToast("No clipboard URLs", "error", "Clipboard text does not contain http or https URLs."));
        return;
      }

      const existing = batchUrls.trim();
      batchUrls = existing ? `${existing}\n${urls.join("\n")}` : urls.join("\n");
      pushToast(createToast("Batch URLs pasted", "success", `${urls.length} URL${urls.length === 1 ? "" : "s"} added.`));
    } catch (error) {
      pushToast(createToast("Clipboard read failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      clipboardBusy = false;
    }
  }

  async function submitBatchUrls() {
    const batchEntries = batchUrlEntriesFromText(batchUrls);
    const urls = batchEntries.map((entry) => entry.sourceUrl);
    if (urls.length === 0) {
      batchFailures = [];
      batchFailureLineNumbers = [];
      pushToast(createToast("No batch URLs", "error", "Paste one or more URLs before creating tasks."));
      return;
    }
    if (urls.length > 1 && taskOutputPath.trim()) {
      batchFailures = [];
      batchFailureLineNumbers = [];
      pushToast(createToast("Batch output file conflict", "error", "Clear Output file for multi-URL batches, or use Output folder instead."));
      return;
    }

    captureBusy = true;
    try {
      await maybeAutoSelectCookieBucket(urls[0]);
      maybeAutoSelectTaskAuthorizationPayload(urls[0]);
      const result = await createDownloadTaskItems(
        urls.map((url) => ({
          sourceUrl: url,
          options: buildHomeCreateOptions(inferHomeTaskKind(url, taskKind))
        }))
      );
      if (result) {
        downloads = [...result.created, ...downloads.filter((task) => !result.created.some((item) => item.id === task.id))].sort(
          (first, second) => first.position - second.position
        );
        batchFailures = result.failed;
        batchFailureLineNumbers = batchEntries.map((entry) => entry.lineNumber);
        const failedMessage = result.failed.length > 0 ? `, ${result.failed.length} failed` : "";
        const detail = result.failed.length > 0 ? `${result.created.length} created${failedMessage}; see batch failures below.` : `${result.created.length} created`;
        pushToast(createToast("Batch queued", "success", detail, firstTaskToastAction(result.created)));
      }
    } catch (error) {
      pushToast(createToast("Batch failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      captureBusy = false;
    }
  }

  async function importBatchFile(event: Event) {
    const input = event.currentTarget as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) {
      return;
    }

    batchFileBusy = true;
    try {
      const urls = extractBatchUrls(await file.text());
      if (urls.length === 0) {
        pushToast(createToast("No batch URLs in file", "error", `${file.name} did not contain any http or https URLs.`));
        return;
      }

      const existing = batchUrls.trim();
      batchUrls = existing ? `${existing}\n${urls.join("\n")}` : urls.join("\n");
      pushToast(createToast("Batch file imported", "success", `${urls.length} URL${urls.length === 1 ? "" : "s"} added.`, targetToastAction("Open", "home", { query: urls[0] ?? "" })));
    } catch (error) {
      pushToast(createToast("Import failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      batchFileBusy = false;
      input.value = "";
    }
  }

  async function createCapturedTask(
    url: string,
    successTitle: string,
    capturedKind: DownloadKind | null = null,
    capturedTitle = ""
  ) {
    const normalizedUrl = url.trim();
    if (!normalizedUrl) {
      pushToast(createToast("No URL entered", "error", "Paste or capture a URL before creating a task."));
      return;
    }

    await maybeAutoSelectCookieBucket(normalizedUrl);
    maybeAutoSelectTaskAuthorizationPayload(normalizedUrl);
    const selectedKind = capturedKind ?? taskKind;
    if (selectedKind === "torrent" || normalizedUrl.toLowerCase().startsWith("magnet:") || normalizedUrl.toLowerCase().endsWith(".torrent")) {
      await createHomeTorrentTask(normalizedUrl, successTitle);
      return;
    }

    if (selectedKind === "p2p") {
      await createHomeP2pTask(normalizedUrl, successTitle);
      return;
    }

    if (selectedKind === "course") {
      await createHomeCourseEntry(normalizedUrl, successTitle);
      return;
    }

    const queueKind = inferHomeTaskKind(normalizedUrl, selectedKind);
    captureBusy = true;
    try {
      const task = await createDownloadTask(
        normalizedUrl,
        taskTitleHint.trim() || capturedTitle.trim() || undefined,
        buildHomeCreateOptions(queueKind)
      );
      if (task) {
        downloads = [task, ...downloads.filter((item) => item.id !== task.id)].sort(
          (first, second) => first.position - second.position
        );
      }
      pushToast(createToast(successTitle, "success", `${queueKind} · ${normalizedUrl}`, task ? targetToastAction("Task", "downloads", { task_id: task.id }) : undefined));
    } catch (error) {
      pushToast(createToast("Task was not created", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      captureBusy = false;
    }
  }

  async function createHomeTorrentTask(value: string, successTitle: string) {
    captureBusy = true;
    try {
      let task: DownloadTask | null = null;
      if (value.toLowerCase().startsWith("magnet:")) {
        task = await queueMagnetUri(value, taskOutputDir.trim() || undefined, buildHomeCreateOptions("torrent"));
      } else {
        const metadata = await parseTorrentFile(value);
        const selectedPaths = metadata?.files.map((file) => file.path) ?? [];
        task = await queueTorrentFile(value, taskOutputDir.trim() || undefined, selectedPaths, buildHomeCreateOptions("torrent"));
      }
      if (task) {
        downloads = [task, ...downloads.filter((item) => item.id !== task.id)].sort(
          (first, second) => first.position - second.position
        );
        pushToast(createToast(successTitle, "success", `${task.kind} · ${task.title}`, targetToastAction("Task", "downloads", { task_id: task.id })));
      }
    } catch (error) {
      pushToast(createToast("Torrent task was not created", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      captureBusy = false;
    }
  }

  async function createHomeP2pTask(value: string, successTitle: string) {
    captureBusy = true;
    try {
      const task = await queueP2pReceive(value, buildHomeCreateOptions("p2p"));
      if (task) {
        downloads = [task, ...downloads.filter((item) => item.id !== task.id)].sort(
