  async function maybeAutoSelectCookieBucket(url: string) {
    const normalizedUrl = url.trim();
    if (!/^https?:\/\//i.test(normalizedUrl) || cookieBuckets.length === 0) {
      return;
    }
    if (taskCookieBucketId && taskCookieBucketId !== taskCookieBucketAutoMatchedId) {
      return;
    }
    if (taskCookieBucketAutoMatchedUrl === normalizedUrl) {
      return;
    }
    try {
      const matches = await matchCookieBuckets(normalizedUrl);
      cookieMatchedBuckets = matches;
      cookieMatchUrl = normalizedUrl;
      taskCookieBucketAutoMatchedUrl = normalizedUrl;
      if (matches.length > 0) {
        taskCookieBucketId = matches[0].id;
        taskCookieBucketAutoMatchedId = matches[0].id;
        pushToast(createToast("Cookie bucket selected", "success", `${matches[0].name} matches this URL.`, targetToastAction("Open", "cookies", { bucket_id: matches[0].id })));
      } else {
        const autoMatchedId = taskCookieBucketAutoMatchedId;
        taskCookieBucketAutoMatchedId = "";
        if (taskCookieBucketId && taskCookieBucketId === autoMatchedId) {
          taskCookieBucketId = "";
        }
      }
    } catch {
      taskCookieBucketAutoMatchedUrl = "";
      taskCookieBucketAutoMatchedId = "";
    }
  }

  async function maybeAutoSelectToolsCookieBucket(url: string) {
    const normalizedUrl = url.trim();
    if (!/^https?:\/\//i.test(normalizedUrl) || cookieBuckets.length === 0) {
      return;
    }
    if (toolsCookieBucketId && toolsCookieBucketId !== toolsCookieBucketAutoMatchedId) {
      return;
    }
    if (toolsCookieBucketAutoMatchedUrl === normalizedUrl) {
