  function hostFromUrl(value: string | null | undefined): string {
    const trimmed = (value ?? "").trim();
    if (!trimmed) {
      return "";
    }
    try {
      return new URL(trimmed).hostname.toLowerCase();
    } catch {
      return "";
    }
  }

  function hostMatchesAuthPayload(urlHost: string, payload: ExtensionAuthorizationPayloadInfo): boolean {
    const candidates = [
      payload.request_host,
      payload.host,
      hostFromUrl(payload.request_url),
      hostFromUrl(payload.page_url)
    ]
      .map((value) => (value ?? "").trim().toLowerCase())
      .filter(Boolean);
    return candidates.some((host) => urlHost === host || urlHost.endsWith(`.${host}`) || host.endsWith(`.${urlHost}`));
  }

  function matchingAuthorizationPayloadForUrl(url: string): ExtensionAuthorizationPayloadInfo | null {
    const normalizedUrl = url.trim();
    if (!/^https?:\/\//i.test(normalizedUrl) || extensionAuthPayloads.length === 0) {
      return null;
    }
    const urlHost = hostFromUrl(normalizedUrl);
    if (!urlHost) {
      return null;
    }
    return extensionAuthPayloads.find((payload) => hostMatchesAuthPayload(urlHost, payload)) ?? null;
  }

  function maybeAutoSelectTaskAuthorizationPayload(url: string) {
    const normalizedUrl = url.trim();
    if (taskAuthPayloadRef && taskAuthPayloadRef !== taskAuthPayloadAutoMatchedRef) {
      return;
    }
    if (taskAuthPayloadAutoMatchedUrl === normalizedUrl) {
      return;
    }
    const payload = matchingAuthorizationPayloadForUrl(normalizedUrl);
    taskAuthPayloadAutoMatchedUrl = normalizedUrl;
    if (payload) {
      taskAuthPayloadRef = payload.payload_ref;
      taskAuthPayloadAutoMatchedRef = payload.payload_ref;
      taskReferer = taskReferer || payload.page_url;
      pushToast(createToast("Authorization payload selected", "success", payload.request_host ?? payload.host, targetToastAction("Open", "extension", { payload_ref: payload.payload_ref, kind: "authorization" })));
    } else {
      const autoMatchedRef = taskAuthPayloadAutoMatchedRef;
      taskAuthPayloadAutoMatchedRef = "";
      if (taskAuthPayloadRef && taskAuthPayloadRef === autoMatchedRef) {
        taskAuthPayloadRef = "";
      }
    }
  }

  function maybeAutoSelectToolsAuthorizationPayload(url: string) {
    const normalizedUrl = url.trim();
    if (toolsAuthPayloadRef && toolsAuthPayloadRef !== toolsAuthPayloadAutoMatchedRef) {
      return;
    }
    if (toolsAuthPayloadAutoMatchedUrl === normalizedUrl) {
      return;
    }
    const payload = matchingAuthorizationPayloadForUrl(normalizedUrl);
    toolsAuthPayloadAutoMatchedUrl = normalizedUrl;
    if (payload) {
      toolsAuthPayloadRef = payload.payload_ref;
      toolsAuthPayloadAutoMatchedRef = payload.payload_ref;
      toolsReferer = toolsReferer || payload.page_url;
      pushToast(createToast("Tools auth payload selected", "success", payload.request_host ?? payload.host, targetToastAction("Open", "tools", { query: normalizedUrl })));
    } else {
      const autoMatchedRef = toolsAuthPayloadAutoMatchedRef;
      toolsAuthPayloadAutoMatchedRef = "";
      if (toolsAuthPayloadRef && toolsAuthPayloadRef === autoMatchedRef) {
        toolsAuthPayloadRef = "";
      }
    }
  }

  function clearTaskAuthorizationPayloadSelection() {
    taskAuthPayloadRef = "";
    taskAuthPayloadAutoMatchedUrl = "";
    taskAuthPayloadAutoMatchedRef = "";
  }

  function clearToolsAuthorizationPayloadSelection() {
    toolsAuthPayloadRef = "";
    toolsAuthPayloadAutoMatchedUrl = "";
    toolsAuthPayloadAutoMatchedRef = "";
  }

  function buildHomeProbeOptions() {
    return {
      userAgent: taskUserAgent,
      referer: taskReferer,
      proxy: taskProxy,
      cookieBucketId: taskCookieBucketId,
      authPayloadRef: taskAuthPayloadRef,
      rateLimit: taskRateLimit
    };
  }

  function buildToolsProbeOptions() {
    return {
      userAgent: toolsUserAgent,
      referer: toolsReferer,
      proxy: toolsProxy,
      cookieBucketId: toolsCookieBucketId,
      authPayloadRef: toolsAuthPayloadRef,
      rateLimit: toolsRateLimit
    };
  }

  function buildToolsCreateOptions(kind: DownloadKind, thumbnailUrl?: string | null) {
    const hasSelectedSubtitles = toolsSelectedSubtitleKeys.length > 0;
    const canAttachSubtitleOptions = kind === "video" || kind === "audio" || kind === "playlist";
    const shouldAttachSubtitleOptions = kind === "subtitles_only" || (canAttachSubtitleOptions && hasSelectedSubtitles);
    return buildTaskCreateOptions({
      kind,
      outputDir: toolsOutputDir,
      userAgent: toolsUserAgent,
      referer: toolsReferer,
      proxy: toolsProxy,
      cookieBucketId: toolsCookieBucketId,
      authPayloadRef: toolsAuthPayloadRef,
      rateLimit: toolsRateLimit,
      liveFromStart: false,
      concurrentFragments: "",
      audioFormat: taskAudioFormat,
      selectedFormatId: "",
      thumbnailUrl,
      subtitleLanguages: shouldAttachSubtitleOptions
        ? uniqueTrimmedList(toolsSelectedSubtitleKeys.map(subtitleLanguageFromKey))
        : undefined,
      subtitleAuto: shouldAttachSubtitleOptions ? subtitleSelectionUsesAuto(toolsSelectedSubtitleKeys) : undefined,
      subtitleEmbed: kind === "subtitles_only" ? false : shouldAttachSubtitleOptions ? subtitleEmbedInput : undefined,
      subtitleKeepVtt: kind === "subtitles_only" ? true : shouldAttachSubtitleOptions ? subtitleKeepVttInput : undefined
    });
  }

