  async function queueHomePlaylistEntries() {
    const entries = metadataPlaylistPreview?.entries ?? [];
    const queueableEntries = entries.filter((entry) => playlistEntryUrl(entry));
    if (queueableEntries.length === 0) {
      pushToast(createToast("No playlist URLs", "error", "Probe a playlist with item URLs before queueing entries."));
      return;
    }

    await maybeAutoSelectCookieBucket(metadataPlaylistPreviewUrl || metadataPreviewUrl || homeUrl);
    maybeAutoSelectTaskAuthorizationPayload(metadataPlaylistPreviewUrl || metadataPreviewUrl || homeUrl);
    metadataPlaylistQueueBusy = true;
    try {
      const result = await createDownloadTaskItems(
        queueableEntries.map((entry) => ({
          sourceUrl: playlistEntryUrl(entry),
          titleOverride: entry.title ?? undefined,
          options: {
            ...buildHomeCreateOptions("video"),
            thumbnailUrl: entry.thumbnail_url ?? undefined
          }
        }))
      );
      if (result) {
        downloads = [...result.created, ...downloads.filter((task) => !result.created.some((item) => item.id === task.id))].sort(
          (first, second) => first.position - second.position
        );
        const failedMessage = result.failed.length > 0 ? `, ${result.failed.length} failed` : "";
        pushToast(createToast("Playlist entries queued", "success", `${result.created.length} created${failedMessage}`, firstTaskToastAction(result.created)));
      }
    } catch (error) {
      pushToast(createToast("Playlist queue failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      metadataPlaylistQueueBusy = false;
    }
  }

