  async function mergeToolsSubtitles() {
    const inputPaths = toolsSubtitleMergeInputs
      .split(/\r?\n/)
      .map((path) => path.trim())
      .filter(Boolean);
    const outputPath = toolsSubtitleMergeOutput.trim();
    if (inputPaths.length < 2 || !outputPath) {
      toolsSubtitleMergeError = "Enter at least two subtitle input paths and one output path.";
      pushToast(createToast("Subtitle merge invalid", "error", toolsSubtitleMergeError));
      return;
    }

    toolsSubtitleMergeBusy = true;
    toolsSubtitleMergeError = "";
    try {
      const result = await mergeMetadataSubtitles({ inputPaths, outputPath });
      toolsSubtitleMergeOutput = result.output_path || outputPath;
      pushToast(createToast("Subtitles merged", "success", `${result.merged_count} files -> ${result.output_path || outputPath}`, advancedFileToastAction(result.output_path || outputPath)));
    } catch (error) {
      toolsSubtitleMergeError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Subtitle merge failed", "error", toolsSubtitleMergeError));
    } finally {
      toolsSubtitleMergeBusy = false;
    }
  }

