  async function runMediaTranscode() {
    const inputPath = transcodeInputPath.trim();
    const outputPath = transcodeOutputPath.trim();
    if (!inputPath || !outputPath) {
      transcodeError = "Input and output media paths are required.";
      pushToast(createToast("Transcode invalid", "error", transcodeError));
      return;
    }
    const crfValue = Number.parseInt(transcodeCrf, 10);
    const crf = Number.isFinite(crfValue) ? Math.max(0, Math.min(51, crfValue)) : undefined;
    const jobId = `media-transcode-${Date.now()}`;
    transcodeBusy = true;
    transcodeJobId = jobId;
    transcodeElapsedSeconds = 0;
    transcodeStatusMessage = "Transcode started.";
    transcodeError = "";
    try {
      const request: TranscodeMediaRequest = {
        jobId,
        inputPath,
        outputPath,
        preset: transcodePreset,
        crf,
        metadataTitle: transcodeMetadataTitle.trim() || undefined,
        metadataArtist: transcodeMetadataArtist.trim() || undefined,
        coverPath: transcodeCoverPath.trim() || undefined
      };
      if (transcodePreset === "custom") {
        request.videoCodec = transcodeVideoCodec;
        request.audioCodec = transcodeAudioCodec;
        request.speedPreset = transcodeSpeedPreset;
      }
      if (transcodePreset.startsWith("audio_")) {
        request.audioBitrate = transcodeAudioBitrate.trim() || undefined;
      }
      const result = await transcodeMedia(request);
      pushToast(createToast("Transcode saved", "success", result.output_path || outputPath, advancedFileToastAction(result.output_path || outputPath)));
    } catch (error) {
      transcodeError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Transcode failed", "error", transcodeError));
    } finally {
      transcodeBusy = false;
    }
  }

  async function runShotDetection() {
    const inputPath = shotInputPath.trim();
    const threshold = Number(shotThreshold);
    if (!inputPath) {
      shotError = "Source video path is required.";
      pushToast(createToast("Shot detection invalid", "error", shotError));
      return;
    }
    if (!Number.isFinite(threshold) || threshold < 0 || threshold > 1) {
      shotError = "Scene threshold must be between 0 and 1.";
      pushToast(createToast("Shot detection invalid", "error", shotError));
      return;
    }

    shotBusy = true;
    shotError = "";
    try {
      const result = await detectShots({
        inputPath,
        threshold
      });
      shotMarkers = result.markers;
      pushToast(createToast("Shots detected", "success", `${result.markers.length} marker${result.markers.length === 1 ? "" : "s"}.`));
    } catch (error) {
      shotMarkers = [];
      shotError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Shot detection failed", "error", shotError));
    } finally {
      shotBusy = false;
    }
  }

  async function saveDetectedShotMarkers() {
    const outputPath = shotOutputPath.trim();
    if (shotMarkers.length === 0) {
      shotError = "Run shot detection before saving markers.";
      pushToast(createToast("Shot markers unavailable", "error", shotError));
      return;
    }
    if (!outputPath) {
      shotError = "Shot marker output path is required.";
      pushToast(createToast("Shot marker export invalid", "error", shotError));
      return;
    }

    shotSaveBusy = true;
    shotError = "";
    try {
      const result = await saveShotMarkers({
        outputPath,
        markers: shotMarkers
      });
      shotOutputPath = result.output_path || outputPath;
      pushToast(createToast("Shot markers saved", "success", `${result.marker_count} marker${result.marker_count === 1 ? "" : "s"} -> ${result.output_path}`, advancedFileToastAction(result.output_path)));
    } catch (error) {
      shotError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Shot marker export failed", "error", shotError));
    } finally {
      shotSaveBusy = false;
    }
  }

  async function runWaveformPeaks() {
    const inputPath = waveformInputPath.trim();
    const bucketCount = Number(waveformBucketCount);
    if (!inputPath) {
      waveformError = "Media path is required.";
      pushToast(createToast("Waveform setup invalid", "error", waveformError));
      return;
    }
    if (!Number.isInteger(bucketCount) || bucketCount < 1 || bucketCount > 4096) {
      waveformError = "Bucket count must be an integer between 1 and 4096.";
      pushToast(createToast("Waveform setup invalid", "error", waveformError));
      return;
    }

    waveformBusy = true;
    waveformError = "";
    try {
      const result = await generateWaveformPeaks({
        inputPath,
        bucketCount
      });
      waveformResult = result;
      selectedWaveformTimeSeconds = null;
      pushToast(createToast("Waveform cached", "success", `${result.bucket_count} peaks -> ${result.cache_path}`, advancedFileToastAction(result.cache_path)));
    } catch (error) {
      waveformResult = null;
      waveformError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Waveform generation failed", "error", waveformError));
    } finally {
      waveformBusy = false;
    }
  }

