  function toggleTorrentFileSelection(path: string) {
    torrentSelectedPaths = torrentSelectedPaths.includes(path)
      ? torrentSelectedPaths.filter((item) => item !== path)
      : [...torrentSelectedPaths, path];
  }

  function selectAllTorrentFiles() {
    torrentSelectedPaths = torrentMetadata?.files.map((file) => file.path) ?? [];
  }

  function clearTorrentFileSelection() {
    torrentSelectedPaths = [];
  }

  function selectFilteredTorrentFiles() {
    const filteredPaths = filteredTorrentFiles.map((file) => file.path);
    torrentSelectedPaths = Array.from(new Set([...torrentSelectedPaths, ...filteredPaths]));
  }

  function clearFilteredTorrentFiles() {
    const filteredPaths = new Set(filteredTorrentFiles.map((file) => file.path));
    torrentSelectedPaths = torrentSelectedPaths.filter((path) => !filteredPaths.has(path));
  }

