  async function createP2pSendOffer() {
    const filePath = p2pSendFilePath.trim();
    if (!filePath) {
      p2pError = "Choose a file before creating a P2P offer.";
      pushToast(createToast("P2P offer invalid", "error", p2pError));
      return;
    }
    p2pBusy = "create";
    try {
      const offer = await createP2pOffer(filePath);
      if (offer) {
        p2pActiveOffer = offer;
        p2pOffers = [offer, ...p2pOffers.filter((item) => item.id !== offer.id)];
        p2pReceiveCode = offer.short_code;
        pushToast(createToast("P2P code created", "success", offer.short_code, targetToastAction("Open", "p2p", { code: offer.short_code })));
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("P2P offer failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  async function startP2pSendOffer(shortCode?: string) {
    const code = (shortCode || p2pActiveOffer?.short_code || p2pReceiveCode).trim();
    if (!code) {
      p2pError = "Create or select a P2P offer before starting send.";
      pushToast(createToast("P2P send invalid", "error", p2pError));
      return;
    }
    p2pBusy = `serve:${code}`;
    try {
      const offer = await startP2pSend(code);
      if (offer) {
        p2pActiveOffer = offer;
        p2pOffers = [offer, ...p2pOffers.filter((item) => item.short_code !== offer.short_code)];
        p2pReceiveCode = offer.share_code || offer.short_code;
        pushToast(createToast("P2P send ready", "success", offer.share_code || offer.short_code, targetToastAction("Open", "p2p", { code: offer.short_code })));
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("P2P send failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  async function lookupP2pReceiveOffer() {
    const code = p2pReceiveCode.trim();
    if (!code) {
      p2pError = "Enter a P2P short code.";
      pushToast(createToast("P2P code invalid", "error", p2pError));
      return;
    }
    p2pBusy = "lookup";
    try {
      if (code.includes("@")) {
        const probe = await probeP2pShare(code);
        p2pActiveOffer = probe
          ? {
              schema_version: 1,
              id: `remote-${probe.short_code}`,
              short_code: probe.short_code,
              file_name: probe.file_name,
              file_path: `p2p://${probe.share_code}`,
              size_bytes: probe.size_bytes,
              status: "serving",
              endpoint_host: probe.endpoint_host,
              endpoint_port: probe.endpoint_port,
              share_code: probe.share_code,
              served_at: null,
              receive_output_dir: p2pReceiveOutputDir.trim() || null,
              receive_requested_at: null,
              created_at: new Date().toISOString(),
              expires_at: "",
              updated_at: new Date().toISOString()
            }
          : null;
      } else {
        p2pActiveOffer = await getP2pOffer(code);
      }
      p2pError = "";
      pushToast(createToast("P2P offer found", "success", p2pActiveOffer?.file_name ?? code, targetToastAction("Open", "p2p", { code })));
    } catch (error) {
      p2pActiveOffer = null;
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("P2P lookup failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  async function prepareP2pReceiveDraft() {
    const code = p2pReceiveCode.trim() || p2pActiveOffer?.short_code || "";
    const outputDir = p2pReceiveOutputDir.trim();
    if (!code) {
      p2pError = "Enter or lookup a P2P short code.";
      pushToast(createToast("P2P receive invalid", "error", p2pError));
      return;
    }
    if (!outputDir) {
      p2pError = "Choose a receive folder before preparing P2P receive.";
      pushToast(createToast("P2P receive invalid", "error", p2pError));
      return;
    }
    p2pBusy = "receive";
    try {
      const offer = await prepareP2pReceive(code, outputDir);
      if (offer) {
        p2pActiveOffer = offer;
        p2pOffers = [offer, ...p2pOffers.filter((item) => item.short_code !== offer.short_code)];
        pushToast(createToast("P2P receive prepared", "success", offer.file_name, targetToastAction("Open", "p2p", { code: offer.short_code })));
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("P2P receive failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  async function queueP2pReceiveDraft() {
    const code = p2pReceiveCode.trim() || p2pActiveOffer?.short_code || "";
    if (!code) {
      p2pError = "Enter or lookup a P2P short code.";
      pushToast(createToast("P2P queue invalid", "error", p2pError));
      return;
    }
    p2pBusy = "queue";
    try {
      const task = await queueP2pReceive(code, buildToolsCreateOptions("p2p"));
      if (task) {
        downloads = [task, ...downloads.filter((item) => item.id !== task.id)].sort(
          (first, second) => first.position - second.position
        );
        pushToast(createToast("P2P receive queued", "success", task.title, targetToastAction("Task", "downloads", { task_id: task.id })));
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("P2P queue failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

