  async function updateP2pOfferControl(shortCode: string, action: "pause" | "resume") {
    p2pBusy = `${action}:${shortCode}`;
    try {
      const offer = action === "pause" ? await pauseP2pOffer(shortCode) : await resumeP2pOffer(shortCode);
      if (offer) {
        p2pActiveOffer = offer;
        p2pOffers = p2pOffers.map((item) => (item.short_code === offer.short_code ? offer : item));
        pushToast(createToast(
          action === "pause" ? "P2P offer paused" : "P2P offer resumed",
          "success",
          offer.short_code,
          p2pOfferToastAction(offer)
        ));
      }
      p2pError = "";
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast(action === "pause" ? "P2P pause failed" : "P2P resume failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

  function mergeP2pOfferBulkResult(result: P2pOfferBulkActionResult | null) {
    const updated = result?.offers ?? [];
    const deleted = new Set(result?.deleted ?? []);
    const byCode = new Map(updated.map((offer) => [offer.short_code, offer]));

    p2pOffers = p2pOffers
      .filter((offer) => !deleted.has(offer.short_code))
      .map((offer) => byCode.get(offer.short_code) ?? offer);

    if (p2pActiveOffer) {
      if (deleted.has(p2pActiveOffer.short_code)) {
        p2pActiveOffer = null;
      } else if (byCode.has(p2pActiveOffer.short_code)) {
        p2pActiveOffer = byCode.get(p2pActiveOffer.short_code) ?? p2pActiveOffer;
      }
    }
  }

  function p2pBulkSummary(result: P2pOfferBulkActionResult | null, noun = "offer") {
    const updated = result?.offers.length ?? 0;
    const deleted = result?.deleted.length ?? 0;
    const failed = result?.failed.length ?? 0;
    const changed = updated + deleted;
    const changedLabel = changed === 1 ? noun : `${noun}s`;
    return `${changed} local ${changedLabel}${failed > 0 ? `, ${failed} failed` : ""}.`;
  }

  async function updateVisibleP2pOffersControl(action: Extract<P2pOfferBulkAction, "pause" | "resume">) {
    const targets = action === "pause" ? visibleP2pPausableOffers : visibleP2pResumableOffers;
    if (targets.length === 0) {
      return;
    }

    p2pBusy = `${action}-visible`;
    try {
      const result = await runP2pOfferBulkAction(action, targets.map((offer) => offer.short_code));
      mergeP2pOfferBulkResult(result);
      p2pError = "";
      pushToast(
        createToast(
          action === "pause" ? "Shown P2P offers paused" : "Shown P2P offers resumed",
          "success",
          p2pBulkSummary(result),
          p2pOfferToastAction(result?.offers[0])
        )
      );
    } catch (error) {
      p2pError = error instanceof Error ? error.message : String(error);
      pushToast(createToast(action === "pause" ? "Shown P2P pause failed" : "Shown P2P resume failed", "error", p2pError));
    } finally {
      p2pBusy = "";
    }
  }

