  async function removeLibraryCatalogItem(item: LibraryItem) {
    libraryBusy = true;
    libraryError = "";
    try {
      libraryCatalog = await deleteLibraryCatalogItem(item.path);
      await refreshLibraryLocalSummary();
      if (libraryScan) {
        libraryScan = {
          ...libraryScan,
          items: libraryScan.items.filter((candidate) => candidate.path !== item.path),
          item_count: libraryScan.items.filter((candidate) => candidate.path !== item.path).length
        };
      }
      if (libraryPreview?.path === item.path) {
        libraryPreview = null;
      }
      pushToast(createToast("Library item removed", "success", "Removed from the local catalog only; the source file was left untouched.", targetToastAction("Open", "library", { query: item.title || item.path })));
    } catch (error) {
