  function requestFilteredLibraryCatalogItemsRemove() {
    if (!libraryCatalog || filteredCatalogLibraryItemCount === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown reading items?",
      message: `Remove ${filteredCatalogLibraryItemCount} shown catalog item${filteredCatalogLibraryItemCount === 1 ? "" : "s"} from FetchDock only. Source files, notes, and reading state are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        const paths = new Set(libraryCatalog?.items.map((item) => item.path) ?? []);
        const targets = filteredLibraryItems.filter((item) => paths.has(item.path));
        libraryBulkBusy = "remove-filtered";
        libraryBusy = true;
        libraryError = "";
        try {
          const result = await deleteLibraryCatalogItems(targets.map((item) => item.path));
          libraryCatalog = result?.catalog ?? libraryCatalog;
          await refreshLibraryLocalSummary();
          const removedPaths = new Set(result?.deleted ?? []);
          if (libraryScan) {
            const items = libraryScan.items.filter((item) => !removedPaths.has(item.path));
            libraryScan = { ...libraryScan, items, item_count: items.length };
          }
          if (libraryPreview && removedPaths.has(libraryPreview.path)) {
            libraryPreview = null;
          }
          const removed = result?.deleted.length ?? 0;
          const failed = result?.failed.length ?? 0;
          pushToast(createToast(
            "Shown reading items removed",
            "success",
            `${removed} catalog item${removed === 1 ? "" : "s"} removed${failed > 0 ? `, ${failed} failed` : ""}.`,
            targetToastAction("Open", "library", { query: targets[0]?.title ?? targets[0]?.path ?? "" })
          ));
        } catch (error) {
          libraryError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown reading remove failed", "error", libraryError));
        } finally {
          libraryBulkBusy = "";
          libraryBusy = false;
        }
      }
    };
  }

