      const after = musicCatalog?.track_count ?? 0;
      musicScan = null;
      musicQueue = musicQueue.filter((track) => track.path && musicCatalog?.tracks.some((item) => item.path === track.path));
      if (activeMusicTrack && !musicQueue.some((track) => track.path === activeMusicTrack?.path)) {
        setActiveMusicTrack(musicQueue[0] ?? null);
      }
      await persistMusicQueue();
      await refreshMusicLocalSummary();
      pushToast(createToast("Missing music tracks pruned", "success", `${Math.max(0, before - after)} removed · ${after} in catalog.`, targetToastAction("Open", "music", { query: musicSearchQuery })));
    } catch (error) {
