  async function removeMusicCatalogTrack(track: MusicTrack) {
    musicBusy = true;
    musicError = "";
    try {
      musicCatalog = await deleteMusicCatalogTrack(track.path);
      if (musicScan) {
        const tracks = musicScan.tracks.filter((candidate) => candidate.path !== track.path);
        musicScan = {
          ...musicScan,
          tracks,
          track_count: tracks.length,
          artists: Array.from(new Set(tracks.map((candidate) => candidate.artist).filter((artist): artist is string => Boolean(artist)))).sort(),
          albums: Array.from(new Set(tracks.map((candidate) => candidate.album).filter((album): album is string => Boolean(album)))).sort()
        };
      }
      musicQueue = musicQueue.filter((candidate) => candidate.path !== track.path);
      if (activeMusicTrack?.path === track.path) {
        setActiveMusicTrack(musicQueue[0] ?? null);
      }
      await persistMusicQueue();
      await refreshMusicLocalSummary();
      pushToast(createToast("Music track removed", "success", "Removed from the local catalog and queue only; the source file was left untouched.", targetToastAction("Open", "music", { query: track.title || track.path })));
    } catch (error) {
      musicError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Music remove failed", "error", musicError));
    } finally {
      musicBusy = false;
    }
  }

  function requestFilteredMusicCatalogTracksRemove() {
    if (!musicCatalog || filteredCatalogMusicTrackCount === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown music tracks?",
      message: `Remove ${filteredCatalogMusicTrackCount} shown catalog track${filteredCatalogMusicTrackCount === 1 ? "" : "s"} from FetchDock. Source files, playlists, playback history, and settings are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        const paths = new Set(musicCatalog?.tracks.map((track) => track.path) ?? []);
        const targets = filteredMusicTracks.filter((track) => paths.has(track.path));
        musicCatalogBulkBusy = "remove-filtered";
        musicBusy = true;
        musicError = "";
        try {
          const result = await deleteMusicCatalogTracks(targets.map((track) => track.path));
          musicCatalog = result?.catalog ?? musicCatalog;
          const removedPaths = new Set(result?.deleted ?? []);
          if (musicScan) {
            const tracks = musicScan.tracks.filter((track) => !removedPaths.has(track.path));
            musicScan = {
              ...musicScan,
              tracks,
              track_count: tracks.length,
              artists: Array.from(new Set(tracks.map((track) => track.artist).filter((artist): artist is string => Boolean(artist)))).sort(),
              albums: Array.from(new Set(tracks.map((track) => track.album).filter((album): album is string => Boolean(album)))).sort()
            };
          }
          musicQueue = musicQueue.filter((track) => !removedPaths.has(track.path));
          if (activeMusicTrack && removedPaths.has(activeMusicTrack.path)) {
            setActiveMusicTrack(musicQueue[0] ?? null);
          }
          await persistMusicQueue();
          await refreshMusicLocalSummary();
          const removed = result?.deleted.length ?? 0;
          const failed = result?.failed.length ?? 0;
          pushToast(createToast(
            "Shown music tracks removed",
            "success",
            `${removed} catalog track${removed === 1 ? "" : "s"} removed${failed > 0 ? `, ${failed} failed` : ""}.`,
            targetToastAction("Open", "music", { query: targets[0]?.title ?? targets[0]?.path ?? "" })
          ));
        } catch (error) {
          musicError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown music remove failed", "error", musicError));
        } finally {
          musicCatalogBulkBusy = "";
          musicBusy = false;
        }
      }
    };
  }

