      musicEqualizer = equalizer;
      musicDiscordPresence = discordPresence;
      musicCatalog = catalog;
      musicServiceMatrix = serviceMatrix;
      musicLocalSummary = summary;
      musicFormatCatalog = formatCatalog;
      musicVolumeInput = String(queueState?.volume_percent ?? 80);
      applyMusicVolume();
      if (queueState?.tracks.length) {
        musicQueue = queueState.tracks;
        setActiveMusicTrack(queueState.tracks.find((track) => track.path === queueState.active_path) ?? queueState.tracks[0] ?? null);
      } else if (catalog?.tracks.length) {
        musicQueue = catalog.tracks.slice(0, 50);
        setActiveMusicTrack(musicQueue[0] ?? null);
      }
      if (sleepTimer) {
        musicSleepMinutesInput = String(sleepTimer.duration_minutes);
      }
      applyMusicEqualizerToGraph();
      musicError = "";
    } catch (error) {
      musicError = error instanceof Error ? error.message : String(error);
    }
  }

