  function appendFilteredMusicTracksToQueue() {
    if (filteredMusicTracks.length === 0) {
      musicError = "No filtered tracks to append.";
      pushToast(createToast("Music queue unchanged", "info", musicError));
      return;
    }
    const existingPaths = new Set(musicQueue.map((track) => track.path));
    const newTracks = filteredMusicTracks.filter((track) => !existingPaths.has(track.path));
    if (newTracks.length === 0) {
      pushToast(createToast("Music queue unchanged", "info", "Shown tracks are already in the queue."));
      return;
    }
    musicQueue = [...musicQueue, ...newTracks];
    if (!activeMusicTrack) {
      setActiveMusicTrack(musicQueue[0] ?? null);
    }
    void persistMusicQueue();
