  function requestVisibleMusicPlaylistsRemove() {
    const targets = visibleMusicPlaylists(filteredMusicPlaylists);
    if (targets.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown playlists?",
      message: `Remove ${targets.length} shown local playlist${targets.length === 1 ? "" : "s"}. The catalog, queue, playback history, settings, and audio files are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        musicPlaylistBusy = "remove-filtered";
        try {
          const result = await deleteMusicPlaylists(targets.map((playlist) => playlist.id));
          const deletedIds = new Set(result.deleted);
          musicPlaylists = musicPlaylists.filter((playlist) => !deletedIds.has(playlist.id));
          if (musicEditingPlaylistId && deletedIds.has(musicEditingPlaylistId)) {
            cancelMusicPlaylistEdit();
          }
          await refreshMusicLocalSummary();
          musicError = "";
          const removed = result.deleted.length;
          const failed = result.failed.length;
          pushToast(createToast(
            "Shown playlists removed",
            "success",
            `${removed} playlist${removed === 1 ? "" : "s"} removed${failed > 0 ? `, ${failed} failed` : ""}.`,
            targetToastAction("Open", "music", { query: targets[0]?.name ?? "" })
          ));
        } catch (error) {
          musicError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown playlist remove failed", "error", musicError));
        } finally {
          musicPlaylistBusy = "";
        }
      }
    };
  }

