  function musicDiscordPresencePreview(): string {
    if (!activeMusicTrack) {
      return "No active local track";
    }
    if (musicDiscordPresence?.privacy_mode === "private") {
      return "Listening in FetchDock";
    }
    const parts = [
      musicDiscordPresence?.include_title !== false ? activeMusicTrack.title : null,
      musicDiscordPresence?.include_artist ? activeMusicTrack.artist : null,
      musicDiscordPresence?.privacy_mode === "detailed" && musicDiscordPresence?.include_album ? activeMusicTrack.album : null
    ].filter(Boolean);
    return parts.join(" · ") || "Listening in FetchDock";
  }

  function scheduleMusicSleepTimer(endsAt: string) {
    if (musicSleepTimeout !== null) {
      window.clearTimeout(musicSleepTimeout);
      musicSleepTimeout = null;
    }
    const delay = new Date(endsAt).getTime() - Date.now();
    if (!Number.isFinite(delay)) {
      return;
    }
    musicSleepTimeout = window.setTimeout(() => {
      musicAudioElement?.pause();
      void setMusicSleepTimerEnabled(false);
    }, Math.max(0, delay));
  }

  async function openLibraryPreview(item: LibraryItem) {
    libraryPreviewBusy = item.path;
    libraryError = "";
    try {
      if (!["txt", "html", "htm", "pdf", "cbz", "epub"].includes(item.format.toLowerCase())) {
        await openLibraryExternal(item.path);
        libraryPreview = null;
        libraryReadingState = null;
        libraryExportResult = null;
        pushToast(createToast("Library item opened externally", "success", item.title, libraryItemToastAction(item)));
        return;
      }
      const openedPreview = await openLibraryItem(item.path);
      if (!openedPreview) {
        throw new Error("Library preview returned an empty response.");
      }
      libraryPreview = openedPreview;
      libraryReadingState = await getLibraryReadingState(item.path);
      const savedProgress = libraryReadingState?.progress_percent ?? 0;
      libraryCbzCurrentPageInput = openedPreview.format === "cbz" ? String(libraryIndexFromProgress(savedProgress, cbzPreviewPages(openedPreview).length)) : libraryCbzCurrentPageInput;
      libraryEpubCurrentSpineInput = openedPreview.format === "epub" ? String(libraryIndexFromProgress(savedProgress, epubReadingOrder(openedPreview).length)) : libraryEpubCurrentSpineInput;
      libraryProgressInput = String(savedProgress);
      libraryExportPath = defaultLibraryExportPath(item.path, libraryExportFormat);
      libraryExportResult = null;
      lastLibraryAutosavedProgressKey = `${item.path}:${savedProgress}`;
      await tick();
      scrollLibraryReaderToProgress(savedProgress);
      await autoLoadLibraryPreviewAtProgress(savedProgress);
      if (libraryPreview) {
        pushToast(createToast("Library item opened", "success", libraryPreview.title, libraryItemToastAction(libraryPreview.path)));
      }
    } catch (error) {
      libraryReadingState = null;
      libraryExportResult = null;
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Library preview failed", "error", libraryError));
    } finally {
      libraryPreviewBusy = "";
    }
  }

  async function autoLoadLibraryPreviewAtProgress(progressPercent = 0) {
    const preview = libraryPreview;
    if (!preview) {
      return;
    }

    if (preview.format === "cbz") {
      const pages = cbzPreviewPages(preview);
      if (pages.length === 0) {
        return;
      }
      const targetIndex = libraryIndexFromProgress(progressPercent, pages.length);
      const page = pages.find((candidate) => candidate.index === targetIndex) ?? pages[targetIndex - 1] ?? pages[0];
      if (!page) {
        return;
      }
      libraryCbzCurrentPageInput = String(page.index);
      if (page.preview_path) {
        jumpToLibraryPosition(indexedPreviewProgress(page.index, pages.length));
        return;
      }
      await loadCbzPagePreview(page);
      return;
    }

    if (preview.format === "epub") {
      const items = epubReadingOrder(preview);
      if (items.length === 0) {
        return;
      }
      const targetIndex = libraryIndexFromProgress(progressPercent, items.length);
      const item = items.find((candidate) => candidate.index === targetIndex) ?? items[targetIndex - 1] ?? items[0];
      if (!item) {
        return;
      }
      libraryEpubCurrentSpineInput = String(item.index);
      if (epubTextPreviews(preview).some((textPreview) => textPreview.index === item.index)) {
        jumpToLibraryPosition(indexedPreviewProgress(item.index, items.length));
        return;
      }
      await loadEpubTextPreview(item);
    }
  }

