  async function loadCbzPagePreview(page: { index: number; path: string }) {
    if (!libraryPreview || libraryPreview.format !== "cbz") {
      return;
    }
    libraryCbzPreviewBusy = String(page.index);
    try {
      const result = await extractLibraryCbzPagePreview(libraryPreview.path, page.index);
      if (!result || !libraryPreview?.extra_json || !Array.isArray(libraryPreview.extra_json.pages)) {
        return;
      }
      const pages = libraryPreview.extra_json.pages.map((rawPage) => {
        if (!rawPage || typeof rawPage !== "object" || Array.isArray(rawPage)) {
          return rawPage;
        }
        const current = rawPage as Record<string, unknown>;
        const currentIndex = typeof current.index === "number" ? current.index : 0;
        if (currentIndex !== result.index) {
          return rawPage;
        }
        return {
          ...current,
          preview_path: result.preview_path,
          size_bytes: result.size_bytes,
          path: result.path
        };
      });
      libraryPreview = {
        ...libraryPreview,
        extra_json: {
          ...libraryPreview.extra_json,
          pages,
          preview_page_count: Math.max(
            typeof libraryPreview.extra_json.preview_page_count === "number" ? libraryPreview.extra_json.preview_page_count : 0,
            cbzPreviewImages({ ...libraryPreview, extra_json: { ...libraryPreview.extra_json, pages } }).length
          ),
          preview_status: "cached_page_previews"
        }
      };
      libraryError = "";
      libraryCbzCurrentPageInput = String(result.index);
      pushToast(createToast("CBZ page cached", "success", `Page ${result.index}`, libraryItemToastAction(libraryPreview.path)));
      await tick();
      jumpToLibraryPosition(indexedPreviewProgress(result.index, cbzPreviewPages(libraryPreview).length));
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("CBZ page preview failed", "error", libraryError));
    } finally {
      libraryCbzPreviewBusy = "";
    }
  }
  async function loadEpubTextPreview(item: { index: number; idref: string; href?: string }) {
    if (!libraryPreview || libraryPreview.format !== "epub") {
      return;
    }
    libraryEpubPreviewBusy = String(item.index);
    try {
      const result = await extractLibraryEpubTextPreview(libraryPreview.path, item.index);
      if (!result || !libraryPreview?.extra_json) {
        return;
      }
      const existing = epubTextPreviews(libraryPreview);
      const nextPreview = {
        index: result.index,
        idref: result.idref,
        href: result.href,
        path: result.path,
        text: result.text,
        size_bytes: result.size_bytes
      };
      const byIndex = new Map(existing.map((preview) => [preview.index, preview]));
      byIndex.set(result.index, nextPreview);
      const textPreviews = Array.from(byIndex.values()).sort((left, right) => left.index - right.index);
      const content = textPreviews.map((preview) => `${preview.path}\n\n${preview.text}`).join("\n\n---\n\n");
      libraryPreview = {
        ...libraryPreview,
        content,
        extra_json: {
          ...libraryPreview.extra_json,
          text_previews: textPreviews,
          preview_status: "spine_text_preview"
        }
      };
      libraryError = "";
      libraryEpubCurrentSpineInput = String(result.index);
      pushToast(createToast("EPUB text extracted", "success", `Spine ${result.index}`, libraryItemToastAction(libraryPreview.path)));
      await tick();
      jumpToLibraryPosition(indexedPreviewProgress(result.index, epubReadingOrder(libraryPreview).length));
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("EPUB text preview failed", "error", libraryError));
    } finally {
      libraryEpubPreviewBusy = "";
    }
  }

  function boundedLibraryIndex(value: string, total: number): number {
    const parsed = Number(value);
    const normalized = Number.isFinite(parsed) ? Math.round(parsed) : 1;
    return Math.max(1, Math.min(Math.max(1, total), normalized));
  }

  async function moveLibraryCbzPage(offset = 0) {
    if (!libraryPreview || libraryPreview.format !== "cbz") {
      return;
    }
    const pages = cbzPreviewPages(libraryPreview);
    if (pages.length === 0) {
      return;
    }
    const targetIndex = boundedLibraryIndex(String(boundedLibraryIndex(libraryCbzCurrentPageInput, pages.length) + offset), pages.length);
    libraryCbzCurrentPageInput = String(targetIndex);
    const page = pages.find((candidate) => candidate.index === targetIndex) ?? pages[targetIndex - 1];
    if (!page) {
      return;
    }
    if (page.preview_path) {
      jumpToLibraryPosition(indexedPreviewProgress(page.index, pages.length));
      return;
    }
    await loadCbzPagePreview(page);
  }

  async function moveLibraryEpubSpine(offset = 0) {
    if (!libraryPreview || libraryPreview.format !== "epub") {
      return;
    }
    const items = epubReadingOrder(libraryPreview);
    if (items.length === 0) {
      return;
    }
    const targetIndex = boundedLibraryIndex(String(boundedLibraryIndex(libraryEpubCurrentSpineInput, items.length) + offset), items.length);
    libraryEpubCurrentSpineInput = String(targetIndex);
    const item = items.find((candidate) => candidate.index === targetIndex) ?? items[targetIndex - 1];
    if (!item) {
      return;
    }
    if (epubTextPreviews(libraryPreview).some((preview) => preview.index === item.index)) {
      jumpToLibraryPosition(indexedPreviewProgress(item.index, items.length));
      return;
    }
    await loadEpubTextPreview(item);
  }

  function parsedLibraryProgress(): number {
    const parsed = Number(libraryProgressInput);
    return Number.isFinite(parsed) ? Math.max(0, Math.min(100, Math.round(parsed))) : 0;
  }

  function libraryScrollPercentFromElement(element: HTMLElement | null): number {
    if (!element) {
      return parsedLibraryProgress();
    }
    const maxScroll = Math.max(0, element.scrollHeight - element.clientHeight);
    if (maxScroll === 0) {
      return 0;
    }
    return Math.max(0, Math.min(100, Math.round((element.scrollTop / maxScroll) * 100)));
  }

  function scrollLibraryReaderToProgress(progressPercent = parsedLibraryProgress()) {
    if (!libraryReaderScrollElement) {
      return;
    }
    const maxScroll = Math.max(0, libraryReaderScrollElement.scrollHeight - libraryReaderScrollElement.clientHeight);
    libraryReaderScrollMuted = true;
    libraryReaderScrollElement.scrollTo({
      top: Math.round(maxScroll * (Math.max(0, Math.min(100, progressPercent)) / 100)),
      behavior: "smooth"
    });
    window.setTimeout(() => {
      libraryReaderScrollMuted = false;
    }, 220);
  }

  function syncLibraryProgressFromScroll() {
    if (libraryReaderScrollMuted || !libraryPreview) {
      return;
    }
    libraryProgressInput = String(libraryScrollPercentFromElement(libraryReaderScrollElement));
    scheduleLibraryProgressAutosave();
  }

  function scheduleLibraryProgressAutosave() {
    if (!libraryPreview) {
      return;
    }
    if (libraryProgressAutosaveTimer) {
      window.clearTimeout(libraryProgressAutosaveTimer);
    }
    libraryProgressAutosaveTimer = window.setTimeout(() => {
      void autosaveCurrentLibraryProgress();
    }, 900);
  }

  async function autosaveCurrentLibraryProgress() {
    if (!libraryPreview) {
      return;
    }
    const progress = parsedLibraryProgress();
    const key = `${libraryPreview.path}:${progress}`;
    if (key === lastLibraryAutosavedProgressKey) {
      return;
    }
    try {
      const state = await saveLibraryProgress(libraryPreview.path, progress);
      if (state) {
        libraryReadingState = state;
        libraryProgressInput = String(state.progress_percent);
        lastLibraryAutosavedProgressKey = `${state.path}:${state.progress_percent}`;
      }
      libraryError = "";
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
    }
  }

  function jumpToLibraryPosition(positionPercent: number) {
    libraryProgressInput = String(Math.max(0, Math.min(100, Math.round(positionPercent))));
    scrollLibraryReaderToProgress(positionPercent);
  }

  function useLibraryScrollAsDraftProgress() {
    const progress = libraryScrollPercentFromElement(libraryReaderScrollElement);
    libraryProgressInput = String(progress);
    pushToast(createToast("Reading progress captured", "info", `${progress}%`, libraryPreview ? libraryItemToastAction(libraryPreview.path) : undefined));
  }

  function setLibraryBookmarkDraftAtCurrentProgress() {
    const progress = libraryScrollPercentFromElement(libraryReaderScrollElement);
    libraryProgressInput = String(progress);
    if (!libraryBookmarkLabel.trim()) {
      libraryBookmarkLabel = `Bookmark ${progress}%`;
    }
    pushToast(createToast("Bookmark draft updated", "info", `${progress}%`, libraryPreview ? libraryItemToastAction(libraryPreview.path) : undefined));
  }

  function setLibraryHighlightDraftAtCurrentProgress() {
    const progress = libraryScrollPercentFromElement(libraryReaderScrollElement);
    libraryProgressInput = String(progress);
    if (!libraryHighlightText.trim()) {
      captureLibrarySelection();
    }
    pushToast(createToast("Highlight draft positioned", "info", `${progress}%`, libraryPreview ? libraryItemToastAction(libraryPreview.path) : undefined));
  }

  function isNodeInsideLibraryReader(node: Node | null): boolean {
    if (!libraryReaderScrollElement || !node) {
      return false;
    }
    const element = node.nodeType === Node.ELEMENT_NODE ? (node as Element) : node.parentElement;
    return Boolean(element && libraryReaderScrollElement.contains(element));
  }

  function copyLibraryBookmarkForEdit(bookmark: LibraryBookmark) {
    libraryBookmarkLabel = bookmark.label;
    jumpToLibraryPosition(bookmark.position_percent);
  }

  function copyLibraryHighlightForEdit(highlight: LibraryHighlight) {
    libraryHighlightText = highlight.text;
    libraryHighlightNote = highlight.note ?? "";
    jumpToLibraryPosition(highlight.position_percent);
  }

  function captureLibrarySelection() {
    const selection = window.getSelection();
    const selectedText = selection?.toString().trim() ?? "";
    if (
      !selection ||
      selection.isCollapsed ||
      !selectedText ||
      (!isNodeInsideLibraryReader(selection.anchorNode) && !isNodeInsideLibraryReader(selection.focusNode))
    ) {
      return;
    }
    libraryHighlightText = selectedText.slice(0, 6000);
    libraryProgressInput = String(libraryScrollPercentFromElement(libraryReaderScrollElement));
    pushToast(createToast("Selection captured", "info", "Highlight text is ready to save."));
  }

  function defaultLibraryExportPath(path: string, format: "json" | "markdown") {
    const normalized = path.trim();
    if (!normalized) {
      return "";
    }
    const separatorIndex = Math.max(normalized.lastIndexOf("/"), normalized.lastIndexOf("\\"));
    const directory = separatorIndex >= 0 ? normalized.slice(0, separatorIndex + 1) : "";
    const fileName = separatorIndex >= 0 ? normalized.slice(separatorIndex + 1) : normalized;
    const stem = fileName.includes(".") ? fileName.slice(0, fileName.lastIndexOf(".")) : fileName;
    return `${directory}${stem}.reading-state.${format === "markdown" ? "md" : "json"}`;
  }

  function libraryLearningNoteBody(preview: LibraryOpenResponse, highlight: string, note: string, progress: number): string {
    const lines = [
      `Source file: ${preview.path}`,
      `Reading format: ${preview.format.toUpperCase()}`,
      `Progress: ${progress}%`,
      "",
      "Highlight:",
      highlight
    ];
    if (note) {
      lines.push("", "Note:", note);
    }
    return lines.join("\n");
  }

  function libraryBookmarkLearningNoteBody(preview: LibraryOpenResponse, label: string, progress: number): string {
    return [
      `Source file: ${preview.path}`,
      `Reading format: ${preview.format.toUpperCase()}`,
      `Progress: ${progress}%`,
      "",
      "Bookmark:",
      label
    ].join("\n");
  }

  async function saveCurrentLibraryProgress() {
    if (!libraryPreview) {
      return;
    }
    libraryStateBusy = true;
    try {
      libraryProgressInput = String(libraryScrollPercentFromElement(libraryReaderScrollElement));
      const state = await saveLibraryProgress(libraryPreview.path, parsedLibraryProgress());
      if (state) {
        libraryReadingState = state;
        libraryProgressInput = String(state.progress_percent);
        lastLibraryAutosavedProgressKey = `${state.path}:${state.progress_percent}`;
        pushToast(createToast("Reading progress saved", "success", `${state.progress_percent}%`, libraryItemToastAction(state.path)));
      }
      libraryError = "";
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Reading progress failed", "error", libraryError));
    } finally {
      libraryStateBusy = false;
    }
  }

