  async function saveCurrentLibraryHighlightAsNote() {
    if (!libraryPreview) {
      return;
    }
    const highlight = libraryHighlightText.trim();
    if (!highlight) {
      libraryError = "Highlight text is required.";
      pushToast(createToast("Note save failed", "error", libraryError));
      return;
    }

    libraryNoteBusy = true;
    libraryError = "";
    try {
      const progress = parsedLibraryProgress();
      const note = libraryHighlightNote.trim();
      const saved = await saveLearningNote({
        title: `${libraryPreview.title} highlight`,
        body: libraryLearningNoteBody(libraryPreview, highlight, note, progress),
        timestampSeconds: progress,
        tags: ["reading", libraryPreview.format.toLowerCase()].filter(Boolean)
      });
      if (saved) {
        learningNotes = [saved, ...learningNotes.filter((item) => item.id !== saved.id)];
        await refreshLearningDashboard();
        pushToast(createToast("Learning note saved", "success", saved.title, learningNoteToastAction(saved)));
      }
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Note save failed", "error", libraryError));
    } finally {
      libraryNoteBusy = false;
    }
  }

