  function requestLibraryAnnotationsClear(scope: "all" | "bookmarks" | "highlights" = "all") {
    if (!libraryPreview || !libraryReadingState) {
      return;
    }
    const count = scope === "bookmarks"
      ? libraryReadingState.bookmarks.length
      : scope === "highlights"
        ? libraryReadingState.highlights.length
        : libraryReadingState.bookmarks.length + libraryReadingState.highlights.length;
    const label = scope === "bookmarks" ? "bookmark" : scope === "highlights" ? "highlight" : "annotation";
    confirmDialog = {
      title: `Clear reading ${label}${scope === "all" ? "s" : ""}?`,
      message: `Remove ${count} local reading ${label}${count === 1 ? "" : "s"} for ${libraryPreview.title}. Reading progress, exported files, learning notes, and the source file are left untouched.`,
      confirmLabel: "Clear",
      onConfirm: async () => {
        if (!libraryPreview) {
          return;
        }
        libraryAnnotationBusy = `clear-${scope}`;
        try {
          const state = await clearLibraryAnnotations(libraryPreview.path, scope);
          if (state) {
            libraryReadingState = state;
            libraryBookmarksExpanded = false;
            libraryHighlightsExpanded = false;
            await refreshLearningDashboard();
            pushToast(createToast("Reading annotations cleared", "success", `${count} ${label}${count === 1 ? "" : "s"}`, libraryItemToastAction(state.path)));
          }
          libraryError = "";
        } catch (error) {
          libraryError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Annotation clear failed", "error", libraryError));
        } finally {
          libraryAnnotationBusy = "";
        }
      }
    };
  }

  function requestFilteredLibraryAnnotationsRemove() {
    if (!libraryPreview || !libraryReadingState) {
      return;
    }
    const bookmarkIds = visibleLibraryBookmarks(filteredLibraryBookmarks).map((bookmark) => bookmark.id);
    const highlightIds = visibleLibraryHighlights(filteredLibraryHighlights).map((highlight) => highlight.id);
    const count = bookmarkIds.length + highlightIds.length;
    if (count === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown annotations?",
      message: `Remove ${count} shown reading annotation${count === 1 ? "" : "s"} for ${libraryPreview.title}. Reading progress, exported files, learning notes, and the source file are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        if (!libraryPreview) {
          return;
        }
        libraryAnnotationBusy = "remove-filtered";
        try {
          const result = await deleteLibraryAnnotations(libraryPreview.path, bookmarkIds, highlightIds);
          if (result) {
            libraryReadingState = result.state;
            await refreshLearningDashboard();
            const removed = result.deleted.length;
            const failed = result.failed.length;
            pushToast(createToast(
              "Reading annotations removed",
              "success",
              `${removed} annotation${removed === 1 ? "" : "s"} removed${failed > 0 ? `, ${failed} failed` : ""}.`,
              libraryItemToastAction(result.state.path)
            ));
          }
          libraryError = "";
        } catch (error) {
          libraryError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Annotation remove failed", "error", libraryError));
        } finally {
          libraryAnnotationBusy = "";
        }
      }
    };
  }

