  async function chooseLibraryExportPath() {
    if (!libraryPreview) {
      return;
    }
    if (!isTauriRuntime()) {
      pushToast(createToast("Save dialog unavailable", "error", "Run the desktop app to choose a reading state export path."));
      return;
    }

    libraryStateBusy = true;
    try {
      const selected = await save({
        title: "Choose reading state export",
        defaultPath: libraryExportPath.trim() || defaultLibraryExportPath(libraryPreview.path, libraryExportFormat),
        filters: libraryExportFormat === "json"
          ? [{ name: "JSON", extensions: ["json"] }]
          : [{ name: "Markdown", extensions: ["md", "markdown"] }]
      });
      if (typeof selected === "string") {
        libraryExportPath = selected;
      }
    } catch (error) {
      libraryError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Reading export path failed", "error", libraryError));
    } finally {
      libraryStateBusy = false;
    }
