  function setActiveMusicTrack(track: MusicTrack | null) {
    activeMusicTrack = track;
    activeMusicCurrentTimeSeconds = 0;
    void loadActiveMusicLyrics();
    void updateMusicCoverTheme(track);
    applyMusicEqualizerToGraph();
  }

  function playMusicTrack(track: MusicTrack) {
    setActiveMusicTrack(track);
    if (!musicQueue.some((item) => item.path === track.path)) {
      musicQueue = [track, ...musicQueue];
    }
    void persistMusicQueue();
  }

  function groupMusicTracks(tracks: MusicTrack[], field: "artist" | "album"): MusicLibraryGroup[] {
    const groups = new Map<string, MusicTrack[]>();
    for (const track of tracks) {
      const name = (field === "artist" ? track.artist : track.album)?.trim() || (field === "artist" ? "Unknown artist" : "Unknown album");
      groups.set(name, [...(groups.get(name) ?? []), track]);
    }
    return [...groups.entries()]
      .map(([name, groupedTracks]) => ({ name, tracks: groupedTracks }))
      .sort((left, right) => left.name.localeCompare(right.name));
  }

  function loadMusicGroup(group: MusicLibraryGroup) {
    musicQueue = group.tracks;
    setActiveMusicTrack(group.tracks[0] ?? null);
    void persistMusicQueue();
  }

  function appendMusicGroup(group: MusicLibraryGroup) {
    const existingPaths = new Set(musicQueue.map((track) => track.path));
    const newTracks = group.tracks.filter((track) => !existingPaths.has(track.path));
    if (newTracks.length === 0) {
      pushToast(createToast("Music queue unchanged", "info", `${group.name} is already queued.`, targetToastAction("Open", "music", { query: group.name })));
      return;
    }
    musicQueue = [...musicQueue, ...newTracks];
    if (!activeMusicTrack) {
      setActiveMusicTrack(musicQueue[0] ?? null);
    }
    void persistMusicQueue();
    pushToast(createToast("Music group appended", "success", `${newTracks.length} track${newTracks.length === 1 ? "" : "s"} added from ${group.name}.`, musicTrackToastAction(newTracks[0])));
  }

  function musicGroupCoverUrls(group: MusicLibraryGroup): string[] {
    const paths = Array.from(new Set(group.tracks.map((track) => track.cover_path).filter((path): path is string => Boolean(path))));
    return paths.slice(0, 4).map((path) => convertFileSrc(path));
  }

