  function parsedMusicVolumePercent(): number {
    const parsed = Number(musicVolumeInput);
    return Number.isFinite(parsed) ? Math.max(0, Math.min(100, Math.round(parsed))) : 80;
  }

  function applyMusicVolume() {
    musicVolumeInput = String(parsedMusicVolumePercent());
    if (musicAudioElement) {
      musicAudioElement.volume = parsedMusicVolumePercent() / 100;
    }
  }

  function setupMusicEqualizerGraph(): boolean {
    if (!musicAudioElement) {
      musicEqualizerStatus = "DSP waiting for player";
      return false;
    }
    try {
      if (!musicAudioContext) {
        const AudioContextConstructor =
          window.AudioContext || (window as WindowWithLegacyAudioContext).webkitAudioContext;
        if (!AudioContextConstructor) {
          musicEqualizerStatus = "WebAudio unavailable";
          return false;
        }
        musicAudioContext = new AudioContextConstructor();
        musicAudioSource = musicAudioContext.createMediaElementSource(musicAudioElement);
        musicBassFilter = musicAudioContext.createBiquadFilter();
        musicMidFilter = musicAudioContext.createBiquadFilter();
        musicTrebleFilter = musicAudioContext.createBiquadFilter();
        musicBassFilter.type = "lowshelf";
        musicBassFilter.frequency.value = 160;
        musicMidFilter.type = "peaking";
        musicMidFilter.frequency.value = 1200;
        musicMidFilter.Q.value = 0.9;
        musicTrebleFilter.type = "highshelf";
        musicTrebleFilter.frequency.value = 5200;
        musicAudioSource
          .connect(musicBassFilter)
          .connect(musicMidFilter)
          .connect(musicTrebleFilter)
          .connect(musicAudioContext.destination);
      }
      if (musicAudioContext.state === "suspended") {
        void musicAudioContext.resume();
      }
      applyMusicEqualizerToGraph();
      return true;
    } catch (error) {
      musicEqualizerStatus = error instanceof Error ? error.message : String(error);
      return false;
    }
  }

  function applyMusicEqualizerToGraph() {
    if (!musicBassFilter || !musicMidFilter || !musicTrebleFilter) {
      musicEqualizerStatus = "DSP idle";
      return;
    }
    const enabled = musicEqualizer?.enabled ?? false;
    const bass = enabled ? musicEqualizer?.bass_gain_db ?? 0 : 0;
    const mid = enabled ? musicEqualizer?.mid_gain_db ?? 0 : 0;
    const treble = enabled ? musicEqualizer?.treble_gain_db ?? 0 : 0;
    const currentTime = musicAudioContext?.currentTime ?? 0;
    musicBassFilter.gain.setTargetAtTime(bass, currentTime, 0.04);
    musicMidFilter.gain.setTargetAtTime(mid, currentTime, 0.04);
    musicTrebleFilter.gain.setTargetAtTime(treble, currentTime, 0.04);
    musicEqualizerStatus = enabled
      ? `DSP active · bass ${bass} dB · mid ${mid} dB · treble ${treble} dB`
      : "DSP bypassed";
  }

  async function saveMusicVolume() {
    applyMusicVolume();
    await persistMusicQueue();
  }

  async function loadActiveMusicLyrics() {
