  function normalizeLyricsFormat(format?: string | null): "lrc" | "txt" | "srt" | "vtt" {
    if (format === "txt" || format === "srt" || format === "vtt") {
      return format;
    }
    return "lrc";
  }

  function defaultMusicLyricsFileName(): string {
    if (!activeMusicTrack) {
      return `lyrics.${musicLyricsFormat}`;
    }
    const name = activeMusicTrack.path.split(/[\\/]/).pop() ?? "track";
    const stem = name.replace(/\.[^.]+$/, "") || "track";
    return `${stem}.${musicLyricsFormat}`;
  }

