  async function updateMusicCoverTheme(track: MusicTrack | null) {
    musicCoverTheme = "";
    if (!track?.cover_path || !musicCoverThemeEnabled) {
      return;
    }
    const image = new Image();
    image.decoding = "async";
    image.src = convertFileSrc(track.cover_path);
    try {
      await image.decode();
      const canvas = document.createElement("canvas");
      canvas.width = 1;
      canvas.height = 1;
      const context = canvas.getContext("2d");
      if (!context) {
        return;
      }
      context.drawImage(image, 0, 0, 1, 1);
      const [red, green, blue] = context.getImageData(0, 0, 1, 1).data;
      musicCoverTheme = `rgb(${red}, ${green}, ${blue})`;
    } catch {
      musicCoverTheme = "";
    }
  }

  function getMusicMediaSession(): MusicMediaSession | null {
    if (typeof navigator === "undefined") {
      return null;
    }
    return (navigator as NavigatorWithMediaSession).mediaSession ?? null;
  }

  function setMusicMediaSessionPlaybackState(state: MusicMediaSessionPlaybackState) {
    const mediaSession = getMusicMediaSession();
    if (!mediaSession) {
      musicMediaSessionSupported = false;
      musicMediaSessionStatus = "Media session unavailable";
      return;
    }
    try {
      mediaSession.playbackState = state;
      syncMusicMediaSessionPosition();
      musicMediaSessionSupported = true;
      musicMediaSessionStatus = activeMusicTrack
        ? `Media session ${state === "none" ? "ready" : state}`
        : "Media session ready";
    } catch (error) {
      musicMediaSessionSupported = true;
      musicMediaSessionStatus = `Media session error: ${error instanceof Error ? error.message : String(error)}`;
    }
  }

  function syncMusicMediaSessionPosition() {
    const mediaSession = getMusicMediaSession();
    if (!mediaSession?.setPositionState || !musicAudioElement || !Number.isFinite(musicAudioElement.duration)) {
      return;
    }
    try {
      mediaSession.setPositionState({
        duration: Math.max(0, musicAudioElement.duration),
        playbackRate: musicAudioElement.playbackRate || 1,
        position: Math.max(0, Math.min(musicAudioElement.currentTime, musicAudioElement.duration))
      });
    } catch {
      // Some WebView hosts expose Media Session but reject position state for local files.
    }
  }

  function installMusicMediaSessionAction(action: string, handler: (details?: MusicMediaSessionActionDetails) => void) {
    const mediaSession = getMusicMediaSession();
    if (!mediaSession) {
      return;
    }
    try {
      mediaSession.setActionHandler(action, handler);
    } catch {
      mediaSession.setActionHandler(action, null);
    }
  }

  function updateMusicMediaSession() {
    const mediaSession = getMusicMediaSession();
    if (!mediaSession) {
      musicMediaSessionSupported = false;
      musicMediaSessionStatus = "Media session unavailable";
      return;
    }
    musicMediaSessionSupported = true;
    try {
      const MediaMetadataConstructor = (window as WindowWithMediaMetadata).MediaMetadata;
      if (activeMusicTrack && MediaMetadataConstructor) {
        mediaSession.metadata = new MediaMetadataConstructor({
          title: activeMusicTrack.title,
          artist: activeMusicTrack.artist ?? "Unknown artist",
          album: activeMusicTrack.album ?? "Unknown album",
          artwork: activeMusicCoverUrl ? [{ src: activeMusicCoverUrl }] : []
        });
      } else {
        mediaSession.metadata = null;
      }
      installMusicMediaSessionAction("play", () => {
        void musicAudioElement?.play();
      });
      installMusicMediaSessionAction("pause", () => {
        musicAudioElement?.pause();
      });
      installMusicMediaSessionAction("previoustrack", () => {
        playPreviousMusicTrack();
      });
      installMusicMediaSessionAction("nexttrack", () => {
        playNextMusicTrack();
      });
      installMusicMediaSessionAction("seekbackward", (details) => {
        if (!musicAudioElement) {
          return;
        }
        musicAudioElement.currentTime = Math.max(0, musicAudioElement.currentTime - (details?.seekOffset ?? 10));
      });
      installMusicMediaSessionAction("seekforward", (details) => {
        if (!musicAudioElement) {
          return;
        }
        const duration = Number.isFinite(musicAudioElement.duration) ? musicAudioElement.duration : Number.MAX_SAFE_INTEGER;
        musicAudioElement.currentTime = Math.min(duration, musicAudioElement.currentTime + (details?.seekOffset ?? 10));
      });
      installMusicMediaSessionAction("seekto", (details) => {
        if (!musicAudioElement || typeof details?.seekTime !== "number") {
          return;
        }
        if (details.fastSeek && "fastSeek" in musicAudioElement) {
          musicAudioElement.fastSeek(details.seekTime);
        } else {
          musicAudioElement.currentTime = Math.max(0, details.seekTime);
        }
      });
      setMusicMediaSessionPlaybackState(musicAudioElement && !musicAudioElement.paused ? "playing" : activeMusicTrack ? "paused" : "none");
    } catch (error) {
      musicMediaSessionStatus = `Media session error: ${error instanceof Error ? error.message : String(error)}`;
    }
  }

  function startActiveMusicPlaybackTimer() {
    musicPlaybackStartedAt = Math.max(0, Math.floor(musicAudioElement?.currentTime ?? 0));
    musicPlaybackRecordedUntil = musicPlaybackStartedAt;
    activeMusicCurrentTimeSeconds = Math.max(0, musicAudioElement?.currentTime ?? 0);
    setupMusicEqualizerGraph();
    setMusicMediaSessionPlaybackState("playing");
  }

  function handleActiveMusicTimeUpdate() {
    activeMusicCurrentTimeSeconds = Math.max(0, musicAudioElement?.currentTime ?? 0);
    syncMusicMediaSessionPosition();
    void recordActiveMusicPlayback(false);
  }

  function handleActiveMusicPause() {
    setMusicMediaSessionPlaybackState(activeMusicTrack ? "paused" : "none");
    void recordActiveMusicPlayback(true);
  }

  function handleActiveMusicEnded() {
    setMusicMediaSessionPlaybackState("paused");
    void recordActiveMusicPlayback(true);
    advanceMusicTrack(1);
  }

  async function recordActiveMusicPlayback(force = false) {
    if (!activeMusicTrack || !musicAudioElement || musicPlaybackBusy) {
      return;
    }
    const currentSecond = Math.max(0, Math.floor(musicAudioElement.currentTime));
    const playedSeconds = Math.max(0, currentSecond - musicPlaybackRecordedUntil);
    if (!force && playedSeconds < 20) {
      return;
    }
    if (playedSeconds <= 0) {
      return;
    }
    musicPlaybackBusy = true;
    try {
      musicPlaybackStats = await recordMusicPlayback(activeMusicTrack, playedSeconds);
      musicPlaybackRecordedUntil = currentSecond;
      await refreshMusicLocalSummary();
      musicError = "";
    } catch (error) {
      musicError = error instanceof Error ? error.message : String(error);
    } finally {
      musicPlaybackBusy = false;
    }
  }

