          musicPlaybackRecordedUntil = Math.max(0, Math.floor(musicAudioElement?.currentTime ?? 0));
          await refreshLearningDashboard();
          await refreshMusicLocalSummary();
          musicError = "";
          pushToast(createToast("Playback history cleared", "success", "Music stats were reset locally.", targetToastAction("Open", "music", { query: "" })));
        } catch (error) {
          musicError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Playback history clear failed", "error", musicError));
        } finally {
          musicPlaybackBusy = false;
        }
      }
    };
  }

