  function advanceMusicTrack(direction: 1 | -1) {
    if (!activeMusicTrack || musicQueue.length === 0) {
      return;
    }
    const index = musicQueue.findIndex((track) => track.path === activeMusicTrack?.path);
    const nextIndex = direction === 1
      ? (index + 1) % musicQueue.length
      : index <= 0 ? musicQueue.length - 1 : index - 1;
    setActiveMusicTrack(musicQueue[nextIndex] ?? null);
    startActiveMusicPlaybackTimer();
    void persistMusicQueue();
  }

  function playNextMusicTrack() {
    void recordActiveMusicPlayback(true);
    advanceMusicTrack(1);
  }

  function playPreviousMusicTrack() {
    void recordActiveMusicPlayback(true);
    advanceMusicTrack(-1);
  }

  function moveMusicQueueTrack(track: MusicTrack, direction: -1 | 1) {
    const index = musicQueue.findIndex((item) => item.path === track.path);
    const nextIndex = index + direction;
    if (index < 0 || nextIndex < 0 || nextIndex >= musicQueue.length) {
      return;
    }
    const nextQueue = [...musicQueue];
    [nextQueue[index], nextQueue[nextIndex]] = [nextQueue[nextIndex], nextQueue[index]];
    musicQueue = nextQueue;
    void persistMusicQueue();
  }

  function dedupeMusicQueueTracks() {
    const seen = new Set<string>();
    const nextQueue = musicQueue.filter((track) => {
      if (seen.has(track.path)) {
        return false;
      }
      seen.add(track.path);
      return true;
    });
    const removed = musicQueue.length - nextQueue.length;
    if (removed === 0) {
      pushToast(createToast("Music queue unchanged", "info", "No duplicate queued tracks found."));
      return;
    }
    musicQueue = nextQueue;
    const activePath = activeMusicTrack?.path ?? "";
    if (activePath && !musicQueue.some((track) => track.path === activePath)) {
      setActiveMusicTrack(musicQueue[0] ?? null);
    }
    void persistMusicQueue();
    pushToast(createToast("Music queue deduped", "success", `${removed} duplicate track${removed === 1 ? "" : "s"} removed.`, targetToastAction("Open", "music", { query: activeMusicTrack?.title ?? "" })));
  }

  function shuffleMusicQueueTracks() {
    if (musicQueue.length < 2) {
      pushToast(createToast("Music queue unchanged", "info", "Add at least two tracks before shuffling."));
      return;
    }
    const activePath = activeMusicTrack?.path ?? musicQueue[0]?.path ?? "";
    const active = musicQueue.find((track) => track.path === activePath) ?? null;
    const rest = musicQueue.filter((track) => track.path !== activePath);
    for (let index = rest.length - 1; index > 0; index -= 1) {
      const swapIndex = Math.floor(Math.random() * (index + 1));
      [rest[index], rest[swapIndex]] = [rest[swapIndex], rest[index]];
    }
    musicQueue = active ? [active, ...rest] : rest;
    void persistMusicQueue();
    pushToast(createToast("Music queue shuffled", "success", `${musicQueue.length} queued track${musicQueue.length === 1 ? "" : "s"} reordered.`, musicTrackToastAction(active)));
  }

  function clearMusicQueueTracks() {
    if (musicQueue.length === 0) {
      return;
    }
    const cleared = musicQueue.length;
    musicQueue = [];
    setActiveMusicTrack(null);
    void persistMusicQueue();
    pushToast(createToast("Music queue cleared", "success", `${cleared} queued track${cleared === 1 ? "" : "s"} removed.`, targetToastAction("Open", "music", { query: "" })));
  }

  function removeMusicQueueTrack(track: MusicTrack) {
    musicQueue = musicQueue.filter((item) => item.path !== track.path);
    if (activeMusicTrack?.path === track.path) {
      setActiveMusicTrack(musicQueue[0] ?? null);
    }
    void persistMusicQueue();
  }

  function buildSubtitleWorkshopSavePreview(content: string, outputPath: string, currentFormat: string): string {
    if (!content.trim() || !outputPath.trim()) {
      return "";
    }

    try {
      const conversion = convertSubtitleWorkshopFormat(
        content,
        outputPath.trim(),
        currentFormat
      );
      return conversion.converted
        ? `${conversion.fromFormat.toUpperCase()} -> ${conversion.toFormat.toUpperCase()} · ${conversion.cueCount} cues will be saved`
        : `${conversion.toFormat.toUpperCase()} save · no format conversion`;
    } catch (error) {
      return error instanceof Error ? error.message : String(error);
    }
  }

  async function openSubtitleWorkshop() {
    const inputPath = subtitleWorkshopInputPath.trim();
    if (!inputPath) {
      subtitleWorkshopError = "Subtitle path is required.";
      pushToast(createToast("Subtitle Workshop invalid", "error", subtitleWorkshopError));
      return;
    }

    subtitleWorkshopBusy = true;
    subtitleWorkshopError = "";
    try {
      const result = await openSubtitleWorkshopFile(inputPath);
      subtitleWorkshopInputPath = result.path || inputPath;
      subtitleWorkshopOutputPath = subtitleWorkshopOutputPath || result.path || inputPath;
      subtitleWorkshopContent = result.content;
      subtitleWorkshopFormat = result.format;
      subtitleWorkshopLineCount = result.line_count;
      pushToast(createToast("Subtitle opened", "success", `${result.format.toUpperCase()} · ${result.line_count} lines`, advancedFileToastAction(result.path || inputPath)));
    } catch (error) {
      subtitleWorkshopContent = "";
      subtitleWorkshopFormat = "";
      subtitleWorkshopLineCount = 0;
      subtitleWorkshopError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Subtitle open failed", "error", subtitleWorkshopError));
    } finally {
      subtitleWorkshopBusy = false;
    }
  }

  async function saveSubtitleWorkshop() {
    const outputPath = subtitleWorkshopOutputPath.trim();
    if (!outputPath) {
      subtitleWorkshopError = "Output subtitle path is required.";
      pushToast(createToast("Subtitle Workshop invalid", "error", subtitleWorkshopError));
      return;
    }

    subtitleWorkshopBusy = true;
    subtitleWorkshopError = "";
    try {
      const conversion = convertSubtitleWorkshopFormat(
        subtitleWorkshopContent,
        outputPath,
        subtitleWorkshopFormat
      );
      const result = await saveSubtitleWorkshopFile({
        outputPath,
        content: conversion.content
      });
      subtitleWorkshopOutputPath = result.output_path || outputPath;
      subtitleWorkshopContent = conversion.content;
      subtitleWorkshopFormat = result.format;
      subtitleWorkshopLineCount = result.line_count;
      pushToast(createToast(
        "Subtitle saved",
        "success",
        conversion.converted ? `${conversion.fromFormat.toUpperCase()} -> ${conversion.toFormat.toUpperCase()} · ${conversion.cueCount} cues` : result.output_path || outputPath,
        advancedFileToastAction(result.output_path || outputPath)
      ));
    } catch (error) {
      subtitleWorkshopError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Subtitle save failed", "error", subtitleWorkshopError));
    } finally {
      subtitleWorkshopBusy = false;
    }
  }

  function replaceAllSubtitleWorkshopMatches() {
    try {
      const result = replaceSubtitleTextMatches(
        subtitleWorkshopContent,
        subtitleWorkshopFindText,
        subtitleWorkshopReplaceText,
        subtitleWorkshopFindOptions
      );
      subtitleWorkshopContent = result.content;
      subtitleWorkshopLineCount = result.content ? result.content.split(/\r?\n/).length : 0;
      subtitleWorkshopError = "";
      pushToast(createToast("Subtitle text replaced", "success", `${result.replacedCount} match${result.replacedCount === 1 ? "" : "es"} updated.`, advancedFileToastAction(subtitleWorkshopOutputPath || subtitleWorkshopInputPath)));
    } catch (error) {
      subtitleWorkshopError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Replace failed", "error", subtitleWorkshopError));
    }
  }

  function updateSubtitleWorkshopCueTiming() {
    const cursorPosition = subtitleWorkshopEditor?.selectionEnd ?? 0;
    const cue = findSubtitleCueTimingAtPosition(subtitleWorkshopContent, cursorPosition);
    subtitleWorkshopCueStartMs = cue?.startMilliseconds ?? null;
    subtitleWorkshopCueEndMs = cue?.endMilliseconds ?? null;
  }

  function waveformPeakOverlapsSubtitleCue(peak: WaveformPeaksResponse["peaks"][number]) {
    if (subtitleWorkshopCueStartMs === null || subtitleWorkshopCueEndMs === null) {
      return false;
    }

    const cueStartSeconds = subtitleWorkshopCueStartMs / 1000;
    const cueEndSeconds = subtitleWorkshopCueEndMs / 1000;
    return peak.end_seconds >= cueStartSeconds && peak.start_seconds <= cueEndSeconds;
  }

  function waveformPeakContainsShotMarker(peak: WaveformPeaksResponse["peaks"][number]) {
    return shotMarkers.some((marker) =>
      marker.timestamp_seconds >= peak.start_seconds && marker.timestamp_seconds <= peak.end_seconds
    );
  }

  function formatSubtitleCueTiming() {
    if (subtitleWorkshopCueStartMs === null || subtitleWorkshopCueEndMs === null) {
      return "No cue selected";
    }

    return `${formatTimestamp(subtitleWorkshopCueStartMs / 1000)} - ${formatTimestamp(subtitleWorkshopCueEndMs / 1000)}`;
  }

  function selectSubtitleCueAtWaveformPeak(peak: WaveformPeaksResponse["peaks"][number]) {
    selectedWaveformTimeSeconds = peak.start_seconds;
    selectSubtitleCueAtMilliseconds(peak.start_seconds * 1000, "No subtitle cue covers that waveform time.");
  }

  function jumpToWaveformTime() {
    const targetSeconds = parseWaveformSeekTime(waveformSeekTime, waveformResult?.duration_seconds ?? 0);
    if (targetSeconds === null) {
      waveformError = "Enter a waveform time as seconds, mm:ss, or hh:mm:ss.";
      pushToast(createToast("Waveform time invalid", "error", waveformError));
      return;
    }

    waveformError = "";
    selectedWaveformTimeSeconds = targetSeconds;
    selectSubtitleCueAtMilliseconds(targetSeconds * 1000, "No subtitle cue covers that waveform time.");
  }

  function selectSubtitleCueAtShotMarker(marker: ShotMarker) {
    selectSubtitleCueAtMilliseconds(marker.timestamp_seconds * 1000, "No subtitle cue is available near that shot marker.", true);
  }

  function selectSubtitleCueAtMilliseconds(
    timestampMilliseconds: number,
    notFoundMessage: string,
    allowNearest = false
  ) {
    const range = allowNearest
      ? findNearestSubtitleCueTextRangeAtTime(subtitleWorkshopContent, timestampMilliseconds)
      : findSubtitleCueTextRangeAtTime(subtitleWorkshopContent, timestampMilliseconds);
    if (!range || !subtitleWorkshopEditor) {
      subtitleWorkshopError = notFoundMessage;
      pushToast(createToast("Cue not found", "error", subtitleWorkshopError));
      return;
    }

    subtitleWorkshopEditor.focus();
    subtitleWorkshopEditor.setSelectionRange(range.start, range.end);
    updateSubtitleWorkshopCueTiming();
    subtitleWorkshopError = "";
  }

  function findNextSubtitleWorkshopMatch() {
    const cursorPosition = subtitleWorkshopEditor?.selectionEnd ?? 0;
    let match;
    try {
      match = findNextSubtitleTextMatch(
        subtitleWorkshopContent,
        subtitleWorkshopFindText,
        cursorPosition,
        subtitleWorkshopFindOptions
      );
    } catch (error) {
      subtitleWorkshopCurrentMatchIndex = 0;
      subtitleWorkshopError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Find next unavailable", "error", subtitleWorkshopError));
      return;
    }
    if (!match || !subtitleWorkshopEditor) {
      subtitleWorkshopCurrentMatchIndex = 0;
      subtitleWorkshopError = subtitleWorkshopFindText.trim() ? "No subtitle text matches found." : "Find text is required.";
      pushToast(createToast("Find next unavailable", "error", subtitleWorkshopError));
      return;
    }

    subtitleWorkshopEditor.focus();
    subtitleWorkshopEditor.setSelectionRange(match.start, match.end);
    updateSubtitleWorkshopCueTiming();
    subtitleWorkshopCurrentMatchIndex =
      findSubtitleTextMatches(subtitleWorkshopContent.slice(0, match.end), subtitleWorkshopFindText, subtitleWorkshopFindOptions);
    subtitleWorkshopError = "";
  }

  function autoFixSubtitleWorkshopText() {
    const result = autoFixSubtitleText(subtitleWorkshopContent);
    subtitleWorkshopContent = result.content;
    subtitleWorkshopLineCount = result.content ? result.content.split(/\r?\n/).length : 0;
    updateSubtitleWorkshopCueTiming();
    subtitleWorkshopError = "";
    pushToast(createToast("Subtitle auto fix applied", "success", `${result.fixedCount} issue${result.fixedCount === 1 ? "" : "s"} fixed.`, advancedFileToastAction(subtitleWorkshopOutputPath || subtitleWorkshopInputPath)));
  }

  function cleanupSubtitleWorkshopTimeline() {
    const result = cleanupSubtitleTimeline(subtitleWorkshopContent);
    subtitleWorkshopContent = result.content;
    subtitleWorkshopLineCount = result.content ? result.content.split(/\r?\n/).length : 0;
    updateSubtitleWorkshopCueTiming();
    subtitleWorkshopError = "";
    pushToast(createToast(
      "Subtitle timeline cleaned",
      "success",
      `${result.removedDuplicateCount} duplicate${result.removedDuplicateCount === 1 ? "" : "s"} removed, ${result.adjustedOverlapCount} overlap${result.adjustedOverlapCount === 1 ? "" : "s"} adjusted.`,
      advancedFileToastAction(subtitleWorkshopOutputPath || subtitleWorkshopInputPath)
    ));
  }

  function shiftSubtitleWorkshopTiming() {
    const offsetMilliseconds = Number(subtitleWorkshopTimingOffset);
    if (!Number.isFinite(offsetMilliseconds)) {
      subtitleWorkshopError = "Timing offset must be a finite number.";
      pushToast(createToast("Timing shift invalid", "error", subtitleWorkshopError));
      return;
    }

    const result = shiftSubtitleTiming(subtitleWorkshopContent, offsetMilliseconds);
    subtitleWorkshopContent = result.content;
    subtitleWorkshopLineCount = result.content ? result.content.split(/\r?\n/).length : 0;
    updateSubtitleWorkshopCueTiming();
    subtitleWorkshopError = "";
    pushToast(createToast("Subtitle timing shifted", "success", `${result.shiftedCount} timestamp${result.shiftedCount === 1 ? "" : "s"} updated.`, advancedFileToastAction(subtitleWorkshopOutputPath || subtitleWorkshopInputPath)));
  }

  function formatSubtitleWorkshopSyncValue(milliseconds: number) {
    return String(Math.round(milliseconds));
  }

  function useSelectedSubtitleCueAsSyncPoint(point: "a" | "b", boundary: "start" | "end" = "start") {
    updateSubtitleWorkshopCueTiming();
    const selectedMilliseconds = boundary === "start" ? subtitleWorkshopCueStartMs : subtitleWorkshopCueEndMs;
    if (selectedMilliseconds === null) {
      subtitleWorkshopError = "Select a timed subtitle cue first.";
      pushToast(createToast("Sync point unavailable", "error", subtitleWorkshopError));
      return;
    }
    const value = formatSubtitleWorkshopSyncValue(selectedMilliseconds);
    if (point === "a") {
      subtitleWorkshopSyncSourceA = value;
      subtitleWorkshopSyncTargetA = subtitleWorkshopSyncTargetA || value;
    } else {
      subtitleWorkshopSyncSourceB = value;
      subtitleWorkshopSyncTargetB = subtitleWorkshopSyncTargetB || value;
    }
    subtitleWorkshopError = "";
  }

  function useSelectedWaveformTimeAsSyncTarget(point: "a" | "b") {
    if (selectedWaveformTimeSeconds === null) {
      subtitleWorkshopError = "Select a waveform time first.";
      pushToast(createToast("Sync target unavailable", "error", subtitleWorkshopError));
      return;
    }
    const value = formatSubtitleWorkshopSyncValue(selectedWaveformTimeSeconds * 1000);
    if (point === "a") {
      subtitleWorkshopSyncTargetA = value;
      subtitleWorkshopSyncSourceA = subtitleWorkshopSyncSourceA || value;
    } else {
      subtitleWorkshopSyncTargetB = value;
      subtitleWorkshopSyncSourceB = subtitleWorkshopSyncSourceB || value;
    }
    subtitleWorkshopError = "";
  }

  function clearSubtitleWorkshopSyncPoints() {
    subtitleWorkshopSyncSourceA = "";
    subtitleWorkshopSyncTargetA = "";
    subtitleWorkshopSyncSourceB = "";
    subtitleWorkshopSyncTargetB = "";
    subtitleWorkshopError = "";
  }

  function syncSubtitleWorkshopTimingToTwoPoints() {
    let sourceA;
    let targetA;
    let sourceB;
    let targetB;
    try {
      sourceA = parseSubtitleWorkshopMilliseconds(subtitleWorkshopSyncSourceA, "Source A");
      targetA = parseSubtitleWorkshopMilliseconds(subtitleWorkshopSyncTargetA, "Target A");
      sourceB = parseSubtitleWorkshopMilliseconds(subtitleWorkshopSyncSourceB, "Source B");
      targetB = parseSubtitleWorkshopMilliseconds(subtitleWorkshopSyncTargetB, "Target B");
      const result = syncSubtitleTimingToTwoPoints(subtitleWorkshopContent, {
        sourceA,
        targetA,
        sourceB,
        targetB
      });
      subtitleWorkshopContent = result.content;
      subtitleWorkshopLineCount = result.content ? result.content.split(/\r?\n/).length : 0;
      updateSubtitleWorkshopCueTiming();
      subtitleWorkshopError = "";
      pushToast(createToast("Subtitle timing synced", "success", `${result.syncedCount} timestamp${result.syncedCount === 1 ? "" : "s"} updated.`, advancedFileToastAction(subtitleWorkshopOutputPath || subtitleWorkshopInputPath)));
    } catch (error) {
      subtitleWorkshopError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Two-point sync failed", "error", subtitleWorkshopError));
    }
  }

  function parseSubtitleWorkshopMilliseconds(value: string, label: string): number {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) {
      throw new Error(`${label} must be a finite millisecond value.`);
    }
    return parsed;
  }

  async function cancelHomeVideoClip() {
    if (!clipJobId) {
      return;
    }

    try {
      await cancelClipVideo(clipJobId);
      clipStatusMessage = "Cancel requested.";
    } catch (error) {
      clipError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Clip cancel failed", "error", clipError));
    }
  }

  async function cancelTranscodeJob() {
    if (!transcodeJobId) {
      return;
    }

    try {
      await cancelClipVideo(transcodeJobId);
      transcodeStatusMessage = "Cancel requested.";
    } catch (error) {
      transcodeError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Transcode cancel failed", "error", transcodeError));
    }
  }

  async function cancelTask(task: DownloadTask) {
    try {
      const updated = await cancelDownloadTask(task.id);
      if (updated) {
        downloads = downloads.map((item) => (item.id === updated.id ? updated : item));
      }
      pushToast(createToast("Task canceled", "success", task.source_url, downloadTaskToastAction(updated ?? task)));
    } catch (error) {
      pushToast(createToast("Cancel failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  function upsertTask(updated: DownloadTask | null) {
    if (!updated) {
      return;
    }

    const exists = downloads.some((item) => item.id === updated.id);
    downloads = (exists
      ? downloads.map((item) => (item.id === updated.id ? updated : item))
      : [updated, ...downloads]
    ).sort((first, second) => first.position - second.position);
  }

  function showDownloadStateToast(event: DownloadStateEvent) {
    if (event.previous_status === event.status) {
      return;
    }

    const terminalStates = new Set<DownloadTask["status"]>(["completed", "failed"]);
    if (!terminalStates.has(event.status)) {
      return;
    }

    const task = event.task;
    const label = task.title || task.source_url || task.id;
    const messageParts = [
      task.kind,
      task.platform && task.platform !== "generic" ? task.platform : "",
      task.output_path ? `Output: ${task.output_path}` : "",
      event.status === "failed" && task.last_error ? task.last_error : "",
      event.status === "completed" && task.downloaded_bytes ? formatBytes(task.downloaded_bytes) : ""
    ].filter(Boolean);

    const toastTitle =
      event.status === "completed"
        ? "Download completed"
        : "Download failed";
    const toastLevel = event.status === "completed" ? "success" : event.status === "failed" ? "error" : "info";

    pushToast(
      createToast(toastTitle, toastLevel, messageParts.join(" · ") || label, {
        label: "Detail",
        onClick: () => void focusDownloadTaskById(task.id, label)
      })
    );
  }

  function handleDownloadState(event: DownloadStateEvent) {
    upsertTask(event.task);
    void refreshDownloadsLocalSummary(false);
    if (["completed", "failed", "canceled"].includes(event.status)) {
      const nextActiveIds = new Set(activeTaskIds);
      nextActiveIds.delete(event.task_id);
      activeTaskIds = nextActiveIds;
    }
    showDownloadStateToast(event);
  }

  function handleDownloadCompleted(event: DownloadCompletedEvent) {
    upsertTask(event.task);
    void refreshDownloadsLocalSummary(false);
    const nextActiveIds = new Set(activeTaskIds);
    nextActiveIds.delete(event.task.id);
    activeTaskIds = nextActiveIds;
  }

  function handleDownloadFailed(event: DownloadFailedEvent) {
    upsertTask(event.task);
    void refreshDownloadsLocalSummary(false);
    const nextActiveIds = new Set(activeTaskIds);
    nextActiveIds.delete(event.task.id);
    activeTaskIds = nextActiveIds;
  }

  function handleDownloadsListChanged(event: DownloadsListChangedEvent) {
    downloads = [...event.tasks].sort((first, second) => first.position - second.position);
    void refreshDownloadsLocalSummary(false);
    const taskById = new Map(downloads.map((task) => [task.id, task]));
    if (selectedTaskDetail) {
      selectedTaskDetail = taskById.get(selectedTaskDetail.id) ?? null;
    }
    if (selectedTaskId && !taskById.has(selectedTaskId)) {
      selectedTaskId = "";
      selectedTaskLogs = [];
      selectedTaskLogEntries = [];
      downloadLogNextCursor = null;
      downloadLogTotalLines = 0;
      downloadLogMatchedLines = 0;
    }
  }

  function handleDownloadProgress(progress: DownloadProgressEvent) {
    downloads = downloads.map((task) => {
      if (task.id !== progress.task_id) {
        return task;
      }

      return {
        ...task,
        status: progress.status,
        downloaded_bytes: progress.downloaded_bytes,
        total_bytes: progress.total_bytes ?? task.total_bytes,
        speed_bytes_per_sec: progress.speed_bytes_per_sec ?? task.speed_bytes_per_sec,
        eta_seconds: progress.eta_seconds ?? task.eta_seconds,
        file_count: progress.file_count ?? task.file_count,
        output_path: progress.output_path ?? task.output_path,
        last_error: progress.status === "failed" ? progress.message : task.last_error,
        updated_at: progress.updated_at
      };
    });

    if (progress.status === "completed" || progress.status === "failed") {
      const nextActiveIds = new Set(activeTaskIds);
      nextActiveIds.delete(progress.task_id);
      activeTaskIds = nextActiveIds;
    }
  }

  function handleClipProgress(progress: ClipProgressEvent) {
    if (clipJobId && progress.job_id === clipJobId) {
      clipElapsedSeconds = progress.elapsed_seconds;
      clipStatusMessage = progress.message;
      if (progress.status === "failed" || progress.status === "canceled") {
        clipError = progress.message;
        clipBusy = false;
      }
      if (progress.status === "completed") {
        clipError = "";
        clipBusy = false;
      }
    }

    if (transcodeJobId && progress.job_id === transcodeJobId) {
      transcodeElapsedSeconds = progress.elapsed_seconds;
      transcodeStatusMessage = progress.message;
      if (progress.status === "failed" || progress.status === "canceled") {
        transcodeError = progress.message;
        transcodeBusy = false;
      }
      if (progress.status === "completed") {
        transcodeError = "";
        transcodeBusy = false;
      }
    }
  }

  async function startTask(task: DownloadTask) {
    activeTaskIds = new Set([...activeTaskIds, task.id]);
    try {
      const updated = await startDownloadTask(task.id);
      upsertTask(updated);
      pushToast(createToast("Download started", "success", task.source_url, downloadTaskToastAction(updated ?? task)));
    } catch (error) {
      pushToast(createToast("Download failed", "error", error instanceof Error ? error.message : String(error)));
      const nextActiveIds = new Set(activeTaskIds);
      nextActiveIds.delete(task.id);
      activeTaskIds = nextActiveIds;
    }
  }

  function canStartTask(task: DownloadTask) {
    return task.status === "queued" || task.status === "failed";
