  async function runDownloadTaskBatchAction(action: DownloadTaskBatchAction, tasks: DownloadTask[], label = "Bulk action") {
    if (tasks.length === 0) {
      return;
    }

    downloadBulkBusy = action;
    try {
      const result = await runDownloadBulkAction(
        action,
        tasks.map((task) => task.id)
      );
      if (!result) {
        return;
      }
      if (result.tasks.length > 0) {
        const updatedById = new Map(result.tasks.map((task) => [task.id, task]));
        if (action === "delete") {
          downloads = downloads.filter((item) => !updatedById.has(item.id));
        } else {
          downloads = downloads
            .map((item) => updatedById.get(item.id) ?? item)
            .sort((first, second) => first.position - second.position);
        }
        if (action === "pause" || action === "cancel" || action === "delete") {
          const nextActiveIds = new Set(activeTaskIds);
          for (const task of result.tasks) {
            nextActiveIds.delete(task.id);
          }
          activeTaskIds = nextActiveIds;
        }
      }
      const succeeded = result.tasks.length;
      const failed = result.failed.length;
      pushToast(
        createToast(
          `${label} finished`,
          failed > 0 ? "error" : "success",
          `${succeeded} succeeded${failed > 0 ? ` · ${failed} failed` : ""}`,
          firstTaskToastAction(result.tasks)
        )
      );
    } catch (error) {
      pushToast(createToast(`${label} failed`, "error", error instanceof Error ? error.message : String(error)));
    } finally {
      downloadBulkBusy = "";
    }
  }

  async function runBulkDownloadAction(action: DownloadTaskBatchAction) {
    const tasks =
      action === "start"
        ? visibleStartableDownloads
        : action === "pause"
          ? visibleActiveDownloads
          : action === "resume"
            ? visiblePausedDownloads
            : action === "retry"
              ? visibleFailedDownloads
              : action === "cancel"
                ? visibleCancelableDownloads
                : action === "archive"
                  ? visibleArchivableDownloads
                  : visibleRestorableDownloads;

    await runDownloadTaskBatchAction(action, tasks, "Visible downloads");
  }

  function requestVisibleDownloadsDelete() {
    const tasks = filteredDownloads;
    if (tasks.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Delete visible download tasks?",
      message: `Remove ${tasks.length} visible download task record${tasks.length === 1 ? "" : "s"} from local history. Output files and unrelated task records are left untouched.`,
      confirmLabel: "Delete visible",
      onConfirm: async () => {
        const targetIds = new Set(tasks.map((task) => task.id));
        await runDownloadTaskBatchAction("delete", tasks, "Visible download delete");
        if (selectedTaskDetail && targetIds.has(selectedTaskDetail.id)) {
          selectedTaskDetail = null;
        }
        if (selectedTaskId && targetIds.has(selectedTaskId)) {
          selectedTaskId = "";
          selectedTaskLogs = [];
          selectedTaskLogEntries = [];
        }
      }
    };
  }

  async function clearCompleted() {
    try {
      const archiveCompleted = (downloadsSettings?.completed_task_cleanup ?? "archive") !== "delete";
      const affected = await clearCompletedDownloads();
      await loadDownloads();
      pushToast(createToast(
        archiveCompleted ? "Completed tasks archived" : "Completed tasks deleted",
        "success",
        `${affected} task${affected === 1 ? "" : "s"}`,
        targetToastAction("Open", "downloads", { status: archiveCompleted ? "archived" : "completed" })
      ));
    } catch (error) {
      pushToast(createToast("Clear failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  function requestArchivedDownloadsClear() {
    confirmDialog = {
      title: "Clear archived downloads?",
      message: `Remove archived download task records from local history${downloadsSettings?.archived_task_retention_days ? ` older than ${downloadsSettings.archived_task_retention_days} day${downloadsSettings.archived_task_retention_days === 1 ? "" : "s"}` : ""}. Output files, active tasks, completed history, failed history, and canceled history are left untouched.`,
      confirmLabel: "Clear",
      onConfirm: async () => {
        downloadBulkBusy = "clear-archived";
        try {
          const affected = await clearArchivedDownloads();
          await loadDownloads();
          pushToast(createToast("Archived downloads cleared", "success", `${affected} task${affected === 1 ? "" : "s"}`, targetToastAction("Open", "downloads", { status: "archived" })));
        } catch (error) {
          pushToast(createToast("Archive clear failed", "error", error instanceof Error ? error.message : String(error)));
        } finally {
          downloadBulkBusy = "";
        }
      }
    };
  }

  function formatBytes(bytes: number) {
    if (bytes < 1024) {
      return `${bytes} B`;
    }

    if (bytes < 1024 * 1024) {
      return `${(bytes / 1024).toFixed(1)} KB`;
    }

    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

