  function filterPlatformRouteSampleResults(
    samples: Array<{ label: string; url: string; classification: UrlCandidateClassification | null }>,
    query: string,
    kind: string
  ): Array<{ label: string; url: string; classification: UrlCandidateClassification | null }> {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedKind = kind.trim().toLowerCase();
    return samples.filter((sample) => {
      const classification = sample.classification;
      if (normalizedKind && normalizedKind !== "all") {
        if (!classification || platformRouteSampleTaskKind(classification) !== normalizedKind) {
          return false;
        }
      }
      if (!normalizedQuery) {
        return true;
      }
      return [
        sample.label,
        sample.url,
        classification?.label,
        classification?.platform,
        classification?.kind,
        classification?.intent,
        classification ? platformRouteSampleTaskKind(classification) : null,
        classification?.detail,
        classification?.subtype,
        classification?.subtypeLabel
      ]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

  function platformRouteSampleTaskKind(classification: UrlCandidateClassification | null): DownloadKind {
    if (!classification) {
      return "video";
    }
    if (classification.intent === "gallery" || classification.suggestedKind === "image") {
      return "image";
    }
    if (classification.intent === "playlist") {
      return "playlist";
    }
    return classification.suggestedKind;
  }

