  function pluginI18nSummary(plugin: PluginInfo): string {
    const metadata = plugin.i18n;
    if (!metadata || typeof metadata !== "object") {
      return "";
    }
    const record = metadata as Record<string, unknown>;
    const locales = Array.isArray(record.locales)
      ? record.locales.filter((value): value is string => typeof value === "string" && value.trim().length > 0)
      : [];
    const labels = record.labels && typeof record.labels === "object" ? record.labels as Record<string, unknown> : null;
    const messages = record.messages && typeof record.messages === "object" ? record.messages as Record<string, unknown> : null;
    const translations = record.translations && typeof record.translations === "object" ? record.translations as Record<string, unknown> : null;
    const keySource = labels ?? messages ?? translations;
    const keyCount = keySource ? Object.keys(keySource).length : 0;
    const parts = [
      locales.length > 0 ? locales.join(", ") : "",
      keyCount > 0 ? `${keyCount} key group${keyCount === 1 ? "" : "s"}` : ""
    ].filter(Boolean);
    return parts.length > 0 ? parts.join(" · ") : "metadata present";
  }

  function pluginNavItemLabel(plugin: PluginInfo, item: PluginInfo["nav_items"][number], language: string): string {
    const metadata = plugin.i18n;
    if (!metadata || typeof metadata !== "object") {
      return item.label;
    }
    const record = metadata as Record<string, unknown>;
    const labels = record.labels && typeof record.labels === "object" ? record.labels as Record<string, unknown> : null;
    const messages = record.messages && typeof record.messages === "object" ? record.messages as Record<string, unknown> : null;
    const translations = record.translations && typeof record.translations === "object" ? record.translations as Record<string, unknown> : null;
    const source = labels ?? messages ?? translations;
    if (!source) {
      return item.label;
    }

    const languageCandidates = [
      language,
      language.split("-")[0],
      "en"
    ].filter((value, index, values) => value && values.indexOf(value) === index);
    const keyCandidates = [
      `nav.${item.id}`,
      `nav_items.${item.id}`,
      item.id,
      item.label
    ];

    for (const lang of languageCandidates) {
      const localized = source[lang];
      if (!localized || typeof localized !== "object") {
        continue;
      }
      const localizedRecord = localized as Record<string, unknown>;
      for (const key of keyCandidates) {
        const value = localizedRecord[key];
        if (typeof value === "string" && value.trim()) {
          return value.trim();
        }
      }
    }

    for (const key of keyCandidates) {
      const value = source[key];
      if (typeof value === "string" && value.trim()) {
        return value.trim();
      }
    }

    return item.label;
  }

