        plugin.manifest_path,
        plugin.last_error,
        ...plugin.capabilities,
        ...plugin.permissions,
        ...plugin.commands,
        ...plugin.events.map((event) => event.name),
        ...plugin.nav_items.map((item) => item.label),
        ...plugin.nav_items.map((item) => pluginNavItemLabel(plugin, item, appLanguage)),
        pluginI18nSummary(plugin),
        plugin.i18n ? JSON.stringify(plugin.i18n) : ""
      ]
