  function cookieBucketScopeLabel(bucket: CookieBucket): string {
    const paths = bucket.path_hints?.length ? bucket.path_hints.slice(0, 3).join(", ") : "/";
    const extraPaths = bucket.path_hints && bucket.path_hints.length > 3 ? ` +${bucket.path_hints.length - 3}` : "";
    const security = bucket.secure_only ? "HTTPS-only" : "HTTP/HTTPS";
    return `${bucket.domain_hints.join(", ") || "no domains"} · paths ${paths}${extraPaths} · ${security}${bucket.expires_summary ? ` · ${bucket.expires_summary}` : ""}`;
  }

