    status: string
  ): PomodoroSession[] {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedStatus = status.trim().toLowerCase();

    return sessions.filter((session) => {
      if (normalizedStatus === "completed" && !session.completed) {
        return false;
      }
      if (normalizedStatus === "open" && session.completed) {
        return false;
      }
      if (normalizedStatus === "linked" && !session.linked_source_url) {
        return false;
      }
      if (!normalizedQuery) {
        return true;
      }

      return [
        session.label,
        session.id,
        session.linked_source_url,
        session.started_at,
        session.ended_at,
        `${session.duration_minutes} min`,
        `${session.break_minutes} break`,
        session.completed ? "completed" : "open"
      ]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

  function visiblePomodoroSessions(sessions: PomodoroSession[]): PomodoroSession[] {
    if (pomodoroSessionsExpanded || pomodoroSessionSearch.trim() || pomodoroSessionStatusFilter !== "all") {
      return sessions;
    }
    return sessions.slice(0, 12);
  }

  function filterChannels(items: ChannelSubscription[], query: string, autoDownload: string) {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedAutoDownload = autoDownload.trim().toLowerCase();

    return items.filter((channel) => {
      if (normalizedAutoDownload === "enabled" && !channel.auto_download) {
        return false;
      }
      if (normalizedAutoDownload === "disabled" && channel.auto_download) {
        return false;
      }
      if (normalizedAutoDownload === "errors" && !channel.last_error) {
        return false;
      }
      if (!normalizedQuery) {
        return true;
      }

      return [
        channel.name,
        channel.id,
        channel.platform,
        channel.source_url,
        channel.last_checked_at,
        channel.last_error,
        channel.created_at,
        channel.updated_at,
        channel.enabled ? "enabled" : "disabled",
        channel.auto_download ? "auto download" : "manual"
      ]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

  function filterChannelHistory(items: ChannelHistoryItem[], query: string, status: string) {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedStatus = status.trim().toLowerCase();

    return items.filter((item) => {
      if (normalizedStatus === "pending" && item.notification_status !== "pending") {
        return false;
      }
      if (normalizedStatus === "queued" && !item.created_task_id) {
        return false;
      }
      if (normalizedStatus === "error" && !item.error) {
        return false;
      }
      if (normalizedStatus === "ready" && (item.error || item.created_task_id)) {
        return false;
      }

      if (!normalizedQuery) {
        return true;
      }

      return [item.id, item.channel_id, item.title, item.author, item.source_url, item.source_kind, item.created_task_id, item.error, item.notification_status]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

  function visibleChannelHistoryItems(items: ChannelHistoryItem[]): ChannelHistoryItem[] {
    if (channelHistoryExpanded || channelHistorySearch.trim() || channelHistoryStatusFilter !== "all") {
      return items;
    }
    return items.slice(0, 20);
  }

  function queueableChannelHistoryItems(items: ChannelHistoryItem[]): ChannelHistoryItem[] {
    return items.filter((item) => !item.error);
  }

  function filterTelegramChats(
    chats: TelegramChat[],
    query: string,
    mediaType: "all" | TelegramMediaItem["media_type"]
  ): TelegramChat[] {
    const normalizedQuery = query.trim().toLowerCase();

    return chats
      .map((chat) => {
        const chatMatches = !normalizedQuery || [chat.id, chat.title, chat.username, chat.kind]
          .filter(Boolean)
          .some((value) => String(value).toLowerCase().includes(normalizedQuery));
        const media = chat.media.filter((item) => {
          if (mediaType !== "all" && item.media_type !== mediaType) {
            return false;
          }
          if (chatMatches) {
            return true;
          }
          return [item.id, item.chat_id, item.title, item.media_type, item.source_url, item.local_path]
            .filter(Boolean)
            .some((value) => String(value).toLowerCase().includes(normalizedQuery));
        });

        return { ...chat, media, media_count: media.length };
      })
      .filter((chat) => chat.media.length > 0 || (!normalizedQuery && mediaType === "all"));
  }

  function filterTelegramChannelDrawerChats(
    chats: TelegramChat[],
    kind: "all" | "channel" | "group"
  ): TelegramChat[] {
    return chats
      .filter((chat) => chat.kind === "channel" || chat.kind === "group")
      .filter((chat) => kind === "all" || chat.kind === kind)
      .sort((left, right) => {
        const leftTime = Date.parse(left.last_message_at ?? left.updated_at);
        const rightTime = Date.parse(right.last_message_at ?? right.updated_at);
        return (Number.isNaN(rightTime) ? 0 : rightTime) - (Number.isNaN(leftTime) ? 0 : leftTime);
      });
  }

