    return items.filter((course) => {
      const courseValues = [course.id, course.title, course.platform, course.source_url, course.status, course.remote_extraction_note];
      const lessonValues = course.lessons.flatMap((lesson) => [lesson.id, lesson.title, lesson.source_url, lesson.local_path]);
      const attachmentValues = course.attachments.flatMap((attachment) => [
        attachment.id,
        attachment.title,
        attachment.kind,
        attachment.source_url,
        attachment.local_path
      ]);
      return [...courseValues, ...lessonValues, ...attachmentValues]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

