  function listLearningNoteTags(notes: LearningNote[]): string[] {
    const tags = new Set<string>();
    for (const note of notes) {
      for (const tag of note.tags) {
        const normalizedTag = tag.trim();
        if (normalizedTag) {
          tags.add(normalizedTag);
        }
      }
    }
    return Array.from(tags).sort((a, b) => a.localeCompare(b));
  }

  function filterLearningNotes(
    notes: LearningNote[],
    query: string,
    tag: string,
    sourceFilter: string,
    sortMode: string
  ): LearningNote[] {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedTag = tag.trim().toLowerCase();
    const normalizedSource = sourceFilter.trim().toLowerCase();

    const filtered = notes.filter((note) => {
      if (normalizedTag && normalizedTag !== "all" && !note.tags.some((item) => item.toLowerCase() === normalizedTag)) {
        return false;
      }
      if (normalizedSource === "with_source" && !note.source_url) {
        return false;
      }
      if (normalizedSource === "without_source" && note.source_url) {
        return false;
      }
      if (normalizedSource === "timestamped" && (note.timestamp_seconds === null || note.timestamp_seconds === undefined)) {
        return false;
      }
      if (normalizedSource === "linked" && note.outgoing_links.length === 0 && note.backlink_count === 0) {
        return false;
      }
      if (!normalizedQuery) {
        return true;
      }
      return [note.title, note.body, note.source_url, note.updated_at, ...note.tags, ...note.outgoing_links]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });

    return filtered.sort((a, b) => {
      if (sortMode === "created_desc") {
        return b.created_at.localeCompare(a.created_at);
      }
      if (sortMode === "created_asc") {
        return a.created_at.localeCompare(b.created_at);
      }
      if (sortMode === "title") {
        return a.title.localeCompare(b.title);
      }
      if (sortMode === "timestamp") {
        const aTime = a.timestamp_seconds ?? Number.MAX_SAFE_INTEGER;
        const bTime = b.timestamp_seconds ?? Number.MAX_SAFE_INTEGER;
        return aTime - bTime || b.updated_at.localeCompare(a.updated_at);
      }
      return b.updated_at.localeCompare(a.updated_at);
    });
  }

  function heatmapMonthLabels(days: LearningDashboard["heatmap"]): Array<{ label: string; column: number }> {
    const labels: Array<{ label: string; column: number }> = [];
    let previousMonth = "";
    for (let index = 0; index < days.length; index += 1) {
      const date = new Date(`${days[index].date}T00:00:00`);
      if (Number.isNaN(date.getTime())) {
        continue;
      }
      const monthKey = `${date.getUTCFullYear()}-${date.getUTCMonth()}`;
      if (monthKey !== previousMonth) {
        labels.push({
          label: date.toLocaleString(undefined, { month: "short", timeZone: "UTC" }),
          column: Math.floor(index / 7) + 1
        });
        previousMonth = monthKey;
      }
    }
    return labels;
  }

  function heatmapWeekdayLabels(days: LearningDashboard["heatmap"]): Array<{ label: string; row: number }> {
    const first = days[0]?.date ? new Date(`${days[0].date}T00:00:00`) : null;
    const offset = first && !Number.isNaN(first.getTime()) ? first.getUTCDay() : 0;
    return [
      { label: "Mon", row: ((1 - offset + 7) % 7) + 1 },
      { label: "Wed", row: ((3 - offset + 7) % 7) + 1 },
      { label: "Fri", row: ((5 - offset + 7) % 7) + 1 }
    ].sort((left, right) => left.row - right.row);
  }

  function graphPreviewLayout(graph: LearningGraph | null): {
    nodes: Array<LearningGraph["nodes"][number] & { x: number; y: number }>;
    edges: Array<LearningGraph["edges"][number] & { x1: number; y1: number; x2: number; y2: number }>;
  } {
    if (!graph || graph.nodes.length === 0) {
      return { nodes: [], edges: [] };
    }
    const visibleNodes = graph.nodes
      .slice()
      .sort((left, right) => right.backlink_count - left.backlink_count || left.title.localeCompare(right.title))
      .slice(0, 12);
    const radius = visibleNodes.length < 4 ? 54 : 78;
    const center = 100;
    const positioned = visibleNodes.map((node, index) => {
      const angle = (Math.PI * 2 * index) / visibleNodes.length - Math.PI / 2;
      return {
        ...node,
        x: Math.round((center + Math.cos(angle) * radius) * 10) / 10,
        y: Math.round((center + Math.sin(angle) * radius) * 10) / 10
      };
    });
    const byId = new Map(positioned.map((node) => [node.id, node]));
    const edges = graph.edges
      .map((edge) => {
        const source = byId.get(edge.source_id);
        const target = byId.get(edge.target_id);
        return source && target
          ? { ...edge, x1: source.x, y1: source.y, x2: target.x, y2: target.y }
          : null;
      })
      .filter((edge): edge is LearningGraph["edges"][number] & { x1: number; y1: number; x2: number; y2: number } => Boolean(edge))
      .slice(0, 24);
    return { nodes: positioned, edges };
  }

  function visibleLearningGraphNodes(graph: LearningGraph): LearningGraph["nodes"] {
    if (learningGraphNodesExpanded) {
      return graph.nodes;
    }
    return graph.nodes.slice(0, 10);
  }

  function visibleLearningGraphEdges(graph: LearningGraph, limit = 8): LearningGraph["edges"] {
    if (learningGraphEdgesExpanded) {
      return graph.edges;
    }
    return graph.edges.slice(0, limit);
  }

  function filterTransferTasks(tasks: DownloadTask[], query: string, status: string): DownloadTask[] {
    const normalizedQuery = query.trim().toLowerCase();
    const normalizedStatus = status.trim().toLowerCase();

    return tasks.filter((task) => {
      if (normalizedStatus && normalizedStatus !== "all" && task.status !== normalizedStatus) {
        return false;
      }
      if (!normalizedQuery) {
        return true;
      }
      return [task.id, task.title, task.source_url, task.platform, task.output_dir, task.output_path, task.last_error, task.status]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery));
    });
  }

  function filterTorrentP2pTransferTasks(tasks: DownloadTask[], query: string, kind: string, status: string): DownloadTask[] {
    const normalizedKind = kind.trim().toLowerCase();
    return filterTransferTasks(tasks, query, status).filter((task) => {
      if (!normalizedKind || normalizedKind === "all") {
        return true;
      }
      return task.kind === normalizedKind;
    });
  }

  function formatDuration(seconds?: number | null) {
    if (!seconds || seconds < 1) {
      return "Duration unknown";
    }

    const minutes = Math.floor(seconds / 60);
    const remainder = Math.floor(seconds % 60)
      .toString()
      .padStart(2, "0");
    if (minutes < 60) {
      return `${minutes}:${remainder}`;
    }

    const hours = Math.floor(minutes / 60);
    return `${hours}:${(minutes % 60).toString().padStart(2, "0")}:${remainder}`;
  }

  function formatPreviewFormat(format: MetadataPreview["formats"][number]) {
    const parts = [
      format.label,
      format.height ? `${format.height}p` : null,
      format.ext?.toUpperCase(),
      format.filesize_bytes ? formatBytes(format.filesize_bytes) : null
    ].filter(Boolean);
    return parts.join(" · ") || format.id;
  }

