  function playlistEntryTitle(entry: MetadataPlaylistEntry): string {
    return entry.title ?? entry.webpage_url ?? entry.url ?? entry.id ?? "Untitled item";
  }

  function playlistEntryUrl(entry: MetadataPlaylistEntry): string {
    return entry.webpage_url ?? entry.url ?? "";
  }

  function formatPlaylistEntryMeta(entry: MetadataPlaylistEntry): string {
    const parts = [
      entry.index ? `#${entry.index}` : null,
      entry.author,
      formatDuration(entry.duration_seconds),
      entry.id ? `id ${entry.id}` : null
    ].filter((part) => part && part !== "Duration unknown");
    return parts.join(" · ") || "Playlist item";
  }

  function galleryEntryTitle(entry: GalleryPreviewEntry): string {
    return entry.file_name ?? entry.url;
  }

  function formatGalleryEntryMeta(entry: GalleryPreviewEntry): string {
    const parts = [
      `#${entry.index}`,
      entry.media_kind && entry.media_kind !== "unknown" ? entry.media_kind : null,
      entry.extension ? entry.extension.toUpperCase() : null
    ].filter(Boolean);
    return parts.join(" · ") || "Gallery item";
  }

  function formatBilibiliHomeStatus(status: BilibiliAccountStatus | null) {
    if (!status) {
      return "Local Bilibili status not loaded";
    }

    const bucket = status.cookie_bucket_name
      ? `${status.cookie_bucket_name}${status.cookie_health ? ` (${status.cookie_health})` : ""}`
      : "no cookie bucket";
    return `${status.status} · ${bucket} · watch later ${status.imported_watch_later_count} · history ${status.imported_history_count}`;
  }

  function formatThumbnailOption(option: ThumbnailOption) {
    const dimensions = option.width && option.height ? `${option.width}x${option.height}` : null;
    const parts = [dimensions, option.preference !== null && option.preference !== undefined ? `pref ${option.preference}` : null].filter(Boolean);
    return parts.join(" · ") || option.url;
  }

  function formatChapterOption(option: ChapterOption) {
    const start = formatTimestamp(option.start_seconds);
    const end = formatTimestamp(option.end_seconds);
    return end ? `${start} - ${end}` : start;
  }

  function formatCommentMeta(option: CommentOption) {
    const parts = [
      option.author,
      option.timestamp_seconds !== null && option.timestamp_seconds !== undefined ? formatTimestamp(option.timestamp_seconds) : null,
      option.like_count !== null && option.like_count !== undefined ? `${option.like_count} like${option.like_count === 1 ? "" : "s"}` : null,
      option.reply_count !== null && option.reply_count !== undefined ? `${option.reply_count} repl${option.reply_count === 1 ? "y" : "ies"}` : null
    ].filter(Boolean);
    return parts.join(" · ") || "Comment";
  }

  function previewCommentText(text: string) {
    return text.length > 180 ? `${text.slice(0, 177)}...` : text;
  }

  function formatTimestamp(seconds?: number | null) {
    if (seconds === null || seconds === undefined || seconds < 0) {
      return "time unknown";
    }

    const wholeSeconds = Math.floor(seconds);
    const minutes = Math.floor(wholeSeconds / 60);
    const remainder = (wholeSeconds % 60).toString().padStart(2, "0");
    if (minutes < 60) {
      return `${minutes}:${remainder}`;
    }

    const hours = Math.floor(minutes / 60);
    return `${hours}:${(minutes % 60).toString().padStart(2, "0")}:${remainder}`;
  }

  function inferHomeTaskKind(url: string, selectedKind: DownloadKind): DownloadKind {
    return inferTaskKindForUrl(url, selectedKind);
