  function recommendedHomeTaskKind(url: string, selectedKind: DownloadKind): DownloadKind | null {
    return recommendedTaskKindForUrl(url, selectedKind);
  }

  function applyRecommendedHomeTaskKind(url: string) {
    const recommended = recommendedHomeTaskKind(url, taskKind);
    if (!recommended) {
      return;
    }
    taskKind = recommended;
    pushToast(createToast("Mode updated", "success", `Home will queue this URL as ${recommended}.`));
  }

  function buildHomeCreateOptions(kind: DownloadKind) {
    const hasSelectedSubtitles = selectedSubtitleKeys.length > 0;
    const canAttachSubtitleOptions = kind === "video" || kind === "audio" || kind === "playlist";
    const shouldAttachSubtitleOptions = kind === "subtitles_only" || (canAttachSubtitleOptions && hasSelectedSubtitles);
    return buildTaskCreateOptions({
      kind,
      outputDir: taskOutputDir,
      outputPath: taskOutputPath,
      userAgent: taskUserAgent,
      referer: taskReferer,
      proxy: taskProxy,
      cookieBucketId: taskCookieBucketId,
      authPayloadRef: taskAuthPayloadRef,
      rateLimit: taskRateLimit,
      liveFromStart: taskLiveFromStart,
      runAfterActiveSlot: taskRunAfterActiveSlot,
      concurrentFragments: taskConcurrentFragments,
      expectedSha256: taskExpectedSha256,
      customYtdlpArgs: taskCustomYtdlpArgs,
      startSeconds: taskStartSeconds,
      endSeconds: taskEndSeconds,
      audioFormat: taskAudioFormat,
      selectedFormatId,
      thumbnailUrl: metadataPreview?.thumbnail_url,
      subtitleLanguages: shouldAttachSubtitleOptions ? selectedSubtitleLanguages() : undefined,
      subtitleAuto: shouldAttachSubtitleOptions ? selectedSubtitleAuto() : undefined,
      subtitleEmbed: kind === "subtitles_only" ? false : shouldAttachSubtitleOptions ? subtitleEmbedInput : undefined,
      subtitleKeepVtt: kind === "subtitles_only" ? true : shouldAttachSubtitleOptions ? subtitleKeepVttInput : undefined,
      sponsorBlockEnabled: taskSponsorBlockEnabled,
      sponsorBlockCategories: taskSponsorBlockCategories.split(","),
      embedMetadata: taskEmbedMetadata,
      embedThumbnail: taskEmbedThumbnail,
      splitChapters: taskSplitChapters
    });
  }

  async function saveHomeAdvancedDefaults() {
    const defaultConcurrentFragmentsText = taskConcurrentFragments.trim();
    const defaultConcurrentFragments = defaultConcurrentFragmentsText ? Number(defaultConcurrentFragmentsText) : null;
    if (
      defaultConcurrentFragments !== null &&
      (!Number.isInteger(defaultConcurrentFragments) || defaultConcurrentFragments < 1 || defaultConcurrentFragments > 16)
    ) {
      pushToast(createToast("Advanced defaults invalid", "error", "Fragments must be a whole number from 1 to 16."));
      return;
    }

    homeAdvancedDefaultsBusy = true;
    const sponsorBlockCategories = uniqueTrimmedList(taskSponsorBlockCategories.split(","));
    try {
      const saved = await updateSettingsDownloads({
        default_output_dir: taskOutputDir.trim() || null,
        default_audio_format: taskAudioFormat,
        default_user_agent: taskUserAgent.trim() || null,
        default_referer: taskReferer.trim() || null,
        default_proxy: taskProxy.trim() || null,
        default_rate_limit: taskRateLimit.trim() || null,
        default_live_from_start: taskLiveFromStart,
        default_concurrent_fragments: defaultConcurrentFragments,
        custom_ytdlp_args: taskCustomYtdlpArgs.trim() || null,
        sponsorblock: {
          enabled: taskSponsorBlockEnabled,
          categories: sponsorBlockCategories
        },
        metadata: {
          embed_metadata: taskEmbedMetadata,
          embed_thumbnail: taskEmbedThumbnail,
          split_chapters: taskSplitChapters
        }
      });
      if (saved) {
        downloadsSettings = saved.downloads;
        defaultOutputDirInput = saved.downloads.default_output_dir ?? "";
        defaultAudioFormatInput = saved.downloads.default_audio_format;
        defaultUserAgentInput = saved.downloads.default_user_agent ?? "";
        defaultRefererInput = saved.downloads.default_referer ?? "";
        defaultProxyInput = saved.downloads.default_proxy ?? "";
        defaultRateLimitInput = saved.downloads.default_rate_limit ?? "";
        defaultLiveFromStartInput = saved.downloads.default_live_from_start;
        defaultConcurrentFragmentsInput = saved.downloads.default_concurrent_fragments
          ? String(saved.downloads.default_concurrent_fragments)
          : "";
        customYtdlpArgsInput = saved.downloads.custom_ytdlp_args ?? "";
        sponsorBlockEnabledInput = saved.downloads.sponsorblock.enabled;
        sponsorBlockCategoriesInput = saved.downloads.sponsorblock.categories.join(", ");
        embedMetadataInput = saved.downloads.metadata.embed_metadata;
        embedThumbnailInput = saved.downloads.metadata.embed_thumbnail;
        splitChaptersInput = saved.downloads.metadata.split_chapters;
        syncHomeTaskDefaultsFromDownloads(saved.downloads);
      }
      pushToast(createToast("Advanced defaults saved", "success", "New tasks inherit these values when their fields are empty.", settingsSectionToastAction("downloads")));
    } catch (error) {
      pushToast(createToast("Advanced defaults failed", "error", error instanceof Error ? error.message : String(error)));
    } finally {
      homeAdvancedDefaultsBusy = false;
    }
  }

  function selectedSubtitleLanguages(): string[] {
    return uniqueTrimmedList(selectedSubtitleKeys.map(subtitleLanguageFromKey));
  }

  function selectedSubtitleAuto(): boolean {
    return subtitleSelectionUsesAuto(selectedSubtitleKeys);
  }

  function formatProgress(task: DownloadTask) {
    const downloaded = task.downloaded_bytes ?? 0;
    if (task.total_bytes && task.total_bytes > 0) {
      const percent = Math.min(100, (downloaded / task.total_bytes) * 100);
      return `${formatBytes(downloaded)} of ${formatBytes(task.total_bytes)} (${percent.toFixed(0)}%)`;
    }

    return `${formatBytes(downloaded)} downloaded`;
  }

  function formatTaskFileSummary(task: DownloadTask) {
    const fileCount = task.file_count ?? null;
    const size = task.total_bytes ?? null;
    if (!fileCount && !size) {
      return "";
    }
    const fileLabel = fileCount ? `${fileCount} file${fileCount === 1 ? "" : "s"}` : "file count unknown";
    return size ? `${fileLabel} · ${formatBytes(size)}` : fileLabel;
  }

  function taskOptionSummary(task: DownloadTask): string {
    const parts = [
      task.quality ? `quality ${task.quality}` : "",
      task.audio_format ? `audio ${task.audio_format}` : "",
      (task.start_seconds !== null && task.start_seconds !== undefined) || (task.end_seconds !== null && task.end_seconds !== undefined)
        ? `clip ${task.start_seconds ?? "start"} -> ${task.end_seconds ?? "end"}`
        : "",
      task.concurrent_fragments ? `${task.concurrent_fragments} fragments` : "",
      task.live_from_start === undefined ? "" : task.live_from_start ? "live from start" : "live from current point",
      task.run_after_active_slot === undefined ? "" : task.run_after_active_slot ? "auto slot" : "manual start",
      task.subtitles ? `subs ${task.subtitles.languages.join(", ") || "all"}${task.subtitles.auto ? " auto" : ""}${task.subtitles.embed ? " embed" : ""}${task.subtitles.keep_vtt ? " keep vtt" : ""}` : "",
      task.sponsorblock ? `SponsorBlock ${task.sponsorblock.enabled ? "on" : "off"}${task.sponsorblock.categories.length ? ` ${task.sponsorblock.categories.join(", ")}` : ""}` : "",
      task.metadata ? `metadata${task.metadata.embed_metadata ? " embed" : ""}${task.metadata.embed_thumbnail ? " thumb" : ""}${task.metadata.split_chapters ? " chapters" : ""}` : "",
      task.custom_ytdlp_args ? "custom yt-dlp args" : ""
    ].filter(Boolean);
    return parts.join(" · ");
  }

  function taskThumbnailSrc(task: DownloadTask): string {
    return task.thumbnail_path ? convertFileSrc(task.thumbnail_path) : task.thumbnail_url ?? "";
  }

  function downloadTaskIntegrity(task: DownloadTask): Record<string, unknown> | null {
    const details = task.details_json;
    if (!details || typeof details !== "object") {
      return null;
    }
    return recordFromRecord(details, "integrity");
  }

  function taskHasIntegrityDetails(task: DownloadTask): boolean {
    return Boolean(taskIntegritySummary(task));
  }

  function taskIntegritySummary(task: DownloadTask): string {
    const integrity = downloadTaskIntegrity(task);
    if (!integrity) {
      return "";
    }

    const expected = stringFromRecord(integrity, "expected_sha256");
    const actual = stringFromRecord(integrity, "actual_sha256");
    const verifiedAt = stringFromRecord(integrity, "verified_at");
    if (!expected && !actual) {
      return "";
    }

    const parts = [
      expected ? `expected ${expected}` : "",
      actual ? `actual ${actual}` : "",
      verifiedAt ? `verified ${verifiedAt}` : ""
    ].filter(Boolean);
    return `SHA-256 ${parts.join(" · ")}`;
  }

  function taskDetailSummary(task: DownloadTask): string {
    const details = task.details_json;
    if (!details || typeof details !== "object") {
      return "";
    }

    const module = stringFromRecord(details, "module");
    if (module === "courses") {
      const course = recordFromRecord(details, "course");
      const lesson = recordFromRecord(details, "lesson");
      const attachment = recordFromRecord(details, "attachment");
      const courseTitle = stringFromRecord(course, "title");
      const itemTitle = stringFromRecord(lesson, "title") || stringFromRecord(attachment, "title");
      const label = lesson ? "Lesson" : attachment ? "Attachment" : "Course item";
      return [label, courseTitle, itemTitle].filter(Boolean).join(" · ");
    }

    if (module === "telegram") {
      const chat = recordFromRecord(details, "chat");
      const media = recordFromRecord(details, "media");
      const chatTitle = stringFromRecord(chat, "title");
      const mediaType = stringFromRecord(media, "media_type");
      const mediaTitle = stringFromRecord(media, "title");
      return ["Telegram", chatTitle, mediaType, mediaTitle].filter(Boolean).join(" · ");
    }

    if (module === "bilibili") {
      const item = recordFromRecord(details, "item");
      const collection = stringFromRecord(item, "collection").replaceAll("_", " ");
      return ["Bilibili", collection, stringFromRecord(item, "title")].filter(Boolean).join(" · ");
    }

    if (module === "channels") {
      const channel = recordFromRecord(details, "channel");
      const history = recordFromRecord(details, "history");
      return ["Channel", stringFromRecord(channel, "name"), stringFromRecord(history, "title")].filter(Boolean).join(" · ");
    }

    const integrity = taskIntegritySummary(task);
    if (integrity) {
      return integrity;
    }

    const transferStatus = stringFromRecord(details, "transfer_status");
    return transferStatus ? `Transfer details · ${transferStatus.replaceAll("_", " ")}` : "";
  }

  function recordFromRecord(source: Record<string, unknown>, key: string): Record<string, unknown> | null {
    const value = source[key];
    return value && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : null;
  }

  function stringFromRecord(source: Record<string, unknown> | null, key: string): string {
    const value = source?.[key];
    return typeof value === "string" ? value : "";
  }

  function cbzPreviewPages(preview: LibraryOpenResponse | null): Array<{ index: number; path: string; size_bytes?: number; preview_path?: string }> {
    if (!preview?.extra_json || preview.format !== "cbz") {
      return [];
    }
    const rawPages = Array.isArray(preview.extra_json.pages) ? preview.extra_json.pages : [];
    return rawPages
      .filter((page): page is Record<string, unknown> => Boolean(page) && typeof page === "object" && !Array.isArray(page))
      .map((page, index) => ({
        index: typeof page.index === "number" ? page.index : index + 1,
        path: typeof page.path === "string" ? page.path : "",
        size_bytes: typeof page.size_bytes === "number" ? page.size_bytes : undefined,
        preview_path: typeof page.preview_path === "string" ? page.preview_path : undefined
      }))
      .filter((page) => page.path);
  }

  function visibleCbzPreviewPages(preview: LibraryOpenResponse | null) {
    const pages = cbzPreviewPages(preview);
    if (libraryCbzPagesExpanded) {
      return pages;
    }
    return pages.slice(0, 60);
  }

  function indexedPreviewProgress(index: number, total: number): number {
    if (total <= 1) {
      return 0;
    }
    return Math.max(0, Math.min(100, Math.round(((index - 1) / Math.max(1, total - 1)) * 100)));
  }

  function libraryIndexFromProgress(progressPercent: number, total: number): number {
    if (total <= 1) {
      return 1;
    }
    const boundedProgress = Math.max(0, Math.min(100, progressPercent));
    return Math.max(1, Math.min(total, Math.round((boundedProgress / 100) * Math.max(1, total - 1)) + 1));
  }

  function cbzPreviewImages(preview: LibraryOpenResponse | null): Array<{ index: number; path: string; src: string }> {
    return cbzPreviewPages(preview)
      .filter((page) => page.preview_path)
      .map((page) => ({
        index: page.index,
        path: page.path,
        src: convertFileSrc(page.preview_path ?? "")
      }))
      .filter((page) => page.src);
  }

  function epubPreviewSummary(preview: LibraryOpenResponse | null): string[] {
    if (!preview?.extra_json || preview.format !== "epub") {
      return [];
    }
    const title = typeof preview.extra_json.title === "string" ? preview.extra_json.title : "";
    const creator = typeof preview.extra_json.creator === "string" ? preview.extra_json.creator : "";
    const language = typeof preview.extra_json.language === "string" ? preview.extra_json.language : "";
    const publisher = typeof preview.extra_json.publisher === "string" ? preview.extra_json.publisher : "";
    const published = typeof preview.extra_json.published === "string" ? preview.extra_json.published : "";
    const opfPath = typeof preview.extra_json.opf_path === "string" ? preview.extra_json.opf_path : "";
    const navHref = typeof preview.extra_json.nav_href === "string" ? preview.extra_json.nav_href : "";
    const spineCount = typeof preview.extra_json.spine_count === "number" ? preview.extra_json.spine_count : 0;
    const manifestCount = typeof preview.extra_json.manifest_count === "number" ? preview.extra_json.manifest_count : 0;
    const coverHref = typeof preview.extra_json.cover_href === "string" ? preview.extra_json.cover_href : "";
    return [
      title ? `Title: ${title}` : "",
      creator ? `Creator: ${creator}` : "",
      language ? `Language: ${language}` : "",
      publisher ? `Publisher: ${publisher}` : "",
      published ? `Published: ${published}` : "",
      opfPath ? `Package: ${opfPath}` : "",
      `${spineCount} reading section${spineCount === 1 ? "" : "s"}`,
      `${manifestCount} manifest item${manifestCount === 1 ? "" : "s"}`,
      navHref ? `Navigation candidate: ${navHref}` : "",
      coverHref ? `Cover candidate: ${coverHref}` : ""
    ].filter(Boolean);
  }

  function epubReadingOrder(preview: LibraryOpenResponse | null): Array<{ index: number; idref: string; href?: string }> {
    if (!preview?.extra_json || preview.format !== "epub" || !Array.isArray(preview.extra_json.reading_order)) {
      return [];
    }
    return preview.extra_json.reading_order
      .filter((item): item is Record<string, unknown> => Boolean(item) && typeof item === "object" && !Array.isArray(item))
      .map((item, index) => ({
        index: typeof item.index === "number" ? item.index : index + 1,
        idref: typeof item.idref === "string" ? item.idref : "",
        href: typeof item.href === "string" ? item.href : undefined
      }))
      .filter((item) => item.idref || item.href);
  }

  function visibleEpubReadingOrder(preview: LibraryOpenResponse | null) {
    const items = epubReadingOrder(preview);
    if (libraryEpubReadingOrderExpanded) {
      return items;
    }
    return items.slice(0, 40);
  }

  function epubTextPreviews(preview: LibraryOpenResponse | null): Array<{ index: number; path: string; text: string }> {
    if (!preview?.extra_json || preview.format !== "epub" || !Array.isArray(preview.extra_json.text_previews)) {
      return [];
    }
    return preview.extra_json.text_previews
      .filter((item): item is Record<string, unknown> => Boolean(item) && typeof item === "object" && !Array.isArray(item))
      .map((item, index) => ({
        index: typeof item.index === "number" ? item.index : index + 1,
        path: typeof item.path === "string" ? item.path : typeof item.href === "string" ? item.href : "",
        text: typeof item.text === "string" ? item.text : ""
      }))
      .filter((item) => item.text);
  }

  function pdfPreviewSummary(preview: LibraryOpenResponse | null): string[] {
    if (!preview?.extra_json || preview.format !== "pdf") {
      return [];
    }
    const title = typeof preview.extra_json.title === "string" ? preview.extra_json.title : "";
    const author = typeof preview.extra_json.author === "string" ? preview.extra_json.author : "";
    const creator = typeof preview.extra_json.creator === "string" ? preview.extra_json.creator : "";
    const producer = typeof preview.extra_json.producer === "string" ? preview.extra_json.producer : "";
    const created = typeof preview.extra_json.created === "string" ? preview.extra_json.created : "";
    const modified = typeof preview.extra_json.modified === "string" ? preview.extra_json.modified : "";
    const pageCount = typeof preview.extra_json.page_count === "number" ? preview.extra_json.page_count : 0;
    const sizeBytes = typeof preview.extra_json.size_bytes === "number" ? preview.extra_json.size_bytes : 0;
    return [
      title ? `Title: ${title}` : "",
      author ? `Author: ${author}` : "",
      creator ? `Creator: ${creator}` : "",
      producer ? `Producer: ${producer}` : "",
      created ? `Created: ${created}` : "",
      modified ? `Modified: ${modified}` : "",
      pageCount ? `${pageCount} detected page${pageCount === 1 ? "" : "s"}` : "",
      sizeBytes ? `${formatBytes(sizeBytes)} file size` : ""
    ].filter(Boolean);
  }

  function libraryItemCoverUrl(item: LibraryItem): string {
    return item.cover_path ? convertFileSrc(item.cover_path) : "";
  }

  function libraryMetadataLabel(item: LibraryItem): string {
    if (item.metadata_source === "epub_opf") {
      return "epub metadata";
    }
    if (item.metadata_source === "pdf_info") {
      return "pdf metadata";
    }
    if (item.metadata_source === "cbz_comic_info") {
      return "comic metadata";
    }
    return "";
  }

  function musicMetadataLabel(track: MusicTrack): string {
    if (track.metadata_source === "sidecar_json") {
      return "sidecar metadata";
    }
    if (track.metadata_source === "audio_tags") {
      return "audio tags";
    }
    return "";
  }

  function parseTimedLyrics(content: string): TimedLyricLine[] {
    const cueLyrics = parseCueTimedLyrics(content);
    if (cueLyrics.length > 0) {
      return cueLyrics.slice(0, 800);
    }
    return content
      .split(/\r?\n/)
      .flatMap((raw) => parseLyricLine(raw))
      .filter((line) => line.text.trim() || line.time_seconds !== null)
      .slice(0, 800);
  }

  function parseCueTimedLyrics(content: string): TimedLyricLine[] {
    const normalized = content
      .replace(/^\uFEFF/, "")
      .replace(/\r\n/g, "\n")
      .replace(/\r/g, "\n")
      .replace(/^WEBVTT[^\n]*(?:\n+|$)/i, "");
    return normalized
      .split(/\n{2,}/)
      .map((block): TimedLyricLine | null => {
        const lines = block.split("\n").map((line) => line.trim()).filter(Boolean);
        const timingIndex = lines.findIndex((line) => line.includes("-->"));
        if (timingIndex === -1) {
          return null;
        }
        const cueMatch = lines[timingIndex].match(/(?:(\d{1,2}):)?(\d{1,2}):(\d{2})(?:[.,](\d{1,3}))?\s*-->/);
        if (!cueMatch) {
          return null;
        }
        const text = lines
          .slice(timingIndex + 1)
          .filter((line) => !/^(NOTE|STYLE|REGION)\b/i.test(line))
          .join(" ")
          .trim();
        return {
          time_seconds: cueTimestampSeconds(cueMatch),
          text: text || lines[timingIndex],
          raw: block.trim()
        };
      })
      .filter((line): line is TimedLyricLine => line !== null);
  }

  function parseLyricLine(raw: string): TimedLyricLine[] {
    const trimmed = raw.trim();
    if (!trimmed) {
      return [];
    }
    const lrcMatches = [...trimmed.matchAll(/\[(\d{1,2}):(\d{2})(?:[.:](\d{1,3}))?\]/g)];
    if (lrcMatches.length > 0) {
      const text = trimmed.replace(/\[(\d{1,2}):(\d{2})(?:[.:](\d{1,3}))?\]/g, "").trim();
      return lrcMatches.map((match) => ({
        time_seconds: lyricTimestampSeconds(match[1], match[2], match[3]),
        text: text || trimmed,
        raw: trimmed
      }));
    }
    if (/^\[[a-zA-Z][a-zA-Z0-9_ -]*:.*\]$/.test(trimmed)) {
      return [];
    }
    const cueMatch = trimmed.match(/(?:(\d{1,2}):)?(\d{1,2}):(\d{2})(?:[.,](\d{1,3}))?\s*-->/);
    if (cueMatch) {
      return [{
        time_seconds: cueTimestampSeconds(cueMatch),
        text: trimmed,
        raw: trimmed
      }];
    }
    return [{ time_seconds: null, text: trimmed, raw: trimmed }];
  }

  function lyricTimestampSeconds(minutes: string, seconds: string, fraction = "0"): number {
    const fractionValue = Number(`0.${fraction.padEnd(3, "0").slice(0, 3)}`);
    return Number(minutes) * 60 + Number(seconds) + fractionValue;
  }

  function cueTimestampSeconds(match: RegExpMatchArray): number {
    const hours = match[1] ? Number(match[1]) : 0;
    const minutes = Number(match[2] ?? "0");
    const seconds = Number(match[3] ?? "0");
    const fraction = match[4] ? Number(`0.${match[4].padEnd(3, "0").slice(0, 3)}`) : 0;
    return hours * 3600 + minutes * 60 + seconds + fraction;
  }

  function activeLyricLineIndex(lines: TimedLyricLine[], currentSeconds: number): number {
    let activeIndex = -1;
    for (let index = 0; index < lines.length; index += 1) {
      const time = lines[index].time_seconds;
      if (time === null) {
        continue;
      }
      if (time <= currentSeconds + 0.15) {
        activeIndex = index;
      } else {
        break;
      }
    }
    return activeIndex;
  }

  function visibleLyricWindow(lines: TimedLyricLine[], activeIndex: number, limit: number): Array<TimedLyricLine & { original_index: number }> {
    if (lines.length <= limit) {
      return lines.map((line, index) => ({ ...line, original_index: index }));
    }
    const start = Math.max(0, Math.min(lines.length - limit, activeIndex > -1 ? activeIndex - Math.floor(limit / 2) : 0));
    return lines.slice(start, start + limit).map((line, index) => ({ ...line, original_index: start + index }));
  }

  function syncActiveMusicLyricScroll(trackPath: string, activeIndex: number) {
    if (!musicLyricsListElement || activeIndex < 0) {
      return;
    }
    const key = `${trackPath}:${activeIndex}`;
    if (lastMusicLyricScrollKey === key) {
      return;
    }
    lastMusicLyricScrollKey = key;
    requestAnimationFrame(() => {
      const activeLine = musicLyricsListElement?.querySelector<HTMLElement>("[data-active='true']");
      activeLine?.scrollIntoView({ block: "center", behavior: "smooth" });
    });
  }

  function seekActiveMusicToLyric(line: TimedLyricLine) {
    if (!musicAudioElement || line.time_seconds === null) {
      return;
    }
    musicAudioElement.currentTime = Math.max(0, line.time_seconds);
    activeMusicCurrentTimeSeconds = musicAudioElement.currentTime;
  }

  function formatEta(seconds?: number | null) {
    if (!seconds || seconds < 1) {
      return "ETA unknown";
    }

    if (seconds < 60) {
      return `${seconds}s remaining`;
    }

    return `${Math.ceil(seconds / 60)}m remaining`;
  }

  async function loadTaskLogs(task: DownloadTask) {
    selectedTaskId = task.id;
    downloadLogSearch = "";
    downloadLogAppliedSearch = "";
    downloadLogLevelFilter = "all";
    downloadLogSourceFilter = "all";
    selectedTaskLogs = [];
    selectedTaskLogEntries = [];
    downloadLogNextCursor = null;
    downloadLogTotalLines = 0;
    downloadLogMatchedLines = 0;
    await Promise.all([loadSelectedTaskLogPage(task.id, { reset: true }), refreshDownloadLogFiles()]);
  }

  async function refreshDownloadLogFiles() {
    try {
      downloadLogFiles = await listDownloadLogFiles();
      downloadLogListResponse = null;
    } catch {
      // The paged task log can still be shown when the local file inventory is unavailable.
    }
  }

  function isDownloadLogIssueLine(line: string) {
    return /\b(error|fail(?:ed|ure)?|warning|warn|exception|panic|traceback)\b/i.test(line);
  }

  function logEntryForLine(line: string, index: number): DownloadLogEntry {
    return selectedTaskLogEntries[index] ?? {
      line_number: index + 1,
      level: isDownloadLogIssueLine(line) ? "issue" : "info",
      source: "fetchdock",
      message: line,
      is_issue: isDownloadLogIssueLine(line),
      raw: line
    };
  }

  function filterSelectedTaskLogEntries(entries: DownloadLogEntry[], level: string, source: string) {
    return entries.filter((entry) => {
      const levelMatches = level === "all" || entry.level === level || (level === "issue" && entry.is_issue);
      const sourceMatches = source === "all" || entry.source === source;
      return levelMatches && sourceMatches;
    });
  }

  function selectedTaskLogIssueEntries() {
    return filteredSelectedTaskLogEntries.filter((entry) => entry.is_issue || isDownloadLogIssueLine(entry.raw));
  }

  function formatLogEntryForCopy(entry: DownloadLogEntry) {
    return `${entry.line_number}\t${entry.level}\t${entry.source}\t${entry.message || entry.raw}`;
  }

  function selectedTaskLogFile() {
    if (!selectedTaskId) {
      return null;
    }
    const expectedName = `download-${selectedTaskId}.log`;
    return downloadLogFiles.find((file) => file.file_name === expectedName) ?? null;
  }

  async function openSourceUrl(url: string, label: string) {
    try {
      await openPath(url);
      pushToast(createToast("Source opened", "success", label, targetToastAction("Open", "downloads", { query: label })));
    } catch (error) {
      pushToast(createToast("Open source failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  function isHttpUrl(value: string | null | undefined) {
    const trimmed = value?.trim().toLowerCase() ?? "";
    return trimmed.startsWith("http://") || trimmed.startsWith("https://");
  }

  function batchUrlEntriesFromText(rawText: string): BatchUrlEntry[] {
    return rawText
      .split(/\r?\n/)
      .flatMap((line, index) =>
        extractHttpUrls(line.trim()).map((sourceUrl) => ({ sourceUrl, lineNumber: index + 1 }))
      );
  }

  function formatBatchFailureLine(failure: BatchFailure) {
    const lineNumber = batchFailureLineNumbers[failure.index] ?? failure.index + 1;
    const source = failure.source_url?.trim() || "(no URL)";
    return `Line ${lineNumber}: ${source} - ${failure.error}`;
  }

  async function copyBatchFailures() {
    await copyTextToClipboard(
      batchFailures.map(formatBatchFailureLine).join("\n"),
      "No batch failures",
      "Batch failures copied",
