  async function copyParsedBatchUrls() {
    const entries = batchUrlEntriesFromText(batchUrls);
    await copyLinesToClipboard(
      entries.map((entry) => `Line ${entry.lineNumber}: ${entry.sourceUrl}`),
      "No parsed batch URLs",
      "Parsed batch URLs copied"
    );
