  async function copyTextToClipboard(text: string, emptyTitle: string, successTitle: string, detail = "Text copied.") {
    const trimmed = text.trim();
    if (!trimmed) {
      pushToast(createToast(emptyTitle, "error", "No visible values are available to copy."));
      return;
    }

    try {
      if (!navigator.clipboard?.writeText) {
        throw new Error("Clipboard write is not available in this runtime.");
      }
      await navigator.clipboard.writeText(text.replace(/\s+$/u, ""));
      pushToast(createToast(successTitle, "success", detail));
    } catch (error) {
      pushToast(createToast("Copy failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  function advancedPreviewIssueEntries() {
    return filteredAdvancedFilePreviewEntries.filter((entry) => entry.is_issue || isDownloadLogIssueLine(entry.raw));
  }

  async function copyAdvancedFilePreview(kind: "raw" | "summary" | "issues" | "structured") {
    if (!advancedFilePreview) {
      pushToast(createToast("No file preview", "error", "Preview a diagnostics or log file before copying."));
      return;
    }

    if (kind === "summary") {
      const lines = [
        `file=${advancedFilePreview.file.path}`,
        `name=${advancedFilePreview.file.file_name}`,
        `size_bytes=${advancedFilePreview.file.size_bytes}`,
        `modified_at=${advancedFilePreview.file.modified_at ?? "unknown"}`,
        `truncated=${advancedFilePreview.truncated}`,
        `max_bytes=${advancedFilePreview.max_bytes}`,
        `structured_rows=${filteredAdvancedFilePreviewEntries.length}`,
        `issue_count=${advancedPreviewIssueEntries().length}`,
        `level_filter=${advancedFilePreviewLevelFilter}`,
        `source_filter=${advancedFilePreviewSourceFilter}`
      ];
      await copyTextToClipboard(lines.join("\n"), "No preview summary", "File preview summary copied", `${lines.length} summary lines copied.`);
      return;
    }

    if (kind === "structured") {
      const lines = filteredAdvancedFilePreviewEntries.map(formatLogEntryForCopy);
      await copyTextToClipboard(
        lines.join("\n"),
        "No structured preview rows",
        "Structured file preview copied",
        `${lines.length} row${lines.length === 1 ? "" : "s"} copied.`
      );
      return;
    }

    if (kind === "issues") {
      const lines = advancedPreviewIssueEntries().map((entry) => entry.raw);
      await copyTextToClipboard(
        lines.join("\n"),
        "No preview issue lines",
        "File preview issues copied",
        `${lines.length} line${lines.length === 1 ? "" : "s"} copied.`
      );
      return;
    }

    await copyTextToClipboard(advancedFilePreview.content, "No preview content", "File preview copied", "Preview text copied.");
  }
  async function copySelectedTaskLog(kind: "loaded" | "summary" | "issues" | "structured") {
    if (!selectedTaskId) {
      pushToast(createToast("No task log", "error", "Select a task before copying its log."));
      return;
    }

    if (kind === "summary") {
      const search = downloadLogAppliedSearch.trim();
      const lines = [
        `task_id=${selectedTaskId}`,
        `loaded_lines=${selectedTaskLogs.length}`,
        `shown_lines=${visibleSelectedTaskLogs.length}`,
        search ? `matching_lines=${downloadLogMatchedLines}` : `total_lines=${downloadLogTotalLines}`,
        `search=${search || "(none)"}`,
        `level_filter=${downloadLogLevelFilter}`,
        `source_filter=${downloadLogSourceFilter}`,
        `next_cursor=${downloadLogNextCursor ?? "(end)"}`
      ];
      await copyTextToClipboard(lines.join("\n"), "No task log summary", "Task log summary copied", `${lines.length} summary lines copied.`);
      return;
    }

    if (kind === "structured") {
      const lines = filteredSelectedTaskLogEntries.map(formatLogEntryForCopy);
      await copyTextToClipboard(
        lines.join("\n"),
        "No structured log rows",
        "Structured task log copied",
        `${lines.length} row${lines.length === 1 ? "" : "s"} copied.`
      );
      return;
    }

    const lines =
      kind === "issues"
        ? selectedTaskLogIssueEntries().map((entry) => entry.raw)
        : visibleSelectedTaskLogs;
    await copyTextToClipboard(
      lines.join("\n"),
      kind === "issues" ? "No issue log lines" : "No task log lines",
      kind === "issues" ? "Task log issues copied" : "Task log lines copied",
      `${lines.length} line${lines.length === 1 ? "" : "s"} copied.`
    );
  }

  async function copyLinesToClipboard(values: string[], emptyTitle: string, successTitle: string) {
    const uniqueValues = Array.from(new Set(values.map((value) => value.trim()).filter(Boolean)));
    if (uniqueValues.length === 0) {
      pushToast(createToast(emptyTitle, "error", "No visible values are available to copy."));
      return;
    }

    try {
      if (!navigator.clipboard?.writeText) {
        throw new Error("Clipboard write is not available in this runtime.");
      }
      await navigator.clipboard.writeText(uniqueValues.join("\n"));
      pushToast(createToast(successTitle, "success", `${uniqueValues.length} value${uniqueValues.length === 1 ? "" : "s"} copied.`));
    } catch (error) {
      pushToast(createToast("Copy failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

