  async function focusDownloadTaskById(taskId: string, label: string) {
    const existing = downloads.find((task) => task.id === taskId);
    currentRoute = "downloads";
    persistRoute("downloads");
    selectedTaskId = taskId;
    selectedTaskDetail = existing ?? null;
    downloadSearchQuery = taskId;
    downloadViewMode = existing?.status === "archived" ? "history" : "active";

    try {
      const refreshed = existing ?? (await getDownloadTask(taskId));
      if (refreshed) {
        upsertTask(refreshed);
        selectedTaskDetail = refreshed;
        downloadViewMode = refreshed.status === "archived" ? "history" : "active";
      }
      await loadSelectedTaskLogPage(taskId, { reset: true });
      pushToast(createToast("Task focused", "success", label, targetToastAction("Task", "downloads", { task_id: taskId })));
    } catch (error) {
      pushToast(createToast("Task focus failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  async function loadSelectedTaskLogPage(
    taskId = selectedTaskId,
    options: { reset?: boolean; search?: string } = {}
  ) {
    if (!taskId) {
      return;
    }

    const reset = options.reset ?? false;
    const search = options.search ?? downloadLogAppliedSearch;
    const cursor = reset ? 0 : downloadLogNextCursor ?? selectedTaskLogs.length;
    logsBusy = true;
    try {
      const page = await getDownloadLogPage(taskId, {
        cursor,
        limit: 200,
        search: search.trim() || undefined
      });
      selectedTaskId = taskId;
      selectedTaskLogs = reset ? page.lines : [...selectedTaskLogs, ...page.lines];
      selectedTaskLogEntries = reset
        ? page.entries ?? []
        : [...selectedTaskLogEntries, ...(page.entries ?? [])];
      downloadLogNextCursor = page.next_cursor ?? null;
      downloadLogTotalLines = page.total_lines;
      downloadLogMatchedLines = page.matched_lines;
      downloadLogAppliedSearch = search;
      logsError = "";
    } catch (error) {
      logsError = error instanceof Error ? error.message : String(error);
    } finally {
      logsBusy = false;
    }
  }

  async function loadRemainingSelectedTaskLogs() {
    if (!selectedTaskId || downloadLogNextCursor === null) {
      return;
    }

    logsBusy = true;
    try {
      let cursor: number | null = downloadLogNextCursor;
      const loadedLines: string[] = [];
      const loadedEntries: DownloadLogEntry[] = [];
      let totalLines = downloadLogTotalLines;
      let matchedLines = downloadLogMatchedLines;
      const search = downloadLogAppliedSearch;

      while (cursor !== null) {
        const page = await getDownloadLogPage(selectedTaskId, {
          cursor,
          limit: 1000,
          search: search.trim() || undefined
        });
        loadedLines.push(...page.lines);
        loadedEntries.push(...(page.entries ?? []));
        totalLines = page.total_lines;
        matchedLines = page.matched_lines;
        cursor = page.next_cursor ?? null;
      }

      selectedTaskLogs = [...selectedTaskLogs, ...loadedLines];
      selectedTaskLogEntries = [...selectedTaskLogEntries, ...loadedEntries];
      downloadLogNextCursor = null;
      downloadLogTotalLines = totalLines;
      downloadLogMatchedLines = matchedLines;
      logsError = "";
      pushToast(createToast("Task log loaded", "success", `${loadedLines.length} additional line${loadedLines.length === 1 ? "" : "s"} loaded.`));
    } catch (error) {
      logsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Task log load failed", "error", logsError));
    } finally {
      logsBusy = false;
    }
  }

  async function applyDownloadLogSearch() {
    if (!selectedTaskId) {
      return;
    }

    selectedTaskLogs = [];
    selectedTaskLogEntries = [];
    downloadLogNextCursor = null;
    await loadSelectedTaskLogPage(selectedTaskId, {
      reset: true,
      search: downloadLogSearch
    });
  }

