  async function moveTask(task: DownloadTask, direction: -1 | 1) {
    const currentIndex = downloads.findIndex((item) => item.id === task.id);
    const nextIndex = currentIndex + direction;
    if (currentIndex < 0 || nextIndex < 0 || nextIndex >= downloads.length) {
      return;
    }

    const nextDownloads = [...downloads];
    [nextDownloads[currentIndex], nextDownloads[nextIndex]] = [nextDownloads[nextIndex], nextDownloads[currentIndex]];

    try {
      downloads = await reorderDownloadTasks(nextDownloads.map((item) => item.id));
    } catch (error) {
      pushToast(createToast("Reorder failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

  function canDragDownloadTask(task: DownloadTask): boolean {
    return downloadsCanReorder && task.status === "queued";
  }

  async function dropDownloadTask(targetTask: DownloadTask) {
    const draggedTaskId = draggedDownloadTaskId;
    draggedDownloadTaskId = "";
    dragOverDownloadTaskId = "";
    if (!draggedTaskId || draggedTaskId === targetTask.id || !canDragDownloadTask(targetTask)) {
      return;
    }

    const nextDownloads = [...downloads];
    const fromIndex = nextDownloads.findIndex((item) => item.id === draggedTaskId);
    const toIndex = nextDownloads.findIndex((item) => item.id === targetTask.id);
    if (fromIndex < 0 || toIndex < 0 || nextDownloads[fromIndex].status !== "queued") {
      return;
    }

    const [draggedTask] = nextDownloads.splice(fromIndex, 1);
    nextDownloads.splice(toIndex, 0, draggedTask);

    try {
      downloads = await reorderDownloadTasks(nextDownloads.map((item) => item.id));
      pushToast(createToast("Queue reordered", "success", `${draggedTask.title} moved.`, downloadTaskToastAction(draggedTask)));
    } catch (error) {
      pushToast(createToast("Reorder failed", "error", error instanceof Error ? error.message : String(error)));
    }
  }

