  async function saveDownloadsSettings() {
    const parsed = Number(maxConcurrencyInput);
    if (!Number.isInteger(parsed) || parsed < 1 || parsed > 8) {
      downloadsSettingsError = "Max active downloads must be a whole number from 1 to 8.";
      pushToast(createToast("Downloads setting invalid", "error", downloadsSettingsError));
      return;
    }
    const filenameTemplate = filenameTemplateInput.trim();
    if (!filenameTemplate) {
      downloadsSettingsError = "Filename template is required.";
      pushToast(createToast("Downloads setting invalid", "error", downloadsSettingsError));
      return;
    }
    const defaultQuality = defaultQualityInput.trim();
    if (!defaultQuality) {
      downloadsSettingsError = "Default quality is required.";
      pushToast(createToast("Downloads setting invalid", "error", downloadsSettingsError));
      return;
    }
    const subtitleLanguages = uniqueTrimmedList(subtitleLanguagesInput.split(","));
    const sponsorBlockCategories = uniqueTrimmedList(sponsorBlockCategoriesInput.split(","));
    const archivedTaskRetentionDaysText = archivedTaskRetentionDaysInput.trim();
    const archivedTaskRetentionDays = archivedTaskRetentionDaysText ? Number(archivedTaskRetentionDaysText) : null;
    if (
      archivedTaskRetentionDays !== null &&
      (!Number.isInteger(archivedTaskRetentionDays) || archivedTaskRetentionDays < 1 || archivedTaskRetentionDays > 3650)
    ) {
      downloadsSettingsError = "Archived retention days must be a whole number from 1 to 3650, or blank.";
      pushToast(createToast("Downloads setting invalid", "error", downloadsSettingsError));
      return;
    }
    const defaultConcurrentFragmentsText = defaultConcurrentFragmentsInput.trim();
    const defaultConcurrentFragments = defaultConcurrentFragmentsText ? Number(defaultConcurrentFragmentsText) : null;
    if (
      defaultConcurrentFragments !== null &&
      (!Number.isInteger(defaultConcurrentFragments) || defaultConcurrentFragments < 1 || defaultConcurrentFragments > 16)
    ) {
      downloadsSettingsError = "Default fragments must be a whole number from 1 to 16.";
      pushToast(createToast("Downloads setting invalid", "error", downloadsSettingsError));
      return;
    }

    downloadsSettingsBusy = true;
    try {
      const saved = await updateSettingsDownloads({
        max_concurrency: parsed,
        default_output_dir: defaultOutputDirInput.trim() || null,
        organize_by_platform: organizeByPlatformInput,
        filename_template: filenameTemplate,
        skip_existing: skipExistingInput,
        completed_task_cleanup: completedTaskCleanupInput === "delete" ? "delete" : "archive",
        archived_task_retention_days: archivedTaskRetentionDays,
        default_quality: defaultQuality,
        default_audio_format: defaultAudioFormatInput,
        default_user_agent: defaultUserAgentInput.trim() || null,
        default_referer: defaultRefererInput.trim() || null,
        default_proxy: defaultProxyInput.trim() || null,
        default_rate_limit: defaultRateLimitInput.trim() || null,
        default_live_from_start: defaultLiveFromStartInput,
        default_concurrent_fragments: defaultConcurrentFragments,
        custom_ytdlp_args: customYtdlpArgsInput.trim() || null,
        subtitles: {
          languages: subtitleLanguages,
          auto: subtitleAutoInput,
          embed: subtitleEmbedInput,
          keep_vtt: subtitleKeepVttInput
        },
        sponsorblock: {
          enabled: sponsorBlockEnabledInput,
          categories: sponsorBlockCategories
        },
        metadata: {
          embed_metadata: embedMetadataInput,
          embed_thumbnail: embedThumbnailInput,
          split_chapters: splitChaptersInput
        }
      });
      if (saved) {
        syncDownloadsSettingsInputs(saved.downloads);
      }
      downloadsSettingsError = "";
      pushToast(createToast(
        "Downloads settings saved",
        "success",
        `${parsed} active download${parsed === 1 ? "" : "s"}`,
        settingsSectionToastAction("downloads")
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      downloadsSettingsError = message;
      pushToast(createToast("Downloads settings failed", "error", message));
    } finally {
      downloadsSettingsBusy = false;
    }
  }

  async function exportDownloadsSettingsBackup() {
    downloadsSettingsTransferBusy = "export";
    downloadsSettingsError = "";
    try {
      const result = await exportDownloadsSettings(downloadsSettingsExportPath.trim() || undefined);
      downloadsSettingsExportResult = result;
      downloadsSettingsImportResult = null;
      if (result?.output_path) {
        downloadsSettingsExportPath = result.output_path;
