      appearanceSettingsError = "Font scale must be a whole number from 90 to 115.";
      pushToast(createToast("Appearance setting invalid", "error", appearanceSettingsError));
      return;
    }

    appearanceSettingsBusy = true;
    try {
      const saved = await updateSettingsAppearance({
        language: appearanceLanguageInput,
        theme: appearanceThemeInput,
        font_scale_percent: fontScale,
        density: appearanceDensityInput
      });
      if (saved) {
        syncAppearanceSettingsInputs(saved.appearance);
      }
