  async function resetSettings(section: SettingsResetSection) {
    const resetAll = section === "all";
    downloadsSettingsBusy = resetAll || section === "downloads" || section === "network";
    appearanceSettingsBusy = resetAll || section === "appearance";
    aiSettingsBusy = resetAll || section === "ai";
    advancedSettingsBusy = resetAll || section === "advanced" ? "reset" : "";
    toolStatusBusy = resetAll || section === "dependencies" || section === "tools";
    try {
      const saved = await resetSettingsSection(section);
      if (saved) {
        syncAppearanceSettingsInputs(saved.appearance);
        downloadsSettings = saved.downloads;
        maxConcurrencyInput = String(saved.downloads.max_concurrency);
        defaultOutputDirInput = saved.downloads.default_output_dir ?? "";
        organizeByPlatformInput = saved.downloads.organize_by_platform;
        filenameTemplateInput = saved.downloads.filename_template;
        skipExistingInput = saved.downloads.skip_existing;
        completedTaskCleanupInput = saved.downloads.completed_task_cleanup ?? "archive";
        archivedTaskRetentionDaysInput = saved.downloads.archived_task_retention_days
          ? String(saved.downloads.archived_task_retention_days)
          : "";
        defaultQualityInput = saved.downloads.default_quality;
        defaultAudioFormatInput = saved.downloads.default_audio_format;
        defaultUserAgentInput = saved.downloads.default_user_agent ?? "";
        defaultRefererInput = saved.downloads.default_referer ?? "";
        defaultProxyInput = saved.downloads.default_proxy ?? "";
        defaultRateLimitInput = saved.downloads.default_rate_limit ?? "";
        defaultLiveFromStartInput = saved.downloads.default_live_from_start;
        defaultConcurrentFragmentsInput = saved.downloads.default_concurrent_fragments ? String(saved.downloads.default_concurrent_fragments) : "";
        customYtdlpArgsInput = saved.downloads.custom_ytdlp_args ?? "";
        subtitleLanguagesInput = saved.downloads.subtitles.languages.join(", ");
        subtitleAutoInput = saved.downloads.subtitles.auto;
        subtitleEmbedInput = saved.downloads.subtitles.embed;
        subtitleKeepVttInput = saved.downloads.subtitles.keep_vtt;
        sponsorBlockEnabledInput = saved.downloads.sponsorblock.enabled;
        sponsorBlockCategoriesInput = saved.downloads.sponsorblock.categories.join(", ");
        embedMetadataInput = saved.downloads.metadata.embed_metadata;
        embedThumbnailInput = saved.downloads.metadata.embed_thumbnail;
        splitChaptersInput = saved.downloads.metadata.split_chapters;
        syncHomeTaskDefaultsFromDownloads(saved.downloads);
        syncAiSettingsInputs(saved.ai);
        syncAdvancedSettingsInputs(saved.advanced);
      }
      if (resetAll || section === "advanced") {
        privacyStatus = await getPrivacyStatus();
      }
      if (resetAll || section === "ai") {
        await loadAiLocalSummary();
      }
      if (resetAll || section === "dependencies" || section === "tools") {
        toolUpdateCheckById = {};
        toolInstallProgressById = {};
        await loadToolStatuses();
      }
      appearanceSettingsError = "";
      downloadsSettingsError = "";
      aiSettingsError = "";
      advancedSettingsError = "";
      pushToast(createToast("Settings reset", "success", section, settingsSectionToastAction(section === "all" ? "advanced" : section)));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      if (section === "appearance") {
        appearanceSettingsError = message;
      } else if (section === "ai") {
        aiSettingsError = message;
      } else if (section === "advanced") {
        advancedSettingsError = message;
      } else if (section === "dependencies" || section === "tools") {
        toolStatusError = message;
      } else {
        downloadsSettingsError = message;
      }
      pushToast(createToast("Settings reset failed", "error", message));
    } finally {
      downloadsSettingsBusy = false;
      appearanceSettingsBusy = false;
      aiSettingsBusy = false;
      toolStatusBusy = false;
      advancedSettingsBusy = "";
    }
  }

  function requestResetImplementedSettings() {
    confirmDialog = {
      title: "Reset implemented settings?",
      message:
        "Restore implemented local settings for Appearance, Downloads, Network, Update, Browser Extension, Channels, AI, Auth fallback, Reader, Music state, and Dependencies. This does not delete Cookie buckets, downloaded files, task history, plugin installs, course manifests, Telegram manifests, or library/music catalogs.",
      confirmLabel: "Reset settings",
      onConfirm: async () => {
        await resetSettings("all");
        await Promise.all([
          loadAuthSettings(),
          loadUpdateSettings(),
          loadExtensionPairingStatus(),
          loadChannels(),
          loadLibraryReaderSettings(),
          loadMusicState(),
          loadToolStatuses()
        ]);
      }
    };
  }

