  async function exportVisibleBilibiliImports() {
    const items = visibleBilibiliImportedItems(filteredBilibiliImportedItems);
    if (items.length === 0) {
      bilibiliError = "No visible Bilibili imports to export.";
      pushToast(createToast("Bilibili export invalid", "error", bilibiliError));
      return;
    }

    bilibiliBusy = "export";
    bilibiliError = "";
    try {
      const result = await exportBilibiliManifest({
        outputPath: bilibiliManifestExportPath.trim() || undefined,
        collection: bilibiliImportCollectionFilter as "all" | "watch_later" | "history",
        ids: items.map((item) => item.id)
      });
      if (result) {
        bilibiliManifestExportResult = result;
        bilibiliManifestExportPath = result.output_path;
        pushToast(createToast(
          "Bilibili imports exported",
          "success",
          `${result.exported_count} item${result.exported_count === 1 ? "" : "s"} · ${result.collection}`,
          advancedFileToastAction(result.output_path)
        ));
      }
    } catch (error) {
      bilibiliError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Bilibili export failed", "error", bilibiliError));
    } finally {
      bilibiliBusy = "";
    }
  }

  async function openBilibiliManifestExportResult() {
    await openLocalPath(bilibiliManifestExportResult?.output_path ?? bilibiliManifestExportPath, "Bilibili export");
  }

  async function revealBilibiliManifestExportResult() {
    await revealLocalPath(bilibiliManifestExportResult?.output_path ?? bilibiliManifestExportPath, "Bilibili export");
