  async function queueBilibiliItem(item: BilibiliImportItem) {
    await maybeAutoSelectToolsCookieBucket(item.source_url);
    maybeAutoSelectToolsAuthorizationPayload(item.source_url);
    bilibiliBusy = item.id;
    try {
      const task = await queueBilibiliImportedItem(item.id, buildToolsCreateOptions("video"));
      if (task) {
        downloads = [task, ...downloads.filter((candidate) => candidate.id !== task.id)].sort(
          (first, second) => first.position - second.position
        );
        bilibiliImportedItems = await listBilibiliImported();
        bilibiliLocalSummary = await getBilibiliLocalSummary();
        pushToast(createToast("Bilibili item queued", "success", item.title, targetToastAction("Task", "downloads", { task_id: task.id })));
      }
      bilibiliError = "";
    } catch (error) {
      bilibiliError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Bilibili queue failed", "error", bilibiliError));
    } finally {
      bilibiliBusy = "";
    }
  }

  async function queueVisibleBilibiliItems() {
    const items = filteredBilibiliImportedItems;
    if (items.length === 0) {
      bilibiliError = "No Bilibili imports match the current filters.";
      pushToast(createToast("Bilibili queue skipped", "info", bilibiliError));
      return;
    }

    await maybeAutoSelectToolsCookieBucket(items[0].source_url);
    maybeAutoSelectToolsAuthorizationPayload(items[0].source_url);
    bilibiliBusy = "queue-visible";
    try {
      const result = await queueBilibiliImportedItems(items.map((item) => item.id), buildToolsCreateOptions("video"));
      if (result.created.length > 0) {
        const createdIds = new Set(result.created.map((task) => task.id));
        downloads = [
          ...result.created,
          ...downloads.filter((candidate) => !createdIds.has(candidate.id))
        ].sort((first, second) => first.position - second.position);
        bilibiliImportedItems = await listBilibiliImported();
        bilibiliLocalSummary = await getBilibiliLocalSummary();
      }
      bilibiliError = "";
      const skippedSummary = result.skipped.length > 0 ? `, ${result.skipped.length} skipped` : "";
      pushToast(
        createToast(
          "Bilibili imports queued",
          "success",
          `${result.created.length} task${result.created.length === 1 ? "" : "s"}${skippedSummary}`,
          result.created[0] ? targetToastAction("Task", "downloads", { task_id: result.created[0].id }) : undefined
        )
      );
    } catch (error) {
      bilibiliError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Bilibili batch queue failed", "error", bilibiliError));
    } finally {
      bilibiliBusy = "";
    }
  }

  function requestBilibiliImportedItemDelete(item: BilibiliImportItem) {
    confirmDialog = {
      title: "Remove Bilibili import?",
      message: `Remove ${item.title} from the local Bilibili import list. Download tasks and Cookie buckets are left untouched.`,
      confirmLabel: "Remove",
      onConfirm: async () => {
        bilibiliBusy = `${item.id}:delete`;
        try {
          const deleted = await deleteBilibiliImportedItem(item.id);
          bilibiliImportedItems = bilibiliImportedItems.filter((candidate) => candidate.id !== item.id);
          bilibiliAccountStatus = await getBilibiliAccountStatus();
          bilibiliLocalSummary = await getBilibiliLocalSummary();
          bilibiliError = "";
          pushToast(createToast(
            deleted ? "Bilibili import removed" : "Bilibili import already removed",
            "success",
            item.title,
            targetToastAction("Open", "bilibili", { query: item.title, collection: item.collection })
          ));
        } catch (error) {
          bilibiliError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Bilibili import remove failed", "error", bilibiliError));
        } finally {
          bilibiliBusy = "";
        }
      }
    };
  }

  function requestFilteredBilibiliImportsDelete() {
    const items = filteredBilibiliImportedItems;
    if (items.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove filtered Bilibili imports?",
      message: `Remove ${items.length} currently filtered Bilibili import${items.length === 1 ? "" : "s"} from the local list. Download tasks and Cookie buckets are left untouched.`,
      confirmLabel: "Remove filtered",
      onConfirm: async () => {
        bilibiliBusy = "delete-filtered";
        try {
          const result = await deleteBilibiliImportedItems(items.map((item) => item.id));
          const ids = new Set(result.deleted);
          bilibiliImportedItems = bilibiliImportedItems.filter((item) => !ids.has(item.id));
          bilibiliAccountStatus = await getBilibiliAccountStatus();
          bilibiliLocalSummary = await getBilibiliLocalSummary();
          bilibiliError = "";
          const failedSummary = result.failed.length > 0 ? ` · ${result.failed.length} failed` : "";
          pushToast(createToast(
            "Bilibili imports removed",
            "success",
            `${result.deleted.length} item${result.deleted.length === 1 ? "" : "s"}${failedSummary}`,
            targetToastAction("Open", "bilibili", { query: items[0]?.title ?? "", collection: items[0]?.collection ?? "all" })
          ));
        } catch (error) {
          bilibiliError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Bilibili filtered remove failed", "error", bilibiliError));
        } finally {
          bilibiliBusy = "";
        }
      }
    };
  }

