  async function chooseCookieExportPath(bucket: CookieBucket) {
    if (!isTauriRuntime()) {
      pushToast(createToast("Save dialog unavailable", "error", "Run the desktop app to choose a Cookie export path."));
      return;
    }

    try {
      const safeName = bucket.name.replace(/[^a-z0-9._-]+/gi, "-").replace(/^-+|-+$/g, "") || bucket.id;
      const selected = await save({
        title: `Export ${bucket.name} cookies`,
        defaultPath: `${safeName}.cookies.txt`,
        filters: [{ name: "Netscape Cookie file", extensions: ["txt", "cookies"] }]
      });
      if (typeof selected === "string") {
        cookieExportPathInputs = { ...cookieExportPathInputs, [bucket.id]: selected };
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast("Cookie export path failed", "error", message));
    }
  }
  async function exportCookie(bucket: CookieBucket) {
    const outputPath = cookieExportPathInputs[bucket.id] ?? "";
    try {
      const path = await exportCookieBucket(bucket.id, outputPath);
      pushToast(createToast(
        "Cookie bucket exported",
        "success",
        path ?? outputPath,
        path ? targetToastAction("Open", "advanced", { file: path }) : targetToastAction("Open", "cookies", { bucket_id: bucket.id })
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast("Cookie export failed", "error", message));
    }
  }

  async function exportCookieBucketsBackup() {
    cookieBucketsBusy = true;
    cookieBucketsError = "";
    try {
      const selectedIds = cookieSelectedIds.length > 0 ? cookieSelectedIds : undefined;
      const result = await exportCookieBuckets(cookieBucketsBackupExportPath.trim() || undefined, selectedIds);
      cookieBucketsBackupExportResult = result;
      cookieBucketsBackupImportResult = null;
      if (result?.output_path) {
        cookieBucketsBackupExportPath = result.output_path;
      }
      await refreshCookieAuthLocalSummary(false);
      pushToast(createToast(
        "Cookie bucket backup exported",
        "success",
        result ? `${result.exported_bucket_count} bucket${result.exported_bucket_count === 1 ? "" : "s"} · ${result.exported_cookie_row_count} rows` : "Exported",
        advancedFileToastAction(result?.output_path ?? "")
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast("Cookie bucket backup export failed", "error", message));
    } finally {
      cookieBucketsBusy = false;
    }
