  async function importCookieBucketsBackup() {
    if (!cookieBucketsBackupImportPath.trim()) {
      cookieBucketsError = "Choose a Cookie bucket backup JSON first.";
      pushToast(createToast("Cookie bucket backup missing", "error", cookieBucketsError));
      return;
    }

    cookieBucketsBusy = true;
    cookieBucketsError = "";
    try {
      const result = await importCookieBuckets(cookieBucketsBackupImportPath.trim());
      cookieBucketsBackupImportResult = result;
      cookieBucketsBackupExportResult = null;
      if (result?.buckets) {
        syncCookieBuckets(result.buckets);
      } else {
        await loadCookieBuckets();
      }
      await loadBilibiliImports();
      await refreshCookieAuthLocalSummary(false);
      pushToast(createToast(
        "Cookie bucket backup imported",
        "success",
        result ? `${result.imported_bucket_count} imported · ${result.skipped_bucket_count} skipped` : "Imported",
        targetToastAction("Open", "cookies", { query: "" })
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast("Cookie bucket backup import failed", "error", message));
    } finally {
      cookieBucketsBusy = false;
    }
  }

  async function runCookieHealthTest(bucket: CookieBucket) {
    cookieTestBusy = bucket.id;
    try {
      const tested = await testCookieBucket(bucket.id, cookieMatchUrl.trim() || undefined);
      if (tested) {
        cookieBuckets = cookieBuckets.map((item) => (item.id === tested.id ? tested : item));
        pushToast(createToast(
          "Cookie bucket tested",
          tested.health === "valid" ? "success" : "info",
          `${tested.name}: ${tested.health}`,
          targetToastAction("Open", "cookies", { bucket_id: tested.id })
        ));
      }
      cookieBucketsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast("Cookie test failed", "error", message));
    } finally {
      cookieTestBusy = "";
    }
  }

  async function runCookieHealthTests(targets: CookieBucket[], busyKey: string, label: string) {
    if (targets.length === 0) {
      return;
    }

    cookieTestBusy = busyKey;
    try {
      const response = await testCookieBuckets(targets.map((bucket) => bucket.id), cookieMatchUrl.trim() || undefined);
      const byId = new Map(response.buckets.map((bucket) => [bucket.id, bucket]));
      cookieBuckets = cookieBuckets.map((bucket) => byId.get(bucket.id) ?? bucket);
      cookieBucketsError = "";
      const failedText = response.failed.length > 0 ? `, ${response.failed.length} failed` : "";
      pushToast(createToast(
        `${label} tested`,
        response.failed.length > 0 ? "warning" : "success",
        `${response.buckets.length} bucket${response.buckets.length === 1 ? "" : "s"}${failedText}`,
        response.buckets[0] ? targetToastAction("Open", "cookies", { bucket_id: response.buckets[0].id }) : undefined
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      pushToast(createToast(`${label} test failed`, "error", message));
    } finally {
      cookieTestBusy = "";
    }
  }

  function toggleCookieSelection(bucketId: string) {
    cookieSelectedIds = cookieSelectedIds.includes(bucketId)
      ? cookieSelectedIds.filter((id) => id !== bucketId)
      : [...cookieSelectedIds, bucketId];
  }

  function selectFilteredCookieBuckets() {
    cookieSelectedIds = Array.from(new Set([...cookieSelectedIds, ...filteredCookieBucketIds]));
  }

  function clearFilteredCookieSelection() {
    const visibleIds = new Set(filteredCookieBucketIds);
    cookieSelectedIds = cookieSelectedIds.filter((id) => !visibleIds.has(id));
  }

