    toolsCookieBucketId = bucket.id;
    if (!toolsUrl.trim() && cookieMatchUrl.trim()) {
      toolsUrl = cookieMatchUrl.trim();
      toolsMetadataPreviewUrl = cookieMatchUrl.trim();
