      title: "Clear selected cookies?",
      message: `Remove ${cookieSelectedIds.length} selected cookie bucket${cookieSelectedIds.length === 1 ? "" : "s"} and their stored files from this device.`,
      confirmLabel: "Clear",
      onConfirm: async () => {
        try {
