          pushToast(createToast("Cookie buckets cleared", "success", `${cleared} removed`, targetToastAction("Open", "cookies", { query: "" })));
          await loadCookieBuckets();
          await loadBilibiliImports();
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          cookieBucketsError = message;
          pushToast(createToast("Cookie clear failed", "error", message));
        }
      }
    };
  }

  function requestClearCookiePlatform() {
    const platform = cookieClearPlatform.trim();
    if (!platform) {
      cookieBucketsError = "Choose a platform to clear.";
      pushToast(createToast("Cookie platform clear invalid", "error", cookieBucketsError));
      return;
    }

    const matchingCount = cookieBuckets.filter((bucket) => bucket.platform?.toLowerCase() === platform.toLowerCase()).length;
    confirmDialog = {
      title: "Clear platform cookies?",
      message: `Remove ${matchingCount} ${platform} cookie bucket${matchingCount === 1 ? "" : "s"} and their stored files from this device.`,
      confirmLabel: "Clear platform",
      onConfirm: async () => {
        try {
          const cleared = await clearCookieBuckets([], platform);
          cookieSelectedIds = cookieSelectedIds.filter((id) => !cookieBuckets.some(
            (bucket) => bucket.id === id && bucket.platform?.toLowerCase() === platform.toLowerCase()
          ));
          pushToast(createToast("Platform cookies cleared", "success", `${cleared} removed`, targetToastAction("Open", "cookies", { query: platform })));
          await loadCookieBuckets();
          await loadBilibiliImports();
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          cookieBucketsError = message;
          pushToast(createToast("Platform clear failed", "error", message));
        }
      }
    };
  }

