  async function createChannel() {
    try {
      const channel = await addChannel({
        name: channelNameInput,
        sourceUrl: channelUrlInput,
        platform: channelPlatformInput.trim() || undefined,
        autoDownload: channelAutoDownloadInput
      });
      if (channel) {
        channelNameInput = "";
        channelUrlInput = "";
        channelPlatformInput = "";
        channelAutoDownloadInput = false;
        pushToast(createToast("Channel added", "success", channel.name, targetToastAction("Open", "channels", { query: channel.id })));
        await loadChannels();
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel add failed", "error", message));
    }
  }

  async function checkChannel(channel: ChannelSubscription) {
    channelCheckBusy = channel.id;
    try {
      const response = await checkChannelNow(channel.id);
      if (response) {
        channels = channels.map((item) => (item.id === response.channel.id ? response.channel : item));
        channelHistory = [...response.items, ...channelHistory];
        if (response.items.some((item) => item.created_task_id)) {
          await loadDownloads();
        }
        const first = response.items[0];
        if (first && !first.error && first.notification_status === "pending") {
          pushToast(createToast("Channel notification", "success", first.title, {
            label: "Open",
            onClick: () => handleShellOpenTarget({ route: "channels", params: { history_id: first.id } })
          }));
        }
        pushToast(
          createToast(
            first?.error ? "Channel check recorded error" : "Channel checked",
            first?.error ? "error" : "success",
            first?.error ?? first?.title ?? channel.name,
            targetToastAction("Open", "channels", first ? { history_id: first.id } : { query: channel.id })
          )
        );
      }
      channelsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel check failed", "error", message));
    } finally {
      channelCheckBusy = "";
    }
  }

  async function saveChannelPollingSettings() {
    channelSettingsBusy = true;
    try {
      const saved = await updateChannelSettings({
        autoPollEnabled: channelPollEnabledInput,
        pollIntervalMinutes: Number(channelPollIntervalInput)
      });
      if (saved) {
        syncChannelSettingsInputs(saved);
        pushToast(createToast("Channel polling saved", "success", `${saved.poll_interval_minutes} min`, settingsSectionToastAction("channels")));
      }
      channelsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel polling failed", "error", message));
    } finally {
      channelSettingsBusy = false;
    }
  }

  async function applyChannelPollResult(result: ChannelPollDueResponse | null, showSummary: boolean) {
    if (!result) {
      return;
    }
    syncChannelSettingsInputs(result.settings);
    channelAutoPollSummary = result.checked > 0
      ? `${result.checked} checked · ${result.created_task_count} queued`
      : "No due channels";
    if (result.items.length > 0) {
      const existingIds = new Set(channelHistory.map((item) => item.id));
      channelHistory = [
        ...result.items.filter((item) => !existingIds.has(item.id)),
        ...channelHistory
      ];
      for (const item of result.items.filter((candidate) => !candidate.error && candidate.notification_status === "pending").slice(0, 3)) {
        pushToast(createToast("Channel notification", "success", item.title, {
          label: "Open",
          onClick: () => handleShellOpenTarget({ route: "channels", params: { history_id: item.id } })
        }));
      }
      await loadChannels();
      if (result.created_task_count > 0) {
        await loadDownloads();
      }
    }
    if (showSummary) {
      pushToast(createToast("Channel poll complete", "success", channelAutoPollSummary, targetToastAction("Open", "channels", { status: "pending" })));
    }
  }

  async function resetChannelSettings() {
    channelSettingsBusy = true;
    try {
      await resetSettingsSection("channels");
      const saved = await getChannelSettings();
      syncChannelSettingsInputs(saved);
      if (saved) {
        channelAutoPollSummary = "";
      }
      channelsError = "";
      pushToast(createToast("Channel settings reset", "success", "Polling defaults restored", settingsSectionToastAction("channels")));
    } catch (error) {
      channelsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Channel reset failed", "error", channelsError));
    } finally {
      channelSettingsBusy = false;
    }
  }

  async function runDueChannelPoll() {
    channelSettingsBusy = true;
    try {
      const result = await pollDueChannels();
      await applyChannelPollResult(result, true);
      channelsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel poll failed", "error", message));
    } finally {
      channelSettingsBusy = false;
    }
  }

  async function runBackgroundChannelPoll() {
    if (channelAutoPollBusy || channelSettingsBusy || !channelSettings?.auto_poll_enabled) {
      return;
    }
    channelAutoPollBusy = true;
    try {
      const result = await pollDueChannels();
      await applyChannelPollResult(result, false);
      channelsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
    } finally {
      channelAutoPollBusy = false;
    }
  }

