    } finally {
      channelNotificationBusy = "";
    }
  }

  async function markVisibleChannelNotificationsShown() {
    const items = visiblePendingChannelNotifications;
    if (items.length === 0) {
      return;
    }

    channelNotificationBusy = "mark-visible";
    try {
      const result = await markChannelNotificationsShown(items.map((item) => item.id));
      const byId = new Map(result.items.map((item) => [item.id, item]));
      channelHistory = channelHistory.map((item) => byId.get(item.id) ?? item);
      channelsError = "";
      const failedSummary = result.failed.length > 0 ? ` · ${result.failed.length} failed` : "";
      pushToast(createToast(
        "Notifications marked",
        "success",
        `${result.items.length} shown item${result.items.length === 1 ? "" : "s"}${failedSummary}`,
        result.items[0] ? targetToastAction("Open", "channels", { history_id: result.items[0].id }) : undefined
      ));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Notification batch update failed", "error", message));
    } finally {
      channelNotificationBusy = "";
    }
  }

  async function queueChannelHistoryDownload(item: ChannelHistoryItem) {
    await maybeAutoSelectToolsCookieBucket(item.source_url);
    maybeAutoSelectToolsAuthorizationPayload(item.source_url);
    channelNotificationBusy = `${item.id}:queue`;
    try {
      const task = await queueChannelHistoryItem(item.id, buildToolsCreateOptions("video"));
      if (task) {
        downloads = [task, ...downloads.filter((candidate) => candidate.id !== task.id)].sort(
          (first, second) => first.position - second.position
        );
        channelHistory = channelHistory.map((candidate) =>
          candidate.id === item.id ? { ...candidate, created_task_id: task.id } : candidate
        );
        pushToast(createToast("Channel item queued", "success", task.title, targetToastAction("Task", "downloads", { task_id: task.id })));
      }
      channelsError = "";
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel queue failed", "error", message));
    } finally {
      channelNotificationBusy = "";
    }
  }

  async function queueFilteredChannelHistoryDownloads() {
    const items = queueableChannelHistoryItems(filteredChannelHistory);
    if (items.length === 0) {
      channelsError = "No queueable channel history items match the current filters.";
      pushToast(createToast("Channel batch skipped", "info", channelsError));
      return;
    }

    await maybeAutoSelectToolsCookieBucket(items[0].source_url);
    maybeAutoSelectToolsAuthorizationPayload(items[0].source_url);
    channelNotificationBusy = "queue-filtered";
    try {
      const result = await queueChannelHistoryItems(items.map((item) => item.id), buildToolsCreateOptions("video"));
      if (result.created.length > 0) {
        const createdIds = new Set(result.created.map((task) => task.id));
        downloads = [
          ...result.created,
          ...downloads.filter((candidate) => !createdIds.has(candidate.id))
        ].sort((first, second) => first.position - second.position);
      }
      channelHistory = result.items;
      channelsError = "";
      const skippedSummary = result.skipped.length > 0 ? ` · ${result.skipped.length} skipped` : "";
      pushToast(
        createToast(
          "Channel history queued",
          "success",
          `${result.created.length} task${result.created.length === 1 ? "" : "s"}${skippedSummary}`,
          firstTaskToastAction(result.created)
        )
      );
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      channelsError = message;
      pushToast(createToast("Channel batch queue failed", "error", message));
    } finally {
      channelNotificationBusy = "";
    }
  }

