  function upsertPlugin(plugin: PluginInfo | null) {
    if (!plugin) {
      return;
    }
    plugins = [plugin, ...plugins.filter((item) => item.id !== plugin.id)].sort((left, right) =>
      left.display_name.localeCompare(right.display_name)
    );
    pluginCommandInputs = {
      ...pluginCommandInputs,
      [plugin.id]: pluginCommandInputs[plugin.id] ?? plugin.commands[0] ?? ""
    };
    pluginCommandPayloadInputs = {
      ...pluginCommandPayloadInputs,
      [plugin.id]: pluginCommandPayloadInputs[plugin.id] ?? "{}"
    };
    pluginEventInputs = {
      ...pluginEventInputs,
      [plugin.id]: pluginEventInputs[plugin.id] ?? plugin.events[0]?.name ?? ""
    };
    pluginEventPayloadInputs = {
      ...pluginEventPayloadInputs,
      [plugin.id]: pluginEventPayloadInputs[plugin.id] ?? "{}"
    };
  }

  function syncPlugins(nextPlugins: PluginInfo[], nextMarketplace: PluginMarketplaceEntry[]) {
    const sortedPlugins = [...nextPlugins].sort((left, right) => left.display_name.localeCompare(right.display_name));
    plugins = sortedPlugins;
    pluginMarketplaceEntries = nextMarketplace;

    const ids = new Set(sortedPlugins.map((plugin) => plugin.id));
    pluginCommandInputs = Object.fromEntries(
      sortedPlugins.map((plugin) => [plugin.id, pluginCommandInputs[plugin.id] ?? plugin.commands[0] ?? ""])
    );
    pluginCommandPayloadInputs = Object.fromEntries(
      sortedPlugins.map((plugin) => [plugin.id, pluginCommandPayloadInputs[plugin.id] ?? "{}"])
    );
    pluginEventInputs = Object.fromEntries(
      sortedPlugins.map((plugin) => [plugin.id, pluginEventInputs[plugin.id] ?? plugin.events[0]?.name ?? ""])
    );
    pluginEventPayloadInputs = Object.fromEntries(
      sortedPlugins.map((plugin) => [plugin.id, pluginEventPayloadInputs[plugin.id] ?? "{}"])
    );
    pluginCommandLogs = Object.fromEntries(Object.entries(pluginCommandLogs).filter(([id]) => ids.has(id)));
    pluginEventLogs = Object.fromEntries(Object.entries(pluginEventLogs).filter(([id]) => ids.has(id)));
    pluginActivityLogs = Object.fromEntries(Object.entries(pluginActivityLogs).filter(([id]) => ids.has(id)));
    if (selectedPluginSettings && !ids.has(selectedPluginSettings.id)) {
      selectedPluginSettings = null;
      pluginSettingsJsonInput = "{}";
    }
    if (activePluginNav && !ids.has(activePluginNav.plugin.id)) {
      navigate("plugins");
    }
  }

  function handlePluginsChanged(event: PluginsChangedEvent) {
    syncPlugins(event.plugins, event.marketplace);
  }

  function marketplaceEntryForPlugin(plugin: PluginInfo) {
    return pluginMarketplaceEntries.find((entry) => entry.id === plugin.id) ?? null;
  }

  function marketplaceVersionLabel(plugin: PluginInfo) {
    const entry = marketplaceEntryForPlugin(plugin);
    if (!entry?.version) {
      return "No registry version";
    }
    return entry.version === plugin.version ? "Registry version matches" : `Registry version ${entry.version}`;
  }

