          courseProgressInputs = {
            ...courseProgressInputs,
            ...Object.fromEntries(result.courses.flatMap((course) => course.lessons.map((lesson) => [`${course.id}:${lesson.id}`, String(lesson.progress_percent)])))
          };
        }
        pushToast(createToast(
          "Course progress imported",
          "success",
          `${result.imported_lesson_count} lesson${result.imported_lesson_count === 1 ? "" : "s"} restored`,
          targetToastAction("Open", "courses", { query: result.courses[0]?.title ?? "" })
        ));
      }
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Course progress import failed", "error", coursesError));
    } finally {
      coursesBusy = false;
    }
  }

  async function openCourseProgressExportResult() {
    await openLocalPath(courseProgressExportResult?.output_path ?? courseProgressExportPath, "Course progress export");
  }

  async function revealCourseProgressExportResult() {
    await revealLocalPath(courseProgressExportResult?.output_path ?? courseProgressExportPath, "Course progress export");
  }

  function requestCourseDelete(course: CourseEntry) {
    confirmDialog = {
      title: "Remove course?",
      message: `Remove ${course.title} from the local course library. Download tasks, learning notes, cookies, and local files are left untouched.`,
      confirmLabel: "Remove",
      onConfirm: async () => {
        courseActionBusy = `${course.id}:delete`;
        try {
          const deleted = await deleteCourse(course.id);
          if (deleted) {
            removeCourseFromState(course.id);
            pushToast(createToast("Course removed", "success", course.title, targetToastAction("Open", "courses", { query: course.title })));
          } else {
            pushToast(createToast("Course already removed", "success", course.title, targetToastAction("Open", "courses", { query: course.title })));
          }
          coursesError = "";
        } catch (error) {
          coursesError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Course remove failed", "error", coursesError));
        } finally {
          courseActionBusy = "";
        }
      }
    };
  }

  function removeCourseFromState(courseId: string) {
    courses = courses.filter((item) => item.id !== courseId);
    delete courseCookieBucketInputs[courseId];
    courseProbeResult = courseProbeResult?.id === courseId ? null : courseProbeResult;
    if (coursePreviewLesson?.course.id === courseId) {
      coursePreviewLesson = null;
    }
    if (coursePreviewAttachment?.course.id === courseId) {
      coursePreviewAttachment = null;
    }
    courseProgressInputs = Object.fromEntries(Object.entries(courseProgressInputs).filter(([key]) => !key.startsWith(`${courseId}:`)));
    courseNoteTitles = Object.fromEntries(Object.entries(courseNoteTitles).filter(([key]) => !key.startsWith(`${courseId}:`)));
    courseNoteBodies = Object.fromEntries(Object.entries(courseNoteBodies).filter(([key]) => !key.startsWith(`${courseId}:`)));
    courseNoteTimestamps = Object.fromEntries(Object.entries(courseNoteTimestamps).filter(([key]) => !key.startsWith(`${courseId}:`)));
    courseExpandedLessonIds = Object.fromEntries(Object.entries(courseExpandedLessonIds).filter(([key]) => key !== courseId));
    courseExpandedAttachmentIds = Object.fromEntries(Object.entries(courseExpandedAttachmentIds).filter(([key]) => key !== courseId));
  }

  function requestFilteredCoursesRemove() {
    const targets = [...filteredCourses];
    if (targets.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown courses?",
      message: `Remove ${targets.length} shown local course entr${targets.length === 1 ? "y" : "ies"}. Download tasks, learning notes, Cookie buckets, lesson progress exports, and local files are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        courseActionBusy = "remove-filtered-courses";
        try {
          const result = await deleteCourses(targets.map((course) => course.id));
          for (const courseId of result.deleted) {
            removeCourseFromState(courseId);
          }
          coursesError = "";
          const removed = result.deleted.length;
          const failed = result.failed.length;
          pushToast(createToast(
            "Courses removed",
            "success",
            `${removed} local course${removed === 1 ? "" : "s"}${failed > 0 ? `, ${failed} failed` : ""}`,
            targetToastAction("Open", "courses", { query: targets[0]?.title ?? "" })
          ));
        } catch (error) {
          coursesError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown course remove failed", "error", coursesError));
        } finally {
          courseActionBusy = "";
        }
      }
    };
  }

  function applyUpdatedCourse(course: CourseEntry) {
    courses = courses.map((item) => (item.id === course.id ? course : item));
    courseCookieBucketInputs[course.id] = course.cookie_bucket_id ?? "";
  }

  function requestCoursesClear() {
    confirmDialog = {
      title: "Clear course library?",
      message: `Remove all ${courses.length} local course candidate${courses.length === 1 ? "" : "s"}. Download tasks, learning notes, cookie buckets, and local files are left untouched.`,
      confirmLabel: "Clear",
      onConfirm: async () => {
        coursesBusy = true;
        courseActionBusy = "clear";
        try {
          const cleared = await clearCourses();
          courses = [];
          courseCookieBucketInputs = {};
          courseProgressInputs = {};
          courseNoteTitles = {};
          courseNoteBodies = {};
          courseNoteTimestamps = {};
          courseExpandedLessonIds = {};
          courseExpandedAttachmentIds = {};
          courseProbeResult = null;
          coursePreviewLesson = null;
          coursePreviewAttachment = null;
          coursesError = "";
          pushToast(createToast("Course library cleared", "success", `${cleared} course${cleared === 1 ? "" : "s"}`, targetToastAction("Open", "courses", { query: "" })));
        } catch (error) {
          coursesError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Course clear failed", "error", coursesError));
        } finally {
          courseActionBusy = "";
          coursesBusy = false;
        }
      }
    };
  }

  async function pruneMissingCourseFiles() {
    coursesBusy = true;
    courseActionBusy = "prune-missing";
    try {
      const response = await pruneMissingCourseLocalFiles();
      if (response) {
        courses = response.courses;
        const removed = response.pruned_lessons + response.pruned_attachments;
        const previewCourse = coursePreviewLesson
          ? response.courses.find((course) => course.id === coursePreviewLesson?.course.id)
          : null;
        const previewLesson = previewCourse?.lessons.find((lesson) => lesson.id === coursePreviewLesson?.lesson.id);
        if (coursePreviewLesson && !previewLesson?.local_path) {
          coursePreviewLesson = null;
        }
        const attachmentCourse = coursePreviewAttachment
          ? response.courses.find((course) => course.id === coursePreviewAttachment?.course.id)
          : null;
        const previewAttachment = attachmentCourse?.attachments.find((attachment) => attachment.id === coursePreviewAttachment?.attachment.id);
        if (coursePreviewAttachment && !previewAttachment?.local_path) {
          coursePreviewAttachment = null;
        }
        pushToast(
          createToast(
            "Course paths pruned",
            "success",
            `${removed} missing local path${removed === 1 ? "" : "s"} removed`,
            targetToastAction("Open", "courses", { query: "" })
          )
        );
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Course prune failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
      coursesBusy = false;
    }
  }

  function courseLessonProgressValue(course: CourseEntry, lesson: CourseLesson): string {
    return courseProgressInputs[`${course.id}:${lesson.id}`] ?? String(lesson.progress_percent);
  }

  async function saveCourseLessonProgress(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}`;
    const parsed = Number(courseLessonProgressValue(course, lesson));
    const progress = Number.isFinite(parsed) ? Math.max(0, Math.min(100, Math.round(parsed))) : 0;
    courseActionBusy = key;
    try {
      const updated = await updateCourseLessonProgress(course.id, lesson.id, progress);
      if (updated) {
        courses = courses.map((item) => (item.id === updated.id ? updated : item));
        courseProgressInputs[key] = String(progress);
        pushToast(createToast("Lesson progress saved", "success", `${lesson.title} · ${progress}%`, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Lesson progress failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  async function saveCourseLessonTimestampNote(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}`;
    const title = (courseNoteTitles[key] || `${lesson.title} note`).trim();
    const body = (courseNoteBodies[key] || "").trim();
    const rawTimestamp = (courseNoteTimestamps[key] || "").trim();
    const timestamp = rawTimestamp ? Number(rawTimestamp) : null;
    if (!body) {
      coursesError = "Lesson note body is required.";
      pushToast(createToast("Lesson note invalid", "error", coursesError));
      return;
    }

    courseActionBusy = `${key}:note`;
    try {
      const note = await saveCourseLessonNote({
        courseId: course.id,
        lessonId: lesson.id,
        title,
        body,
        timestampSeconds: Number.isFinite(timestamp) ? Math.max(0, Math.round(timestamp as number)) : null
      });
      if (note) {
        learningNotes = [note, ...learningNotes.filter((item) => item.id !== note.id)];
        courses = courses.map((item) =>
          item.id === course.id
            ? {
                ...item,
                lessons: item.lessons.map((candidate) =>
                  candidate.id === lesson.id
                    ? { ...candidate, note_count: candidate.note_count + 1 }
                    : candidate
                )
              }
            : item
        );
        courseNoteBodies[key] = "";
        pushToast(createToast("Lesson note saved", "success", note.title, learningNoteToastAction(note)));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Lesson note failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  async function openCourseLessonMedia(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}:open`;
    courseActionBusy = key;
    try {
      const updated = await openCourseLesson(course.id, lesson.id);
      if (updated) {
        courses = courses.map((item) => (item.id === updated.id ? updated : item));
      }
      coursesError = "";
      pushToast(createToast("Lesson opened", "success", lesson.title, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Lesson open failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  function courseLessonPreviewKind(lesson: CourseLesson) {
    const path = lesson.local_path?.toLowerCase() ?? "";
    if (/\.(mp4|m4v|webm|mov|mkv)$/.test(path)) {
      return "video";
    }
    if (/\.(mp3|m4a|aac|ogg|opus|flac|wav)$/.test(path)) {
      return "audio";
    }
    return "";
  }

  function canPreviewCourseAttachment(attachment: CourseAttachment) {
    return Boolean(attachment.local_path && attachment.local_path.toLowerCase().endsWith(".pdf"));
  }

  function courseLessonNotes(lesson: CourseLesson): LearningNote[] {
    return learningNotes.filter((note) => {
      if (lesson.source_url && note.source_url === lesson.source_url) {
        return true;
      }
      return note.title.toLowerCase().includes(lesson.title.toLowerCase()) && note.tags.includes("course");
    });
  }

  async function jumpToCourseLessonNote(course: CourseEntry, lesson: CourseLesson, note: LearningNote) {
    if (!lesson.local_path || !courseLessonPreviewKind(lesson)) {
      pushToast(createToast("Lesson preview unavailable", "error", "This lesson has no local playable media."));
      return;
    }
    coursePreviewLesson = { course, lesson };
    await tick();
    if (coursePreviewMediaElement && note.timestamp_seconds !== null && note.timestamp_seconds !== undefined) {
      coursePreviewMediaElement.currentTime = Math.max(0, note.timestamp_seconds);
      try {
        await coursePreviewMediaElement.play();
      } catch {
        // Browser autoplay rules may require the user to press play.
      }
      pushToast(createToast("Lesson timestamp opened", "success", `${lesson.title} · ${formatTimestamp(note.timestamp_seconds)}`, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
    } else {
      pushToast(createToast("Lesson preview opened", "success", lesson.title, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
    }
  }

  function previewCourseLessonMedia(course: CourseEntry, lesson: CourseLesson) {
    coursePreviewLesson = { course, lesson };
    coursePreviewProgressSaveKey = "";
    pushToast(createToast("Lesson preview", "success", lesson.title, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
  }

  function useCurrentCoursePreviewTime(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}`;
    if (!coursePreviewMediaElement || !coursePreviewLesson || coursePreviewLesson.course.id !== course.id || coursePreviewLesson.lesson.id !== lesson.id) {
      pushToast(createToast("Preview time unavailable", "error", "Open this lesson in Preview before capturing the note time."));
      return;
    }

    const seconds = Math.max(0, Math.floor(coursePreviewMediaElement.currentTime || 0));
    courseNoteTimestamps[key] = String(seconds);
    pushToast(createToast("Preview time captured", "success", `${lesson.title} · ${formatTimestamp(seconds)}`, targetToastAction("Open", "courses", { course_id: course.id, lesson_id: lesson.id })));
  }

  async function saveCourseCookieBucket(course: CourseEntry) {
    const key = `${course.id}:cookie`;
    courseActionBusy = key;
    try {
      const updated = await updateCourseCookieBucket(course.id, courseCookieBucketValue(course) || undefined);
      if (updated) {
        courses = courses.map((item) => (item.id === updated.id ? updated : item));
        courseCookieBucketInputs[updated.id] = updated.cookie_bucket_id ?? "";
        pushToast(createToast("Course cookie saved", "success", cookieBucketLabel(updated.cookie_bucket_id), courseToastAction(updated)));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Course cookie failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  function restoreCoursePreviewProgress() {
    if (!coursePreviewLesson || !coursePreviewMediaElement || !Number.isFinite(coursePreviewMediaElement.duration)) {
      return;
    }
    const progress = Math.max(0, Math.min(99, coursePreviewLesson.lesson.progress_percent));
    if (progress <= 0) {
      return;
    }
    coursePreviewMediaElement.currentTime = Math.max(0, (coursePreviewMediaElement.duration * progress) / 100);
  }

  async function saveCoursePreviewProgressFromMedia() {
    if (!coursePreviewLesson || !coursePreviewMediaElement || !Number.isFinite(coursePreviewMediaElement.duration) || coursePreviewMediaElement.duration <= 0) {
      return;
    }
    const progress = Math.max(0, Math.min(100, Math.round((coursePreviewMediaElement.currentTime / coursePreviewMediaElement.duration) * 100)));
    const key = `${coursePreviewLesson.course.id}:${coursePreviewLesson.lesson.id}:${progress}`;
    if (progress === coursePreviewLesson.lesson.progress_percent || progress < 1 || key === coursePreviewProgressSaveKey) {
      return;
    }
    coursePreviewProgressSaveKey = key;
    try {
      const updated = await updateCourseLessonProgress(coursePreviewLesson.course.id, coursePreviewLesson.lesson.id, progress);
      if (updated) {
        courses = courses.map((item) => (item.id === updated.id ? updated : item));
        const updatedLesson = updated.lessons.find((lesson) => lesson.id === coursePreviewLesson?.lesson.id);
        coursePreviewLesson = {
          course: updated,
          lesson: updatedLesson ?? { ...coursePreviewLesson.lesson, progress_percent: progress }
        };
        courseProgressInputs[`${updated.id}:${coursePreviewLesson.lesson.id}`] = String(progress);
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
    }
  }

  function previewCourseAttachment(course: CourseEntry, attachment: CourseAttachment) {
    coursePreviewAttachment = { course, attachment };
    pushToast(createToast("Attachment preview", "success", attachment.title, targetToastAction("Open", "courses", { course_id: course.id, attachment_id: attachment.id })));
  }

  async function queueCourseLessonDownload(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}:queue`;
    if (lesson.source_url) {
      await maybeAutoSelectToolsCookieBucket(lesson.source_url);
      maybeAutoSelectToolsAuthorizationPayload(lesson.source_url);
    }
    courseActionBusy = key;
    try {
      const task = await queueCourseLesson(
        course.id,
        lesson.id,
        toolsOutputDir.trim() || undefined,
        courseCookieBucketValue(course) || undefined,
        buildToolsCreateOptions("course_lesson")
      );
      if (task) {
        downloads = [task, ...downloads.filter((item) => item.id !== task.id)];
        pushToast(createToast("Lesson queued", "success", task.title, targetToastAction("Task", "downloads", { task_id: task.id })));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Lesson queue failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  async function queueCourseLessonsBatch(course: CourseEntry) {
    const firstLessonSourceUrl = course.lessons.find((lesson) => lesson.source_url)?.source_url;
    if (firstLessonSourceUrl) {
      await maybeAutoSelectToolsCookieBucket(firstLessonSourceUrl);
      maybeAutoSelectToolsAuthorizationPayload(firstLessonSourceUrl);
    }
    courseActionBusy = `${course.id}:queue-all`;
    try {
      const result = await queueAllCourseLessons(
        course.id,
        toolsOutputDir.trim() || undefined,
        undefined,
        courseCookieBucketValue(course) || undefined,
        buildToolsCreateOptions("course_lesson")
      );
      if (result) {
        downloads = await listDownloadTasks();
        pushToast(createToast(
          "Course lessons queued",
          "success",
          `${result.created.length} created · ${result.skipped.length} skipped`,
          targetToastAction("Open", "courses", { course_id: course.id })
        ));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Course batch queue failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  async function queueFilteredCourseLessonsBatch() {
    courseActionBusy = "queue-filtered-lessons";
    try {
      const groups = new Map<string, { course: CourseEntry; lessonIds: string[] }>();
      const sourcePairs = shownCourseLessonPairs().filter((item) => item.lesson.source_url);
      for (const { course, lesson } of sourcePairs) {
        const group = groups.get(course.id) ?? { course, lessonIds: [] };
        group.lessonIds.push(lesson.id);
        groups.set(course.id, group);
      }
      const firstLessonSourceUrl = sourcePairs[0]?.lesson.source_url;
      if (firstLessonSourceUrl) {
        await maybeAutoSelectToolsCookieBucket(firstLessonSourceUrl);
        maybeAutoSelectToolsAuthorizationPayload(firstLessonSourceUrl);
      }
      const result = await queueManyCourseLessons(
        Array.from(groups.values()).map(({ course, lessonIds }) => ({
          courseId: course.id,
          lessonIds,
          outputDir: toolsOutputDir.trim() || undefined,
          cookieBucketId: courseCookieBucketValue(course) || undefined,
          options: buildToolsCreateOptions("course_lesson")
        }))
      );
      downloads = await listDownloadTasks();
      coursesError = "";
      const failedText = result.failed.length > 0 ? ` · ${result.failed.length} failed` : "";
      pushToast(createToast(
        "Shown course lessons queued",
        result.failed.length > 0 ? "warning" : "success",
        `${result.created.length} created · ${result.skipped.length} skipped${failedText}`
      ));
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Shown lessons queue failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

