  async function removeCourseLessonItem(course: CourseEntry, lesson: CourseLesson) {
    const key = `${course.id}:${lesson.id}:delete`;
    courseActionBusy = key;
    try {
      const response = await deleteCourseLesson(course.id, lesson.id);
      if (response) {
        applyUpdatedCourse(response.course);
        delete courseProgressInputs[`${course.id}:${lesson.id}`];
        delete courseNoteTitles[`${course.id}:${lesson.id}`];
        delete courseNoteBodies[`${course.id}:${lesson.id}`];
        delete courseNoteTimestamps[`${course.id}:${lesson.id}`];
        if (coursePreviewLesson?.course.id === course.id && coursePreviewLesson.lesson.id === lesson.id) {
          coursePreviewLesson = null;
        }
        pushToast(createToast(
          response.deleted ? "Lesson removed" : "Lesson already removed",
          "success",
