  async function removeCourseAttachmentItem(course: CourseEntry, attachment: CourseAttachment) {
    const key = `${course.id}:${attachment.id}:delete-attachment`;
    courseActionBusy = key;
    try {
      const response = await deleteCourseAttachment(course.id, attachment.id);
      if (response) {
        applyUpdatedCourse(response.course);
        if (coursePreviewAttachment?.course.id === course.id && coursePreviewAttachment.attachment.id === attachment.id) {
          coursePreviewAttachment = null;
        }
        pushToast(createToast(
          response.deleted ? "Attachment removed" : "Attachment already removed",
          "success",
          attachment.title,
          courseToastAction(response.course)
        ));
      }
      coursesError = "";
    } catch (error) {
      coursesError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Attachment remove failed", "error", coursesError));
    } finally {
      courseActionBusy = "";
    }
  }

  function requestShownCourseLessonsRemove() {
    const pairs = shownCourseLessonPairs();
    if (pairs.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown lessons?",
      message: `Remove ${pairs.length} shown lesson${pairs.length === 1 ? "" : "s"} from the local course outline. Download tasks, learning notes, Cookie buckets, and local files are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        courseActionBusy = "remove-shown-lessons";
        try {
          const groups = new Map<string, string[]>();
          for (const { course, lesson } of pairs) {
            const lessonIds = groups.get(course.id) ?? [];
            lessonIds.push(lesson.id);
            groups.set(course.id, lessonIds);
          }
          const result = await deleteCourseLessons(
            Array.from(groups, ([courseId, lessonIds]) => ({
              courseId,
              lessonIds
            }))
          );
          for (const course of result.courses) {
            applyUpdatedCourse(course);
          }
          const deletedLessonKeys = new Set(result.deleted);
          for (const { course, lesson } of pairs) {
            if (!deletedLessonKeys.has(`${course.id}:${lesson.id}`)) {
              continue;
            }
            const courseId = course.id;
            const lessonId = lesson.id;
            delete courseProgressInputs[`${courseId}:${lessonId}`];
            delete courseNoteTitles[`${courseId}:${lessonId}`];
            delete courseNoteBodies[`${courseId}:${lessonId}`];
            delete courseNoteTimestamps[`${courseId}:${lessonId}`];
            if (coursePreviewLesson?.course.id === courseId && coursePreviewLesson.lesson.id === lessonId) {
              coursePreviewLesson = null;
            }
          }
          coursesError = "";
          const removed = result.deleted.length;
          const failed = result.failed.length;
          pushToast(createToast(
            "Shown lessons removed",
            "success",
            `${removed} lesson${removed === 1 ? "" : "s"} removed${failed > 0 ? `, ${failed} failed` : ""}.`,
            courseToastAction(result.courses[0] ?? pairs[0]?.course)
          ));
        } catch (error) {
          coursesError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown lessons remove failed", "error", coursesError));
        } finally {
          courseActionBusy = "";
        }
      }
    };
  }

