  async function addLearningNote() {
    learningBusy = true;
    learningError = "";
    try {
      const tags = learningNoteTags
        .split(",")
        .map((tag) => tag.trim())
        .filter(Boolean);
      const timestamp = learningNoteTimestamp.trim() ? Number(learningNoteTimestamp) : null;
      const note = await saveLearningNote({
        id: learningEditingNoteId || undefined,
        title: learningNoteTitle.trim(),
        body: learningNoteBody.trim(),
        sourceUrl: learningNoteSourceUrl.trim() || undefined,
        timestampSeconds: Number.isFinite(timestamp) ? timestamp : null,
        tags
      });
      if (note) {
        learningNotes = [note, ...learningNotes.filter((item) => item.id !== note.id)];
        learningNoteTitle = "";
        learningNoteBody = "";
        learningNoteSourceUrl = "";
        learningNoteTimestamp = "";
        learningNoteTags = "";
        learningEditingNoteId = "";
        await refreshLearningDashboard();
        pushToast(createToast("Note saved", "success", note.title, learningNoteToastAction(note)));
      }
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Note save failed", "error", learningError));
    } finally {
      learningBusy = false;
    }
  }

