  async function saveLearningDailyGoal() {
    const parsed = Number(learningDailyGoalInput);
    if (!Number.isFinite(parsed) || parsed < 1) {
      learningError = "Daily focus goal must be at least 1 minute.";
      pushToast(createToast("Daily goal invalid", "error", learningError));
      return;
    }
    learningBusy = true;
    learningError = "";
    try {
      learningDashboard = await updateLearningDailyGoal(Math.round(parsed));
      if (learningDashboard) {
        learningDailyGoalInput = String(learningDashboard.daily_goal_minutes);
      }
      pushToast(createToast("Daily goal saved", "success", `${learningDailyGoalInput} minutes`, targetToastAction("Open", "learning", { query: "goal" })));
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Daily goal failed", "error", learningError));
    } finally {
      learningBusy = false;
    }
  }

