    spacedReviewPrompt = draft.prompt;
    spacedReviewAnswer = draft.answer;
    spacedReviewNoteId = note.id;
    spacedReviewSourceUrl = draft.sourceUrl ?? "";
    spacedReviewTags = draft.tags.join(", ");
    spacedReviewDueOnly = false;
    pushToast(createToast("Review draft filled", "success", note.title, targetToastAction("Open", "learning", { query: note.id })));
