  async function saveSpacedReviewCardFromNote(note: LearningNote) {
    spacedReviewBusy = `note:${note.id}`;
    try {
      const draft = learningNoteReviewDraft(note);
      const card = await saveSpacedReviewCard({
        prompt: draft.prompt,
        answer: draft.answer,
        noteId: note.id,
        sourceUrl: draft.sourceUrl,
        tags: draft.tags
      });
      if (card) {
        spacedReviewCards = [card, ...spacedReviewCards.filter((item) => item.id !== card.id)];
        await refreshLearningDashboard();
        pushToast(createToast("Review card saved", "success", card.prompt, targetToastAction("Open", "learning", { query: card.id })));
      }
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Review card save failed", "error", learningError));
    } finally {
      spacedReviewBusy = "";
    }
  }

  async function addSpacedReviewCardFromForm() {
    const prompt = spacedReviewPrompt.trim();
    const answer = spacedReviewAnswer.trim();
    if (!prompt || !answer) {
      learningError = "Review prompt and answer are required.";
      pushToast(createToast("Review card invalid", "error", learningError));
      return;
    }
    spacedReviewBusy = "save";
    try {
      const card = await saveSpacedReviewCard({
        prompt,
        answer,
        noteId: spacedReviewNoteId.trim() || undefined,
        sourceUrl: spacedReviewSourceUrl.trim() || undefined,
        tags: spacedReviewTags.split(",").map((tag) => tag.trim()).filter(Boolean)
      });
      if (card) {
        spacedReviewCards = [card, ...spacedReviewCards.filter((item) => item.id !== card.id)];
        spacedReviewPrompt = "";
        spacedReviewAnswer = "";
        spacedReviewTags = "";
        spacedReviewSourceUrl = "";
        spacedReviewNoteId = "";
        await refreshLearningDashboard();
        pushToast(createToast("Review card saved", "success", card.prompt, targetToastAction("Open", "learning", { query: card.id })));
      }
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Review card save failed", "error", learningError));
    } finally {
      spacedReviewBusy = "";
    }
