  async function rateSpacedReviewCard(card: SpacedReviewCard, rating: "again" | "hard" | "good" | "easy") {
    spacedReviewBusy = `${card.id}:${rating}`;
    try {
      const updated = await reviewSpacedReviewCard(card.id, rating);
      if (updated) {
        spacedReviewCards = spacedReviewCards.map((item) => item.id === updated.id ? updated : item);
        await refreshLearningDashboard();
        pushToast(createToast("Review recorded", "success", `${updated.prompt} · due ${updated.due_at}`, targetToastAction("Open", "learning", { query: updated.id })));
