  function parsedPomodoroMinutes(): number {
    const parsed = Number(pomodoroDuration);
    return Number.isFinite(parsed) ? Math.max(1, Math.min(240, Math.round(parsed))) : 25;
  }

  function parsedPomodoroBreakMinutes(): number {
    const parsed = Number(pomodoroBreak);
    return Number.isFinite(parsed) ? Math.max(0, Math.min(120, Math.round(parsed))) : 0;
  }

  function formatTimerSeconds(totalSeconds: number): string {
    const clamped = Math.max(0, Math.round(totalSeconds));
    const minutes = Math.floor(clamped / 60);
    const seconds = clamped % 60;
    return `${minutes}:${seconds.toString().padStart(2, "0")}`;
  }

  function startPomodoroTimer() {
    const totalSeconds = parsedPomodoroMinutes() * 60;
    pomodoroDuration = String(parsedPomodoroMinutes());
    pomodoroBreak = String(parsedPomodoroBreakMinutes());
    if (pomodoroTimerRemainingSeconds <= 0 || pomodoroTimerRemainingSeconds === pomodoroTimerTotalSeconds) {
      pomodoroTimerRemainingSeconds = totalSeconds;
    }
    pomodoroTimerTotalSeconds = totalSeconds;
    pomodoroTimerStartedAt = pomodoroTimerStartedAt ?? new Date().toISOString();
    pomodoroTimerRunning = true;
    pushToast(createToast("Focus timer started", "success", pomodoroTimerLabel, targetToastAction("Open", "learning", { query: pomodoroTimerLabel })));
  }

  function pausePomodoroTimer() {
    pomodoroTimerRunning = false;
    pushToast(createToast("Focus timer paused", "success", pomodoroTimerLabel, targetToastAction("Open", "learning", { query: pomodoroTimerLabel })));
  }

  function resetPomodoroTimer() {
    pomodoroTimerRunning = false;
    pomodoroTimerTotalSeconds = parsedPomodoroMinutes() * 60;
    pomodoroTimerRemainingSeconds = pomodoroTimerTotalSeconds;
    pomodoroTimerStartedAt = null;
  }

  function tickPomodoroTimer() {
    if (!pomodoroTimerRunning) {
      return;
    }
    if (pomodoroTimerRemainingSeconds <= 1) {
      pomodoroTimerRemainingSeconds = 0;
      pomodoroTimerRunning = false;
      void completePomodoroTimer();
      return;
    }
    pomodoroTimerRemainingSeconds -= 1;
  }

  async function completePomodoroTimer() {
    pauseLearningMedia();
    const label = pomodoroLabel.trim() || "Focus timer";
    try {
      const session = await savePomodoroSession({
        label,
        durationMinutes: Math.max(1, Math.round(pomodoroTimerTotalSeconds / 60)),
        breakMinutes: parsedPomodoroBreakMinutes(),
        completed: true,
        linkedSourceUrl: pomodoroSourceUrl.trim() || undefined,
        notifyOnComplete: true
      });
      if (session) {
        pomodoroSessions = [session, ...pomodoroSessions];
        await refreshLearningDashboard();
        pushToast(createToast("Focus timer complete", "success", "Playback paused and session recorded.", {
          label: "Open",
          onClick: () => handleShellOpenTarget({ route: "learning", params: { session_id: session.id } })
        }));
      } else {
        pushToast(createToast("Focus timer complete", "success", "Playback paused and session recorded."));
      }
    } catch (error) {
      learningError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Focus timer complete", "error", learningError));
    } finally {
      pomodoroTimerStartedAt = null;
      pomodoroTimerRemainingSeconds = pomodoroTimerTotalSeconds;
    }
  }

  function pauseLearningMedia() {
    coursePreviewMediaElement?.pause();
    musicAudioElement?.pause();
    for (const element of document.querySelectorAll("audio, video")) {
      if (element instanceof HTMLMediaElement) {
        element.pause();
      }
    }
  }

