  function removeTelegramChatFromState(chatId: string) {
    const removedChat = telegramChats.find((chat) => chat.id === chatId);
    const removedMediaIds = new Set(removedChat?.media.map((media) => media.id) ?? []);
    telegramChats = telegramChats.filter((chat) => chat.id !== chatId);
    telegramExpandedMediaChatIds = Object.fromEntries(Object.entries(telegramExpandedMediaChatIds).filter(([id]) => id !== chatId));
    if (telegramCloneChatId === chatId) {
      telegramCloneChatId = telegramChats[0]?.id ?? "";
    }
    if (telegramChannelDrawerSelectedId === chatId) {
      telegramChannelDrawerSelectedId = "";
      telegramBrowserSearch = "";
    }
    if (telegramCloneResult?.chat.id === chatId) {
      telegramCloneResult = null;
    }
    if (telegramPreviewMedia && (telegramPreviewMedia.chat_id === chatId || removedMediaIds.has(telegramPreviewMedia.id))) {
      telegramPreviewMedia = null;
    }
    if (telegramSearchResults) {
      telegramSearchResults = {
        chats: telegramSearchResults.chats.filter((chat) => chat.id !== chatId),
        media: telegramSearchResults.media.filter((media) => media.chat_id !== chatId && !removedMediaIds.has(media.id))
      };
    }
  }

  function clearTelegramChatState() {
    telegramChats = [];
    telegramCloneChatId = "";
    telegramCloneResult = null;
    telegramPreviewMedia = null;
    telegramSearchResults = null;
    telegramExpandedMediaChatIds = {};
    telegramChatsExpanded = false;
    telegramChannelDrawerSelectedId = "";
    telegramChannelDrawerExpanded = false;
    telegramChannelDrawerKind = "all";
  }

  function requestTelegramChatDelete(chat: TelegramChat) {
    confirmDialog = {
      title: "Remove Telegram chat?",
      message: `Remove ${chat.title} from the local imported Telegram manifest index. Media files, download tasks, transfer records, and account state are left untouched.`,
      confirmLabel: "Remove",
      onConfirm: async () => {
        telegramBusy = true;
        try {
          const deleted = await deleteTelegramChat(chat.id);
          removeTelegramChatFromState(chat.id);
          await loadTelegramSyncStatus();
          await loadTelegramLocalSummary();
          telegramError = "";
          pushToast(createToast(
            deleted ? "Telegram chat removed" : "Telegram chat already removed",
            "success",
            chat.title,
            targetToastAction("Open", "telegram", { query: chat.title })
          ));
        } catch (error) {
          telegramError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Telegram chat remove failed", "error", telegramError));
        } finally {
          telegramBusy = false;
        }
      }
    };
  }

  function requestFilteredTelegramChatsRemove() {
    const targets = visibleTelegramChats(filteredTelegramChats);
    if (targets.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove filtered Telegram chats?",
      message: `Remove ${targets.length} shown imported Telegram chat${targets.length === 1 ? "" : "s"} from the local manifest index. Media files, download tasks, transfer records, and account state are left untouched.`,
      confirmLabel: "Remove filtered",
      onConfirm: async () => {
        telegramBusy = true;
        try {
          const result = await deleteTelegramChats(targets.map((chat) => chat.id));
          for (const chatId of result.deleted) {
            removeTelegramChatFromState(chatId);
          }
          await loadTelegramSyncStatus();
          await loadTelegramLocalSummary();
          telegramError = "";
          const removed = result.deleted.length;
          const failed = result.failed.length;
          pushToast(createToast(
            "Telegram chats removed",
            "success",
            `${removed} imported chat${removed === 1 ? "" : "s"}${failed > 0 ? `, ${failed} failed` : ""}`,
            targetToastAction("Open", "telegram", { query: targets[0]?.title ?? "" })
          ));
        } catch (error) {
          telegramError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Filtered Telegram chat remove failed", "error", telegramError));
        } finally {
          telegramBusy = false;
        }
      }
    };
  }

