            targetToastAction("Open", "telegram", { query: telegramBrowserSearch })
          )
        );
      }
      telegramError = "";
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram prune failed", "error", telegramError));
