  async function copyTelegramCapabilityCatalogFields(kind: "capability" | "command" | "surface" | "file" | "media-type" | "secret" | "limit" | "note") {
    const lines = kind === "capability"
      ? telegramCapabilityCatalog?.capabilities.map((item) => `${item.capability}: ${item.status} · ${item.scope}`) ?? []
      : kind === "command"
        ? telegramCapabilityCatalog?.capabilities.flatMap((item) => [...item.commands, ...item.cli_aliases].map((command) => `${item.capability}: ${command}`)) ?? []
        : kind === "surface"
          ? telegramCapabilityCatalog?.telegram_surfaces ?? []
          : kind === "file"
            ? telegramCapabilityCatalog?.data_files ?? []
            : kind === "media-type"
              ? telegramCapabilityCatalog?.supported_media_types ?? []
              : kind === "secret"
                ? telegramCapabilityCatalog?.sensitive_fields ?? []
                : kind === "limit"
                  ? telegramCapabilityCatalog?.capabilities.flatMap((item) => item.limitations.map((limitation) => `${item.capability}: ${limitation}`)) ?? []
                  : telegramCapabilityCatalog?.review_notes ?? [];
    await copyLinesToClipboard(lines, "No Telegram capability catalog fields", "Telegram capability catalog fields copied");
  }

