  async function queueTelegramMediaItem(media: TelegramMediaItem) {
    if (media.source_url) {
      await maybeAutoSelectToolsCookieBucket(media.source_url);
      maybeAutoSelectToolsAuthorizationPayload(media.source_url);
    }
    telegramMediaBusy = media.id;
    try {
      const task = await queueTelegramMedia(media.id, buildToolsCreateOptions("telegram_media"));
      if (task) {
        pushToast(createToast("Telegram media queued", "success", task.title, targetToastAction("Task", "downloads", { task_id: task.id })));
        await loadDownloads();
        await loadTelegramSyncStatus();
        await loadTelegramLocalSummary();
      }
      telegramError = "";
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram media queue failed", "error", telegramError));
    } finally {
      telegramMediaBusy = "";
    }
  }

  async function queueTelegramMediaBatch(items: TelegramMediaItem[], label: string) {
    const media = queueableTelegramMedia(items);
    if (media.length === 0) {
      telegramError = "No Telegram media with source URLs matches this view.";
      pushToast(createToast("Telegram batch skipped", "info", telegramError));
      return;
    }

    if (media[0].source_url) {
      await maybeAutoSelectToolsCookieBucket(media[0].source_url);
      maybeAutoSelectToolsAuthorizationPayload(media[0].source_url);
    }
    telegramMediaBusy = label;
    try {
      const result = await queueTelegramMediaItems(
        media.map((item) => item.id),
        toolsOutputDir.trim() || undefined,
        buildToolsCreateOptions("telegram_media")
      );
      if (result.created.length > 0) {
        const createdIds = new Set(result.created.map((task) => task.id));
        downloads = [
          ...result.created,
          ...downloads.filter((candidate) => !createdIds.has(candidate.id))
        ].sort((first, second) => first.position - second.position);
      }
      await loadTelegramSyncStatus();
      await loadTelegramLocalSummary();
      telegramError = "";
      const skippedSummary = result.skipped.length > 0 ? ` · ${result.skipped.length} skipped` : "";
      pushToast(
        createToast(
          "Telegram media queued",
          "success",
          `${result.created.length} task${result.created.length === 1 ? "" : "s"}${skippedSummary}`,
          result.created[0] ? targetToastAction("Task", "downloads", { task_id: result.created[0].id }) : undefined
        )
      );
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram batch queue failed", "error", telegramError));
    } finally {
      telegramMediaBusy = "";
    }
  }

  async function queueTelegramChatMedia(chat: TelegramChat) {
    await queueTelegramMediaBatch(chat.media, `chat:${chat.id}`);
  }

  async function copyTelegramLocalMediaBatch(items: TelegramMediaItem[], label: string) {
    const media = localCopyableTelegramMedia(items);
    if (media.length === 0) {
      telegramError = "No Telegram media with local files matches this view.";
      pushToast(createToast("Telegram local save skipped", "info", telegramError));
      return;
    }
    const outputDir = telegramLocalCopyOutputDir.trim();
    if (!outputDir) {
      telegramError = "Choose a save folder for local Telegram media first.";
      pushToast(createToast("Telegram save folder required", "error", telegramError));
      return;
    }

    telegramMediaBusy = label;
    try {
      const uniqueIds = Array.from(new Set(media.map((item) => item.id)));
      const result = await copyTelegramLocalMedia(uniqueIds, outputDir);
      telegramError = "";
      const skippedSummary = result.skipped.length > 0 ? ` · ${result.skipped.length} skipped` : "";
      const firstOutput = result.copied[0]?.output_path;
      pushToast(
        createToast(
          "Telegram local media saved",
          "success",
          `${result.copied.length} file${result.copied.length === 1 ? "" : "s"} copied${skippedSummary}`,
          firstOutput ? advancedFileToastAction(firstOutput) : undefined
        )
      );
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram local save failed", "error", telegramError));
    } finally {
      telegramMediaBusy = "";
    }
  }

  async function copyTelegramLocalMediaItem(media: TelegramMediaItem) {
    await copyTelegramLocalMediaBatch([media], `${media.id}:copy`);
  }

  async function removeTelegramMediaItem(media: TelegramMediaItem) {
    telegramMediaBusy = `${media.id}:delete`;
    try {
      const response = await deleteTelegramMedia(media.id);
      if (response) {
        telegramChats = response.chats;
        if (telegramPreviewMedia?.id === media.id) {
          telegramPreviewMedia = null;
        }
        if (telegramSearchResults) {
          telegramSearchResults = {
            chats: telegramSearchResults.chats,
            media: telegramSearchResults.media.filter((item) => item.id !== media.id)
          };
        }
        await loadTelegramSyncStatus();
        await loadTelegramLocalSummary();
        pushToast(createToast(
          response.deleted ? "Telegram media removed" : "Telegram media already removed",
          "success",
          media.title,
          targetToastAction("Open", "telegram", { query: media.title, chat_id: media.chat_id })
        ));
      }
      telegramError = "";
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram media remove failed", "error", telegramError));
    } finally {
      telegramMediaBusy = "";
    }
  }

  function requestTelegramMediaBatchRemove(items: TelegramMediaItem[], label: string, busyKey: string) {
    const uniqueItems = Array.from(new Map(items.map((item) => [item.id, item])).values());
    if (uniqueItems.length === 0) {
      return;
    }

    confirmDialog = {
      title: `Remove ${label}?`,
      message: `Remove ${uniqueItems.length} imported Telegram media item${uniqueItems.length === 1 ? "" : "s"} from the local manifest index. Media files, download tasks, transfer records, chats, and account state are left untouched.`,
      confirmLabel: "Remove",
      onConfirm: async () => {
        telegramMediaBusy = busyKey;
        try {
          const response = await deleteTelegramMediaItems(uniqueItems.map((media) => media.id));
          if (response) {
            const ids = new Set(response.deleted);
            telegramChats = response.chats;
            if (telegramPreviewMedia && ids.has(telegramPreviewMedia.id)) {
              telegramPreviewMedia = null;
            }
            if (telegramSearchResults) {
              telegramSearchResults = {
                chats: telegramSearchResults.chats,
                media: telegramSearchResults.media.filter((item) => !ids.has(item.id))
              };
            }
            await loadTelegramSyncStatus();
            await loadTelegramLocalSummary();
            telegramError = "";
            const failedSummary = response.failed.length > 0 ? ` · ${response.failed.length} failed` : "";
            pushToast(createToast(
              "Telegram media removed",
              "success",
              `${response.deleted.length} item${response.deleted.length === 1 ? "" : "s"} removed.${failedSummary}`,
              targetToastAction("Open", "telegram", { query: uniqueItems[0]?.title ?? "", chat_id: uniqueItems[0]?.chat_id ?? "" })
            ));
          }
        } catch (error) {
          telegramError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Telegram media remove failed", "error", telegramError));
        } finally {
          telegramMediaBusy = "";
        }
      }
    };
  }

  function toggleTelegramCloneMediaType(mediaType: TelegramMediaItem["media_type"]) {
    if (telegramCloneMediaTypes.includes(mediaType)) {
      const nextTypes = telegramCloneMediaTypes.filter((item) => item !== mediaType);
      telegramCloneMediaTypes = nextTypes.length > 0 ? nextTypes : [mediaType];
      return;
    }
    telegramCloneMediaTypes = [...telegramCloneMediaTypes, mediaType];
  }

  async function runTelegramCloneWizard() {
    if (!telegramCloneChatId) {
      telegramError = "Choose a Telegram chat first.";
      pushToast(createToast("Telegram clone invalid", "error", telegramError));
      return;
    }
    const parsedLimit = Number.parseInt(telegramCloneLimit, 10);
    const limit = Number.isFinite(parsedLimit) ? Math.max(1, Math.min(500, parsedLimit)) : 100;
    telegramBusy = true;
    telegramError = "";
    try {
      const result = await cloneTelegramChat({
        chatId: telegramCloneChatId,
        outputDir: telegramCloneOutputDir.trim() || undefined,
        mediaTypes: telegramCloneMediaTypes,
        limit,
        options: buildToolsCreateOptions("telegram_media")
      });
      if (result) {
        telegramCloneResult = result;
        telegramCloneLimit = String(limit);
        downloads = await listDownloadTasks();
        await loadTelegramSyncStatus();
        await loadTelegramLocalSummary();
        pushToast(createToast(
          "Telegram clone queued",
          "success",
          `${result.created.length} created · ${result.skipped.length} skipped`,
          targetToastAction("Open", "telegram", { chat_id: result.chat.id })
        ));
      }
    } catch (error) {
      telegramError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Telegram clone failed", "error", telegramError));
    } finally {
