  function telegramPreviewFileKind(media: TelegramMediaItem): "pdf" | "html" | "other" {
    const path = media.local_path?.toLowerCase() ?? "";
    if (path.endsWith(".pdf")) {
      return "pdf";
    }
    if (path.endsWith(".html") || path.endsWith(".htm")) {
      return "html";
    }
    return "other";
  }

