  function requestFilteredPluginStateChange(targetState: "enabled" | "disabled") {
    const targets = filteredPlugins.filter((plugin) => plugin.state !== targetState);
    if (targets.length === 0) {
      return;
    }

    confirmDialog = {
      title: targetState === "enabled" ? "Enable shown plugins?" : "Disable shown plugins?",
      message: `${targetState === "enabled" ? "Enable" : "Disable"} ${targets.length} shown installed plugin${targets.length === 1 ? "" : "s"}. Plugin manifests, settings, data, and marketplace entries are left untouched.`,
      confirmLabel: targetState === "enabled" ? "Enable shown" : "Disable shown",
      onConfirm: async () => {
        pluginActionBusy = targetState === "enabled" ? "enable-filtered" : "disable-filtered";
        try {
          const response = await setPluginsState(targets.map((plugin) => plugin.id), targetState);
          for (const plugin of response.plugins) {
            upsertPlugin(plugin);
          }
          if (targetState === "disabled" && targets.some((plugin) => currentRoute.startsWith(`plugin:${plugin.id}:`))) {
            navigate("plugins");
          }
          pluginsError = "";
          const changed = response.plugins.length;
          const failed = response.failed.length;
          pushToast(createToast(
            targetState === "enabled" ? "Shown plugins enabled" : "Shown plugins disabled",
            "success",
            `${changed} plugin${changed === 1 ? "" : "s"}${failed > 0 ? `, ${failed} failed` : ""}`,
            pluginToastAction(response.plugins[0])
          ));
        } catch (error) {
          pluginsError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Plugin bulk state change failed", "error", pluginsError));
        } finally {
          pluginActionBusy = "";
        }
      }
    };
  }

