  function selectedPluginSettingsSchema(): Record<string, unknown> | null {
    if (!selectedPluginSettings) {
      return null;
    }
    const plugin = selectedPluginForSettings();
    const schema = plugin?.settings_schema;
    return schema && typeof schema === "object" && !Array.isArray(schema)
      ? (schema as Record<string, unknown>)
      : null;
  }

  function selectedPluginForSettings(): PluginInfo | undefined {
    const pluginId = selectedPluginSettings?.id;
    return pluginId ? plugins.find((item) => item.id === pluginId) : undefined;
  }

  function pluginSettingsSchemaFields() {
    const schema = selectedPluginSettingsSchema();
    const properties = schema?.properties;
    if (!properties || typeof properties !== "object" || Array.isArray(properties)) {
      return [];
    }
    return Object.entries(properties as Record<string, unknown>)
      .map(([key, value]) => {
        const field = value && typeof value === "object" && !Array.isArray(value)
          ? (value as Record<string, unknown>)
          : {};
        const rawType = field.type;
        const type = typeof rawType === "string" ? rawType : "string";
        const enumValues = Array.isArray(field.enum)
          ? field.enum.filter((item) => ["string", "number", "boolean"].includes(typeof item))
          : [];
        const supported = ["string", "number", "integer", "boolean", "object", "array"].includes(type) || enumValues.length > 0;
        return {
          key,
          title: typeof field.title === "string" ? field.title : key,
          description: typeof field.description === "string" ? field.description : "",
          type,
          enumValues,
          supported
        };
      })
      .filter((field) => field.supported);
  }

  function pluginSettingValue(key: string): unknown {
    const settings = selectedPluginSettings?.settings;
    if (!settings || typeof settings !== "object" || Array.isArray(settings)) {
      return "";
    }
    return (settings as Record<string, unknown>)[key] ?? "";
  }

  function pluginSettingJsonValue(key: string): string {
    const value = pluginSettingValue(key);
    if (value === "") {
      return "";
    }
    return JSON.stringify(value, null, 2);
  }

  function updatePluginSettingJsonInput(key: string, value: string) {
    const trimmed = value.trim();
    if (!trimmed) {
      updatePluginSettingInput(key, null);
      return;
    }
    try {
      updatePluginSettingInput(key, JSON.parse(trimmed));
      pluginSettingsError = "";
    } catch (error) {
      pluginSettingsError = error instanceof Error ? error.message : String(error);
    }
  }

  function updatePluginSettingInput(key: string, value: unknown) {
    if (!selectedPluginSettings) {
      return;
    }
    const nextSettings = {
      ...(selectedPluginSettings.settings as Record<string, unknown>),
      [key]: value
    };
    selectedPluginSettings = { ...selectedPluginSettings, settings: nextSettings };
    pluginSettingsJsonInput = JSON.stringify(nextSettings, null, 2);
  }

  function formatPluginCommandPayload(pluginId: string) {
    try {
      const parsed = JSON.parse(pluginCommandPayloadInputs[pluginId] || "{}");
      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
        throw new Error("Plugin command payload must be a JSON object.");
      }
      pluginCommandPayloadInputs = {
        ...pluginCommandPayloadInputs,
        [pluginId]: JSON.stringify(parsed, null, 2)
      };
      pluginCommandError = "";
    } catch (error) {
      pluginCommandError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin command payload invalid", "error", pluginCommandError));
    }
  }

  function formatPluginEventPayload(pluginId: string) {
    try {
      const parsed = JSON.parse(pluginEventPayloadInputs[pluginId] || "{}");
      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
        throw new Error("Plugin event payload must be a JSON object.");
      }
      pluginEventPayloadInputs = {
        ...pluginEventPayloadInputs,
        [pluginId]: JSON.stringify(parsed, null, 2)
      };
      pluginEventError = "";
    } catch (error) {
      pluginEventError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin event payload invalid", "error", pluginEventError));
    }
  }

  function reusePluginCommandPayload(plugin: PluginInfo) {
    const entry = pluginCommandLogs[plugin.id]?.commands[0];
    if (!entry) {
      pluginCommandError = "Refresh command logs before reusing a payload.";
      pushToast(createToast("Plugin command payload unavailable", "error", pluginCommandError));
      return;
    }
    pluginCommandInputs = { ...pluginCommandInputs, [plugin.id]: entry.command };
    pluginCommandPayloadInputs = {
      ...pluginCommandPayloadInputs,
      [plugin.id]: JSON.stringify(entry.payload ?? {}, null, 2)
    };
  }

  function reusePluginEventPayload(plugin: PluginInfo) {
    const entry = pluginEventLogs[plugin.id]?.events[0];
    if (!entry) {
      pluginEventError = "Refresh event logs before reusing a payload.";
      pushToast(createToast("Plugin event payload unavailable", "error", pluginEventError));
      return;
    }
    pluginEventInputs = { ...pluginEventInputs, [plugin.id]: entry.event };
    pluginEventPayloadInputs = {
      ...pluginEventPayloadInputs,
      [plugin.id]: JSON.stringify(entry.payload ?? {}, null, 2)
    };
  }

  async function refreshPluginCommandLogs(plugin: PluginInfo, quiet = false) {
    pluginCommandLogBusy = plugin.id;
    try {
      const response = await listPluginCommandLogs(plugin.id, 20);
      if (response) {
