  async function saveSelectedPluginSettings() {
    if (!selectedPluginSettings) {
      return;
    }
    let patch: Record<string, unknown>;
    try {
      const parsed = JSON.parse(pluginSettingsJsonInput || "{}");
      if (!parsed || Array.isArray(parsed) || typeof parsed !== "object") {
        throw new Error("Plugin settings must be a JSON object.");
      }
      patch = parsed as Record<string, unknown>;
    } catch (error) {
      pluginSettingsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin settings invalid", "error", pluginSettingsError));
      return;
    }

    pluginSettingsBusy = selectedPluginSettings.id;
    try {
      const response = await updatePluginSettings(selectedPluginSettings.id, patch);
      selectedPluginSettings = response;
      pluginSettingsJsonInput = JSON.stringify(response?.settings ?? {}, null, 2);
      pluginSettingsError = "";
      pushToast(createToast("Plugin settings saved", "success", response?.id ?? "plugin", pluginToastAction(response?.id)));
    } catch (error) {
      pluginSettingsError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin settings failed", "error", pluginSettingsError));
    } finally {
      pluginSettingsBusy = "";
    }
  }

  async function runManifestPluginCommand(plugin: PluginInfo) {
    const command = (pluginCommandInputs[plugin.id] ?? "").trim();
    if (!command) {
      pluginCommandError = "Choose or enter a plugin command.";
      pushToast(createToast("Plugin command invalid", "error", pluginCommandError));
      return;
    }

    let payload: Record<string, unknown>;
    try {
      const parsed = JSON.parse(pluginCommandPayloadInputs[plugin.id] || "{}");
      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
        throw new Error("Plugin command payload must be a JSON object.");
      }
      payload = parsed as Record<string, unknown>;
    } catch (error) {
      pluginCommandError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin command payload invalid", "error", pluginCommandError));
      return;
    }

    pluginCommandBusy = plugin.id;
    try {
      const response = await runPluginCommand(plugin.id, command, payload);
      lastPluginCommandResult = response;
      pluginCommandError = "";
      await refreshPluginCommandLogs(plugin, true);
      pushToast(createToast("Plugin command queued", "success", response?.message ?? command, pluginToastAction(plugin)));
    } catch (error) {
      pluginCommandError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Plugin command failed", "error", pluginCommandError));
    } finally {
      pluginCommandBusy = "";
    }
  }

