          plugins = plugins.filter((item) => item.id !== plugin.id);
          if (currentRoute.startsWith(`plugin:${plugin.id}:`)) {
            navigate("plugins");
          }
          if (selectedPluginSettings?.id === plugin.id) {
            selectedPluginSettings = null;
            pluginSettingsJsonInput = "{}";
          }
          pluginsError = "";
          pushToast(createToast("Plugin uninstalled", "success", plugin.display_name, targetToastAction("Open", "plugins", { query: plugin.id })));
