          pluginsError = message;
          pushToast(createToast("Plugin uninstall failed", "error", message));
        } finally {
          pluginActionBusy = "";
        }
      }
    };
  }

  function parseExtensionBlockedHosts(value: string): string[] {
    const trimmed = value.trim();
    let source = value;
    if (trimmed.startsWith("[") || trimmed.startsWith("{")) {
      try {
        const parsed = JSON.parse(trimmed) as unknown;
        if (Array.isArray(parsed)) {
          source = parsed.map(String).join("\n");
        } else if (parsed && typeof parsed === "object" && Array.isArray((parsed as { blockedHosts?: unknown }).blockedHosts)) {
          source = (parsed as { blockedHosts: unknown[] }).blockedHosts.map(String).join("\n");
        }
      } catch {
        source = value;
      }
    }
    return source
      .split(/\r?\n|,/)
      .map((host) => host.trim().toLowerCase())
      .filter(Boolean)
      .filter((host, index, hosts) => hosts.indexOf(host) === index);
  }

  function normalizeExtensionBridgeDiscoveryPorts(value: unknown): number[] {
    const rawPorts = Array.isArray(value)
      ? value
      : String(value ?? "")
          .split(/\r?\n|,/)
          .filter(Boolean);
    const ports: number[] = [];
    for (const rawPort of rawPorts) {
      const port = Number(rawPort);
      if (Number.isInteger(port) && port > 0 && port <= 65535 && !ports.includes(port)) {
        ports.push(port);
      }
    }
    return ports.length ? ports : Array.from({ length: 11 }, (_, index) => 17654 + index);
  }

  function buildExtensionConnectorProfileFallback() {
    return {
      schema_version: 1,
      appId: "dev.fetchdock.desktop",
      profileVersion: 1,
      source: "fetchdock-desktop",
      exported_at: new Date().toISOString(),
      defaultBridgePort: 17654,
      bridgeDiscoveryPorts: normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput),
      bridgeBaseUrl: extensionBridgeUrlInput.trim() || extensionOptions?.bridge_url || "http://127.0.0.1:17654",
      pairingToken: extensionPairingToken?.pairing_code ?? extensionTokenInput.trim(),
      tokenExpiresAt: extensionPairingToken?.expires_at ?? extensionPairingStatus?.expires_at ?? null,
      useDeepLinkFallback: extensionDeepLinkFallbackInput,
      mediaSnifferEnabled: extensionCaptureMediaInput,
      headerCaptureEnabled: extensionCaptureHeadersInput,
      blockedHosts: parseExtensionBlockedHosts(extensionBlockedHostsInput),
      privacy: {
        cookie_payload_contents_included: false,
        authorization_payload_contents_included: false
      }
    };
  }

  async function refreshExtensionConnectorProfile(createToken = false, showFeedback = true) {
    extensionOptionsBusy = true;
    extensionPairingError = "";
    try {
      const profile = await getExtensionConnectorProfile({
        token: extensionTokenInput.trim() || undefined,
        createToken,
        label: extensionPairingLabel.trim() || undefined
      });
      const displayProfile = profile
        ? {
            ...profile,
            bridgeDiscoveryPorts: normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput),
            bridgeBaseUrl: extensionBridgeUrlInput.trim() || profile.bridgeBaseUrl,
            useDeepLinkFallback: extensionDeepLinkFallbackInput,
            mediaSnifferEnabled: extensionCaptureMediaInput,
            headerCaptureEnabled: extensionCaptureHeadersInput,
            blockedHosts: parseExtensionBlockedHosts(extensionBlockedHostsInput)
          }
        : buildExtensionConnectorProfileFallback();
      extensionConnectorProfileJson = JSON.stringify(displayProfile, null, 2);
      if (profile?.pairingToken) {
        extensionPairingToken = {
          pairing_code: profile.pairingToken,
          expires_at: profile.tokenExpiresAt ?? extensionPairingToken?.expires_at ?? ""
        };
        await loadExtensionPairingStatus();
      }
      if (showFeedback) {
        pushToast(createToast("Extension profile refreshed", "success", displayProfile.bridgeBaseUrl, targetToastAction("Open", "extension", { kind: "all" })));
      }
    } catch (error) {
      extensionPairingError = error instanceof Error ? error.message : String(error);
      extensionConnectorProfileJson = JSON.stringify(buildExtensionConnectorProfileFallback(), null, 2);
      if (showFeedback) {
        pushToast(createToast("Extension profile preview used local fallback", "warning", extensionPairingError, targetToastAction("Open", "extension", { kind: "all" })));
      }
    } finally {
      extensionOptionsBusy = false;
    }
  }

  async function copyExtensionConnectorProfile() {
    await refreshExtensionConnectorProfile(!extensionPairingStatus?.token_required && !extensionTokenInput.trim(), false);
    const profile = extensionConnectorProfileJson;
    if (!profile) {
      return;
    }
    try {
      if (!navigator.clipboard?.writeText) {
        throw new Error("Clipboard write is not available in this runtime.");
      }
      await navigator.clipboard?.writeText(profile);
      pushToast(createToast("Extension profile copied", "success", "Import this JSON in the extension options page.", targetToastAction("Open", "extension", { kind: "all" })));
    } catch (error) {
      extensionPairingError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Copy failed", "error", extensionPairingError || "Clipboard write was blocked."));
    }
  }

  async function saveExtensionOptionsState() {
    extensionOptionsBusy = true;
    extensionPairingError = "";
    try {
      extensionOptions = await updateExtensionOptions({
        bridgeUrl: extensionBridgeUrlInput.trim() || undefined,
        bridgeDiscoveryPorts: normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput),
        token: extensionTokenInput.trim() || undefined,
        deepLinkFallback: extensionDeepLinkFallbackInput,
        captureMedia: extensionCaptureMediaInput,
        captureHeaders: extensionCaptureHeadersInput,
        blockedHosts: parseExtensionBlockedHosts(extensionBlockedHostsInput)
      });
      if (extensionOptions) {
        extensionBridgeUrlInput = extensionOptions.bridge_url;
        extensionBridgeDiscoveryPortsInput = normalizeExtensionBridgeDiscoveryPorts(
          extensionOptions.bridge_discovery_ports
        ).join(",");
        extensionTokenInput = "";
        extensionDeepLinkFallbackInput = extensionOptions.deep_link_fallback;
        extensionCaptureMediaInput = extensionOptions.capture_media;
        extensionCaptureHeadersInput = extensionOptions.capture_headers;
        extensionBlockedHostsInput = (extensionOptions.blocked_hosts ?? []).join("\n");
      }
      await refreshExtensionLocalSummary(false);
      pushToast(createToast("Extension options saved", "success", extensionOptions?.bridge_url ?? "local bridge", targetToastAction("Open", "extension", { kind: "all" })));
    } catch (error) {
      extensionPairingError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Extension options failed", "error", extensionPairingError));
    } finally {
      extensionOptionsBusy = false;
    }
  }

