  async function importExtensionOptionsBackup() {
    const inputPath = extensionOptionsImportPath.trim();
    if (!inputPath) {
      extensionPairingError = "Choose an extension options JSON backup first.";
      pushToast(createToast("Extension options backup missing", "error", extensionPairingError));
      return;
    }

    extensionOptionsTransferBusy = "import";
    extensionPairingError = "";
    try {
      const result = await importExtensionOptions(inputPath);
      extensionOptionsImportResult = result;
      if (result?.options) {
        syncExtensionOptionsInputs(result.options);
      }
      await Promise.all([
        loadExtensionPairingStatus(),
        refreshExtensionLocalSummary(false),
        refreshExtensionPackageSummary()
      ]);
      pushToast(createToast(
        "Extension options imported",
        "success",
        result ? `${result.imported_setting_count} settings` : "Options restored",
        targetToastAction("Open", "extension", { kind: "all" })
      ));
    } catch (error) {
      extensionPairingError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Extension options import failed", "error", extensionPairingError));
    } finally {
      extensionOptionsTransferBusy = "";
    }
  }

