  function requestFilteredExtensionAuthorizationPayloadsRemove() {
    const payloads = [...filteredExtensionAuthPayloads];
    if (payloads.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove filtered authorization payloads?",
      message: `Remove ${payloads.length} shown staged Authorization header payload${payloads.length === 1 ? "" : "s"}. Download tasks, Cookie buckets, and extension pairing state are left untouched.`,
      confirmLabel: "Remove filtered",
      onConfirm: async () => {
        extensionAuthPayloadBusy = "remove-filtered";
        try {
          const result = await deleteExtensionAuthorizationPayloads(payloads.map((payload) => payload.payload_ref));
          const ids = new Set(result.deleted);
          if (taskAuthPayloadRef && ids.has(taskAuthPayloadRef)) {
            clearTaskAuthorizationPayloadSelection();
          }
          if (toolsAuthPayloadRef && ids.has(toolsAuthPayloadRef)) {
            clearToolsAuthorizationPayloadSelection();
          }
          extensionAuthPayloads = extensionAuthPayloads.filter((payload) => !ids.has(payload.payload_ref));
          extensionPairingError = "";
          const failedSummary = result.failed.length > 0 ? ` · ${result.failed.length} failed` : "";
          pushToast(createToast(
            "Authorization payloads removed",
            "success",
            `${result.deleted.length} payload${result.deleted.length === 1 ? "" : "s"} removed.${failedSummary}`,
            targetToastAction("Open", "extension", { kind: "authorization", query: payloads[0]?.payload_ref ?? "" })
          ));
        } catch (error) {
          extensionPairingError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Authorization payload remove failed", "error", extensionPairingError));
        } finally {
          extensionAuthPayloadBusy = "";
        }
      }
    };
  }

