  async function importExtensionCookiePayload(payload: ExtensionCookiePayloadInfo) {
    const fallbackName = payload.file.file_name.replace(/\.(cookies|txt)$/i, "").trim() || payload.payload_ref;
    extensionCookiePayloadBusy = payload.payload_ref;
    cookieBucketsBusy = true;
    try {
      const bucket = await importCookieBucket({
        name: cookieImportName.trim() || `Extension ${fallbackName}`,
        platform: cookieImportPlatform.trim() || undefined,
        source: { type: "browser_extension", payload_ref: payload.payload_ref }
      });
      if (bucket) {
        cookieImportName = "";
        cookieExtensionPayloadRef = "";
        cookieBucketsError = "";
        extensionPairingError = "";
        pushToast(createToast(
          "Extension cookies imported",
          "success",
          `${bucket.cookie_count} cookie rows; staged payload kept for review.`,
          targetToastAction("Open", "cookies", { bucket_id: bucket.id })
        ));
        await loadCookieBuckets();
        await loadBilibiliImports();
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      cookieBucketsError = message;
      extensionPairingError = message;
      pushToast(createToast("Extension cookie import failed", "error", message, targetToastAction("Open", "extension", { payload_ref: payload.payload_ref, kind: "cookie" })));
    } finally {
      extensionCookiePayloadBusy = "";
      cookieBucketsBusy = false;
    }
  }

  async function importFilteredExtensionCookiePayloads() {
    const payloads = [...filteredExtensionCookiePayloads];
    if (payloads.length === 0) {
      return;
    }

    extensionCookiePayloadBusy = "import-filtered";
    cookieBucketsBusy = true;
    const imported: string[] = [];
    const failed: string[] = [];
    try {
      for (const payload of payloads) {
        const fallbackName = payload.file.file_name.replace(/\.(cookies|txt)$/i, "").trim() || payload.payload_ref;
        try {
          const bucket = await importCookieBucket({
            name: `Extension ${fallbackName}`,
            platform: cookieImportPlatform.trim() || undefined,
            source: { type: "browser_extension", payload_ref: payload.payload_ref }
          });
          if (bucket) {
            imported.push(bucket.id);
          }
        } catch {
          failed.push(payload.payload_ref);
        }
      }
      cookieBucketsError = failed.length > 0 ? `${failed.length} staged payload import failed.` : "";
      extensionPairingError = cookieBucketsError;
      pushToast(createToast(
        "Extension payload import complete",
        failed.length > 0 ? "info" : "success",
        `${imported.length} bucket${imported.length === 1 ? "" : "s"} imported; ${failed.length} failed; staged payloads kept.`,
        targetToastAction("Open", "cookies", { query: imported[0] ?? payloads[0]?.payload_ref ?? "" })
      ));
      await loadCookieBuckets();
      await loadBilibiliImports();
    } finally {
      extensionCookiePayloadBusy = "";
      cookieBucketsBusy = false;
    }
  }

