  async function chooseUpdateManifestFile() {
    if (!isTauriRuntime()) {
      pushToast(createToast("File picker unavailable", "error", "Run the desktop app to choose a local update manifest."));
      return;
    }

    advancedBusy = "choose-update-manifest";
    try {
      const selected = await open({
        title: "Choose local update manifest",
        directory: false,
        multiple: false,
        filters: [{ name: "FetchDock update manifest", extensions: ["json"] }]
      });
      if (typeof selected === "string") {
        updateManifestPathInput = selected;
      }
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Update manifest selection failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  async function checkLocalUpdateManifest() {
    const manifestPath = updateManifestPathInput.trim();
    if (!manifestPath) {
      advancedError = "Update manifest path is required.";
      pushToast(createToast("Update manifest invalid", "error", advancedError));
      return;
    }
    advancedBusy = "update-manifest";
    advancedError = "";
    try {
      updateManifestResult = await checkUpdateManifest(manifestPath);
      updateDueCheckResult = null;
      updateSettings = await updateUpdateSettings({
        manifestPath,
        lastCheckedAt: updateManifestResult?.checked_at ?? new Date().toISOString(),
        lastResult: updateManifestResult?.update_available
          ? `update available: ${updateManifestResult.latest_version ?? "unknown"}`
          : "current"
      });
      await refreshUpdateLocalSummary(false);
      pushToast(createToast(
        updateManifestResult?.update_available ? "Update available" : "No update available",
        updateManifestResult?.update_available ? "success" : "info",
        updateManifestResult?.latest_version ?? "local manifest checked",
        settingsSectionToastAction("advanced")
      ));
    } catch (error) {
      updateManifestResult = null;
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Update manifest failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  async function checkSavedUpdateManifest() {
    advancedBusy = "configured-update-manifest";
    advancedError = "";
    try {
      updateManifestResult = await checkConfiguredUpdateManifest();
      updateDueCheckResult = null;
      updateSettings = await getUpdateSettings();
      if (updateSettings?.manifest_path) {
        updateManifestPathInput = updateSettings.manifest_path;
      }
      await refreshUpdateLocalSummary(false);
      pushToast(createToast(
