        updateManifestResult?.update_available ? "success" : "info",
        updateManifestResult?.latest_version ?? "saved manifest checked",
        settingsSectionToastAction("advanced")
      ));
    } catch (error) {
      updateManifestResult = null;
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Saved update check failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  async function checkDueUpdateManifestNow() {
    advancedBusy = "due-update-manifest";
    advancedError = "";
    try {
      updateDueCheckResult = await checkDueUpdateManifest();
      updateSettings = updateDueCheckResult?.settings ?? await getUpdateSettings();
      updateManifestResult = updateDueCheckResult?.result ?? updateManifestResult;
      if (updateSettings?.manifest_path) {
        updateManifestPathInput = updateSettings.manifest_path;
      }
      await refreshUpdateLocalSummary(false);
      const detail = updateDueCheckResult?.checked
        ? updateDueCheckResult.result?.latest_version ?? "due manifest checked"
        : updateDueCheckResult?.reason ?? updateDueCheckResult?.status ?? "not due";
      pushToast(createToast(
        updateDueCheckResult?.checked ? "Due update checked" : "Due update skipped",
        updateDueCheckResult?.checked ? "success" : "info",
        detail,
        settingsSectionToastAction("advanced")
      ));
    } catch (error) {
      updateDueCheckResult = null;
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Due update check failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  async function saveUpdateSettings() {
    const interval = Number(updateIntervalInput.trim());
    if (!Number.isInteger(interval) || interval < 1 || interval > 168) {
      advancedError = "Update check interval must be a whole number from 1 to 168.";
      pushToast(createToast("Update settings invalid", "error", advancedError));
      return;
    }
    updateSettingsBusy = true;
    advancedError = "";
    try {
      updateSettings = await updateUpdateSettings({
        enabled: updateEnabledInput,
        manifestPath: updateManifestPathInput.trim() || null,
        checkIntervalHours: interval
      });
      if (updateSettings) {
        updateEnabledInput = updateSettings.enabled;
        updateManifestPathInput = updateSettings.manifest_path ?? "";
        updateIntervalInput = String(updateSettings.check_interval_hours);
      }
      await refreshUpdateLocalSummary(false);
      pushToast(createToast("Update settings saved", "success", "Local update preferences stored", settingsSectionToastAction("advanced")));
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Update settings failed", "error", advancedError));
    } finally {
      updateSettingsBusy = false;
    }
  }

