  async function importUpdateSettingsBackup() {
    const inputPath = updateSettingsImportPath.trim();
    if (!inputPath) {
      advancedError = "Choose an update settings JSON backup first.";
      pushToast(createToast("Update settings backup missing", "error", advancedError));
      return;
    }

    updateSettingsBusy = true;
    advancedError = "";
    try {
      const result = await importUpdateSettings(inputPath);
      if (result) {
        updateSettingsImportResult = result;
        updateSettings = result.settings;
        updateEnabledInput = result.settings.enabled;
        updateManifestPathInput = result.settings.manifest_path ?? "";
        updateIntervalInput = String(result.settings.check_interval_hours);
        updateManifestResult = null;
        updateDueCheckResult = null;
        await refreshUpdateLocalSummary(false);
      }
      pushToast(createToast(
        "Update settings imported",
        "success",
        result ? `Interval ${result.settings.check_interval_hours}h` : "Import complete",
        settingsSectionToastAction("advanced")
      ));
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Update settings import failed", "error", advancedError));
    } finally {
      updateSettingsBusy = false;
    }
