  function advancedLogLimitValue() {
    const trimmed = advancedLogLimitInput.trim();
    if (!trimmed) {
      return null;
    }
    const value = Number.parseInt(trimmed, 10);
    return Number.isFinite(value) && value > 0 ? value : null;
  }

  function advancedLogListFilters() {
    return {
      query: advancedFileSearch.trim() || null,
      task_id: advancedLogTaskFilter.trim() || null,
      limit: advancedLogLimitValue()
    };
  }

  async function loadAdvancedFiles() {
    advancedBusy = "refresh";
    try {
      const [diagnostics, logResponse] = await Promise.all([
        listDiagnosticsFiles(),
        listDownloadLogFilesResponse(advancedLogListFilters())
      ]);
      diagnosticsFiles = diagnostics;
      downloadLogFiles = logResponse.logs;
      downloadLogListResponse = logResponse;
      advancedError = "";
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
    } finally {
      advancedBusy = "";
    }
  }

  async function previewAdvancedFile(file: LocalFileSummary, kind: "diagnostics" | "log") {
    advancedBusy = file.path;
    try {
      advancedFilePreview = kind === "diagnostics" ? await readDiagnosticsFile(file.path) : await readDownloadLog(file.path);
      advancedFilePreviewLevelFilter = "all";
      advancedFilePreviewSourceFilter = "all";
      advancedError = "";
      if (advancedFilePreview) {
        pushToast(createToast("File preview loaded", "success", advancedFilePreview.file.file_name, advancedFileToastAction(advancedFilePreview.file.path)));
      }
    } catch (error) {
      advancedFilePreview = null;
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("File preview failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  async function deleteAdvancedFile(file: LocalFileSummary, kind: "diagnostics" | "log") {
    advancedBusy = `delete:${file.path}`;
    try {
      const deleted = kind === "diagnostics"
        ? await deleteDiagnosticsFile(file.path)
        : await deleteDownloadLogFile(file.path);
      if (kind === "diagnostics") {
        diagnosticsFiles = diagnosticsFiles.filter((candidate) => candidate.path !== file.path);
      } else {
        downloadLogFiles = downloadLogFiles.filter((candidate) => candidate.path !== file.path);
      }
      if (advancedFilePreview?.file.path === file.path) {
        advancedFilePreview = null;
      }
      advancedError = "";
      pushToast(createToast(
        deleted ? "Local file deleted" : "Local file already deleted",
        "success",
        file.file_name,
        targetToastAction("Open", "advanced", { kind })
      ));
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Local file delete failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  function requestVisibleAdvancedFilesRemove() {
    const targets = visibleAdvancedFiles(filteredAdvancedFiles);
    if (targets.length === 0) {
      return;
    }

    confirmDialog = {
      title: "Remove shown diagnostics and logs?",
      message: `Remove ${targets.length} shown local diagnostics/log file${targets.length === 1 ? "" : "s"}. Download tasks, outputs, Cookie buckets, plugin data, and settings are left untouched.`,
      confirmLabel: "Remove shown",
      onConfirm: async () => {
        advancedBusy = "delete-filtered";
        try {
          const result = await deleteLocalFiles(targets.map((entry) => ({ kind: entry.kind, path: entry.file.path })));
          const targetPaths = new Set(result.deleted);
          diagnosticsFiles = diagnosticsFiles.filter((file) => !targetPaths.has(file.path));
          downloadLogFiles = downloadLogFiles.filter((file) => !targetPaths.has(file.path));
          if (advancedFilePreview && targetPaths.has(advancedFilePreview.file.path)) {
            advancedFilePreview = null;
          }
          advancedError = "";
          const failedSummary = result.failed.length > 0 ? ` · ${result.failed.length} failed` : "";
          pushToast(createToast(
            "Shown local files removed",
            "success",
            `${result.deleted.length} file${result.deleted.length === 1 ? "" : "s"}${failedSummary}`,
            targetToastAction("Open", "advanced", { kind: targets[0]?.kind ?? "all" })
          ));
        } catch (error) {
          advancedError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Shown local file remove failed", "error", advancedError));
        } finally {
          advancedBusy = "";
        }
      }
    };
  }

  function requestClearAdvancedFiles(kind: "diagnostics" | "log" | "all") {
    const diagnosticCount = kind === "log" ? 0 : diagnosticsFiles.length;
    const logCount = kind === "diagnostics" ? 0 : downloadLogFiles.length;
    confirmDialog = {
      title: kind === "all" ? "Clear diagnostics and logs?" : `Clear ${kind === "diagnostics" ? "diagnostics" : "download logs"}?`,
      message: `Remove ${diagnosticCount} diagnostics JSON file${diagnosticCount === 1 ? "" : "s"} and ${logCount} download log file${logCount === 1 ? "" : "s"}. Download tasks, outputs, Cookie buckets, plugin data, and settings are left untouched.`,
      confirmLabel: "Clear",
      onConfirm: async () => {
        advancedBusy = `clear:${kind}`;
        try {
          let cleared = 0;
          if (kind === "diagnostics" || kind === "all") {
            cleared += await clearDiagnosticsFiles();
            diagnosticsFiles = [];
          }
          if (kind === "log" || kind === "all") {
            cleared += await clearDownloadLogFiles();
            downloadLogFiles = [];
          }
          advancedFilePreview = null;
          advancedError = "";
          pushToast(createToast("Local files cleared", "success", `${cleared} file${cleared === 1 ? "" : "s"}`, targetToastAction("Open", "advanced", { kind })));
        } catch (error) {
          advancedError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Local file clear failed", "error", advancedError));
        } finally {
          advancedBusy = "";
        }
      }
    };
  }

  async function previewPartialDownloadCleanup() {
    advancedBusy = "preview-partials";
    try {
      partialCleanupPreview = await cleanupPartialDownloads(true);
      advancedError = "";
      pushToast(createToast(
        "Partial downloads scanned",
        "success",
        `${partialCleanupPreview.matched} file${partialCleanupPreview.matched === 1 ? "" : "s"}`,
        targetToastAction("Open", "advanced", { query: ".part" })
      ));
    } catch (error) {
      advancedError = error instanceof Error ? error.message : String(error);
      pushToast(createToast("Partial scan failed", "error", advancedError));
    } finally {
      advancedBusy = "";
    }
  }

  function requestPartialDownloadCleanup() {
    const matched = partialCleanupPreview?.matched ?? 0;
    if (matched === 0) {
      void previewPartialDownloadCleanup();
      return;
    }
    confirmDialog = {
      title: "Delete partial downloads?",
      message: `Remove ${matched} .part file${matched === 1 ? "" : "s"} from the local downloads folder.`,
      confirmLabel: "Delete partials",
      onConfirm: async () => {
        advancedBusy = "cleanup-partials";
        try {
          partialCleanupPreview = await cleanupPartialDownloads(false);
          await loadAdvancedFiles();
          advancedError = "";
          pushToast(createToast(
            "Partial downloads deleted",
            "success",
            `${partialCleanupPreview.deleted} removed`,
            targetToastAction("Open", "advanced", { query: ".part" })
          ));
        } catch (error) {
          advancedError = error instanceof Error ? error.message : String(error);
          pushToast(createToast("Partial cleanup failed", "error", advancedError));
        } finally {
          advancedBusy = "";
        }
      }
    };
  }

  function runCommand(command: CommandAction) {
    navigate(command.route as AppRoute);
    if (command.settingsSectionId) {
      tick().then(() => focusSettingsSection(command.settingsSectionId!));
    }
  }

  function routeLabel(route: RouteId): string {
    return translate(appLanguage, `nav.${route}`);
  }
</script>

<svelte:head>
  <title>FetchDock</title>
</svelte:head>

<div class={`app-shell ${appearanceClass}`} style={appearanceStyle}>
  <aside class="sidebar" aria-label={translate(appLanguage, "nav.primary")}>
    <div class="brand">
      <div class="brand-mark">F</div>
      <div>
        <div class="brand-name">FetchDock</div>
        <div class="brand-subtitle">{translate(appLanguage, "brand.subtitle")}</div>
      </div>
    </div>

    <nav class="nav-list">
