          <svelte:component this={item.icon} size={18} strokeWidth={2.1} />
          <span>{routeLabel(item.id)}</span>
        </button>
      {/each}
      {#if enabledPluginNavEntries.length > 0}
        <div class="nav-separator">{translate(appLanguage, "nav.pluginsSection")}</div>
