            <Puzzle size={18} strokeWidth={2.1} />
            <span>{entry.label}</span>
          </button>
        {/each}
      {/if}
    </nav>

    <div class="sidebar-footer">
      <button class="utility-button" type="button" on:click={() => (commandOpen = true)}>
        <Command size={16} />
        <span>{translate(appLanguage, "button.command")}</span>
        <kbd>Ctrl K</kbd>
      </button>
    </div>
  </aside>

  <main class="workspace">
    <header class="topbar">
      <div>
        <p class="eyebrow">Module A</p>
        <h1>{activeTitle}</h1>
      </div>
      <div class="topbar-actions">
        <button class="icon-button" type="button" title={translate(appLanguage, "button.refreshStatus")} on:click={loadStatus}>
          <Monitor size={18} />
        </button>
        <button class="primary-button" type="button" on:click={() => (commandOpen = true)}>
          <Search size={17} />
          <span>{translate(appLanguage, "button.search")}</span>
        </button>
      </div>
    </header>

    {#if currentRoute === "home"}
      <section class="panel hero-panel">
        <div class="panel-copy">
          <p class="eyebrow">Capture entry</p>
          <h2>Collect links and create queued task drafts.</h2>
          <p>
            Deep links, the global shortcut, and manual input now feed the same local queue entry point.
            Metadata probing and active downloader execution remain part of the next modules.
          </p>
          <div class="url-capture">
            <Link2 size={18} />
            <input
