              on:keydown={(event) => event.key === "Enter" && submitHomeUrl()}
            />
            <button
              class="icon-button"
              type="button"
              title="Paste URL from clipboard"
              disabled={captureBusy || clipboardBusy}
              on:click={pasteClipboardUrl}
            >
              <ClipboardPaste size={17} />
            </button>
            <button class="primary-button" type="button" disabled={captureBusy} on:click={submitHomeUrl}>
              Queue
            </button>
          </div>
          <label class="title-hint-row">
            <span>Title hint</span>
            <input bind:value={taskTitleHint} placeholder="Optional task title override" spellcheck="false" />
          </label>
          <div class="mode-segment" aria-label="Download mode">
            <button
              class:active={taskKind === "video"}
