            </label>
            <label class="checkbox-option">
              <input type="checkbox" bind:checked={taskEmbedMetadata} />
              <span>Embed metadata</span>
            </label>
            <label class="checkbox-option">
              <input type="checkbox" bind:checked={taskEmbedThumbnail} />
              <span>Embed thumbnail</span>
            </label>
            <label class="checkbox-option">
              <input type="checkbox" bind:checked={taskSplitChapters} />
              <span>Split chapters</span>
            </label>
            <label class="wide-option">
              <span>yt-dlp args</span>
              <textarea
                bind:value={taskCustomYtdlpArgs}
                placeholder='Example: --match-filter "duration < 3600"'
                spellcheck="false"
