                  {#if metadataPlaylistPreview.entries.length > 8}
                    <div class="course-list-toolbar compact-toolbar">
                      <small>{visibleHomePlaylistEntries(metadataPlaylistPreview.entries).length} shown of {metadataPlaylistPreview.entries.length} probed item{metadataPlaylistPreview.entries.length === 1 ? "" : "s"}</small>
                      <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("playlist")}>
                        Copy URLs
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataSummary}>
                        Copy summary
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                        Copy JSON
                      </button>
                      <button class="small-button" type="button" on:click={() => (homePlaylistEntriesExpanded = !homePlaylistEntriesExpanded)}>
