                      <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("gallery")}>
                        Copy URLs
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataSummary}>
                        Copy summary
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                        Copy JSON
                      </button>
                      <button class="small-button" type="button" on:click={() => (homeGalleryEntriesExpanded = !homeGalleryEntriesExpanded)}>
                        {homeGalleryEntriesExpanded ? "Collapse gallery" : "Show probed gallery"}
                      </button>
                    </div>
                  {:else}
                    <div class="course-list-toolbar compact-toolbar">
                      <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("gallery")}>
                        Copy URLs
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataSummary}>
                        Copy summary
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                        Copy JSON
                      </button>
                    </div>
                  {/if}
                {/if}
              {/if}
