                  </button>
                  <button
                    class="secondary-button compact-button"
                    type="button"
                    disabled={metadataSaveBusy}
                    on:click={saveHomeMetadataInfo}
                  >
                    {metadataSaveBusy ? "Saving" : "Save metadata"}
                  </button>
                  <button
                    class="secondary-button compact-button"
                    type="button"
                    disabled={commentsListBusy}
                    on:click={listHomeComments}
                  >
                    {commentsListBusy ? "Loading" : "List comments"}
                  </button>
                  <button
                    class="secondary-button compact-button"
                    type="button"
                    disabled={commentsSaveBusy}
                    on:click={saveHomeComments}
                  >
                    {commentsSaveBusy ? "Saving" : "Save comments"}
                  </button>
                  <button
                    class="secondary-button compact-button"
                    type="button"
                    disabled={liveChatSaveBusy}
                    on:click={saveHomeLiveChat}
                  >
                    {liveChatSaveBusy ? "Saving" : "Save live chat"}
                  </button>
                </div>
              </div>
              {#if chapterOptions.length > 0}
                <div class="chapter-list">
                  {#each visibleHomeChapters(chapterOptions) as chapter}
                    <div>
                      <strong>{chapter.title ?? "Untitled chapter"}</strong>
                      <small>{formatChapterOption(chapter)}</small>
                    </div>
                  {/each}
                </div>
                {#if chapterOptions.length > 5}
                  <div class="course-list-toolbar compact-toolbar">
                    <small>{visibleHomeChapters(chapterOptions).length} shown of {chapterOptions.length} chapter{chapterOptions.length === 1 ? "" : "s"}</small>
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("chapter")}>
                      Copy chapters
                    </button>
                    <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                      Copy JSON
                    </button>
                    <button class="small-button" type="button" on:click={() => (homeChapterOptionsExpanded = !homeChapterOptionsExpanded)}>
                      {homeChapterOptionsExpanded ? "Collapse chapters" : "Show all chapters"}
                    </button>
                  </div>
                {:else}
                  <div class="course-list-toolbar compact-toolbar">
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("chapter")}>
                      Copy chapters
                    </button>
                    <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                      Copy JSON
                    </button>
                  </div>
                {/if}
              {/if}
              {#if commentOptions.length > 0}
                <div class="comment-list">
                  {#each visibleHomeComments(commentOptions) as comment}
                    <div>
                      <strong>{formatCommentMeta(comment)}</strong>
                      <small>{previewCommentText(comment.text)}</small>
                    </div>
                  {/each}
                </div>
                {#if commentOptions.length > 5}
                  <div class="course-list-toolbar compact-toolbar">
                    <small>{visibleHomeComments(commentOptions).length} shown of {commentOptions.length} comment{commentOptions.length === 1 ? "" : "s"}</small>
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("comment-id")}>
                      Copy ids
                    </button>
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("comment-text")}>
                      Copy text
                    </button>
                    <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                      Copy JSON
                    </button>
                    <button class="small-button" type="button" on:click={() => (homeCommentOptionsExpanded = !homeCommentOptionsExpanded)}>
                      {homeCommentOptionsExpanded ? "Collapse comments" : "Show all comments"}
                    </button>
                  </div>
                {:else}
                  <div class="course-list-toolbar compact-toolbar">
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("comment-id")}>
                      Copy ids
                    </button>
                    <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("comment-text")}>
                      Copy text
                    </button>
                    <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                      Copy JSON
                    </button>
                  </div>
                {/if}
                {#if commentsListUrl}
                  <small class="format-hint">Loaded from {commentsListUrl}</small>
                {/if}
              {/if}
              {#if chapterListError}
                <small class="error-text">{chapterListError}</small>
              {/if}
              {#if chapterSaveError}
                <small class="error-text">{chapterSaveError}</small>
              {/if}
              {#if metadataSaveError}
                <small class="error-text">{metadataSaveError}</small>
              {/if}
              {#if commentsListError}
                <small class="error-text">{commentsListError}</small>
              {/if}
              {#if commentsSaveError}
                <small class="error-text">{commentsSaveError}</small>
              {/if}
              {#if liveChatSaveError}
                <small class="error-text">{liveChatSaveError}</small>
              {/if}
            </div>
            {#if metadataPreview.formats.length > 0}
              <div class="format-list">
                {#each visibleHomeFormats(metadataPreview.formats) as format}
                  <label class:selected={selectedFormatId === format.id}>
                    <input
                      type="radio"
                      name="preview-format"
                      value={format.id}
                      bind:group={selectedFormatId}
                      disabled={!["video", "playlist"].includes(taskKind)}
                    />
                    <strong>{format.id}</strong>
                    <small>{formatPreviewFormat(format)}</small>
                  </label>
                {/each}
              </div>
              {#if metadataPreview.formats.length > 5}
                <div class="course-list-toolbar compact-toolbar">
                  <small>{visibleHomeFormats(metadataPreview.formats).length} shown of {metadataPreview.formats.length} format{metadataPreview.formats.length === 1 ? "" : "s"}</small>
                  <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("format")}>
                    Copy ids
                  </button>
                  <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" on:click={() => (homeFormatOptionsExpanded = !homeFormatOptionsExpanded)}>
                    {homeFormatOptionsExpanded ? "Collapse formats" : "Show all formats"}
                  </button>
                </div>
              {:else}
                <div class="course-list-toolbar compact-toolbar">
                  <button class="small-button" type="button" on:click={() => copyVisibleHomeMetadataFields("format")}>
                    Copy ids
                  </button>
                  <button class="small-button" type="button" on:click={copyVisibleHomeMetadataJson}>
                    Copy JSON
                  </button>
                </div>
              {/if}
              <small class="format-hint">
                {["video", "playlist"].includes(taskKind) && selectedFormatId
                  ? `${taskKind === "playlist" ? "Playlist" : "Video"} downloads will request format ${selectedFormatId}.`
                  : taskKind === "image"
                    ? "Images mode uses gallery-dl and ignores video formats."
                    : ["pdf", "book"].includes(taskKind)
                      ? "Document modes use direct-file downloads when the URL points to a file."
                      : taskKind === "webpage"
                        ? "Webpage mode saves the main HTML and a conservative same-origin asset folder; full offline mirroring is still pending."
                        : "Format selection applies to Video and Playlist modes."}
              </small>
            {/if}
          </div>
        {:else}
          <div class="status-grid">
            {@render StatusTile("Runtime", isTauriRuntime() ? "Tauri" : "Browser")}
            {@render StatusTile("Mode", status?.mode ?? "unknown")}
            {@render StatusTile("Version", status?.app_version ?? "0.1.0")}
            {@render StatusTile("Database", `migration ${status?.database_migration ?? 0}`)}
          </div>
        {/if}
      </section>
    {:else if currentRoute === "downloads"}
      <section class="panel downloads-panel">
        <div class="section-heading">
          <div>
            <h2>Download queue</h2>
            <p>Queued, active, paused, completed, failed, and archived direct-file entries are persisted locally.</p>
          </div>
          <div class="section-actions">
            <button class="secondary-button" type="button" on:click={clearCompleted}>Clear completed</button>
            <button class="secondary-button danger" type="button" disabled={downloadBulkBusy !== "" || archivedDownloadCount === 0} on:click={requestArchivedDownloadsClear}>
              Clear archived
            </button>
            <button class="secondary-button" type="button" on:click={loadDownloads}>Refresh</button>
          </div>
        </div>
        <div class="filter-tabs" aria-label="Download status filters">
          <button
            class:active={downloadViewMode === "active"}
            type="button"
            aria-pressed={downloadViewMode === "active"}
            on:click={() => {
              downloadViewMode = "active";
              if (downloadStatusFilter === "archived") {
                downloadStatusFilter = "all";
              }
            }}
          >
            Queue
          </button>
          <button
            class:active={downloadViewMode === "history"}
            type="button"
            aria-pressed={downloadViewMode === "history"}
            on:click={() => (downloadViewMode = "history")}
          >
            History
          </button>
          <button
            class:active={downloadViewMode === "all"}
            type="button"
            aria-pressed={downloadViewMode === "all"}
            on:click={() => (downloadViewMode = "all")}
          >
            All
          </button>
        </div>
        <div class="filter-tabs" aria-label="Download status filters">
          {#each downloadStatusFilters as filter}
            <button
              class:active={downloadStatusFilter === filter.id}
              type="button"
              on:click={() => (downloadStatusFilter = filter.id)}
            >
              {filter.label}
            </button>
          {/each}
        </div>
        <div class="filter-tabs" aria-label="Download type filters">
          {#each downloadKindFilters as filter}
            <button
              class:active={downloadKindFilter === filter.id}
              type="button"
              on:click={() => (downloadKindFilter = filter.id)}
            >
              {filter.label}
            </button>
          {/each}
        </div>
        <div class="filter-tabs quick-filter-tabs" aria-label="Download quick filters">
          <button type="button" on:click={() => focusDownloadStatus("queued")}>Queued ({queuedDownloadCount})</button>
          <button type="button" on:click={() => focusDownloadStatus("active")}>Active ({activeDownloadCount})</button>
          <button type="button" on:click={() => focusDownloadStatus("failed")}>Failed ({failedDownloadCount})</button>
          <button type="button" on:click={() => focusDownloadOperationalFilter("retryable")}>Retryable ({retryableDownloadCount})</button>
          <button type="button" on:click={() => focusDownloadOperationalFilter("with_output")}>Has output ({outputBackedDownloadCount})</button>
        </div>
        <div class="download-search-row" aria-label="Download search filters">
          <label>
            <span>Platform</span>
            <select bind:value={downloadPlatformFilter} aria-label="Download platform filter">
              {#each downloadPlatformOptions as option}
                <option value={option.id}>{option.label}</option>
              {/each}
            </select>
          </label>
          <label>
            <span>Search</span>
            <input bind:value={downloadSearchQuery} placeholder="Title, URL, output, option, hash, error" spellcheck="false" />
          </label>
          <label>
            <span>Operational</span>
            <select bind:value={downloadOperationalFilter} aria-label="Download operational filter">
              {#each downloadOperationalFilters as option}
                <option value={option.id}>{option.label}</option>
              {/each}
            </select>
          </label>
          <label>
            <span>Date</span>
            <select bind:value={downloadDateField} aria-label="Download date filter field">
              <option value="created">Created</option>
              <option value="updated">Updated</option>
            </select>
          </label>
          <label>
            <span>From</span>
            <input bind:value={downloadDateFrom} type="date" aria-label="Download from date" />
          </label>
          <label>
            <span>To</span>
            <input bind:value={downloadDateTo} type="date" aria-label="Download to date" />
          </label>
          <label>
            <span>Sort</span>
            <select bind:value={downloadSortMode} aria-label="Download sort mode">
              {#each downloadSortModes as option}
                <option value={option.id}>{option.label}</option>
              {/each}
            </select>
          </label>
          {#if downloadsAreFiltered}
            <button
              class="secondary-button compact-button"
              type="button"
              on:click={clearDownloadFilters}
            >
              Clear filters
            </button>
          {/if}
        </div>
        <div class="download-preset-row" aria-label="Download filter presets">
          <label>
            <span>Preset name</span>
            <input bind:value={downloadFilterPresetName} placeholder="Save current filters" spellcheck="false" />
          </label>
          <button class="secondary-button compact-button" type="button" on:click={saveCurrentDownloadFilterPreset}>
            Save preset
          </button>
          <label>
            <span>Saved presets</span>
            <select bind:value={downloadFilterPresetSelection} aria-label="Saved download filter presets">
              <option value="">Choose preset</option>
              {#each downloadFilterPresets as preset}
                <option value={preset.id}>{preset.name}</option>
              {/each}
            </select>
          </label>
          <button
            class="secondary-button compact-button"
            type="button"
            disabled={!downloadFilterPresetSelection}
            on:click={() => applyDownloadFilterPreset(downloadFilterPresetSelection)}
          >
            Apply
          </button>
          <button
            class="small-button"
            type="button"
            disabled={!downloadFilterPresetSelection}
            on:click={deleteSelectedDownloadFilterPreset}
          >
            Remove
          </button>
          <button
            class="small-button"
            type="button"
            disabled={downloadFilterPresets.length === 0}
            on:click={copyDownloadFilterPresetSummary}
          >
            Copy presets
          </button>
          <button
            class="small-button"
            type="button"
            disabled={downloadFilterPresets.length === 0}
            on:click={copyDownloadFilterPresetJson}
          >
            Copy JSON
          </button>
        </div>
        <div class="download-preset-row" aria-label="Download filter preset backup">
          <label>
            <span>Preset export</span>
            <input bind:value={downloadFilterPresetsExportPath} placeholder="fetchdock-download-filter-presets.json" spellcheck="false" />
          </label>
          <button
            class="small-button"
            type="button"
            disabled={Boolean(downloadFilterPresetsTransferBusy)}
            on:click={chooseDownloadFilterPresetsExportPath}
          >
            Choose
          </button>
          <button
            class="secondary-button compact-button"
            type="button"
            disabled={Boolean(downloadFilterPresetsTransferBusy) || downloadFilterPresets.length === 0}
            on:click={exportDownloadFilterPresetBackup}
          >
            {downloadFilterPresetsTransferBusy === "export" ? "Exporting" : "Export"}
          </button>
          <button class="small-button" type="button" disabled={!downloadFilterPresetsExportPath.trim()} on:click={() => openLocalPath(downloadFilterPresetsExportPath, "Download filter preset export")}>
            Open
          </button>
          <button class="small-button" type="button" disabled={!downloadFilterPresetsExportPath.trim()} on:click={() => revealLocalPath(downloadFilterPresetsExportPath, "Download filter preset export")}>
            Reveal
          </button>
          <label>
            <span>Preset import</span>
            <input bind:value={downloadFilterPresetsImportPath} placeholder="Choose preset backup JSON" spellcheck="false" />
          </label>
          <button
            class="small-button"
            type="button"
            disabled={Boolean(downloadFilterPresetsTransferBusy)}
            on:click={chooseDownloadFilterPresetsImportFile}
          >
            Choose
          </button>
          <button
            class="secondary-button compact-button"
            type="button"
            disabled={Boolean(downloadFilterPresetsTransferBusy) || !downloadFilterPresetsImportPath.trim()}
            on:click={importDownloadFilterPresetBackup}
          >
            {downloadFilterPresetsTransferBusy === "import" ? "Importing" : "Import"}
          </button>
          {#if downloadFilterPresetsExportResult}
            <small>{downloadFilterPresetsExportResult.exported_preset_count} preset{downloadFilterPresetsExportResult.exported_preset_count === 1 ? "" : "s"} exported.</small>
          {:else if downloadFilterPresetsImportResult}
            <small>{downloadFilterPresetsImportResult.imported_preset_count} preset{downloadFilterPresetsImportResult.imported_preset_count === 1 ? "" : "s"} imported.</small>
          {:else}
            <small>Backup stores UI filter preset metadata only; it does not include tasks, logs, Cookie/Auth values, or downloaded files.</small>
          {/if}
        </div>
        {#if filteredDownloads.length > 0}
          <div class="download-bulk-row" aria-label="Visible download bulk actions">
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleStartableDownloads.length === 0}
              on:click={() => runBulkDownloadAction("start")}
            >
              Start visible ({visibleStartableDownloads.length})
            </button>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleActiveDownloads.length === 0}
              on:click={() => runBulkDownloadAction("pause")}
            >
              {downloadBulkBusy === "pause" ? "Pausing" : `Pause visible (${visibleActiveDownloads.length})`}
            </button>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visiblePausedDownloads.length === 0}
              on:click={() => runBulkDownloadAction("resume")}
            >
              Resume visible ({visiblePausedDownloads.length})
            </button>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleFailedDownloads.length === 0}
              on:click={() => runBulkDownloadAction("retry")}
            >
              Retry visible ({visibleFailedDownloads.length})
            </button>
            <button
              class="secondary-button compact-button danger"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleCancelableDownloads.length === 0}
              on:click={() => runBulkDownloadAction("cancel")}
            >
              Cancel visible ({visibleCancelableDownloads.length})
            </button>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleArchivableDownloads.length === 0}
              on:click={() => runBulkDownloadAction("archive")}
            >
              Archive visible ({visibleArchivableDownloads.length})
            </button>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={downloadBulkBusy !== "" || visibleRestorableDownloads.length === 0}
              on:click={() => runBulkDownloadAction("restore")}
            >
              Restore visible ({visibleRestorableDownloads.length})
            </button>
            <button
              class="secondary-button compact-button danger"
              type="button"
              disabled={downloadBulkBusy !== "" || filteredDownloads.length === 0}
              on:click={requestVisibleDownloadsDelete}
            >
              {downloadBulkBusy === "delete" ? "Deleting" : `Delete visible (${filteredDownloads.length})`}
            </button>
            <button class="secondary-button compact-button" type="button" on:click={() => copyVisibleDownloadFields("source")}>
              Copy sources
            </button>
            <button class="secondary-button compact-button" type="button" on:click={() => copyVisibleDownloadFields("output")}>
              Copy outputs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={copyVisibleDownloadSummary}>
              Copy summary
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={copyVisibleDownloadJson}>
              Copy JSON
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.output_dir)} on:click={() => copyVisibleDownloadFields("output-dir")}>
              Copy output dirs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("id")}>
              Copy ids
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("title")}>
              Copy titles
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("status")}>
              Copy statuses
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("kind")}>
              Copy kinds
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("platform")}>
              Copy platforms
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("progress")}>
              Copy progress
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.downloaded_bytes)} on:click={() => copyVisibleDownloadFields("downloaded")}>
              Copy downloaded
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.total_bytes)} on:click={() => copyVisibleDownloadFields("size")}>
              Copy sizes
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.speed_bytes_per_sec)} on:click={() => copyVisibleDownloadFields("speed")}>
              Copy speeds
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.eta_seconds)} on:click={() => copyVisibleDownloadFields("eta")}>
              Copy ETAs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.file_count)} on:click={() => copyVisibleDownloadFields("files")}>
              Copy files
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.last_error)} on:click={() => copyVisibleDownloadFields("error")}>
              Copy errors
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.error_category)} on:click={() => copyVisibleDownloadFields("error-category")}>
              Copy error cats
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("retry")}>
              Copy retries
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.cookie_bucket_id)} on:click={() => copyVisibleDownloadFields("cookie")}>
              Copy cookie refs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.auth_payload_ref)} on:click={() => copyVisibleDownloadFields("auth")}>
              Copy auth refs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.thumbnail_url)} on:click={() => copyVisibleDownloadFields("thumbnail-url")}>
              Copy thumb URLs
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.thumbnail_path)} on:click={() => copyVisibleDownloadFields("thumbnail-path")}>
              Copy thumb paths
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.user_agent)} on:click={() => copyVisibleDownloadFields("user-agent")}>
              Copy user agents
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.referer)} on:click={() => copyVisibleDownloadFields("referer")}>
              Copy referers
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.proxy)} on:click={() => copyVisibleDownloadFields("proxy")}>
              Copy proxies
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.rate_limit)} on:click={() => copyVisibleDownloadFields("rate-limit")}>
              Copy rate limits
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.live_from_start !== undefined)} on:click={() => copyVisibleDownloadFields("live")}>
              Copy live
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.run_after_active_slot !== undefined)} on:click={() => copyVisibleDownloadFields("slot")}>
              Copy slot mode
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.concurrent_fragments)} on:click={() => copyVisibleDownloadFields("fragments")}>
              Copy fragments
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.custom_ytdlp_args)} on:click={() => copyVisibleDownloadFields("custom-args")}>
              Copy custom args
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.start_seconds !== null && task.start_seconds !== undefined || task.end_seconds !== null && task.end_seconds !== undefined)} on:click={() => copyVisibleDownloadFields("clip")}>
              Copy clips
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.quality)} on:click={() => copyVisibleDownloadFields("quality")}>
              Copy quality
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.audio_format)} on:click={() => copyVisibleDownloadFields("audio-format")}>
              Copy audio formats
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.subtitles)} on:click={() => copyVisibleDownloadFields("subtitles")}>
              Copy subtitles
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.sponsorblock)} on:click={() => copyVisibleDownloadFields("sponsorblock")}>
              Copy SponsorBlock
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.metadata)} on:click={() => copyVisibleDownloadFields("metadata")}>
              Copy metadata
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some(taskHasIntegrityDetails)} on:click={() => copyVisibleDownloadFields("integrity")}>
              Copy SHA-256
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.started_at)} on:click={() => copyVisibleDownloadFields("started")}>
              Copy started
            </button>
            <button class="secondary-button compact-button" type="button" disabled={!filteredDownloads.some((task) => task.finished_at)} on:click={() => copyVisibleDownloadFields("finished")}>
              Copy finished
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("created")}>
              Copy created
            </button>
            <button class="secondary-button compact-button" type="button" disabled={filteredDownloads.length === 0} on:click={() => copyVisibleDownloadFields("updated")}>
              Copy updated
            </button>
          </div>
        {/if}
        {#if downloadsError}
          <p class="error-text">{downloadsError}</p>
        {:else if downloads.length === 0}
          <div class="empty-state compact">
            <FolderOpen size={34} />
            <h2>No queued links yet</h2>
            <p>Capture or paste a URL from Home to create the first local task draft.</p>
          </div>
        {:else if downloadViewTasks.length === 0}
          <div class="empty-state compact">
            <FolderOpen size={34} />
            <h2>{downloadViewMode === "all" ? "No download tasks yet" : downloadViewMode === "history" ? "No history yet" : "No active queue tasks"}</h2>
            <p>{downloadViewMode === "all" ? "Capture or paste a URL from Home to create the first local task draft." : downloadViewMode === "history" ? "Completed, failed, canceled, and archived tasks will appear here." : "Archived tasks are available from the History or All view."}</p>
          </div>
        {:else if filteredDownloads.length === 0}
          <div class="empty-state compact">
            <FolderOpen size={34} />
            <h2>No matching tasks</h2>
            <p>Change the status filter or refresh the local queue.</p>
          </div>
        {:else}
          <div class="task-list" aria-label="Download task drafts">
            {#each filteredDownloads as task, index}
              <article
                class="task-row"
                class:dragging={draggedDownloadTaskId === task.id}
                class:drag-over={dragOverDownloadTaskId === task.id && draggedDownloadTaskId !== task.id}
                draggable={canDragDownloadTask(task)}
                on:dragstart={(event) => {
                  if (!canDragDownloadTask(task)) {
                    event.preventDefault();
                    return;
                  }
                  draggedDownloadTaskId = task.id;
                  event.dataTransfer?.setData("text/plain", task.id);
                  if (event.dataTransfer) {
                    event.dataTransfer.effectAllowed = "move";
                  }
                }}
                on:dragenter={(event) => {
                  if (draggedDownloadTaskId && canDragDownloadTask(task)) {
                    event.preventDefault();
                    dragOverDownloadTaskId = task.id;
                  }
                }}
                on:dragover={(event) => {
                  if (draggedDownloadTaskId && canDragDownloadTask(task)) {
                    event.preventDefault();
                    if (event.dataTransfer) {
                      event.dataTransfer.dropEffect = "move";
                    }
                    dragOverDownloadTaskId = task.id;
                  }
                }}
                on:dragleave={() => {
                  if (dragOverDownloadTaskId === task.id) {
                    dragOverDownloadTaskId = "";
                  }
                }}
                on:drop|preventDefault={() => dropDownloadTask(task)}
                on:dragend={() => {
                  draggedDownloadTaskId = "";
                  dragOverDownloadTaskId = "";
                }}
              >
                <div class="task-thumbnail" aria-hidden="true">
                  {#if taskThumbnailSrc(task)}
                    <img src={taskThumbnailSrc(task)} alt="" />
                  {:else}
                    <span>{task.kind.slice(0, 1).toUpperCase()}</span>
                  {/if}
                </div>
                <div class="task-main">
                  <strong>{task.title}</strong>
                  <small>{task.source_url}</small>
                  {#if task.output_dir}
                    <small>Output folder {task.output_dir}</small>
                  {/if}
                  {#if task.output_path}
                    <small>Saved to {task.output_path}</small>
                  {/if}
                  {#if taskDetailSummary(task)}
                    <small class="task-detail-summary">{taskDetailSummary(task)}</small>
                  {/if}
                  {#if taskIntegritySummary(task) && taskDetailSummary(task) !== taskIntegritySummary(task)}
                    <small class="task-detail-summary">{taskIntegritySummary(task)}</small>
                  {/if}
                  {#if task.last_error}
                    <small class="error-text">{task.last_error}</small>
                  {/if}
                  {#if task.downloaded_bytes}
                    <small>{formatProgress(task)}</small>
                  {/if}
                  {#if formatTaskFileSummary(task)}
                    <small>{formatTaskFileSummary(task)}</small>
                  {/if}
                  {#if task.speed_bytes_per_sec}
                    <small>
                      {formatBytes(task.speed_bytes_per_sec)}/s · {formatEta(task.eta_seconds)} ·
                      {task.file_count ?? 1} file
                    </small>
                  {/if}
                  {#if task.retry_count > 0}
                    <small>Retry attempts: {task.retry_count}</small>
                  {/if}
                </div>
                <span class="task-chip">{task.kind} · {task.platform}</span>
                <span class="task-status">{task.status}</span>
                <time datetime={task.created_at}>{new Date(task.created_at).toLocaleString()}</time>
                <div class="task-actions">
                  <button
                    class="small-button"
                    type="button"
                    disabled={!downloadsCanReorder || index === 0}
                    on:click={() => moveTask(task, -1)}
                  >
                    Up
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!downloadsCanReorder || index === filteredDownloads.length - 1}
                    on:click={() => moveTask(task, 1)}
                  >
                    Down
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!canStartTask(task) || activeTaskIds.has(task.id)}
                    on:click={() => startTask(task)}
                  >
                    Start
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={task.status !== "active"}
                    on:click={() => pauseTask(task)}
                  >
                    Pause
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={task.status !== "paused"}
                    on:click={() => resumeTask(task)}
                  >
                    Resume
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={task.status !== "failed" && task.status !== "canceled"}
                    on:click={() => retryTask(task)}
                  >
                    Retry
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"}
                    on:click={() => cancelTask(task)}
                  >
                    Cancel
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!task.output_path}
                    on:click={() => revealTaskFile(task)}
                  >
                    <ExternalLink size={13} />
                    Reveal
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!task.output_dir && !task.output_path}
                    on:click={() => openTaskFolder(task)}
                  >
                    <FolderOpen size={13} />
                    Open
                  </button>
                  <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                    Source
                  </button>
                  <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                    <FileText size={13} />
                    Logs
                  </button>
                  {#if task.status === "archived"}
                    <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                  {:else if ["completed", "failed", "canceled"].includes(task.status)}
                    <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                  {/if}
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadDetailBusy === task.id}
                    on:click={() => refreshDownloadTaskDetail(task)}
                  >
                    {downloadDetailBusy === task.id ? "Refreshing" : "Detail"}
                  </button>
                  <button class="small-button danger" type="button" on:click={() => deleteTask(task)}>Delete</button>
                </div>
              </article>
            {/each}
          </div>
          {#if selectedTaskDetail}
            {@const activeSelectedTaskDetail = selectedTaskDetail}
            <aside class="log-panel task-detail-panel">
              <div class="section-heading compact-heading">
                <div>
                  <h2>Task detail</h2>
                  <p>{activeSelectedTaskDetail.id} · {activeSelectedTaskDetail.status} · {activeSelectedTaskDetail.kind}</p>
                </div>
                <div class="inline-actions">
                  <button class="small-button" type="button" on:click={() => copyDownloadTaskSummary(activeSelectedTaskDetail)}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" on:click={() => copyDownloadTaskJson(activeSelectedTaskDetail)}>
                    Copy JSON
                  </button>
                  <button class="icon-button" type="button" title="Close task detail" on:click={() => (selectedTaskDetail = null)}>
                    <X size={18} />
                  </button>
                </div>
              </div>
              <div class="detail-grid">
                <span>
                  <strong>Source</strong>
                  <small>{activeSelectedTaskDetail.source_url}</small>
                  <button class="small-button" type="button" on:click={() => openSourceUrl(activeSelectedTaskDetail.source_url, activeSelectedTaskDetail.title)}>
                    Open source
                  </button>
                </span>
                <span>
                  <strong>Platform</strong>
                  <small>{activeSelectedTaskDetail.platform}</small>
                </span>
                <span>
                  <strong>Created</strong>
                  <small>{new Date(activeSelectedTaskDetail.created_at).toLocaleString()}</small>
                </span>
                <span>
                  <strong>Updated</strong>
                  <small>{new Date(activeSelectedTaskDetail.updated_at).toLocaleString()}</small>
                </span>
                <span>
                  <strong>Progress</strong>
                  <small>{formatProgress(activeSelectedTaskDetail)}</small>
                </span>
                <span>
                  <strong>Output folder</strong>
                  <small>{activeSelectedTaskDetail.output_dir ?? "default"}</small>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!activeSelectedTaskDetail.output_dir && !activeSelectedTaskDetail.output_path}
                    on:click={() => openTaskFolder(activeSelectedTaskDetail)}
                  >
                    Open output
                  </button>
                </span>
                <span>
                  <strong>Output file</strong>
                  <small>{activeSelectedTaskDetail.output_path ?? "not saved yet"}</small>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!activeSelectedTaskDetail.output_path}
                    on:click={() => revealTaskFile(activeSelectedTaskDetail)}
                  >
                    Reveal output
                  </button>
                </span>
                <span>
                  <strong>Network</strong>
                  <small>
                    {[
                      activeSelectedTaskDetail.user_agent ? "user-agent" : null,
                      activeSelectedTaskDetail.referer ? "referer" : null,
                      activeSelectedTaskDetail.proxy ? "proxy" : null,
                      activeSelectedTaskDetail.rate_limit ? `rate ${activeSelectedTaskDetail.rate_limit}` : null
                    ].filter(Boolean).join(" · ") || "defaults"}
                  </small>
                </span>
                <span>
                  <strong>Auth</strong>
                  <small>{activeSelectedTaskDetail.cookie_bucket_id ? `cookie ${activeSelectedTaskDetail.cookie_bucket_id}` : "none"}</small>
                </span>
                <span>
                  <strong>Retry</strong>
                  <small>{activeSelectedTaskDetail.retry_count} attempt{activeSelectedTaskDetail.retry_count === 1 ? "" : "s"}</small>
                </span>
                <span>
                  <strong>Files</strong>
                  <small>{formatTaskFileSummary(activeSelectedTaskDetail) || `${activeSelectedTaskDetail.file_count ?? 0} file(s)`}</small>
                </span>
                {#if taskOptionSummary(activeSelectedTaskDetail)}
                  <span>
                    <strong>Options</strong>
                    <small>{taskOptionSummary(activeSelectedTaskDetail)}</small>
                  </span>
                {/if}
                {#if taskIntegritySummary(activeSelectedTaskDetail)}
                  <span>
                    <strong>Integrity</strong>
                    <small>{taskIntegritySummary(activeSelectedTaskDetail)}</small>
                  </span>
                {/if}
              </div>
              {#if activeSelectedTaskDetail.last_error}
                <p class="error-text">{activeSelectedTaskDetail.last_error}</p>
              {/if}
            </aside>
          {/if}
          {#if selectedTaskId}
            <aside class="log-panel">
              <div class="section-heading compact-heading">
                <div>
                  <h2>Task log</h2>
                  <p>
                    {selectedTaskId} · {visibleSelectedTaskLogs.length} shown · {selectedTaskLogs.length} loaded
                    {downloadLogAppliedSearch.trim()
                      ? ` of ${downloadLogMatchedLines} matching line${downloadLogMatchedLines === 1 ? "" : "s"}`
                      : ` of ${downloadLogTotalLines} line${downloadLogTotalLines === 1 ? "" : "s"}`}
                  </p>
                </div>
                <button class="icon-button" type="button" title="Close logs" on:click={() => {
                  selectedTaskId = "";
                  selectedTaskLogs = [];
                  selectedTaskLogEntries = [];
                  downloadLogLevelFilter = "all";
                  downloadLogSourceFilter = "all";
                }}>
                  <X size={18} />
                </button>
              </div>
              <div class="library-filter-row">
                <input
                  bind:value={downloadLogSearch}
                  placeholder="Search this task log"
                  spellcheck="false"
                  aria-label="Download task log search"
                />
                <button class="small-button" type="button" disabled={logsBusy} on:click={applyDownloadLogSearch}>
                  Search
                </button>
                <button class="small-button" type="button" disabled={logsBusy && !downloadLogAppliedSearch} on:click={() => {
                  downloadLogSearch = "";
                  void applyDownloadLogSearch();
                }}>
                  Reset
                </button>
              </div>
              <div class="log-filter-row">
                <label>
                  <span>Level</span>
                  <select bind:value={downloadLogLevelFilter} aria-label="Download task log level filter">
                    {#each selectedTaskLogLevelOptions as level}
                      <option value={level}>{level}</option>
                    {/each}
                  </select>
                </label>
                <label>
                  <span>Source</span>
                  <select bind:value={downloadLogSourceFilter} aria-label="Download task log source filter">
                    {#each selectedTaskLogSourceOptions as source}
                      <option value={source}>{source}</option>
                    {/each}
                  </select>
                </label>
                <small>{visibleSelectedTaskLogs.length} shown</small>
              </div>
              <div class="course-list-toolbar compact-toolbar">
                <small>{downloadLogAppliedSearch.trim() ? "Matching loaded log lines" : "Loaded log lines"}</small>
                <button class="small-button" type="button" disabled={visibleSelectedTaskLogs.length === 0} on:click={() => copySelectedTaskLog("loaded")}>
                  Copy shown
                </button>
                <button class="small-button" type="button" disabled={filteredSelectedTaskLogEntries.length === 0} on:click={() => copySelectedTaskLog("structured")}>
                  Copy structured
                </button>
                <button class="small-button" type="button" disabled={visibleSelectedTaskLogs.length === 0} on:click={() => copySelectedTaskLog("summary")}>
                  Copy summary
                </button>
                <button
                  class="small-button"
                  type="button"
                  disabled={selectedTaskLogIssueEntries().length === 0}
                  on:click={() => copySelectedTaskLog("issues")}
                >
                  Copy issues
                </button>
                <button class="small-button" type="button" disabled={!selectedTaskLogFile()} on:click={() => openLocalPath(selectedTaskLogFile()?.path, selectedTaskLogFile()?.file_name ?? "Task log")}>
                  Open log
                </button>
                <button class="small-button" type="button" disabled={!selectedTaskLogFile()} on:click={() => revealLocalPath(selectedTaskLogFile()?.path, selectedTaskLogFile()?.file_name ?? "Task log")}>
                  Reveal log
                </button>
              </div>
              {#if logsBusy}
                <p class="muted">Loading log lines.</p>
              {:else if logsError}
                <p class="error-text">{logsError}</p>
              {:else if selectedTaskLogs.length === 0}
                <p class="muted">{downloadLogAppliedSearch.trim() ? "No log lines match the current search." : "No log lines recorded for this task yet."}</p>
              {:else if filteredSelectedTaskLogEntries.length === 0}
                <p class="muted">No loaded log lines match the current level/source filters.</p>
              {:else}
                <div class="log-entry-list">
                  {#each filteredSelectedTaskLogEntries as entry}
                    <div class={`log-entry level-${entry.level}${entry.is_issue ? " issue" : ""}`}>
                      <span>{entry.line_number}</span>
                      <strong>{entry.level}</strong>
                      <small>{entry.source}</small>
                      <code>{entry.message || entry.raw}</code>
                    </div>
                  {/each}
                </div>
                {#if downloadLogNextCursor !== null}
                  <div class="course-list-toolbar compact-toolbar">
                    <small>Next cursor {downloadLogNextCursor}</small>
                    <button class="small-button" type="button" disabled={logsBusy} on:click={() => loadSelectedTaskLogPage()}>
                      Load more
                    </button>
                    <button class="small-button" type="button" disabled={logsBusy} on:click={loadRemainingSelectedTaskLogs}>
                      Load rest
                    </button>
                  </div>
                {/if}
              {/if}
            </aside>
          {/if}
        {/if}
      </section>
    {:else if currentRoute === "channels"}
      <section class="channels-grid">
        <div class="panel">
          <div class="section-heading">
            <div>
              <p class="eyebrow">Module R</p>
              <h2>Channel tracking</h2>
            </div>
            <button class="secondary-button" type="button" disabled={channelsBusy} on:click={loadChannels}>Refresh</button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Add channel</strong>
              <small>Track a channel, profile, playlist, or feed URL for manual checks.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={channelNameInput} placeholder="Channel label" spellcheck="false" aria-label="Channel label" />
              <input bind:value={channelUrlInput} placeholder="https://example.com/channel" spellcheck="false" aria-label="Channel URL" />
              <input bind:value={channelPlatformInput} placeholder="Platform, optional" spellcheck="false" aria-label="Channel platform" />
              <label class="inline-check">
                <input type="checkbox" bind:checked={channelAutoDownloadInput} />
                <span>Auto-download new items later</span>
              </label>
              <button class="secondary-button" type="button" disabled={channelsBusy} on:click={createChannel}>Add channel</button>
            </div>
          </div>
          {#if channelsError}
            <p class="error-text">{channelsError}</p>
          {/if}
        </div>

        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local backup</p>
              <h2>Channel data</h2>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={channelsBusy || Boolean(channelBackupTransferBusy) || filteredChannels.length === 0} on:click={exportVisibleChannels}>
                {channelBackupTransferBusy === "export" ? "Exporting" : "Export shown"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={channelsBusy || Boolean(channelBackupTransferBusy) || !channelBackupImportPath.trim()} on:click={importChannelBackupFile}>
                {channelBackupTransferBusy === "import" ? "Importing" : "Import JSON"}
              </button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Export subscriptions, history, and polling settings</strong>
              <small>Local JSON only; created download tasks, files, and cookies are left outside the backup.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-input-row">
                <input bind:value={channelBackupExportPath} placeholder="Optional export path" spellcheck="false" aria-label="Channels export path" />
                <button class="icon-button" type="button" title="Choose channels export" disabled={channelsBusy || Boolean(channelBackupTransferBusy)} on:click={chooseChannelBackupExportPath}>
                  <FolderOpen size={16} />
                </button>
              </div>
              <div class="path-input-row">
                <input bind:value={channelBackupImportPath} placeholder="Channels JSON to import" spellcheck="false" aria-label="Channels import path" />
                <button class="icon-button" type="button" title="Choose channels JSON" disabled={channelsBusy || Boolean(channelBackupTransferBusy)} on:click={chooseChannelBackupImportFile}>
                  <FileText size={16} />
                </button>
              </div>
              {#if channelBackupExportResult}
                <div class="section-actions">
                  <button class="small-button" type="button" on:click={openChannelBackupExportResult}>Open export</button>
                  <button class="small-button" type="button" on:click={revealChannelBackupExportResult}>Reveal export</button>
                </div>
              {/if}
            </div>
          </div>
        </div>


        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local capabilities</p>
              <h2>Channel capability catalog</h2>
              <p>
                {channelsCapabilityCatalog
                  ? `${channelsCapabilityCatalog.capability_count} capabilities · generated ${channelsCapabilityCatalog.generated_at}`
                  : "Review local channel store, history, polling, notification, backup, and queue-link metadata without polling remote sources."}
              </p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={channelLocalSummaryBusy} on:click={refreshChannelsCapabilityCatalog}>
                {channelLocalSummaryBusy ? "Refreshing" : "Refresh catalog"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={channelLocalSummaryBusy} on:click={exportChannelsCapabilityCatalogFile}>
                {channelLocalSummaryBusy ? "Exporting" : "Export catalog"}
              </button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Subscriptions, checks, history, notifications, and safe exports</strong>
              <small>Metadata-only catalog; it does not poll feeds, queue tasks, include source URL values, expose Cookie values, or read downloaded files.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-input-row">
                <input bind:value={channelsCapabilityCatalogExportPath} placeholder="Optional catalog export path" spellcheck="false" aria-label="Channels capability catalog export path" />
              </div>
              <div class="section-actions">
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={copyChannelsCapabilityCatalogSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={copyChannelsCapabilityCatalogJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={() => copyChannelsCapabilityCatalogFields("capability")}>Copy capabilities</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={() => copyChannelsCapabilityCatalogFields("command")}>Copy commands</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={() => copyChannelsCapabilityCatalogFields("event")}>Copy events</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalog} on:click={() => copyChannelsCapabilityCatalogFields("limit")}>Copy limits</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalogExportResult && !channelsCapabilityCatalogExportPath.trim()} on:click={() => openLocalPath(channelsCapabilityCatalogExportResult || channelsCapabilityCatalogExportPath, "Channels capability catalog")}>Open export</button>
                <button class="small-button" type="button" disabled={!channelsCapabilityCatalogExportResult && !channelsCapabilityCatalogExportPath.trim()} on:click={() => revealLocalPath(channelsCapabilityCatalogExportResult || channelsCapabilityCatalogExportPath, "Channels capability catalog")}>Reveal export</button>
              </div>
              {#if channelsCapabilityCatalog}
                <div class="metric-grid compact-metrics">
                  <span><strong>{channelsCapabilityCatalog.capability_count}</strong><small>capabilities</small></span>
                  <span><strong>{channelsCapabilityCatalog.event_names.length}</strong><small>events</small></span>
                  <span><strong>{channelsCapabilityCatalog.supported_status_filters.length}</strong><small>filters</small></span>
                  <span><strong>{channelsCapabilityCatalog.verifies_remote_feeds ? "yes" : "pending"}</strong><small>remote feeds</small></span>
                </div>
                <div class="compact-list">
                  {#each channelsCapabilityCatalog.capabilities as item}
                    <small><strong>{item.label}</strong> · {item.status} · {item.scope}</small>
                  {/each}
                </div>
              {/if}
            </div>
          </div>
        </div>


        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local summary</p>
              <h2>Channel overview</h2>
              <p>
                {localChannelsSummary
                  ? `${localChannelsSummary.channel_count} channels · ${localChannelsSummary.history_count} history · generated ${localChannelsSummary.generated_at}`
                  : "Read local channel metadata without polling remote sources or exporting credentials."}
              </p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={channelLocalSummaryBusy} on:click={refreshChannelsLocalSummary}>
                {channelLocalSummaryBusy ? "Refreshing" : "Refresh summary"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={channelLocalSummaryBusy} on:click={exportChannelsSummary}>
                {channelLocalSummaryBusy ? "Exporting" : "Export summary"}
              </button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Subscriptions, history, notifications, and polling settings</strong>
              <small>Metadata-only JSON; it does not run checks, create tasks, include downloaded files, or expose Cookie values.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-input-row">
                <input bind:value={channelLocalSummaryExportPath} placeholder="Optional summary export path" spellcheck="false" aria-label="Channels summary export path" />
                <button class="icon-button" type="button" title="Choose channels summary export" disabled={channelLocalSummaryBusy} on:click={chooseChannelsSummaryExportPath}>
                  <FolderOpen size={16} />
                </button>
              </div>
              <div class="section-actions">
                <button class="small-button" type="button" disabled={!localChannelsSummary} on:click={copyChannelsLocalSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!localChannelsSummary} on:click={copyChannelsLocalSummaryJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={(localChannelsSummary?.platform_counts.length ?? 0) === 0} on:click={() => copyChannelsLocalSummaryFields("platform")}>Copy platforms</button>
                <button class="small-button" type="button" disabled={(localChannelsSummary?.source_kind_counts.length ?? 0) === 0} on:click={() => copyChannelsLocalSummaryFields("source-kind")}>Copy history kinds</button>
                <button class="small-button" type="button" disabled={!channelLocalSummaryExportResult && !channelLocalSummaryExportPath.trim()} on:click={() => openLocalPath(channelLocalSummaryExportResult || channelLocalSummaryExportPath, "Channels summary")}>Open export</button>
                <button class="small-button" type="button" disabled={!channelLocalSummaryExportResult && !channelLocalSummaryExportPath.trim()} on:click={() => revealLocalPath(channelLocalSummaryExportResult || channelLocalSummaryExportPath, "Channels summary")}>Reveal export</button>
              </div>
              {#if localChannelsSummary}
                <div class="metric-grid compact-metrics">
                  <span><strong>{localChannelsSummary.enabled_count}</strong><small>enabled</small></span>
                  <span><strong>{localChannelsSummary.auto_download_count}</strong><small>auto-download</small></span>
                  <span><strong>{localChannelsSummary.queued_history_count}</strong><small>queued history</small></span>
                  <span><strong>{localChannelsSummary.notification_pending_count}</strong><small>pending notifications</small></span>
                </div>
              {/if}
            </div>
          </div>
        </div>


        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Polling</p>
              <h2>Auto checks</h2>
            </div>
            <button class="secondary-button compact-button" type="button" disabled={channelSettingsBusy} on:click={runDueChannelPoll}>
              {channelSettingsBusy ? "Checking" : "Poll due"}
            </button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Polling interval</strong>
              <small>{channelSettings?.last_poll_finished_at ? `Last poll ${channelSettings.last_poll_finished_at}` : "No automatic poll recorded."}</small>
              <small>{channelSettings?.auto_poll_enabled ? `Local timer active · ${channelAutoPollSummary || "waiting for due interval"}` : "Local timer disabled."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <label class="inline-check">
                <input type="checkbox" bind:checked={channelPollEnabledInput} />
                <span>Enable local polling</span>
              </label>
              <input bind:value={channelPollIntervalInput} inputmode="numeric" aria-label="Channel polling interval minutes" />
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={channelSettingsBusy} on:click={saveChannelPollingSettings}>Save polling</button>
                <button class="small-button" type="button" disabled={channelSettingsBusy} on:click={resetChannelSettings}>Reset</button>
              </div>
            </div>
          </div>
          {#if channelSettings?.last_error}
            <p class="error-text">{channelSettings.last_error}</p>
          {/if}
        </div>

        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Tracked channels</h2>
              <p>{filteredChannels.length} shown of {channels.length} tracked channel{channels.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelUrls("subscriptions")}>
                Copy URLs
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={copyVisibleChannelSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={copyVisibleChannelJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("id")}>
                Copy ids
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("name")}>
                Copy names
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("platform")}>
                Copy platforms
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("auto")}>
                Copy auto states
              </button>
              <button class="small-button" type="button" disabled={!filteredChannels.some((channel) => channel.last_checked_at)} on:click={() => copyVisibleChannelFields("checked")}>
                Copy checked
              </button>
              <button class="small-button" type="button" disabled={!filteredChannels.some((channel) => channel.last_error)} on:click={() => copyVisibleChannelFields("error")}>
                Copy errors
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("created")}>
                Copy created
              </button>
              <button class="small-button" type="button" disabled={filteredChannels.length === 0} on:click={() => copyVisibleChannelFields("updated")}>
                Copy updated
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={channelsBusy || filteredChannels.length === 0} on:click={requestFilteredChannelsRemove}>
                Remove filtered
              </button>
              <button class="small-button danger" type="button" disabled={channelsBusy || channels.length === 0} on:click={requestChannelsClear}>
                Clear channels
              </button>
            </div>
          </div>
          <div class="library-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={channelSearchQuery} placeholder="Name, URL, platform, error" spellcheck="false" />
            </label>
            <label>
              <span>Auto-download</span>
              <select bind:value={channelAutoDownloadFilter} aria-label="Channel auto-download filter">
                <option value="all">All channels</option>
                <option value="enabled">Auto-download enabled</option>
                <option value="disabled">Manual only</option>
                <option value="errors">With errors</option>
              </select>
            </label>
          </div>
          <div class="channel-list">
            {#if channels.length === 0}
              <p class="muted">No channels are tracked yet.</p>
            {:else if filteredChannels.length === 0}
              <p class="muted">No tracked channels match the current filters.</p>
            {:else}
              {#each filteredChannels as channel}
                <article class="channel-card">
                  <div>
                    <strong>{channel.name}</strong>
                    <small>{channel.platform} · {channel.source_url}</small>
                    <small>{channel.last_checked_at ? `Checked ${channel.last_checked_at}` : "Not checked yet"}</small>
                    {#if channel.last_error}
                      <small class="error-text">{channel.last_error}</small>
                    {/if}
                  </div>
                  <div class="section-actions">
                    <button class="small-button" type="button" on:click={() => openSourceUrl(channel.source_url, channel.name)}>
                      Open source
                    </button>
                    <button class="secondary-button" type="button" disabled={channelCheckBusy === channel.id} on:click={() => checkChannel(channel)}>
                      {channelCheckBusy === channel.id ? "Checking" : "Check now"}
                    </button>
                    <button class="small-button danger" type="button" on:click={() => requestChannelRemove(channel)}>Remove</button>
                  </div>
                </article>
              {/each}
            {/if}
          </div>
        </div>

        <div class="panel channels-history-panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Channel history</h2>
              <p>{filteredChannelHistory.length} shown of {channelHistory.length} local check result{channelHistory.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={filteredChannelHistory.length === 0} on:click={() => copyVisibleChannelUrls("history")}>
                Copy URLs
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={copyVisibleChannelHistorySummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={copyVisibleChannelHistoryJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={() => copyVisibleChannelFields("history-title")}>
                Copy titles
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={() => copyVisibleChannelFields("history-id")}>
                Copy ids
              </button>
              <button class="small-button" type="button" disabled={!visibleChannelHistoryItems(filteredChannelHistory).some((item) => item.author)} on:click={() => copyVisibleChannelFields("history-author")}>
                Copy authors
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={() => copyVisibleChannelFields("history-kind")}>
                Copy source kinds
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={() => copyVisibleChannelFields("history-notification")}>
                Copy notifications
              </button>
              <button class="small-button" type="button" disabled={visibleChannelHistoryItems(filteredChannelHistory).length === 0} on:click={() => copyVisibleChannelFields("history-checked")}>
                Copy checked
              </button>
              <button class="small-button" type="button" disabled={!visibleChannelHistoryItems(filteredChannelHistory).some((item) => item.error)} on:click={() => copyVisibleChannelFields("history-error")}>
                Copy errors
              </button>
              <button class="small-button" type="button" disabled={!visibleChannelHistoryItems(filteredChannelHistory).some((item) => item.dedupe_key)} on:click={() => copyVisibleChannelFields("history-dedupe")}>
                Copy dedupe
              </button>
              <button class="small-button" type="button" disabled={!visibleChannelHistoryItems(filteredChannelHistory).some((item) => item.created_task_id)} on:click={() => copyVisibleChannelFields("history-task")}>
                Copy task ids
              </button>
              <button class="secondary-button compact-button" type="button" disabled={channelsBusy || queueableChannelHistoryItems(filteredChannelHistory).length === 0 || channelNotificationBusy === "queue-filtered"} on:click={queueFilteredChannelHistoryDownloads}>
                {channelNotificationBusy === "queue-filtered" ? "Queueing" : "Queue filtered"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={channelsBusy || visiblePendingChannelNotifications.length === 0 || channelNotificationBusy === "mark-visible"} on:click={markVisibleChannelNotificationsShown}>
                {channelNotificationBusy === "mark-visible" ? "Marking" : "Mark shown"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={channelsBusy || visibleChannelHistoryItems(filteredChannelHistory).length === 0 || channelNotificationBusy === "delete-filtered"} on:click={requestFilteredChannelHistoryDelete}>
                {channelNotificationBusy === "delete-filtered" ? "Removing" : "Remove filtered"}
              </button>
              <button class="small-button danger" type="button" disabled={channelsBusy || channelHistory.length === 0} on:click={requestChannelHistoryClear}>
                Clear history
              </button>
            </div>
          </div>
          <div class="library-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={channelHistorySearch} placeholder="Title, author, URL, task, error" spellcheck="false" />
            </label>
            <label>
              <span>Status</span>
              <select bind:value={channelHistoryStatusFilter} aria-label="Channel history status filter">
                <option value="all">All history</option>
                <option value="pending">Pending notification</option>
                <option value="queued">Queued task</option>
                <option value="ready">Ready to queue</option>
                <option value="error">Errors</option>
              </select>
            </label>
          </div>
          <div class="filter-tabs quick-filter-tabs" aria-label="Channel history quick filters">
            <button type="button" on:click={() => setChannelHistoryQuickStatus("pending")}>Pending</button>
            <button type="button" on:click={() => setChannelHistoryQuickStatus("queued")}>Queued</button>
            <button type="button" on:click={() => setChannelHistoryQuickStatus("ready")}>Ready</button>
            <button type="button" on:click={() => setChannelHistoryQuickStatus("error")}>Errors</button>
            <button type="button" on:click={() => setChannelHistoryQuickStatus("all")}>All</button>
          </div>
          <div class="channel-list">
            {#if channelHistory.length === 0}
              <p class="muted">Manual checks will appear here.</p>
            {:else if filteredChannelHistory.length === 0}
              <p class="muted">No channel history items match the current filters.</p>
            {:else}
              <div class="course-list-toolbar">
                <small>
                  Showing {visibleChannelHistoryItems(filteredChannelHistory).length} of {filteredChannelHistory.length} matching history item{filteredChannelHistory.length === 1 ? "" : "s"}
                </small>
                {#if filteredChannelHistory.length > 20 && !channelHistorySearch.trim() && channelHistoryStatusFilter === "all"}
                  <button class="small-button" type="button" on:click={() => (channelHistoryExpanded = !channelHistoryExpanded)}>
                    {channelHistoryExpanded ? "Collapse history" : "Show all history"}
                  </button>
                {/if}
              </div>
              {#each visibleChannelHistoryItems(filteredChannelHistory) as item}
                <article class="channel-card compact-card">
                  <div>
                    <strong>{item.title}</strong>
                    <small>{item.author ?? "Unknown author"} · {item.checked_at}</small>
                    <small>{item.source_url}</small>
                    {#if item.source_kind}
                      <small>Source {item.source_kind.replaceAll("_", " ")}</small>
                    {/if}
                    {#if item.created_task_id}
                      <small>Created task {item.created_task_id}</small>
                    {/if}
                    {#if item.notification_status && item.notification_status !== "none"}
                      <small>Notification {item.notification_status}</small>
                    {/if}
                    {#if item.error}
                      <small class="error-text">{item.error}</small>
                    {/if}
                  </div>
                  <div class="section-actions">
                    <button class="small-button" type="button" on:click={() => openSourceUrl(item.source_url, item.title)}>
                      Open source
                    </button>
                    {#if item.created_task_id}
                      {@const createdTaskId = item.created_task_id}
                      <button class="small-button" type="button" on:click={() => focusDownloadTaskById(createdTaskId, item.title)}>
                        Task
                      </button>
                    {/if}
                    {#if !item.error}
                      <button
                        class="small-button"
                        type="button"
                        disabled={channelNotificationBusy === `${item.id}:queue`}
                        on:click={() => queueChannelHistoryDownload(item)}
                      >
                        {channelNotificationBusy === `${item.id}:queue` ? "Queueing" : item.created_task_id ? "Queue again" : "Queue"}
                      </button>
                    {/if}
                    {#if item.notification_status === "pending"}
                      <button
                        class="small-button"
                        type="button"
                        disabled={channelNotificationBusy === item.id}
                        on:click={() => markChannelHistoryNotificationShown(item)}
                      >
                        {channelNotificationBusy === item.id ? "Marking" : "Mark shown"}
                      </button>
                    {/if}
                    <button
                      class="small-button danger"
                      type="button"
                      disabled={channelNotificationBusy === `${item.id}:delete`}
                      on:click={() => requestChannelHistoryDelete(item)}
                    >
                      {channelNotificationBusy === `${item.id}:delete` ? "Removing" : "Remove"}
                    </button>
                  </div>
                </article>
              {/each}
            {/if}
          </div>
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local transfers</p>
              <h2>Channel transfers</h2>
            </div>
            <button class="secondary-button compact-button" type="button" on:click={loadDownloads}>Refresh</button>
          </div>
          <div class="library-filter-row transfer-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={channelTransferSearch} placeholder="Title, URL, platform, output path, or error" spellcheck="false" aria-label="Channel transfer search" />
            </label>
            <label>
              <span>Status</span>
              <select bind:value={channelTransferStatusFilter} aria-label="Channel transfer status filter">
                <option value="all">All status</option>
                <option value="queued">Queued</option>
                <option value="active">Active</option>
                <option value="paused">Paused</option>
                <option value="completed">Completed</option>
                <option value="failed">Failed</option>
                <option value="canceled">Canceled</option>
                <option value="archived">Archived</option>
              </select>
            </label>
          </div>
          {#if channelTransferTasks.length === 0}
            <p class="muted">Queued channel history downloads will appear here after manual checks or auto-download create local tasks.</p>
          {:else if filteredChannelTransferTasks.length === 0}
            <p class="muted">No channel transfers match the current filters.</p>
          {:else}
            <div class="course-list-toolbar">
              <small class="format-hint">
                {visibleChannelTransferTasks(filteredChannelTransferTasks).length} shown of {channelTransferTasks.length} local channel transfer task{channelTransferTasks.length === 1 ? "" : "s"}.
              </small>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskSummary(visibleChannelTransferTasks(filteredChannelTransferTasks), "Channel transfer")}>
                Copy summary
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskJson(visibleChannelTransferTasks(filteredChannelTransferTasks), "Channel transfer", { search: channelTransferSearch, status: channelTransferStatusFilter })}>
                Copy JSON
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleChannelTransferTasks(filteredChannelTransferTasks), "source", "Channel transfer")}>
                Copy sources
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleChannelTransferTasks(filteredChannelTransferTasks), "output", "Channel transfer")}>
                Copy outputs
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferStartableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("start", visibleChannelTransferStartableTasks, "Channel transfers")}
              >
                Start shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferActiveTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("pause", visibleChannelTransferActiveTasks, "Channel transfers")}
              >
                Pause shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferPausedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("resume", visibleChannelTransferPausedTasks, "Channel transfers")}
              >
                Resume shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferFailedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("retry", visibleChannelTransferFailedTasks, "Channel transfers")}
              >
                Retry shown
              </button>
              <button
                class="small-button danger"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferCancelableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("cancel", visibleChannelTransferCancelableTasks, "Channel transfers")}
              >
                Cancel shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferArchivableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("archive", visibleChannelTransferArchivableTasks, "Channel transfers")}
              >
                Archive shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleChannelTransferRestorableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("restore", visibleChannelTransferRestorableTasks, "Channel transfers")}
              >
                Restore shown
              </button>
              {#if filteredChannelTransferTasks.length > 10 && !channelTransferSearch.trim() && channelTransferStatusFilter === "all"}
                <button class="small-button" type="button" on:click={() => (channelTransfersExpanded = !channelTransfersExpanded)}>
                  {channelTransfersExpanded ? "Collapse transfers" : "Show all transfers"}
                </button>
              {/if}
            </div>
            <div class="telegram-media-list transfer-task-list">
              {#each visibleChannelTransferTasks(filteredChannelTransferTasks) as task}
                <div>
                  <span>
                    <strong>{task.title}</strong>
                    <small>{task.status} · {formatProgress(task)}</small>
                    <small>{task.platform} · {task.source_url}</small>
                    {#if task.output_path}
                      <small>Saved to {task.output_path}</small>
                    {:else if task.output_dir}
                      <small>Output folder {task.output_dir}</small>
                    {/if}
                    {#if task.last_error}
                      <small class="error-text">{task.last_error}</small>
                    {/if}
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" disabled={!canStartTask(task) || activeTaskIds.has(task.id)} on:click={() => startTask(task)}>
                      Start
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "active"} on:click={() => pauseTask(task)}>
                      Pause
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "paused"} on:click={() => resumeTask(task)}>
                      Resume
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "failed" && task.status !== "canceled"} on:click={() => retryTask(task)}>
                      Retry
                    </button>
                    <button class="small-button" type="button" disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"} on:click={() => cancelTask(task)}>
                      Cancel
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_path} on:click={() => revealTaskFile(task)}>
                      Reveal
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_dir && !task.output_path} on:click={() => openTaskFolder(task)}>
                      Open
                    </button>
                    <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                      Source
                    </button>
                    <button class="small-button" type="button" on:click={() => focusDownloadTaskById(task.id, task.title)}>
                      Detail
                    </button>
                    <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                      Logs
                    </button>
                    {#if task.status === "archived"}
                      <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                    {:else if ["completed", "failed", "canceled"].includes(task.status)}
                      <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                    {/if}
                  </div>
                </div>
              {/each}
            </div>
          {/if}
        </div>
      </section>
    {:else if currentRoute === "courses"}
      <section class="channels-grid">
        <div class="panel">
          <div class="section-heading">
            <div>
              <p class="eyebrow">Module H</p>
              <h2>Courses</h2>
            </div>
            <button class="secondary-button" type="button" disabled={coursesBusy} on:click={loadCourses}>Refresh</button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Course URL</strong>
              <small>Probe or save a course candidate before real lesson extraction is wired.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={courseUrlInput} placeholder="https://course.example.com/..." spellcheck="false" aria-label="Course URL" />
              <input bind:value={courseTitleInput} placeholder="Title hint, optional" spellcheck="false" aria-label="Course title hint" />
              <select bind:value={courseImportCookieBucketId} aria-label="Course cookie account">
                <option value="">No cookie bucket</option>
                {#each cookieBuckets as bucket}
                  <option value={bucket.id}>{bucket.name} · {bucket.health}</option>
                {/each}
              </select>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={runCourseProbe}>Probe</button>
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={saveCourseCandidate}>Import candidate</button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Local manifest</strong>
              <small>Import a FetchDock JSON course outline with lessons and attachments.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={courseManifestPathInput} placeholder="C:/Courses/course.fetchdock.json" spellcheck="false" aria-label="Course manifest path" />
                <button class="icon-button" type="button" title="Choose course manifest" disabled={coursesBusy} on:click={chooseCourseManifestFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!courseManifestPathInput.trim()} on:click={() => openLocalPath(courseManifestPathInput, "Course manifest")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!courseManifestPathInput.trim()} on:click={() => revealLocalPath(courseManifestPathInput, "Course manifest")}>
                  Reveal
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={courseManifestExportPath} placeholder="Optional export path" spellcheck="false" aria-label="Course manifest export path" />
                <button class="icon-button" type="button" title="Choose course export" disabled={coursesBusy} on:click={chooseCourseManifestExportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!courseManifestExportResult && !courseManifestExportPath.trim()} on:click={openCourseManifestExportResult}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!courseManifestExportResult && !courseManifestExportPath.trim()} on:click={revealCourseManifestExportResult}>
                  Reveal export
                </button>
              </div>
              {#if courseManifestExportResult}
                <small>{courseManifestExportResult.exported_count} course{courseManifestExportResult.exported_count === 1 ? "" : "s"} exported · {courseManifestExportResult.output_path}</small>
              {/if}
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={importLocalCourseManifest}>Import manifest</button>
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={importLocalCourseManifestBundle}>Import bundle</button>
                <button class="secondary-button" type="button" disabled={coursesBusy || filteredCourses.length === 0} on:click={exportVisibleCourseManifest}>Export shown</button>
              </div>
              <small>Selected cookie bucket is stored with imported courses and inherited by queued lessons or attachments. Import bundle accepts local FetchDock course exports; export writes the shown local outlines only.</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Progress backup</strong>
              <small>Export or restore local lesson progress for courses that already exist in this library.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={courseProgressImportPath} placeholder="C:/Courses/course-progress.json" spellcheck="false" aria-label="Course progress import path" />
                <button class="icon-button" type="button" title="Choose course progress backup" disabled={coursesBusy} on:click={chooseCourseProgressImportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!courseProgressImportPath.trim()} on:click={() => openLocalPath(courseProgressImportPath, "Course progress backup")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!courseProgressImportPath.trim()} on:click={() => revealLocalPath(courseProgressImportPath, "Course progress backup")}>
                  Reveal
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={courseProgressExportPath} placeholder="Optional progress export path" spellcheck="false" aria-label="Course progress export path" />
                <button class="icon-button" type="button" title="Choose course progress export" disabled={coursesBusy} on:click={chooseCourseProgressExportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!courseProgressExportResult && !courseProgressExportPath.trim()} on:click={openCourseProgressExportResult}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!courseProgressExportResult && !courseProgressExportPath.trim()} on:click={revealCourseProgressExportResult}>
                  Reveal export
                </button>
              </div>
              {#if courseProgressExportResult}
                <small>{courseProgressExportResult.exported_lesson_count} lesson{courseProgressExportResult.exported_lesson_count === 1 ? "" : "s"} exported from {courseProgressExportResult.exported_course_count} course{courseProgressExportResult.exported_course_count === 1 ? "" : "s"} · {courseProgressExportResult.output_path}</small>
              {/if}
              {#if courseProgressImportResult}
                <small>{courseProgressImportResult.imported_lesson_count} lesson{courseProgressImportResult.imported_lesson_count === 1 ? "" : "s"} restored · {courseProgressImportResult.skipped_course_count} skipped courses · {courseProgressImportResult.skipped_lesson_count} skipped lessons</small>
              {/if}
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={coursesBusy || !courseProgressImportPath.trim()} on:click={importCourseProgressBackup}>Import progress</button>
                <button class="secondary-button" type="button" disabled={coursesBusy || filteredCourses.length === 0} on:click={exportVisibleCourseProgressBackup}>Export shown progress</button>
              </div>
              <small>Progress backups store lesson ids, titles, progress percent, opened time, and note counts only. They do not import course outlines, source URLs, Cookie buckets, notes, attachments, media files, or download tasks.</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Local course summary</strong>
              <small>Review local course outlines, queueable lesson and attachment sources, progress, notes, and transfer status metadata.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions compact-actions">
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={loadCourses}>Refresh summary</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={copyCourseLocalSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={copyCourseLocalSummaryJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={() => copyCourseLocalSummaryFields("platform")}>Copy platforms</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={() => copyCourseLocalSummaryFields("status")}>Copy statuses</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={() => copyCourseLocalSummaryFields("attachment-kind")}>Copy attachment kinds</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={() => copyCourseLocalSummaryFields("transfer-status")}>Copy transfer statuses</button>
                <button class="small-button" type="button" disabled={!courseLocalSummary} on:click={() => copyCourseLocalSummaryFields("note")}>Copy notes</button>
              </div>
              {#if courseLocalSummary}
                <div class="compact-stats-grid">
                  <span>{courseLocalSummary.course_count} courses</span>
                  <span>{courseLocalSummary.lesson_count} lessons</span>
                  <span>{courseLocalSummary.attachment_count} attachments</span>
                  <span>{courseLocalSummary.queueable_lesson_count} queueable lessons</span>
                  <span>{courseLocalSummary.queueable_attachment_count} queueable attachments</span>
                  <span>{courseLocalSummary.average_progress_percent}% average progress</span>
                  <span>{courseLocalSummary.cookie_linked_course_count} cookie-linked</span>
                  <span>{courseLocalSummary.transfer_task_count} transfers</span>
                </div>
                <small>{courseLocalSummary.local_lesson_count} local lessons · {courseLocalSummary.missing_local_lesson_count} missing lesson paths · {courseLocalSummary.local_attachment_count} local attachments · {courseLocalSummary.missing_local_attachment_count} missing attachment paths</small>
                <small>Last updated {courseLocalSummary.last_updated_at ?? "never"} · data root {courseLocalSummary.data_root}</small>
              {:else}
                <small>Summary is available in the desktop runtime after loading local courses.</small>
              {/if}
              <div class="path-picker-row">
                <input bind:value={courseSummaryExportPath} placeholder="C:/path/course-summary.json" spellcheck="false" aria-label="Course summary export path" />
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={exportCourseSummary}>Export summary</button>
                <button class="small-button" type="button" disabled={!courseSummaryExportPath.trim() && !courseSummaryExportResult} on:click={() => openLocalPath(courseSummaryExportResult || courseSummaryExportPath, "Course summary")}>Open export</button>
                <button class="small-button" type="button" disabled={!courseSummaryExportPath.trim() && !courseSummaryExportResult} on:click={() => revealLocalPath(courseSummaryExportResult || courseSummaryExportPath, "Course summary")}>Reveal export</button>
              </div>
              <small>This summary exports local metadata only. It does not include Cookie values, note bodies, downloaded files, or remote course-platform data.</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Course capability catalog</strong>
              <small>Review Courses commands, CLI aliases, UI surfaces, task kinds, data files, and parity limits.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions compact-actions">
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={loadCourses}>Refresh catalog</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={copyCourseCapabilityCatalogSummary}>Copy catalog</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={copyCourseCapabilityCatalogJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={() => copyCourseCapabilityCatalogFields("capability")}>Copy capabilities</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={() => copyCourseCapabilityCatalogFields("command")}>Copy commands</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={() => copyCourseCapabilityCatalogFields("surface")}>Copy surfaces</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={() => copyCourseCapabilityCatalogFields("task-kind")}>Copy task kinds</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalog} on:click={() => copyCourseCapabilityCatalogFields("limit")}>Copy limits</button>
              </div>
              {#if courseCapabilityCatalog}
                <div class="compact-stats-grid">
                  <span>{courseCapabilityCatalog.capability_count} capabilities</span>
                  <span>{courseCapabilityCatalog.supported_platforms.length} platforms</span>
                  <span>{courseCapabilityCatalog.course_surfaces.length} surfaces</span>
                  <span>{courseCapabilityCatalog.task_kinds.length} task kinds</span>
                  <span>gate {courseCapabilityCatalog.parity_gate_status}</span>
                  <span>login {courseCapabilityCatalog.verifies_platform_login_e2e ? "verified" : "pending"}</span>
                </div>
                <small>Platforms {courseCapabilityCatalog.supported_platforms.join(", ") || "none"} · task kinds {courseCapabilityCatalog.task_kinds.join(", ") || "none"}</small>
                <small>Cookie values {courseCapabilityCatalog.includes_cookie_values ? "included" : "excluded"} · note bodies {courseCapabilityCatalog.includes_note_bodies ? "included" : "excluded"} · files {courseCapabilityCatalog.includes_downloaded_files ? "included" : "excluded"}</small>
              {:else}
                <small>Catalog is available in the desktop runtime after loading local courses.</small>
              {/if}
              <div class="path-picker-row">
                <input bind:value={courseCapabilityCatalogExportPath} placeholder="C:/path/course-capability-catalog.json" spellcheck="false" aria-label="Course capability catalog export path" />
                <button class="secondary-button" type="button" disabled={coursesBusy} on:click={exportCourseCapabilityCatalogFile}>Export catalog</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalogExportPath.trim() && !courseCapabilityCatalogExportResult} on:click={() => openLocalPath(courseCapabilityCatalogExportResult || courseCapabilityCatalogExportPath, "Course capability catalog")}>Open export</button>
                <button class="small-button" type="button" disabled={!courseCapabilityCatalogExportPath.trim() && !courseCapabilityCatalogExportResult} on:click={() => revealLocalPath(courseCapabilityCatalogExportResult || courseCapabilityCatalogExportPath, "Course capability catalog")}>Reveal export</button>
              </div>
              <small>The catalog is metadata-only. It does not perform platform login, crawl remote attachments, run downloads, include Cookie values, include note bodies, or verify player E2E.</small>
            </div>
          </div>
          {#if courseProbeResult}
            <p class="muted">{courseProbeResult.platform} · {courseProbeResult.title} · {courseProbeResult.status} · {cookieBucketLabel(courseProbeResult.cookie_bucket_id)}</p>
          {/if}
          {#if coursesError}
            <p class="error-text">{coursesError}</p>
          {/if}
        </div>
        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Platform matrix</h2>
              <p>{coursePlatformMatrix.length} target course platform{coursePlatformMatrix.length === 1 ? "" : "s"} tracked.</p>
            </div>
            <div class="inline-actions">
              {#if coursePlatformMatrix.length > 5}
                <button class="secondary-button compact-button" type="button" disabled={coursesBusy} on:click={() => (coursePlatformMatrixExpanded = !coursePlatformMatrixExpanded)}>
                  {coursePlatformMatrixExpanded ? "Collapse" : "Show all"}
                </button>
              {/if}
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy} on:click={chooseCoursePlatformMatrixExportPath}>
                {coursesBusy ? "Choosing" : "Save matrix as"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy} on:click={exportCurrentCoursePlatformMatrix}>
                Export matrix
              </button>
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy || coursePlatformMatrix.length === 0} on:click={copyCoursePlatformMatrixSummary}>
                Copy matrix
              </button>
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy || coursePlatformMatrix.length === 0} on:click={copyCoursePlatformMatrixJson}>
                Copy matrix JSON
              </button>
              <button class="secondary-button compact-button" type="button" disabled={filteredCoursePlatformSamples.length === 0} on:click={() => copyCoursePlatformSampleUrls(filteredCoursePlatformSamples)}>
                Copy URLs
              </button>
              <button class="secondary-button compact-button" type="button" disabled={visibleCoursePlatformSamples(filteredCoursePlatformSamples).length === 0} on:click={copyVisibleCoursePlatformSampleSummary}>
                Copy sample summary
              </button>
              <button class="secondary-button compact-button" type="button" disabled={visibleCoursePlatformSamples(filteredCoursePlatformSamples).length === 0} on:click={copyVisibleCoursePlatformSampleJson}>
                Copy sample JSON
              </button>
              <button class="small-button" type="button" disabled={visibleCoursePlatformSamples(filteredCoursePlatformSamples).length === 0} on:click={() => copyCoursePlatformSampleFields("label")}>
                Copy labels
              </button>
              <button class="small-button" type="button" disabled={visibleCoursePlatformSamples(filteredCoursePlatformSamples).length === 0} on:click={() => copyCoursePlatformSampleFields("platform")}>
                Copy platforms
              </button>
              <button class="small-button" type="button" disabled={visibleCoursePlatformSamples(filteredCoursePlatformSamples).length === 0} on:click={() => copyCoursePlatformSampleFields("title")}>
                Copy title hints
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(coursePlatformSampleBusy)} on:click={chooseCoursePlatformSamplesExportPath}>
                {coursePlatformSampleBusy === "choose-export" ? "Choosing" : "Save samples as"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(coursePlatformSampleBusy)} on:click={exportCurrentCoursePlatformSamples}>
                {coursePlatformSampleBusy === "export" ? "Exporting" : "Export samples"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(coursePlatformSampleBusy) || filteredCoursePlatformSamples.length === 0} on:click={importShownCoursePlatformSamples}>
                {coursePlatformSampleBusy === "import-shown" ? "Importing" : "Import samples"}
              </button>
            </div>
          </div>
          <div class="metadata-tool compact-export-grid">
            <label class="wide-option">
              <span>Matrix export</span>
              <div class="path-picker-row">
                <input bind:value={coursePlatformMatrixExportPath} placeholder="C:/FetchDock/course-platform-matrix.json" spellcheck="false" aria-label="Course platform matrix export path" />
                <button class="small-button" type="button" disabled={!coursePlatformMatrixExportPath.trim()} on:click={() => openLocalPath(coursePlatformMatrixExportPath, "Course platform matrix")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!coursePlatformMatrixExportPath.trim()} on:click={() => revealLocalPath(coursePlatformMatrixExportPath, "Course platform matrix")}>
                  Reveal
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Samples export</span>
              <div class="path-picker-row">
                <input bind:value={coursePlatformSamplesExportPath} placeholder="C:/FetchDock/course-platform-samples.json" spellcheck="false" aria-label="Course platform samples export path" />
                <button class="small-button" type="button" disabled={!coursePlatformSamplesExportPath.trim()} on:click={() => openLocalPath(coursePlatformSamplesExportPath, "Course platform samples")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!coursePlatformSamplesExportPath.trim()} on:click={() => revealLocalPath(coursePlatformSamplesExportPath, "Course platform samples")}>
                  Reveal
                </button>
              </div>
            </label>
          </div>
          <div class="channel-list compact-list">
            {#each (coursePlatformMatrixExpanded ? coursePlatformMatrix : coursePlatformMatrix.slice(0, 5)) as platform}
              <article class="channel-card compact-card">
                <div>
                  <strong>{platform.label}</strong>
                  <small>{platform.status.replaceAll("_", " ")} · {platform.host_hints.join(", ")}</small>
                  <small>{platform.evidence[0]}</small>
                  <small>{platform.limitations[0]}</small>
                </div>
              </article>
            {/each}
          </div>
          {#if coursePlatformSamples.length > 0}
            <div class="course-list-toolbar compact-toolbar">
              <input bind:value={coursePlatformSampleSearch} placeholder="Search samples, platform, or URL" spellcheck="false" aria-label="Course platform sample search" />
              <small>{visibleCoursePlatformSamples(filteredCoursePlatformSamples).length} shown of {filteredCoursePlatformSamples.length} matching course sample{filteredCoursePlatformSamples.length === 1 ? "" : "s"}.</small>
              {#if filteredCoursePlatformSamples.length > 5 && !coursePlatformSampleSearch.trim()}
                <button class="small-button" type="button" disabled={Boolean(coursePlatformSampleBusy)} on:click={() => (coursePlatformSamplesExpanded = !coursePlatformSamplesExpanded)}>
                  {coursePlatformSamplesExpanded ? "Collapse samples" : "Show samples"}
                </button>
              {/if}
            </div>
            {#if filteredCoursePlatformSamples.length === 0}
              <p class="muted">No course platform samples match the current filter.</p>
            {:else}
              <div class="channel-list compact-list">
                {#each visibleCoursePlatformSamples(filteredCoursePlatformSamples) as sample}
                <article class="channel-card compact-card">
                  <div>
                    <strong>{sample.label}</strong>
                    <small>{sample.platform_id} · {sample.url}</small>
                    <small>Imports as local candidate only; remote lesson extraction remains pending.</small>
                  </div>
                  <div class="section-actions">
                    <button class="small-button" type="button" on:click={() => openSourceUrl(sample.url, sample.label)}>Open</button>
                    <button class="small-button" type="button" disabled={Boolean(coursePlatformSampleBusy)} on:click={() => importCoursePlatformSample(sample)}>
                      {coursePlatformSampleBusy === sample.platform_id ? "Importing" : "Import"}
                    </button>
                  </div>
                </article>
                {/each}
              </div>
            {/if}
          {/if}
        </div>
        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Course library</h2>
              <p>{filteredCourses.length} shown of {courses.length} local course{courses.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy || filteredQueueableCourseLessonsCount === 0 || courseActionBusy === "queue-filtered-lessons"} on:click={queueFilteredCourseLessonsBatch}>
                {courseActionBusy === "queue-filtered-lessons" ? "Queueing" : "Queue shown lessons"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy || filteredQueueableCourseAttachmentsCount === 0 || courseActionBusy === "queue-filtered-attachments"} on:click={queueFilteredCourseAttachmentsBatch}>
                {courseActionBusy === "queue-filtered-attachments" ? "Queueing" : "Queue shown attachments"}
              </button>
              <button class="small-button" type="button" disabled={!shownCourseLessonPairs().some(({ lesson }) => lesson.source_url)} on:click={() => copyShownCourseItemSources("lessons")}>
                Copy lesson URLs
              </button>
              <button class="small-button" type="button" disabled={!shownCourseAttachmentPairs().some(({ attachment }) => attachment.source_url)} on:click={() => copyShownCourseItemSources("attachments")}>
                Copy attachment URLs
              </button>
              <button class="small-button" type="button" disabled={filteredCourses.length === 0} on:click={() => copyShownCourseFields("course-id")}>
                Copy course ids
              </button>
              <button class="small-button" type="button" disabled={filteredCourses.length === 0} on:click={() => copyShownCourseFields("course-title")}>
                Copy course titles
              </button>
              <button class="small-button" type="button" disabled={shownCourseLessonPairs().length === 0} on:click={() => copyShownCourseFields("lesson-id")}>
                Copy lesson ids
              </button>
              <button class="small-button" type="button" disabled={shownCourseLessonPairs().length === 0} on:click={() => copyShownCourseFields("lesson-title")}>
                Copy lesson titles
              </button>
              <button class="small-button" type="button" disabled={!shownCourseLessonPairs().some(({ lesson }) => lesson.local_path)} on:click={() => copyShownCourseFields("lesson-local")}>
                Copy lesson paths
              </button>
              <button class="small-button" type="button" disabled={shownCourseLessonPairs().length === 0} on:click={() => copyShownCourseFields("lesson-progress")}>
                Copy lesson progress
              </button>
              <button class="small-button" type="button" disabled={shownCourseLessonPairs().length === 0} on:click={() => copyShownCourseFields("lesson-duration")}>
                Copy lesson durations
              </button>
              <button class="small-button" type="button" disabled={shownCourseAttachmentPairs().length === 0} on:click={() => copyShownCourseFields("attachment-id")}>
                Copy attachment ids
              </button>
              <button class="small-button" type="button" disabled={shownCourseAttachmentPairs().length === 0} on:click={() => copyShownCourseFields("attachment-title")}>
                Copy attachment titles
              </button>
              <button class="small-button" type="button" disabled={filteredCourses.length === 0} on:click={copyShownCourseSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={filteredCourses.length === 0} on:click={copyShownCourseJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!shownCourseAttachmentPairs().some(({ attachment }) => attachment.local_path)} on:click={() => copyShownCourseFields("attachment-local")}>
                Copy attachment paths
              </button>
              <button class="small-button" type="button" disabled={shownCourseAttachmentPairs().length === 0} on:click={() => copyShownCourseFields("attachment-kind")}>
                Copy attachment kinds
              </button>
              <button class="small-button" type="button" disabled={shownCourseAttachmentPairs().length === 0} on:click={() => copyShownCourseFields("attachment-size")}>
                Copy attachment sizes
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={coursesBusy || filteredRemovableCourseLessonsCount === 0 || courseActionBusy === "remove-shown-lessons"} on:click={requestShownCourseLessonsRemove}>
                {courseActionBusy === "remove-shown-lessons" ? "Removing" : "Remove shown lessons"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={coursesBusy || filteredRemovableCourseAttachmentsCount === 0 || courseActionBusy === "remove-shown-attachments"} on:click={requestShownCourseAttachmentsRemove}>
                {courseActionBusy === "remove-shown-attachments" ? "Removing" : "Remove shown attachments"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={coursesBusy || filteredCourses.length === 0 || courseActionBusy === "remove-filtered-courses"} on:click={requestFilteredCoursesRemove}>
                {courseActionBusy === "remove-filtered-courses" ? "Removing" : "Remove shown courses"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={coursesBusy || courses.length === 0 || courseActionBusy === "prune-missing"} on:click={pruneMissingCourseFiles}>
                {courseActionBusy === "prune-missing" ? "Pruning" : "Prune missing"}
              </button>
              <button class="small-button danger" type="button" disabled={coursesBusy || courses.length === 0} on:click={requestCoursesClear}>
                Clear courses
              </button>
            </div>
          </div>
          <div class="library-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={courseSearchQuery} placeholder="Course, lesson, attachment, URL, or path" spellcheck="false" />
            </label>
          </div>
          <div class="channel-list">
            {#if courses.length === 0}
              <p class="muted">Imported course candidates will appear here.</p>
            {:else if filteredCourses.length === 0}
              <p class="muted">No courses match the current search.</p>
            {:else}
              {#each filteredCourses as course}
                <article class="channel-card">
                  <div>
                    <div class="section-heading compact-heading">
                      <div>
                        <strong>{course.title}</strong>
                      </div>
                      <button
                        class="secondary-button compact-button"
                        type="button"
                        disabled={courseActionBusy === `${course.id}:queue-all` || !course.lessons.some((lesson) => lesson.source_url)}
                        on:click={() => queueCourseLessonsBatch(course)}
                      >
                        {courseActionBusy === `${course.id}:queue-all` ? "Queueing" : "Queue all"}
                      </button>
                      <button
                        class="small-button danger"
                        type="button"
                        disabled={courseActionBusy === `${course.id}:delete`}
                        on:click={() => requestCourseDelete(course)}
                      >
                        Remove
                      </button>
                    </div>
                    <small>{course.platform} · {course.status} · {course.source_url}</small>
                    {#if course.remote_extraction_note}
                      <small>{course.remote_extraction_note}</small>
                    {/if}
                    <small>{course.lesson_count} lessons · {course.attachment_count} attachments · {cookieBucketLabel(course.cookie_bucket_id)}</small>
                    <div class="course-cookie-control">
                      <select
                        value={courseCookieBucketValue(course)}
                        aria-label={`Cookie bucket for ${course.title}`}
                        on:change={(event) => (courseCookieBucketInputs[course.id] = event.currentTarget.value)}
                      >
                        <option value="">No cookie bucket</option>
                        {#each cookieBuckets as bucket}
                          <option value={bucket.id}>{bucket.name} · {bucket.health}</option>
                        {/each}
                      </select>
                      <button class="small-button" type="button" disabled={courseActionBusy === `${course.id}:cookie`} on:click={() => saveCourseCookieBucket(course)}>
                        Save cookie
                      </button>
                    </div>
                    {#if course.lessons.length > 0}
                      <div class="course-list-toolbar">
                        <small>
                          Showing {visibleCourseLessons(course).length} of {course.lessons.length} lesson{course.lessons.length === 1 ? "" : "s"}
                        </small>
                        {#if course.lessons.length > 6 && !courseSearchQuery.trim()}
                          <button class="small-button" type="button" on:click={() => toggleCourseLessons(course.id)}>
                            {courseExpandedLessonIds[course.id] ? "Collapse lessons" : "Show all lessons"}
                          </button>
                        {/if}
                      </div>
                      <div class="course-detail-list">
                        {#each visibleCourseLessons(course) as lesson}
                          {@const lessonKey = `${course.id}:${lesson.id}`}
                          <div>
                            <span>
                              <strong>{lesson.title}</strong>
                              <small>{lesson.duration_seconds ? formatDuration(lesson.duration_seconds) : "Duration unknown"} · {lesson.progress_percent}% · {lesson.local_path ?? lesson.source_url ?? "No media path"}</small>
                              {#if lesson.opened_at}
                                <small>Opened {lesson.opened_at}</small>
                              {/if}
                            </span>
                            <div class="course-progress-control">
                              <input
                                value={courseLessonProgressValue(course, lesson)}
                                inputmode="numeric"
                                aria-label={`Progress for ${lesson.title}`}
                                on:input={(event) => (courseProgressInputs[lessonKey] = event.currentTarget.value)}
                              />
                              <button class="small-button" type="button" disabled={courseActionBusy === lessonKey} on:click={() => saveCourseLessonProgress(course, lesson)}>
                                Save
                              </button>
                              {#if lesson.local_path}
                                <button class="small-button" type="button" disabled={!courseLessonPreviewKind(lesson)} on:click={() => previewCourseLessonMedia(course, lesson)}>
                                  Preview
                                </button>
                                <button class="small-button" type="button" disabled={courseActionBusy === `${lessonKey}:open`} on:click={() => openCourseLessonMedia(course, lesson)}>
                                  Open
                                </button>
                                <button class="small-button" type="button" disabled={courseActionBusy === lesson.local_path} on:click={() => revealCourseLocalPath(lesson.local_path ?? "", "Lesson")}>
                                  Reveal
                                </button>
                              {/if}
                              {#if lesson.source_url}
                                <button class="small-button" type="button" on:click={() => openCourseLessonSource(course, lesson)}>
                                  Open source
                                </button>
                                <button class="small-button" type="button" disabled={courseActionBusy === `${lessonKey}:queue`} on:click={() => queueCourseLessonDownload(course, lesson)}>
                                  Queue
                                </button>
                              {/if}
                              <button class="small-button danger" type="button" disabled={courseActionBusy === `${lessonKey}:delete`} on:click={() => removeCourseLessonItem(course, lesson)}>
                                Remove
                              </button>
                            </div>
                            {#if courseLessonNotes(lesson).length > 0}
                              <div class="course-note-jumps">
                                {#each courseLessonNotes(lesson).slice(0, 3) as note}
                                  <button class="small-button" type="button" disabled={!lesson.local_path || !courseLessonPreviewKind(lesson)} on:click={() => jumpToCourseLessonNote(course, lesson, note)}>
                                    {note.timestamp_seconds !== null && note.timestamp_seconds !== undefined ? formatTimestamp(note.timestamp_seconds) : "Open"} · {note.title}
                                  </button>
                                {/each}
                              </div>
                            {/if}
                            <div class="course-note-control">
                              <div>
                                <input
                                  value={courseNoteTitles[lessonKey] ?? `${lesson.title} note`}
                                  aria-label={`Note title for ${lesson.title}`}
                                  on:input={(event) => (courseNoteTitles[lessonKey] = event.currentTarget.value)}
                                />
                                <span class="timestamp-capture-control">
                                  <input
                                    value={courseNoteTimestamps[lessonKey] ?? ""}
                                    inputmode="numeric"
                                    placeholder="seconds"
                                    aria-label={`Timestamp for ${lesson.title}`}
                                    on:input={(event) => (courseNoteTimestamps[lessonKey] = event.currentTarget.value)}
                                  />
                                  <button class="small-button" type="button" disabled={!lesson.local_path || !courseLessonPreviewKind(lesson)} on:click={() => useCurrentCoursePreviewTime(course, lesson)}>
                                    Now
                                  </button>
                                </span>
                              </div>
                              <textarea
                                value={courseNoteBodies[lessonKey] ?? ""}
                                placeholder={`Add note${lesson.note_count ? ` · ${lesson.note_count} saved` : ""}`}
                                aria-label={`Note body for ${lesson.title}`}
                                on:input={(event) => (courseNoteBodies[lessonKey] = event.currentTarget.value)}
                              ></textarea>
                              <button class="small-button" type="button" disabled={courseActionBusy === `${lessonKey}:note`} on:click={() => saveCourseLessonTimestampNote(course, lesson)}>
                                Add note
                              </button>
                            </div>
                          </div>
                        {/each}
                      </div>
                    {/if}
                    {#if course.attachments.length > 0}
                      <div class="section-actions compact-actions">
                        <small>
                          Showing {visibleCourseAttachments(course).length} of {course.attachments.length} attachment{course.attachments.length === 1 ? "" : "s"}
                        </small>
                        <button
                          class="secondary-button compact-button"
                          type="button"
                          disabled={courseActionBusy === `${course.id}:queue-attachments` || !course.attachments.some((attachment) => attachment.source_url)}
                          on:click={() => queueCourseAttachmentsBatch(course)}
                        >
                          {courseActionBusy === `${course.id}:queue-attachments` ? "Queueing" : "Queue attachments"}
                        </button>
                        {#if course.attachments.length > 4 && !courseSearchQuery.trim()}
                          <button class="small-button" type="button" on:click={() => toggleCourseAttachments(course.id)}>
                            {courseExpandedAttachmentIds[course.id] ? "Collapse attachments" : "Show all attachments"}
                          </button>
                        {/if}
                      </div>
                      <div class="course-detail-list compact-course-list">
                        {#each visibleCourseAttachments(course) as attachment}
                          {@const localAttachmentPath = attachment.local_path}
                          <div>
                            <span>
                              <strong>{attachment.title}</strong>
                              <small>{attachment.kind.toUpperCase()} · {attachment.size_bytes ? formatBytes(attachment.size_bytes) : "size unknown"} · {attachment.local_path ?? attachment.source_url ?? "No attachment path"}</small>
                            </span>
                            <div class="section-actions">
                              {#if attachment.source_url}
                                <button
                                  class="small-button"
                                  type="button"
                                  on:click={() => openCourseAttachmentSource(course, attachment)}
                                >
                                  Open source
                                </button>
                                <button
                                  class="small-button"
                                  type="button"
                                  disabled={courseActionBusy === `${course.id}:${attachment.id}:queue-attachment`}
                                  on:click={() => queueCourseAttachmentItem(course, attachment)}
                                >
                                  {courseActionBusy === `${course.id}:${attachment.id}:queue-attachment` ? "Queueing" : "Queue"}
                                </button>
                              {/if}
                              {#if localAttachmentPath}
                                <button class="small-button" type="button" disabled={!canPreviewCourseAttachment(attachment)} on:click={() => previewCourseAttachment(course, attachment)}>
                                  Preview
                                </button>
                                <button class="small-button" type="button" disabled={courseActionBusy === localAttachmentPath} on:click={() => openCourseAttachment(localAttachmentPath)}>
                                  Open
                                </button>
                                <button class="small-button" type="button" disabled={courseActionBusy === localAttachmentPath} on:click={() => revealCourseAttachment(localAttachmentPath)}>
                                  Reveal
                                </button>
                              {/if}
                              <button
                                class="small-button danger"
                                type="button"
                                disabled={courseActionBusy === `${course.id}:${attachment.id}:delete-attachment`}
                                on:click={() => removeCourseAttachmentItem(course, attachment)}
                              >
                                Remove
                              </button>
                            </div>
                          </div>
                        {/each}
                      </div>
                    {/if}
                  </div>
                </article>
              {/each}
            {/if}
          </div>
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local transfers</p>
              <h2>Course transfers</h2>
            </div>
            <button class="secondary-button compact-button" type="button" on:click={loadDownloads}>Refresh</button>
          </div>
          <div class="library-filter-row transfer-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={courseTransferSearch} placeholder="Title, URL, platform, output path, or error" spellcheck="false" aria-label="Course transfer search" />
            </label>
            <label>
              <span>Status</span>
              <select bind:value={courseTransferStatusFilter} aria-label="Course transfer status filter">
                <option value="all">All status</option>
                <option value="queued">Queued</option>
                <option value="active">Active</option>
                <option value="paused">Paused</option>
                <option value="completed">Completed</option>
                <option value="failed">Failed</option>
                <option value="canceled">Canceled</option>
                <option value="archived">Archived</option>
              </select>
            </label>
          </div>
          {#if courseTransferTasks.length === 0}
            <p class="muted">Queued course lessons and attachments will appear here after you queue items from the local course library.</p>
          {:else if filteredCourseTransferTasks.length === 0}
            <p class="muted">No course transfers match the current filters.</p>
          {:else}
            <div class="course-list-toolbar">
              <small class="format-hint">
                {visibleCourseTransferTasks(filteredCourseTransferTasks).length} shown of {courseTransferTasks.length} local course transfer task{courseTransferTasks.length === 1 ? "" : "s"}.
              </small>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskSummary(visibleCourseTransferTasks(filteredCourseTransferTasks), "Course transfer")}>
                Copy summary
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskJson(visibleCourseTransferTasks(filteredCourseTransferTasks), "Course transfer", { search: courseTransferSearch, status: courseTransferStatusFilter })}>
                Copy JSON
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleCourseTransferTasks(filteredCourseTransferTasks), "source", "Course transfer")}>
                Copy sources
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleCourseTransferTasks(filteredCourseTransferTasks), "output", "Course transfer")}>
                Copy outputs
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferStartableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("start", visibleCourseTransferStartableTasks, "Course transfers")}
              >
                Start shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferActiveTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("pause", visibleCourseTransferActiveTasks, "Course transfers")}
              >
                Pause shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferPausedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("resume", visibleCourseTransferPausedTasks, "Course transfers")}
              >
                Resume shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferFailedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("retry", visibleCourseTransferFailedTasks, "Course transfers")}
              >
                Retry shown
              </button>
              <button
                class="small-button danger"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferCancelableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("cancel", visibleCourseTransferCancelableTasks, "Course transfers")}
              >
                Cancel shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferArchivableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("archive", visibleCourseTransferArchivableTasks, "Course transfers")}
              >
                Archive shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleCourseTransferRestorableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("restore", visibleCourseTransferRestorableTasks, "Course transfers")}
              >
                Restore shown
              </button>
              {#if filteredCourseTransferTasks.length > 10 && !courseTransferSearch.trim() && courseTransferStatusFilter === "all"}
                <button class="small-button" type="button" on:click={() => (courseTransfersExpanded = !courseTransfersExpanded)}>
                  {courseTransfersExpanded ? "Collapse transfers" : "Show all transfers"}
                </button>
              {/if}
            </div>
            <div class="telegram-media-list transfer-task-list">
              {#each visibleCourseTransferTasks(filteredCourseTransferTasks) as task}
                <div>
                  <span>
                    <strong>{task.title}</strong>
                    <small>{task.status} · {formatProgress(task)}</small>
                    <small>{task.kind.replaceAll("_", " ")} · {task.platform} · {task.source_url}</small>
                    {#if task.output_path}
                      <small>Saved to {task.output_path}</small>
                    {:else if task.output_dir}
                      <small>Output folder {task.output_dir}</small>
                    {/if}
                    {#if taskDetailSummary(task)}
                      <small>{taskDetailSummary(task)}</small>
                    {/if}
                    {#if task.last_error}
                      <small class="error-text">{task.last_error}</small>
                    {/if}
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" disabled={!canStartTask(task) || activeTaskIds.has(task.id)} on:click={() => startTask(task)}>
                      Start
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "active"} on:click={() => pauseTask(task)}>
                      Pause
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "paused"} on:click={() => resumeTask(task)}>
                      Resume
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "failed" && task.status !== "canceled"} on:click={() => retryTask(task)}>
                      Retry
                    </button>
                    <button class="small-button" type="button" disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"} on:click={() => cancelTask(task)}>
                      Cancel
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_path} on:click={() => revealTaskFile(task)}>
                      Reveal
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_dir && !task.output_path} on:click={() => openTaskFolder(task)}>
                      Open
                    </button>
                    <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                      Source
                    </button>
                    <button class="small-button" type="button" on:click={() => focusDownloadTaskById(task.id, task.title)}>
                      Detail
                    </button>
                    <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                      Logs
                    </button>
                    {#if task.status === "archived"}
                      <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                    {:else if ["completed", "failed", "canceled"].includes(task.status)}
                      <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                    {/if}
                  </div>
                </div>
              {/each}
            </div>
          {/if}
        </div>
        {#if coursePreviewLesson && coursePreviewUrl}
          {@const activeCoursePreviewLesson = coursePreviewLesson}
          <div class="panel course-preview-panel">
            <div class="section-heading compact-heading">
              <div>
                <p class="eyebrow">{activeCoursePreviewLesson.course.title}</p>
                <h2>{activeCoursePreviewLesson.lesson.title}</h2>
              </div>
              <button class="icon-button" type="button" title="Close lesson preview" on:click={() => (coursePreviewLesson = null)}>
                <X size={18} />
              </button>
            </div>
            <div class="preview-toolbar section-actions">
              <button
                class="small-button"
                type="button"
                disabled={courseActionBusy === `${activeCoursePreviewLesson.course.id}:${activeCoursePreviewLesson.lesson.id}:open`}
                on:click={() => openCourseLessonMedia(activeCoursePreviewLesson.course, activeCoursePreviewLesson.lesson)}
              >
                Open
              </button>
              <button
                class="small-button"
                type="button"
                disabled={!activeCoursePreviewLesson.lesson.local_path || courseActionBusy === activeCoursePreviewLesson.lesson.local_path}
                on:click={() => revealCourseLocalPath(activeCoursePreviewLesson.lesson.local_path ?? "", "Lesson")}
              >
                Reveal
              </button>
              <button class="small-button" type="button" disabled={!coursePreviewMediaElement} on:click={saveCoursePreviewProgressFromMedia}>
                Save progress
              </button>
              {#if activeCoursePreviewLesson.lesson.source_url}
                <button
                  class="small-button"
                  type="button"
                  on:click={() => openCourseLessonSource(activeCoursePreviewLesson.course, activeCoursePreviewLesson.lesson)}
                >
                  Open source
                </button>
                <button
                  class="small-button"
                  type="button"
                  disabled={courseActionBusy === `${activeCoursePreviewLesson.course.id}:${activeCoursePreviewLesson.lesson.id}:queue`}
                  on:click={() => queueCourseLessonDownload(activeCoursePreviewLesson.course, activeCoursePreviewLesson.lesson)}
                >
                  Queue
                </button>
              {/if}
            </div>
            {#if courseLessonPreviewKind(activeCoursePreviewLesson.lesson) === "video"}
              <video bind:this={coursePreviewMediaElement} controls src={coursePreviewUrl} on:loadedmetadata={restoreCoursePreviewProgress} on:timeupdate={saveCoursePreviewProgressFromMedia}>
                <track kind="captions" />
              </video>
            {:else if courseLessonPreviewKind(activeCoursePreviewLesson.lesson) === "audio"}
              <audio bind:this={coursePreviewMediaElement} controls src={coursePreviewUrl} on:loadedmetadata={restoreCoursePreviewProgress} on:timeupdate={saveCoursePreviewProgressFromMedia}></audio>
            {/if}
            <small>{activeCoursePreviewLesson.lesson.local_path} · restores near {activeCoursePreviewLesson.lesson.progress_percent}%</small>
          </div>
        {/if}
        {#if coursePreviewAttachment && courseAttachmentPreviewUrl}
          {@const activeCoursePreviewAttachment = coursePreviewAttachment}
          <div class="panel course-preview-panel course-attachment-preview-panel">
            <div class="section-heading compact-heading">
              <div>
                <p class="eyebrow">{activeCoursePreviewAttachment.course.title}</p>
                <h2>{activeCoursePreviewAttachment.attachment.title}</h2>
              </div>
              <button class="icon-button" type="button" title="Close attachment preview" on:click={() => (coursePreviewAttachment = null)}>
                <X size={18} />
              </button>
            </div>
            <div class="preview-toolbar section-actions">
              <button class="small-button" type="button" disabled={!activeCoursePreviewAttachment.attachment.local_path || courseActionBusy === activeCoursePreviewAttachment.attachment.local_path} on:click={() => openCourseAttachment(activeCoursePreviewAttachment.attachment.local_path ?? "")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!activeCoursePreviewAttachment.attachment.local_path || courseActionBusy === activeCoursePreviewAttachment.attachment.local_path} on:click={() => revealCourseAttachment(activeCoursePreviewAttachment.attachment.local_path ?? "")}>
                Reveal
              </button>
              {#if activeCoursePreviewAttachment.attachment.source_url}
                <button
                  class="small-button"
                  type="button"
                  on:click={() => openCourseAttachmentSource(activeCoursePreviewAttachment.course, activeCoursePreviewAttachment.attachment)}
                >
                  Open source
                </button>
                <button
                  class="small-button"
                  type="button"
                  disabled={courseActionBusy === `${activeCoursePreviewAttachment.course.id}:${activeCoursePreviewAttachment.attachment.id}:queue-attachment`}
                  on:click={() => queueCourseAttachmentItem(activeCoursePreviewAttachment.course, activeCoursePreviewAttachment.attachment)}
                >
                  Queue
                </button>
              {/if}
            </div>
            <iframe title={activeCoursePreviewAttachment.attachment.title} src={courseAttachmentPreviewUrl}></iframe>
            <small>{activeCoursePreviewAttachment.attachment.local_path}</small>
          </div>
        {/if}
      </section>
    {:else if currentRoute === "learning"}
      <section class="learning-grid">
        <div class="panel">
          <div class="section-heading">
            <div>
              <p class="eyebrow">Module K</p>
              <h2>Notes</h2>
            </div>
            <button class="secondary-button" type="button" disabled={learningBusy} on:click={loadLearning}>Refresh</button>
          </div>
          <div class="setting-row">
            <span>
              <strong>{learningEditingNoteId ? "Edit note" : "New note"}</strong>
              <small>{learningEditingNoteId ? "Updates the selected local note." : "Local note with optional source URL and timestamp."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={learningNoteTitle} placeholder="Title" spellcheck="false" aria-label="Note title" />
              <textarea bind:value={learningNoteBody} placeholder="Write the note, link with [[Note title]]" spellcheck="true" aria-label="Note body"></textarea>
              <div class="two-column-inputs">
                <input bind:value={learningNoteSourceUrl} placeholder="Source URL, optional" spellcheck="false" aria-label="Note source URL" />
                <input bind:value={learningNoteTimestamp} placeholder="Timestamp seconds" inputmode="numeric" aria-label="Timestamp seconds" />
              </div>
              <input bind:value={learningNoteTags} placeholder="tags, comma separated" spellcheck="false" aria-label="Note tags" />
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={learningBusy} on:click={addLearningNote}>
