                  <button class="secondary-button" type="button" disabled={learningBusy} on:click={cancelLearningNoteEdit}>Cancel edit</button>
                {/if}
              </div>
              <div class="advanced-file-preview compact-preview">
                <div>
                  <strong>Update capability catalog</strong>
                  <small>{updateCapabilityCatalog ? `${updateCapabilityCatalog.capability_count} capabilities · gate ${updateCapabilityCatalog.parity_gate_status} · signed update ${updateCapabilityCatalog.verifies_signed_update_e2e ? "verified" : "pending"}` : "Lists updater manifest, settings, summary, due poll, and signed-updater gaps without installing updates."}</small>
                </div>
                <div class="section-actions">
                  <button class="small-button" type="button" disabled={updateSummaryBusy} on:click={() => refreshUpdateCapabilityCatalog()}>
                    {updateSummaryBusy ? "Refreshing" : "Refresh catalog"}
