                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalog} on:click={copyUpdateCapabilityCatalogJson}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalog} on:click={() => copyUpdateCapabilityCatalogFields("capability")}>
                    Copy capabilities
                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalog} on:click={() => copyUpdateCapabilityCatalogFields("command")}>
                    Copy commands
                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalog} on:click={() => copyUpdateCapabilityCatalogFields("surface")}>
                    Copy surfaces
                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalog} on:click={() => copyUpdateCapabilityCatalogFields("limit")}>
                    Copy limits
                  </button>
                </div>
                {#if updateCapabilityCatalog}
                  <div class="learning-stat-grid legal-stat-grid">
                    <span><strong>{updateCapabilityCatalog.capability_count}</strong><small>capabilities</small></span>
                    <span><strong>{updateCapabilityCatalog.supported_manifest_sources.length}</strong><small>sources</small></span>
                    <span><strong>{updateCapabilityCatalog.supported_check_modes.length}</strong><small>modes</small></span>
                    <span><strong>{updateCapabilityCatalog.verifies_rollback_e2e ? "verified" : "pending"}</strong><small>rollback E2E</small></span>
                  </div>
                  <small>{updateCapabilityCatalog.review_notes.join(" ")}</small>
                {/if}
                <div class="path-picker-row">
                  <input bind:value={updateCapabilityCatalogExportPath} placeholder="C:/FetchDock/update-capability-catalog.json" spellcheck="false" aria-label="Update capability catalog export path" />
                  <button class="small-button" type="button" disabled={updateSummaryBusy} on:click={chooseUpdateCapabilityCatalogExportPath}>
                    Save as
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={updateSummaryBusy} on:click={exportUpdateCapabilityCatalogFile}>
                    {updateSummaryBusy ? "Exporting" : "Export catalog"}
