                  <button class="small-button" type="button" disabled={!updateCapabilityCatalogExportResult && !updateCapabilityCatalogExportPath.trim()} on:click={() => openLocalPath(updateCapabilityCatalogExportResult || updateCapabilityCatalogExportPath, "Update capability catalog")}>
                    Open export
                  </button>
                  <button class="small-button" type="button" disabled={!updateCapabilityCatalogExportResult && !updateCapabilityCatalogExportPath.trim()} on:click={() => revealLocalPath(updateCapabilityCatalogExportResult || updateCapabilityCatalogExportPath, "Update capability catalog")}>
                    Reveal export
                  </button>
                </div>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Daily journal</strong>
