                    {/each}
                  </select>
                </label>
              </div>
              <div class="library-filter-row learning-filter-row">
                <label>
                  <span>Source</span>
                  <select bind:value={learningNoteSourceFilter} aria-label="Learning note source filter">
                    <option value="all">All notes</option>
                    <option value="with_source">With source</option>
                    <option value="without_source">No source</option>
                    <option value="timestamped">Timestamped</option>
                    <option value="linked">Linked/backlinked</option>
                  </select>
                </label>
                <label>
                  <span>Sort</span>
                  <select bind:value={learningNoteSortMode} aria-label="Learning note sort mode">
                    <option value="updated_desc">Recently updated</option>
                    <option value="created_desc">Newest created</option>
                    <option value="created_asc">Oldest created</option>
                    <option value="title">Title A-Z</option>
                    <option value="timestamp">Timestamp first</option>
                  </select>
                </label>
              </div>
              <button class="secondary-button" type="button" disabled={learningBusy} on:click={searchLearningNotes}>Reload from store</button>
            </div>
          </div>
