                  <FolderOpen size={16} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={learningBusy || Boolean(learningNotesTransferBusy) || !learningNotesImportPath.trim()} on:click={importLearningNotesFile}>
                  {learningNotesTransferBusy === "import" ? "Importing" : "Import JSON"}
