                  <button class="small-button" type="button" disabled={learningBusy || Boolean(learningNotesTransferBusy)} on:click={openLearningNotesExportResult}>Open export</button>
                  <button class="small-button" type="button" disabled={learningBusy || Boolean(learningNotesTransferBusy)} on:click={revealLearningNotesExportResult}>Reveal export</button>
                </div>
              {/if}
            </div>
          </div>
