              <button class="small-button" type="button" disabled={spacedReviewCards.length === 0} on:click={copySpacedReviewSummary}>Copy summary</button>
              <button class="small-button" type="button" disabled={spacedReviewCards.length === 0} on:click={copySpacedReviewJson}>Copy JSON</button>
            </div>
