                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy) || Boolean(spacedReviewTransferBusy)} on:click={openSpacedReviewExportResult}>Open export</button>
                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy) || Boolean(spacedReviewTransferBusy)} on:click={revealSpacedReviewExportResult}>Reveal export</button>
                </div>
              {/if}
            </div>
          </div>
          <div class="learning-graph-list learning-review-list">
            {#each visibleSpacedReviewCards as card}
