                <small>due {card.due_at} · interval {card.interval_days}d · ease {card.ease} · reviews {card.review_count}</small>
                <small>{card.tags.map((tag) => `#${tag}`).join(" ")}{card.source_url ? ` · ${card.source_url}` : ""}</small>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => rateSpacedReviewCard(card, "again")}>Again</button>
                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => rateSpacedReviewCard(card, "hard")}>Hard</button>
                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => rateSpacedReviewCard(card, "good")}>Good</button>
                  <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => rateSpacedReviewCard(card, "easy")}>Easy</button>
                  <button class="small-button danger-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => removeSpacedReviewCard(card)}>Delete</button>
                </div>
              </span>
            {/each}
            {#if visibleSpacedReviewCards.length === 0}
              <small>No local review cards match the current filter.</small>
            {/if}
          </div>
        </div>
        <div class="panel learning-dashboard-panel">
          <div class="section-heading compact-heading">
