                {learningLocalSummaryBusy ? "Refreshing" : "Refresh"}
              </button>
              <button class="small-button" type="button" disabled={!learningLocalSummary} on:click={copyLearningLocalSummary}>Copy summary</button>
              <button class="small-button" type="button" disabled={!learningLocalSummary} on:click={copyLearningLocalSummaryJson}>Copy JSON</button>
            </div>
          </div>
          <div class="learning-stat-grid">
            <div>
              <strong>{learningLocalSummary?.note_count ?? learningNotes.length}</strong>
