              <strong>{learningLocalSummary?.review_card_count ?? spacedReviewCards.length}</strong>
              <small>review cards</small>
            </div>
            <div>
              <strong>{learningLocalSummary?.due_review_card_count ?? dueSpacedReviewCards.length}</strong>
              <small>due cards</small>
            </div>
            <div>
              <strong>{learningLocalSummary?.pomodoro_session_count ?? pomodoroSessions.length}</strong>
              <small>focus sessions</small>
            </div>
            <div>
              <strong>{learningLocalSummary?.focus_minutes_total ?? pomodoroCompletedMinutes}</strong>
              <small>focus minutes</small>
            </div>
            <div>
              <strong>{learningLocalSummary?.graph_node_count ?? learningGraph?.nodes.length ?? 0}</strong>
              <small>graph nodes</small>
            </div>
            <div>
              <strong>{learningLocalSummary?.graph_edge_count ?? learningGraph?.edges.length ?? 0}</strong>
              <small>graph links</small>
            </div>
          </div>
          <small class="format-hint">
            Last note {learningLocalSummary?.last_note_updated_at ?? "never"} · last focus {learningLocalSummary?.last_session_ended_at ?? "never"} · note bodies exported: {learningLocalSummary?.includes_note_bodies ? "yes" : "no"} · source URLs exported: {learningLocalSummary?.includes_source_urls ? "yes" : "no"}
          </small>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" disabled={!learningLocalSummary?.tag_counts.length} on:click={() => copyLearningLocalSummaryFields("tag")}>Copy tags</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.note_source_status_counts.length} on:click={() => copyLearningLocalSummaryFields("note-source")}>Copy note sources</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.note_timestamp_status_counts.length} on:click={() => copyLearningLocalSummaryFields("note-time")}>Copy note times</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.review_tag_counts.length} on:click={() => copyLearningLocalSummaryFields("review-tag")}>Copy review tags</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.pomodoro_status_counts.length} on:click={() => copyLearningLocalSummaryFields("focus-status")}>Copy focus states</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.pomodoro_source_status_counts.length} on:click={() => copyLearningLocalSummaryFields("focus-source")}>Copy focus sources</button>
            <button class="small-button" type="button" disabled={!learningLocalSummary?.review_notes.length} on:click={() => copyLearningLocalSummaryFields("note")}>Copy notes</button>
          </div>
          <div class="setting-control wide-control stacked-control compact-export-control">
            <div class="search-row">
              <input bind:value={learningSummaryExportPath} placeholder="C:/Exports/fetchdock-learning-summary.json" spellcheck="false" aria-label="Learning summary export path" />
              <button class="icon-button" type="button" title="Choose learning summary export" disabled={learningLocalSummaryBusy} on:click={async () => {
                learningLocalSummaryBusy = true;
                try {
                  const selected = await save({
                    title: "Export learning summary",
                    defaultPath: learningSummaryExportPath.trim() || "fetchdock-learning-summary.json",
                    filters: [{ name: "JSON", extensions: ["json"] }]
                  });
                  if (selected) learningSummaryExportPath = selected;
                } finally {
                  learningLocalSummaryBusy = false;
                }
              }}>
                <FolderOpen size={16} />
              </button>
              <button class="secondary-button compact-button" type="button" disabled={learningLocalSummaryBusy} on:click={exportLearningSummary}>
                {learningLocalSummaryBusy ? "Exporting" : "Export summary"}
              </button>
            </div>
            <div class="section-actions compact-toolbar">
              <button class="small-button" type="button" disabled={!learningSummaryExportResult && !learningSummaryExportPath.trim()} on:click={() => openLocalPath(learningSummaryExportResult || learningSummaryExportPath, "Learning summary")}>Open</button>
              <button class="small-button" type="button" disabled={!learningSummaryExportResult && !learningSummaryExportPath.trim()} on:click={() => revealLocalPath(learningSummaryExportResult || learningSummaryExportPath, "Learning summary")}>Reveal</button>
              {#if learningSummaryExportResult}
                <small>Last export: {learningSummaryExportResult}</small>
              {/if}
            </div>
          </div>
        </div>
        <div class="panel learning-dashboard-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Progress</p>
              <h2>Dashboard</h2>
            </div>
            <div class="section-actions compact-actions">
              <strong>{learningDashboard?.current_streak_days ?? 0} day</strong>
              <button class="small-button" type="button" disabled={!learningDashboard} on:click={copyLearningDashboardSummary}>
                Copy dashboard
              </button>
              <button class="small-button" type="button" disabled={!learningDashboard} on:click={copyLearningDashboardJson}>
                Copy JSON
              </button>
            </div>
          </div>
          <div class="setting-control wide-control stacked-control compact-export-control">
            <div class="search-row">
              <input bind:value={learningDashboardExportPath} placeholder="C:/Exports/fetchdock-learning-dashboard.json" spellcheck="false" aria-label="Learning dashboard export path" />
              <button class="icon-button" type="button" title="Choose dashboard export" disabled={Boolean(learningDashboardExportBusy)} on:click={chooseLearningDashboardExportPath}>
                <FolderOpen size={16} />
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(learningDashboardExportBusy)} on:click={exportLearningDashboardFile}>
                {learningDashboardExportBusy === "export" ? "Exporting" : "Export dashboard"}
              </button>
            </div>
            {#if learningDashboardExportResult}
              <div class="section-actions compact-toolbar">
                <small>{learningDashboardExportResult.heatmap_days} heatmap day{learningDashboardExportResult.heatmap_days === 1 ? "" : "s"} exported · {learningDashboardExportResult.archive_path}</small>
                <button class="small-button" type="button" disabled={Boolean(learningDashboardExportBusy)} on:click={openLearningDashboardExportResult}>Open export</button>
                <button class="small-button" type="button" disabled={Boolean(learningDashboardExportBusy)} on:click={revealLearningDashboardExportResult}>Reveal export</button>
              </div>
            {/if}
          </div>
          <div class="learning-stat-grid">
            <div>
              <strong>{learningDashboard?.note_count ?? learningNotes.length}</strong>
              <small>notes</small>
            </div>
            <div>
              <strong>{learningDashboard?.completed_session_count ?? pomodoroCompletedCount}</strong>
              <small>focus sessions</small>
            </div>
            <div>
              <strong>{learningDashboard?.completed_minutes ?? pomodoroCompletedMinutes}</strong>
              <small>focus minutes</small>
            </div>
            <div>
              <strong>{learningDashboard?.active_day_count_30d ?? 0}</strong>
              <small>active days</small>
            </div>
            <div>
              <strong>{learningDashboard?.course_progress_count ?? 0}</strong>
              <small>course lessons</small>
            </div>
            <div>
              <strong>{learningDashboard?.reading_progress_count ?? 0}</strong>
              <small>reading items</small>
            </div>
            <div>
              <strong>{learningDashboard?.reading_annotation_count ?? 0}</strong>
              <small>annotations</small>
            </div>
            <div>
              <strong>{learningDashboard?.music_play_count ?? 0}</strong>
              <small>music plays</small>
            </div>
            <div>
              <strong>{learningDashboard?.music_played_minutes ?? 0}</strong>
              <small>music minutes</small>
            </div>
            <div>
              <strong>{learningDashboard?.today_focus_minutes ?? 0}/{learningDashboard?.daily_goal_minutes ?? (Number(learningDailyGoalInput) || 25)}</strong>
              <small>{learningDashboard?.daily_goal_met ? "goal met" : "daily goal"}</small>
            </div>
          </div>
          <div class="setting-control wide-control stacked-control compact-export-control">
            <div class="search-row">
              <input bind:value={learningDailyGoalInput} inputmode="numeric" aria-label="Daily focus goal minutes" />
              <button class="secondary-button" type="button" disabled={learningBusy} on:click={saveLearningDailyGoal}>Save goal</button>
            </div>
            <div class="search-row">
              <input bind:value={learningDailyGoalExportPath} placeholder="C:/Exports/fetchdock-daily-goal.json" spellcheck="false" aria-label="Daily goal export path" />
              <button class="icon-button" type="button" title="Choose daily goal export" disabled={Boolean(learningDailyGoalTransferBusy)} on:click={chooseLearningDailyGoalExportPath}>
                <FolderOpen size={16} />
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(learningDailyGoalTransferBusy)} on:click={exportLearningDailyGoalFile}>
                {learningDailyGoalTransferBusy === "export" ? "Exporting" : "Export goal"}
              </button>
            </div>
            <div class="search-row">
              <input bind:value={learningDailyGoalImportPath} placeholder="C:/Exports/fetchdock-daily-goal.json" spellcheck="false" aria-label="Daily goal import path" />
              <button class="icon-button" type="button" title="Choose daily goal JSON" disabled={Boolean(learningDailyGoalTransferBusy)} on:click={chooseLearningDailyGoalImportFile}>
                <FolderOpen size={16} />
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(learningDailyGoalTransferBusy) || !learningDailyGoalImportPath.trim()} on:click={importLearningDailyGoalFile}>
                {learningDailyGoalTransferBusy === "import" ? "Importing" : "Import goal"}
              </button>
            </div>
            {#if learningDailyGoalExportResult}
              <div class="section-actions compact-toolbar">
                <small>{learningDailyGoalExportResult.focus_minutes} focus minutes exported · {learningDailyGoalExportResult.output_path}</small>
                <button class="small-button" type="button" disabled={Boolean(learningDailyGoalTransferBusy)} on:click={openLearningDailyGoalExportResult}>Open export</button>
                <button class="small-button" type="button" disabled={Boolean(learningDailyGoalTransferBusy)} on:click={revealLearningDailyGoalExportResult}>Reveal export</button>
              </div>
            {/if}
            <small class="format-hint">Daily goal backup stores only the local target minutes, not notes, sessions, URLs, files, Cookie values, or activity history.</small>
          </div>
          <div class="learning-heatmap-frame">
            <div class="learning-heatmap-months" aria-hidden="true">
              {#each learningHeatmapMonthLabels as month}
                <span style={`grid-column: ${month.column};`}>{month.label}</span>
              {/each}
            </div>
            <div class="learning-heatmap-body">
              <div class="learning-heatmap-weekdays" aria-hidden="true">
                {#each learningHeatmapWeekdayLabels as weekday}
                  <span style={`grid-row: ${weekday.row};`}>{weekday.label}</span>
                {/each}
              </div>
              <div class="learning-heatmap year-heatmap" aria-label="Year-style learning activity">
                {#each learningDashboard?.heatmap ?? [] as day}
                  <span
                    title={`${day.date}: ${day.activity_count} activities, ${day.focus_minutes} minutes`}
                    class:level-one={day.activity_count > 0}
                    class:level-two={day.activity_count > 1 || day.focus_minutes >= 25}
                    class:level-three={day.activity_count > 3 || day.focus_minutes >= 60}
                  ></span>
                {/each}
              </div>
            </div>
          </div>
          <small class="format-hint">
            {learningDashboard?.active_day_count_30d ?? 0} active day{(learningDashboard?.active_day_count_30d ?? 0) === 1 ? "" : "s"} in the last 30 days · longest streak {learningDashboard?.longest_streak_days ?? 0} day{(learningDashboard?.longest_streak_days ?? 0) === 1 ? "" : "s"}.
          </small>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" disabled={!learningDashboard?.heatmap.length} on:click={() => copyLearningHeatmapFields("date")}>
              Copy dates
            </button>
            <button class="small-button" type="button" disabled={!learningDashboard?.heatmap.some((day) => day.activity_count > 0 || day.focus_minutes > 0)} on:click={() => copyLearningHeatmapFields("active")}>
              Copy active days
            </button>
            <button class="small-button" type="button" disabled={!learningDashboard?.heatmap.some((day) => day.focus_minutes > 0)} on:click={() => copyLearningHeatmapFields("focus")}>
              Copy focus days
            </button>
          </div>
          <small class="format-hint">
            Knowledge graph: {learningGraph?.nodes.length ?? 0} node{(learningGraph?.nodes.length ?? 0) === 1 ? "" : "s"} · {learningGraph?.edges.length ?? 0} link{(learningGraph?.edges.length ?? 0) === 1 ? "" : "s"}.
          </small>
          <div class="setting-control wide-control stacked-control compact-export-control">
            <div class="search-row">
              <input bind:value={learningGraphExportPath} placeholder="C:/Exports/fetchdock-learning-graph.json" spellcheck="false" aria-label="Learning graph export path" />
              <button class="icon-button" type="button" title="Choose graph export" disabled={Boolean(learningGraphExportBusy)} on:click={chooseLearningGraphExportPath}>
                <FolderOpen size={16} />
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(learningGraphExportBusy)} on:click={exportLearningGraphFile}>
                {learningGraphExportBusy === "export" ? "Exporting" : "Export graph"}
              </button>
            </div>
            {#if learningGraphExportResult}
              <div class="section-actions compact-toolbar">
                <small>{learningGraphExportResult.node_count} node{learningGraphExportResult.node_count === 1 ? "" : "s"} · {learningGraphExportResult.edge_count} link{learningGraphExportResult.edge_count === 1 ? "" : "s"} exported · {learningGraphExportResult.archive_path}</small>
                <button class="small-button" type="button" disabled={Boolean(learningGraphExportBusy)} on:click={openLearningGraphExportResult}>Open export</button>
                <button class="small-button" type="button" disabled={Boolean(learningGraphExportBusy)} on:click={revealLearningGraphExportResult}>Reveal export</button>
              </div>
            {/if}
          </div>
          {#if learningGraph?.nodes.length}
            <div class="learning-graph-map" aria-label="Knowledge graph preview">
              {#if learningGraphPreview.nodes.length}
                <svg class="learning-graph-canvas" viewBox="0 0 200 200" role="img" aria-label="Knowledge graph node map">
                  {#each learningGraphPreview.edges as edge}
                    <line x1={edge.x1} y1={edge.y1} x2={edge.x2} y2={edge.y2}>
                      <title>{edge.label}</title>
                    </line>
                  {/each}
                  {#each learningGraphPreview.nodes as node}
                    <g transform={`translate(${node.x} ${node.y})`}>
                      <title>{node.title}</title>
                      <circle r={node.backlink_count > 0 ? 9 : 7}></circle>
                      <text y="23">{node.title.length > 12 ? `${node.title.slice(0, 12)}...` : node.title}</text>
                    </g>
                  {/each}
                </svg>
              {/if}
              <div class="learning-graph-nodes">
                {#each visibleLearningGraphNodes(learningGraph) as node}
                  <button type="button" class:linked={node.backlink_count > 0 || learningGraph.edges.some((edge) => edge.source_id === node.id)} on:click={() => focusLearningGraphNode(node)}>
                    <strong>{node.title}</strong>
                    <small>{node.backlink_count} backlink{node.backlink_count === 1 ? "" : "s"}</small>
                  </button>
                {/each}
              </div>
              <div class="course-list-toolbar compact-toolbar">
                <small>{visibleLearningGraphNodes(learningGraph).length} shown of {learningGraph.nodes.length} graph node{learningGraph.nodes.length === 1 ? "" : "s"}</small>
                <button class="small-button" type="button" on:click={copyVisibleLearningGraphSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" on:click={copyVisibleLearningGraphJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" on:click={() => copyVisibleLearningGraphFields("node")}>
                  Copy nodes
                </button>
              </div>
              {#if learningGraph.nodes.length > 10}
                <div class="course-list-toolbar compact-toolbar">
                  <button class="small-button" type="button" on:click={() => (learningGraphNodesExpanded = !learningGraphNodesExpanded)}>
                    {learningGraphNodesExpanded ? "Collapse nodes" : "Show all nodes"}
                  </button>
                </div>
              {/if}
              {#if learningGraph.edges.length}
                <div class="learning-graph-edges">
                  {#each visibleLearningGraphEdges(learningGraph, 8) as edge}
                    {@const source = learningGraph.nodes.find((node) => node.id === edge.source_id)}
                    {@const target = learningGraph.nodes.find((node) => node.id === edge.target_id)}
                    <span>{source?.title ?? edge.source_id} -> {target?.title ?? edge.target_id}</span>
                  {/each}
                </div>
                <div class="course-list-toolbar compact-toolbar">
                  <small>{visibleLearningGraphEdges(learningGraph, 8).length} shown of {learningGraph.edges.length} graph link{learningGraph.edges.length === 1 ? "" : "s"}</small>
                  <button class="small-button" type="button" on:click={() => copyVisibleLearningGraphFields("link")}>
                    Copy links
                  </button>
                </div>
                {#if learningGraph.edges.length > 8}
                  <div class="course-list-toolbar compact-toolbar">
                    <button class="small-button" type="button" on:click={() => (learningGraphEdgesExpanded = !learningGraphEdgesExpanded)}>
                      {learningGraphEdgesExpanded ? "Collapse links" : "Show all links"}
                    </button>
                  </div>
                {/if}
              {/if}
            </div>
          {/if}
          {#if learningGraph?.edges.length}
            <div class="learning-graph-list">
              {#each visibleLearningGraphEdges(learningGraph, 6) as edge}
                {@const source = learningGraph.nodes.find((node) => node.id === edge.source_id)}
                {@const target = learningGraph.nodes.find((node) => node.id === edge.target_id)}
                <span>{source?.title ?? edge.source_id} -> {target?.title ?? edge.target_id}</span>
              {/each}
            </div>
          {/if}
        </div>
        <div class="panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Pomodoro</p>
              <h2>Focus sessions</h2>
            </div>
            <strong>{pomodoroTimerLabel}</strong>
          </div>
          <div class="pomodoro-timer">
            <div>
              <strong>{pomodoroTimerRunning ? "Focus running" : "Focus timer"}</strong>
              <small>{pomodoroCompletedMinutes} recorded min · {pomodoroTimerProgress}% current session</small>
            </div>
            <progress max="100" value={pomodoroTimerProgress}></progress>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={pomodoroTimerRunning} on:click={startPomodoroTimer}>Start</button>
              <button class="secondary-button compact-button" type="button" disabled={!pomodoroTimerRunning} on:click={pausePomodoroTimer}>Pause</button>
              <button class="secondary-button compact-button" type="button" on:click={resetPomodoroTimer}>Reset</button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Record session</strong>
              <small>{pomodoroCompletedCount} completed session{pomodoroCompletedCount === 1 ? "" : "s"}. Timer completion pauses current media.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={pomodoroLabel} placeholder="Label, optional" spellcheck="false" aria-label="Pomodoro label" />
              <div class="two-column-inputs">
                <input bind:value={pomodoroDuration} inputmode="numeric" aria-label="Focus minutes" />
                <input bind:value={pomodoroBreak} inputmode="numeric" aria-label="Break minutes" />
              </div>
              <input bind:value={pomodoroSourceUrl} placeholder="Linked source URL, optional" spellcheck="false" aria-label="Pomodoro source URL" />
              <label class="checkbox-control">
                <input type="checkbox" bind:checked={pomodoroCompleted} />
                <span>Completed</span>
              </label>
              <button class="secondary-button" type="button" disabled={learningBusy} on:click={recordPomodoroSession}>Record session</button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Import / export focus</strong>
              <small>Local JSON backup for the currently visible focus sessions.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="search-row">
                <input bind:value={pomodoroSessionsExportPath} placeholder="C:/Exports/fetchdock-focus-sessions.json" spellcheck="false" aria-label="Focus sessions export path" />
                <button class="icon-button" type="button" title="Choose focus sessions export" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy)} on:click={choosePomodoroSessionsExportPath}>
                  <FolderOpen size={16} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy) || visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={exportVisiblePomodoroSessions}>
                  {pomodoroSessionsTransferBusy === "export" ? "Exporting" : "Export shown"}
                </button>
              </div>
              <div class="search-row">
                <input bind:value={pomodoroSessionsImportPath} placeholder="C:/Exports/fetchdock-focus-sessions.json" spellcheck="false" aria-label="Focus sessions import path" />
                <button class="icon-button" type="button" title="Choose focus sessions JSON" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy)} on:click={choosePomodoroSessionsImportFile}>
                  <FolderOpen size={16} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy) || !pomodoroSessionsImportPath.trim()} on:click={importPomodoroSessionsFile}>
                  {pomodoroSessionsTransferBusy === "import" ? "Importing" : "Import JSON"}
                </button>
              </div>
              {#if pomodoroSessionsExportResult}
                <div class="section-actions compact-toolbar">
                  <small>{pomodoroSessionsExportResult.exported_count} session{pomodoroSessionsExportResult.exported_count === 1 ? "" : "s"} exported · {pomodoroSessionsExportResult.output_path}</small>
                  <button class="small-button" type="button" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy)} on:click={openPomodoroSessionsExportResult}>Open export</button>
                  <button class="small-button" type="button" disabled={learningBusy || Boolean(pomodoroSessionsTransferBusy)} on:click={revealPomodoroSessionsExportResult}>Reveal export</button>
                </div>
              {/if}
            </div>
          </div>
        </div>

        <div class="panel learning-notes-panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Saved notes</h2>
              <p>{filteredLearningNotes.length} shown of {learningNotes.length} local note{learningNotes.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={copyFilteredLearningNoteSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={copyFilteredLearningNoteJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!filteredLearningNotes.some((note) => note.source_url)} on:click={() => copyFilteredLearningNoteFields("source")}>
                Copy sources
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={() => copyFilteredLearningNoteFields("id")}>
                Copy ids
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={() => copyFilteredLearningNoteFields("title")}>
                Copy titles
              </button>
              <button class="small-button" type="button" disabled={!filteredLearningNotes.some((note) => note.tags.length)} on:click={() => copyFilteredLearningNoteFields("tag")}>
                Copy tags
              </button>
              <button class="small-button" type="button" disabled={!filteredLearningNotes.some((note) => note.timestamp_seconds !== null && note.timestamp_seconds !== undefined)} on:click={() => copyFilteredLearningNoteFields("timestamp")}>
                Copy times
              </button>
              <button class="small-button" type="button" disabled={!filteredLearningNotes.some((note) => note.outgoing_links.length)} on:click={() => copyFilteredLearningNoteFields("link")}>
                Copy links
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={() => copyFilteredLearningNoteFields("created")}>
                Copy created
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={() => copyFilteredLearningNoteFields("updated")}>
                Copy updated
              </button>
              <button class="small-button" type="button" disabled={filteredLearningNotes.length === 0} on:click={() => copyFilteredLearningNoteFields("backlink")}>
                Copy backlinks
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={learningBusy || filteredLearningNotes.length === 0} on:click={requestFilteredLearningNotesRemove}>
                Remove filtered
              </button>
              <button class="small-button danger" type="button" disabled={learningBusy || learningNotes.length === 0} on:click={requestLearningNotesClear}>
                Clear notes
              </button>
            </div>
          </div>
          <div class="channel-list">
            {#if learningNotes.length === 0}
              <p class="muted">Saved notes will appear here.</p>
            {:else if filteredLearningNotes.length === 0}
              <p class="muted">No notes match the current filters.</p>
            {:else}
              {#each filteredLearningNotes as note}
                <article class="channel-card learning-note-card">
                  <div>
                    <strong>{note.title}</strong>
                    <small>{note.updated_at}{note.source_url ? ` · ${note.source_url}` : ""}</small>
                    <p>{note.body}</p>
                    {#if note.outgoing_links.length || note.backlink_count}
                      <small>
                        {note.outgoing_links.length ? `Links: ${note.outgoing_links.join(", ")}` : "No outgoing links"}
                        · {note.backlink_count} backlink{note.backlink_count === 1 ? "" : "s"}
                      </small>
                    {/if}
                    {#if note.tags.length}
                      <small>{note.tags.map((tag) => `#${tag}`).join(" ")}</small>
                    {/if}
                  </div>
                  <div class="section-actions">
                    {#if note.source_url}
                      <button class="small-button" type="button" disabled={learningBusy} on:click={() => openLearningNoteSource(note)}>Open source</button>
                    {/if}
                    <button class="small-button" type="button" disabled={learningBusy} on:click={() => editLearningNoteItem(note)}>Edit</button>
                    <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => fillSpacedReviewCardFromNote(note)}>Draft</button>
                    <button class="small-button" type="button" disabled={Boolean(spacedReviewBusy)} on:click={() => saveSpacedReviewCardFromNote(note)}>
                      {spacedReviewBusy === `note:${note.id}` ? "Saving" : "Review"}
                    </button>
                    <button class="small-button danger" type="button" disabled={learningBusy} on:click={() => removeLearningNoteItem(note)}>Delete</button>
                  </div>
                </article>
              {/each}
