              </button>
              <button class="small-button" type="button" disabled={visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={() => copyVisiblePomodoroSessionFields("duration")}>
                Copy durations
              </button>
              <button class="small-button" type="button" disabled={visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={() => copyVisiblePomodoroSessionFields("break")}>
                Copy breaks
              </button>
              <button class="small-button" type="button" disabled={visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={() => copyVisiblePomodoroSessionFields("status")}>
                Copy statuses
              </button>
              <button class="small-button" type="button" disabled={visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={() => copyVisiblePomodoroSessionFields("started")}>
                Copy starts
              </button>
              <button class="small-button" type="button" disabled={visiblePomodoroSessions(filteredPomodoroSessions).length === 0} on:click={() => copyVisiblePomodoroSessionFields("ended")}>
                Copy ends
              </button>
