            {:else}
              {#if filteredPomodoroSessions.length > 12 && !pomodoroSessionSearch.trim() && pomodoroSessionStatusFilter === "all"}
                <div class="course-list-toolbar compact-toolbar">
                  <small>Showing {visiblePomodoroSessions(filteredPomodoroSessions).length} of {filteredPomodoroSessions.length} focus session{filteredPomodoroSessions.length === 1 ? "" : "s"}</small>
                  <button class="small-button" type="button" on:click={() => (pomodoroSessionsExpanded = !pomodoroSessionsExpanded)}>
                    {pomodoroSessionsExpanded ? "Collapse sessions" : "Show all sessions"}
                  </button>
                </div>
              {/if}
              {#each visiblePomodoroSessions(filteredPomodoroSessions) as session}
                <article class="channel-card compact-card">
                  <div>
                    <strong>{session.label}</strong>
                    <small>{session.duration_minutes} min focus · {session.break_minutes} min break · {session.completed ? "completed" : "open"}</small>
                    <small>{session.started_at}</small>
                    {#if session.linked_source_url}
                      <small>{session.linked_source_url}</small>
                    {/if}
                  </div>
                  <div class="section-actions">
                    {#if session.linked_source_url}
                      <button class="small-button" type="button" disabled={learningBusy} on:click={() => openSourceUrl(session.linked_source_url ?? "", session.label)}>
