              </div>
              <div class="path-picker-row">
                <input bind:value={telegramStateImportPath} placeholder="C:/Exports/fetchdock-telegram-state.json" spellcheck="false" aria-label="Telegram state import path" />
                <button class="icon-button" type="button" title="Choose Telegram state backup" disabled={telegramBusy || Boolean(telegramStateTransferBusy)} on:click={chooseTelegramStateImportFile}>
                  <FolderOpen size={17} />
                </button>
