            <p class="muted">Phone hint: {telegramState.phone_hint}</p>
          {/if}
          {#if telegramError || telegramState?.last_error}
            <p class="error-text">{telegramError || telegramState?.last_error}</p>
          {/if}
        </div>
        <div class="panel">
