                <article>
                  <strong>Manifest</strong>
                  <small>{telegramSyncStatus.last_manifest_updated_at}</small>
                </article>
              {/if}
            </div>
          {:else}
            <p class="muted">Local manifest sync summary is available inside the desktop runtime.</p>
          {/if}
