                    type="checkbox"
                    checked={telegramCloneMediaTypes.includes(mediaType)}
                    on:change={() => toggleTelegramCloneMediaType(mediaType)}
                  />
                  <span>{mediaType}</span>
                </label>
              {/each}
            </div>
            <label>
              <span>Limit</span>
              <input bind:value={telegramCloneLimit} inputmode="numeric" placeholder="100" aria-label="Telegram clone item limit" />
            </label>
          </div>
          {#if telegramCloneResult}
            <div class="telegram-clone-summary">
              <strong>{telegramCloneResult.chat.title}</strong>
              <small>{telegramCloneResult.created.length} queued · {telegramCloneResult.skipped.length} skipped</small>
              {#if telegramCloneResult.skipped.length > 0}
                <div class="telegram-media-list">
                  {#each telegramCloneResult.skipped.slice(0, 5) as skipped}
                    <div>
                      <span>
                        <strong>{skipped.title}</strong>
                        <small>{skipped.reason}</small>
                      </span>
                    </div>
                  {/each}
                </div>
              {/if}
            </div>
          {/if}
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local transfers</p>
              <h2>Transfer panel</h2>
            </div>
            <button class="secondary-button compact-button" type="button" on:click={() => { void loadDownloads(); void loadTelegramSyncStatus(); void loadTelegramLocalSummary(); }}>Refresh</button>
          </div>
          <div class="library-filter-row transfer-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={telegramTransferSearch} placeholder="Title, URL, output path, or error" spellcheck="false" aria-label="Telegram transfer search" />
            </label>
            <label>
              <span>Status</span>
              <select bind:value={telegramTransferStatusFilter} aria-label="Telegram transfer status filter">
                <option value="all">All status</option>
                <option value="queued">Queued</option>
                <option value="active">Active</option>
                <option value="paused">Paused</option>
                <option value="completed">Completed</option>
                <option value="failed">Failed</option>
                <option value="canceled">Canceled</option>
                <option value="archived">Archived</option>
              </select>
            </label>
          </div>
          {#if telegramTransferTasks.length === 0}
            <p class="muted">Queued Telegram media transfers will appear here after you queue media or run the clone wizard.</p>
          {:else if filteredTelegramTransferTasks.length === 0}
            <p class="muted">No Telegram transfers match the current filters.</p>
          {:else}
            <div class="course-list-toolbar">
              <small class="format-hint">
                {visibleTelegramTransferTasks(filteredTelegramTransferTasks).length} shown of {telegramTransferTasks.length} local transfer task{telegramTransferTasks.length === 1 ? "" : "s"}.
              </small>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskSummary(visibleTelegramTransferTasks(filteredTelegramTransferTasks), "Telegram transfer")}>
                Copy summary
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskJson(visibleTelegramTransferTasks(filteredTelegramTransferTasks), "Telegram transfer", { search: telegramTransferSearch, status: telegramTransferStatusFilter })}>
                Copy JSON
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleTelegramTransferTasks(filteredTelegramTransferTasks), "source", "Telegram transfer")}>
                Copy sources
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleTelegramTransferTasks(filteredTelegramTransferTasks), "output", "Telegram transfer")}>
                Copy outputs
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferStartableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("start", visibleTelegramTransferStartableTasks, "Telegram transfers")}
              >
                Start shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferActiveTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("pause", visibleTelegramTransferActiveTasks, "Telegram transfers")}
              >
                Pause shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferPausedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("resume", visibleTelegramTransferPausedTasks, "Telegram transfers")}
              >
                Resume shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferFailedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("retry", visibleTelegramTransferFailedTasks, "Telegram transfers")}
              >
                Retry shown
              </button>
              <button
                class="small-button danger"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferCancelableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("cancel", visibleTelegramTransferCancelableTasks, "Telegram transfers")}
              >
                Cancel shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferArchivableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("archive", visibleTelegramTransferArchivableTasks, "Telegram transfers")}
              >
                Archive shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTelegramTransferRestorableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("restore", visibleTelegramTransferRestorableTasks, "Telegram transfers")}
              >
                Restore shown
              </button>
              {#if filteredTelegramTransferTasks.length > 10 && !telegramTransferSearch.trim() && telegramTransferStatusFilter === "all"}
                <button class="small-button" type="button" on:click={() => (telegramTransfersExpanded = !telegramTransfersExpanded)}>
                  {telegramTransfersExpanded ? "Collapse transfers" : "Show all transfers"}
                </button>
              {/if}
            </div>
            <div class="telegram-media-list transfer-task-list">
              {#each visibleTelegramTransferTasks(filteredTelegramTransferTasks) as task}
                <div>
                  <span>
                    <strong>{task.title}</strong>
                    <small>{task.status} · {formatProgress(task)}</small>
                    {#if task.output_path}
                      <small>Saved to {task.output_path}</small>
                    {:else if task.output_dir}
                      <small>Output folder {task.output_dir}</small>
                    {/if}
                    {#if task.last_error}
                      <small class="error-text">{task.last_error}</small>
                    {/if}
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" disabled={!canStartTask(task) || activeTaskIds.has(task.id)} on:click={() => startTask(task)}>
                      Start
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "active"} on:click={() => pauseTask(task)}>
                      Pause
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "paused"} on:click={() => resumeTask(task)}>
                      Resume
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "failed" && task.status !== "canceled"} on:click={() => retryTask(task)}>
                      Retry
                    </button>
                    <button class="small-button" type="button" disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"} on:click={() => cancelTask(task)}>
                      Cancel
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_path} on:click={() => revealTaskFile(task)}>
                      Reveal
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_dir && !task.output_path} on:click={() => openTaskFolder(task)}>
                      Open
                    </button>
                    <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                      Source
                    </button>
                    <button class="small-button" type="button" on:click={() => focusDownloadTaskById(task.id, task.title)}>
                      Detail
                    </button>
                    <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                      Logs
                    </button>
                    {#if task.status === "archived"}
                      <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                    {:else if ["completed", "failed", "canceled"].includes(task.status)}
                      <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                    {/if}
                  </div>
                </div>
              {/each}
            </div>
          {/if}
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Chat browser</h2>
              <p>{filteredTelegramChats.length} shown of {telegramChats.length} imported chat{telegramChats.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={telegramBusy || queueableTelegramMedia(filteredTelegramMediaItems).length === 0 || telegramMediaBusy === "queue-filtered"} on:click={() => queueTelegramMediaBatch(filteredTelegramMediaItems, "queue-filtered")}>
                {telegramMediaBusy === "queue-filtered" ? "Queueing" : "Queue filtered"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={telegramBusy || localCopyableTelegramMedia(filteredTelegramMediaItems).length === 0 || telegramMediaBusy === "copy-filtered"} on:click={() => copyTelegramLocalMediaBatch(filteredTelegramMediaItems, "copy-filtered")}>
                {telegramMediaBusy === "copy-filtered" ? "Saving" : "Save filtered"}
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={copyVisibleTelegramSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={copyVisibleTelegramJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!visibleTelegramChats(filteredTelegramChats).some((chat) => visibleTelegramMedia(chat).some((media) => media.source_url))} on:click={() => copyVisibleTelegramMediaFields("source")}>
                Copy source URLs
              </button>
              <button class="small-button" type="button" disabled={!visibleTelegramChats(filteredTelegramChats).some((chat) => visibleTelegramMedia(chat).some((media) => media.local_path))} on:click={() => copyVisibleTelegramMediaFields("local")}>
                Copy local paths
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={() => copyVisibleTelegramMediaFields("chat-id")}>
                Copy chat ids
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={() => copyVisibleTelegramMediaFields("chat-title")}>
                Copy chat titles
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={() => copyVisibleTelegramMediaFields("chat-kind")}>
                Copy chat types
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={() => copyVisibleTelegramMediaFields("chat-count")}>
                Copy media counts
              </button>
              <button class="small-button" type="button" disabled={!visibleTelegramChats(filteredTelegramChats).some((chat) => chat.last_message_at)} on:click={() => copyVisibleTelegramMediaFields("chat-last")}>
                Copy last messages
              </button>
              <button class="small-button" type="button" disabled={visibleTelegramChats(filteredTelegramChats).length === 0} on:click={() => copyVisibleTelegramMediaFields("chat-updated")}>
                Copy chat updated
              </button>
              <button class="small-button" type="button" disabled={!visibleTelegramChats(filteredTelegramChats).some((chat) => chat.username)} on:click={() => copyVisibleTelegramMediaFields("username")}>
                Copy usernames
              </button>
              <button class="small-button" type="button" disabled={filteredTelegramMediaItems.length === 0} on:click={() => copyVisibleTelegramMediaFields("media-id")}>
                Copy media ids
              </button>
              <button class="small-button" type="button" disabled={filteredTelegramMediaItems.length === 0} on:click={() => copyVisibleTelegramMediaFields("media-title")}>
                Copy media titles
              </button>
              <button class="small-button" type="button" disabled={filteredTelegramMediaItems.length === 0} on:click={() => copyVisibleTelegramMediaFields("media-type")}>
                Copy media types
              </button>
              <button class="small-button" type="button" disabled={!filteredTelegramMediaItems.some((media) => media.size_bytes)} on:click={() => copyVisibleTelegramMediaFields("media-size")}>
                Copy media sizes
              </button>
              <button class="small-button" type="button" disabled={!filteredTelegramMediaItems.some((media) => media.created_at)} on:click={() => copyVisibleTelegramMediaFields("media-created")}>
                Copy media created
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={telegramBusy || filteredTelegramMediaItems.length === 0 || telegramMediaBusy === "remove-filtered"} on:click={() => requestTelegramMediaBatchRemove(filteredTelegramMediaItems, "filtered media", "remove-filtered")}>
                {telegramMediaBusy === "remove-filtered" ? "Removing" : "Remove filtered"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={telegramBusy || visibleTelegramChats(filteredTelegramChats).length === 0} on:click={requestFilteredTelegramChatsRemove}>
                Remove filtered chats
              </button>
              <button class="secondary-button compact-button" type="button" disabled={telegramBusy || telegramChats.length === 0 || telegramMediaBusy === "prune-missing"} on:click={pruneMissingTelegramLocalMedia}>
                {telegramMediaBusy === "prune-missing" ? "Pruning" : "Prune missing"}
              </button>
              <button class="small-button danger" type="button" disabled={telegramBusy || telegramChats.length === 0} on:click={requestTelegramChatsClear}>
                Clear imported
              </button>
            </div>
          </div>
          <div class="library-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={telegramBrowserSearch} placeholder="Chat, username, title, URL, path" spellcheck="false" />
            </label>
            <label>
              <span>Media</span>
              <select bind:value={telegramBrowserMediaType} aria-label="Telegram media type filter">
                <option value="all">All media</option>
                {#each telegramCloneMediaTypeOptions as mediaType}
                  <option value={mediaType}>{mediaType}</option>
                {/each}
              </select>
            </label>
            <label>
              <span>Save folder</span>
              <div class="path-picker-row">
                <input bind:value={telegramLocalCopyOutputDir} placeholder="Choose folder for local media copies" spellcheck="false" aria-label="Telegram local media save folder" />
                <button class="icon-button" type="button" title="Choose Telegram local media save folder" disabled={telegramBusy} on:click={chooseTelegramLocalCopyOutputDir}>
                  <FolderOpen size={17} />
                </button>
              </div>
            </label>
          </div>
          {#if telegramChats.length === 0}
            <p class="muted">Import a local manifest to browse chats and media while MTProto transport is still in progress.</p>
          {:else if filteredTelegramChats.length === 0}
            <p class="muted">No imported Telegram media matches the current filters.</p>
          {:else}
            <div class="channel-list">
              <div class="course-list-toolbar">
                <small>
                  Showing {visibleTelegramChats(filteredTelegramChats).length} of {filteredTelegramChats.length} matching chat{filteredTelegramChats.length === 1 ? "" : "s"}
                </small>
                {#if filteredTelegramChats.length > 12 && !telegramBrowserSearch.trim() && telegramBrowserMediaType === "all"}
                  <button class="small-button" type="button" on:click={() => (telegramChatsExpanded = !telegramChatsExpanded)}>
                    {telegramChatsExpanded ? "Collapse chats" : "Show all chats"}
                  </button>
                {/if}
              </div>
              {#each visibleTelegramChats(filteredTelegramChats) as chat}
                <article class="channel-card">
                  <div>
                    <div class="section-heading compact-heading">
                      <div>
                        <strong>{chat.title}</strong>
                        <small>{chat.kind}{chat.username ? ` · @${chat.username}` : ""} · {chat.media_count} media{chat.last_message_at ? ` · ${chat.last_message_at}` : ""}</small>
                      </div>
                      <div class="section-actions">
                        <button class="small-button" type="button" disabled={queueableTelegramMedia(chat.media).length === 0 || telegramMediaBusy === `chat:${chat.id}`} on:click={() => queueTelegramChatMedia(chat)}>
                          {telegramMediaBusy === `chat:${chat.id}` ? "Queueing" : "Queue chat"}
                        </button>
                        <button class="small-button" type="button" disabled={localCopyableTelegramMedia(chat.media).length === 0 || telegramMediaBusy === `copy-chat:${chat.id}`} on:click={() => copyTelegramLocalMediaBatch(chat.media, `copy-chat:${chat.id}`)}>
                          {telegramMediaBusy === `copy-chat:${chat.id}` ? "Saving" : "Save chat"}
                        </button>
                        <button class="small-button danger" type="button" disabled={telegramBusy} on:click={() => requestTelegramChatDelete(chat)}>
                          Remove
                        </button>
                      </div>
                    </div>
                    {#if chat.media.length > 0}
                      <div class="course-list-toolbar compact-toolbar">
                        <small>
                          Showing {visibleTelegramMedia(chat).length} of {chat.media.length} media item{chat.media.length === 1 ? "" : "s"}
                        </small>
                        {#if chat.media.length > 4 && !telegramBrowserSearch.trim() && telegramBrowserMediaType === "all"}
                          <button class="small-button" type="button" on:click={() => toggleTelegramChatMedia(chat.id)}>
                            {telegramExpandedMediaChatIds[chat.id] ? "Collapse media" : "Show all media"}
                          </button>
                        {/if}
                      </div>
                      <div class="telegram-media-list">
                        {#each visibleTelegramMedia(chat) as media}
                          <div>
                            <span>
                              <strong>{media.title}</strong>
                              <small>{media.media_type} · {media.size_bytes ? formatBytes(media.size_bytes) : "size unknown"} · {media.source_url ?? media.local_path}</small>
                            </span>
                            <div class="section-actions">
                              <button class="small-button" type="button" disabled={!media.source_url || telegramMediaBusy === media.id} on:click={() => queueTelegramMediaItem(media)}>
                                Queue
                              </button>
                              {#if media.source_url}
                                <button class="small-button" type="button" on:click={() => openTelegramMediaSource(media)}>
                                  Open source
                                </button>
                              {/if}
                              <button class="small-button" type="button" disabled={!canPreviewTelegramMedia(media)} on:click={() => previewTelegramMediaItem(media)}>
                                Preview
                              </button>
                              <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:open`} on:click={() => openTelegramMediaItem(media)}>
                                Open
                              </button>
                              <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:copy`} on:click={() => copyTelegramLocalMediaItem(media)}>
                                {telegramMediaBusy === `${media.id}:copy` ? "Saving" : "Save local"}
                              </button>
                              <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:reveal`} on:click={() => revealTelegramMediaItem(media)}>
                                Reveal
                              </button>
                              <button class="small-button danger" type="button" disabled={telegramMediaBusy === `${media.id}:delete`} on:click={() => removeTelegramMediaItem(media)}>
                                Remove
                              </button>
                            </div>
                          </div>
                        {/each}
                      </div>
                    {/if}
                  </div>
                </article>
              {/each}
            </div>
          {/if}
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>Search results</h2>
              <p>{telegramSearchResults?.media.length ?? 0} matching media item{telegramSearchResults?.media.length === 1 ? "" : "s"}.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={!telegramSearchResults || queueableTelegramMedia(telegramSearchResults.media).length === 0 || telegramMediaBusy === "queue-search"} on:click={() => telegramSearchResults && queueTelegramMediaBatch(telegramSearchResults.media, "queue-search")}>
                {telegramMediaBusy === "queue-search" ? "Queueing" : "Queue results"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={!telegramSearchResults || localCopyableTelegramMedia(telegramSearchResults.media).length === 0 || telegramMediaBusy === "copy-search"} on:click={() => telegramSearchResults && copyTelegramLocalMediaBatch(telegramSearchResults.media, "copy-search")}>
                {telegramMediaBusy === "copy-search" ? "Saving" : "Save results"}
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || (telegramSearchResults.chats.length === 0 && telegramSearchResults.media.length === 0)} on:click={copyTelegramSearchResultSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || (telegramSearchResults.chats.length === 0 && telegramSearchResults.media.length === 0)} on:click={copyTelegramSearchResultJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || !telegramSearchResults.media.some((media) => media.source_url)} on:click={() => copyTelegramSearchResultFields("source")}>
                Copy source URLs
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || !telegramSearchResults.media.some((media) => media.local_path)} on:click={() => copyTelegramSearchResultFields("local")}>
                Copy local paths
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || telegramSearchResults.chats.length === 0} on:click={() => copyTelegramSearchResultFields("chat-id")}>
                Copy chat ids
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || telegramSearchResults.media.length === 0} on:click={() => copyTelegramSearchResultFields("media-id")}>
                Copy media ids
              </button>
              <button class="small-button" type="button" disabled={!telegramSearchResults || (telegramSearchResults.chats.length === 0 && telegramSearchResults.media.length === 0)} on:click={() => copyTelegramSearchResultFields("title")}>
                Copy titles
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={!telegramSearchResults || filteredTelegramSearchMediaCount === 0 || telegramMediaBusy === "remove-search"} on:click={() => telegramSearchResults && requestTelegramMediaBatchRemove(telegramSearchResults.media, "search results", "remove-search")}>
                {telegramMediaBusy === "remove-search" ? "Removing" : "Remove results"}
              </button>
            </div>
          </div>
          {#if !telegramSearchResults}
            <p class="muted">Search local imported Telegram chats or media.</p>
          {:else if telegramSearchResults.chats.length === 0 && telegramSearchResults.media.length === 0}
            <p class="muted">No local Telegram matches.</p>
          {:else}
            <div class="telegram-media-list">
              {#each telegramSearchResults.chats as chat}
                <div>
                  <span>
                    <strong>{chat.title}</strong>
                    <small>{chat.kind} · {chat.media_count} media</small>
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" on:click={() => openTelegramChatInBrowser(chat)}>
                      Open
                    </button>
                    <button class="small-button" type="button" disabled={queueableTelegramMedia(chat.media).length === 0 || telegramMediaBusy === `chat:${chat.id}`} on:click={() => queueTelegramChatMedia(chat)}>
                      {telegramMediaBusy === `chat:${chat.id}` ? "Queueing" : "Queue chat"}
                    </button>
                  </div>
                </div>
              {/each}
              {#each telegramSearchResults.media as media}
                <div>
                  <span>
                    <strong>{media.title}</strong>
                    <small>{media.media_type} · {media.source_url ?? media.local_path}</small>
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" disabled={!media.source_url || telegramMediaBusy === media.id} on:click={() => queueTelegramMediaItem(media)}>
                      Queue
                    </button>
                    {#if media.source_url}
                      <button class="small-button" type="button" on:click={() => openTelegramMediaSource(media)}>
                        Open source
                      </button>
                    {/if}
                    <button class="small-button" type="button" disabled={!canPreviewTelegramMedia(media)} on:click={() => previewTelegramMediaItem(media)}>
                      Preview
                    </button>
                    <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:open`} on:click={() => openTelegramMediaItem(media)}>
                      Open
                    </button>
                    <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:copy`} on:click={() => copyTelegramLocalMediaItem(media)}>
                      {telegramMediaBusy === `${media.id}:copy` ? "Saving" : "Save local"}
                    </button>
                    <button class="small-button" type="button" disabled={!media.local_path || telegramMediaBusy === `${media.id}:reveal`} on:click={() => revealTelegramMediaItem(media)}>
                      Reveal
                    </button>
                    <button class="small-button danger" type="button" disabled={telegramMediaBusy === `${media.id}:delete`} on:click={() => removeTelegramMediaItem(media)}>
                      Remove
                    </button>
