              <button class="small-button" type="button" disabled={!activeTelegramPreviewMedia.local_path || telegramMediaBusy === `${activeTelegramPreviewMedia.id}:reveal`} on:click={() => revealTelegramMediaItem(activeTelegramPreviewMedia)}>
