                  <button class="small-button" type="button" disabled={!toolsCommentsOutputPath.trim()} on:click={() => revealLocalPath(toolsCommentsOutputPath, "Comments")}>
                    Reveal
                  </button>
                </div>
                <div class="path-picker-row compact-path-row">
                  <input bind:value={toolsLiveChatOutputPath} placeholder="C:/FetchDock/live-chat.json" spellcheck="false" aria-label="Live chat output path" />
                  <button class="small-button" type="button" disabled={toolsLiveChatSaveBusy} on:click={chooseToolsLiveChatOutputPath}>
                    Save as
                  </button>
                  <button class="small-button" type="button" disabled={!toolsLiveChatOutputPath.trim()} on:click={() => openLocalPath(toolsLiveChatOutputPath, "Live chat")}>
                    Open file
                  </button>
                  <button class="small-button" type="button" disabled={!toolsLiveChatOutputPath.trim()} on:click={() => revealLocalPath(toolsLiveChatOutputPath, "Live chat")}>
                    Reveal
                  </button>
                </div>
                {#if toolsCommentOptions.length > 0}
