                        <small>{previewCommentText(comment.text)}</small>
                      </div>
                    {/each}
                  </div>
                  {#if toolsCommentOptions.length > 5}
                    <div class="course-list-toolbar compact-toolbar">
                      <small>{visibleToolsComments(toolsCommentOptions).length} shown of {toolsCommentOptions.length} comment{toolsCommentOptions.length === 1 ? "" : "s"}</small>
                      <button class="small-button" type="button" on:click={() => copyVisibleToolsMetadataFields("comment-id")}>
                        Copy ids
                      </button>
                      <button class="small-button" type="button" on:click={() => copyVisibleToolsMetadataFields("comment-text")}>
                        Copy text
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleToolsMetadataJson}>
                        Copy JSON
                      </button>
                      <button class="small-button" type="button" on:click={() => (toolsCommentOptionsExpanded = !toolsCommentOptionsExpanded)}>
                        {toolsCommentOptionsExpanded ? "Collapse comments" : "Show all comments"}
                      </button>
                    </div>
                  {:else}
                    <div class="course-list-toolbar compact-toolbar">
                      <button class="small-button" type="button" on:click={() => copyVisibleToolsMetadataFields("comment-id")}>
                        Copy ids
                      </button>
                      <button class="small-button" type="button" on:click={() => copyVisibleToolsMetadataFields("comment-text")}>
                        Copy text
                      </button>
                      <button class="small-button" type="button" on:click={copyVisibleToolsMetadataJson}>
                        Copy JSON
                      </button>
                    </div>
                  {/if}
                {/if}
                {#if toolsCommentsListError}
