            <div class="inline-actions">
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy)} on:click={loadPlatformMatrix}>
                {platformMatrixBusy === "load" ? "Refreshing" : "Refresh"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy)} on:click={choosePlatformMatrixExportPath}>
                {platformMatrixBusy === "choose-export" ? "Choosing" : "Save as"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy)} on:click={handleExportPlatformMatrix}>
                {platformMatrixBusy === "export" ? "Exporting" : "Export report"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy) || platformMatrix.length === 0} on:click={copyPlatformMatrixSummary}>
                Copy matrix
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy) || platformMatrix.length === 0} on:click={copyPlatformMatrixJson}>
                Copy JSON
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy) || !platformLocalSummary} on:click={copyPlatformLocalSummary}>
                Copy summary
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy) || !platformLocalSummary} on:click={copyPlatformLocalSummaryJson}>
                Copy summary JSON
              </button>
              <button class="small-button" type="button" disabled={!platformLocalSummary} on:click={() => copyPlatformLocalSummaryFields("status")}>
                Copy status counts
              </button>
              <button class="small-button" type="button" disabled={!platformLocalSummary} on:click={() => copyPlatformLocalSummaryFields("category")}>
                Copy category counts
              </button>
              <button class="small-button" type="button" disabled={!platformLocalSummary} on:click={() => copyPlatformLocalSummaryFields("route")}>
                Copy route counts
              </button>
              <button class="small-button" type="button" disabled={!platformLocalSummary} on:click={() => copyPlatformLocalSummaryFields("note")}>
                Copy notes
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy)} on:click={choosePlatformSummaryExportPath}>
                {platformMatrixBusy === "choose-summary-export" ? "Choosing" : "Save summary as"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(platformMatrixBusy)} on:click={handleExportPlatformLocalSummary}>
                {platformMatrixBusy === "export-summary" ? "Exporting" : "Export summary"}
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("route")}>
                Copy routes
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("name")}>
                Copy names
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("category")}>
                Copy categories
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("status")}>
                Copy statuses
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("evidence")}>
                Copy evidence
              </button>
              <button class="small-button" type="button" disabled={platformMatrix.length === 0} on:click={() => copyPlatformMatrixFields("limitation")}>
                Copy limits
              </button>
            </div>
          </div>
          <div class="path-picker-row compact-path-row">
            <input bind:value={platformMatrixExportPath} placeholder="C:/FetchDock/platform-matrix.json" spellcheck="false" aria-label="Platform matrix export path" />
            <button class="small-button" type="button" disabled={!platformMatrixExportPath.trim()} on:click={() => openLocalPath(platformMatrixExportPath, "Platform matrix")}>
              Open file
            </button>
            <button class="small-button" type="button" disabled={!platformMatrixExportPath.trim()} on:click={() => revealLocalPath(platformMatrixExportPath, "Platform matrix")}>
              Reveal
            </button>
          </div>
          <div class="path-picker-row compact-path-row">
            <input bind:value={platformSummaryExportPath} placeholder="C:/FetchDock/platform-summary.json" spellcheck="false" aria-label="Platform summary export path" />
            <button class="small-button" type="button" disabled={!platformSummaryExportPath.trim()} on:click={() => openLocalPath(platformSummaryExportPath, "Platform summary")}>
              Open summary
            </button>
            <button class="small-button" type="button" disabled={!platformSummaryExportPath.trim()} on:click={() => revealLocalPath(platformSummaryExportPath, "Platform summary")}>
              Reveal summary
            </button>
          </div>
          {#if platformMatrixError}
            <p class="error-text">{platformMatrixError}</p>
          {:else if platformMatrix.length === 0}
            <p class="muted">Platform route details are available inside the desktop runtime.</p>
          {:else}
            <div class="music-stats-panel">
              <div>
                <strong>{platformMatrix.length} route declarations</strong>
                <small>Shows the local route and implementation state; it is not a live site verification report.</small>
              </div>
              <div class="music-playlist-list">
                {#each visiblePlatformMatrixEntries(platformMatrix) as entry}
                  <article>
                    <div>
                      <strong>{entry.display_name}</strong>
                      <small>{entry.route} · {entry.category.replace(/_/g, " ")}</small>
                      <small>{entry.evidence.join(" · ")}</small>
                      {#if entry.limitations.length > 0}
                        <small>{entry.limitations.join(" · ")}</small>
                      {/if}
                    </div>
                    <span class="task-chip">{formatPlatformStatus(entry.status)}</span>
                  </article>
                {/each}
              </div>
              {#if platformMatrixExpanded || platformMatrix.length > visiblePlatformMatrixEntries(platformMatrix).length}
                <div class="course-list-toolbar compact-toolbar">
                  <small>{visiblePlatformMatrixEntries(platformMatrix).length} shown of {platformMatrix.length} route declaration{platformMatrix.length === 1 ? "" : "s"}</small>
                  <button class="small-button" type="button" on:click={() => (platformMatrixExpanded = !platformMatrixExpanded)}>
                    {platformMatrixExpanded ? "Show target routes" : "Show all routes"}
                  </button>
                </div>
              {/if}
            </div>
          {/if}
          <div class="music-stats-panel">
            <div>
              <strong>Route sample check</strong>
              <small>Local URL classification for target platform examples. This checks app routing only, not live site download success.</small>
              <small>Sample source: {platformRouteSampleSource}.</small>
            </div>
            <div class="course-list-toolbar compact-toolbar">
              <input bind:value={platformRouteSampleSearch} placeholder="Search sample, platform, route, or URL" spellcheck="false" aria-label="Platform route sample search" />
              <select bind:value={platformRouteSampleKindFilter} aria-label="Platform route sample kind filter">
                <option value="all">All task kinds</option>
                <option value="video">Video</option>
                <option value="playlist">Playlist</option>
                <option value="image">Image</option>
                <option value="audio">Audio</option>
                <option value="pdf">PDF</option>
                <option value="book">Book</option>
                <option value="subtitles_only">Subtitles</option>
                <option value="generic">Generic</option>
              </select>
              <button
                class="secondary-button compact-button"
                type="button"
                disabled={Boolean(platformRouteSampleQueueBusy) || filteredPlatformRouteSampleResults.length === 0}
                on:click={() => queuePlatformRouteSamples(filteredPlatformRouteSampleResults)}
              >
                {platformRouteSampleQueueBusy === "shown" ? "Queueing" : "Queue shown"}
              </button>
              <button
                class="secondary-button compact-button"
                type="button"
                disabled={filteredPlatformRouteSampleResults.length === 0}
                on:click={() => copyPlatformRouteSampleUrls(filteredPlatformRouteSampleResults)}
              >
                Copy URLs
              </button>
              <button class="secondary-button compact-button" type="button" disabled={visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length === 0} on:click={copyVisiblePlatformRouteSampleSummary}>
                Copy summary
              </button>
              <button class="secondary-button compact-button" type="button" disabled={visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length === 0} on:click={copyVisiblePlatformRouteSampleJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length === 0} on:click={() => copyPlatformRouteSampleFields("url")}>
                Copy visible URLs
              </button>
              <button class="small-button" type="button" disabled={visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length === 0} on:click={() => copyPlatformRouteSampleFields("label")}>
                Copy labels
              </button>
              <button class="small-button" type="button" disabled={!visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).some((sample) => sample.classification?.platform)} on:click={() => copyPlatformRouteSampleFields("platform")}>
                Copy platforms
              </button>
              <button class="small-button" type="button" disabled={!visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).some((sample) => sample.classification?.suggestedKind)} on:click={() => copyPlatformRouteSampleFields("kind")}>
                Copy kinds
              </button>
              <button class="small-button" type="button" disabled={!visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).some((sample) => sample.classification?.intent)} on:click={() => copyPlatformRouteSampleFields("intent")}>
                Copy intents
              </button>
              <button
                class="secondary-button compact-button"
                type="button"
                disabled={Boolean(platformMatrixBusy)}
                on:click={choosePlatformRouteSamplesExportPath}
              >
                {platformMatrixBusy === "choose-samples-export" ? "Choosing" : "Save samples as"}
              </button>
              <button
                class="secondary-button compact-button"
                type="button"
                disabled={Boolean(platformMatrixBusy)}
                on:click={handleExportPlatformRouteSamples}
              >
                {platformMatrixBusy === "export-samples" ? "Exporting" : "Export samples"}
              </button>
            </div>
            <div class="path-picker-row compact-path-row">
              <input bind:value={platformRouteSamplesExportPath} placeholder="C:/FetchDock/platform-route-samples.json" spellcheck="false" aria-label="Platform route samples export path" />
              <button class="small-button" type="button" disabled={!platformRouteSamplesExportPath.trim()} on:click={() => openLocalPath(platformRouteSamplesExportPath, "Platform route samples")}>
                Open file
              </button>
              <button class="small-button" type="button" disabled={!platformRouteSamplesExportPath.trim()} on:click={() => revealLocalPath(platformRouteSamplesExportPath, "Platform route samples")}>
                Reveal
              </button>
            </div>
            <div class="music-playlist-list">
              {#each visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults) as sample}
                <article>
                  <div>
                    <strong>{sample.label}</strong>
                    {#if sample.classification}
                      <small>{sample.classification.label} · {sample.classification.platform} · {sample.classification.intent.replace(/_/g, " ")} · {sample.classification.suggestedKind}</small>
                      <small>{sample.classification.detail}{sample.classification.subtypeLabel ? ` · ${sample.classification.subtypeLabel}` : ""}</small>
                    {:else}
                      <small class="error-text">No local route classification</small>
                    {/if}
                    <small>{sample.url}</small>
                  </div>
                  <button class="small-button" type="button" on:click={() => openSourceUrl(sample.url, sample.label)}>
                    Open sample
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={!sample.classification || Boolean(platformRouteSampleQueueBusy)}
                    on:click={() => queuePlatformRouteSamples([sample], sample.label)}
                  >
                    {platformRouteSampleQueueBusy === sample.label ? "Queueing" : "Queue"}
                  </button>
                  <span class="task-chip">{sample.classification?.kind.replace(/_/g, " ") ?? "unmatched"}</span>
                </article>
              {/each}
            </div>
            {#if filteredPlatformRouteSampleResults.length === 0}
              <p class="muted">No route samples match the current filter.</p>
            {/if}
            {#if platformRouteSamplesExpanded || filteredPlatformRouteSampleResults.length > visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length}
              <div class="course-list-toolbar compact-toolbar">
                <small>{visiblePlatformRouteSampleResults(filteredPlatformRouteSampleResults).length} shown of {filteredPlatformRouteSampleResults.length} route sample{filteredPlatformRouteSampleResults.length === 1 ? "" : "s"}</small>
                <button class="small-button" type="button" on:click={() => (platformRouteSamplesExpanded = !platformRouteSamplesExpanded)}>
                  {platformRouteSamplesExpanded ? "Collapse samples" : "Show all samples"}
                </button>
              </div>
            {/if}
          </div>
