              <button class="secondary-button compact-button" type="button" disabled={torrentBusy} on:click={runTorrentParse}>
                {torrentBusy ? "Parsing" : "Parse"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={torrentQueueBusy} on:click={queueParsedTorrentFile}>
                {torrentQueueBusy ? "Queueing" : "Queue"}
              </button>
            </div>
          </div>
          <div class="metadata-tool">
            <label class="wide-option">
              <span>Torrent file</span>
              <div class="path-picker-row">
                <input bind:value={torrentInputPath} placeholder="C:/Downloads/example.torrent" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose torrent file" disabled={torrentInputBusy} on:click={chooseTorrentInputFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!torrentInputPath.trim()} on:click={() => openLocalPath(torrentInputPath, "Torrent file")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!torrentInputPath.trim()} on:click={() => revealLocalPath(torrentInputPath, "Torrent file")}>
                  Reveal
                </button>
              </div>
            </label>
            {#if torrentError}
              <p class="error-text">{torrentError}</p>
            {/if}
            {#if torrentMetadata}
              <div class="torrent-summary">
                <div>
                  <strong>{torrentMetadata.name}</strong>
                  <small>{torrentMetadata.info_hash}</small>
                  <small>{torrentMetadata.file_count} file{torrentMetadata.file_count === 1 ? "" : "s"} · {formatBytes(torrentMetadata.total_size_bytes)}</small>
                  <small>{torrentMetadata.piece_count} piece{torrentMetadata.piece_count === 1 ? "" : "s"} · {formatBytes(torrentMetadata.piece_length_bytes)} each</small>
                  <small>
                    {torrentSelectedPaths.length} selected · {formatBytes(torrentSelectedSize)} · {torrentMetadata.trackers.length} tracker{torrentMetadata.trackers.length === 1 ? "" : "s"}
                  </small>
                </div>
                <div class="torrent-selection-actions">
                  <button class="small-button" type="button" on:click={selectAllTorrentFiles}>All</button>
                  <button class="small-button" type="button" disabled={filteredTorrentFiles.length === 0} on:click={selectFilteredTorrentFiles}>Shown</button>
                  <button class="small-button" type="button" disabled={filteredTorrentFiles.length === 0} on:click={clearFilteredTorrentFiles}>Clear shown</button>
                  <button class="small-button" type="button" on:click={clearTorrentFileSelection}>None</button>
                  <button class="small-button" type="button" on:click={copyTorrentMetadataSummary}>Copy summary</button>
                  <button class="small-button" type="button" on:click={copyTorrentMetadataJson}>Copy JSON</button>
                  <button class="small-button" type="button" disabled={filteredTorrentFiles.length === 0} on:click={() => copyFilteredTorrentMetadataFields("file")}>Copy paths</button>
                  <button class="small-button" type="button" disabled={torrentMetadata.trackers.length === 0} on:click={() => copyFilteredTorrentMetadataFields("tracker")}>Copy trackers</button>
                  <button class="small-button" type="button" on:click={() => copyFilteredTorrentMetadataFields("hash")}>Copy hash</button>
                </div>
