                      <input type="checkbox" bind:checked={torrentFileSelectedOnly} />
                      <span>Selected only</span>
                    </label>
                  </label>
                </div>
                <div class="torrent-file-list">
                  {#if filteredTorrentFiles.length === 0}
                    <small class="format-hint">No torrent files match the current filters.</small>
