                    {#if filteredTorrentFiles.length > 20 && !torrentFileSearch.trim() && !torrentFileSelectedOnly}
                      <div class="course-list-toolbar compact-toolbar">
                        <small>Showing {visibleTorrentFiles(filteredTorrentFiles).length} of {filteredTorrentFiles.length} torrent file{filteredTorrentFiles.length === 1 ? "" : "s"}</small>
                        <button class="small-button" type="button" on:click={() => (torrentFilesExpanded = !torrentFilesExpanded)}>
                          {torrentFilesExpanded ? "Collapse files" : "Show all files"}
                        </button>
                      </div>
                    {/if}
                    {#each visibleTorrentFiles(filteredTorrentFiles) as file}
                      <label class:selected={torrentSelectedPaths.includes(file.path)}>
                        <input
                          type="checkbox"
                          checked={torrentSelectedPaths.includes(file.path)}
                          on:change={() => toggleTorrentFileSelection(file.path)}
                        />
                        <span>{file.path}</span>
                        <small>{formatBytes(file.size_bytes)}</small>
                      </label>
                    {/each}
                  {/if}
                </div>
                {#if torrentMetadata.files.length > filteredTorrentFiles.length}
                  <small class="format-hint">{filteredTorrentFiles.length} shown of {torrentMetadata.files.length} torrent file{torrentMetadata.files.length === 1 ? "" : "s"}.</small>
                {/if}
                {#if torrentMetadata.trackers.length > 0}
                  <div class="course-list-toolbar compact-toolbar">
                    <small class="format-hint">{visibleTrackers(torrentMetadata.trackers, torrentTrackersExpanded, 3).join(", ")}</small>
                    {#if torrentMetadata.trackers.length > 3}
                      <button class="small-button" type="button" on:click={() => (torrentTrackersExpanded = !torrentTrackersExpanded)}>
                        {torrentTrackersExpanded ? "Collapse trackers" : "Show all trackers"}
                      </button>
                    {/if}
                  </div>
                {/if}
              </div>
            {/if}
          </div>
        </div>
        <div class="panel torrent-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">P2P tools</p>
              <h2>Magnet metadata</h2>
            </div>
            <div class="inline-actions">
              <button class="secondary-button compact-button" type="button" disabled={magnetBusy} on:click={runMagnetParse}>
                {magnetBusy ? "Parsing" : "Parse"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={magnetQueueBusy} on:click={queueParsedMagnet}>
                {magnetQueueBusy ? "Queueing" : "Queue"}
              </button>
            </div>
          </div>
          <div class="metadata-tool">
            <div class="p2p-offer-panel wide-option">
              <div class="section-heading compact-heading">
                <div>
                  <strong>Local Torrent/P2P summary</strong>
                  {#if p2pLocalSummary}
                    <small>{p2pLocalSummary.offer_count} offer{p2pLocalSummary.offer_count === 1 ? "" : "s"} · {p2pLocalSummary.torrent_transfer_count} torrent transfer{p2pLocalSummary.torrent_transfer_count === 1 ? "" : "s"} · {p2pLocalSummary.p2p_transfer_count} P2P transfer{p2pLocalSummary.p2p_transfer_count === 1 ? "" : "s"}</small>
                  {:else}
                    <small>Local metadata-only summary of offers, torrent drafts, P2P drafts, and transfer tasks.</small>
                  {/if}
                </div>
                <div class="inline-actions">
                  <button class="small-button" type="button" disabled={Boolean(p2pBusy)} on:click={refreshP2pLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!p2pLocalSummary} on:click={copyP2pLocalSummary}>Copy summary</button>
                  <button class="small-button" type="button" disabled={!p2pLocalSummary} on:click={copyP2pLocalSummaryJson}>Copy JSON</button>
                </div>
              </div>
              {#if p2pLocalSummary}
                <div class="library-summary-grid">
                  <span>Offers <strong>{p2pLocalSummary.offer_count}</strong></span>
                  <span>Active <strong>{p2pLocalSummary.active_offer_count}</strong></span>
                  <span>Hashes <strong>{p2pLocalSummary.hashed_offer_count}/{p2pLocalSummary.offer_count}</strong></span>
                  <span>Sources <strong>{p2pLocalSummary.local_source_path_count}/{p2pLocalSummary.source_path_count}</strong></span>
                  <span>Receive folders <strong>{p2pLocalSummary.receive_folder_count}</strong></span>
                  <span>Torrent drafts <strong>{p2pLocalSummary.torrent_file_draft_count}</strong></span>
                  <span>Magnet drafts <strong>{p2pLocalSummary.magnet_draft_count}</strong></span>
                  <span>P2P drafts <strong>{p2pLocalSummary.p2p_receive_draft_count}</strong></span>
                  <span>Sidecars <strong>{p2pLocalSummary.sidecar_ready_transfer_count}</strong></span>
                </div>
                <small>Transfers: {p2pLocalSummary.queued_transfer_count} queued · {p2pLocalSummary.active_transfer_count} active · {p2pLocalSummary.completed_transfer_count} completed · {p2pLocalSummary.failed_transfer_count} failed · {p2pLocalSummary.archived_transfer_count} archived</small>
                <small>Metadata: {p2pLocalSummary.torrent_info_hash_count} info hash{p2pLocalSummary.torrent_info_hash_count === 1 ? "" : "es"} · {p2pLocalSummary.torrent_tracker_count + p2pLocalSummary.magnet_tracker_count} tracker{p2pLocalSummary.torrent_tracker_count + p2pLocalSummary.magnet_tracker_count === 1 ? "" : "s"} · {p2pLocalSummary.magnet_web_seed_count} web seed{p2pLocalSummary.magnet_web_seed_count === 1 ? "" : "s"}</small>
                <div class="torrent-selection-actions">
                  <button class="small-button" type="button" disabled={p2pLocalSummary.offer_status_counts.length === 0} on:click={() => copyP2pLocalSummaryFields("offer-status")}>Copy offer statuses</button>
                  <button class="small-button" type="button" disabled={p2pLocalSummary.transfer_status_counts.length === 0} on:click={() => copyP2pLocalSummaryFields("transfer-status")}>Copy transfer statuses</button>
                  <button class="small-button" type="button" disabled={p2pLocalSummary.transfer_kind_counts.length === 0} on:click={() => copyP2pLocalSummaryFields("transfer-kind")}>Copy transfer kinds</button>
                  <button class="small-button" type="button" disabled={p2pLocalSummary.draft_type_counts.length === 0} on:click={() => copyP2pLocalSummaryFields("draft-type")}>Copy draft types</button>
                  <button class="small-button" type="button" disabled={p2pLocalSummary.source_path_status_counts.length === 0} on:click={() => copyP2pLocalSummaryFields("source-status")}>Copy source status</button>
                  <button class="small-button" type="button" disabled={p2pLocalSummary.offer_count === 0} on:click={() => copyP2pLocalSummaryFields("hash-status")}>Copy hash status</button>
                  <button class="small-button" type="button" on:click={() => copyP2pLocalSummaryFields("note")}>Copy notes</button>
                </div>
              {/if}
              <div class="path-picker-row">
                <input bind:value={p2pSummaryExportPath} placeholder="C:/path/p2p-summary.json" spellcheck="false" aria-label="Torrent and P2P summary export path" />
                <button class="small-button" type="button" disabled={Boolean(p2pBusy)} on:click={chooseP2pSummaryExportPath}>{p2pBusy === "summary-choose" ? "Choosing" : "Save as"}</button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy)} on:click={exportP2pSummary}>{p2pBusy === "summary-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!p2pSummaryExportResult && !p2pSummaryExportPath.trim()} on:click={() => openLocalPath(p2pSummaryExportResult || p2pSummaryExportPath, "Torrent/P2P summary")}>Open</button>
                <button class="small-button" type="button" disabled={!p2pSummaryExportResult && !p2pSummaryExportPath.trim()} on:click={() => revealLocalPath(p2pSummaryExportResult || p2pSummaryExportPath, "Torrent/P2P summary")}>Reveal</button>
              </div>
            </div>
            <div class="p2p-offer-panel wide-option">
              <div class="section-heading compact-heading">
                <div>
                  <strong>Capability catalog</strong>
                  {#if p2pCapabilityCatalog}
                    <small>{p2pCapabilityCatalog.capability_count} capabilities · {p2pCapabilityCatalog.p2p_surfaces.length} surfaces · gate {p2pCapabilityCatalog.parity_gate_status}</small>
                  {:else}
                    <small>Metadata-only map of Torrent/P2P commands, surfaces, boundaries, and current verification gaps.</small>
                  {/if}
                </div>
                <div class="inline-actions">
                  <button class="small-button" type="button" disabled={Boolean(p2pBusy)} on:click={refreshP2pLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!p2pCapabilityCatalog} on:click={copyP2pCapabilityCatalogSummary}>Copy catalog</button>
                  <button class="small-button" type="button" disabled={!p2pCapabilityCatalog} on:click={copyP2pCapabilityCatalogJson}>Copy JSON</button>
                </div>
              </div>
              {#if p2pCapabilityCatalog}
                <div class="library-summary-grid">
                  <span>Capabilities <strong>{p2pCapabilityCatalog.capability_count}</strong></span>
                  <span>Surfaces <strong>{p2pCapabilityCatalog.p2p_surfaces.length}</strong></span>
                  <span>Task kinds <strong>{p2pCapabilityCatalog.task_kinds.length}</strong></span>
                  <span>Offer statuses <strong>{p2pCapabilityCatalog.supported_offer_statuses.length}</strong></span>
                  <span>Draft types <strong>{p2pCapabilityCatalog.supported_draft_types.length}</strong></span>
                  <span>LAN E2E <strong>{p2pCapabilityCatalog.verifies_lan_p2p_e2e ? "verified" : "pending"}</strong></span>
                </div>
                <small>Networks: tracker {p2pCapabilityCatalog.contacts_trackers ? "yes" : "no"} · DHT {p2pCapabilityCatalog.contacts_dht ? "yes" : "no"} · relay {p2pCapabilityCatalog.contacts_relays ? "yes" : "no"} · peer {p2pCapabilityCatalog.contacts_peers ? "yes" : "no"}.</small>
                <small>E2E: BitTorrent {p2pCapabilityCatalog.verifies_bittorrent_e2e ? "verified" : "pending"} · LAN P2P {p2pCapabilityCatalog.verifies_lan_p2p_e2e ? "verified" : "pending"} · NAT/relay {p2pCapabilityCatalog.verifies_nat_or_relay_e2e ? "verified" : "pending"}.</small>
                <div class="torrent-selection-actions">
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("capability")}>Copy capabilities</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("command")}>Copy commands</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("surface")}>Copy surfaces</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("task-kind")}>Copy task kinds</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("offer-status")}>Copy offer statuses</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("draft-type")}>Copy draft types</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("limit")}>Copy limits</button>
                  <button class="small-button" type="button" on:click={() => copyP2pCapabilityCatalogFields("note")}>Copy notes</button>
                </div>
              {/if}
              <div class="path-picker-row">
                <input bind:value={p2pCapabilityCatalogExportPath} placeholder="C:/path/p2p-capability-catalog.json" spellcheck="false" aria-label="Torrent and P2P capability catalog export path" />
                <button class="small-button" type="button" disabled={Boolean(p2pBusy)} on:click={chooseP2pCapabilityCatalogExportPath}>{p2pBusy === "catalog-choose" ? "Choosing" : "Save as"}</button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy)} on:click={exportP2pCapabilityCatalogFile}>{p2pBusy === "catalog-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!p2pCapabilityCatalogExportResult && !p2pCapabilityCatalogExportPath.trim()} on:click={() => openLocalPath(p2pCapabilityCatalogExportResult || p2pCapabilityCatalogExportPath, "Torrent/P2P capability catalog")}>Open</button>
                <button class="small-button" type="button" disabled={!p2pCapabilityCatalogExportResult && !p2pCapabilityCatalogExportPath.trim()} on:click={() => revealLocalPath(p2pCapabilityCatalogExportResult || p2pCapabilityCatalogExportPath, "Torrent/P2P capability catalog")}>Reveal</button>
              </div>
            </div>
            <label class="wide-option">
              <span>Magnet URI</span>
              <input bind:value={magnetInput} placeholder="magnet:?xt=urn:btih:..." spellcheck="false" />
            </label>
            {#if magnetError}
              <p class="error-text">{magnetError}</p>
            {/if}
            {#if magnetMetadata}
              <div class="torrent-summary">
                <div>
                  <strong>{magnetMetadata.display_name ?? "Unnamed magnet"}</strong>
                  <small>{magnetMetadata.info_hash}</small>
                  <small>{magnetMetadata.trackers.length} tracker{magnetMetadata.trackers.length === 1 ? "" : "s"} · {magnetMetadata.web_seeds.length} web seed{magnetMetadata.web_seeds.length === 1 ? "" : "s"}</small>
                </div>
                <div class="torrent-selection-actions">
                  <button class="small-button" type="button" on:click={copyMagnetMetadataSummary}>Copy summary</button>
                  <button class="small-button" type="button" on:click={copyMagnetMetadataJson}>Copy JSON</button>
                  <button class="small-button" type="button" on:click={() => copyMagnetMetadataFields("hash")}>Copy hash</button>
                  <button class="small-button" type="button" disabled={magnetMetadata.trackers.length === 0} on:click={() => copyMagnetMetadataFields("tracker")}>Copy trackers</button>
                  <button class="small-button" type="button" disabled={magnetMetadata.web_seeds.length === 0} on:click={() => copyMagnetMetadataFields("web-seed")}>Copy web seeds</button>
                  <button class="small-button" type="button" on:click={() => copyMagnetMetadataFields("topic")}>Copy topic</button>
                </div>
                {#if magnetMetadata.trackers.length > 0}
                  <div class="course-list-toolbar compact-toolbar">
                    <small class="format-hint">{visibleTrackers(magnetMetadata.trackers, magnetTrackersExpanded, 4).join(", ")}</small>
                    {#if magnetMetadata.trackers.length > 4}
                      <button class="small-button" type="button" on:click={() => (magnetTrackersExpanded = !magnetTrackersExpanded)}>
                        {magnetTrackersExpanded ? "Collapse trackers" : "Show all trackers"}
                      </button>
                    {/if}
                  </div>
                {/if}
              </div>
            {/if}
            <div class="p2p-offer-panel wide-option">
              <div class="section-heading compact-heading">
                <div>
                  <strong>Short-code file transfer</strong>
                  <small>Creates short-code offers; Start send exposes a LAN share code and queued receives pull the file when an endpoint is present.</small>
                </div>
                <button class="secondary-button compact-button" type="button" disabled={p2pBusy === "create"} on:click={createP2pSendOffer}>
                  {p2pBusy === "create" ? "Creating" : "Create code"}
                </button>
                <button class="secondary-button compact-button" type="button" disabled={!p2pActiveOffer || p2pBusy.startsWith("serve:")} on:click={() => startP2pSendOffer()}>
                  {p2pBusy.startsWith("serve:") ? "Starting" : "Start send"}
                </button>
              </div>
              <label>
                <span>Send file</span>
                <div class="path-picker-row">
                  <input bind:value={p2pSendFilePath} placeholder="C:/Downloads/file.zip" spellcheck="false" />
                  <button class="icon-button" type="button" title="Choose file to send" disabled={p2pBusy === "file"} on:click={chooseP2pSendFile}>
                    <FolderOpen size={17} />
                  </button>
                  <button class="small-button" type="button" disabled={!p2pSendFilePath.trim()} on:click={() => openLocalPath(p2pSendFilePath, "P2P send file")}>
                    Open
                  </button>
                  <button class="small-button" type="button" disabled={!p2pSendFilePath.trim()} on:click={() => revealLocalPath(p2pSendFilePath, "P2P send file")}>
                    Reveal
                  </button>
                </div>
              </label>
              <label>
                <span>Receive code</span>
                <div class="path-picker-row">
                  <input bind:value={p2pReceiveCode} placeholder="ABC123" spellcheck="false" />
                  <button class="secondary-button compact-button" type="button" disabled={p2pBusy === "lookup"} on:click={lookupP2pReceiveOffer}>
                    {p2pBusy === "lookup" ? "Looking" : "Lookup"}
                  </button>
                </div>
              </label>
              <label>
                <span>Receive folder</span>
                <div class="path-picker-row">
                  <input bind:value={p2pReceiveOutputDir} placeholder="C:/Downloads/Received" spellcheck="false" />
                  <button class="icon-button" type="button" title="Choose receive folder" disabled={p2pBusy === "receive-folder"} on:click={chooseP2pReceiveFolder}>
                    <FolderOpen size={17} />
                  </button>
                  <button class="small-button" type="button" disabled={!p2pReceiveOutputDir.trim()} on:click={() => openLocalPath(p2pReceiveOutputDir, "P2P receive folder")}>
                    Open
                  </button>
                  <button class="small-button" type="button" disabled={!p2pReceiveOutputDir.trim()} on:click={() => revealLocalPath(p2pReceiveOutputDir, "P2P receive folder")}>
                    Reveal
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={p2pBusy === "receive"} on:click={prepareP2pReceiveDraft}>
                    {p2pBusy === "receive" ? "Preparing" : "Prepare receive"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={p2pBusy === "queue"} on:click={queueP2pReceiveDraft}>
                    {p2pBusy === "queue" ? "Queueing" : "Queue receive"}
                  </button>
                </div>
              </label>
              {#if p2pActiveOffer}
                {@const activeP2pOffer = p2pActiveOffer}
                <div class="status-card">
                  <strong>{activeP2pOffer.short_code} · {activeP2pOffer.file_name}</strong>
                  <small>{activeP2pOffer.status} · {formatBytes(activeP2pOffer.size_bytes)}{activeP2pOffer.expires_at ? ` · expires ${activeP2pOffer.expires_at}` : ""}</small>
                  {#if activeP2pOffer.share_code}
                    <small>Share code · {activeP2pOffer.share_code}</small>
                  {/if}
                  {#if activeP2pOffer.sha256}
                    <small>SHA-256 · {activeP2pOffer.sha256}</small>
                  {/if}
                  {#if activeP2pOffer.receive_output_dir}
                    <small>Receive folder · {activeP2pOffer.receive_output_dir}</small>
                  {/if}
                  <code>{activeP2pOffer.file_path}</code>
                  <div class="preview-toolbar">
                    <button class="small-button" type="button" disabled={p2pBusy === `open:${activeP2pOffer.short_code}`} on:click={() => openP2pOfferSourceFile(activeP2pOffer)}>
                      Open source
                    </button>
                    <button class="small-button" type="button" disabled={p2pBusy === `reveal:${activeP2pOffer.short_code}`} on:click={() => revealP2pOfferSourceFile(activeP2pOffer)}>
                      Reveal source
                    </button>
                    {#if activeP2pOffer.receive_output_dir}
                      <button class="small-button" type="button" disabled={p2pBusy === `open-receive:${activeP2pOffer.short_code}`} on:click={() => openP2pOfferReceiveFolder(activeP2pOffer)}>
                        Open receive folder
                      </button>
                    {/if}
                    {#if activeP2pOffer.sha256}
                      <button class="small-button" type="button" on:click={() => copyTextToClipboard(activeP2pOffer.sha256 ?? "", "No P2P SHA-256 hash", "P2P SHA-256 copied")}>
                        Copy SHA-256
                      </button>
                    {/if}
                    <button class="small-button" type="button" disabled={p2pBusy === `serve:${activeP2pOffer.short_code}` || !["waiting", "serving"].includes(activeP2pOffer.status)} on:click={() => startP2pSendOffer(activeP2pOffer.short_code)}>
                      {activeP2pOffer.status === "serving" ? "Restart send" : "Start send"}
                    </button>
                  </div>
                </div>
              {/if}
              {#if p2pOffers.length > 0}
                <div class="library-filter-row p2p-filter-row">
                  <label>
                    <span>Offer search</span>
                    <input bind:value={p2pOfferSearch} placeholder="Code, hash, file, path, or folder" spellcheck="false" aria-label="P2P offer search" />
                  </label>
                  <label>
                    <span>Status</span>
                    <select bind:value={p2pOfferStatusFilter} aria-label="P2P offer status filter">
                      <option value="all">All status</option>
                      <option value="waiting">Waiting</option>
                      <option value="serving">Serving</option>
                      <option value="paused">Paused</option>
                      <option value="receive_ready">Receive ready</option>
                      <option value="completed">Completed</option>
                      <option value="canceled">Canceled</option>
                      <option value="expired">Expired</option>
                    </select>
                  </label>
                  <button class="secondary-button compact-button danger" type="button" disabled={p2pBusy === "clear"} on:click={clearLocalP2pOffers}>
                    {p2pBusy === "clear" ? "Clearing" : "Clear offers"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy) || visibleP2pPausableOffers.length === 0} on:click={() => updateVisibleP2pOffersControl("pause")}>
                    {p2pBusy === "pause-visible" ? "Pausing" : "Pause shown"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy) || visibleP2pResumableOffers.length === 0} on:click={() => updateVisibleP2pOffersControl("resume")}>
                    {p2pBusy === "resume-visible" ? "Resuming" : "Resume shown"}
                  </button>
                  <button class="secondary-button compact-button danger" type="button" disabled={Boolean(p2pBusy) || visibleP2pCancelableOffers.length === 0} on:click={requestVisibleP2pOffersCancel}>
                    {p2pBusy === "cancel-visible" ? "Canceling" : "Cancel shown"}
                  </button>
                  <button class="secondary-button compact-button danger" type="button" disabled={Boolean(p2pBusy) || filteredP2pOffers.length === 0} on:click={requestVisibleP2pOffersRemove}>
                    {p2pBusy === "delete-filtered" ? "Removing" : "Remove shown"}
                  </button>
                  <button class="small-button" type="button" disabled={visibleP2pOffers(filteredP2pOffers).length === 0} on:click={copyVisibleP2pOfferSummary}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" disabled={visibleP2pOffers(filteredP2pOffers).length === 0} on:click={copyVisibleP2pOfferJson}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" disabled={visibleP2pOffers(filteredP2pOffers).length === 0} on:click={() => copyVisibleP2pOfferFields("code")}>
                    Copy codes
                  </button>
                  <button class="small-button" type="button" disabled={visibleP2pOffers(filteredP2pOffers).length === 0} on:click={() => copyVisibleP2pOfferFields("share")}>
                    Copy shares
                  </button>
                  <button class="small-button" type="button" disabled={visibleP2pOffers(filteredP2pOffers).length === 0} on:click={() => copyVisibleP2pOfferFields("source")}>
                    Copy sources
                  </button>
                  <button class="small-button" type="button" disabled={!visibleP2pOffers(filteredP2pOffers).some((offer) => offer.sha256)} on:click={() => copyVisibleP2pOfferFields("sha256")}>
                    Copy SHA-256
                  </button>
                  <button class="small-button" type="button" disabled={!visibleP2pOffers(filteredP2pOffers).some((offer) => offer.receive_output_dir)} on:click={() => copyVisibleP2pOfferFields("receive")}>
                    Copy folders
                  </button>
                </div>
                <div class="path-picker-row p2p-offer-backup-row">
                  <input bind:value={p2pOffersExportPath} placeholder="C:/Exports/fetchdock-p2p-offers.json" spellcheck="false" aria-label="P2P offers export path" />
                  <button class="small-button" type="button" disabled={Boolean(p2pBusy) || Boolean(p2pOffersTransferBusy)} on:click={chooseP2pOffersExportPath}>
                    {p2pOffersTransferBusy === "choose-export" ? "Choosing" : "Save as"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy) || Boolean(p2pOffersTransferBusy) || visibleP2pOffers(filteredP2pOffers).length === 0} on:click={exportVisibleP2pOffersFile}>
                    {p2pOffersTransferBusy === "export" ? "Exporting" : "Export shown"}
                  </button>
                  <button class="small-button" type="button" disabled={!p2pOffersExportResult && !p2pOffersExportPath.trim()} on:click={openP2pOffersExportResult}>Open</button>
                  <button class="small-button" type="button" disabled={!p2pOffersExportResult && !p2pOffersExportPath.trim()} on:click={revealP2pOffersExportResult}>Reveal</button>
                </div>
                <div class="path-picker-row p2p-offer-backup-row">
                  <input bind:value={p2pOffersImportPath} placeholder="C:/Exports/fetchdock-p2p-offers.json" spellcheck="false" aria-label="P2P offers import path" />
                  <button class="small-button" type="button" disabled={Boolean(p2pBusy) || Boolean(p2pOffersTransferBusy)} on:click={chooseP2pOffersImportFile}>
                    {p2pOffersTransferBusy === "choose-import" ? "Choosing" : "Choose JSON"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={Boolean(p2pBusy) || Boolean(p2pOffersTransferBusy) || !p2pOffersImportPath.trim()} on:click={importP2pOffersFile}>
                    {p2pOffersTransferBusy === "import" ? "Importing" : "Import JSON"}
                  </button>
                  {#if p2pOffersExportResult}
                    <small>{p2pOffersExportResult.exported_count} offer{p2pOffersExportResult.exported_count === 1 ? "" : "s"} exported · {p2pOffersExportResult.output_path}</small>
                  {/if}
                </div>
                {#if filteredP2pOffers.length === 0}
                  <small class="format-hint">No P2P offers match the current filters.</small>
                {:else}
                  <div class="course-list-toolbar compact-toolbar">
                    <small class="format-hint">{visibleP2pOffers(filteredP2pOffers).length} shown of {p2pOffers.length} local offer{p2pOffers.length === 1 ? "" : "s"}.</small>
                    {#if filteredP2pOffers.length > 8 && !p2pOfferSearch.trim() && p2pOfferStatusFilter === "all"}
                      <button class="small-button" type="button" on:click={() => (p2pOffersExpanded = !p2pOffersExpanded)}>
                        {p2pOffersExpanded ? "Collapse offers" : "Show all offers"}
                      </button>
                    {/if}
                  </div>
                  <div class="p2p-offer-list">
                    {#each visibleP2pOffers(filteredP2pOffers) as offer}
                      <article>
                        <div>
                          <strong>{offer.short_code} · {offer.file_name}</strong>
                          <small>{offer.status} · {formatBytes(offer.size_bytes)}</small>
                          {#if offer.share_code}
                            <small>{offer.share_code}</small>
                          {/if}
                          {#if offer.sha256}
                            <small>SHA-256: {offer.sha256}</small>
                          {/if}
                          {#if offer.receive_output_dir}
                            <small>{offer.receive_output_dir}</small>
                          {/if}
                        </div>
                        <button
                          class="small-button"
                          type="button"
                          disabled={p2pBusy === `open:${offer.short_code}`}
                          on:click={() => openP2pOfferSourceFile(offer)}
                        >
                          Open
                        </button>
                        <button
                          class="small-button"
                          type="button"
                          disabled={p2pBusy === `reveal:${offer.short_code}`}
                          on:click={() => revealP2pOfferSourceFile(offer)}
                        >
                          Reveal
                        </button>
                        {#if offer.receive_output_dir}
                          <button
                            class="small-button"
                            type="button"
                            disabled={p2pBusy === `open-receive:${offer.short_code}`}
                            on:click={() => openP2pOfferReceiveFolder(offer)}
                          >
                            Folder
                          </button>
                        {/if}
                        <button
                          class="small-button"
                          type="button"
                          disabled={p2pBusy === `pause:${offer.short_code}` || !["waiting", "serving", "receive_ready"].includes(offer.status)}
                          on:click={() => updateP2pOfferControl(offer.short_code, "pause")}
                        >
                          Pause
                        </button>
                        <button
                          class="small-button"
                          type="button"
                          disabled={p2pBusy === `serve:${offer.short_code}` || !["waiting", "serving"].includes(offer.status)}
                          on:click={() => startP2pSendOffer(offer.short_code)}
                        >
                          Send
                        </button>
                        <button
                          class="small-button"
                          type="button"
                          disabled={p2pBusy === `resume:${offer.short_code}` || offer.status !== "paused"}
                          on:click={() => updateP2pOfferControl(offer.short_code, "resume")}
                        >
                          Resume
                        </button>
                        <button
                          class="small-button danger"
                          type="button"
                          disabled={p2pBusy === offer.short_code || !["waiting", "serving", "paused", "receive_ready"].includes(offer.status)}
                          on:click={() => cancelP2pSendOffer(offer.short_code)}
                        >
                          Cancel
                        </button>
                        <button
                          class="small-button danger"
                          type="button"
                          disabled={p2pBusy === `delete:${offer.short_code}`}
                          on:click={() => removeP2pOffer(offer.short_code)}
                        >
                          Remove
                        </button>
                      </article>
                    {/each}
                  </div>
                {/if}
              {/if}
              {#if p2pError}
                <p class="error-text">{p2pError}</p>
              {/if}
            </div>
          </div>
        </div>
        <div class="panel telegram-browser-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Local transfers</p>
              <h2>Torrent and P2P transfers</h2>
            </div>
            <button class="secondary-button compact-button" type="button" on:click={() => { void loadDownloads(); void loadP2pOffers(); }}>Refresh</button>
          </div>
          <div class="library-filter-row transfer-filter-row">
            <label>
              <span>Search</span>
              <input bind:value={torrentP2pTransferSearch} placeholder="Title, URI, output path, or error" spellcheck="false" aria-label="Torrent and P2P transfer search" />
            </label>
            <label>
              <span>Kind</span>
              <select bind:value={torrentP2pTransferKindFilter} aria-label="Torrent and P2P transfer kind filter">
                <option value="all">Torrent and P2P</option>
                <option value="torrent">Torrent</option>
                <option value="p2p">P2P</option>
              </select>
            </label>
            <label>
              <span>Status</span>
              <select bind:value={torrentP2pTransferStatusFilter} aria-label="Torrent and P2P transfer status filter">
                <option value="all">All status</option>
                <option value="queued">Queued</option>
                <option value="active">Active</option>
                <option value="paused">Paused</option>
                <option value="completed">Completed</option>
                <option value="failed">Failed</option>
                <option value="canceled">Canceled</option>
                <option value="archived">Archived</option>
              </select>
            </label>
          </div>
          {#if torrentP2pTransferTasks.length === 0}
            <p class="muted">Queued torrent, magnet, and P2P receive tasks will appear here after you queue them.</p>
          {:else if filteredTorrentP2pTransferTasks.length === 0}
            <p class="muted">No torrent or P2P transfers match the current filters.</p>
          {:else}
            <div class="course-list-toolbar">
              <small class="format-hint">
                {visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks).length} shown of {torrentP2pTransferTasks.length} local transfer task{torrentP2pTransferTasks.length === 1 ? "" : "s"}.
              </small>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskSummary(visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks), "Torrent/P2P transfer")}>
                Copy summary
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskJson(visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks), "Torrent/P2P transfer", { search: torrentP2pTransferSearch, kind: torrentP2pTransferKindFilter, status: torrentP2pTransferStatusFilter })}>
                Copy JSON
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks), "source", "Torrent/P2P transfer")}>
                Copy sources
              </button>
              <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks), "output", "Torrent/P2P transfer")}>
                Copy outputs
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferStartableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("start", visibleTorrentP2pTransferStartableTasks, "Torrent and P2P transfers")}
              >
                Start shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferActiveTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("pause", visibleTorrentP2pTransferActiveTasks, "Torrent and P2P transfers")}
              >
                Pause shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferPausedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("resume", visibleTorrentP2pTransferPausedTasks, "Torrent and P2P transfers")}
              >
                Resume shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferFailedTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("retry", visibleTorrentP2pTransferFailedTasks, "Torrent and P2P transfers")}
              >
                Retry shown
              </button>
              <button
                class="small-button danger"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferCancelableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("cancel", visibleTorrentP2pTransferCancelableTasks, "Torrent and P2P transfers")}
              >
                Cancel shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferArchivableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("archive", visibleTorrentP2pTransferArchivableTasks, "Torrent and P2P transfers")}
              >
                Archive shown
              </button>
              <button
                class="small-button"
                type="button"
                disabled={downloadBulkBusy !== "" || visibleTorrentP2pTransferRestorableTasks.length === 0}
                on:click={() => runDownloadTaskBatchAction("restore", visibleTorrentP2pTransferRestorableTasks, "Torrent and P2P transfers")}
              >
                Restore shown
              </button>
              {#if filteredTorrentP2pTransferTasks.length > 10 && !torrentP2pTransferSearch.trim() && torrentP2pTransferKindFilter === "all" && torrentP2pTransferStatusFilter === "all"}
                <button class="small-button" type="button" on:click={() => (torrentP2pTransfersExpanded = !torrentP2pTransfersExpanded)}>
                  {torrentP2pTransfersExpanded ? "Collapse transfers" : "Show all transfers"}
                </button>
              {/if}
            </div>
            <div class="telegram-media-list transfer-task-list">
              {#each visibleTorrentP2pTransferTasks(filteredTorrentP2pTransferTasks) as task}
                <div>
                  <span>
                    <strong>{task.title}</strong>
                    <small>{task.kind} · {task.platform} · {task.status} · {formatProgress(task)}</small>
                    {#if task.output_path}
                      <small>Saved to {task.output_path}</small>
                    {:else if task.output_dir}
                      <small>Output folder {task.output_dir}</small>
                    {/if}
                    {#if task.last_error}
                      <small class="error-text">{task.last_error}</small>
                    {/if}
                  </span>
                  <div class="section-actions">
                    <button class="small-button" type="button" disabled={!canStartTask(task) || activeTaskIds.has(task.id)} on:click={() => startTask(task)}>
                      Start
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "active"} on:click={() => pauseTask(task)}>
                      Pause
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "paused"} on:click={() => resumeTask(task)}>
                      Resume
                    </button>
                    <button class="small-button" type="button" disabled={task.status !== "failed" && task.status !== "canceled"} on:click={() => retryTask(task)}>
                      Retry
                    </button>
                    <button class="small-button" type="button" disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"} on:click={() => cancelTask(task)}>
                      Cancel
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_path} on:click={() => revealTaskFile(task)}>
                      Reveal
                    </button>
                    <button class="small-button" type="button" disabled={!task.output_dir && !task.output_path} on:click={() => openTaskFolder(task)}>
                      Open
                    </button>
                    <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                      Source
                    </button>
                    <button class="small-button" type="button" on:click={() => focusDownloadTaskById(task.id, task.title)}>
                      Detail
                    </button>
                    <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                      Logs
                    </button>
                    {#if task.status === "archived"}
                      <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                    {:else if ["completed", "failed", "canceled"].includes(task.status)}
                      <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                    {/if}
                  </div>
                </div>
              {/each}
            </div>
          {/if}
        </div>
        <div class="panel tool-intro-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Media tools</p>
              <h2>Video clip and markers</h2>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={Boolean(mediaToolsSummaryBusy)} on:click={refreshMediaToolsLocalSummary}>
                {mediaToolsSummaryBusy === "refresh" ? "Refreshing" : "Refresh summary"}
              </button>
              <button class="small-button" type="button" on:click={copyMediaToolsLocalSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" on:click={copyMediaToolsLocalSummaryJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsLocalSummary || mediaToolsLocalSummary.waveform_cache_files.length === 0} on:click={() => copyMediaToolsLocalSummaryFields("waveform")}>
                Copy waveform files
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsLocalSummary || mediaToolsLocalSummary.subtitle_sidecar_files.length === 0} on:click={() => copyMediaToolsLocalSummaryFields("subtitle")}>
                Copy subtitle files
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsLocalSummary || mediaToolsLocalSummary.tool_status_counts.length === 0} on:click={() => copyMediaToolsLocalSummaryFields("tool")}>
                Copy tool counts
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsLocalSummary || mediaToolsLocalSummary.review_notes.length === 0} on:click={() => copyMediaToolsLocalSummaryFields("note")}>
                Copy notes
              </button>
            </div>
          </div>
          <div class="legal-export-row">
            <span>
              <strong>Media tools summary</strong>
              <small>{mediaToolsLocalSummary ? `${mediaToolsLocalSummary.waveform_cache_file_count} waveform cache · ${mediaToolsLocalSummary.subtitle_sidecar_file_count} subtitle sidecars · executes tools ${mediaToolsLocalSummary.executes_media_tools ? "yes" : "no"}` : "Local summary covers FFmpeg/Whisper configuration, waveform cache, subtitle sidecars, and current UI draft state."}</small>
            </span>
            <div class="inline-actions">
              <input bind:value={mediaToolsSummaryExportPath} placeholder="C:/FetchDock/media-tools-summary.json" spellcheck="false" aria-label="Media tools summary export path" />
              <button class="small-button" type="button" disabled={Boolean(mediaToolsSummaryBusy)} on:click={chooseMediaToolsSummaryExportPath}>
                {mediaToolsSummaryBusy === "choose-export" ? "Choosing" : "Save as"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={Boolean(mediaToolsSummaryBusy)} on:click={exportMediaToolsSummary}>
                {mediaToolsSummaryBusy === "export" ? "Exporting" : "Export summary"}
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsSummaryExportPath.trim()} on:click={() => openLocalPath(mediaToolsSummaryExportPath, "Media tools summary")}>
                Open summary
              </button>
              <button class="small-button" type="button" disabled={!mediaToolsSummaryExportPath.trim()} on:click={() => revealLocalPath(mediaToolsSummaryExportPath, "Media tools summary")}>
                Reveal summary
              </button>
            </div>
          </div>
          {#if mediaToolsSummaryError}
            <p class="error-text">{mediaToolsSummaryError}</p>
          {/if}
          {@render VideoClipTool("full")}
          <div class="clip-tools clip-tools-full" aria-label="Local media transcode">
            <div class="clip-tools-header">
              <div>
                <strong>FFmpeg transcode</strong>
                <small>{transcodeStatusMessage || "Local media conversion and simple metadata embed"}</small>
              </div>
              <div class="clip-actions">
                {#if transcodeBusy}
                  <button class="secondary-button compact-button" type="button" on:click={cancelTranscodeJob}>
                    Cancel
                  </button>
                {/if}
                <button class="primary-button compact-button" type="button" disabled={transcodeBusy} on:click={runMediaTranscode}>
                  {transcodeBusy ? "Transcoding" : "Transcode"}
                </button>
              </div>
            </div>
            <label class="wide-option">
              <span>Input media</span>
              <div class="path-picker-row">
                <input bind:value={transcodeInputPath} placeholder="C:/Media/source.mkv" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose media to transcode" disabled={transcodeInputBusy === "input"} on:click={chooseTranscodeInputFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!transcodeInputPath.trim()} on:click={() => openLocalPath(transcodeInputPath, "Transcode input")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!transcodeInputPath.trim()} on:click={() => revealLocalPath(transcodeInputPath, "Transcode input")}>
                  Reveal
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Output file</span>
              <div class="path-picker-row">
                <input bind:value={transcodeOutputPath} placeholder="C:/Media/output.mp4" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose transcode output" disabled={transcodeInputBusy === "output"} on:click={chooseTranscodeOutputPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!transcodeOutputPath.trim()} on:click={() => openLocalPath(transcodeOutputPath, "Transcode output")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!transcodeOutputPath.trim()} on:click={() => revealLocalPath(transcodeOutputPath, "Transcode output")}>
                  Reveal
                </button>
              </div>
            </label>
            <label>
              <span>Preset</span>
              <select bind:value={transcodePreset} aria-label="Transcode preset">
                <option value="copy">Copy streams</option>
                <option value="h264">H.264 MP4</option>
                <option value="h265">H.265 compact</option>
                <option value="vp9">VP9 WebM</option>
                <option value="audio_mp3">MP3 audio</option>
                <option value="audio_aac">AAC audio</option>
                <option value="audio_opus">Opus audio</option>
                <option value="custom">Custom</option>
              </select>
            </label>
            {#if ["h264", "h265", "vp9", "custom"].includes(transcodePreset)}
              <label>
                <span>CRF</span>
                <input bind:value={transcodeCrf} inputmode="numeric" placeholder="23" spellcheck="false" />
              </label>
            {/if}
            {#if transcodePreset === "custom"}
              <label>
                <span>Video codec</span>
                <input bind:value={transcodeVideoCodec} placeholder="libx264" spellcheck="false" />
              </label>
              <label>
                <span>Audio codec</span>
                <input bind:value={transcodeAudioCodec} placeholder="aac" spellcheck="false" />
              </label>
              <label>
                <span>Speed preset</span>
                <input bind:value={transcodeSpeedPreset} placeholder="medium" spellcheck="false" />
              </label>
            {/if}
            {#if transcodePreset.startsWith("audio_")}
              <label>
                <span>Audio bitrate</span>
                <input bind:value={transcodeAudioBitrate} placeholder="192k" spellcheck="false" />
              </label>
            {/if}
            <label>
              <span>Metadata title</span>
              <input bind:value={transcodeMetadataTitle} placeholder="Optional" spellcheck="false" />
            </label>
            <label>
              <span>Metadata artist</span>
              <input bind:value={transcodeMetadataArtist} placeholder="Optional" spellcheck="false" />
            </label>
            <label class="wide-option">
              <span>Cover image</span>
              <div class="path-picker-row">
                <input bind:value={transcodeCoverPath} placeholder="Optional JPG/PNG/WebP" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose cover image" disabled={transcodeInputBusy === "cover"} on:click={chooseTranscodeCoverFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!transcodeCoverPath.trim()} on:click={() => openLocalPath(transcodeCoverPath, "Transcode cover")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!transcodeCoverPath.trim()} on:click={() => revealLocalPath(transcodeCoverPath, "Transcode cover")}>
                  Reveal
                </button>
              </div>
            </label>
            {#if transcodeBusy || transcodeStatusMessage}
              <small class="clip-status wide-option">
                {transcodeBusy ? `Elapsed ${transcodeElapsedSeconds}s` : transcodeStatusMessage}
              </small>
            {/if}
            {#if transcodeError}
              <p class="error-text wide-option">{transcodeError}</p>
            {/if}
          </div>
          <div class="shot-tools" aria-label="Shot change detection">
            <div class="clip-tools-header">
              <div>
                <strong>Shot detection</strong>
                <small>{shotMarkers.length > 0 ? `${shotMarkers.length} marker${shotMarkers.length === 1 ? "" : "s"} found` : "Local FFmpeg scene markers"}</small>
              </div>
              <div class="inline-actions">
                <button class="secondary-button compact-button" type="button" disabled={shotSaveBusy || shotMarkers.length === 0} on:click={saveDetectedShotMarkers}>
                  {shotSaveBusy ? "Saving" : "Save markers"}
                </button>
                <button class="primary-button compact-button" type="button" disabled={shotBusy} on:click={runShotDetection}>
                  {shotBusy ? "Detecting" : "Detect shots"}
                </button>
              </div>
            </div>
            <label class="wide-option">
              <span>Source video</span>
              <div class="path-picker-row">
                <input bind:value={shotInputPath} placeholder="C:/Media/source.mp4" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose source video" disabled={shotInputBusy} on:click={chooseShotInputFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!shotInputPath.trim()} on:click={() => openLocalPath(shotInputPath, "Shot source")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!shotInputPath.trim()} on:click={() => revealLocalPath(shotInputPath, "Shot source")}>
                  Reveal
                </button>
              </div>
            </label>
            <label>
              <span>Scene threshold</span>
              <input bind:value={shotThreshold} inputmode="decimal" placeholder="0.35" spellcheck="false" />
            </label>
            <label class="wide-option">
              <span>Marker output JSON</span>
              <div class="path-picker-row">
                <input bind:value={shotOutputPath} placeholder="C:/Media/source.shots.json" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose shot marker output" disabled={shotInputBusy} on:click={chooseShotOutputPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!shotOutputPath.trim()} on:click={() => openLocalPath(shotOutputPath, "Shot marker output")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!shotOutputPath.trim()} on:click={() => revealLocalPath(shotOutputPath, "Shot marker output")}>
                  Reveal
                </button>
              </div>
            </label>
            {#if shotMarkers.length > 0}
              <div class="shot-marker-list wide-option">
                <div class="course-list-toolbar compact-toolbar">
                  <small class="format-hint">{visibleShotMarkers(shotMarkers).length} shown of {shotMarkers.length} marker{shotMarkers.length === 1 ? "" : "s"}</small>
                  <button class="small-button" type="button" on:click={copyShotMarkerSummary}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" on:click={copyShotMarkerJson}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" on:click={() => copyVisibleShotMarkerFields("time")}>
                    Copy times
                  </button>
                  <button class="small-button" type="button" on:click={() => copyVisibleShotMarkerFields("score")}>
                    Copy scores
                  </button>
                </div>
                {#each visibleShotMarkers(shotMarkers) as marker}
                  <button
                    type="button"
                    title={`Select subtitle cue near ${formatTimestamp(marker.timestamp_seconds)}`}
                    on:click={() => selectSubtitleCueAtShotMarker(marker)}
                  >
                    <strong>{formatTimestamp(marker.timestamp_seconds)}</strong>
                    <small>score {marker.score.toFixed(3)}</small>
                  </button>
                {/each}
                {#if shotMarkers.length > 12}
                  <div class="course-list-toolbar compact-toolbar">
                    <button class="small-button" type="button" on:click={() => (shotMarkersExpanded = !shotMarkersExpanded)}>
                      {shotMarkersExpanded ? "Collapse markers" : "Show all markers"}
                    </button>
                  </div>
                {/if}
              </div>
            {/if}
            {#if shotError}
              <p class="error-text wide-option">{shotError}</p>
            {/if}
          </div>
          <div class="waveform-tools" aria-label="Waveform peaks">
            <div class="clip-tools-header">
              <div>
                <strong>Waveform peaks</strong>
                <small>{waveformResult ? `${waveformResult.bucket_count} peaks cached` : "Local FFmpeg audio peak cache"}</small>
              </div>
              <button class="primary-button compact-button" type="button" disabled={waveformBusy} on:click={runWaveformPeaks}>
                {waveformBusy ? "Generating" : "Generate peaks"}
              </button>
            </div>
            <label class="wide-option">
              <span>Source media</span>
              <div class="path-picker-row">
                <input bind:value={waveformInputPath} placeholder="C:/Media/source.mp4" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose source media" disabled={waveformInputBusy} on:click={chooseWaveformInputFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!waveformInputPath.trim()} on:click={() => openLocalPath(waveformInputPath, "Waveform source")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!waveformInputPath.trim()} on:click={() => revealLocalPath(waveformInputPath, "Waveform source")}>
                  Reveal
                </button>
              </div>
            </label>
            <label>
              <span>Peak buckets</span>
              <input bind:value={waveformBucketCount} inputmode="numeric" placeholder="256" spellcheck="false" />
            </label>
            {#if waveformResult}
              {@const activeWaveformResult = waveformResult}
              <div class="waveform-preview wide-option">
                <div class="waveform-controls">
                  <label class="waveform-zoom">
                    <span>Peak width</span>
                    <input bind:value={waveformPeakWidth} type="range" min="2" max="12" step="1" />
                  </label>
                  <label class="waveform-seek">
                    <span>Jump to time</span>
                    <div class="path-picker-row">
                      <input bind:value={waveformSeekTime} placeholder="01:23.500" spellcheck="false" />
                      <button class="secondary-button compact-button" type="button" on:click={jumpToWaveformTime}>
                        Jump
                      </button>
                    </div>
                  </label>
                </div>
                <div
                  class="waveform-bars"
                  aria-label="Waveform peak preview"
                  style={`--waveform-peak-width: ${normalizeWaveformPeakWidth(Number(waveformPeakWidth))}px`}
                >
                  {#each listWaveformTimelinePeaks(activeWaveformResult.peaks) as peak}
                    {@const barHeight = `${Math.max(4, Math.min(100, Math.max(Math.abs(peak.min), Math.abs(peak.max)) * 100))}%`}
                    <button
                      class:cue-overlap={waveformPeakOverlapsSubtitleCue(peak)}
                      class:shot-marker-overlap={waveformPeakContainsShotMarker(peak)}
                      class:selected-time={waveformPeakContainsTime(peak, selectedWaveformTimeSeconds)}
                      type="button"
                      aria-label={`Select subtitle cue near ${formatTimestamp(peak.start_seconds)}`}
                      style={`height: ${barHeight}`}
                      title={`${formatTimestamp(peak.start_seconds)} score ${peak.rms.toFixed(3)}`}
                      on:click={() => selectSubtitleCueAtWaveformPeak(peak)}
                    ></button>
                  {/each}
                </div>
                <small>
                  {formatDuration(activeWaveformResult.duration_seconds)} · {activeWaveformResult.sample_rate} Hz · waveform {selectedWaveformTimeSeconds === null ? "not selected" : formatTimestamp(selectedWaveformTimeSeconds)} · cue {formatSubtitleCueTiming()} · {activeWaveformResult.cache_path}
                </small>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" on:click={copyWaveformSummary}>Copy summary</button>
                  <button class="small-button" type="button" on:click={copyWaveformJson}>Copy JSON</button>
                  <button class="small-button" type="button" on:click={() => openLocalPath(activeWaveformResult.cache_path, "Waveform cache")}>Open cache</button>
                  <button class="small-button" type="button" on:click={() => revealLocalPath(activeWaveformResult.cache_path, "Waveform cache")}>Reveal cache</button>
                </div>
              </div>
            {/if}
            {#if waveformError}
              <p class="error-text wide-option">{waveformError}</p>
            {/if}
          </div>
          <div class="whisper-tools" aria-label="Whisper subtitles">
            <div class="clip-tools-header">
              <div>
                <strong>Whisper subtitles</strong>
                <small>{whisperResultPath || "Local Whisper CLI transcription to subtitle sidecar"}</small>
              </div>
              <div class="inline-actions">
                {#if whisperBusy}
                  <button class="secondary-button compact-button" type="button" on:click={cancelWhisperJob}>
                    Cancel
                  </button>
                {/if}
                <button class="primary-button compact-button" type="button" disabled={whisperBusy} on:click={runWhisperSubtitles}>
                  {whisperBusy ? "Transcribing" : "Generate"}
                </button>
              </div>
            </div>
            <label class="wide-option">
              <span>Input media</span>
              <div class="path-picker-row">
                <input bind:value={whisperInputPath} placeholder="C:/Media/source.mp4" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose media for Whisper" disabled={whisperInputBusy === "input"} on:click={chooseWhisperInputFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!whisperInputPath.trim()} on:click={() => openLocalPath(whisperInputPath, "Whisper input")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!whisperInputPath.trim()} on:click={() => revealLocalPath(whisperInputPath, "Whisper input")}>
                  Reveal
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Output folder</span>
              <div class="path-picker-row">
                <input bind:value={whisperOutputDir} placeholder="Default: beside input media" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose Whisper output folder" disabled={whisperInputBusy === "output"} on:click={chooseWhisperOutputDir}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!whisperOutputDir.trim()} on:click={() => openLocalPath(whisperOutputDir, "Whisper output folder")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!whisperOutputDir.trim()} on:click={() => revealLocalPath(whisperOutputDir, "Whisper output folder")}>
                  Reveal
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Output file</span>
              <div class="path-picker-row">
                <input bind:value={whisperOutputPath} placeholder={`Optional exact .${whisperOutputFormat} path`} spellcheck="false" />
                <button class="small-button" type="button" disabled={whisperInputBusy === "output-file"} on:click={chooseWhisperOutputPath}>
                  Save as
                </button>
                <button class="small-button" type="button" disabled={!whisperOutputPath.trim()} on:click={() => openLocalPath(whisperOutputPath, "Whisper output")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!whisperOutputPath.trim()} on:click={() => revealLocalPath(whisperOutputPath, "Whisper output")}>
                  Reveal
                </button>
              </div>
            </label>
            <label>
              <span>Format</span>
              <select bind:value={whisperOutputFormat} aria-label="Whisper output format">
                <option value="srt">SRT</option>
                <option value="vtt">VTT</option>
                <option value="txt">TXT</option>
              </select>
            </label>
            <label>
              <span>Task</span>
              <select bind:value={whisperTask} aria-label="Whisper task">
                <option value="transcribe">Transcribe</option>
                <option value="translate">Translate to English</option>
              </select>
            </label>
            <label>
              <span>Language</span>
              <input bind:value={whisperLanguage} placeholder="Optional, e.g. en" spellcheck="false" />
            </label>
            <label>
              <span>Model</span>
              <input bind:value={whisperModel} placeholder="tiny, base, small..." spellcheck="false" />
            </label>
            {#if whisperResultPath}
              <div class="clip-status wide-option section-actions compact-actions">
                <small>{whisperResultPath}</small>
                <button class="small-button" type="button" on:click={copyWhisperResultSummary}>Copy summary</button>
                <button class="small-button" type="button" on:click={copyWhisperResultJson}>Copy JSON</button>
                <button class="small-button" type="button" on:click={() => openLocalPath(whisperResultPath, "Whisper result")}>Open result</button>
                <button class="small-button" type="button" on:click={() => revealLocalPath(whisperResultPath, "Whisper result")}>Reveal result</button>
              </div>
            {/if}
            {#if whisperError}
              <p class="error-text wide-option">{whisperError}</p>
            {/if}
          </div>
          <div class="subtitle-workshop-tools" aria-label="Subtitle Workshop">
            <div class="clip-tools-header">
              <div>
                <strong>Subtitle Workshop</strong>
                <small>{subtitleWorkshopFormat ? `${subtitleWorkshopFormat.toUpperCase()} · ${subtitleWorkshopLineCount} lines` : "Open, edit, and save SRT/VTT/ASS"}</small>
              </div>
              <div class="inline-actions">
                <button class="secondary-button compact-button" type="button" disabled={subtitleWorkshopBusy} on:click={openSubtitleWorkshop}>
                  Open
                </button>
                <button class="primary-button compact-button" type="button" disabled={subtitleWorkshopBusy} on:click={saveSubtitleWorkshop}>
                  Save
                </button>
              </div>
            </div>
            <label class="wide-option">
              <span>Subtitle file</span>
              <div class="path-picker-row">
                <input bind:value={subtitleWorkshopInputPath} placeholder="C:/Subtitles/source.srt" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose subtitle file" disabled={subtitleWorkshopInputBusy} on:click={chooseSubtitleWorkshopFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!subtitleWorkshopInputPath.trim()} on:click={() => openLocalPath(subtitleWorkshopInputPath, "Subtitle source")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!subtitleWorkshopInputPath.trim()} on:click={() => revealLocalPath(subtitleWorkshopInputPath, "Subtitle source")}>
                  Reveal
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Editor</span>
              <textarea
                bind:this={subtitleWorkshopEditor}
                bind:value={subtitleWorkshopContent}
                placeholder="Open a subtitle file or paste SRT, VTT, or ASS content here"
                spellcheck="false"
                on:click={updateSubtitleWorkshopCueTiming}
                on:keyup={updateSubtitleWorkshopCueTiming}
                on:input={updateSubtitleWorkshopCueTiming}
              ></textarea>
            </label>
            <div class="subtitle-replace-row wide-option">
              <label>
                <span>Find</span>
                <input bind:value={subtitleWorkshopFindText} placeholder="Text to find" spellcheck="false" />
              </label>
              <label>
                <span>Replace with</span>
                <input bind:value={subtitleWorkshopReplaceText} placeholder="Replacement text" spellcheck="false" />
              </label>
              <label class="inline-check">
                <input type="checkbox" bind:checked={subtitleWorkshopRegexMode} />
                <span>Regex</span>
              </label>
              <button class="secondary-button compact-button" type="button" on:click={findNextSubtitleWorkshopMatch}>
                Find next
              </button>
              <button class="secondary-button compact-button" type="button" on:click={replaceAllSubtitleWorkshopMatches}>
                Replace all
              </button>
              <small>{subtitleWorkshopFindText.trim() ? `${subtitleWorkshopCurrentMatchIndex && subtitleWorkshopMatchCount ? `${subtitleWorkshopCurrentMatchIndex}/` : ""}${subtitleWorkshopMatchCount} match${subtitleWorkshopMatchCount === 1 ? "" : "es"}` : "Enter text to find"}</small>
            </div>
            <div class="subtitle-timing-row wide-option">
              <label>
                <span>Timing offset ms</span>
                <input bind:value={subtitleWorkshopTimingOffset} inputmode="numeric" placeholder="250 or -250" spellcheck="false" />
              </label>
              <button class="secondary-button compact-button" type="button" on:click={shiftSubtitleWorkshopTiming}>
                Shift timing
              </button>
              <button class="secondary-button compact-button" type="button" on:click={autoFixSubtitleWorkshopText}>
                Auto fix
              </button>
              <button class="secondary-button compact-button" type="button" on:click={cleanupSubtitleWorkshopTimeline}>
                Clean timeline
              </button>
              <small>SRT/VTT timing, sort, dedupe, and overlap cleanup</small>
            </div>
            <div class="subtitle-sync-row wide-option">
              <label>
                <span>Source A ms</span>
                <input bind:value={subtitleWorkshopSyncSourceA} inputmode="numeric" placeholder="1000" spellcheck="false" />
              </label>
              <label>
                <span>Target A ms</span>
                <input bind:value={subtitleWorkshopSyncTargetA} inputmode="numeric" placeholder="2000" spellcheck="false" />
              </label>
              <label>
                <span>Source B ms</span>
                <input bind:value={subtitleWorkshopSyncSourceB} inputmode="numeric" placeholder="3000" spellcheck="false" />
              </label>
              <label>
                <span>Target B ms</span>
                <input bind:value={subtitleWorkshopSyncTargetB} inputmode="numeric" placeholder="6000" spellcheck="false" />
              </label>
              <div class="subtitle-sync-actions">
                <button class="secondary-button compact-button" type="button" on:click={() => useSelectedSubtitleCueAsSyncPoint("a", "start")}>
                  Cue start A
                </button>
                <button class="secondary-button compact-button" type="button" on:click={() => useSelectedSubtitleCueAsSyncPoint("b", "start")}>
                  Cue start B
                </button>
                <button class="secondary-button compact-button" type="button" on:click={() => useSelectedSubtitleCueAsSyncPoint("a", "end")}>
                  Cue end A
                </button>
                <button class="secondary-button compact-button" type="button" on:click={() => useSelectedSubtitleCueAsSyncPoint("b", "end")}>
                  Cue end B
                </button>
                <button class="secondary-button compact-button" type="button" disabled={selectedWaveformTimeSeconds === null} on:click={() => useSelectedWaveformTimeAsSyncTarget("a")}>
                  Wave target A
                </button>
                <button class="secondary-button compact-button" type="button" disabled={selectedWaveformTimeSeconds === null} on:click={() => useSelectedWaveformTimeAsSyncTarget("b")}>
                  Wave target B
                </button>
                <button class="secondary-button compact-button" type="button" on:click={clearSubtitleWorkshopSyncPoints}>
                  Clear sync
                </button>
                <button class="secondary-button compact-button" type="button" on:click={syncSubtitleWorkshopTimingToTwoPoints}>
                  Sync timing
                </button>
              </div>
            </div>
            <label class="wide-option">
              <span>Save as</span>
              <div class="path-picker-row">
                <input bind:value={subtitleWorkshopOutputPath} placeholder="C:/Subtitles/edited.vtt" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose subtitle output" disabled={subtitleWorkshopInputBusy} on:click={chooseSubtitleWorkshopOutputPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!subtitleWorkshopOutputPath.trim()} on:click={() => openLocalPath(subtitleWorkshopOutputPath, "Subtitle output")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!subtitleWorkshopOutputPath.trim()} on:click={() => revealLocalPath(subtitleWorkshopOutputPath, "Subtitle output")}>
                  Reveal
                </button>
              </div>
              {#if subtitleWorkshopSavePreview}
                <small class:conversion-warning={subtitleWorkshopSavePreview.includes("not supported") || subtitleWorkshopSavePreview.includes("No timed subtitle cues")}>{subtitleWorkshopSavePreview}</small>
              {:else}
                <small>SRT/VTT converts from the output extension; ASS saves without lossy conversion.</small>
              {/if}
            </label>
            {#if subtitleWorkshopError}
              <p class="error-text wide-option">{subtitleWorkshopError}</p>
            {/if}
          </div>
        </div>
        <div class="panel local-library-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Library tools</p>
              <h2>Local reading library</h2>
            </div>
            <div class="inline-actions">
              <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={loadLibraryCatalog}>
                Refresh
              </button>
              <button class="secondary-button compact-button" type="button" disabled={libraryBusy || !libraryCatalog} on:click={pruneMissingLibraryCatalogItems}>
                Prune missing
              </button>
              <button class="secondary-button compact-button" type="button" disabled={libraryBusy || !libraryCatalog?.folders.length} on:click={rescanCurrentLibraryCatalog}>
                {libraryBusyMode === "rescan" ? "Rescanning" : "Rescan catalog"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={libraryBusy || !libraryCatalog?.item_count} on:click={clearCurrentLibraryCatalog}>
                Clear catalog
              </button>
              <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={previewLibraryScan}>
                {libraryBusyMode === "scan" ? "Scanning" : "Scan preview"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={importLibraryCatalogFolder}>
                {libraryBusyMode === "import" ? "Importing" : "Import catalog"}
              </button>
            </div>
          </div>
          <div class="metadata-tool">
            <label class="wide-option">
              <span>Folder</span>
              <div class="path-picker-row">
                <input bind:value={libraryFolderPath} placeholder="C:/Books" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose library folder" disabled={libraryFolderBusy} on:click={chooseLibraryFolder}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!libraryFolderPath.trim()} on:click={() => openLocalPath(libraryFolderPath, "Library folder")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!libraryFolderPath.trim()} on:click={() => revealLocalPath(libraryFolderPath, "Library folder")}>
                  Reveal
                </button>
              </div>
            </label>
            {#if libraryError}
              <p class="error-text">{libraryError}</p>
            {/if}
            {#if libraryCatalog}
              <small class="format-hint wide-option">
