              </small>
              <div class="section-actions compact-actions wide-option">
                <button class="small-button" type="button" disabled={!libraryCatalog} on:click={copyLibraryCatalogSummary}>
                  Copy catalog
                </button>
                <button class="small-button" type="button" disabled={!libraryCatalog} on:click={copyLibraryCatalogJson}>
                  Copy catalog JSON
                </button>
                <button class="small-button" type="button" disabled={libraryCatalog.folders.length === 0} on:click={() => copyLibraryCatalogFields("folder")}>
                  Copy folders
                </button>
              </div>
            {/if}
            <label class="wide-option">
              <span>Catalog JSON export</span>
              <div class="path-picker-row">
                <input bind:value={libraryCatalogExportPath} placeholder="C:/Backups/fetchdock-library-catalog.json" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose catalog export path" disabled={libraryBusy} on:click={chooseLibraryCatalogBackupExportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={exportLibraryCatalogBackup}>
                  {libraryBusyMode === "catalog-export" ? "Exporting" : "Export JSON"}
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Catalog JSON import</span>
              <div class="path-picker-row">
                <input bind:value={libraryCatalogImportPath} placeholder="C:/Backups/fetchdock-library-catalog.json" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose catalog JSON" disabled={libraryBusy} on:click={chooseLibraryCatalogBackupImportFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={libraryBusy || !libraryCatalogImportPath.trim()} on:click={importLibraryCatalogBackup}>
                  {libraryBusyMode === "catalog-import" ? "Importing" : "Import JSON"}
                </button>
              </div>
            </label>
            {#if libraryCatalogExportResult}
              <div class="section-actions compact-actions wide-option">
                <small>{libraryCatalogExportResult.exported_item_count} catalog item{libraryCatalogExportResult.exported_item_count === 1 ? "" : "s"} · {libraryCatalogExportResult.exported_folder_count} folder{libraryCatalogExportResult.exported_folder_count === 1 ? "" : "s"} · {libraryCatalogExportResult.output_path}</small>
                <button class="small-button" type="button" disabled={libraryBusy} on:click={openLibraryCatalogExportResult}>Open JSON</button>
                <button class="small-button" type="button" disabled={libraryBusy} on:click={revealLibraryCatalogExportResult}>Reveal JSON</button>
              </div>
            {/if}
            <div class="summary-panel wide-option">
              <div class="summary-header">
                <div>
                  <strong>Local library summary</strong>
                  {#if libraryLocalSummary}
                    <small>{libraryLocalSummary.catalog_item_count} item{libraryLocalSummary.catalog_item_count === 1 ? "" : "s"} · {libraryLocalSummary.local_item_count} local · {libraryLocalSummary.missing_item_count} missing · {libraryLocalSummary.average_progress_percent}% avg progress</small>
                  {:else}
                    <small>Catalog, reading-state, and reader settings summary</small>
                  {/if}
                </div>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={libraryBusy} on:click={refreshLibraryLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary} on:click={copyLibraryLocalSummary}>Copy summary</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary} on:click={copyLibraryLocalSummaryJson}>Copy JSON</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary} on:click={() => copyLibraryLocalSummaryFields("format")}>Copy formats</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary} on:click={() => copyLibraryLocalSummaryFields("metadata")}>Copy metadata</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary?.author_counts.length} on:click={() => copyLibraryLocalSummaryFields("author")}>Copy authors</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary?.reading_format_counts.length} on:click={() => copyLibraryLocalSummaryFields("reading-format")}>Copy reading formats</button>
                  <button class="small-button" type="button" disabled={!libraryLocalSummary} on:click={() => copyLibraryLocalSummaryFields("note")}>Copy notes</button>
                </div>
              </div>
              {#if libraryLocalSummary}
                <div class="compact-stats-grid">
                  <span>Formats <strong>{libraryLocalSummary.supported_format_count}</strong></span>
                  <span>Size <strong>{formatBytes(libraryLocalSummary.total_size_bytes)}</strong></span>
                  <span>Covers <strong>{libraryLocalSummary.catalog_cover_count}</strong></span>
                  <span>Authors <strong>{libraryLocalSummary.author_count}</strong></span>
                  <span>Reading states <strong>{libraryLocalSummary.reading_state_count}</strong></span>
                  <span>Started <strong>{libraryLocalSummary.started_item_count}</strong></span>
                  <span>Completed <strong>{libraryLocalSummary.completed_item_count}</strong></span>
                  <span>Bookmarks <strong>{libraryLocalSummary.bookmark_count}</strong></span>
                  <span>Highlights <strong>{libraryLocalSummary.highlight_count}</strong></span>
                  <span>Notes <strong>{libraryLocalSummary.highlight_note_count}</strong></span>
                </div>
                <small>Reader: {libraryLocalSummary.reader_theme} · {libraryLocalSummary.reader_font_family} · {libraryLocalSummary.reader_font_size_percent}% size · {libraryLocalSummary.reader_line_height_percent}% line · {libraryLocalSummary.reader_zoom_percent}% zoom{libraryLocalSummary.reader_focus_mode ? " · focus" : ""}</small>
              {/if}
              <div class="path-picker-row summary-export-row">
                <input bind:value={librarySummaryExportPath} placeholder="C:/path/library-summary.json" spellcheck="false" aria-label="Library summary export path" />
                <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={exportLibrarySummary}>{libraryBusyMode === "summary-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!librarySummaryExportPath.trim() && !librarySummaryExportResult} on:click={() => openLocalPath(librarySummaryExportResult || librarySummaryExportPath, "Library summary")}>Open export</button>
                <button class="small-button" type="button" disabled={!librarySummaryExportPath.trim() && !librarySummaryExportResult} on:click={() => revealLocalPath(librarySummaryExportResult || librarySummaryExportPath, "Library summary")}>Reveal export</button>
              </div>
            </div>
            <div class="summary-panel wide-option">
              <div class="summary-header">
                <div>
                  <strong>Reader format catalog</strong>
                  {#if libraryFormatCatalog}
                    <small>{libraryFormatCatalog.format_count} formats · file bodies {libraryFormatCatalog.includes_file_bodies ? "included" : "excluded"} · renderer QA {libraryFormatCatalog.verifies_full_renderer ? "verified" : "pending"}</small>
                  {:else}
                    <small>Local reader format capability boundaries.</small>
                  {/if}
                </div>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={libraryBusy} on:click={refreshLibraryLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!libraryFormatCatalog} on:click={copyLibraryFormatCatalogSummary}>Copy summary</button>
                  <button class="small-button" type="button" disabled={!libraryFormatCatalog} on:click={copyLibraryFormatCatalogJson}>Copy JSON</button>
                  <button class="small-button" type="button" disabled={!libraryFormatCatalog} on:click={() => copyLibraryFormatCatalogFields("format")}>Copy formats</button>
                  <button class="small-button" type="button" disabled={!libraryFormatCatalog} on:click={() => copyLibraryFormatCatalogFields("limit")}>Copy limits</button>
                  <button class="small-button" type="button" disabled={!libraryFormatCatalog} on:click={() => copyLibraryFormatCatalogFields("note")}>Copy notes</button>
                </div>
              </div>
              {#if libraryFormatCatalog}
                <div class="compact-stats-grid">
                  <span>Formats <strong>{libraryFormatCatalog.format_count}</strong></span>
                  <span>File bodies <strong>{libraryFormatCatalog.includes_file_bodies ? "yes" : "no"}</strong></span>
                  <span>Full renderer <strong>{libraryFormatCatalog.verifies_full_renderer ? "yes" : "pending"}</strong></span>
                  <span>Manual matrix <strong>{libraryFormatCatalog.verifies_manual_reader_matrix ? "yes" : "pending"}</strong></span>
                </div>
              {/if}
              <div class="path-picker-row summary-export-row">
                <input bind:value={libraryFormatCatalogExportPath} placeholder="C:/path/library-format-catalog.json" spellcheck="false" aria-label="Library format catalog export path" />
                <button class="secondary-button compact-button" type="button" disabled={libraryBusy} on:click={exportLibraryFormatCatalogFile}>{libraryBusyMode === "format-catalog-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!libraryFormatCatalogExportPath.trim() && !libraryFormatCatalogExportResult} on:click={() => openLocalPath(libraryFormatCatalogExportResult || libraryFormatCatalogExportPath, "Library format catalog")}>Open export</button>
                <button class="small-button" type="button" disabled={!libraryFormatCatalogExportPath.trim() && !libraryFormatCatalogExportResult} on:click={() => revealLocalPath(libraryFormatCatalogExportResult || libraryFormatCatalogExportPath, "Library format catalog")}>Reveal export</button>
              </div>
              <small>Metadata-only: no source document bodies, book contents, full renderer proof, or manual reader matrix.</small>
            </div>
            {#if libraryDisplayItems.length > 0}
              <div class="library-filter-row wide-option">
                <label>
                  <span>Search</span>
                  <input bind:value={librarySearchQuery} placeholder="Title, author, format, or path" spellcheck="false" />
                </label>
                <label>
                  <span>Format</span>
                  <select bind:value={libraryFormatFilter} aria-label="Library format filter">
                    {#each libraryFormatOptions as option}
                      <option value={option}>{option === "all" ? "All formats" : option.toUpperCase()}</option>
                    {/each}
                  </select>
                </label>
              </div>
              <div class="library-summary">
                <strong>
                  {visibleLibraryItems(filteredLibraryItems).length} shown of {libraryDisplayItems.length}
                  {libraryScan ? ` in ${libraryScan.folder_path}` : " catalog items"}
                </strong>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={copyFilteredLibraryItemSummary}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={copyFilteredLibraryItemJson}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={() => copyFilteredLibraryItemFields("path")}>
                    Copy paths
                  </button>
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={() => copyFilteredLibraryItemFields("title")}>
                    Copy titles
                  </button>
                  <button class="small-button" type="button" disabled={!filteredLibraryItems.some((item) => item.author)} on:click={() => copyFilteredLibraryItemFields("author")}>
                    Copy authors
                  </button>
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={() => copyFilteredLibraryItemFields("format")}>
                    Copy formats
                  </button>
                  <button class="small-button" type="button" disabled={filteredLibraryItems.length === 0} on:click={() => copyFilteredLibraryItemFields("size")}>
                    Copy sizes
                  </button>
                  <button class="small-button" type="button" disabled={!filteredLibraryItems.some((item) => item.cover_path)} on:click={() => copyFilteredLibraryItemFields("cover")}>
                    Copy covers
                  </button>
                  <button class="small-button" type="button" disabled={!filteredLibraryItems.some((item) => libraryMetadataLabel(item))} on:click={() => copyFilteredLibraryItemFields("metadata")}>
                    Copy metadata
                  </button>
                  <button class="small-button" type="button" disabled={!filteredLibraryItems.some((item) => item.modified_at)} on:click={() => copyFilteredLibraryItemFields("modified")}>
                    Copy modified
                  </button>
                </div>
                {#if libraryCatalog}
                  <div class="section-actions compact-actions">
                    <button
                      class="secondary-button compact-button danger"
                      type="button"
                      disabled={libraryBusy || libraryBulkBusy === "remove-filtered" || filteredCatalogLibraryItemCount === 0}
                      on:click={requestFilteredLibraryCatalogItemsRemove}
                    >
                      {libraryBulkBusy === "remove-filtered" ? "Removing" : "Remove shown"}
                    </button>
                    <small>{filteredCatalogLibraryItemCount} shown catalog item{filteredCatalogLibraryItemCount === 1 ? "" : "s"} removable.</small>
                  </div>
                {/if}
                {#if filteredLibraryItems.length > 20 && !librarySearchQuery.trim() && libraryFormatFilter === "all"}
                  <div class="course-list-toolbar compact-toolbar">
                    <small>{filteredLibraryItems.length} matching supported file{filteredLibraryItems.length === 1 ? "" : "s"}</small>
                    <button class="small-button" type="button" on:click={() => (libraryItemsExpanded = !libraryItemsExpanded)}>
                      {libraryItemsExpanded ? "Collapse files" : "Show all files"}
                    </button>
                  </div>
                {/if}
                <div class="library-item-list">
                  {#each visibleLibraryItems(filteredLibraryItems) as item}
                    <article>
                      <div class="library-item-main">
                        {#if libraryItemCoverUrl(item)}
                          <img src={libraryItemCoverUrl(item)} alt="" />
                        {/if}
                        <div>
                          <span>{item.title}</span>
                          <small>{item.format.toUpperCase()} · {item.author ?? "Unknown author"}{libraryMetadataLabel(item) ? ` · ${libraryMetadataLabel(item)}` : ""}{item.cover_path ? " · cover" : ""} · {formatBytes(item.size_bytes)}</small>
                          <small>{libraryPreviewBusy === item.path ? "Opening" : item.path}</small>
                        </div>
                      </div>
                      <div class="section-actions">
                        <button class="small-button" type="button" disabled={libraryPreviewBusy === item.path} on:click={() => openLibraryPreview(item)}>
                          {["txt", "html", "htm", "pdf", "cbz", "epub"].includes(item.format.toLowerCase()) ? "Preview" : "Open"}
                        </button>
                        <button class="small-button" type="button" disabled={libraryPreviewBusy === item.path} on:click={() => revealLibraryItem(item)}>
                          Reveal
                        </button>
                        <button
                          class="small-button danger"
                          type="button"
                          disabled={libraryBusy || !libraryCatalog?.items.some((catalogItem) => catalogItem.path === item.path)}
                          on:click={() => removeLibraryCatalogItem(item)}
                        >
                          Remove
                        </button>
                      </div>
                    </article>
                  {/each}
                </div>
                {#if filteredLibraryItems.length === 0}
                  <small class="format-hint">No library items match the current filters.</small>
                {/if}
              </div>
            {/if}
            {#if libraryPreview}
              <div
                class={`reader-preview reader-theme-${libraryReaderSettings?.theme ?? "paper"} reader-font-${libraryReaderSettings?.font_family ?? "serif"} ${libraryReaderSettings?.focus_mode ? "focus-mode" : ""}`}
                style={readerPreviewStyle}
              >
                <div>
                  <strong>{libraryPreview.title}</strong>
                  <small>
                    {libraryPreview.format.toUpperCase()}
                    {#if libraryPreview.format === "cbz"}
                      · {libraryPreview.word_count} pages
                    {:else if libraryPreview.format === "epub"}
                      · {libraryPreview.word_count} sections
                    {:else if libraryPreview.format === "pdf" && libraryPreview.word_count > 0}
                      · {libraryPreview.word_count} pages
                    {:else if libraryPreview.format !== "pdf"}
                      · {libraryPreview.word_count} words
                    {/if}
                    · {libraryPreview.modified_at ?? "modified time unknown"}
                  </small>
                  <div class="preview-toolbar section-actions">
                    <button class="small-button" type="button" disabled={libraryPreviewBusy === libraryPreview.path} on:click={openCurrentLibraryExternal}>
                      Open external
                    </button>
                    <button class="small-button" type="button" disabled={libraryPreviewBusy === libraryPreview.path} on:click={revealCurrentLibraryPreview}>
                      Reveal
                    </button>
                    <button class="small-button" type="button" on:click={copyCurrentLibraryPreviewSummary}>
                      Copy preview
                    </button>
                    <button class="small-button" type="button" on:click={copyCurrentLibraryPreviewJson}>
                      Copy preview JSON
                    </button>
                    <button class="small-button" type="button" disabled={libraryPreview.format === "pdf" || libraryPreview.format === "cbz"} on:click={copyCurrentLibraryPreviewText}>
                      Copy text
                    </button>
                  </div>
                </div>
                <div class="reader-controls">
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={libraryReaderSettings?.focus_mode ?? false}
                      disabled={libraryReaderSettingsBusy}
                      on:change={(event) => saveLibraryReaderSettings({ focusMode: event.currentTarget.checked })}
                    />
                    <span>Focus</span>
                  </label>
                  <select
                    value={libraryReaderSettings?.theme ?? "paper"}
                    disabled={libraryReaderSettingsBusy}
                    aria-label="Reader theme"
                    on:change={(event) => saveLibraryReaderSettings({ theme: event.currentTarget.value as LibraryReaderSettings["theme"] })}
                  >
                    <option value="paper">Paper</option>
                    <option value="light">Light</option>
                    <option value="dark">Dark</option>
                  </select>
                  <label>
                    <span>Family</span>
                    <select
                      value={libraryReaderSettings?.font_family ?? "serif"}
                      disabled={libraryReaderSettingsBusy}
                      aria-label="Reader font family"
                      on:change={(event) => saveLibraryReaderSettings({ fontFamily: event.currentTarget.value as LibraryReaderSettings["font_family"] })}
                    >
                      <option value="serif">Serif</option>
                      <option value="sans">Sans</option>
                      <option value="system">System</option>
                      <option value="mono">Mono</option>
                    </select>
                  </label>
                  <label>
                    <span>Size</span>
                    <input
                      value={libraryReaderSettings?.font_size_percent ?? 100}
                      inputmode="numeric"
                      disabled={libraryReaderSettingsBusy}
                      aria-label="Reader font size percent"
                      on:change={(event) => saveLibraryReaderSettings({ fontSizePercent: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <label>
                    <span>Line</span>
                    <input
                      value={libraryReaderSettings?.line_height_percent ?? 160}
                      inputmode="numeric"
                      disabled={libraryReaderSettingsBusy}
                      aria-label="Reader line height percent"
                      on:change={(event) => saveLibraryReaderSettings({ lineHeightPercent: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <label>
                    <span>Zoom</span>
                    <input
                      value={libraryReaderSettings?.zoom_percent ?? 100}
                      inputmode="numeric"
                      disabled={libraryReaderSettingsBusy}
                      aria-label="Reader zoom percent"
                      on:change={(event) => saveLibraryReaderSettings({ zoomPercent: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={libraryReaderSettingsBusy} on:click={resetLibraryReaderSettings}>
                    Reset
                  </button>
                  <input bind:value={libraryReaderSettingsExportPath} placeholder="C:/Backups/fetchdock-reader-settings.json" spellcheck="false" aria-label="Reader settings export path" />
                  <button class="small-button" type="button" disabled={libraryReaderSettingsBusy} on:click={chooseLibraryReaderSettingsExportPath}>
                    Save as
                  </button>
                  <button class="small-button" type="button" disabled={libraryReaderSettingsBusy} on:click={exportLibraryReaderSettingsBackup}>
                    Export settings
                  </button>
                  <button class="small-button" type="button" disabled={!libraryReaderSettingsExportPath.trim() && !libraryReaderSettingsExportResult} on:click={() => openLocalPath(libraryReaderSettingsExportResult?.output_path || libraryReaderSettingsExportPath, "Reader settings backup")}>
                    Open settings
                  </button>
                  <input bind:value={libraryReaderSettingsImportPath} placeholder="C:/Backups/fetchdock-reader-settings.json" spellcheck="false" aria-label="Reader settings import path" />
                  <button class="small-button" type="button" disabled={libraryReaderSettingsBusy} on:click={chooseLibraryReaderSettingsImportFile}>
                    Choose settings
                  </button>
                  <button class="small-button" type="button" disabled={libraryReaderSettingsBusy || !libraryReaderSettingsImportPath.trim()} on:click={importLibraryReaderSettingsBackup}>
                    Import settings
                  </button>
                  <small>Reader settings JSON only moves focus/theme/font/spacing/zoom; catalog, books, reading-state, notes, and annotations stay separate.</small>
                </div>
                <div class="reader-state-panel">
                  <label>
                    <span>Progress</span>
                    <input bind:value={libraryProgressInput} inputmode="numeric" aria-label="Reading progress percent" />
                  </label>
                  <label>
                    <span>Bookmark label</span>
                    <input bind:value={libraryBookmarkLabel} placeholder="Chapter or note" spellcheck="true" />
                  </label>
                  <div class="section-actions">
                    <button class="secondary-button" type="button" disabled={libraryStateBusy} on:click={saveCurrentLibraryProgress}>Save progress</button>
                    <button class="secondary-button" type="button" disabled={libraryStateBusy} on:click={addCurrentLibraryBookmark}>Add bookmark</button>
                    <button class="small-button" type="button" disabled={libraryNoteBusy} on:click={saveCurrentLibraryBookmarkAsNote}>
                      {libraryNoteBusy ? "Saving note" : "Bookmark note"}
                    </button>
                    <button class="small-button" type="button" on:click={() => scrollLibraryReaderToProgress()}>Jump to progress</button>
                    <button class="small-button" type="button" on:click={useLibraryScrollAsDraftProgress}>Use scroll</button>
                  </div>
                  <div class="reader-quick-progress" aria-label="Reader quick progress">
                    {#each [0, 25, 50, 75, 100] as progress}
                      <button class="small-button" type="button" on:click={() => jumpToLibraryPosition(progress)}>{progress}%</button>
                    {/each}
                    <button class="small-button" type="button" on:click={setLibraryBookmarkDraftAtCurrentProgress}>Bookmark here</button>
                  </div>
                  <textarea bind:value={libraryHighlightText} placeholder="Highlight text" spellcheck="true" aria-label="Highlight text"></textarea>
                  <input bind:value={libraryHighlightNote} placeholder="Highlight note, optional" spellcheck="true" aria-label="Highlight note" />
                  <div class="section-actions">
                    <button class="secondary-button" type="button" disabled={libraryStateBusy} on:click={addCurrentLibraryHighlight}>Add highlight</button>
                    <button class="small-button" type="button" on:click={captureLibrarySelection}>Use selection</button>
                    <button class="small-button" type="button" on:click={setLibraryHighlightDraftAtCurrentProgress}>Highlight here</button>
                    <button class="secondary-button" type="button" disabled={libraryNoteBusy || !libraryHighlightText.trim()} on:click={saveCurrentLibraryHighlightAsNote}>
                      {libraryNoteBusy ? "Saving note" : "Save as note"}
                    </button>
                  </div>
                  <label>
                    <span>Export</span>
                    <select bind:value={libraryExportFormat} aria-label="Reading state export format">
                      <option value="markdown">Markdown</option>
                      <option value="json">JSON</option>
                    </select>
                  </label>
                  <label class="wide-option">
                    <span>Export path</span>
                    <div class="path-picker-row">
                      <input bind:value={libraryExportPath} placeholder="C:/Books/book.reading-state.md" spellcheck="false" />
                      <button class="icon-button" type="button" title="Choose reading export path" disabled={libraryStateBusy || !libraryPreview} on:click={chooseLibraryExportPath}>
                        <FolderOpen size={17} />
                      </button>
                    </div>
                  </label>
                  <div class="section-actions">
                    <button
                      class="small-button"
                      type="button"
                      on:click={() => {
                        if (libraryPreview) libraryExportPath = defaultLibraryExportPath(libraryPreview.path, libraryExportFormat);
                      }}
                    >
                      Default path
                    </button>
                    <button class="secondary-button" type="button" disabled={libraryStateBusy} on:click={exportCurrentLibraryReadingState}>
                      Export state
                    </button>
                  </div>
                  <label class="wide-option">
                    <span>Import JSON</span>
                    <div class="path-picker-row">
                      <input bind:value={libraryImportStatePath} placeholder="C:/Books/book.reading-state.json" spellcheck="false" />
                      <button class="icon-button" type="button" title="Choose reading state JSON" disabled={libraryStateBusy} on:click={chooseLibraryReadingStateFile}>
                        <FolderOpen size={17} />
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={libraryStateBusy || !libraryImportStatePath.trim()} on:click={importCurrentLibraryReadingState}>
                        Import state
                      </button>
                    </div>
                  </label>
                  {#if libraryExportResult}
                    <div class="section-actions compact-actions">
                      <small>{libraryExportResult.format} export · {libraryExportResult.bookmark_count} bookmark{libraryExportResult.bookmark_count === 1 ? "" : "s"} · {libraryExportResult.highlight_count} highlight{libraryExportResult.highlight_count === 1 ? "" : "s"} · {libraryExportResult.output_path}</small>
                      <button class="small-button" type="button" disabled={libraryStateBusy} on:click={openLibraryExportResult}>Open export</button>
                      <button class="small-button" type="button" disabled={libraryStateBusy} on:click={revealLibraryExportResult}>Reveal export</button>
                    </div>
                  {/if}
                  <label class="wide-option">
                    <span>All reading states JSON</span>
                    <div class="path-picker-row">
                      <input bind:value={libraryReadingStatesExportPath} placeholder="C:/Backups/fetchdock-library-reading-states.json" spellcheck="false" />
                      <button class="icon-button" type="button" title="Choose reading states export path" disabled={libraryStateBusy} on:click={chooseLibraryReadingStatesBackupExportPath}>
                        <FolderOpen size={17} />
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={libraryStateBusy} on:click={exportLibraryReadingStatesBackup}>
                        Export all
                      </button>
                    </div>
                  </label>
                  <label class="wide-option">
                    <span>Import all states JSON</span>
                    <div class="path-picker-row">
                      <input bind:value={libraryReadingStatesImportPath} placeholder="C:/Backups/fetchdock-library-reading-states.json" spellcheck="false" />
                      <button class="icon-button" type="button" title="Choose reading states JSON" disabled={libraryStateBusy} on:click={chooseLibraryReadingStatesBackupImportFile}>
                        <FolderOpen size={17} />
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={libraryStateBusy || !libraryReadingStatesImportPath.trim()} on:click={importLibraryReadingStatesBackup}>
                        Import all
                      </button>
                    </div>
                  </label>
                  {#if libraryReadingStatesExportResult}
                    <div class="section-actions compact-actions">
                      <small>{libraryReadingStatesExportResult.exported_count} reading state{libraryReadingStatesExportResult.exported_count === 1 ? "" : "s"} · {libraryReadingStatesExportResult.bookmark_count} bookmark{libraryReadingStatesExportResult.bookmark_count === 1 ? "" : "s"} · {libraryReadingStatesExportResult.highlight_count} highlight{libraryReadingStatesExportResult.highlight_count === 1 ? "" : "s"} · {libraryReadingStatesExportResult.output_path}</small>
                      <button class="small-button" type="button" disabled={libraryStateBusy} on:click={openLibraryReadingStatesExportResult}>Open JSON</button>
                      <button class="small-button" type="button" disabled={libraryStateBusy} on:click={revealLibraryReadingStatesExportResult}>Reveal JSON</button>
                    </div>
                  {/if}
                  {#if libraryReadingState}
                    <small>{libraryReadingState.progress_percent}% read · {libraryReadingState.bookmarks.length} bookmark{libraryReadingState.bookmarks.length === 1 ? "" : "s"} · {libraryReadingState.highlights.length} highlight{libraryReadingState.highlights.length === 1 ? "" : "s"} · {filteredLibraryBookmarks.length + filteredLibraryHighlights.length} shown</small>
                    <div class="section-actions">
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={copyVisibleLibraryAnnotationSummary}
                      >
                        Copy summary
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={copyVisibleLibraryAnnotationJson}
                      >
                        Copy JSON
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={() => copyVisibleLibraryAnnotationFields("id")}
                      >
                        Copy ids
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={() => copyVisibleLibraryAnnotationFields("text")}
                      >
                        Copy text
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={() => copyVisibleLibraryAnnotationFields("type")}
                      >
                        Copy types
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={() => copyVisibleLibraryAnnotationFields("progress")}
                      >
                        Copy progress
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={() => copyVisibleLibraryAnnotationFields("created")}
                      >
                        Copy created
                      </button>
                      <button
                        class="small-button danger"
                        type="button"
                        disabled={Boolean(libraryAnnotationBusy) || visibleLibraryBookmarks(filteredLibraryBookmarks).length + visibleLibraryHighlights(filteredLibraryHighlights).length === 0}
                        on:click={requestFilteredLibraryAnnotationsRemove}
                      >
                        {libraryAnnotationBusy === "remove-filtered" ? "Removing" : "Remove shown"}
                      </button>
                      <button
                        class="small-button danger"
                        type="button"
                        disabled={Boolean(libraryAnnotationBusy) || libraryReadingState.bookmarks.length + libraryReadingState.highlights.length === 0}
                        on:click={() => requestLibraryAnnotationsClear("all")}
                      >
                        Clear annotations
                      </button>
                    </div>
                    <div class="library-filter-row">
                      <input
                        bind:value={libraryAnnotationSearch}
                        placeholder="Search bookmarks and highlights"
                        spellcheck="false"
                        aria-label="Reading annotation search"
                      />
                      <select bind:value={libraryAnnotationTypeFilter} aria-label="Reading annotation type filter">
                        <option value="all">All annotations</option>
                        <option value="bookmarks">Bookmarks</option>
                        <option value="highlights">Highlights</option>
                      </select>
                    </div>
                    {#if libraryReadingState.bookmarks.length + libraryReadingState.highlights.length > 0 && filteredLibraryBookmarks.length + filteredLibraryHighlights.length === 0}
                      <small class="format-hint">No reading annotations match the current filters.</small>
                    {/if}
                    {#if filteredLibraryBookmarks.length > 0}
                      <div class="reader-state-list">
                        <div class="course-list-toolbar compact-toolbar">
                          <small>Showing {visibleLibraryBookmarks(filteredLibraryBookmarks).length} of {filteredLibraryBookmarks.length} bookmark{filteredLibraryBookmarks.length === 1 ? "" : "s"}</small>
                          {#if filteredLibraryBookmarks.length > 8 && !libraryAnnotationSearch.trim() && libraryAnnotationTypeFilter === "all"}
                            <button class="small-button" type="button" on:click={() => (libraryBookmarksExpanded = !libraryBookmarksExpanded)}>
                              {libraryBookmarksExpanded ? "Collapse bookmarks" : "Show all bookmarks"}
                            </button>
                          {/if}
                        </div>
                        {#each visibleLibraryBookmarks(filteredLibraryBookmarks) as bookmark}
                          <article>
                            <span>{bookmark.position_percent}% · {bookmark.label}</span>
                            <div class="section-actions">
                              <button class="small-button" type="button" on:click={() => jumpToLibraryPosition(bookmark.position_percent)}>Go</button>
                              <button class="small-button" type="button" on:click={() => copyLibraryBookmarkForEdit(bookmark)}>Edit</button>
                              <button class="small-button" type="button" disabled={libraryAnnotationBusy === bookmark.id} on:click={() => saveLibraryBookmarkItemAsNote(bookmark)}>Note</button>
                              <button class="small-button" type="button" disabled={libraryAnnotationBusy === bookmark.id} on:click={() => applyLibraryBookmark(bookmark.id)}>Update</button>
                              <button class="small-button danger" type="button" disabled={libraryAnnotationBusy === bookmark.id} on:click={() => removeLibraryBookmark(bookmark.id)}>Delete</button>
                            </div>
                          </article>
                        {/each}
                      </div>
                    {/if}
                    {#if filteredLibraryHighlights.length > 0}
                      <div class="reader-state-list">
                        <div class="course-list-toolbar compact-toolbar">
                          <small>Showing {visibleLibraryHighlights(filteredLibraryHighlights).length} of {filteredLibraryHighlights.length} highlight{filteredLibraryHighlights.length === 1 ? "" : "s"}</small>
                          {#if filteredLibraryHighlights.length > 8 && !libraryAnnotationSearch.trim() && libraryAnnotationTypeFilter === "all"}
                            <button class="small-button" type="button" on:click={() => (libraryHighlightsExpanded = !libraryHighlightsExpanded)}>
                              {libraryHighlightsExpanded ? "Collapse highlights" : "Show all highlights"}
                            </button>
                          {/if}
                        </div>
                        {#each visibleLibraryHighlights(filteredLibraryHighlights) as highlight}
                          <article>
                            <span>{highlight.position_percent}% · {highlight.text}{highlight.note ? ` · ${highlight.note}` : ""}</span>
                            <div class="section-actions">
                              <button class="small-button" type="button" on:click={() => jumpToLibraryPosition(highlight.position_percent)}>Go</button>
                              <button class="small-button" type="button" on:click={() => copyLibraryHighlightForEdit(highlight)}>Edit</button>
                              <button class="small-button" type="button" disabled={libraryAnnotationBusy === highlight.id} on:click={() => saveLibraryHighlightItemAsNote(highlight)}>Note</button>
                              <button class="small-button" type="button" disabled={libraryAnnotationBusy === highlight.id} on:click={() => applyLibraryHighlight(highlight.id)}>Update</button>
                              <button class="small-button danger" type="button" disabled={libraryAnnotationBusy === highlight.id} on:click={() => removeLibraryHighlight(highlight.id)}>Delete</button>
                            </div>
                          </article>
                        {/each}
                      </div>
                    {/if}
                  {/if}
                </div>
                <div
                  class="reader-content-scroll"
                  bind:this={libraryReaderScrollElement}
                  on:scroll={syncLibraryProgressFromScroll}
                >
                  {#if libraryPreview.format === "html" || libraryPreview.format === "htm"}
                    <iframe title={libraryPreview.title} sandbox="" srcdoc={libraryPreview.content}></iframe>
                  {:else if libraryPreview.format === "pdf"}
                    {#if pdfPreviewSummary(libraryPreview).length > 0}
                      <div class="pdf-metadata-preview">
                        <strong>PDF document metadata</strong>
                        <div>
                          {#each pdfPreviewSummary(libraryPreview) as line}
                            <span>{line}</span>
                          {/each}
                        </div>
                      </div>
                    {/if}
                    <iframe class="pdf-preview-frame" title={libraryPreview.title} src={libraryPreviewUrl}></iframe>
                  {:else if libraryPreview.format === "cbz"}
                    <div class="cbz-manifest-preview">
                      <strong>{typeof libraryPreview.extra_json?.page_count === "number" ? libraryPreview.extra_json.page_count : cbzPreviewPages(libraryPreview).length} image page{(typeof libraryPreview.extra_json?.page_count === "number" ? libraryPreview.extra_json.page_count : cbzPreviewPages(libraryPreview).length) === 1 ? "" : "s"} found</strong>
                      <small>{cbzPreviewImages(libraryPreview).length > 0 ? `${cbzPreviewImages(libraryPreview).length} page preview image${cbzPreviewImages(libraryPreview).length === 1 ? "" : "s"} cached locally.` : "Use Preview beside a page row to cache an individual image page locally."}</small>
                      {#if cbzPreviewPages(libraryPreview).length > 0}
                        <div class="reader-page-controls">
                          <button class="small-button" type="button" disabled={Boolean(libraryCbzPreviewBusy) || boundedLibraryIndex(libraryCbzCurrentPageInput, cbzPreviewPages(libraryPreview).length) <= 1} on:click={() => moveLibraryCbzPage(-1)}>
                            Previous
                          </button>
                          <label>
                            <span>Page</span>
                            <input bind:value={libraryCbzCurrentPageInput} inputmode="numeric" aria-label="CBZ page index" />
                          </label>
                          <small>of {cbzPreviewPages(libraryPreview).length}</small>
                          <button class="small-button" type="button" disabled={Boolean(libraryCbzPreviewBusy)} on:click={() => moveLibraryCbzPage(0)}>
                            {libraryCbzPreviewBusy ? "Caching" : "Go"}
                          </button>
                          <button class="small-button" type="button" disabled={Boolean(libraryCbzPreviewBusy) || boundedLibraryIndex(libraryCbzCurrentPageInput, cbzPreviewPages(libraryPreview).length) >= cbzPreviewPages(libraryPreview).length} on:click={() => moveLibraryCbzPage(1)}>
                            Next
                          </button>
                        </div>
                      {/if}
                      {#if typeof libraryPreview.extra_json?.total_image_size_bytes === "number"}
                        <small>
                          {formatBytes(libraryPreview.extra_json.total_image_size_bytes)}
                          {typeof libraryPreview.extra_json?.total_image_compressed_size_bytes === "number"
                            ? ` source images · ${formatBytes(libraryPreview.extra_json.total_image_compressed_size_bytes)} compressed`
                            : " source images"}
                          {libraryPreview.extra_json?.truncated ? " · preview list capped" : ""}
                        </small>
                      {/if}
                      {#if cbzPreviewImages(libraryPreview).length > 0}
                        <div class="cbz-page-preview-grid">
                          {#each cbzPreviewImages(libraryPreview) as page}
                          <figure>
                            <img src={page.src} alt={`Page ${page.index}`} />
                            <figcaption>
                              {page.index}. {page.path}
                              <button
                                class="inline-text-button"
                                type="button"
                                on:click={() => jumpToLibraryPosition(indexedPreviewProgress(page.index, cbzPreviewPages(libraryPreview).length))}
                              >
                                Go
                              </button>
                            </figcaption>
                          </figure>
                          {/each}
                        </div>
                      {/if}
                      <div>
                        {#each visibleCbzPreviewPages(libraryPreview) as page}
                          <span>
                            {page.index}. {page.path}{page.size_bytes ? ` · ${formatBytes(page.size_bytes)}` : ""}
                            <button
                              class="inline-text-button"
                              type="button"
                              on:click={() => jumpToLibraryPosition(indexedPreviewProgress(page.index, cbzPreviewPages(libraryPreview).length))}
                            >
                              Go
                            </button>
                            {#if !page.preview_path}
                              <button
                                class="inline-text-button"
                                type="button"
                                disabled={libraryCbzPreviewBusy === String(page.index)}
                                on:click={() => loadCbzPagePreview(page)}
                              >
                                {libraryCbzPreviewBusy === String(page.index) ? "Caching" : "Preview"}
                              </button>
                            {/if}
                          </span>
                        {/each}
                      </div>
                      {#if cbzPreviewPages(libraryPreview).length > 60}
                        <div class="course-list-toolbar compact-toolbar">
                          <small>{visibleCbzPreviewPages(libraryPreview).length} shown of {cbzPreviewPages(libraryPreview).length} archive page{cbzPreviewPages(libraryPreview).length === 1 ? "" : "s"}</small>
                          <button class="small-button" type="button" on:click={() => (libraryCbzPagesExpanded = !libraryCbzPagesExpanded)}>
                            {libraryCbzPagesExpanded ? "Collapse pages" : "Show all pages"}
                          </button>
                        </div>
                      {/if}
                    </div>
                  {:else if libraryPreview.format === "epub"}
                    <div class="cbz-manifest-preview">
                      <strong>EPUB package manifest</strong>
                      <small>{epubTextPreviews(libraryPreview).length > 0 ? `${epubTextPreviews(libraryPreview).length} spine text preview${epubTextPreviews(libraryPreview).length === 1 ? "" : "s"} extracted locally.` : "This EPUB has package metadata and reading order; no local spine text was extracted."}</small>
                      {#if epubReadingOrder(libraryPreview).length > 0}
                        <div class="reader-page-controls">
                          <button class="small-button" type="button" disabled={Boolean(libraryEpubPreviewBusy) || boundedLibraryIndex(libraryEpubCurrentSpineInput, epubReadingOrder(libraryPreview).length) <= 1} on:click={() => moveLibraryEpubSpine(-1)}>
                            Previous
                          </button>
                          <label>
                            <span>Spine</span>
                            <input bind:value={libraryEpubCurrentSpineInput} inputmode="numeric" aria-label="EPUB spine index" />
                          </label>
                          <small>of {epubReadingOrder(libraryPreview).length}</small>
                          <button class="small-button" type="button" disabled={Boolean(libraryEpubPreviewBusy)} on:click={() => moveLibraryEpubSpine(0)}>
                            {libraryEpubPreviewBusy ? "Extracting" : "Go"}
                          </button>
                          <button class="small-button" type="button" disabled={Boolean(libraryEpubPreviewBusy) || boundedLibraryIndex(libraryEpubCurrentSpineInput, epubReadingOrder(libraryPreview).length) >= epubReadingOrder(libraryPreview).length} on:click={() => moveLibraryEpubSpine(1)}>
                            Next
                          </button>
                        </div>
                      {/if}
                      <div>
                        {#each epubPreviewSummary(libraryPreview) as line}
                          <span>{line}</span>
                        {/each}
                      </div>
                      {#if epubTextPreviews(libraryPreview).length > 0}
                        <strong>Reader text preview</strong>
                        <pre class="epub-reader-text">{libraryPreview.content}</pre>
                        <div class="epub-text-preview-list">
                          {#each epubTextPreviews(libraryPreview) as item}
                            <article>
                              <div class="preview-row-heading">
                                <strong>{item.index}. {item.path}</strong>
                                <button
                                  class="small-button"
                                  type="button"
                                  on:click={() => jumpToLibraryPosition(indexedPreviewProgress(item.index, epubReadingOrder(libraryPreview).length || epubTextPreviews(libraryPreview).length))}
                                >
                                  Go
                                </button>
                              </div>
                              <p>{item.text}</p>
                            </article>
                          {/each}
                        </div>
                      {/if}
                      {#if epubReadingOrder(libraryPreview).length > 0}
                        <strong>Reading order preview</strong>
                        <div>
                          {#each visibleEpubReadingOrder(libraryPreview) as item}
                            <span>
                              {item.index}. {item.href ?? item.idref}
                              <button
                                class="inline-text-button"
                                type="button"
                                on:click={() => jumpToLibraryPosition(indexedPreviewProgress(item.index, epubReadingOrder(libraryPreview).length))}
                              >
                                Go
                              </button>
                              {#if !epubTextPreviews(libraryPreview).some((preview) => preview.index === item.index)}
                                <button
                                  class="inline-text-button"
                                  type="button"
                                  disabled={libraryEpubPreviewBusy === String(item.index)}
                                  on:click={() => loadEpubTextPreview(item)}
                                >
                                  {libraryEpubPreviewBusy === String(item.index) ? "Extracting" : "Extract text"}
                                </button>
                              {/if}
                            </span>
                          {/each}
                        </div>
                        {#if epubReadingOrder(libraryPreview).length > 40}
                          <div class="course-list-toolbar compact-toolbar">
                            <small>{visibleEpubReadingOrder(libraryPreview).length} shown of {epubReadingOrder(libraryPreview).length} reading-order item{epubReadingOrder(libraryPreview).length === 1 ? "" : "s"}</small>
                            <button class="small-button" type="button" on:click={() => (libraryEpubReadingOrderExpanded = !libraryEpubReadingOrderExpanded)}>
                              {libraryEpubReadingOrderExpanded ? "Collapse order" : "Show full order"}
                            </button>
                          </div>
                        {/if}
                      {/if}
                    </div>
                  {:else}
                    <pre>{libraryPreview.content}</pre>
                  {/if}
                </div>
              </div>
            {/if}
          </div>
        </div>
        <div class="panel local-library-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Music tools</p>
              <h2>Local music library</h2>
            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={refreshMusicCatalog}>
                Refresh
              </button>
              <button class="secondary-button compact-button" type="button" disabled={musicBusy || !musicCatalog} on:click={pruneMissingMusicCatalogTracks}>
                Prune missing
              </button>
              <button class="secondary-button compact-button" type="button" disabled={musicBusy || !musicCatalog?.folders.length} on:click={rescanCurrentMusicCatalog}>
                {musicBusyMode === "rescan" ? "Rescanning" : "Rescan catalog"}
              </button>
              <button class="secondary-button compact-button danger" type="button" disabled={musicBusy || !musicCatalog?.track_count} on:click={clearCurrentMusicCatalog}>
                Clear catalog
              </button>
              <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={importMusicLibraryFolder}>
                {musicBusyMode === "import" ? "Importing" : "Import"}
              </button>
              <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={runMusicScan}>
                {musicBusyMode === "scan" ? "Scanning" : "Scan"}
              </button>
            </div>
          </div>
          <div class="metadata-tool">
            <label class="wide-option">
              <span>Folder</span>
              <div class="path-picker-row">
                <input bind:value={musicFolderPath} placeholder="C:/Music" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose music folder" disabled={musicFolderBusy} on:click={chooseMusicFolder}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={!musicFolderPath.trim()} on:click={() => openLocalPath(musicFolderPath, "Music folder")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!musicFolderPath.trim()} on:click={() => revealLocalPath(musicFolderPath, "Music folder")}>
                  Reveal
                </button>
              </div>
            </label>
            {#if musicError}
              <p class="error-text">{musicError}</p>
            {/if}
            {#if musicCatalog}
              <div class="library-summary">
                <strong>{musicCatalog.track_count} catalog track{musicCatalog.track_count === 1 ? "" : "s"} · {musicCatalog.artists.length} artist{musicCatalog.artists.length === 1 ? "" : "s"} · {musicCatalog.albums.length} album{musicCatalog.albums.length === 1 ? "" : "s"}</strong>
                <small>{musicCatalog.folders.length} imported folder{musicCatalog.folders.length === 1 ? "" : "s"} · updated {musicCatalog.updated_at}</small>
                {#if musicCatalog.folders.length > 0}
                  <small>{musicCatalog.folders.slice(0, 2).join(" · ")}{musicCatalog.folders.length > 2 ? ` · ${musicCatalog.folders.length - 2} more` : ""}</small>
                {/if}
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={!musicCatalog} on:click={copyMusicCatalogSummary}>
                    Copy catalog
                  </button>
                  <button class="small-button" type="button" disabled={!musicCatalog} on:click={copyMusicCatalogJson}>
                    Copy catalog JSON
                  </button>
                  <button class="small-button" type="button" disabled={musicCatalog.folders.length === 0} on:click={() => copyMusicCatalogFields("folder")}>
                    Copy folders
                  </button>
                  <button class="small-button" type="button" disabled={musicCatalog.artists.length === 0} on:click={() => copyMusicCatalogFields("artist")}>
                    Copy artists
                  </button>
                  <button class="small-button" type="button" disabled={musicCatalog.albums.length === 0} on:click={() => copyMusicCatalogFields("album")}>
                    Copy albums
                  </button>
                </div>
              </div>
            {/if}
            <label class="wide-option">
              <span>Catalog JSON export</span>
              <div class="path-picker-row">
                <input bind:value={musicCatalogExportPath} placeholder="C:/Backups/fetchdock-music-catalog.json" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose music catalog export path" disabled={musicBusy} on:click={chooseMusicCatalogBackupExportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={exportMusicCatalogBackup}>
                  {musicBusyMode === "catalog-export" ? "Exporting" : "Export JSON"}
                </button>
              </div>
            </label>
            <label class="wide-option">
              <span>Catalog JSON import</span>
              <div class="path-picker-row">
                <input bind:value={musicCatalogImportPath} placeholder="C:/Backups/fetchdock-music-catalog.json" spellcheck="false" />
                <button class="icon-button" type="button" title="Choose music catalog JSON" disabled={musicBusy} on:click={chooseMusicCatalogBackupImportFile}>
                  <FolderOpen size={17} />
                </button>
                <button class="secondary-button compact-button" type="button" disabled={musicBusy || !musicCatalogImportPath.trim()} on:click={importMusicCatalogBackup}>
                  {musicBusyMode === "catalog-import" ? "Importing" : "Import JSON"}
                </button>
              </div>
            </label>
            {#if musicCatalogExportResult}
              <div class="section-actions compact-actions wide-option">
                <small>{musicCatalogExportResult.exported_track_count} catalog track{musicCatalogExportResult.exported_track_count === 1 ? "" : "s"} · {musicCatalogExportResult.exported_folder_count} folder{musicCatalogExportResult.exported_folder_count === 1 ? "" : "s"} · {musicCatalogExportResult.output_path}</small>
                <button class="small-button" type="button" disabled={musicBusy} on:click={openMusicCatalogExportResult}>Open JSON</button>
                <button class="small-button" type="button" disabled={musicBusy} on:click={revealMusicCatalogExportResult}>Reveal JSON</button>
              </div>
            {/if}
            <div class="music-stats-panel">
              <div class="course-list-toolbar compact-toolbar">
                <span>
                  <strong>Service matrix</strong>
                  <small>External music services are tracked honestly here; only local files are currently implemented as a library source.</small>
                </span>
                <button class="small-button" type="button" disabled={musicBusy || musicBusyMode === "choose-service-matrix-export"} on:click={chooseMusicServiceMatrixExportPath}>
                  {musicBusyMode === "choose-service-matrix-export" ? "Choosing" : "Save as"}
                </button>
                <button class="small-button" type="button" disabled={musicBusy} on:click={exportCurrentMusicServiceMatrix}>
                  {musicBusyMode === "export-service-matrix" ? "Exporting" : "Export matrix"}
                </button>
                <button class="small-button" type="button" disabled={musicBusy || musicServiceMatrix.length === 0} on:click={copyMusicServiceMatrixSummary}>
                  Copy matrix
                </button>
                <button class="small-button" type="button" disabled={musicBusy || musicServiceMatrix.length === 0} on:click={copyMusicServiceMatrixJson}>
                  Copy JSON
                </button>
              </div>
              <div class="path-picker-row compact-path-row">
                <input bind:value={musicServiceMatrixExportPath} placeholder="C:/FetchDock/music-service-matrix.json" spellcheck="false" aria-label="Music service matrix export path" />
                <button class="small-button" type="button" disabled={!musicServiceMatrixExportPath.trim()} on:click={() => openLocalPath(musicServiceMatrixExportPath, "Music service matrix")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!musicServiceMatrixExportPath.trim()} on:click={() => revealLocalPath(musicServiceMatrixExportPath, "Music service matrix")}>
                  Reveal
                </button>
              </div>
              <div class="music-playlist-list">
                {#each musicServiceMatrix as service}
                  <article>
                    <div>
                      <strong>{service.name}</strong>
                      <small>{service.mode}</small>
                      <small>{service.note}</small>
                    </div>
                    <span class="task-chip">{service.status.replace("_", " ")}</span>
                  </article>
                {/each}
              </div>
            </div>
            <div class="summary-panel wide-option">
              <div class="summary-header">
                <div>
                  <strong>Local music summary</strong>
                  {#if musicLocalSummary}
                    <small>{musicLocalSummary.track_count} track{musicLocalSummary.track_count === 1 ? "" : "s"} · {musicLocalSummary.local_track_count} local · {musicLocalSummary.missing_track_count} missing · {formatDuration(musicLocalSummary.played_seconds)} played</small>
                  {:else}
                    <small>Catalog, queue, playlist, playback, settings, and service-status summary</small>
                  {/if}
                </div>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={musicBusy} on:click={refreshMusicLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary} on:click={copyMusicLocalSummary}>Copy summary</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary} on:click={copyMusicLocalSummaryJson}>Copy JSON</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary} on:click={() => copyMusicLocalSummaryFields("format")}>Copy formats</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary?.artist_counts.length} on:click={() => copyMusicLocalSummaryFields("artist")}>Copy artists</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary?.album_counts.length} on:click={() => copyMusicLocalSummaryFields("album")}>Copy albums</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary} on:click={() => copyMusicLocalSummaryFields("metadata")}>Copy metadata</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary?.queue_format_counts.length} on:click={() => copyMusicLocalSummaryFields("queue-format")}>Copy queue formats</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary?.playlist_track_counts.length} on:click={() => copyMusicLocalSummaryFields("playlist")}>Copy playlists</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary?.service_status_counts.length} on:click={() => copyMusicLocalSummaryFields("service-status")}>Copy service statuses</button>
                  <button class="small-button" type="button" disabled={!musicLocalSummary} on:click={() => copyMusicLocalSummaryFields("note")}>Copy notes</button>
                </div>
              </div>
              {#if musicLocalSummary}
                <div class="compact-stats-grid">
                  <span>Formats <strong>{musicLocalSummary.supported_format_count}</strong></span>
                  <span>Size <strong>{formatBytes(musicLocalSummary.total_size_bytes)}</strong></span>
                  <span>Covers <strong>{musicLocalSummary.cover_count}</strong></span>
                  <span>Artists <strong>{musicLocalSummary.artist_count}</strong></span>
                  <span>Albums <strong>{musicLocalSummary.album_count}</strong></span>
                  <span>Queue <strong>{musicLocalSummary.queue_track_count}</strong></span>
                  <span>Playlists <strong>{musicLocalSummary.playlist_count}</strong></span>
                  <span>Playlist tracks <strong>{musicLocalSummary.playlist_track_count}</strong></span>
                  <span>Playback <strong>{musicLocalSummary.playback_event_count}</strong></span>
                  <span>Services <strong>{musicLocalSummary.external_service_count}</strong></span>
                </div>
                <small>Queue: {musicLocalSummary.queue_active_track_present ? "active track" : "no active track"} · {musicLocalSummary.queue_volume_percent}% volume · sleep {musicLocalSummary.sleep_timer_enabled ? `${musicLocalSummary.sleep_timer_duration_minutes} min` : "off"} · EQ {musicLocalSummary.equalizer_enabled ? musicLocalSummary.equalizer_preset : "off"} · Discord {musicLocalSummary.discord_presence_enabled ? musicLocalSummary.discord_presence_status.replaceAll("_", " ") : "off"}</small>
              {/if}
              <div class="path-picker-row summary-export-row">
                <input bind:value={musicSummaryExportPath} placeholder="C:/path/music-summary.json" spellcheck="false" aria-label="Music summary export path" />
                <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={exportMusicSummary}>{musicBusyMode === "summary-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!musicSummaryExportPath.trim() && !musicSummaryExportResult} on:click={() => openLocalPath(musicSummaryExportResult || musicSummaryExportPath, "Music summary")}>Open export</button>
                <button class="small-button" type="button" disabled={!musicSummaryExportPath.trim() && !musicSummaryExportResult} on:click={() => revealLocalPath(musicSummaryExportResult || musicSummaryExportPath, "Music summary")}>Reveal export</button>
              </div>
            </div>
            <div class="summary-panel wide-option">
              <div class="summary-header">
                <div>
                  <strong>Music format catalog</strong>
                  {#if musicFormatCatalog}
                    <small>{musicFormatCatalog.format_count} format{musicFormatCatalog.format_count === 1 ? "" : "s"} · audio bodies {musicFormatCatalog.includes_audio_file_bodies ? "included" : "excluded"} · playback QA {musicFormatCatalog.verifies_playback_quality ? "verified" : "pending"}</small>
                  {:else}
                    <small>Local audio format capability boundaries.</small>
                  {/if}
                </div>
                <div class="section-actions compact-actions">
                  <button class="small-button" type="button" disabled={musicBusy} on:click={refreshMusicLocalSummary}>Refresh</button>
                  <button class="small-button" type="button" disabled={!musicFormatCatalog} on:click={copyMusicFormatCatalogSummary}>Copy summary</button>
                  <button class="small-button" type="button" disabled={!musicFormatCatalog} on:click={copyMusicFormatCatalogJson}>Copy JSON</button>
                  <button class="small-button" type="button" disabled={!musicFormatCatalog} on:click={() => copyMusicFormatCatalogFields("format")}>Copy formats</button>
                  <button class="small-button" type="button" disabled={!musicFormatCatalog} on:click={() => copyMusicFormatCatalogFields("limit")}>Copy limits</button>
                  <button class="small-button" type="button" disabled={!musicFormatCatalog} on:click={() => copyMusicFormatCatalogFields("note")}>Copy notes</button>
                </div>
              </div>
              {#if musicFormatCatalog}
                <div class="compact-stats-grid">
                  <span>Formats <strong>{musicFormatCatalog.format_count}</strong></span>
                  <span>Playback QA <strong>{musicFormatCatalog.verifies_playback_quality ? "yes" : "pending"}</strong></span>
                  <span>Service QA <strong>{musicFormatCatalog.verifies_external_service_connectors ? "yes" : "pending"}</strong></span>
                  <span>Manual matrix <strong>{musicFormatCatalog.verifies_manual_player_matrix ? "yes" : "pending"}</strong></span>
                </div>
                <div class="music-playlist-list compact-list">
                  {#each musicFormatCatalog.formats as item}
                    <article>
                      <div>
                        <strong>{item.format.toUpperCase()} · .{item.extensions.join(", .")}</strong>
                        <small>metadata {item.metadata_supported ? "yes" : "no"} · embedded tags {item.embedded_metadata_supported ? "yes" : "no"} · cover {item.cover_supported ? "yes" : "no"} · embedded cover {item.embedded_cover_supported ? "yes" : "no"}</small>
                        <small>queue {item.queue_supported ? "yes" : "no"} · lyrics {item.lyrics_supported ? "yes" : "no"} · playlist {item.playlist_supported ? "yes" : "no"} · stats {item.playback_stats_supported ? "yes" : "no"} · export {item.export_supported ? "yes" : "no"}</small>
                        <small>{item.limitations.join(" ")}</small>
                      </div>
                    </article>
                  {/each}
                </div>
                <small>{musicFormatCatalog.review_notes.join(" ")}</small>
              {/if}
              <div class="path-picker-row summary-export-row">
                <input bind:value={musicFormatCatalogExportPath} placeholder="C:/path/music-format-catalog.json" spellcheck="false" aria-label="Music format catalog export path" />
                <button class="secondary-button compact-button" type="button" disabled={musicBusy} on:click={exportMusicFormatCatalogFile}>{musicBusyMode === "format-catalog-export" ? "Exporting" : "Export"}</button>
                <button class="small-button" type="button" disabled={!musicFormatCatalogExportPath.trim() && !musicFormatCatalogExportResult} on:click={() => openLocalPath(musicFormatCatalogExportResult || musicFormatCatalogExportPath, "Music format catalog")}>Open export</button>
                <button class="small-button" type="button" disabled={!musicFormatCatalogExportPath.trim() && !musicFormatCatalogExportResult} on:click={() => revealLocalPath(musicFormatCatalogExportResult || musicFormatCatalogExportPath, "Music format catalog")}>Reveal export</button>
              </div>
              <small>Metadata-only catalog: no audio file bodies, external-service connectors, playback-quality matrix, or manual player verification.</small>
            </div>
            {#if musicScan || musicCatalog || musicQueue.length > 0}
              <div class="library-summary">
                {#if musicScan}
                  <strong>{musicScan.track_count} scanned track{musicScan.track_count === 1 ? "" : "s"} · {musicScan.artists.length} artist{musicScan.artists.length === 1 ? "" : "s"} · {musicScan.albums.length} album{musicScan.albums.length === 1 ? "" : "s"}</strong>
                {/if}
                {#if activeMusicTrack}
                  {@const currentMusicTrack = activeMusicTrack}
                  <div class="music-player" style={musicPlayerStyle}>
                    <div class="music-player-header">
                      {#if activeMusicCoverUrl}
                        <img src={activeMusicCoverUrl} alt="" />
                      {/if}
                      <div>
                        <strong>{currentMusicTrack.title}</strong>
                        <small>{currentMusicTrack.artist ?? "Unknown artist"} · {currentMusicTrack.album ?? "Unknown album"}</small>
                        <small>{currentMusicTrack.cover_path ? `Cover: ${currentMusicTrack.cover_path}` : "No sidecar cover found"}</small>
                        <small>{musicQueueState ? `Queue saved ${musicQueueState.updated_at}` : musicQueueBusy ? "Saving queue" : "Queue not saved yet"}</small>
                        <small>{musicMediaSessionStatus}</small>
                      </div>
                    </div>
                    <small>Playback runs in the docked mini player and follows the same queue, lyrics, Media Session, and stats state.</small>
                    <button class="secondary-button compact-button" type="button" on:click={playPreviousMusicTrack}>Previous</button>
                    <button class="secondary-button compact-button" type="button" on:click={playNextMusicTrack}>Next</button>
                    <button class="secondary-button compact-button" type="button" disabled={musicBusyMode === `open:${currentMusicTrack.path}`} on:click={() => openMusicTrackFile(currentMusicTrack)}>
                      Open
                    </button>
                    <button class="secondary-button compact-button" type="button" disabled={musicBusyMode === `reveal:${currentMusicTrack.path}`} on:click={() => revealMusicTrackFile(currentMusicTrack)}>
                      Reveal
                    </button>
                    <label class="inline-check">
                      <input type="checkbox" bind:checked={musicCoverThemeEnabled} />
                      <span>Cover theme</span>
                    </label>
                    <label class="compact-input">
                      <span>Volume</span>
                      <input bind:value={musicVolumeInput} inputmode="numeric" aria-label="Music volume percent" on:change={saveMusicVolume} />
                    </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicQueueBusy} on:click={persistMusicQueue}>
                    Save queue
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicQueueBusy} on:click={resetMusicQueueState}>
                    Reset queue
                  </button>
                  {#if musicLyricsBusy}
                    <small>Loading lyrics.</small>
                    {:else if musicLyrics?.lyrics_path}
                      <div class="music-lyrics-panel">
                        <strong>Lyrics · {musicLyrics.format?.toUpperCase() ?? "TEXT"} · {musicLyrics.line_count} lines</strong>
                        <small>{musicLyrics.lyrics_path}</small>
                        <div class="inline-actions">
                          <button class="small-button" type="button" on:click={copyMusicLyricsSummary}>
                            Copy summary
                          </button>
                          <button class="small-button" type="button" on:click={copyMusicLyricsText}>
                            Copy text
                          </button>
                          <button class="small-button" type="button" disabled={activeMusicLyricsLines.length === 0} on:click={copyMusicLyricsTimedLines}>
                            Copy timed
                          </button>
                          <button class="small-button" type="button" on:click={copyMusicLyricsJson}>
                            Copy JSON
                          </button>
                          <button class="small-button" type="button" on:click={() => openLocalPath(musicLyrics?.lyrics_path ?? "", "Lyrics file")}>
                            Open lyrics
                          </button>
                          <button class="small-button" type="button" on:click={() => revealLocalPath(musicLyrics?.lyrics_path ?? "", "Lyrics file")}>
                            Reveal lyrics
                          </button>
                        </div>
                        <small>
                          {activeMusicLyricIndex > -1
                            ? `Synced line ${activeMusicLyricIndex + 1} at ${formatTimestamp(activeMusicCurrentTimeSeconds)}`
                            : "No timed line active yet"}
                        </small>
                        <div class="music-lyrics-list" bind:this={musicLyricsListElement}>
                          {#each visibleMusicLyrics as line}
                            <button
                              type="button"
                              class:active={line.original_index === activeMusicLyricIndex}
                              disabled={line.time_seconds === null}
                              data-active={line.original_index === activeMusicLyricIndex ? "true" : undefined}
                              on:click={() => seekActiveMusicToLyric(line)}
                            >
                              {line.time_seconds !== null ? `${formatTimestamp(line.time_seconds)} · ` : ""}{line.text}
                            </button>
                          {/each}
                        </div>
                      </div>
                    {:else}
                      <small>No sidecar lyrics found next to this track.</small>
                    {/if}
                  {#if activeMusicTrack}
                    <div class="music-library-tools lyrics-editor">
                      <label class="wide-option">
                        <span>Lyrics editor</span>
                        <textarea bind:value={musicLyricsDraft} placeholder="[00:12.00]Line text" spellcheck="true" aria-label="Music lyrics text"></textarea>
                      </label>
                      <label>
                        <span>Format</span>
                        <select bind:value={musicLyricsFormat} aria-label="Lyrics format">
                          <option value="lrc">LRC</option>
                          <option value="txt">TXT</option>
                          <option value="srt">SRT</option>
                          <option value="vtt">VTT</option>
                        </select>
                      </label>
                      <label>
                        <span>Lyrics path</span>
                        <input bind:value={musicLyricsOutputPath} placeholder={defaultMusicLyricsFileName()} spellcheck="false" aria-label="Music lyrics output path" />
                      </label>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsSaveBusy === "choose"} on:click={chooseMusicLyricsOutputPath}>
                        {musicLyricsSaveBusy === "choose" ? "Choosing" : "Save as"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={Boolean(musicLyricsSaveBusy) || !musicLyricsDraft.trim()} on:click={() => persistActiveMusicLyrics(false)}>
                        {musicLyricsSaveBusy === "save" ? "Saving" : "Save lyrics"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsDraft.trim().length === 0} on:click={copyMusicLyricsSummary}>
                        Copy summary
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsDraft.trim().length === 0} on:click={copyMusicLyricsText}>
                        Copy text
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={activeMusicLyricsLines.length === 0} on:click={copyMusicLyricsTimedLines}>
                        Copy timed
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsDraft.trim().length === 0} on:click={copyMusicLyricsJson}>
                        Copy JSON
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={Boolean(musicLyricsSaveBusy) || !musicLyricsDraft.trim() || !musicLyricsOutputPath.trim()} on:click={() => persistActiveMusicLyrics(true)}>
                        {musicLyricsSaveBusy === "save-as" ? "Saving" : "Save to path"}
                      </button>
                      <label>
                        <span>Backup export</span>
                        <input bind:value={musicLyricsExportPath} placeholder="C:/Music/fetchdock-music-lyrics.json" spellcheck="false" aria-label="Music lyrics backup export path" />
                      </label>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsSaveBusy === "choose-export"} on:click={chooseMusicLyricsExportPath}>
                        {musicLyricsSaveBusy === "choose-export" ? "Choosing" : "Save backup as"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={Boolean(musicLyricsSaveBusy) || !musicLyrics?.lyrics_path} on:click={exportActiveMusicLyricsBackup}>
                        {musicLyricsSaveBusy === "export" ? "Exporting" : "Export backup"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={!musicLyricsExportResult && !musicLyricsExportPath.trim()} on:click={() => openLocalPath(musicLyricsExportResult?.output_path || musicLyricsExportPath, "Music lyrics backup")}>
                        Open backup
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={!musicLyricsExportResult && !musicLyricsExportPath.trim()} on:click={() => revealLocalPath(musicLyricsExportResult?.output_path || musicLyricsExportPath, "Music lyrics backup")}>
                        Reveal backup
                      </button>
                      <label>
                        <span>Backup import</span>
                        <input bind:value={musicLyricsImportPath} placeholder="C:/Music/fetchdock-music-lyrics.json" spellcheck="false" aria-label="Music lyrics backup import path" />
                      </label>
                      <button class="secondary-button compact-button" type="button" disabled={musicLyricsSaveBusy === "choose-import"} on:click={chooseMusicLyricsImportPath}>
                        {musicLyricsSaveBusy === "choose-import" ? "Choosing" : "Choose backup"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={Boolean(musicLyricsSaveBusy) || !musicLyricsImportPath.trim()} on:click={importActiveMusicLyricsBackup}>
                        {musicLyricsSaveBusy === "import" ? "Importing" : "Import backup"}
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={!musicLyricsImportPath.trim()} on:click={() => openLocalPath(musicLyricsImportPath, "Music lyrics backup")}>
                        Open import
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={!musicLyricsImportPath.trim()} on:click={() => revealLocalPath(musicLyricsImportPath, "Music lyrics backup")}>
                        Reveal import
                      </button>
                      <small class="wide-option">
                        Lyrics backup moves one local sidecar lyric file only. Audio files, catalog, queue, playlists, playback history, and external lyrics services stay outside this JSON.
                        {musicLyricsImportResult ? ` Last import wrote ${musicLyricsImportResult.imported_line_count} line${musicLyricsImportResult.imported_line_count === 1 ? "" : "s"} to ${musicLyricsImportResult.lyrics_path}.` : ""}
                      </small>
                    </div>
                  {/if}
                  </div>
                {/if}
                <div class="music-library-tools">
                  <label>
                    <span>{musicEditingPlaylistId ? "Editing playlist" : "Playlist name"}</span>
                    <input bind:value={musicPlaylistName} placeholder="Road queue" spellcheck="false" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "save"} on:click={saveCurrentMusicPlaylist}>
                    {musicPlaylistBusy === "save" ? "Saving" : musicEditingPlaylistId ? "Update playlist" : "Save queue"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "export-queue"} on:click={exportCurrentMusicQueuePlaylist}>
                    {musicPlaylistBusy === "export-queue" ? "Exporting" : "Export queue"}
                  </button>
                  <label>
                    <span>Export path</span>
                    <input bind:value={musicPlaylistExportPath} placeholder="C:/Music/fetchdock-playlist.m3u8" spellcheck="false" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "choose-export"} on:click={chooseMusicPlaylistExportPath}>
                    {musicPlaylistBusy === "choose-export" ? "Choosing" : "Save as"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={!musicPlaylistExportPath.trim()} on:click={() => openLocalPath(musicPlaylistExportPath, "Music playlist export")}>
                    Open export
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={!musicPlaylistExportPath.trim()} on:click={() => revealLocalPath(musicPlaylistExportPath, "Music playlist export")}>
                    Reveal export
                  </button>
                  <label>
                    <span>M3U path</span>
                    <input bind:value={musicPlaylistImportPath} placeholder="C:/Music/queue.m3u8" spellcheck="false" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "choose-import"} on:click={chooseMusicPlaylistFile}>
                    {musicPlaylistBusy === "choose-import" ? "Choosing" : "Choose M3U"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={!musicPlaylistImportPath.trim()} on:click={() => openLocalPath(musicPlaylistImportPath, "Music playlist import")}>
                    Open M3U
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={!musicPlaylistImportPath.trim()} on:click={() => revealLocalPath(musicPlaylistImportPath, "Music playlist import")}>
                    Reveal M3U
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "import" || !musicPlaylistImportPath.trim()} on:click={importStoredMusicPlaylist}>
                    {musicPlaylistBusy === "import" ? "Importing" : "Import M3U"}
                  </button>
                  <label>
                    <span>Backup JSON</span>
                    <input bind:value={musicPlaylistsExportPath} placeholder="C:/Music/fetchdock-music-playlists.json" spellcheck="false" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "choose-playlists-export"} on:click={chooseMusicPlaylistsBackupExportPath}>
                    {musicPlaylistBusy === "choose-playlists-export" ? "Choosing" : "Save JSON as"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "export-playlists" || visibleMusicPlaylists(filteredMusicPlaylists).length === 0} on:click={exportVisibleMusicPlaylistsBackup}>
                    {musicPlaylistBusy === "export-playlists" ? "Exporting" : "Export JSON"}
                  </button>
                  <button class="small-button" type="button" disabled={!musicPlaylistsExportPath.trim() && !musicPlaylistsExportResult} on:click={() => openLocalPath(musicPlaylistsExportResult?.output_path || musicPlaylistsExportPath, "Music playlists backup")}>
                    Open JSON
                  </button>
                  <button class="small-button" type="button" disabled={!musicPlaylistsExportPath.trim() && !musicPlaylistsExportResult} on:click={() => revealLocalPath(musicPlaylistsExportResult?.output_path || musicPlaylistsExportPath, "Music playlists backup")}>
                    Reveal JSON
                  </button>
                  <label>
                    <span>Import JSON</span>
                    <input bind:value={musicPlaylistsImportPath} placeholder="C:/Music/fetchdock-music-playlists.json" spellcheck="false" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "choose-playlists-import"} on:click={chooseMusicPlaylistsBackupImportFile}>
                    {musicPlaylistBusy === "choose-playlists-import" ? "Choosing" : "Choose JSON"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "import-playlists" || !musicPlaylistsImportPath.trim()} on:click={importMusicPlaylistsBackupFile}>
                    {musicPlaylistBusy === "import-playlists" ? "Importing" : "Import JSON"}
                  </button>
                  {#if musicEditingPlaylistId}
                    <button class="secondary-button compact-button" type="button" disabled={musicPlaylistBusy === "save"} on:click={cancelMusicPlaylistEdit}>Cancel edit</button>
                  {/if}
                  <button class="secondary-button compact-button danger" type="button" disabled={musicPlaylistBusy === "clear" || musicPlaylists.length === 0} on:click={requestMusicPlaylistsClear}>
                    Clear playlists
                  </button>
                  <label>
                    <span>Settings JSON</span>
                    <input bind:value={musicSettingsExportPath} placeholder="C:/Music/fetchdock-music-settings.json" spellcheck="false" aria-label="Music settings export path" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicSettingsBusy} on:click={chooseMusicSettingsExportPath}>
                    Save settings as
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicSettingsBusy} on:click={exportMusicSettingsBackup}>
                    {musicSettingsBusy ? "Working" : "Export settings"}
                  </button>
                  <button class="small-button" type="button" disabled={!musicSettingsExportPath.trim() && !musicSettingsExportResult} on:click={() => openLocalPath(musicSettingsExportResult?.output_path || musicSettingsExportPath, "Music settings backup")}>
                    Open settings
                  </button>
                  <button class="small-button" type="button" disabled={!musicSettingsExportPath.trim() && !musicSettingsExportResult} on:click={() => revealLocalPath(musicSettingsExportResult?.output_path || musicSettingsExportPath, "Music settings backup")}>
                    Reveal settings
                  </button>
                  <label>
                    <span>Import settings</span>
                    <input bind:value={musicSettingsImportPath} placeholder="C:/Music/fetchdock-music-settings.json" spellcheck="false" aria-label="Music settings import path" />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicSettingsBusy} on:click={chooseMusicSettingsImportFile}>
                    Choose settings
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicSettingsBusy || !musicSettingsImportPath.trim()} on:click={importMusicSettingsBackup}>
                    {musicSettingsBusy ? "Working" : "Import settings"}
                  </button>
                  <small class="wide-option">Settings JSON covers sleep timer, equalizer, and Discord Presence metadata only; queue, playlists, lyrics, playback history, catalog folders, and audio files are separate.</small>
                  <label>
                    <span>Sleep minutes</span>
                    <input bind:value={musicSleepMinutesInput} inputmode="numeric" spellcheck="false" />
                  </label>
                  <button
                    class="secondary-button compact-button"
                    type="button"
                    disabled={musicSleepTimerBusy}
                    on:click={() => setMusicSleepTimerEnabled(!(musicSleepTimer?.enabled ?? false))}
                  >
                    {musicSleepTimer?.enabled ? "Stop timer" : "Start timer"}
                  </button>
                  <button class="secondary-button compact-button" type="button" disabled={musicSleepTimerBusy} on:click={resetMusicSleepTimerState}>
                    Reset timer
                  </button>
                  {#if musicSleepTimer?.enabled}
                    <small class="wide-option">Pauses playback at {musicSleepTimer.ends_at}</small>
                  {/if}
                </div>
                <div class="music-library-tools">
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicEqualizer?.enabled ?? false}
                      disabled={musicEqualizerBusy}
                      on:change={(event) => saveMusicEqualizer({ enabled: event.currentTarget.checked })}
                    />
                    <span>Equalizer</span>
                  </label>
                  <label>
                    <span>Preset</span>
                    <select
                      value={musicEqualizer?.preset ?? "flat"}
                      disabled={musicEqualizerBusy}
                      aria-label="Equalizer preset"
                      on:change={(event) => saveMusicEqualizer({ preset: event.currentTarget.value as MusicEqualizerState["preset"] })}
                    >
                      <option value="flat">Flat</option>
                      <option value="warm">Warm</option>
                      <option value="bright">Bright</option>
                      <option value="voice">Voice</option>
                      <option value="bass">Bass</option>
                    </select>
                  </label>
                  <label>
                    <span>Bass</span>
                    <input
                      value={musicEqualizer?.bass_gain_db ?? 0}
                      inputmode="numeric"
                      disabled={musicEqualizerBusy}
                      aria-label="Bass gain dB"
                      on:change={(event) => saveMusicEqualizer({ bassGainDb: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <label>
                    <span>Mid</span>
                    <input
                      value={musicEqualizer?.mid_gain_db ?? 0}
                      inputmode="numeric"
                      disabled={musicEqualizerBusy}
                      aria-label="Mid gain dB"
                      on:change={(event) => saveMusicEqualizer({ midGainDb: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <label>
                    <span>Treble</span>
                    <input
                      value={musicEqualizer?.treble_gain_db ?? 0}
                      inputmode="numeric"
                      disabled={musicEqualizerBusy}
                      aria-label="Treble gain dB"
                      on:change={(event) => saveMusicEqualizer({ trebleGainDb: Number(event.currentTarget.value) })}
                    />
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicEqualizerBusy} on:click={resetMusicEqualizerState}>
                    Reset EQ
                  </button>
                  <small class="wide-option">{musicEqualizerStatus}</small>
                </div>
                <div class="music-library-tools">
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicDiscordPresence?.enabled ?? false}
                      disabled={musicDiscordPresenceBusy}
                      on:change={(event) => saveMusicDiscordPresence({ enabled: event.currentTarget.checked })}
                    />
                    <span>Discord Rich Presence</span>
                  </label>
                  <label>
                    <span>Privacy</span>
                    <select
                      value={musicDiscordPresence?.privacy_mode ?? "reduced"}
                      disabled={musicDiscordPresenceBusy}
                      aria-label="Discord Rich Presence privacy"
                      on:change={(event) => saveMusicDiscordPresence({ privacyMode: event.currentTarget.value as MusicDiscordPresenceState["privacy_mode"] })}
                    >
                      <option value="reduced">Reduced</option>
                      <option value="detailed">Detailed</option>
                      <option value="private">Private</option>
                    </select>
                  </label>
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicDiscordPresence?.include_title ?? true}
                      disabled={musicDiscordPresenceBusy}
                      on:change={(event) => saveMusicDiscordPresence({ includeTitle: event.currentTarget.checked })}
                    />
                    <span>Title</span>
                  </label>
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicDiscordPresence?.include_artist ?? true}
                      disabled={musicDiscordPresenceBusy}
                      on:change={(event) => saveMusicDiscordPresence({ includeArtist: event.currentTarget.checked })}
                    />
                    <span>Artist</span>
                  </label>
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicDiscordPresence?.include_album ?? false}
                      disabled={musicDiscordPresenceBusy}
                      on:change={(event) => saveMusicDiscordPresence({ includeAlbum: event.currentTarget.checked })}
                    />
                    <span>Album</span>
                  </label>
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={musicDiscordPresence?.include_elapsed ?? true}
                      disabled={musicDiscordPresenceBusy}
                      on:change={(event) => saveMusicDiscordPresence({ includeElapsed: event.currentTarget.checked })}
                    />
                    <span>Elapsed</span>
                  </label>
                  <button class="secondary-button compact-button" type="button" disabled={musicDiscordPresenceBusy} on:click={resetMusicDiscordPresenceState}>
                    Reset presence
                  </button>
                  <small class="wide-option">
                    {musicDiscordPresencePreview()} · {musicDiscordPresence?.integration_status.replaceAll("_", " ") ?? "disabled"}; Discord IPC is still pending.
                  </small>
                </div>
                {#if musicPlaylists.length > 0}
                  <div class="library-filter-row">
                    <input
                      bind:value={musicPlaylistSearch}
                      placeholder="Search playlists or tracks"
                      spellcheck="false"
                      aria-label="Music playlist search"
                    />
                    <span class="filter-count-label">{visibleMusicPlaylists(filteredMusicPlaylists).length} shown of {musicPlaylists.length} playlist{musicPlaylists.length === 1 ? "" : "s"}</span>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={copyVisibleMusicPlaylistSummary}>
                      Copy summary
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={copyVisibleMusicPlaylistJson}>
                      Copy JSON
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={() => copyVisibleMusicPlaylistFields("id")}>
                      Copy ids
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={() => copyVisibleMusicPlaylistFields("name")}>
                      Copy names
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={() => copyVisibleMusicPlaylistFields("count")}>
                      Copy counts
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicPlaylists.length === 0} on:click={() => copyVisibleMusicPlaylistFields("updated")}>
                      Copy updated
                    </button>
                    <button
                      class="secondary-button compact-button danger"
                      type="button"
                      disabled={musicPlaylistBusy === "remove-filtered" || filteredMusicPlaylists.length === 0}
                      on:click={requestVisibleMusicPlaylistsRemove}
                    >
                      {musicPlaylistBusy === "remove-filtered" ? "Removing" : "Remove shown"}
                    </button>
                  </div>
                  <div class="music-playlist-list">
                    {#if filteredMusicPlaylists.length === 0}
                      <small class="format-hint">No playlists match the current search.</small>
                    {:else}
                      {#if filteredMusicPlaylists.length > 8 && !musicPlaylistSearch.trim()}
                        <div class="course-list-toolbar compact-toolbar">
                          <small>{filteredMusicPlaylists.length} matching playlist{filteredMusicPlaylists.length === 1 ? "" : "s"}</small>
                          <button class="small-button" type="button" on:click={() => (musicPlaylistsExpanded = !musicPlaylistsExpanded)}>
                            {musicPlaylistsExpanded ? "Collapse playlists" : "Show all playlists"}
                          </button>
                        </div>
                      {/if}
                      {#each visibleMusicPlaylists(filteredMusicPlaylists) as playlist}
                        <article>
                          <div>
                            <strong>{playlist.name}</strong>
                            <small>{playlist.tracks.length} track{playlist.tracks.length === 1 ? "" : "s"} · {playlist.updated_at}</small>
                          </div>
                          <div class="section-actions">
                            <button class="small-button" type="button" on:click={() => loadMusicPlaylist(playlist)}>Load</button>
                            <button class="small-button" type="button" on:click={() => editMusicPlaylist(playlist)}>Edit</button>
                            <button class="small-button" type="button" disabled={musicPlaylistBusy === `export:${playlist.id}`} on:click={() => exportStoredMusicPlaylist(playlist)}>Export</button>
                            <button class="small-button danger" type="button" disabled={musicPlaylistBusy === playlist.id} on:click={() => removeMusicPlaylist(playlist)}>Delete</button>
                          </div>
                        </article>
                      {/each}
                    {/if}
                  </div>
                {/if}
                {#if musicPlaybackStats}
                  <div class="music-stats-panel">
                    <div class="course-list-toolbar compact-toolbar">
                      <div>
                        <strong>{musicPlaybackStats.play_count} play{musicPlaybackStats.play_count === 1 ? "" : "s"}</strong>
                        <small>{Math.round(musicPlaybackStats.played_seconds / 60)} minute{Math.round(musicPlaybackStats.played_seconds / 60) === 1 ? "" : "s"} recorded locally</small>
                      </div>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.play_count === 0} on:click={copyVisibleMusicPlaybackSummary}>
                        Copy summary
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.play_count === 0} on:click={copyVisibleMusicPlaybackJson}>
                        Copy JSON
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.top_tracks.length === 0} on:click={() => copyMusicCatalogFields("top")}>
                        Copy top
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.top_tracks.length === 0} on:click={() => copyVisibleMusicPlaybackFields("top-path")}>
                        Copy top paths
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.top_tracks.length === 0} on:click={() => copyVisibleMusicPlaybackFields("top-last")}>
                        Copy last played
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.recent.length === 0} on:click={() => copyMusicCatalogFields("recent")}>
                        Copy recent
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.recent.length === 0} on:click={() => copyVisibleMusicPlaybackFields("recent-path")}>
                        Copy recent paths
                      </button>
                      <button class="small-button" type="button" disabled={musicPlaybackStats.recent.length === 0} on:click={() => copyVisibleMusicPlaybackFields("recent-duration")}>
                        Copy durations
                      </button>
                      <button class="small-button danger" type="button" disabled={musicPlaybackBusy || musicPlaybackStats.play_count === 0} on:click={requestMusicPlaybackHistoryClear}>
                        Clear history
                      </button>
                    </div>
                    <div class="music-library-tools">
                      <input bind:value={musicPlaybackExportPath} placeholder="C:/Backups/fetchdock-music-playback-history.json" spellcheck="false" aria-label="Music playback history export path" />
                      <button class="small-button" type="button" disabled={musicPlaybackBusy} on:click={chooseMusicPlaybackHistoryExportPath}>
                        Save as
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={musicPlaybackBusy} on:click={exportMusicPlaybackBackup}>
                        {musicPlaybackBusy ? "Working" : "Export playback"}
                      </button>
                      <button class="small-button" type="button" disabled={!musicPlaybackExportPath.trim() && !musicPlaybackExportResult} on:click={() => openLocalPath(musicPlaybackExportResult?.output_path || musicPlaybackExportPath, "Music playback history export")}>
                        Open export
                      </button>
                      <button class="small-button" type="button" disabled={!musicPlaybackExportPath.trim() && !musicPlaybackExportResult} on:click={() => revealLocalPath(musicPlaybackExportResult?.output_path || musicPlaybackExportPath, "Music playback history export")}>
                        Reveal export
                      </button>
                    </div>
                    <div class="music-library-tools">
                      <input bind:value={musicPlaybackImportPath} placeholder="C:/Backups/fetchdock-music-playback-history.json" spellcheck="false" aria-label="Music playback history import path" />
                      <button class="small-button" type="button" disabled={musicPlaybackBusy} on:click={chooseMusicPlaybackHistoryImportFile}>
                        Choose file
                      </button>
                      <button class="secondary-button compact-button" type="button" disabled={musicPlaybackBusy || !musicPlaybackImportPath.trim()} on:click={importMusicPlaybackBackup}>
                        {musicPlaybackBusy ? "Working" : "Import playback"}
                      </button>
                      <button class="small-button" type="button" disabled={!musicPlaybackImportPath.trim()} on:click={() => openLocalPath(musicPlaybackImportPath, "Music playback history backup")}>
                        Open file
                      </button>
                      <button class="small-button" type="button" disabled={!musicPlaybackImportPath.trim()} on:click={() => revealLocalPath(musicPlaybackImportPath, "Music playback history backup")}>
                        Reveal
                      </button>
                      <small>Moves local playback event metadata only; audio files, catalog, queue, playlists, lyrics, and settings stay outside this backup.</small>
                    </div>
                    {#if musicPlaybackStats.top_tracks.length > 0}
                      <div class="music-playlist-list">
                        {#each visibleMusicTopTracks(musicPlaybackStats) as item}
                          <article>
                            <div>
                              <strong>{item.track.title}</strong>
                              <small>{item.play_count} play{item.play_count === 1 ? "" : "s"} · {Math.round(item.played_seconds / 60)} min · {item.track.artist ?? "Unknown artist"}</small>
                            </div>
                            <button class="small-button" type="button" on:click={() => playMusicTrack(item.track)}>Play</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `open:${item.track.path}`} on:click={() => openMusicTrackFile(item.track)}>Open</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `reveal:${item.track.path}`} on:click={() => revealMusicTrackFile(item.track)}>Reveal</button>
                          </article>
                        {/each}
                        {#if musicPlaybackStats.top_tracks.length > 5}
                          <div class="course-list-toolbar compact-toolbar">
                            <small>{visibleMusicTopTracks(musicPlaybackStats).length} shown of {musicPlaybackStats.top_tracks.length} top track{musicPlaybackStats.top_tracks.length === 1 ? "" : "s"}</small>
                            <button class="small-button" type="button" on:click={() => (musicTopTracksExpanded = !musicTopTracksExpanded)}>
                              {musicTopTracksExpanded ? "Collapse top tracks" : "Show all top tracks"}
                            </button>
                          </div>
                        {/if}
                      </div>
                    {/if}
                    {#if musicPlaybackStats.recent.length > 0}
                      <div class="music-playlist-list">
                        {#each visibleMusicRecentPlays(musicPlaybackStats) as event}
                          <article>
                            <div>
                              <strong>{event.track.title}</strong>
                              <small>{event.played_at} · {event.played_seconds}s · {event.track.artist ?? "Unknown artist"}</small>
                            </div>
                            <button class="small-button" type="button" on:click={() => playMusicTrack(event.track)}>Play</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `open:${event.track.path}`} on:click={() => openMusicTrackFile(event.track)}>Open</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `reveal:${event.track.path}`} on:click={() => revealMusicTrackFile(event.track)}>Reveal</button>
                          </article>
                        {/each}
                        {#if musicPlaybackStats.recent.length > 5}
                          <div class="course-list-toolbar compact-toolbar">
                            <small>{visibleMusicRecentPlays(musicPlaybackStats).length} shown of {musicPlaybackStats.recent.length} recent play{musicPlaybackStats.recent.length === 1 ? "" : "s"}</small>
                            <button class="small-button" type="button" on:click={() => (musicRecentPlaysExpanded = !musicRecentPlaysExpanded)}>
                              {musicRecentPlaysExpanded ? "Collapse recent" : "Show all recent"}
                            </button>
                          </div>
                        {/if}
                      </div>
                    {/if}
                  </div>
                {/if}
                <div class="music-stats-panel">
                  <div class="course-list-toolbar compact-toolbar">
                    <div>
                      <strong>Queue JSON backup</strong>
                      <small>{musicQueue.length} queued track{musicQueue.length === 1 ? "" : "s"} · local queue metadata</small>
                    </div>
                  </div>
                  <div class="music-library-tools">
                    <input bind:value={musicQueueExportPath} placeholder="C:/Backups/fetchdock-music-queue.json" spellcheck="false" aria-label="Music queue export path" />
                    <button class="small-button" type="button" disabled={musicQueueBusy} on:click={chooseMusicQueueExportPath}>
                      Save as
                    </button>
                    <button class="secondary-button compact-button" type="button" disabled={musicQueueBusy} on:click={exportMusicQueueBackup}>
                      {musicQueueBusy ? "Working" : "Export queue"}
                    </button>
                    <button class="small-button" type="button" disabled={!musicQueueExportPath.trim() && !musicQueueExportResult} on:click={() => openLocalPath(musicQueueExportResult?.output_path || musicQueueExportPath, "Music queue export")}>
                      Open export
                    </button>
                    <button class="small-button" type="button" disabled={!musicQueueExportPath.trim() && !musicQueueExportResult} on:click={() => revealLocalPath(musicQueueExportResult?.output_path || musicQueueExportPath, "Music queue export")}>
                      Reveal export
                    </button>
                  </div>
                  <div class="music-library-tools">
                    <input bind:value={musicQueueImportPath} placeholder="C:/Backups/fetchdock-music-queue.json" spellcheck="false" aria-label="Music queue import path" />
                    <button class="small-button" type="button" disabled={musicQueueBusy} on:click={chooseMusicQueueImportFile}>
                      Choose file
                    </button>
                    <button class="secondary-button compact-button" type="button" disabled={musicQueueBusy || !musicQueueImportPath.trim()} on:click={importMusicQueueBackup}>
                      {musicQueueBusy ? "Working" : "Import queue"}
                    </button>
                    <button class="small-button" type="button" disabled={!musicQueueImportPath.trim()} on:click={() => openLocalPath(musicQueueImportPath, "Music queue backup")}>
                      Open file
                    </button>
                    <button class="small-button" type="button" disabled={!musicQueueImportPath.trim()} on:click={() => revealLocalPath(musicQueueImportPath, "Music queue backup")}>
                      Reveal
                    </button>
                    <small>Moves queue track metadata, active track, and volume only; audio files, catalog folders, playlists, lyrics, playback history, and settings stay outside this backup.</small>
                  </div>
                </div>
                {#if musicQueue.length > 0}
                  <div class="music-playlist-list">
                    {#if musicQueue.length > 8}
                      <div class="course-list-toolbar compact-toolbar">
                        <small>Showing {visibleMusicQueueTracks(musicQueue).length} of {musicQueue.length} queued track{musicQueue.length === 1 ? "" : "s"}</small>
                        <button class="small-button" type="button" on:click={shuffleMusicQueueTracks}>
                          Shuffle
                        </button>
                        <button class="small-button" type="button" on:click={dedupeMusicQueueTracks}>
                          Dedupe
                        </button>
                        <button class="small-button" type="button" on:click={copyVisibleMusicQueueSummary}>
                          Copy summary
                        </button>
                        <button class="small-button" type="button" on:click={copyVisibleMusicQueueJson}>
                          Copy JSON
                        </button>
                        <button class="small-button" type="button" on:click={() => copyVisibleMusicQueueFields("index")}>
                          Copy order
                        </button>
                        <button class="small-button" type="button" on:click={() => copyVisibleMusicQueueFields("path")}>
                          Copy paths
                        </button>
                        <button class="small-button danger" type="button" on:click={clearMusicQueueTracks}>
                          Clear
                        </button>
                        <button class="small-button" type="button" on:click={() => (musicQueueExpanded = !musicQueueExpanded)}>
                          {musicQueueExpanded ? "Collapse queue" : "Show full queue"}
                        </button>
                      </div>
                    {:else}
                      <div class="course-list-toolbar compact-toolbar">
                        <small>{musicQueue.length} queued track{musicQueue.length === 1 ? "" : "s"}</small>
                        <button class="small-button" type="button" on:click={shuffleMusicQueueTracks}>
                          Shuffle
                        </button>
                        <button class="small-button" type="button" on:click={dedupeMusicQueueTracks}>
                          Dedupe
                        </button>
                        <button class="small-button" type="button" on:click={copyVisibleMusicQueueSummary}>
                          Copy summary
                        </button>
                        <button class="small-button" type="button" on:click={copyVisibleMusicQueueJson}>
                          Copy JSON
                        </button>
                        <button class="small-button" type="button" on:click={() => copyVisibleMusicQueueFields("index")}>
                          Copy order
                        </button>
                        <button class="small-button" type="button" on:click={() => copyVisibleMusicQueueFields("path")}>
                          Copy paths
                        </button>
                        <button class="small-button danger" type="button" on:click={clearMusicQueueTracks}>
                          Clear
                        </button>
                      </div>
                    {/if}
                    {#each visibleMusicQueueTracks(musicQueue) as track}
                      {@const queueIndex = musicQueue.findIndex((item) => item.path === track.path)}
                      <article class:active={activeMusicTrack?.path === track.path}>
                        <div>
                          <strong>{queueIndex + 1}. {track.title}</strong>
                          <small>{track.artist ?? "Unknown artist"} · {track.album ?? "Unknown album"}{track.cover_path ? " · cover" : ""}{musicMetadataLabel(track) ? ` · ${musicMetadataLabel(track)}` : ""}</small>
                        </div>
                        <div class="section-actions">
                          <button class="small-button" type="button" on:click={() => playMusicTrack(track)}>Play</button>
                          <button class="small-button" type="button" disabled={musicBusyMode === `open:${track.path}`} on:click={() => openMusicTrackFile(track)}>Open</button>
                          <button class="small-button" type="button" disabled={musicBusyMode === `reveal:${track.path}`} on:click={() => revealMusicTrackFile(track)}>Reveal</button>
                          <button class="small-button" type="button" disabled={queueIndex === 0} on:click={() => moveMusicQueueTrack(track, -1)}>Up</button>
                          <button class="small-button" type="button" disabled={queueIndex === musicQueue.length - 1} on:click={() => moveMusicQueueTrack(track, 1)}>Down</button>
                          <button class="small-button danger" type="button" on:click={() => removeMusicQueueTrack(track)}>Remove</button>
                        </div>
                      </article>
                    {/each}
                  </div>
                {/if}
                {#if musicLibraryTracks.length > 0}
                  <div class="library-filter-row">
                    <label>
                      <span>Search</span>
                      <input bind:value={musicSearchQuery} placeholder="Title, artist, album, format, or path" spellcheck="false" />
                    </label>
                    <label>
                      <span>Format</span>
                      <select bind:value={musicFormatFilter} aria-label="Music format filter">
                        {#each musicFormatOptions as option}
                          <option value={option}>{option === "all" ? "All formats" : option.toUpperCase()}</option>
                        {/each}
                      </select>
                    </label>
                  </div>
                  <div class="section-actions compact-actions">
                    <button class="secondary-button compact-button" type="button" disabled={filteredMusicTracks.length === 0 || musicQueueBusy} on:click={loadFilteredMusicTracks}>
                      Load shown tracks
                    </button>
                    <button class="secondary-button compact-button" type="button" disabled={filteredMusicTracks.length === 0 || musicQueueBusy} on:click={appendFilteredMusicTracksToQueue}>
                      Append shown
                    </button>
                    <button class="secondary-button compact-button" type="button" disabled={filteredMusicTracks.length === 0 || musicPlaylistBusy === "save-filtered"} on:click={saveFilteredMusicPlaylist}>
                      {musicPlaylistBusy === "save-filtered" ? "Saving" : "Save shown playlist"}
                    </button>
                    <button
                      class="secondary-button compact-button danger"
                      type="button"
                      disabled={musicBusy || musicCatalogBulkBusy === "remove-filtered" || filteredCatalogMusicTrackCount === 0}
                      on:click={requestFilteredMusicCatalogTracksRemove}
                    >
                      {musicCatalogBulkBusy === "remove-filtered" ? "Removing" : "Remove shown"}
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={copyFilteredMusicTrackSummary}>
                      Copy summary
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={copyFilteredMusicTrackJson}>
                      Copy JSON
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={() => copyFilteredMusicTrackFields("path")}>
                      Copy paths
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={() => copyFilteredMusicTrackFields("title")}>
                      Copy titles
                    </button>
                    <button class="small-button" type="button" disabled={!filteredMusicTracks.some((track) => track.artist)} on:click={() => copyFilteredMusicTrackFields("artist")}>
                      Copy artists
                    </button>
                    <button class="small-button" type="button" disabled={!filteredMusicTracks.some((track) => track.album)} on:click={() => copyFilteredMusicTrackFields("album")}>
                      Copy albums
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={() => copyFilteredMusicTrackFields("format")}>
                      Copy formats
                    </button>
                    <button class="small-button" type="button" disabled={filteredMusicTracks.length === 0} on:click={() => copyFilteredMusicTrackFields("size")}>
                      Copy sizes
                    </button>
                    <button class="small-button" type="button" disabled={!filteredMusicTracks.some((track) => track.cover_path)} on:click={() => copyFilteredMusicTrackFields("cover")}>
                      Copy covers
                    </button>
                    <button class="small-button" type="button" disabled={!filteredMusicTracks.some((track) => musicMetadataLabel(track))} on:click={() => copyFilteredMusicTrackFields("metadata")}>
                      Copy metadata
                    </button>
                    <button class="small-button" type="button" disabled={!filteredMusicTracks.some((track) => track.modified_at)} on:click={() => copyFilteredMusicTrackFields("modified")}>
                      Copy modified
                    </button>
                    <small>{filteredMusicTracks.length} shown track{filteredMusicTracks.length === 1 ? "" : "s"}</small>
                    {#if musicCatalog}
                      <small>{filteredCatalogMusicTrackCount} shown catalog track{filteredCatalogMusicTrackCount === 1 ? "" : "s"} removable.</small>
                    {/if}
                  </div>
                  <div class="filter-tabs" aria-label="Music library views">
                    <button type="button" class:active={musicLibraryView === "tracks"} on:click={() => (musicLibraryView = "tracks")}>Tracks</button>
                    <button type="button" class:active={musicLibraryView === "artists"} on:click={() => (musicLibraryView = "artists")}>Artists</button>
                    <button type="button" class:active={musicLibraryView === "albums"} on:click={() => (musicLibraryView = "albums")}>Albums</button>
                  </div>
                  {#if musicLibraryView === "tracks"}
                    <div class="library-item-list">
                      {#if filteredMusicTracks.length > 20 && !musicSearchQuery.trim() && musicFormatFilter === "all"}
                        <div class="course-list-toolbar compact-toolbar">
                          <small>{filteredMusicTracks.length} matching track{filteredMusicTracks.length === 1 ? "" : "s"}</small>
                          <button class="small-button" type="button" on:click={() => (musicTracksExpanded = !musicTracksExpanded)}>
                            {musicTracksExpanded ? "Collapse tracks" : "Show all tracks"}
                          </button>
                        </div>
                      {/if}
                      {#each visibleMusicTracks(filteredMusicTracks) as track}
                        <article class:active={activeMusicTrack?.path === track.path}>
                          <div>
                            <span>{track.title}</span>
                            <small>{track.format.toUpperCase()} · {track.artist ?? "Unknown artist"} · {track.album ?? "Unknown album"}{track.cover_path ? " · cover" : ""}{musicMetadataLabel(track) ? ` · ${musicMetadataLabel(track)}` : ""} · {formatBytes(track.size_bytes)}</small>
                          </div>
                          <div class="section-actions">
                            <button class="small-button" type="button" on:click={() => playMusicTrack(track)}>Play</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `open:${track.path}`} on:click={() => openMusicTrackFile(track)}>Open</button>
                            <button class="small-button" type="button" disabled={musicBusyMode === `reveal:${track.path}`} on:click={() => revealMusicTrackFile(track)}>Reveal</button>
                            <button
                              class="small-button danger"
                              type="button"
                              disabled={musicBusy || !musicCatalog?.tracks.some((catalogTrack) => catalogTrack.path === track.path)}
                              on:click={() => removeMusicCatalogTrack(track)}
                            >
                              Remove
                            </button>
                          </div>
                        </article>
                      {/each}
                    </div>
                  {:else if musicLibraryView === "artists"}
                    <div class="music-group-list">
                      {#if musicArtistGroups.length > 12 && !musicSearchQuery.trim() && musicFormatFilter === "all"}
                        <div class="course-list-toolbar compact-toolbar">
                          <small>{musicArtistGroups.length} matching artist group{musicArtistGroups.length === 1 ? "" : "s"}</small>
                          <button class="small-button" type="button" on:click={() => (musicArtistsExpanded = !musicArtistsExpanded)}>
                            {musicArtistsExpanded ? "Collapse artists" : "Show all artists"}
                          </button>
                        </div>
                      {/if}
                      {#each visibleMusicGroups(musicArtistGroups, "artist") as group}
                        {@const groupCoverUrls = musicGroupCoverUrls(group)}
                        <article>
                          <div class="music-group-summary">
                            <div class="music-group-covers" aria-hidden="true">
                              {#each groupCoverUrls as coverUrl}
                                <img src={coverUrl} alt="" />
                              {/each}
                              {#if groupCoverUrls.length === 0}
                                <span>{group.name.slice(0, 1).toUpperCase()}</span>
                              {/if}
                            </div>
                            <span>
                              <strong>{group.name}</strong>
                              <small>{group.tracks.length} track{group.tracks.length === 1 ? "" : "s"} · {group.tracks[0]?.album ?? "Mixed albums"}</small>
                            </span>
                          </div>
                          <div class="section-actions">
                            <button class="small-button" type="button" on:click={() => loadMusicGroup(group)}>Load</button>
                            <button class="small-button" type="button" on:click={() => appendMusicGroup(group)}>Append</button>
                            <button class="small-button" type="button" on:click={() => playMusicTrack(group.tracks[0])}>Play first</button>
                          </div>
                        </article>
                      {/each}
                    </div>
                  {:else}
                    <div class="music-group-list">
                      {#if musicAlbumGroups.length > 12 && !musicSearchQuery.trim() && musicFormatFilter === "all"}
                        <div class="course-list-toolbar compact-toolbar">
                          <small>{musicAlbumGroups.length} matching album group{musicAlbumGroups.length === 1 ? "" : "s"}</small>
                          <button class="small-button" type="button" on:click={() => (musicAlbumsExpanded = !musicAlbumsExpanded)}>
                            {musicAlbumsExpanded ? "Collapse albums" : "Show all albums"}
                          </button>
                        </div>
                      {/if}
                      {#each visibleMusicGroups(musicAlbumGroups, "album") as group}
                        {@const groupCoverUrls = musicGroupCoverUrls(group)}
                        <article>
                          <div class="music-group-summary">
                            <div class="music-group-covers" aria-hidden="true">
                              {#each groupCoverUrls as coverUrl}
                                <img src={coverUrl} alt="" />
                              {/each}
                              {#if groupCoverUrls.length === 0}
                                <span>{group.name.slice(0, 1).toUpperCase()}</span>
                              {/if}
                            </div>
                            <span>
                              <strong>{group.name}</strong>
                              <small>{group.tracks.length} track{group.tracks.length === 1 ? "" : "s"} · {group.tracks[0]?.artist ?? "Unknown artist"}</small>
                            </span>
                          </div>
                          <div class="section-actions">
                            <button class="small-button" type="button" on:click={() => loadMusicGroup(group)}>Load</button>
                            <button class="small-button" type="button" on:click={() => appendMusicGroup(group)}>Append</button>
                            <button class="small-button" type="button" on:click={() => playMusicTrack(group.tracks[0])}>Play first</button>
                          </div>
                        </article>
                      {/each}
                    </div>
                  {/if}
                  {#if filteredMusicTracks.length === 0}
                    <small class="format-hint">No music tracks match the current filters.</small>
                  {/if}
                {/if}
              </div>
            {/if}
          </div>
        </div>
      </section>
    {:else if currentRoute === "settings"}
      <section class="settings-grid">
        <div class="panel settings-search-panel">
          <div class="section-heading compact-heading">
            <div>
              <h2>{translate(appLanguage, "settings.searchTitle")}</h2>
              <p>{translate(appLanguage, "settings.searchDescription")}</p>
            </div>
          </div>
          <div class="settings-search-control">
            <input
              bind:value={settingsQuery}
              placeholder={translate(appLanguage, "settings.searchPlaceholder")}
              spellcheck="false"
              aria-label="Search settings"
              on:keydown={handleSettingsSearchKeydown}
            />
            <button class="secondary-button" type="button" disabled={settingsSearchBusy} on:click={runSettingsSearch}>
              {translate(appLanguage, "settings.searchButton")}
            </button>
          </div>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" on:click={copySettingsSearchSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" on:click={copySettingsSearchJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={settingsSearchResults.length === 0} on:click={() => copySettingsSearchFields("section")}>
              Copy sections
            </button>
            <button class="small-button" type="button" disabled={settingsSearchResults.length === 0} on:click={() => copySettingsSearchFields("title")}>
              Copy titles
            </button>
            <button class="small-button" type="button" disabled={settingsSearchResults.length === 0} on:click={() => copySettingsSearchFields("keyword")}>
              Copy keywords
            </button>
          </div>
          {#if settingsSearchError}
            <p class="error-text">{settingsSearchError}</p>
          {:else if settingsSummary}
            <p class="muted">{settingsSummary}</p>
          {/if}
          {#if settingsSearchResults.length > 0}
            <div class="settings-search-results">
              {#each settingsSearchResults as result}
                <button
                  type="button"
                  class:active={activeSettingsSectionId === result.section_id}
                  aria-pressed={activeSettingsSectionId === result.section_id}
                  on:click={() => focusSettingsSection(result.section_id)}
                >
                  <strong>{result.title}</strong>
                  <small>{result.description}</small>
                </button>
              {/each}
            </div>
          {/if}
          {#if activeSettingsSectionId}
            <p class="muted">Highlight is pinned to {activeSettingsSectionId}; run a new search to clear it.</p>
          {/if}
        </div>
        <div
          id="settings-paths"
          class:settings-highlight={activeSettingsSectionId === "paths"}
          class="panel"
        >
          <h2>Application paths</h2>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" disabled={!status} on:click={copyAppPathSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={copyAppPathJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={() => copyAppPathFields("path")}>
              Copy paths
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={() => copyAppPathFields("label")}>
              Copy labels
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={exportInfrastructureSummary}>
              Export summary
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={chooseInfrastructureSummaryExportPath}>
              Save as
            </button>
            <button class="small-button" type="button" disabled={!infrastructureSummaryExportPath.trim()} on:click={() => openLocalPath(infrastructureSummaryExportPath, "Infrastructure summary")}>
              Open export
            </button>
            <button class="small-button" type="button" disabled={!infrastructureSummaryExportPath.trim()} on:click={() => revealLocalPath(infrastructureSummaryExportPath, "Infrastructure summary")}>
              Reveal export
            </button>
          </div>
          {#if infrastructureSummaryExportPath || appInfrastructureSummary}
            <p class="muted">{infrastructureSummaryExportPath || `${appInfrastructureSummary?.path_count ?? 0} paths · quick capture ${appInfrastructureSummary?.quick_capture_enabled ? "enabled" : "disabled"} · shortcut ${formatShortcutRegistrationState(appInfrastructureSummary?.quick_capture_registered)} · autostart ${appInfrastructureSummary?.autostart_available ? appInfrastructureSummary.autostart_enabled ? "enabled" : "disabled" : "unavailable"}`}</p>
          {/if}
          {#if statusError}
            <p class="error-text">{statusError}</p>
          {:else if status}
            {@render PathList(status.paths)}
          {:else}
            <p class="muted">Path details are available inside the desktop runtime.</p>
          {/if}
        </div>
        <div
          id="settings-infrastructure"
          class:settings-highlight={activeSettingsSectionId === "infrastructure"}
          class="panel"
        >
          <h2>Infrastructure checks</h2>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" on:click={copyInfrastructureSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" on:click={copyInfrastructureJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" on:click={() => copyInfrastructureFields("check")}>
              Copy checks
            </button>
            <button class="small-button" type="button" disabled={!quickCaptureShortcutInput.trim() && !appShellSettings?.quick_capture_shortcut} on:click={() => copyInfrastructureFields("shortcut")}>
              Copy shortcut
            </button>
            <button class="small-button" type="button" on:click={() => copyInfrastructureFields("mode")}>
              Copy mode
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={exportInfrastructureSummary}>
              Export summary
            </button>
            <button class="small-button" type="button" disabled={!status} on:click={chooseInfrastructureSummaryExportPath}>
              Save as
            </button>
          </div>
          <div class="summary-panel nested-summary">
            <div class="summary-header">
              <span>
                <strong>Infrastructure capability catalog</strong>
                {#if appInfrastructureCapabilityCatalog}
                  <small>{appInfrastructureCapabilityCatalog.capability_count} capabilit{appInfrastructureCapabilityCatalog.capability_count === 1 ? "y" : "ies"} · OS matrix {appInfrastructureCapabilityCatalog.verifies_os_shell_behavior ? "verified" : "deferred"}</small>
                {:else}
                  <small>Local app shell, shortcut, tray, portable, and path capability metadata.</small>
                {/if}
              </span>
              <div class="section-actions compact-actions">
                <button class="secondary-button" type="button" disabled={infrastructureCatalogBusy} on:click={() => refreshInfrastructureCatalog()}>
                  {infrastructureCatalogBusy ? "Refreshing" : "Refresh"}
                </button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={copyInfrastructureCatalogSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={copyInfrastructureCatalogJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("capability")}>Copy capabilities</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("command")}>Copy commands</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("ui")}>Copy UI</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("config")}>Copy config</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("event")}>Copy events</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("flag")}>Copy flags</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("scope")}>Copy scopes</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("limit")}>Copy limits</button>
                <button class="small-button" type="button" disabled={!appInfrastructureCapabilityCatalog} on:click={() => copyInfrastructureCatalogFields("note")}>Copy notes</button>
              </div>
            </div>
            {#if appInfrastructureCapabilityCatalog}
              <div class="metric-grid compact-grid">
                <span>Capabilities <strong>{appInfrastructureCapabilityCatalog.capability_count}</strong></span>
                <span>Path values <strong>{appInfrastructureCapabilityCatalog.includes_path_values ? "yes" : "no"}</strong></span>
                <span>Shortcut value <strong>{appInfrastructureCapabilityCatalog.includes_shortcut_value ? "yes" : "no"}</strong></span>
                <span>Autostart state <strong>{appInfrastructureCapabilityCatalog.includes_autostart_state ? "yes" : "no"}</strong></span>
                <span>Mutates shortcuts <strong>{appInfrastructureCapabilityCatalog.mutates_shortcuts ? "yes" : "no"}</strong></span>
                <span>Mutates autostart <strong>{appInfrastructureCapabilityCatalog.mutates_autostart ? "yes" : "no"}</strong></span>
                <span>Opens windows <strong>{appInfrastructureCapabilityCatalog.opens_windows ? "yes" : "no"}</strong></span>
                <span>Starts downloads <strong>{appInfrastructureCapabilityCatalog.starts_downloads ? "yes" : "no"}</strong></span>
              </div>
              <div class="compact-list">
                {#each appInfrastructureCapabilityCatalog.capabilities as item}
                  <span>{item.capability} · {item.status} · desktop {item.requires_desktop_runtime ? "yes" : "no"} · mutates {item.mutates_state ? "yes" : "no"}</span>
                {/each}
              </div>
              <small>{appInfrastructureCapabilityCatalog.review_notes.join(" ")}</small>
            {/if}
            <div class="setting-control wide-control">
              <input
                bind:value={infrastructureCatalogExportPath}
                placeholder="Optional infrastructure catalog export JSON path"
                spellcheck="false"
                aria-label="Infrastructure catalog export path"
              />
              <button class="small-button" type="button" disabled={infrastructureCatalogBusy} on:click={chooseInfrastructureCatalogExportPath}>
                Save as
              </button>
              <button class="secondary-button compact-button" type="button" disabled={infrastructureCatalogBusy} on:click={exportInfrastructureCatalog}>
                {infrastructureCatalogBusy ? "Exporting" : "Export catalog"}
              </button>
              <button class="small-button" type="button" disabled={!infrastructureCatalogExportResult && !infrastructureCatalogExportPath.trim()} on:click={() => openLocalPath(infrastructureCatalogExportResult || infrastructureCatalogExportPath, "Infrastructure catalog")}>
                Open export
              </button>
              <button class="small-button" type="button" disabled={!infrastructureCatalogExportResult && !infrastructureCatalogExportPath.trim()} on:click={() => revealLocalPath(infrastructureCatalogExportResult || infrastructureCatalogExportPath, "Infrastructure catalog")}>
                Reveal export
              </button>
            </div>
            {#if infrastructureCatalogExportResult}
              <small>Last catalog export: {infrastructureCatalogExportResult}</small>
            {/if}
          </div>
          <div class="check-list">
            {@render CheckRow("Tray shell", "Window close hides to tray in desktop runtime.")}
            {@render CheckRow("Portable mode", "Detected from executable-adjacent portable markers.")}
            {@render CheckRow("Deep link scheme", "Configured as fetchdock:// for later extension fallback.")}
            {@render CheckRow("Quick capture", appShellSettings?.quick_capture_enabled ? `Global shortcut ${appShellSettings.quick_capture_shortcut} · ${formatShortcutRegistrationState(appInfrastructureSummary?.quick_capture_registered)}` : "Global shortcut disabled.")}
          </div>
          <div class="settings-grid compact-settings-grid">
            <label class="inline-check">
              <input type="checkbox" bind:checked={quickCaptureEnabledInput} disabled={quickCaptureBusy} />
              <span>Enable quick capture shortcut</span>
            </label>
            <label>
              <span>Shortcut</span>
              <input bind:value={quickCaptureShortcutInput} placeholder="CommandOrControl+Shift+V" spellcheck="false" disabled={quickCaptureBusy} />
            </label>
          </div>
          <div class="section-actions compact-actions">
            <button class="secondary-button compact-button" type="button" disabled={quickCaptureBusy} on:click={saveQuickCaptureSettings}>
              {quickCaptureBusy ? "Saving" : "Save shortcut"}
            </button>
            <button class="small-button" type="button" disabled={quickCaptureBusy} on:click={resetQuickCaptureSettings}>
              Default shortcut
            </button>
            <small>{appShellSettings?.updated_at ? `Updated ${appShellSettings.updated_at}` : "Default quick capture shortcut is active unless disabled."}</small>
          </div>
          <div class="advanced-file-preview compact-preview">
            <div>
              <strong>App shell JSON backup</strong>
              <small>{appShellSettingsExportResult ? `${appShellSettingsExportResult.exported_setting_count} settings -> ${appShellSettingsExportResult.output_path}` : appShellSettingsImportResult ? `Imported ${appShellSettingsImportResult.imported_setting_count} settings from ${appShellSettingsImportResult.input_path}` : "Moves quick-capture shortcut settings only; autostart, tray state, diagnostics, and downloads stay separate."}</small>
            </div>
            <div class="path-picker-row">
              <input bind:value={appShellSettingsExportPath} placeholder="C:/Backups/fetchdock-app-shell-settings.json" spellcheck="false" aria-label="App shell settings export path" />
              <button class="small-button" type="button" disabled={quickCaptureBusy} on:click={chooseAppShellSettingsExportPath}>
                Save as
              </button>
              <button class="small-button" type="button" disabled={quickCaptureBusy} on:click={exportAppShellSettingsBackup}>
                Export shell
              </button>
              <button class="small-button" type="button" disabled={!appShellSettingsExportPath.trim() && !appShellSettingsExportResult} on:click={() => openLocalPath(appShellSettingsExportResult?.output_path || appShellSettingsExportPath, "App shell settings backup")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!appShellSettingsExportPath.trim() && !appShellSettingsExportResult} on:click={() => revealLocalPath(appShellSettingsExportResult?.output_path || appShellSettingsExportPath, "App shell settings backup")}>
                Reveal
              </button>
            </div>
            <div class="path-picker-row">
              <input bind:value={appShellSettingsImportPath} placeholder="C:/Backups/fetchdock-app-shell-settings.json" spellcheck="false" aria-label="App shell settings import path" />
              <button class="small-button" type="button" disabled={quickCaptureBusy} on:click={chooseAppShellSettingsImportFile}>
                Choose backup
              </button>
              <button class="small-button" type="button" disabled={quickCaptureBusy || !appShellSettingsImportPath.trim()} on:click={importAppShellSettingsBackup}>
                Import shell
              </button>
              <button class="small-button" type="button" disabled={!appShellSettingsImportPath.trim()} on:click={() => openLocalPath(appShellSettingsImportPath, "App shell settings backup")}>
                Open input
              </button>
              <button class="small-button" type="button" disabled={!appShellSettingsImportPath.trim()} on:click={() => revealLocalPath(appShellSettingsImportPath, "App shell settings backup")}>
                Reveal input
              </button>
            </div>
          </div>
          {#if quickCaptureError}
            <p class="error-text">{quickCaptureError}</p>
          {/if}
        </div>
        <div
          id="settings-dependencies"
          class:settings-highlight={activeSettingsSectionId === "dependencies"}
          class="panel"
        >
          <div class="section-heading compact-heading">
            <div>
              <h2>Dependencies</h2>
              <p>Local tool detection for downloader modules.</p>
            </div>
            <div class="section-actions">
              <button class="secondary-button" type="button" disabled={toolStatusBusy} on:click={loadToolStatuses}>
                Refresh
              </button>
              <button class="secondary-button" type="button" disabled={toolStatusBusy} on:click={() => resetSettings("dependencies")}>
                Reset tools
              </button>
              <button class="small-button" type="button" disabled={toolStatuses.length === 0} on:click={copyDependencyToolSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={toolStatuses.length === 0} on:click={copyDependencyToolJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={toolStatuses.length === 0} on:click={() => copyDependencyToolFields("id")}>
                Copy ids
              </button>
              <button class="small-button" type="button" disabled={toolStatuses.length === 0} on:click={() => copyDependencyToolFields("path")}>
                Copy paths
              </button>
              <button class="small-button" type="button" disabled={toolStatuses.length === 0} on:click={() => copyDependencyToolFields("version")}>
                Copy versions
              </button>
              <button class="small-button" type="button" disabled={toolDownloadSources.length === 0} on:click={() => copyDependencyToolFields("source")}>
                Copy sources
              </button>
              <button class="small-button" type="button" disabled={toolDownloadSources.length === 0} on:click={() => copyDependencyToolFields("hash")}>
                Copy hashes
              </button>
              <button class="small-button" type="button" disabled={toolStatusBusy} on:click={exportToolsSummary}>
                Export summary
              </button>
              <button class="small-button" type="button" disabled={toolStatusBusy} on:click={chooseToolsSummaryExportPath}>
                Save as
              </button>
              <button class="small-button" type="button" disabled={!toolsSummaryExportPath.trim()} on:click={() => openLocalPath(toolsSummaryExportPath, "Tools summary")}>
                Open export
              </button>
              <button class="small-button" type="button" disabled={!toolsSummaryExportPath.trim()} on:click={() => revealLocalPath(toolsSummaryExportPath, "Tools summary")}>
                Reveal export
              </button>
            </div>
          </div>
          <p class="muted">
            {toolsSummaryExportPath || (toolsLocalSummary ? `${toolsLocalSummary.tool_count} tools · installed ${toolsLocalSummary.installed_count} · missing ${toolsLocalSummary.missing_count} · errors ${toolsLocalSummary.error_count} · sources ${toolsLocalSummary.download_source_count} · managed files ${toolsLocalSummary.managed_file_count}` : "Reset tools clears local path overrides, download source entries, and install errors; managed dependency files stay on disk.")}
          </p>
          <div class="advanced-file-preview compact-preview">
            <div>
              <strong>Tool settings JSON backup</strong>
              <small>{toolSettingsExportResult ? `${toolSettingsExportResult.path_override_count} paths · ${toolSettingsExportResult.download_source_count} sources -> ${toolSettingsExportResult.output_path}` : toolSettingsImportResult ? `Imported ${toolSettingsImportResult.path_override_count} paths · ${toolSettingsImportResult.download_source_count} sources from ${toolSettingsImportResult.input_path}` : "Moves dependency path overrides, configured download sources, and install-error metadata only; managed binaries stay on disk."}</small>
            </div>
            <div class="path-picker-row">
              <input bind:value={toolSettingsExportPath} placeholder="C:/Backups/fetchdock-tool-settings.json" spellcheck="false" aria-label="Tool settings export path" />
              <button class="small-button" type="button" disabled={toolStatusBusy} on:click={chooseToolSettingsExportPath}>
                Save as
              </button>
              <button class="small-button" type="button" disabled={toolStatusBusy} on:click={exportToolSettingsBackup}>
                Export settings
              </button>
              <button class="small-button" type="button" disabled={!toolSettingsExportPath.trim() && !toolSettingsExportResult} on:click={() => openLocalPath(toolSettingsExportResult?.output_path || toolSettingsExportPath, "Tool settings backup")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!toolSettingsExportPath.trim() && !toolSettingsExportResult} on:click={() => revealLocalPath(toolSettingsExportResult?.output_path || toolSettingsExportPath, "Tool settings backup")}>
                Reveal
              </button>
            </div>
            <div class="path-picker-row">
              <input bind:value={toolSettingsImportPath} placeholder="C:/Backups/fetchdock-tool-settings.json" spellcheck="false" aria-label="Tool settings import path" />
              <button class="small-button" type="button" disabled={toolStatusBusy} on:click={chooseToolSettingsImportFile}>
                Choose backup
              </button>
              <button class="small-button" type="button" disabled={toolStatusBusy || !toolSettingsImportPath.trim()} on:click={importToolSettingsBackup}>
                Import settings
              </button>
              <button class="small-button" type="button" disabled={!toolSettingsImportPath.trim()} on:click={() => openLocalPath(toolSettingsImportPath, "Tool settings backup")}>
                Open input
              </button>
              <button class="small-button" type="button" disabled={!toolSettingsImportPath.trim()} on:click={() => revealLocalPath(toolSettingsImportPath, "Tool settings backup")}>
                Reveal input
              </button>
            </div>
          </div>
          {#if toolStatusError}
            <p class="error-text">{toolStatusError}</p>
          {:else if toolStatuses.length === 0}
            <p class="muted">Dependency status is available inside the desktop runtime.</p>
          {:else}
            <div class="tool-list">
              {#each toolStatuses as tool}
                {@const installAction = getToolInstallAction(tool, toolInstallBusy)}
                {@const installDetail = getToolInstallDetail(tool, toolInstallProgressById[tool.id])}
                {@const updateCheck = toolUpdateCheckById[tool.id]}
                <article class="tool-row">
                  <div class="tool-summary">
                    <span>
                      <strong>{tool.id}</strong>
                      <small>{tool.path ?? "No executable found"}</small>
                      {#if tool.version}
                        <small>Version {tool.version}</small>
                      {/if}
                      {#if installDetail}
                        <small class:error-text={installDetail.level === "error"}>{installDetail.text}</small>
                      {/if}
                      {#if updateCheck}
                        <small>{updateCheck.message}{updateCheck.latest_version ? ` · latest ${updateCheck.latest_version}` : ""}</small>
                      {/if}
                    </span>
                    <span class={`tool-state ${tool.state}`}>{tool.state}</span>
                    <small>{tool.managed ? "managed" : "PATH / override"}</small>
                  </div>
                  <div class="tool-path-control">
                    <input
                      bind:value={toolPathInputs[tool.id]}
                      placeholder="Executable path"
                      spellcheck="false"
                      aria-label={`${tool.id} executable path`}
                      disabled={toolPathBusy === tool.id}
                    />
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id}
                      on:click={() => chooseToolExecutable(tool)}
                    >
                      Choose
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id}
                      on:click={() => saveToolPath(tool)}
                    >
                      Save
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id}
                      on:click={() => clearSavedToolPath(tool)}
                    >
                      Clear
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id || !toolPathInputs[tool.id]?.trim()}
                      on:click={() => openLocalPath(toolPathInputs[tool.id], `${tool.id} executable`)}
                    >
                      Open path
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id || !toolPathInputs[tool.id]?.trim()}
                      on:click={() => revealLocalPath(toolPathInputs[tool.id], `${tool.id} executable`)}
                    >
                      Reveal
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolPathBusy === tool.id || !toolPathInputs[tool.id]?.trim()}
                      on:click={() => copyLinesToClipboard([toolPathInputs[tool.id]], `No ${tool.id} path`, `${tool.id} path copied`)}
                    >
                      Copy path
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolUpdateCheckBusy === tool.id || !tool.managed || !tool.updatable}
                      on:click={() => checkToolUpdateStatus(tool)}
                    >
                      {toolUpdateCheckBusy === tool.id ? "Checking" : "Check"}
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={installAction.disabled}
                      on:click={() => requestToolInstall(tool)}
                    >
                      {installAction.label}
                    </button>
                  </div>
                  <div class="tool-path-control">
                    <input
                      bind:value={toolSourceUrlInputs[tool.id]}
                      placeholder="Artifact URL for managed install"
                      spellcheck="false"
                      aria-label={`${tool.id} download source URL`}
                      disabled={toolSourceBusy === tool.id}
                    />
                    <input
                      bind:value={toolSourceSha256Inputs[tool.id]}
                      placeholder="SHA-256"
                      spellcheck="false"
                      aria-label={`${tool.id} download source SHA-256`}
                      disabled={toolSourceBusy === tool.id}
                    />
                    <input
                      bind:value={toolSourceArchiveInputs[tool.id]}
                      placeholder="Archive member, optional"
                      spellcheck="false"
                      aria-label={`${tool.id} archive member path`}
                      disabled={toolSourceBusy === tool.id}
                    />
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolSourceBusy === tool.id}
                      on:click={() => saveToolDownloadSource(tool)}
                    >
                      Save source
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolSourceBusy === tool.id || !toolSourceUrlInputs[tool.id]?.trim()}
                      on:click={() => openSourceUrl(toolSourceUrlInputs[tool.id].trim(), `${tool.id} download source`)}
                    >
                      Open source
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolSourceBusy === tool.id || !toolSourceUrlInputs[tool.id]?.trim()}
                      on:click={() => copyLinesToClipboard([toolSourceUrlInputs[tool.id]], `No ${tool.id} source URL`, `${tool.id} source URL copied`)}
                    >
                      Copy source
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolSourceBusy === tool.id || !toolSourceSha256Inputs[tool.id]?.trim()}
                      on:click={() => copyLinesToClipboard([toolSourceSha256Inputs[tool.id]], `No ${tool.id} source hash`, `${tool.id} source hash copied`)}
                    >
                      Copy hash
                    </button>
                    <button
                      class="secondary-button"
                      type="button"
                      disabled={toolSourceBusy === tool.id}
                      on:click={() => clearSavedToolDownloadSource(tool)}
                    >
                      Clear source
                    </button>
                  </div>
                </article>
              {/each}
            </div>
          {/if}
        </div>
        <div
          id="settings-appearance"
          class:settings-highlight={activeSettingsSectionId === "appearance"}
          class="panel"
        >
          <h2>Appearance</h2>
          <div class="section-actions compact-actions">
