              <button class="small-button" type="button" disabled={!appearanceSettingsExportPath.trim() && !appearanceSettingsExportResult} on:click={() => revealLocalPath(appearanceSettingsExportResult?.output_path || appearanceSettingsExportPath, "Appearance settings backup")}>
