              <button class="small-button" type="button" disabled={!appearanceCapabilityCatalogExportPath.trim() && !appearanceCapabilityCatalogExportResult} on:click={() => openLocalPath(appearanceCapabilityCatalogExportResult || appearanceCapabilityCatalogExportPath, "Appearance capability catalog")}>
