              </button>
              <button class="small-button" type="button" disabled={!appearanceCapabilityCatalogExportPath.trim() && !appearanceCapabilityCatalogExportResult} on:click={() => revealLocalPath(appearanceCapabilityCatalogExportResult || appearanceCapabilityCatalogExportPath, "Appearance capability catalog")}>
