              <button class="secondary-button compact-button" type="button" disabled={diagnosticsBusy} on:click={handleExportAppearanceThemeCatalog}>
                {diagnosticsBusy ? "Exporting" : "Export catalog"}
              </button>
              <button class="small-button" type="button" disabled={!appearanceThemeCatalogExportPath.trim()} on:click={() => openLocalPath(appearanceThemeCatalogExportPath, "Theme catalog")}>
