            <small>Catalog export is metadata-only: no external theme files, screenshots, logos, downloaded content, Cookie/Auth values, or visual QA proof.</small>
            {#if appearanceThemeCatalogError}
              <p class="error-text">{appearanceThemeCatalogError}</p>
            {/if}
          </div>
          <div class="advanced-file-preview compact-preview">
            <div>
