                bind:value={appearanceFontScaleInput}
                type="number"
                min="90"
                max="115"
                step="1"
                aria-label="Font scale percent"
                disabled={appearanceSettingsBusy || appearanceSettings === null}
              />
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Density</strong>
