              Save appearance
            </button>
            <button
              class="secondary-button"
              type="button"
              disabled={appearanceSettingsBusy || appearanceSettings === null}
              on:click={() => resetSettings("appearance")}
            >
              Reset appearance
            </button>
          </div>
          {#if appearanceSettingsError}
            <p class="error-text">{appearanceSettingsError}</p>
          {/if}
        </div>
        <div
