          class:settings-highlight={activeSettingsSectionId === "downloads"}
          class="panel"
        >
          <h2>Downloads</h2>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={copyDownloadsDefaultsSummary}>
