            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={copyDownloadsDefaultsJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null || !defaultOutputDirInput.trim()} on:click={() => copyDownloadsDefaultsFields("output")}>
              Copy output
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyDownloadsDefaultsFields("quality")}>
              Copy quality
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyDownloadsDefaultsFields("subtitle")}>
              Copy subtitles
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyDownloadsDefaultsFields("sponsorblock")}>
              Copy SponsorBlock
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyDownloadsDefaultsFields("metadata")}>
              Copy metadata
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyDownloadsDefaultsFields("cleanup")}>
              Copy cleanup
            </button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Max active downloads</strong>
              <small>
                {#if downloadsSettings}
                  Scheduler starts up to {downloadsSettings.max_concurrency} task{downloadsSettings.max_concurrency === 1 ? "" : "s"} at once.
                {:else}
                  Available inside the desktop runtime.
                {/if}
              </small>
            </span>
            <div class="setting-control">
              <input
                bind:value={maxConcurrencyInput}
                min="1"
                max="8"
                step="1"
                type="number"
                aria-label="Max active downloads"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
              <button
                class="secondary-button"
                type="button"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
                on:click={saveDownloadsSettings}
              >
                Save
              </button>
              <button
                class="secondary-button"
                type="button"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
                on:click={() => resetSettings("downloads")}
              >
                Reset
              </button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Downloads settings backup</strong>
              <small>
                {downloadsSettingsImportResult
                  ? `Imported ${downloadsSettingsImportResult.imported_setting_count} local settings from ${downloadsSettingsImportResult.input_path}.`
                  : downloadsSettingsExportResult
                    ? `Exported ${downloadsSettingsExportResult.exported_setting_count} local settings to ${downloadsSettingsExportResult.output_path}.`
                    : "Back up download defaults, network defaults, subtitle, SponsorBlock, metadata, and cleanup preferences."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-input-row">
                <input bind:value={downloadsSettingsExportPath} placeholder="C:/Backups/fetchdock-downloads-settings.json" spellcheck="false" aria-label="Downloads settings export path" />
                <button class="small-button" type="button" disabled={Boolean(downloadsSettingsTransferBusy)} on:click={chooseDownloadsSettingsExportPath}>
                  Save as
                </button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(downloadsSettingsTransferBusy) || downloadsSettings === null} on:click={exportDownloadsSettingsBackup}>
                  {downloadsSettingsTransferBusy === "export" ? "Exporting" : "Export settings"}
                </button>
                <button class="small-button" type="button" disabled={!downloadsSettingsExportPath.trim() && !downloadsSettingsExportResult} on:click={() => openLocalPath(downloadsSettingsExportResult?.output_path || downloadsSettingsExportPath, "Downloads settings backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!downloadsSettingsExportPath.trim() && !downloadsSettingsExportResult} on:click={() => revealLocalPath(downloadsSettingsExportResult?.output_path || downloadsSettingsExportPath, "Downloads settings backup")}>
                  Reveal
                </button>
              </div>
              <div class="path-input-row">
                <input bind:value={downloadsSettingsImportPath} placeholder="C:/Backups/fetchdock-downloads-settings.json" spellcheck="false" aria-label="Downloads settings import path" />
                <button class="small-button" type="button" disabled={Boolean(downloadsSettingsTransferBusy)} on:click={chooseDownloadsSettingsImportFile}>
