                </button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(downloadsSettingsTransferBusy) || !downloadsSettingsImportPath.trim()} on:click={importDownloadsSettingsBackup}>
                  {downloadsSettingsTransferBusy === "import" ? "Importing" : "Import settings"}
                </button>
                <button class="small-button" type="button" disabled={!downloadsSettingsImportPath.trim()} on:click={() => openLocalPath(downloadsSettingsImportPath, "Downloads settings backup")}>
                  Open input
                </button>
              </div>
