                aria-label="Default quality"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Default audio format</strong>
              <small>Stored on new tasks for future audio extraction integrations.</small>
            </span>
