                    <span>{item.filter} · {item.status} · copy {item.supports_copy ? "yes" : "no"} · export {item.supports_export ? "yes" : "no"} · preset {item.preset_field ?? "none"}</span>
                  {/each}
                </div>
                <small>{downloadsFilterCatalog.review_notes.join(" ")}</small>
              {/if}
              <div class="setting-control wide-control">
                <input
                  bind:value={downloadsFilterCatalogExportPath}
                  placeholder="Optional filter catalog export JSON path"
                  spellcheck="false"
                  aria-label="Downloads filter catalog export path"
                />
                <button class="small-button" type="button" disabled={downloadsFilterCatalogBusy} on:click={chooseDownloadsFilterCatalogExportPath}>
                  Save as
                </button>
                <button class="secondary-button compact-button" type="button" disabled={downloadsFilterCatalogBusy} on:click={exportDownloadsFilterCatalogFile}>
                  {downloadsFilterCatalogBusy ? "Exporting" : "Export filters"}
                </button>
                <button class="small-button" type="button" disabled={!downloadsFilterCatalogExportResult && !downloadsFilterCatalogExportPath.trim()} on:click={() => openPath(downloadsFilterCatalogExportResult || downloadsFilterCatalogExportPath)}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!downloadsFilterCatalogExportResult && !downloadsFilterCatalogExportPath.trim()} on:click={() => revealFile(downloadsFilterCatalogExportResult || downloadsFilterCatalogExportPath)}>
                  Reveal export
                </button>
              </div>
              {#if downloadsFilterCatalogExportResult}
                <small>Last filter export: {downloadsFilterCatalogExportResult}</small>
              {/if}
            </div>
            <div class="setting-control wide-control">
              <input
                bind:value={downloadsTasksExportPath}
                placeholder="Optional task backup export JSON path"
                spellcheck="false"
                aria-label="Downloads task backup export path"
              />
              <button class="small-button" type="button" disabled={downloadsTasksTransferBusy} on:click={chooseDownloadsTasksExportPath}>
                Save as
              </button>
              <button class="secondary-button compact-button" type="button" disabled={downloadsTasksTransferBusy} on:click={exportDownloadsTaskBackup}>
                {downloadsTasksTransferBusy ? "Working" : "Export tasks"}
              </button>
              <button class="small-button" type="button" disabled={!downloadsTasksExportResult?.output_path && !downloadsTasksExportPath.trim()} on:click={() => openPath(downloadsTasksExportResult?.output_path || downloadsTasksExportPath)}>
                Open backup
              </button>
              <button class="small-button" type="button" disabled={!downloadsTasksExportResult?.output_path && !downloadsTasksExportPath.trim()} on:click={() => revealFile(downloadsTasksExportResult?.output_path || downloadsTasksExportPath)}>
                Reveal backup
              </button>
            </div>
            <div class="setting-control wide-control">
              <input
                bind:value={downloadsTasksImportPath}
                placeholder="Download task backup JSON to import"
                spellcheck="false"
                aria-label="Downloads task backup import path"
              />
              <button class="small-button" type="button" disabled={downloadsTasksTransferBusy} on:click={chooseDownloadsTasksImportPath}>
                Choose
              </button>
              <button class="secondary-button compact-button" type="button" disabled={downloadsTasksTransferBusy || !downloadsTasksImportPath.trim()} on:click={importDownloadsTaskBackup}>
                {downloadsTasksTransferBusy ? "Working" : "Import tasks"}
              </button>
            </div>
            {#if downloadsTasksExportResult}
              <small>Task backup: {downloadsTasksExportResult.exported_task_count} task{downloadsTasksExportResult.exported_task_count === 1 ? "" : "s"} -> {downloadsTasksExportResult.output_path}</small>
            {:else if downloadsTasksImportResult}
              <small>Task import: {downloadsTasksImportResult.imported_task_count} imported · {downloadsTasksImportResult.skipped_task_count} skipped · active downgraded {downloadsTasksImportResult.downgraded_active_task_count}</small>
            {:else}
              <small>Task backups include source URLs and queue metadata only; output files, log bodies, Cookie values, and Authorization values stay outside the JSON.</small>
            {/if}
          </div>
        </div>
        <div
          id="settings-network"
          class:settings-highlight={activeSettingsSectionId === "network"}
          class="panel"
        >
          <h2>Network</h2>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={copyNetworkSettingsSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={copyNetworkSettingsJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null || !defaultUserAgentInput.trim()} on:click={() => copyNetworkSettingsFields("user-agent")}>
              Copy User-Agent
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null || !defaultRefererInput.trim()} on:click={() => copyNetworkSettingsFields("referer")}>
              Copy referer
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null || !defaultProxyInput.trim()} on:click={() => copyNetworkSettingsFields("proxy")}>
              Copy proxy
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null || !defaultRateLimitInput.trim()} on:click={() => copyNetworkSettingsFields("rate")}>
              Copy rate
            </button>
            <button class="small-button" type="button" disabled={downloadsSettings === null} on:click={() => copyNetworkSettingsFields("fragments")}>
              Copy fragments
            </button>
          </div>
          <div class="setting-row block-row">
            <span>
              <strong>Network settings backup</strong>
              <small>Local JSON backup for User-Agent, Referer, proxy, rate limit, live, and fragments defaults only.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={networkSettingsExportPath} placeholder="C:/Backups/fetchdock-network-settings.json" spellcheck="false" aria-label="Network settings export path" />
                <button class="small-button" type="button" disabled={Boolean(networkSettingsTransferBusy)} on:click={chooseNetworkSettingsExportPath}>
                  Save as
                </button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(networkSettingsTransferBusy)} on:click={exportNetworkSettingsBackup}>
                  {networkSettingsTransferBusy === "export" ? "Exporting" : "Export network"}
                </button>
                <button class="small-button" type="button" disabled={!networkSettingsExportPath.trim() && !networkSettingsExportResult} on:click={openNetworkSettingsExportResult}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!networkSettingsExportPath.trim() && !networkSettingsExportResult} on:click={revealNetworkSettingsExportResult}>
                  Reveal
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={networkSettingsImportPath} placeholder="C:/Backups/fetchdock-network-settings.json" spellcheck="false" aria-label="Network settings import path" />
                <button class="small-button" type="button" disabled={Boolean(networkSettingsTransferBusy)} on:click={chooseNetworkSettingsImportFile}>
                  Choose
                </button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(networkSettingsTransferBusy) || !networkSettingsImportPath.trim()} on:click={importNetworkSettingsBackup}>
                  {networkSettingsTransferBusy === "import" ? "Importing" : "Import network"}
                </button>
                <button class="small-button" type="button" disabled={!networkSettingsImportPath.trim()} on:click={() => openLocalPath(networkSettingsImportPath, "Network settings backup")}>
                  Open import
                </button>
                <button class="small-button" type="button" disabled={!networkSettingsImportPath.trim()} on:click={() => revealLocalPath(networkSettingsImportPath, "Network settings backup")}>
                  Reveal import
                </button>
              </div>
              <small>{networkSettingsExportResult ? `Exported ${networkSettingsExportResult.exported_setting_count} network defaults to ${networkSettingsExportResult.output_path}.` : networkSettingsImportResult ? `Imported ${networkSettingsImportResult.imported_setting_count} network defaults from ${networkSettingsImportResult.input_path}.` : "This backup does not include task source URLs, Cookie values, Authorization values, downloaded files, diagnostics bodies, log bodies, or proxy connectivity results."}</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Default User-Agent</strong>
              <small>Used by new tasks unless the Home task field overrides it.</small>
            </span>
            <div class="setting-control wide-control">
              <input
                bind:value={defaultUserAgentInput}
                placeholder="Downloader default"
                spellcheck="false"
                aria-label="Default User-Agent"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Default referer</strong>
              <small>Used by new tasks unless the Home task field overrides it.</small>
            </span>
            <div class="setting-control wide-control">
              <input
                bind:value={defaultRefererInput}
                placeholder="https://example.com/page"
                spellcheck="false"
                aria-label="Default referer"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Default proxy</strong>
              <small>Applied to yt-dlp and direct-file tasks unless the Home task field overrides it.</small>
            </span>
            <div class="setting-control wide-control">
              <input
                bind:value={defaultProxyInput}
                placeholder="http:// or socks5://"
                spellcheck="false"
                aria-label="Default proxy"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
              <button class="secondary-button compact-button" type="button" disabled={networkValidationBusy} on:click={validateCurrentNetworkSettings}>
                {networkValidationBusy ? "Checking" : "Check proxy"}
              </button>
            </div>
          </div>
          {#if networkValidation}
            <p class="muted">
              {networkValidation.message}{networkValidation.proxy_configured ? ` ${networkValidation.proxy_kind}://${networkValidation.proxy_host}:${networkValidation.proxy_port}` : ""}
            </p>
          {/if}
          <div class="setting-row">
            <span>
              <strong>Default rate limit</strong>
              <small>Applied to yt-dlp and direct-file tasks unless the Home task field overrides it.</small>
            </span>
            <div class="setting-control wide-control">
              <input
                bind:value={defaultRateLimitInput}
                placeholder="500K, 2M"
                spellcheck="false"
                aria-label="Default rate limit"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
            </div>
          </div>
          <label class="setting-row checkbox-row">
            <span>
              <strong>Default live from start</strong>
              <small>Applied to yt-dlp live tasks unless the Home task field overrides it.</small>
            </span>
            <input
              bind:checked={defaultLiveFromStartInput}
              type="checkbox"
              disabled={downloadsSettingsBusy || downloadsSettings === null}
            />
          </label>
          <div class="setting-row">
            <span>
              <strong>Default fragments</strong>
              <small>Applied to yt-dlp tasks when set from 1 to 16.</small>
            </span>
            <div class="setting-control wide-control">
              <input
                bind:value={defaultConcurrentFragmentsInput}
                inputmode="numeric"
                placeholder="1-16"
                spellcheck="false"
                aria-label="Default fragments"
                disabled={downloadsSettingsBusy || downloadsSettings === null}
              />
            </div>
          </div>
          <div class="setting-control right-control">
            <button
              class="secondary-button"
              type="button"
              disabled={downloadsSettingsBusy || downloadsSettings === null}
              on:click={saveNetworkSettings}
            >
              Save network
            </button>
            <button
              class="secondary-button"
              type="button"
              disabled={downloadsSettingsBusy || downloadsSettings === null}
              on:click={() => resetSettings("network")}
            >
              Reset network
            </button>
          </div>
          {#if downloadsSettingsError}
            <p class="error-text">{downloadsSettingsError}</p>
          {/if}
        </div>

        <div
          id="settings-cookies"
          class:settings-highlight={activeSettingsSectionId === "cookies"}
          class="panel"
        >
          <h2>Cookies</h2>
          <div class="tool-panel compact-tool-panel">
            <div class="tool-panel-heading">
              <span>
                <strong>Local Cookie/Auth summary</strong>
                {#if cookieAuthLocalSummary}
                  <small>{cookieAuthLocalSummary.cookie_bucket_count} bucket{cookieAuthLocalSummary.cookie_bucket_count === 1 ? "" : "s"} · {cookieAuthLocalSummary.cookie_row_count} rows · {cookieAuthLocalSummary.staged_cookie_payload_count + cookieAuthLocalSummary.staged_authorization_payload_count} staged payload{cookieAuthLocalSummary.staged_cookie_payload_count + cookieAuthLocalSummary.staged_authorization_payload_count === 1 ? "" : "s"}</small>
                {:else}
                  <small>No local Cookie/Auth summary loaded yet.</small>
                {/if}
              </span>
              <div class="section-actions compact-actions">
                <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={() => refreshCookieAuthLocalSummary()}>
                  {cookieBucketsBusy ? "Refreshing" : "Refresh"}
                </button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary} on:click={copyCookieAuthLocalSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary} on:click={copyCookieAuthLocalSummaryJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary?.platform_counts.length} on:click={() => copyCookieAuthLocalSummaryFields("platform")}>Copy platforms</button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary?.health_counts.length} on:click={() => copyCookieAuthLocalSummaryFields("health")}>Copy health</button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary?.staged_payload_counts.length} on:click={() => copyCookieAuthLocalSummaryFields("payload")}>Copy payloads</button>
                <button class="small-button" type="button" disabled={!cookieAuthLocalSummary} on:click={() => copyCookieAuthLocalSummaryFields("note")}>Copy notes</button>
              </div>
            </div>
            {#if cookieAuthLocalSummary}
              <div class="stat-chip-grid compact-stat-grid">
                <span>Buckets <strong>{cookieAuthLocalSummary.cookie_bucket_count}</strong></span>
                <span>Rows <strong>{cookieAuthLocalSummary.cookie_row_count}</strong></span>
                <span>Valid <strong>{cookieAuthLocalSummary.valid_cookie_bucket_count}</strong></span>
                <span>Untested <strong>{cookieAuthLocalSummary.untested_cookie_bucket_count}</strong></span>
                <span>Domains <strong>{cookieAuthLocalSummary.domain_hint_count}</strong></span>
                <span>Paths <strong>{cookieAuthLocalSummary.path_hint_count}</strong></span>
                <span>Storage <strong>{cookieAuthLocalSummary.storage_file_count}/{cookieAuthLocalSummary.cookie_bucket_count}</strong></span>
                <span>Payloads <strong>{cookieAuthLocalSummary.staged_cookie_payload_count + cookieAuthLocalSummary.staged_authorization_payload_count}</strong></span>
              </div>
              <small>Twitter/X fallback {cookieAuthLocalSummary.twitter_x_manual_cookie_set ? (cookieAuthLocalSummary.twitter_x_manual_cookie_enabled ? "enabled" : "stored") : "not set"} · Bilibili cookie {cookieAuthLocalSummary.bilibili_cookie_bucket_set ? cookieAuthLocalSummary.bilibili_cookie_health ?? "configured" : "none"} · values exported: Cookie {cookieAuthLocalSummary.includes_cookie_values ? "yes" : "no"}, Authorization {cookieAuthLocalSummary.includes_authorization_values ? "yes" : "no"}</small>
              <small>Last updated {cookieAuthLocalSummary.last_cookie_bucket_updated_at ?? "never"} · last tested {cookieAuthLocalSummary.last_cookie_tested_at ?? "never"}</small>
            {/if}
            <div class="path-picker-row compact-path-row">
              <input bind:value={cookieAuthSummaryExportPath} placeholder="C:/path/cookie-auth-summary.json" spellcheck="false" aria-label="Cookie and Auth summary export path" />
              <button class="small-button" type="button" disabled={cookieBucketsBusy} on:click={exportCookieAuthSummary}>Export JSON</button>
              <button class="small-button" type="button" disabled={!cookieAuthSummaryExportResult && !cookieAuthSummaryExportPath.trim()} on:click={() => openLocalPath(cookieAuthSummaryExportResult || cookieAuthSummaryExportPath, "Cookie/Auth summary")}>Open</button>
              <button class="small-button" type="button" disabled={!cookieAuthSummaryExportResult && !cookieAuthSummaryExportPath.trim()} on:click={() => revealLocalPath(cookieAuthSummaryExportResult || cookieAuthSummaryExportPath, "Cookie/Auth summary")}>Reveal</button>
            </div>
          </div>
          <div class="tool-panel compact-tool-panel">
            <div class="tool-panel-heading">
              <span>
                <strong>Cookie/Auth capability catalog</strong>
                {#if cookieAuthCapabilityCatalog}
                  <small>{cookieAuthCapabilityCatalog.capability_count} capabilities · sources {cookieAuthCapabilityCatalog.supported_sources.length} · health states {cookieAuthCapabilityCatalog.supported_health_states.length}</small>
                {:else}
                  <small>No Cookie/Auth capability catalog loaded yet.</small>
                {/if}
              </span>
              <div class="section-actions compact-actions">
                <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={() => refreshCookieAuthCapabilityCatalog()}>
                  {cookieBucketsBusy ? "Refreshing" : "Refresh"}
                </button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={copyCookieAuthCapabilityCatalogSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={copyCookieAuthCapabilityCatalogJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={() => copyCookieAuthCapabilityCatalogFields("capability")}>Copy capabilities</button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={() => copyCookieAuthCapabilityCatalogFields("command")}>Copy commands</button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={() => copyCookieAuthCapabilityCatalogFields("secret")}>Copy secret fields</button>
                <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalog} on:click={() => copyCookieAuthCapabilityCatalogFields("limit")}>Copy limits</button>
              </div>
            </div>
            {#if cookieAuthCapabilityCatalog}
              <div class="stat-chip-grid compact-stat-grid">
                <span>Capabilities <strong>{cookieAuthCapabilityCatalog.capability_count}</strong></span>
                <span>Sources <strong>{cookieAuthCapabilityCatalog.supported_sources.length}</strong></span>
                <span>Health <strong>{cookieAuthCapabilityCatalog.supported_health_states.length}</strong></span>
                <span>Values <strong>{cookieAuthCapabilityCatalog.includes_cookie_values ? "included" : "excluded"}</strong></span>
                <span>Auth headers <strong>{cookieAuthCapabilityCatalog.includes_authorization_values ? "included" : "excluded"}</strong></span>
                <span>Live login <strong>{cookieAuthCapabilityCatalog.verifies_live_login ? "verified" : "pending"}</strong></span>
              </div>
              <div class="compact-list">
                {#each cookieAuthCapabilityCatalog.capabilities as item}
                  <small><strong>{item.label}</strong> · {item.status} · {item.scope}</small>
                {/each}
              </div>
              <small>{cookieAuthCapabilityCatalog.review_notes.join(" ")}</small>
            {/if}
            <div class="path-picker-row compact-path-row">
              <input bind:value={cookieAuthCapabilityCatalogExportPath} placeholder="C:/path/cookie-auth-capability-catalog.json" spellcheck="false" aria-label="Cookie and Auth capability catalog export path" />
              <button class="small-button" type="button" disabled={cookieBucketsBusy} on:click={exportCookieAuthCapabilityCatalogFile}>Export JSON</button>
              <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalogExportResult && !cookieAuthCapabilityCatalogExportPath.trim()} on:click={() => openLocalPath(cookieAuthCapabilityCatalogExportResult || cookieAuthCapabilityCatalogExportPath, "Cookie/Auth capability catalog")}>Open</button>
              <button class="small-button" type="button" disabled={!cookieAuthCapabilityCatalogExportResult && !cookieAuthCapabilityCatalogExportPath.trim()} on:click={() => revealLocalPath(cookieAuthCapabilityCatalogExportResult || cookieAuthCapabilityCatalogExportPath, "Cookie/Auth capability catalog")}>Reveal</button>
            </div>
          </div>
          <div class="setting-row block-row">
            <span>
              <strong>Cookie bucket backup</strong>
              <small>Explicit JSON backup for managed Cookie buckets. This includes Cookie values; Authorization headers and staged extension payload bodies stay outside it.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={cookieBucketsBackupExportPath} placeholder="C:/Backups/fetchdock-cookie-buckets.json" spellcheck="false" aria-label="Cookie bucket backup export path" />
                <button class="small-button" type="button" disabled={cookieBucketsBusy} on:click={chooseCookieBucketsBackupExportPath}>
                  Save as
                </button>
                <button class="secondary-button" type="button" disabled={cookieBucketsBusy || cookieBuckets.length === 0} on:click={exportCookieBucketsBackup}>
                  {cookieBucketsBusy ? "Working" : cookieSelectedIds.length > 0 ? `Export ${cookieSelectedIds.length} selected` : "Export buckets"}
                </button>
                <button class="small-button" type="button" disabled={!cookieBucketsBackupExportResult && !cookieBucketsBackupExportPath.trim()} on:click={() => openLocalPath(cookieBucketsBackupExportResult?.output_path || cookieBucketsBackupExportPath, "Cookie bucket backup")}>
                  Open backup
                </button>
                <button class="small-button" type="button" disabled={!cookieBucketsBackupExportResult && !cookieBucketsBackupExportPath.trim()} on:click={() => revealLocalPath(cookieBucketsBackupExportResult?.output_path || cookieBucketsBackupExportPath, "Cookie bucket backup")}>
                  Reveal backup
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={cookieBucketsBackupImportPath} placeholder="C:/Backups/fetchdock-cookie-buckets.json" spellcheck="false" aria-label="Cookie bucket backup import path" />
                <button class="small-button" type="button" disabled={cookieBucketsBusy} on:click={chooseCookieBucketsBackupImportFile}>
                  Choose
                </button>
                <button class="secondary-button" type="button" disabled={cookieBucketsBusy || !cookieBucketsBackupImportPath.trim()} on:click={importCookieBucketsBackup}>
                  {cookieBucketsBusy ? "Working" : "Import buckets"}
                </button>
                <button class="small-button" type="button" disabled={!cookieBucketsBackupImportPath.trim()} on:click={() => openLocalPath(cookieBucketsBackupImportPath, "Cookie bucket backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!cookieBucketsBackupImportPath.trim()} on:click={() => revealLocalPath(cookieBucketsBackupImportPath, "Cookie bucket backup")}>
                  Reveal
                </button>
              </div>
              <small>{cookieBucketsBackupExportResult ? `Exported ${cookieBucketsBackupExportResult.exported_bucket_count} bucket${cookieBucketsBackupExportResult.exported_bucket_count === 1 ? "" : "s"} with ${cookieBucketsBackupExportResult.exported_cookie_row_count} Cookie row${cookieBucketsBackupExportResult.exported_cookie_row_count === 1 ? "" : "s"} -> ${cookieBucketsBackupExportResult.output_path}` : cookieBucketsBackupImportResult ? `Imported ${cookieBucketsBackupImportResult.imported_bucket_count} bucket${cookieBucketsBackupImportResult.imported_bucket_count === 1 ? "" : "s"} · ${cookieBucketsBackupImportResult.skipped_bucket_count} skipped · ${cookieBucketsBackupImportResult.total_bucket_count} total` : "Use the metadata summary above when you do not want Cookie values in an export."}</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Import cookie bucket</strong>
              <small>Paste Netscape cookie rows or import a local cookie file.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={cookieImportName} placeholder="Account label" spellcheck="false" aria-label="Cookie bucket name" />
              <input bind:value={cookieImportPlatform} placeholder="Platform, optional" spellcheck="false" aria-label="Cookie platform" />
            </div>
          </div>
          <div class="setting-row block-row">
            <span>
              <strong>Paste cookies</strong>
              <small>Stored locally; the UI only keeps bucket metadata after import.</small>
            </span>
            <textarea bind:value={cookieImportText} placeholder="# Netscape HTTP Cookie File" spellcheck="false" aria-label="Pasted cookies"></textarea>
            <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={importCookieFromPaste}>Import paste</button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Import from file</strong>
              <small>Reads a local Netscape cookie file and stores a managed copy.</small>
            </span>
            <div class="setting-control wide-control">
              <input bind:value={cookieImportFilePath} placeholder="C:/path/cookies.txt" spellcheck="false" aria-label="Cookie file path" />
              <button class="icon-button" type="button" title="Choose Cookie file" disabled={cookieBucketsBusy} on:click={chooseCookieImportFile}>
                <FolderOpen size={16} />
              </button>
              <button class="small-button" type="button" disabled={!cookieImportFilePath.trim()} on:click={() => openLocalPath(cookieImportFilePath, "Cookie import file")}>
                Open file
              </button>
              <button class="small-button" type="button" disabled={!cookieImportFilePath.trim()} on:click={() => revealLocalPath(cookieImportFilePath, "Cookie import file")}>
                Reveal
              </button>
              <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={importCookieFromFile}>Import file</button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Import from extension payload</strong>
              <small>Reads a captured payload id from the local extension bridge staging folder.</small>
            </span>
            <div class="setting-control wide-control">
              <input bind:value={cookieExtensionPayloadRef} placeholder="payload-id" spellcheck="false" aria-label="Extension cookie payload id" />
              <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={importCookieFromExtensionPayload}>Import payload</button>
            </div>
          </div>
          <div class="setting-row block-row">
            <span>
              <strong>Extension cookie payloads</strong>
              <small>{extensionCookiePayloads.length} staged payload{extensionCookiePayloads.length === 1 ? "" : "s"}; clearing these does not delete imported Cookie buckets.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionCookiePayloadBusy === "refresh"} on:click={refreshExtensionCookiePayloads}>
                  {extensionCookiePayloadBusy === "refresh" ? "Refreshing" : "Refresh payloads"}
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={copyFilteredExtensionCookiePayloadSummary}>
