                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("ref")}>
                  Copy refs
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("name")}>
                  Copy names
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("size")}>
                  Copy sizes
                </button>
                <button class="small-button" type="button" disabled={!filteredExtensionCookiePayloads.some((payload) => payload.file.modified_at)} on:click={() => copyFilteredExtensionCookiePayloadFields("modified")}>
                  Copy modified
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionCookiePayloadBusy) || cookieBucketsBusy || filteredExtensionCookiePayloads.length === 0} on:click={importFilteredExtensionCookiePayloads}>
                  {extensionCookiePayloadBusy === "import-filtered" ? "Importing" : "Import filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionCookiePayloadBusy) || filteredExtensionCookiePayloads.length === 0} on:click={requestFilteredExtensionCookiePayloadsRemove}>
                  {extensionCookiePayloadBusy === "remove-filtered" ? "Removing" : "Remove filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionCookiePayloadBusy) || extensionCookiePayloads.length === 0} on:click={requestClearExtensionCookiePayloads}>
                  Clear payloads
                </button>
              </div>
              <div class="library-filter-row">
                <input bind:value={extensionCookiePayloadSearch} placeholder="Search payload ids, file names, paths" spellcheck="false" aria-label="Extension cookie payload search" />
                <span class="filter-count-label">{filteredExtensionCookiePayloads.length} shown of {extensionCookiePayloads.length} staged payload{extensionCookiePayloads.length === 1 ? "" : "s"}</span>
              </div>
              {#if extensionCookiePayloads.length === 0}
                <small>No cookie payloads have been staged yet.</small>
              {:else if filteredExtensionCookiePayloads.length === 0}
                <small>No cookie payloads match the current search.</small>
              {:else}
                <div class="compact-list">
                  {#each filteredExtensionCookiePayloads as payload}
                    <article class="compact-list-item">
                      <span>
                        <strong>{payload.payload_ref}</strong>
                        <small>{payload.file.file_name} · {formatBytes(payload.file.size_bytes)} · {payload.file.modified_at ?? "modified time unknown"}</small>
                        <code>{payload.file.path}</code>
                      </span>
                      <button class="small-button" type="button" disabled={extensionCookiePayloadBusy === payload.payload_ref} on:click={() => useExtensionCookiePayload(payload)}>
                        Use
                      </button>
                      <button class="secondary-button" type="button" disabled={Boolean(extensionCookiePayloadBusy) || cookieBucketsBusy} on:click={() => importExtensionCookiePayload(payload)}>
                        {extensionCookiePayloadBusy === payload.payload_ref ? "Importing" : "Import"}
                      </button>
                      <button class="small-button" type="button" disabled={extensionCookiePayloadBusy === payload.payload_ref} on:click={() => openLocalPath(payload.file.path, payload.file.file_name)}>
                        Open file
                      </button>
                      <button class="small-button" type="button" disabled={extensionCookiePayloadBusy === payload.payload_ref} on:click={() => revealLocalPath(payload.file.path, payload.file.file_name)}>
                        Reveal
                      </button>
                      <button class="small-button danger" type="button" disabled={Boolean(extensionCookiePayloadBusy)} on:click={() => removeExtensionCookiePayload(payload.payload_ref)}>
                        Delete
                      </button>
                    </article>
                  {/each}
                </div>
              {/if}
            </div>
          </div>
          <div class="setting-row block-row">
            <span>
              <strong>Twitter/X manual Cookie header</strong>
              <small>{authSettings?.twitter_x.manual_cookie_header_set ? `Stored · ${authSettings.twitter_x.manual_cookie_header_preview ?? "header saved"}` : "Used only for Twitter/X yt-dlp tasks when no task cookie bucket is selected."}</small>
            </span>
            <textarea bind:value={twitterManualCookieHeaderInput} placeholder="auth_token=...; ct0=..." spellcheck="false" aria-label="Twitter/X manual Cookie header"></textarea>
            <label class="inline-check">
              <input type="checkbox" bind:checked={twitterManualCookieEnabled} disabled={!authSettings?.twitter_x.manual_cookie_header_set && !twitterManualCookieHeaderInput.trim()} />
              <span>Use for Twitter/X fallback</span>
            </label>
            <div class="section-actions">
              <button class="secondary-button" type="button" disabled={twitterAuthBusy} on:click={() => saveTwitterManualCookieHeader(false)}>
                {twitterAuthBusy ? "Saving" : "Save Twitter/X header"}
              </button>
              <button class="small-button danger" type="button" disabled={twitterAuthBusy || !authSettings?.twitter_x.manual_cookie_header_set} on:click={resetAuthSettings}>
                Clear
              </button>
            </div>
            <div class="path-picker-row">
              <input bind:value={authSettingsExportPath} placeholder="C:/Backups/fetchdock-auth-settings.json" spellcheck="false" aria-label="Auth settings export path" />
              <button class="small-button" type="button" disabled={Boolean(authSettingsTransferBusy)} on:click={chooseAuthSettingsExportPath}>
                Choose export
              </button>
              <button class="small-button" type="button" disabled={Boolean(authSettingsTransferBusy)} on:click={exportAuthSettingsBackup}>
                {authSettingsTransferBusy === "export" ? "Exporting" : "Export safe JSON"}
              </button>
              <button class="small-button" type="button" disabled={!authSettingsExportPath.trim() && !authSettingsExportResult} on:click={() => openLocalPath(authSettingsExportResult?.output_path || authSettingsExportPath, "Auth settings backup")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!authSettingsExportPath.trim() && !authSettingsExportResult} on:click={() => revealLocalPath(authSettingsExportResult?.output_path || authSettingsExportPath, "Auth settings backup")}>
                Reveal
              </button>
            </div>
            <div class="path-picker-row">
              <input bind:value={authSettingsImportPath} placeholder="C:/Backups/fetchdock-auth-settings.json" spellcheck="false" aria-label="Auth settings import path" />
              <button class="small-button" type="button" disabled={Boolean(authSettingsTransferBusy)} on:click={chooseAuthSettingsImportFile}>
                Choose backup
              </button>
              <button class="small-button" type="button" disabled={Boolean(authSettingsTransferBusy) || !authSettingsImportPath.trim()} on:click={importAuthSettingsBackup}>
                {authSettingsTransferBusy === "import" ? "Importing" : "Import safe JSON"}
              </button>
              <button class="small-button" type="button" disabled={!authSettingsImportPath.trim()} on:click={() => openLocalPath(authSettingsImportPath, "Auth settings backup")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!authSettingsImportPath.trim()} on:click={() => revealLocalPath(authSettingsImportPath, "Auth settings backup")}>
                Reveal
              </button>
            </div>
            <small>{authSettingsExportResult ? `${authSettingsExportResult.exported_setting_count} public settings -> ${authSettingsExportResult.output_path}` : authSettingsImportResult ? `Imported ${authSettingsImportResult.imported_setting_count} public settings · ${authSettingsImportResult.skipped_secret_count} secret value${authSettingsImportResult.skipped_secret_count === 1 ? "" : "s"} skipped` : "Safe backup only; manual Cookie header values are never exported or restored from JSON."}</small>
            {#if authSettingsImportResult?.review_notes.length}
              <small>{authSettingsImportResult.review_notes.join(" ")}</small>
            {/if}
          </div>
          <div class="setting-row">
            <span>
              <strong>Match URL</strong>
              <small>Find local buckets whose cookie scope applies to a URL; best match appears first.</small>
            </span>
            <div class="setting-control wide-control">
              <input bind:value={cookieMatchUrl} placeholder="https://example.com/watch" spellcheck="false" aria-label="Cookie match URL" />
              <button class="secondary-button" type="button" disabled={cookieBucketsBusy} on:click={runCookieMatch}>Match</button>
            </div>
          </div>
          {#if cookieMatchedBuckets.length > 0}
            <div class="setting-row block-row">
              <span>
                <strong>Matching buckets</strong>
                <small>Select a matched bucket to use it on the next Home download task. Platform, path, domain specificity, and recency decide order.</small>
              </span>
              <div class="compact-list">
                {#each cookieMatchedBuckets as bucket}
                  <article class="compact-list-item">
                    <span>
                      <strong>{bucket.name}</strong>
                      <small>{bucket.platform ?? "generic"} · {bucket.health} · {cookieBucketScopeLabel(bucket)}</small>
                    </span>
                    <button class="small-button" type="button" on:click={() => useCookieBucketForHome(bucket)}>
                      Use on Home
                    </button>
                    <button class="small-button" type="button" on:click={() => useCookieBucketForTools(bucket)}>
                      Use on Tools
                    </button>
                  </article>
                {/each}
              </div>
            </div>
          {/if}
          <div class="setting-row">
            <span>
              <strong>Bulk clear</strong>
              <small>{cookieSelectedIds.length} selected bucket{cookieSelectedIds.length === 1 ? "" : "s"} · platform clear uses saved bucket metadata.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={cookieBucketsBusy || cookieSelectedIds.length === 0} on:click={requestClearSelectedCookies}>
                  Clear selected
                </button>
              </div>
              <div class="two-column-inputs">
                <select bind:value={cookieClearPlatform} aria-label="Cookie platform to clear">
