                  {#each cookiePlatformOptions as platform}
                    <option value={platform}>{platform}</option>
                  {/each}
                </select>
                <button class="small-button danger" type="button" disabled={cookieBucketsBusy || !cookieClearPlatform} on:click={requestClearCookiePlatform}>
                  Clear platform
                </button>
              </div>
            </div>
          </div>
          <div class="library-filter-row">
