            </button>
            <button class="small-button" type="button" disabled={selectedFilteredCookieCount === 0} on:click={clearFilteredCookieSelection}>
              Clear filtered selection
            </button>
            <button class="small-button" type="button" disabled={cookieTestBusy === "test-selected" || cookieSelectedIds.length === 0} on:click={() => runCookieHealthTests(cookieBuckets.filter((bucket) => cookieSelectedIds.includes(bucket.id)), "test-selected", "Selected cookies")}>
              {cookieTestBusy === "test-selected" ? "Testing" : "Test selected"}
            </button>
            <button class="small-button" type="button" disabled={cookieTestBusy === "test-filtered" || filteredCookieBuckets.length === 0} on:click={() => runCookieHealthTests(filteredCookieBuckets, "test-filtered", "Shown cookies")}>
              {cookieTestBusy === "test-filtered" ? "Testing" : "Test shown"}
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={copyFilteredCookieBucketSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={copyFilteredCookieBucketJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("id")}>
              Copy ids
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("name")}>
              Copy names
            </button>
            <button class="small-button" type="button" disabled={!filteredCookieBuckets.some((bucket) => bucket.platform)} on:click={() => copyFilteredCookieBucketFields("platform")}>
              Copy platforms
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("health")}>
              Copy health
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("count")}>
              Copy counts
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("storage")}>
              Copy storage
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("domain")}>
              Copy domains
            </button>
            <button class="small-button" type="button" disabled={!filteredCookieBuckets.some((bucket) => bucket.path_hints?.length)} on:click={() => copyFilteredCookieBucketFields("path")}>
              Copy paths
            </button>
            <button class="small-button" type="button" disabled={!filteredCookieBuckets.some((bucket) => bucket.expires_summary)} on:click={() => copyFilteredCookieBucketFields("expiry")}>
              Copy expiry
            </button>
            <button class="small-button" type="button" disabled={filteredCookieBuckets.length === 0} on:click={() => copyFilteredCookieBucketFields("scope")}>
              Copy scope
            </button>
          </div>
          <div class="cookie-bucket-list">
            {#if cookieBuckets.length === 0}
              <p class="muted">No cookie buckets yet.</p>
            {:else if filteredCookieBuckets.length === 0}
              <p class="muted">No cookie buckets match the current filters.</p>
            {:else}
              {#each filteredCookieBuckets as bucket}
                <article class="cookie-bucket-card">
                  <label class="inline-check">
                    <input
                      type="checkbox"
                      checked={cookieSelectedIds.includes(bucket.id)}
                      on:change={() => toggleCookieSelection(bucket.id)}
                      aria-label={`Select ${bucket.name}`}
                    />
                    <span>Select</span>
                  </label>
                  <div>
                    <strong>{bucket.name}</strong>
                    <small>{bucket.platform ?? "generic"} · {bucket.cookie_count} rows · {bucket.health} · {cookieBucketScopeLabel(bucket)}</small>
                    {#if bucket.last_tested_at}
                      <small>Last tested {new Date(bucket.last_tested_at).toLocaleString()}</small>
                    {/if}
                    <small>{bucket.storage_path}</small>
                  </div>
                  <div class="setting-control wide-control stacked-control">
                    <input bind:value={cookieRenameInputs[bucket.id]} aria-label={`Rename ${bucket.name}`} />
                    <input bind:value={cookieExportPathInputs[bucket.id]} aria-label={`Export path for ${bucket.name}`} />
                    <button class="small-button" type="button" on:click={() => chooseCookieExportPath(bucket)}>Choose export</button>
                    <div class="section-actions">
                      <button class="secondary-button" type="button" on:click={() => saveCookieBucketName(bucket)}>Rename</button>
                      <button class="secondary-button" type="button" on:click={() => exportCookie(bucket)}>Export</button>
                      <button class="small-button" type="button" on:click={() => openLocalPath(bucket.storage_path, `${bucket.name} storage`)}>
                        Open stored
                      </button>
                      <button class="small-button" type="button" on:click={() => revealLocalPath(bucket.storage_path, `${bucket.name} storage`)}>
                        Reveal stored
                      </button>
                      <button class="small-button" type="button" disabled={!cookieExportPathInputs[bucket.id]?.trim()} on:click={() => openLocalPath(cookieExportPathInputs[bucket.id], `${bucket.name} export`)}>
                        Open export
                      </button>
                      <button class="small-button" type="button" disabled={!cookieExportPathInputs[bucket.id]?.trim()} on:click={() => revealLocalPath(cookieExportPathInputs[bucket.id], `${bucket.name} export`)}>
                        Reveal export
                      </button>
                      <button class="secondary-button" type="button" disabled={cookieTestBusy === bucket.id} on:click={() => runCookieHealthTest(bucket)}>
                        {cookieTestBusy === bucket.id ? "Testing" : "Test"}
                      </button>
                      <button class="small-button danger" type="button" on:click={() => requestCookieDelete(bucket)}>Delete</button>
                    </div>
                  </div>
                </article>
              {/each}
            {/if}
          </div>
          {#if cookieBucketsError}
            <p class="error-text">{cookieBucketsError}</p>
          {/if}
          <div class="setting-row">
            <span>
              <strong>Bilibili account status</strong>
              <small>{bilibiliAccountStatus?.message ?? "Local Bilibili status has not been loaded yet."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <code>{bilibiliAccountStatus?.status ?? "unknown"}</code>
              <small>
                Bucket: {bilibiliAccountStatus?.cookie_bucket_name ?? "none"} · Health: {bilibiliAccountStatus?.cookie_health ?? "n/a"}
              </small>
              <small>
                Watch later {bilibiliAccountStatus?.imported_watch_later_count ?? 0} · History {bilibiliAccountStatus?.imported_history_count ?? 0}
              </small>
              <div class="section-actions">
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={loadBilibiliImports}>Refresh status</button>
                <button class="small-button" type="button" disabled={!bilibiliAccountStatus} on:click={copyBilibiliAccountStatusSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!bilibiliAccountStatus} on:click={copyBilibiliAccountStatusJson}>Copy JSON</button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Bilibili local summary</strong>
              <small>Metadata-only review of local Cookie bucket state, imported manifests, and linked transfer tasks.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions compact-actions">
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={loadBilibiliImports}>Refresh summary</button>
                <button class="small-button" type="button" disabled={!bilibiliLocalSummary} on:click={copyBilibiliLocalSummary}>Copy summary</button>
                <button class="small-button" type="button" disabled={!bilibiliLocalSummary} on:click={copyBilibiliLocalSummaryJson}>Copy JSON</button>
                <button class="small-button" type="button" disabled={(bilibiliLocalSummary?.collection_counts.length ?? 0) === 0} on:click={() => copyBilibiliLocalSummaryFields("collection")}>Copy collections</button>
                <button class="small-button" type="button" disabled={(bilibiliLocalSummary?.owner_counts.length ?? 0) === 0} on:click={() => copyBilibiliLocalSummaryFields("owner")}>Copy owners</button>
                <button class="small-button" type="button" disabled={(bilibiliLocalSummary?.transfer_status_counts.length ?? 0) === 0} on:click={() => copyBilibiliLocalSummaryFields("transfer-status")}>Copy transfers</button>
                <button class="small-button" type="button" disabled={(bilibiliLocalSummary?.review_notes.length ?? 0) === 0} on:click={() => copyBilibiliLocalSummaryFields("note")}>Copy notes</button>
              </div>
              {#if bilibiliLocalSummary}
                <div class="status-grid compact-status-grid">
                  <span><small>Imports</small><strong>{bilibiliLocalSummary.import_count}</strong></span>
                  <span><small>Watch later</small><strong>{bilibiliLocalSummary.watch_later_count}</strong></span>
                  <span><small>History</small><strong>{bilibiliLocalSummary.history_count}</strong></span>
                  <span><small>Queued</small><strong>{bilibiliLocalSummary.queued_import_count}</strong></span>
                  <span><small>Transfers</small><strong>{bilibiliLocalSummary.transfer_task_count}</strong></span>
                  <span><small>Duration</small><strong>{formatDuration(bilibiliLocalSummary.total_duration_seconds)}</strong></span>
                </div>
                <small>Status {bilibiliLocalSummary.account_status} · Cookie {bilibiliLocalSummary.cookie_bucket_set ? "configured" : "none"} · Last import {bilibiliLocalSummary.last_imported_at ?? "never"}</small>
                {#if bilibiliLocalSummary.collection_counts.length > 0}
                  <small>{bilibiliLocalSummary.collection_counts.map((entry) => `${entry.key} ${entry.count}`).join(" · ")}</small>
                {/if}
              {:else}
                <small>No local Bilibili summary loaded yet.</small>
              {/if}
              <div class="path-picker-row">
                <input bind:value={bilibiliSummaryExportPath} placeholder="C:/FetchDock/bilibili-summary.json" spellcheck="false" aria-label="Bilibili summary export path" />
                <button class="icon-button" type="button" title="Choose Bilibili summary export" disabled={Boolean(bilibiliBusy)} on:click={chooseBilibiliSummaryExportPath}>
                  <FolderOpen size={17} />
                </button>
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={exportBilibiliSummary}>{bilibiliBusy === "summary-export" ? "Exporting" : "Export JSON"}</button>
                <button class="small-button" type="button" disabled={!(bilibiliSummaryExportResult || bilibiliSummaryExportPath.trim())} on:click={() => openLocalPath(bilibiliSummaryExportResult || bilibiliSummaryExportPath, "Bilibili summary")}>Open file</button>
                <button class="small-button" type="button" disabled={!(bilibiliSummaryExportResult || bilibiliSummaryExportPath.trim())} on:click={() => revealLocalPath(bilibiliSummaryExportResult || bilibiliSummaryExportPath, "Bilibili summary")}>Reveal</button>
              </div>
              {#if bilibiliSummaryExportResult}
                <small>Last export: {bilibiliSummaryExportResult}</small>
              {/if}
            </div>
          </div>
          <div class="setting-row">
