              <div class="two-column-inputs">
                <input bind:value={bilibiliManifestPath} placeholder="C:/Exports/bilibili.json" spellcheck="false" aria-label="Bilibili manifest path" />
                <select bind:value={bilibiliCollection} aria-label="Bilibili collection">
                  <option value="watch_later">Watch later</option>
                  <option value="history">History</option>
                  <option value="manifest">Keep manifest collections</option>
                </select>
              </div>
              <div class="path-picker-row">
                <input bind:value={bilibiliManifestExportPath} placeholder="Optional export path" spellcheck="false" aria-label="Bilibili export path" />
