                </button>
                <button class="small-button" type="button" disabled={!bilibiliManifestExportResult && !bilibiliManifestExportPath.trim()} on:click={revealBilibiliManifestExportResult}>
                  Reveal export
                </button>
              </div>
              {#if bilibiliManifestExportResult}
                <small>{bilibiliManifestExportResult.exported_count} item{bilibiliManifestExportResult.exported_count === 1 ? "" : "s"} exported · {bilibiliManifestExportResult.collection} · {bilibiliManifestExportResult.output_path}</small>
              {/if}
              <div class="section-actions">
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={chooseBilibiliManifestFile}>
                  Choose file
                </button>
                <button class="secondary-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={importBilibiliLocalManifest}>Import Bilibili</button>
                <button class="secondary-button" type="button" disabled={Boolean(bilibiliBusy) || visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={exportVisibleBilibiliImports}>
                  {bilibiliBusy === "export" ? "Exporting" : "Export shown"}
                </button>
                <button class="small-button" type="button" disabled={!bilibiliManifestPath.trim()} on:click={() => openLocalPath(bilibiliManifestPath, "Bilibili manifest")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!bilibiliManifestPath.trim()} on:click={() => revealLocalPath(bilibiliManifestPath, "Bilibili manifest")}>
                  Reveal
                </button>
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy)} on:click={loadBilibiliImports}>Refresh</button>
                <button class="small-button" type="button" disabled={Boolean(bilibiliBusy) || filteredBilibiliImportedItems.length === 0} on:click={queueVisibleBilibiliItems}>
                  {bilibiliBusy === "queue-visible" ? "Queueing" : "Queue filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(bilibiliBusy) || filteredBilibiliImportedItems.length === 0} on:click={requestFilteredBilibiliImportsDelete}>
                  {bilibiliBusy === "delete-filtered" ? "Removing" : "Remove filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(bilibiliBusy) || bilibiliImportedItems.length === 0} on:click={() => requestBilibiliImportsClear(bilibiliImportCollectionFilter === "all" ? "all" : (bilibiliImportCollectionFilter as "watch_later" | "history"))}>
                  Clear {bilibiliImportCollectionFilter === "all" ? "imports" : bilibiliImportCollectionFilter.replace("_", " ")}
                </button>
              </div>
            </div>
          </div>
          {#if bilibiliError}
            <p class="error-text">{bilibiliError}</p>
          {/if}
          {#if bilibiliImportedItems.length > 0}
            <div class="library-filter-row">
              <input
                bind:value={bilibiliImportSearch}
                placeholder="Search Bilibili imports"
                spellcheck="false"
                aria-label="Bilibili import search"
              />
              <select bind:value={bilibiliImportCollectionFilter} aria-label="Bilibili import collection filter">
                <option value="all">All collections</option>
                <option value="watch_later">Watch later</option>
                <option value="history">History</option>
              </select>
              <span class="filter-count-label">{visibleBilibiliImportedItems(filteredBilibiliImportedItems).length} shown of {bilibiliImportedItems.length} imported item{bilibiliImportedItems.length === 1 ? "" : "s"}</span>
            </div>
            <div class="section-actions compact-actions">
              <button class="small-button" type="button" on:click={() => setBilibiliImportQuickCollection("all")}>
                All
              </button>
              <button class="small-button" type="button" on:click={() => setBilibiliImportQuickCollection("watch_later")}>
                Watch later
              </button>
              <button class="small-button" type="button" on:click={() => setBilibiliImportQuickCollection("history")}>
                History
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={copyVisibleBilibiliImportSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={copyVisibleBilibiliImportJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={() => copyVisibleBilibiliImportFields("source")}>
                Copy URLs
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={() => copyVisibleBilibiliImportFields("id")}>
                Copy ids
              </button>
              <button class="small-button" type="button" disabled={!visibleBilibiliImportedItems(filteredBilibiliImportedItems).some((item) => item.created_task_id)} on:click={() => copyVisibleBilibiliImportFields("task")}>
                Copy task ids
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={() => copyVisibleBilibiliImportFields("title")}>
                Copy titles
              </button>
              <button class="small-button" type="button" disabled={!visibleBilibiliImportedItems(filteredBilibiliImportedItems).some((item) => item.owner)} on:click={() => copyVisibleBilibiliImportFields("owner")}>
                Copy owners
              </button>
              <button class="small-button" type="button" disabled={!visibleBilibiliImportedItems(filteredBilibiliImportedItems).some((item) => item.duration_seconds)} on:click={() => copyVisibleBilibiliImportFields("duration")}>
                Copy durations
              </button>
              <button class="small-button" type="button" disabled={visibleBilibiliImportedItems(filteredBilibiliImportedItems).length === 0} on:click={() => copyVisibleBilibiliImportFields("collection")}>
                Copy collections
              </button>
              <button class="small-button" type="button" disabled={!visibleBilibiliImportedItems(filteredBilibiliImportedItems).some((item) => item.added_at)} on:click={() => copyVisibleBilibiliImportFields("added")}>
                Copy added times
              </button>
            </div>
            <div class="cookie-bucket-list">
              {#if filteredBilibiliImportedItems.length === 0}
                <p class="muted">No Bilibili imports match the current filters.</p>
              {:else}
                {#if filteredBilibiliImportedItems.length > 12 && !bilibiliImportSearch.trim() && bilibiliImportCollectionFilter === "all"}
                  <div class="course-list-toolbar compact-toolbar">
                    <small>{filteredBilibiliImportedItems.length} matching Bilibili item{filteredBilibiliImportedItems.length === 1 ? "" : "s"}</small>
                    <button class="small-button" type="button" on:click={() => (bilibiliImportsExpanded = !bilibiliImportsExpanded)}>
                      {bilibiliImportsExpanded ? "Collapse imports" : "Show all imports"}
                    </button>
                  </div>
                {/if}
                {#each visibleBilibiliImportedItems(filteredBilibiliImportedItems) as item}
                  <article class="cookie-bucket-card">
                    <div>
                      <strong>{item.title}</strong>
                      <small>{item.collection}{item.owner ? ` · ${item.owner}` : ""}{item.duration_seconds ? ` · ${formatDuration(item.duration_seconds)}` : ""}</small>
                      <small>{item.source_url}</small>
                      {#if item.created_task_id}
                        <small>Created task {item.created_task_id}</small>
                      {/if}
                    </div>
                    <div class="section-actions">
                      <button class="small-button" type="button" on:click={() => openSourceUrl(item.source_url, item.title)}>
                        Open source
                      </button>
                      {#if item.created_task_id}
                        {@const createdTaskId = item.created_task_id}
                        <button class="small-button" type="button" on:click={() => focusDownloadTaskById(createdTaskId, item.title)}>
                          Task
                        </button>
                      {/if}
                      <button class="secondary-button" type="button" disabled={bilibiliBusy === item.id} on:click={() => queueBilibiliItem(item)}>
                        {bilibiliBusy === item.id ? "Queueing" : "Queue"}
                      </button>
                      <button class="small-button danger" type="button" disabled={Boolean(bilibiliBusy)} on:click={() => requestBilibiliImportedItemDelete(item)}>
                        Remove
                      </button>
                    </div>
                  </article>
                {/each}
              {/if}
            </div>
          {/if}
          <div class="setting-row">
            <span>
              <strong>Bilibili transfers</strong>
              <small>Local task controls for imports that have already created download tasks.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="library-filter-row transfer-filter-row">
                <label>
                  <span>Search</span>
                  <input bind:value={bilibiliTransferSearch} placeholder="Title, URL, platform, output path, or error" spellcheck="false" aria-label="Bilibili transfer search" />
                </label>
                <label>
                  <span>Status</span>
                  <select bind:value={bilibiliTransferStatusFilter} aria-label="Bilibili transfer status filter">
                    <option value="all">All status</option>
                    <option value="queued">Queued</option>
                    <option value="active">Active</option>
                    <option value="paused">Paused</option>
                    <option value="completed">Completed</option>
                    <option value="failed">Failed</option>
                    <option value="canceled">Canceled</option>
                    <option value="archived">Archived</option>
                  </select>
                </label>
              </div>
              {#if bilibiliTransferTasks.length === 0}
                <p class="muted">Queue a Bilibili import to show its linked local download task here.</p>
              {:else if filteredBilibiliTransferTasks.length === 0}
                <p class="muted">No Bilibili transfers match the current filters.</p>
              {:else}
                <div class="course-list-toolbar">
                  <small class="format-hint">
                    {visibleBilibiliTransferTasks(filteredBilibiliTransferTasks).length} shown of {bilibiliTransferTasks.length} local Bilibili transfer task{bilibiliTransferTasks.length === 1 ? "" : "s"}.
                  </small>
                  <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskSummary(visibleBilibiliTransferTasks(filteredBilibiliTransferTasks), "Bilibili transfer")}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskJson(visibleBilibiliTransferTasks(filteredBilibiliTransferTasks), "Bilibili transfer", { search: bilibiliTransferSearch, status: bilibiliTransferStatusFilter })}>
                    Copy JSON
                  </button>
                  <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleBilibiliTransferTasks(filteredBilibiliTransferTasks), "source", "Bilibili transfer")}>
                    Copy sources
                  </button>
                  <button class="small-button" type="button" on:click={() => copyVisibleTransferTaskFields(visibleBilibiliTransferTasks(filteredBilibiliTransferTasks), "output", "Bilibili transfer")}>
                    Copy outputs
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferStartableTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("start", visibleBilibiliTransferStartableTasks, "Bilibili transfers")}
                  >
                    Start shown
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferActiveTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("pause", visibleBilibiliTransferActiveTasks, "Bilibili transfers")}
                  >
                    Pause shown
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferPausedTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("resume", visibleBilibiliTransferPausedTasks, "Bilibili transfers")}
                  >
                    Resume shown
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferFailedTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("retry", visibleBilibiliTransferFailedTasks, "Bilibili transfers")}
                  >
                    Retry shown
                  </button>
                  <button
                    class="small-button danger"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferCancelableTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("cancel", visibleBilibiliTransferCancelableTasks, "Bilibili transfers")}
                  >
                    Cancel shown
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferArchivableTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("archive", visibleBilibiliTransferArchivableTasks, "Bilibili transfers")}
                  >
                    Archive shown
                  </button>
                  <button
                    class="small-button"
                    type="button"
                    disabled={downloadBulkBusy !== "" || visibleBilibiliTransferRestorableTasks.length === 0}
                    on:click={() => runDownloadTaskBatchAction("restore", visibleBilibiliTransferRestorableTasks, "Bilibili transfers")}
                  >
                    Restore shown
                  </button>
                  {#if filteredBilibiliTransferTasks.length > 10 && !bilibiliTransferSearch.trim() && bilibiliTransferStatusFilter === "all"}
                    <button class="small-button" type="button" on:click={() => (bilibiliTransfersExpanded = !bilibiliTransfersExpanded)}>
                      {bilibiliTransfersExpanded ? "Collapse transfers" : "Show all transfers"}
                    </button>
                  {/if}
                </div>
                <div class="telegram-media-list transfer-task-list">
                  {#each visibleBilibiliTransferTasks(filteredBilibiliTransferTasks) as task}
                    <div>
                      <span>
                        <strong>{task.title}</strong>
                        <small>{task.status} · {formatProgress(task)}</small>
                        <small>{task.platform} · {task.source_url}</small>
                        {#if task.output_path}
                          <small>Saved to {task.output_path}</small>
                        {:else if task.output_dir}
                          <small>Output folder {task.output_dir}</small>
                        {/if}
                        {#if task.last_error}
                          <small class="error-text">{task.last_error}</small>
                        {/if}
                      </span>
                      <div class="section-actions">
                        <button class="small-button" type="button" disabled={!canStartTask(task) || activeTaskIds.has(task.id)} on:click={() => startTask(task)}>
                          Start
                        </button>
                        <button class="small-button" type="button" disabled={task.status !== "active"} on:click={() => pauseTask(task)}>
                          Pause
                        </button>
                        <button class="small-button" type="button" disabled={task.status !== "paused"} on:click={() => resumeTask(task)}>
                          Resume
                        </button>
                        <button class="small-button" type="button" disabled={task.status !== "failed" && task.status !== "canceled"} on:click={() => retryTask(task)}>
                          Retry
                        </button>
                        <button class="small-button" type="button" disabled={task.status === "canceled" || task.status === "completed" || task.status === "archived"} on:click={() => cancelTask(task)}>
                          Cancel
                        </button>
                        <button class="small-button" type="button" disabled={!task.output_path} on:click={() => revealTaskFile(task)}>
                          Reveal
                        </button>
                        <button class="small-button" type="button" disabled={!task.output_dir && !task.output_path} on:click={() => openTaskFolder(task)}>
                          Open
                        </button>
                        <button class="small-button" type="button" on:click={() => openSourceUrl(task.source_url, task.title)}>
                          Source
                        </button>
                        <button class="small-button" type="button" on:click={() => focusDownloadTaskById(task.id, task.title)}>
                          Detail
                        </button>
                        <button class="small-button" type="button" on:click={() => loadTaskLogs(task)}>
                          Logs
                        </button>
                        {#if task.status === "archived"}
                          <button class="small-button" type="button" on:click={() => restoreTask(task)}>Restore</button>
                        {:else if ["completed", "failed", "canceled"].includes(task.status)}
                          <button class="small-button" type="button" on:click={() => archiveTask(task)}>Archive</button>
                        {/if}
                      </div>
                    </div>
                  {/each}
                </div>
              {/if}
            </div>
          </div>
        </div>

        <div
          id="settings-extension"
          class:settings-highlight={activeSettingsSectionId === "extension"}
          class="panel"
        >
          <h2>Browser Extension</h2>
          <div class="setting-row">
            <span>
              <strong>Local bridge</strong>
              <small>Extension requests are accepted on loopback only.</small>
            </span>
            <div class="setting-control wide-control">
              <code>http://127.0.0.1:17654</code>
              <div class="section-actions">
                <button class="small-button" type="button" on:click={() => copyExtensionOptionFields("bridge")}>
                  Copy bridge
                </button>
                <button class="small-button" type="button" on:click={() => copyExtensionOptionFields("port")}>
                  Copy ports
                </button>
                <button class="small-button" type="button" on:click={() => copyExtensionOptionFields("endpoint")}>
                  Copy endpoints
                </button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Unpacked extension folder</strong>
              <small>{extensionPackageSummary ? `${extensionPackageSummary.source_file_count} source files · ${formatBytes(extensionPackageSummary.source_total_size_bytes)}` : "Load this folder in Chrome or Firefox developer mode for the current scaffold."}</small>
            </span>
            <div class="setting-control wide-control">
              <code>{extensionPackageSummary?.extension_dir ?? "browser-extension"}</code>
              <div class="section-actions">
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={() => openLocalPath(extensionPackageSummary?.extension_dir, "Browser extension folder")}>
                  Open folder
                </button>
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={() => revealLocalPath(extensionPackageSummary?.manifest_path, "Browser extension manifest")}>
                  Reveal manifest
                </button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Extension local summary</strong>
              <small>
                {extensionLocalSummary
                  ? `${extensionLocalSummary.package.source_file_count} source files · ${extensionLocalSummary.cookie_payload_count + extensionLocalSummary.authorization_payload_count} staged payloads · gate ${extensionLocalSummary.release_safety.release_gate_status}`
                  : "Aggregate extension options, pairing, staged payload inventory, package metadata, and release-safety metadata."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionSummaryBusy} on:click={() => refreshExtensionLocalSummary()}>
                  {extensionSummaryBusy ? "Refreshing" : "Refresh summary"}
                </button>
                <button class="small-button" type="button" disabled={!extensionLocalSummary} on:click={copyExtensionLocalSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={!extensionLocalSummary} on:click={copyExtensionLocalSummaryJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!extensionLocalSummary} on:click={() => copyExtensionLocalSummaryFields("options")}>
                  Copy options
                </button>
                <button class="small-button" type="button" disabled={!extensionLocalSummary} on:click={() => copyExtensionLocalSummaryFields("pairing")}>
                  Copy pairing
                </button>
                <button class="small-button" type="button" disabled={(extensionLocalSummary?.cookie_payload_count ?? 0) + (extensionLocalSummary?.authorization_payload_count ?? 0) === 0} on:click={() => copyExtensionLocalSummaryFields("payload")}>
                  Copy payloads
                </button>
                <button class="small-button" type="button" disabled={!extensionLocalSummary} on:click={() => copyExtensionLocalSummaryFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={(extensionLocalSummary?.review_notes.length ?? 0) === 0} on:click={() => copyExtensionLocalSummaryFields("note")}>
                  Copy notes
                </button>
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={handleExportExtensionLocalSummary}>
                  Export summary
                </button>
              </div>
              <div class="inline-field">
                <input bind:value={extensionSummaryExportPath} placeholder="C:/path/extension-local-summary.json" spellcheck="false" aria-label="Extension local summary export path" />
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseExtensionSummaryExportPath}>
                  Save as
                </button>
                <button class="small-button" type="button" disabled={!extensionSummaryExportPath.trim()} on:click={() => openLocalPath(extensionSummaryExportPath, "Extension local summary")}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!extensionSummaryExportPath.trim()} on:click={() => revealLocalPath(extensionSummaryExportPath, "Extension local summary")}>
                  Reveal export
                </button>
              </div>
              {#if extensionLocalSummary}
                <div class="metric-grid compact-metrics">
                  <div>
                    <strong>{extensionLocalSummary.package.source_file_count}</strong>
                    <small>source files</small>
                  </div>
                  <div>
                    <strong>{extensionLocalSummary.package.package_targets.length}</strong>
                    <small>targets</small>
                  </div>
                  <div>
                    <strong>{extensionLocalSummary.pairing.paired ? "paired" : "unpaired"}</strong>
                    <small>pairing</small>
                  </div>
                  <div>
                    <strong>{extensionLocalSummary.options.blocked_hosts.length}</strong>
                    <small>blocked hosts</small>
                  </div>
                  <div>
                    <strong>{extensionLocalSummary.cookie_payload_count}</strong>
                    <small>Cookie payloads</small>
                  </div>
                  <div>
                    <strong>{extensionLocalSummary.authorization_payload_count}</strong>
                    <small>Auth payloads</small>
                  </div>
                </div>
                <small>bridge {extensionLocalSummary.options.bridge_url} · discovery ports {extensionLocalSummary.options.bridge_discovery_ports.length} · media {extensionLocalSummary.options.capture_media ? "on" : "off"} · headers {extensionLocalSummary.options.capture_headers ? "on" : "off"}</small>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Extension capability catalog</strong>
              <small>
                {extensionCapabilityCatalog
                  ? `${extensionCapabilityCatalog.capability_count} capabilities · ${extensionCapabilityCatalog.bridge_endpoints.length} bridge endpoints · gate ${extensionCapabilityCatalog.release_gate_status}`
                  : "Review bridge, pairing, options, media sniffer, payload staging, package review, and release-safety capability boundaries."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionSummaryBusy} on:click={refreshExtensionCapabilityCatalog}>
                  {extensionSummaryBusy ? "Refreshing" : "Refresh catalog"}
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={copyExtensionCapabilityCatalogSummary}>
                  Copy catalog
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={copyExtensionCapabilityCatalogJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={() => copyExtensionCapabilityCatalogFields("capability")}>
                  Copy capabilities
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={() => copyExtensionCapabilityCatalogFields("command")}>
                  Copy commands
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={() => copyExtensionCapabilityCatalogFields("endpoint")}>
                  Copy endpoints
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalog} on:click={() => copyExtensionCapabilityCatalogFields("limit")}>
                  Copy limits
                </button>
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={handleExportExtensionCapabilityCatalog}>
                  Export catalog
                </button>
              </div>
              <div class="inline-field">
                <input bind:value={extensionCapabilityCatalogExportPath} placeholder="C:/path/extension-capability-catalog.json" spellcheck="false" aria-label="Extension capability catalog export path" />
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalogExportResult && !extensionCapabilityCatalogExportPath.trim()} on:click={() => openLocalPath(extensionCapabilityCatalogExportResult || extensionCapabilityCatalogExportPath, "Extension capability catalog")}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!extensionCapabilityCatalogExportResult && !extensionCapabilityCatalogExportPath.trim()} on:click={() => revealLocalPath(extensionCapabilityCatalogExportResult || extensionCapabilityCatalogExportPath, "Extension capability catalog")}>
                  Reveal export
                </button>
              </div>
              {#if extensionCapabilityCatalog}
                <div class="metric-grid compact-metrics">
                  <div>
                    <strong>{extensionCapabilityCatalog.capability_count}</strong>
                    <small>capabilities</small>
                  </div>
                  <div>
                    <strong>{extensionCapabilityCatalog.bridge_endpoints.length}</strong>
                    <small>endpoints</small>
                  </div>
                  <div>
                    <strong>{extensionCapabilityCatalog.extension_surfaces.length}</strong>
                    <small>surfaces</small>
                  </div>
                  <div>
                    <strong>{extensionCapabilityCatalog.verifies_browser_e2e ? "verified" : "pending"}</strong>
                    <small>browser E2E</small>
                  </div>
                </div>
                <small>payloads {extensionCapabilityCatalog.supported_payload_kinds.join(", ") || "none"} · browser storage {extensionCapabilityCatalog.includes_browser_storage ? "included" : "excluded"} · token values {extensionCapabilityCatalog.includes_pairing_token_values ? "included" : "excluded"}</small>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Extension package review</strong>
              <small>
                {extensionPackageSummary
                  ? `${extensionPackageSummary.extension_name ?? "Extension"} ${extensionPackageSummary.extension_version ?? ""} · ${extensionPackageSummary.package_targets.length} package target${extensionPackageSummary.package_targets.length === 1 ? "" : "s"}`
                  : "Review local extension source and generated package manifest metadata without reading browser data."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionPackageBusy} on:click={refreshExtensionPackageSummary}>
                  {extensionPackageBusy ? "Refreshing" : "Refresh package"}
                </button>
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={copyExtensionPackageSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={copyExtensionPackageJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={(extensionPackageSummary?.source_files.length ?? 0) === 0} on:click={() => copyExtensionPackageFields("source-file")}>
                  Copy files
                </button>
                <button class="small-button" type="button" disabled={(extensionPackageSummary?.source_files.length ?? 0) === 0} on:click={() => copyExtensionPackageFields("source-sha")}>
                  Copy hashes
                </button>
                <button class="small-button" type="button" disabled={(extensionPackageSummary?.package_targets.length ?? 0) === 0} on:click={() => copyExtensionPackageFields("target")}>
                  Copy targets
                </button>
                <button class="small-button" type="button" disabled={(extensionPackageSummary?.review_notes.length ?? 0) === 0} on:click={() => copyExtensionPackageFields("review-note")}>
                  Copy notes
                </button>
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={handleExportExtensionPackageSummary}>
                  Export package
                </button>
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={() => openLocalPath(extensionPackageSummary?.package_manifest_path, "Browser extension package manifest")}>
                  Open manifest
                </button>
                <button class="small-button" type="button" disabled={!extensionPackageSummary} on:click={() => revealLocalPath(extensionPackageSummary?.package_manifest_path, "Browser extension package manifest")}>
                  Reveal package
                </button>
              </div>
              <div class="inline-field">
                <input bind:value={extensionPackageSummaryExportPath} placeholder="C:/path/extension-package-summary.json" spellcheck="false" aria-label="Extension package summary export path" />
