                      <article>
                        <div>
                          <strong>{target.target}</strong>
                          <small>{target.zip_path ?? "zip path missing"} · {target.file_count} files · {formatBytes(target.total_size_bytes)}</small>
                          <small>{target.zip_sha256 ?? "SHA-256 missing"}</small>
                        </div>
                        <span class="task-chip">package</span>
                      </article>
                    {/each}
                  </div>
                {/if}
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Release-safety evidence</strong>
              <small>
                {extensionReleaseSafetySummary
                  ? `gate ${extensionReleaseSafetySummary.release_gate_status} · ${extensionReleaseSafetySummary.package_target_count} package targets · ${extensionReleaseSafetySummary.staged_cookie_payload_count + extensionReleaseSafetySummary.staged_authorization_payload_count} staged payloads`
                  : "Review extension package, pairing, options, blocked hosts, and staged payload metadata without exposing secrets."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="small-button" type="button" disabled={!extensionReleaseSafetySummary} on:click={copyExtensionReleaseSafetySummary}>
