                </button>
                <button class="small-button" type="button" disabled={!extensionReleaseSafetySummary} on:click={copyExtensionReleaseSafetyJson}>
                  Copy safety JSON
                </button>
                <button class="small-button" type="button" disabled={(extensionReleaseSafetySummary?.review_notes.length ?? 0) === 0} on:click={copyExtensionReleaseSafetyNotes}>
                  Copy safety notes
                </button>
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={handleExportExtensionReleaseSafetySummary}>
                  Export safety
                </button>
              </div>
              <div class="inline-field">
                <input bind:value={extensionReleaseSafetyExportPath} placeholder="C:/path/extension-release-safety.json" spellcheck="false" aria-label="Extension release-safety export path" />
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseExtensionReleaseSafetyExportPath}>
                  Save as
                </button>
                <button class="small-button" type="button" disabled={!extensionReleaseSafetyExportPath.trim()} on:click={() => openLocalPath(extensionReleaseSafetyExportPath, "Extension release-safety summary")}>
                  Open export
                </button>
                <button class="small-button" type="button" disabled={!extensionReleaseSafetyExportPath.trim()} on:click={() => revealLocalPath(extensionReleaseSafetyExportPath, "Extension release-safety summary")}>
                  Reveal export
                </button>
              </div>
              {#if extensionReleaseSafetySummary}
                <div class="metric-grid compact-metrics">
                  <div>
                    <strong>{extensionReleaseSafetySummary.release_gate_status}</strong>
                    <small>release gate</small>
                  </div>
                  <div>
                    <strong>{extensionReleaseSafetySummary.package_manifest_present ? "present" : "missing"}</strong>
                    <small>package manifest</small>
                  </div>
                  <div>
                    <strong>{extensionReleaseSafetySummary.paired ? "paired" : "unpaired"}</strong>
                    <small>pairing</small>
                  </div>
                  <div>
                    <strong>{extensionReleaseSafetySummary.blocked_host_count}</strong>
                    <small>blocked hosts</small>
                  </div>
                  <div>
                    <strong>{extensionReleaseSafetySummary.staged_cookie_payload_count}</strong>
                    <small>Cookie payloads</small>
                  </div>
                  <div>
                    <strong>{extensionReleaseSafetySummary.staged_authorization_payload_count}</strong>
                    <small>Auth payloads</small>
