            <div class="setting-control wide-control">
              <code>GET /health · POST /pair/start · POST /pair/complete · POST /v1/extension/download · POST /download/page · POST /download/media · POST /download/batch · POST /v1/extension/cookies · POST /cookies/import · POST /v1/extension/authorization</code>
            </div>
          </div>
