                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={copyFilteredExtensionAuthorizationPayloadSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={copyFilteredExtensionAuthorizationPayloadJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("ref")}>
                  Copy refs
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("host")}>
                  Copy hosts
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("name")}>
                  Copy names
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("size")}>
                  Copy sizes
                </button>
                <button class="small-button" type="button" disabled={!filteredExtensionAuthPayloads.some((payload) => payload.file.modified_at)} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("modified")}>
