                </button>
                <button class="small-button" type="button" disabled={filteredExtensionAuthPayloads.length === 0} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("page")}>
                  Copy page URLs
                </button>
                <button class="small-button" type="button" disabled={!filteredExtensionAuthPayloads.some((payload) => payload.request_url)} on:click={() => copyFilteredExtensionAuthorizationPayloadFields("request")}>
