                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionAuthPayloadBusy) || filteredExtensionAuthPayloads.length === 0} on:click={requestFilteredExtensionAuthorizationPayloadsRemove}>
                  {extensionAuthPayloadBusy === "remove-filtered" ? "Removing" : "Remove filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionAuthPayloadBusy) || extensionAuthPayloads.length === 0} on:click={requestClearExtensionAuthorizationPayloads}>
                  Clear payloads
                </button>
              </div>
              <div class="library-filter-row">
                <input
                  bind:value={extensionAuthPayloadSearch}
                  placeholder="Search hosts, URLs, payload ids"
                  spellcheck="false"
                  aria-label="Extension authorization payload search"
                />
