              {:else}
                <div class="compact-list">
                  {#each filteredExtensionAuthPayloads as payload}
                    <article class="compact-list-item">
                      <span>
                        <strong>{payload.request_host ?? payload.host}</strong>
                        <small>{payload.preview} · {payload.captured_at ?? payload.stored_at ?? "time unknown"}</small>
                        <small>Page {payload.page_url}</small>
                        {#if payload.request_url}
                          <small>Request {payload.request_url}</small>
                        {/if}
                        <code>{payload.payload_ref}</code>
                        <code>{payload.file.path}</code>
                        {#if taskAuthPayloadRef === payload.payload_ref}
                          <small>Selected for the next Home task.</small>
                        {/if}
                      </span>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionAuthPayloadBusy === payload.payload_ref}
