                        Use on Tools
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={!payload.page_url}
                        on:click={() => openSourceUrl(payload.page_url, `${payload.payload_ref} page`)}
                      >
                        Open page
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={!payload.request_url}
                        on:click={() => openSourceUrl(payload.request_url ?? "", `${payload.payload_ref} request`)}
                      >
                        Open request
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionAuthPayloadBusy === payload.payload_ref}
                        on:click={() => openLocalPath(payload.file.path, payload.file.file_name)}
                      >
                        Open file
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionAuthPayloadBusy === payload.payload_ref}
                        on:click={() => revealLocalPath(payload.file.path, payload.file.file_name)}
                      >
                        Reveal
                      </button>
                      <button
                        class="small-button danger"
                        type="button"
                        disabled={Boolean(extensionAuthPayloadBusy)}
                        on:click={() => removeExtensionAuthorizationPayload(payload.payload_ref)}
                      >
                        Delete
                      </button>
                    </article>
                  {/each}
                </div>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Cookie payloads</strong>
              <small>{extensionCookiePayloads.length} staged Cookie header payload{extensionCookiePayloads.length === 1 ? "" : "s"} waiting for import into Cookie buckets.</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionCookiePayloadBusy === "refresh"} on:click={refreshExtensionCookiePayloads}>
                  {extensionCookiePayloadBusy === "refresh" ? "Refreshing" : "Refresh payloads"}
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={copyFilteredExtensionCookiePayloadSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={copyFilteredExtensionCookiePayloadJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("ref")}>
                  Copy refs
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("name")}>
                  Copy names
                </button>
                <button class="small-button" type="button" disabled={filteredExtensionCookiePayloads.length === 0} on:click={() => copyFilteredExtensionCookiePayloadFields("size")}>
                  Copy sizes
                </button>
                <button class="small-button" type="button" disabled={!filteredExtensionCookiePayloads.some((payload) => payload.file.modified_at)} on:click={() => copyFilteredExtensionCookiePayloadFields("modified")}>
                  Copy modified
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionCookiePayloadBusy) || cookieBucketsBusy || filteredExtensionCookiePayloads.length === 0} on:click={importFilteredExtensionCookiePayloads}>
                  {extensionCookiePayloadBusy === "import-filtered" ? "Importing" : "Import filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionCookiePayloadBusy) || filteredExtensionCookiePayloads.length === 0} on:click={requestFilteredExtensionCookiePayloadsRemove}>
                  {extensionCookiePayloadBusy === "remove-filtered" ? "Removing" : "Remove filtered"}
                </button>
                <button class="small-button danger" type="button" disabled={Boolean(extensionCookiePayloadBusy) || extensionCookiePayloads.length === 0} on:click={requestClearExtensionCookiePayloads}>
                  Clear payloads
                </button>
              </div>
              <small>Import creates managed Cookie bucket copies and keeps staged payload files for review.</small>
              <div class="library-filter-row">
                <input bind:value={extensionCookiePayloadSearch} placeholder="Search payload ids, file names, paths" spellcheck="false" aria-label="Extension cookie payload search" />
                <span class="filter-count-label">{filteredExtensionCookiePayloads.length} shown of {extensionCookiePayloads.length} staged payload{extensionCookiePayloads.length === 1 ? "" : "s"}</span>
              </div>
              {#if extensionCookiePayloads.length === 0}
                <small>No cookie payloads have been staged yet.</small>
              {:else if filteredExtensionCookiePayloads.length === 0}
                <small>No cookie payloads match the current search.</small>
              {:else}
                <div class="compact-list">
                  {#each filteredExtensionCookiePayloads as payload}
                    <article class="compact-list-item">
                      <span>
                        <strong>{payload.payload_ref}</strong>
                        <small>{payload.file.file_name} · {formatBytes(payload.file.size_bytes)} · {payload.file.modified_at ?? "modified time unknown"}</small>
                        <code>{payload.file.path}</code>
                        {#if cookieExtensionPayloadRef === payload.payload_ref}
                          <small>Selected for Cookie import.</small>
                        {/if}
                      </span>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionCookiePayloadBusy === payload.payload_ref}
                        on:click={() => useExtensionCookiePayload(payload)}
                      >
                        Use
                      </button>
                      <button
                        class="secondary-button"
                        type="button"
                        disabled={Boolean(extensionCookiePayloadBusy) || cookieBucketsBusy}
                        on:click={() => importExtensionCookiePayload(payload)}
                      >
                        {extensionCookiePayloadBusy === payload.payload_ref ? "Importing" : "Import"}
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionCookiePayloadBusy === payload.payload_ref}
                        on:click={() => openLocalPath(payload.file.path, payload.file.file_name)}
                      >
                        Open file
                      </button>
                      <button
                        class="small-button"
                        type="button"
                        disabled={extensionCookiePayloadBusy === payload.payload_ref}
                        on:click={() => revealLocalPath(payload.file.path, payload.file.file_name)}
                      >
                        Reveal
                      </button>
                      <button
                        class="small-button danger"
                        type="button"
                        disabled={Boolean(extensionCookiePayloadBusy)}
                        on:click={() => removeExtensionCookiePayload(payload.payload_ref)}
                      >
                        Delete
                      </button>
                    </article>
                  {/each}
                </div>
              {/if}
            </div>
