            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={extensionPairingLabel} placeholder="Browser label" spellcheck="false" aria-label="Extension pairing label" />
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionPairingBusy} on:click={createExtensionToken}>
                  {extensionPairingBusy ? "Working" : "Create token"}
                </button>
                <button class="small-button" type="button" disabled={extensionPairingBusy} on:click={copyExtensionConnectorProfile}>
                  Copy profile
                </button>
                <button class="small-button" type="button" disabled={extensionPairingBusy} on:click={() => copyExtensionOptionFields("pairing")}>
                  Copy status
                </button>
                <button class="small-button danger" type="button" disabled={extensionPairingBusy || !extensionPairingStatus?.token_required} on:click={revokeExtensionToken}>
                  Revoke
                </button>
                <button class="small-button" type="button" disabled={extensionPairingBusy} on:click={loadExtensionPairingStatus}>Refresh status</button>
              </div>
              {#if extensionPairingToken}
                <code>{extensionPairingToken.pairing_code}</code>
              {/if}
              <div class="path-picker-row">
                <input bind:value={extensionPairingExportPath} placeholder="C:/Backups/fetchdock-extension-pairing.json" spellcheck="false" aria-label="Extension pairing metadata export path" />
                <button class="small-button" type="button" disabled={Boolean(extensionPairingTransferBusy)} on:click={chooseExtensionPairingExportPath}>
                  Choose export
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionPairingTransferBusy)} on:click={exportExtensionPairingBackup}>
                  {extensionPairingTransferBusy === "export" ? "Exporting" : "Export metadata"}
                </button>
                <button class="small-button" type="button" disabled={!extensionPairingExportPath.trim() && !extensionPairingExportResult} on:click={() => openLocalPath(extensionPairingExportResult?.output_path || extensionPairingExportPath, "Extension pairing backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!extensionPairingExportPath.trim() && !extensionPairingExportResult} on:click={() => revealLocalPath(extensionPairingExportResult?.output_path || extensionPairingExportPath, "Extension pairing backup")}>
                  Reveal
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={extensionPairingImportPath} placeholder="C:/Backups/fetchdock-extension-pairing.json" spellcheck="false" aria-label="Extension pairing metadata import path" />
                <button class="small-button" type="button" disabled={Boolean(extensionPairingTransferBusy)} on:click={chooseExtensionPairingImportFile}>
                  Choose backup
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionPairingTransferBusy) || !extensionPairingImportPath.trim()} on:click={importExtensionPairingBackup}>
                  {extensionPairingTransferBusy === "import" ? "Importing" : "Import metadata"}
                </button>
                <button class="small-button" type="button" disabled={!extensionPairingImportPath.trim()} on:click={() => openLocalPath(extensionPairingImportPath, "Extension pairing backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!extensionPairingImportPath.trim()} on:click={() => revealLocalPath(extensionPairingImportPath, "Extension pairing backup")}>
                  Reveal
                </button>
              </div>
              <small>{extensionPairingExportResult ? `Metadata exported -> ${extensionPairingExportResult.output_path}` : extensionPairingImportResult ? `Imported metadata from ${extensionPairingImportResult.input_path}; token values were not restored.` : "Pairing metadata backup excludes token values; imported paired backups return to unpaired until a new token is created."}</small>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Extension options</strong>
              <small>{extensionOptions ? `Saved ${extensionOptions.updated_at}` : "Persist local extension-side defaults."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <input bind:value={extensionBridgeUrlInput} placeholder="http://127.0.0.1:17654" spellcheck="false" aria-label="Extension bridge URL" />
              <input bind:value={extensionBridgeDiscoveryPortsInput} placeholder="17654,17655,17656" spellcheck="false" aria-label="Extension bridge discovery ports" />
              <input bind:value={extensionTokenInput} placeholder={extensionOptions?.token_set ? "Token already saved" : "Pairing token, optional"} spellcheck="false" aria-label="Extension pairing token" />
              <label class="inline-check">
                <input type="checkbox" bind:checked={extensionDeepLinkFallbackInput} />
                <span>Deep link fallback</span>
              </label>
              <label class="inline-check">
                <input type="checkbox" bind:checked={extensionCaptureMediaInput} />
                <span>Capture media candidates</span>
              </label>
              <label class="inline-check">
                <input type="checkbox" bind:checked={extensionCaptureHeadersInput} />
                <span>Capture Referer/User-Agent and secret-header presence</span>
              </label>
              <textarea bind:value={extensionBlockedHostsInput} placeholder="example.com&#10;media.example.net" spellcheck="false" aria-label="Extension blocked hosts"></textarea>
              <small>{normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput).length} discovery port{normalizeExtensionBridgeDiscoveryPorts(extensionBridgeDiscoveryPortsInput).length === 1 ? "" : "s"}; comma or newline separated.</small>
              <small>{parseExtensionBlockedHosts(extensionBlockedHostsInput).length} blocked host{parseExtensionBlockedHosts(extensionBlockedHostsInput).length === 1 ? "" : "s"}; paste newline, comma-separated, or exported JSON host lists.</small>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={extensionOptionsBusy} on:click={saveExtensionOptionsState}>
                  {extensionOptionsBusy ? "Saving" : "Save options"}
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy} on:click={reloadExtensionOptions}>
                  Reload options
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy} on:click={() => refreshExtensionConnectorProfile()}>
                  Preview profile
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy} on:click={() => copyExtensionOptionFields("summary")}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy} on:click={copyExtensionOptionsJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy || parseExtensionBlockedHosts(extensionBlockedHostsInput).length === 0} on:click={() => copyExtensionOptionFields("blocked")}>
                  Copy blocked
                </button>
                <button class="small-button" type="button" disabled={extensionOptionsBusy} on:click={resetExtensionSettings}>
                  Reset
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={extensionOptionsExportPath} placeholder="C:/Backups/fetchdock-extension-options.json" spellcheck="false" aria-label="Extension options export path" />
                <button class="small-button" type="button" disabled={Boolean(extensionOptionsTransferBusy)} on:click={chooseExtensionOptionsExportPath}>
                  Choose export
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionOptionsTransferBusy)} on:click={exportExtensionOptionsBackup}>
                  {extensionOptionsTransferBusy === "export" ? "Exporting" : "Export JSON"}
                </button>
                <button class="small-button" type="button" disabled={!extensionOptionsExportPath.trim() && !extensionOptionsExportResult} on:click={() => openLocalPath(extensionOptionsExportResult?.output_path || extensionOptionsExportPath, "Extension options backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!extensionOptionsExportPath.trim() && !extensionOptionsExportResult} on:click={() => revealLocalPath(extensionOptionsExportResult?.output_path || extensionOptionsExportPath, "Extension options backup")}>
                  Reveal
                </button>
              </div>
              <div class="path-picker-row">
                <input bind:value={extensionOptionsImportPath} placeholder="C:/Backups/fetchdock-extension-options.json" spellcheck="false" aria-label="Extension options import path" />
                <button class="small-button" type="button" disabled={Boolean(extensionOptionsTransferBusy)} on:click={chooseExtensionOptionsImportFile}>
                  Choose backup
                </button>
                <button class="small-button" type="button" disabled={Boolean(extensionOptionsTransferBusy) || !extensionOptionsImportPath.trim()} on:click={importExtensionOptionsBackup}>
                  {extensionOptionsTransferBusy === "import" ? "Importing" : "Import JSON"}
                </button>
                <button class="small-button" type="button" disabled={!extensionOptionsImportPath.trim()} on:click={() => openLocalPath(extensionOptionsImportPath, "Extension options backup")}>
                  Open
                </button>
                <button class="small-button" type="button" disabled={!extensionOptionsImportPath.trim()} on:click={() => revealLocalPath(extensionOptionsImportPath, "Extension options backup")}>
                  Reveal
                </button>
              </div>
              <small>{extensionOptionsExportResult ? `${extensionOptionsExportResult.exported_setting_count} settings -> ${extensionOptionsExportResult.output_path}` : extensionOptionsImportResult ? `Imported ${extensionOptionsImportResult.imported_setting_count} settings from ${extensionOptionsImportResult.input_path}` : "Local options backup only; pairing token values, staged payload contents, browser storage, and downloads stay outside this JSON."}</small>
              {#if extensionConnectorProfileJson}
                <textarea readonly bind:value={extensionConnectorProfileJson} aria-label="Extension connector profile JSON"></textarea>
                <small>Import this JSON in the extension options page. It never includes staged Cookie or Authorization payload contents.</small>
              {/if}
            </div>
          </div>
