            </button>
            <button class="small-button" type="button" on:click={copyChannelSettingsJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" on:click={() => copyChannelSettingsFields("counts")}>
              Copy counts
            </button>
            <button class="small-button" type="button" on:click={() => copyChannelSettingsFields("polling")}>
