              <small>{channelSettingsExportResult ? `${channelSettingsExportResult.exported_setting_count} settings -> ${channelSettingsExportResult.output_path}` : channelSettingsImportResult ? `Imported ${channelSettingsImportResult.imported_setting_count} settings from ${channelSettingsImportResult.input_path}` : "Moves local polling preferences only."}</small>
            </div>
            <div class="path-picker-row">
              <input bind:value={channelSettingsExportPath} placeholder="C:/Backups/fetchdock-channel-settings.json" spellcheck="false" aria-label="Channel settings export path" />
