              <button class="small-button" type="button" disabled={!channelSettingsExportPath.trim() && !channelSettingsExportResult} on:click={() => openLocalPath(channelSettingsExportResult?.output_path || channelSettingsExportPath, "Channel settings backup")}>
                Open
              </button>
              <button class="small-button" type="button" disabled={!channelSettingsExportPath.trim() && !channelSettingsExportResult} on:click={() => revealLocalPath(channelSettingsExportResult?.output_path || channelSettingsExportPath, "Channel settings backup")}>
                Reveal
              </button>
            </div>
            <div class="path-picker-row">
              <input bind:value={channelSettingsImportPath} placeholder="C:/Backups/fetchdock-channel-settings.json" spellcheck="false" aria-label="Channel settings import path" />
              <button class="small-button" type="button" disabled={Boolean(channelSettingsTransferBusy)} on:click={chooseChannelSettingsImportFile}>
                Choose backup
              </button>
              <button class="small-button" type="button" disabled={Boolean(channelSettingsTransferBusy) || !channelSettingsImportPath.trim()} on:click={importChannelSettingsBackup}>
                {channelSettingsTransferBusy === "import" ? "Importing" : "Import settings"}
              </button>
              <button class="small-button" type="button" disabled={!channelSettingsImportPath.trim()} on:click={() => openLocalPath(channelSettingsImportPath, "Channel settings backup")}>
                Open input
              </button>
              <button class="small-button" type="button" disabled={!channelSettingsImportPath.trim()} on:click={() => revealLocalPath(channelSettingsImportPath, "Channel settings backup")}>
                Reveal input
              </button>
            </div>
            <small>Backup excludes subscriptions, channel history, source URLs, Cookie values, downloaded files, and created download tasks; import does not poll channels or start downloads.</small>
          </div>
          <div class="setting-row">
            <span>
              <strong>Tracked subscriptions</strong>
              <small>{channels.length} local channel{channels.length === 1 ? "" : "s"} · {channelHistory.length} history item{channelHistory.length === 1 ? "" : "s"}</small>
            </span>
            <div class="section-actions">
              <button class="secondary-button" type="button" disabled={channelsBusy} on:click={loadChannels}>Refresh</button>
              <button class="secondary-button" type="button" on:click={() => navigate("channels")}>Open channels</button>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Auto-download subset</strong>
              <small>Manual checks can create queued video tasks when a subscription has auto-download enabled.</small>
            </span>
            <code>{channels.filter((channel) => channel.auto_download).length} enabled</code>
          </div>
          <div class="setting-row">
            <span>
              <strong>Polling</strong>
              <small>{channelSettings?.last_poll_finished_at ? `Last poll ${channelSettings.last_poll_finished_at}` : "No automatic poll recorded."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <label class="inline-check">
                <input type="checkbox" bind:checked={channelPollEnabledInput} />
                <span>Enable local polling</span>
              </label>
              <input bind:value={channelPollIntervalInput} inputmode="numeric" aria-label="Settings channel polling interval minutes" />
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={channelSettingsBusy} on:click={saveChannelPollingSettings}>
                  {channelSettingsBusy ? "Saving" : "Save polling"}
                </button>
                <button class="secondary-button" type="button" disabled={channelSettingsBusy} on:click={runDueChannelPoll}>
                  {channelSettingsBusy ? "Checking" : "Poll due"}
                </button>
                <button class="small-button" type="button" disabled={channelSettingsBusy} on:click={resetChannelSettings}>
                  Reset
                </button>
              </div>
              {#if channelAutoPollSummary}
                <small>{channelAutoPollSummary}</small>
              {/if}
            </div>
          </div>
          {#if channelsError}
            <p class="error-text">{channelsError}</p>
          {/if}
        </div>

        <div
          id="settings-plugins"
          class:settings-highlight={activeSettingsSectionId === "plugins"}
          class="panel"
        >
          <h2>Plugins</h2>
          <div class="section-actions compact-actions">
            <button class="small-button" type="button" on:click={copyPluginSettingsSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" on:click={copyPluginSettingsJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" on:click={() => copyPluginSettingsFields("counts")}>
              Copy counts
            </button>
            <button class="small-button" type="button" on:click={() => copyPluginSettingsFields("states")}>
              Copy states
            </button>
            <button class="small-button" type="button" on:click={() => copyPluginSettingsFields("filters")}>
              Copy filters
            </button>
            <button class="small-button" type="button" disabled={!status?.paths.plugins_dir} on:click={() => copyPluginSettingsFields("path")}>
              Copy path
            </button>
            <button class="small-button" type="button" disabled={!pluginCapabilityCatalog} on:click={copyPluginCapabilityCatalogSummary}>
              Copy catalog
            </button>
            <button class="small-button" type="button" disabled={!pluginCapabilityCatalog} on:click={copyPluginCapabilityCatalogJson}>
              Copy catalog JSON
            </button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Local registry</strong>
              <small>{plugins.length} installed manifest entr{plugins.length === 1 ? "y" : "ies"}; capability gate {pluginCapabilityCatalog?.parity_gate_status ?? "pending"}; dynamic loading remains disabled in this subset.</small>
            </span>
