              <button class="secondary-button" type="button" disabled={Boolean(pluginActionBusy)} on:click={handleExportPluginCapabilityCatalog}>Export catalog</button>
              <button class="secondary-button" type="button" on:click={() => navigate("plugins")}>Open plugins</button>
            </div>
