            <button class="small-button" type="button" disabled={aiSettings === null} on:click={copyAiSettingsJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={aiSettings === null} on:click={() => copyAiSettingsFields("provider")}>
              Copy provider
            </button>
            <button class="small-button" type="button" disabled={aiSettings === null} on:click={() => copyAiSettingsFields("whisper")}>
              Copy Whisper
            </button>
            <button class="small-button" type="button" disabled={aiSettings === null} on:click={() => copyAiSettingsFields("flags")}>
              Copy flags
            </button>
          </div>
          <div class="setting-row">
            <span>
              <strong>Local provider scope</strong>
