              <button class="small-button" type="button" disabled={!aiLocalSummary} on:click={copyAiLocalSummaryJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!aiLocalSummary} on:click={() => copyAiLocalSummaryFields("provider")}>
                Copy provider
              </button>
              <button class="small-button" type="button" disabled={!aiLocalSummary} on:click={() => copyAiLocalSummaryFields("whisper")}>
                Copy Whisper
              </button>
              <button class="small-button" type="button" disabled={!aiLocalSummary} on:click={() => copyAiLocalSummaryFields("flags")}>
                Copy flags
              </button>
              <button class="small-button" type="button" disabled={!aiLocalSummary} on:click={() => copyAiLocalSummaryFields("privacy")}>
