                    <strong>{aiLocalSummary.local_provider_enabled ? "on" : "off"}</strong>
                  </span>
                  <span>
                    <small>Cloud</small>
                    <strong>{aiLocalSummary.cloud_provider_enabled ? "on" : "off"}</strong>
                  </span>
                  <span>
                    <small>API key</small>
                    <strong>{aiLocalSummary.api_key_configured ? "set" : "none"}</strong>
                  </span>
                  <span>
                    <small>Whisper</small>
                    <strong>{aiLocalSummary.whisper_configured ? "ready" : "missing"}</strong>
                  </span>
