                </button>
                <button class="small-button" type="button" disabled={!aiCapabilityCatalog} on:click={() => copyAiCapabilityCatalogFields("capability")}>
                  Copy capabilities
                </button>
                <button class="small-button" type="button" disabled={!aiCapabilityCatalog} on:click={() => copyAiCapabilityCatalogFields("command")}>
                  Copy commands
                </button>
                <button class="small-button" type="button" disabled={!aiCapabilityCatalog} on:click={() => copyAiCapabilityCatalogFields("surface")}>
                  Copy surfaces
                </button>
                <button class="small-button" type="button" disabled={!aiCapabilityCatalog} on:click={() => copyAiCapabilityCatalogFields("limit")}>
                  Copy limits
                </button>
              </div>
