                  : "URL inclusion default is not loaded."}
              </small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <label class="inline-check">
                <input type="checkbox" bind:checked={diagnosticsIncludeUrls} />
                <span>Include download URLs in diagnostics by default</span>
              </label>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={Boolean(advancedSettingsBusy)} on:click={saveAdvancedSettings}>
