              <strong>Advanced settings backup</strong>
              <small>{advancedSettingsExportPath || advancedSettingsImportPath || "Exports only the diagnostics URL-inclusion default."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-input-row">
                <input bind:value={advancedSettingsExportPath} placeholder="C:/path/fetchdock-advanced-settings.json" spellcheck="false" aria-label="Advanced settings export path" />
                <button class="small-button" type="button" disabled={Boolean(advancedSettingsBusy)} on:click={chooseAdvancedSettingsExportPath}>
                  Save as
                </button>
                <button class="secondary-button compact-button" type="button" disabled={Boolean(advancedSettingsBusy)} on:click={exportAdvancedSettingsBackup}>
