                </button>
                <button class="small-button" type="button" disabled={!advancedSettingsExportPath.trim() && !advancedSettingsExportResult} on:click={revealAdvancedSettingsExportResult}>
                  Reveal
                </button>
              </div>
              <div class="path-input-row">
