            Copy i18n
          </button>
          <button class="small-button" type="button" disabled={!filteredPlugins.some((plugin) => plugin.installed_at)} on:click={() => copyFilteredPluginFields("installed")}>
            Copy installed
          </button>
          <button class="small-button" type="button" disabled={!filteredPlugins.some((plugin) => plugin.updated_at)} on:click={() => copyFilteredPluginFields("updated")}>
            Copy updated
          </button>
          <button class="small-button" type="button" disabled={!filteredPlugins.some((plugin) => plugin.last_error)} on:click={() => copyFilteredPluginFields("error")}>
            Copy errors
          </button>
        </div>
        {#if pluginMarketplaceEntries.length > 0}
          <div class="library-filter-row plugin-filter-row">
            <label>
              <span>Marketplace</span>
              <input bind:value={pluginMarketplaceSearch} placeholder="Entry name, id, source, hash, signature, capability, permission, manifest" spellcheck="false" aria-label="Plugin marketplace search" />
            </label>
            <span class="filter-count-label">{filteredPluginMarketplaceEntries.length} shown of {pluginMarketplaceEntries.length} imported entr{pluginMarketplaceEntries.length === 1 ? "y" : "ies"}</span>
            <button class="small-button" type="button" disabled={visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length === 0} on:click={copyVisiblePluginMarketplaceSummary}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length === 0} on:click={copyVisiblePluginMarketplaceJson}>
              Copy JSON
            </button>
            <button class="small-button" type="button" disabled={visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length === 0} on:click={() => copyVisiblePluginMarketplaceFields("manifest")}>
              Copy manifests
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.source)} on:click={() => copyVisiblePluginMarketplaceFields("source")}>
              Copy sources
            </button>
            <button class="small-button" type="button" disabled={visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length === 0} on:click={() => copyVisiblePluginMarketplaceFields("id")}>
              Copy ids
            </button>
            <button class="small-button" type="button" disabled={visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length === 0} on:click={() => copyVisiblePluginMarketplaceFields("name")}>
              Copy names
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.version)} on:click={() => copyVisiblePluginMarketplaceFields("version")}>
              Copy versions
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.sha256)} on:click={() => copyVisiblePluginMarketplaceFields("sha256")}>
              Copy SHA-256
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.signature)} on:click={() => copyVisiblePluginMarketplaceFields("signature")}>
              Copy signatures
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.signature_url)} on:click={() => copyVisiblePluginMarketplaceFields("signature-url")}>
              Copy signature URLs
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.capabilities.length > 0)} on:click={() => copyVisiblePluginMarketplaceFields("capability")}>
              Copy capabilities
            </button>
            <button class="small-button" type="button" disabled={!visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).some((entry) => entry.permissions.length > 0)} on:click={() => copyVisiblePluginMarketplaceFields("permission")}>
              Copy permissions
            </button>
            <button class="small-button danger" type="button" disabled={Boolean(pluginActionBusy) || filteredPluginMarketplaceEntries.length === 0} on:click={requestFilteredPluginMarketplaceEntriesDelete}>
              {pluginActionBusy === "marketplace-delete-filtered" ? "Removing" : "Remove filtered"}
            </button>
          </div>
          {#if filteredPluginMarketplaceEntries.length === 0}
            <p class="muted">No marketplace entries match the current search.</p>
          {:else}
            {#if filteredPluginMarketplaceEntries.length > 8 && !pluginMarketplaceSearch.trim()}
              <div class="course-list-toolbar compact-toolbar">
                <small>{visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries).length} shown of {filteredPluginMarketplaceEntries.length} marketplace entr{filteredPluginMarketplaceEntries.length === 1 ? "y" : "ies"}</small>
                <button class="small-button" type="button" on:click={() => (pluginMarketplaceExpanded = !pluginMarketplaceExpanded)}>
                  {pluginMarketplaceExpanded ? "Collapse entries" : "Show all entries"}
                </button>
              </div>
            {/if}
            <div class="plugin-list marketplace-list">
              {#each visiblePluginMarketplaceEntries(filteredPluginMarketplaceEntries) as entry}
                <article class="plugin-card">
                  <div>
                    <strong>{entry.name}</strong>
                    <small>{entry.id}{entry.version ? ` · ${entry.version}` : ""}</small>
                    {#if entry.description}
                      <small>{entry.description}</small>
                    {/if}
                    {#if entry.sha256}
                      <small>SHA-256: {entry.sha256}</small>
                    {/if}
                    {#if entry.signature}
                      <small>Signature: {entry.signature}</small>
                    {/if}
                    {#if entry.signature_url}
                      <small>Signature URL: {entry.signature_url}</small>
                    {/if}
                    {#if entry.capabilities.length > 0}
                      <small>Capabilities: {entry.capabilities.join(", ")}</small>
                    {/if}
                    {#if entry.permissions.length > 0}
                      <small>Permissions: {entry.permissions.join(", ")}</small>
                    {/if}
                    <small>{entry.manifest_path}</small>
                  </div>
                  <div class="section-actions">
                    <button class="secondary-button" type="button" disabled={pluginActionBusy === `marketplace:${entry.id}`} on:click={() => installMarketplacePlugin(entry)}>
                      {pluginActionBusy === `marketplace:${entry.id}` ? "Installing" : "Install"}
                    </button>
                    <button class="small-button" type="button" on:click={() => openPluginPath(entry.manifest_path, entry.name)}>
                      Open manifest
                    </button>
                    <button class="small-button" type="button" on:click={() => revealPluginPath(entry.manifest_path, entry.name)}>
                      Reveal manifest
                    </button>
                    {#if entry.source}
                      <button class="small-button" type="button" on:click={() => openSourceUrl(entry.source ?? "", entry.name)}>
                        Open source
                      </button>
                    {/if}
                    <button class="small-button danger" type="button" disabled={Boolean(pluginActionBusy)} on:click={() => requestPluginMarketplaceEntryDelete(entry)}>
                      Remove
                    </button>
                  </div>
                </article>
              {/each}
            </div>
          {/if}
        {/if}
        <div class="library-filter-row plugin-filter-row">
          <label>
            <span>Logs</span>
            <input bind:value={pluginLogSearch} placeholder="Command, event, status, payload, or time" spellcheck="false" aria-label="Plugin log search" />
          </label>
          <span class="filter-count-label">Filters command and event logs after you refresh them.</span>
          <button class="small-button danger" type="button" disabled={Boolean(pluginCommandLogBusy) || filteredPlugins.length === 0} on:click={requestClearFilteredPluginCommandLogs}>
            {pluginCommandLogBusy === "clear-filtered" ? "Clearing" : "Clear shown commands"}
          </button>
          <button class="small-button danger" type="button" disabled={Boolean(pluginActivityBusy) || filteredPlugins.length === 0} on:click={requestClearFilteredPluginActivity}>
            {pluginActivityBusy === "clear-filtered" ? "Clearing" : "Clear shown activity"}
          </button>
          <button class="small-button danger" type="button" disabled={Boolean(pluginEventLogBusy) || filteredPlugins.length === 0} on:click={requestClearFilteredPluginEvents}>
            {pluginEventLogBusy === "clear-filtered" ? "Clearing" : "Clear shown events"}
          </button>
        </div>
        <div class="plugin-list">
          {#if plugins.length === 0}
            <div class="empty-state compact-empty">
              <ShieldCheck size={34} />
              <h2>No local plugins installed</h2>
              <p>Install a FetchDock plugin manifest to register it without loading executable code yet.</p>
            </div>
          {:else if filteredPlugins.length === 0}
            <p class="muted">No installed plugins match the current filters.</p>
          {:else}
            <small class="format-hint">{filteredPlugins.length} shown of {plugins.length} installed plugin{plugins.length === 1 ? "" : "s"}.</small>
            {#each filteredPlugins as plugin}
              <article class="plugin-card">
                <div>
                  <strong>{plugin.display_name}</strong>
                  <small>{plugin.id} · {plugin.version} · ABI {plugin.abi_version}</small>
                  <small>Host ABI {plugin.host_abi_version} · {plugin.preflight_status}</small>
                  <small>{plugin.preflight_message}</small>
                  {#if plugin.dynamic_library_path}
                    <small>Library: {plugin.dynamic_library_path}</small>
                  {/if}
                  {#if plugin.entrypoint}
                    <small>Entrypoint: {plugin.entrypoint}</small>
                  {/if}
                  <small>{plugin.manifest_path}</small>
                  {#if plugin.capabilities.length > 0}
                    <small>Capabilities: {plugin.capabilities.join(", ")}</small>
                  {/if}
                  {#if plugin.permissions.length > 0}
                    <small>Permissions: {plugin.permissions.join(", ")}</small>
                  {/if}
                  {#if plugin.commands.length > 0}
                    <small>Commands: {plugin.commands.join(", ")}</small>
                  {/if}
                  {#if plugin.events.length > 0}
                    <small>Events: {plugin.events.map((event) => event.name).join(", ")}</small>
                  {/if}
                  {#if plugin.nav_items.length > 0}
                    <small>Navigation: {plugin.nav_items.map((item) => item.label).join(", ")}</small>
                  {/if}
                  {#if pluginI18nSummary(plugin)}
                    <small>I18n: {pluginI18nSummary(plugin)}</small>
                  {/if}
                  {#if plugin.last_error}
                    <small class="error-text">{plugin.last_error}</small>
                  {/if}
                  <small>{marketplaceVersionLabel(plugin)}</small>
                </div>
                <div class="plugin-actions">
                  <span class={`plugin-state ${plugin.state}`}>{plugin.state}</span>
                  {#if marketplaceEntryForPlugin(plugin)}
                    <button class="small-button" type="button" disabled={pluginActionBusy === `update:${plugin.id}`} on:click={() => updateMarketplacePlugin(plugin)}>
                      {pluginActionBusy === `update:${plugin.id}` ? "Updating" : "Update"}
                    </button>
                  {/if}
                  <button class="secondary-button" type="button" disabled={pluginActionBusy === plugin.id} on:click={() => togglePlugin(plugin)}>
                    {plugin.state === "enabled" ? "Disable" : "Enable"}
                  </button>
                  <button class="small-button" type="button" disabled={pluginActionBusy === `check:${plugin.id}`} on:click={() => checkInstalledPluginHost(plugin)}>
                    {pluginActionBusy === `check:${plugin.id}` ? "Checking" : "Check host"}
                  </button>
                  <button class="small-button" type="button" disabled={pluginSettingsBusy === plugin.id} on:click={() => loadPluginSettings(plugin)}>
                    Settings
                  </button>
                  <button class="small-button" type="button" disabled={pluginDataDirBusy === plugin.id} on:click={() => openPluginDataDirectory(plugin)}>
                    {pluginDataDirBusy === plugin.id ? "Opening" : "Open data"}
                  </button>
                  <button class="small-button" type="button" on:click={() => openPluginPath(plugin.manifest_path, plugin.display_name)}>
                    Open manifest
                  </button>
                  <button class="small-button" type="button" on:click={() => revealPluginPath(plugin.manifest_path, plugin.display_name)}>
                    Reveal manifest
                  </button>
                  {#if plugin.dynamic_library_path}
                    <button class="small-button" type="button" on:click={() => revealPluginPath(plugin.dynamic_library_path, `${plugin.display_name} library`)}>
                      Reveal library
                    </button>
                  {/if}
                  <button class="small-button danger" type="button" disabled={pluginActionBusy === plugin.id} on:click={() => requestPluginUninstall(plugin)}>
                    Uninstall
                  </button>
                </div>
                {#if plugin.commands.length > 0}
                  <div class="plugin-command-panel">
                    <select bind:value={pluginCommandInputs[plugin.id]} aria-label={`Command for ${plugin.display_name}`}>
                      {#each plugin.commands as command}
                        <option value={command}>{command}</option>
                      {/each}
                    </select>
                    <textarea
                      bind:value={pluginCommandPayloadInputs[plugin.id]}
                      spellcheck="false"
                      aria-label={`Command payload for ${plugin.display_name}`}
                    ></textarea>
                    <button
                      class="secondary-button compact-button"
                      type="button"
                      disabled={pluginCommandBusy === plugin.id || plugin.state !== "enabled"}
                      on:click={() => runManifestPluginCommand(plugin)}
                    >
                      {pluginCommandBusy === plugin.id ? "Queueing" : "Run command"}
                    </button>
                    <button
                      class="small-button"
                      type="button"
                      disabled={pluginCommandLogBusy === plugin.id}
                      on:click={() => refreshPluginCommandLogs(plugin)}
                    >
                      {pluginCommandLogBusy === plugin.id ? "Refreshing" : "Refresh commands"}
                    </button>
                    <button class="small-button" type="button" on:click={() => formatPluginCommandPayload(plugin.id)}>
                      Format JSON
                    </button>
                    <button class="small-button" type="button" disabled={!pluginCommandLogs[plugin.id]?.commands.length} on:click={() => reusePluginCommandPayload(plugin)}>
                      Reuse latest
                    </button>
                    <button class="small-button" type="button" disabled={!pluginCommandLogs[plugin.id]?.commands.length} on:click={() => copyPluginCommandLogSummary(plugin)}>
                      Copy summary
                    </button>
                    <button class="small-button" type="button" disabled={!pluginCommandLogs[plugin.id]?.commands.length} on:click={() => copyPluginCommandLogJson(plugin)}>
                      Copy JSON
                    </button>
                    <button class="small-button danger" type="button" disabled={pluginCommandLogBusy === plugin.id || !pluginCommandLogs[plugin.id]?.commands.length} on:click={() => requestClearPluginCommandLogs(plugin)}>
                      Clear commands
                    </button>
                  </div>
                  {#if pluginCommandLogs[plugin.id]}
                    <div class="plugin-event-log">
                      <div>
                        <strong>Recent command calls</strong>
                        <small>{pluginCommandLogs[plugin.id].log_path}</small>
                      </div>
                      {#if filterPluginCommandLogEntries(pluginCommandLogs[plugin.id].commands, pluginLogSearch).length === 0}
                        <small>No command calls yet.</small>
                      {:else}
                        <div class="compact-list">
                          {#each filterPluginCommandLogEntries(pluginCommandLogs[plugin.id].commands, pluginLogSearch) as entry}
                            <article class="compact-list-item">
                              <span>
                                <strong>{entry.command}</strong>
                                <small>{entry.status} · {entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                                <code>{JSON.stringify(entry.payload)}</code>
                              </span>
                            </article>
                          {/each}
                        </div>
                      {/if}
                    </div>
                  {/if}
                {/if}
                <div class="plugin-command-panel">
                  <button
                    class="small-button"
                    type="button"
                    disabled={pluginActivityBusy === plugin.id}
                    on:click={() => refreshPluginActivity(plugin)}
                  >
                    {pluginActivityBusy === plugin.id ? "Refreshing" : "Refresh activity"}
                  </button>
                  <button class="small-button danger" type="button" disabled={pluginActivityBusy === plugin.id || !pluginActivityLogs[plugin.id]?.activities.length} on:click={() => requestClearPluginActivity(plugin)}>
                    Clear activity
                  </button>
                  <button class="small-button" type="button" disabled={!pluginActivityLogs[plugin.id]?.activities.length} on:click={() => copyPluginActivityLogSummary(plugin)}>
                    Copy summary
                  </button>
                  <button class="small-button" type="button" disabled={!pluginActivityLogs[plugin.id]?.activities.length} on:click={() => copyPluginActivityLogJson(plugin)}>
                    Copy JSON
                  </button>
                </div>
                {#if pluginActivityLogs[plugin.id]}
                  <div class="plugin-event-log">
                    <div>
                      <strong>Recent activity</strong>
                      <small>{pluginActivityLogs[plugin.id].log_path}</small>
                    </div>
                    {#if filterPluginActivityEntries(pluginActivityLogs[plugin.id].activities, pluginLogSearch).length === 0}
                      <small>No plugin activity matches the current filter.</small>
                    {:else}
                      <div class="compact-list">
                        {#each filterPluginActivityEntries(pluginActivityLogs[plugin.id].activities, pluginLogSearch) as entry}
                          <article class="compact-list-item">
                            <span>
                              <strong>{entry.message}</strong>
                              <small>{entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                            </span>
                          </article>
                        {/each}
                      </div>
                    {/if}
                  </div>
                {/if}
                {#if plugin.events.length > 0}
                  <div class="plugin-command-panel">
                    <select bind:value={pluginEventInputs[plugin.id]} aria-label={`Event for ${plugin.display_name}`}>
                      {#each plugin.events as event}
                        <option value={event.name}>{event.name}</option>
                      {/each}
                    </select>
                    <textarea
                      bind:value={pluginEventPayloadInputs[plugin.id]}
                      spellcheck="false"
                      aria-label={`Event payload for ${plugin.display_name}`}
                    ></textarea>
                    <button
                      class="secondary-button compact-button"
                      type="button"
                      disabled={pluginEventBusy === plugin.id || plugin.state !== "enabled"}
                      on:click={() => emitManifestPluginEvent(plugin)}
                    >
                      {pluginEventBusy === plugin.id ? "Recording" : "Record event"}
                    </button>
                    <button
                      class="small-button"
                      type="button"
                      disabled={pluginEventLogBusy === plugin.id}
                      on:click={() => refreshPluginEvents(plugin)}
                    >
                      {pluginEventLogBusy === plugin.id ? "Refreshing" : "Refresh events"}
                    </button>
                    <button class="small-button" type="button" on:click={() => formatPluginEventPayload(plugin.id)}>
                      Format JSON
                    </button>
                    <button class="small-button" type="button" disabled={!pluginEventLogs[plugin.id]?.events.length} on:click={() => reusePluginEventPayload(plugin)}>
                      Reuse latest
                    </button>
                    <button class="small-button" type="button" disabled={!pluginEventLogs[plugin.id]?.events.length} on:click={() => copyPluginEventLogSummary(plugin)}>
                      Copy summary
                    </button>
                    <button class="small-button" type="button" disabled={!pluginEventLogs[plugin.id]?.events.length} on:click={() => copyPluginEventLogJson(plugin)}>
                      Copy JSON
                    </button>
                    <button class="small-button danger" type="button" disabled={pluginEventLogBusy === plugin.id || !pluginEventLogs[plugin.id]?.events.length} on:click={() => requestClearPluginEvents(plugin)}>
                      Clear events
                    </button>
                  </div>
                  {#if pluginEventLogs[plugin.id]}
                    <div class="plugin-event-log">
                      <div>
                        <strong>Recent events</strong>
                        <small>{pluginEventLogs[plugin.id].log_path}</small>
                      </div>
                      {#if filterPluginEventLogEntries(pluginEventLogs[plugin.id].events, pluginLogSearch).length === 0}
                        <small>No recorded events yet.</small>
                      {:else}
                        <div class="compact-list">
                          {#each filterPluginEventLogEntries(pluginEventLogs[plugin.id].events, pluginLogSearch) as entry}
                            <article class="compact-list-item">
                              <span>
                                <strong>{entry.event}</strong>
                                <small>{entry.status} · {entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                                <code>{JSON.stringify(entry.payload)}</code>
                              </span>
                            </article>
                          {/each}
                        </div>
                      {/if}
                    </div>
                  {/if}
                {/if}
              </article>
            {/each}
          {/if}
        </div>
        {#if lastPluginCommandResult}
          <div class="status-card">
            <strong>{lastPluginCommandResult.command}</strong>
            <small>{lastPluginCommandResult.message}</small>
            <code>{lastPluginCommandResult.log_path}</code>
          </div>
        {/if}
        {#if lastPluginEventResult}
          <div class="status-card">
            <strong>{lastPluginEventResult.event}</strong>
            <small>{lastPluginEventResult.message}</small>
            <code>{lastPluginEventResult.log_path}</code>
          </div>
        {/if}
        {#if pluginCommandError}
          <p class="error-text">{pluginCommandError}</p>
        {/if}
        {#if pluginEventError}
          <p class="error-text">{pluginEventError}</p>
        {/if}
        {#if selectedPluginSettings}
          <div class="plugin-settings-panel">
            <div class="section-heading compact-heading">
              <div>
                <h3>Plugin settings</h3>
                <p>{selectedPluginSettings.id} data: {selectedPluginSettings.data_dir}</p>
              </div>
              <div class="inline-actions">
                {#if selectedPluginForSettings()}
                  <button
                    class="small-button"
                    type="button"
                    disabled={pluginDataDirBusy === selectedPluginSettings.id}
                    on:click={() => openPluginDataDirectory(selectedPluginForSettings()!)}
                  >
                    {pluginDataDirBusy === selectedPluginSettings.id ? "Opening" : "Open data"}
                  </button>
                {/if}
                <button
                  class="secondary-button"
                  type="button"
                  disabled={pluginSettingsBusy === selectedPluginSettings.id}
                  on:click={saveSelectedPluginSettings}
                >
                  Save settings
                </button>
              </div>
            </div>
            {#if pluginSettingsSchemaFields().length > 0}
              <div class="plugin-settings-form">
                {#each pluginSettingsSchemaFields() as field}
                  <label>
                    <span>{field.title}</span>
                    {#if field.enumValues.length > 0}
                      <select
                        value={String(pluginSettingValue(field.key))}
                        on:change={(event) => updatePluginSettingInput(field.key, event.currentTarget.value)}
                      >
                        <option value="">Unset</option>
                        {#each field.enumValues as option}
                          <option value={String(option)}>{String(option)}</option>
                        {/each}
                      </select>
                    {:else if field.type === "boolean"}
                      <input
                        type="checkbox"
                        checked={pluginSettingValue(field.key) === true}
                        on:change={(event) => updatePluginSettingInput(field.key, event.currentTarget.checked)}
                      />
                    {:else if field.type === "number" || field.type === "integer"}
                      <input
                        type="number"
                        step={field.type === "integer" ? "1" : "any"}
                        value={String(pluginSettingValue(field.key))}
                        on:input={(event) => {
                          const raw = event.currentTarget.value;
                          updatePluginSettingInput(field.key, raw === "" ? "" : Number(raw));
                        }}
                      />
                    {:else if field.type === "object" || field.type === "array"}
                      <textarea
                        class="schema-json-field"
                        spellcheck="false"
                        value={pluginSettingJsonValue(field.key)}
                        on:input={(event) => updatePluginSettingJsonInput(field.key, event.currentTarget.value)}
                      ></textarea>
                    {:else}
                      <input
                        value={String(pluginSettingValue(field.key))}
                        on:input={(event) => updatePluginSettingInput(field.key, event.currentTarget.value)}
                      />
                    {/if}
                    {#if field.description}
                      <small>{field.description}</small>
                    {/if}
                  </label>
                {/each}
              </div>
            {/if}
            <textarea bind:value={pluginSettingsJsonInput} spellcheck="false" aria-label="Plugin settings JSON"></textarea>
            <small>JSON object values are stored under the plugin data directory. Set a key to null to remove it.</small>
          </div>
        {/if}
        {#if pluginSettingsError}
          <p class="error-text">{pluginSettingsError}</p>
        {/if}
      </section>
    {:else if activePluginNav}
      <section class="panel plugin-entry-panel">
        <div class="section-heading">
          <div>
            <p class="eyebrow">Plugin entry</p>
            <h2>{activePluginNav.label}</h2>
            <p>{activePluginNav.plugin.display_name} contributes this navigation entry from its local manifest.</p>
          </div>
          <button class="secondary-button" type="button" on:click={() => loadPluginSettings(activePluginNav.plugin)}>
            Open settings
          </button>
        </div>
        <div class="plugin-entry-grid">
          <div>
            <strong>Manifest</strong>
            <small>{activePluginNav.plugin.manifest_path}</small>
          </div>
          <div>
            <strong>Plugin id</strong>
            <small>{activePluginNav.plugin.id}</small>
          </div>
          <div>
            <strong>Entry id</strong>
            <small>{activePluginNav.item.id}</small>
          </div>
          <div>
            <strong>Execution status</strong>
            <small>{activePluginNav.plugin.preflight_status}: {activePluginNav.plugin.preflight_message}</small>
          </div>
          {#if activePluginNav.plugin.dynamic_library_path}
            <div>
              <strong>Dynamic library</strong>
              <small>{activePluginNav.plugin.dynamic_library_path}</small>
            </div>
          {/if}
        </div>
        {#if activePluginNav.plugin.commands.length > 0}
          <div class="plugin-command-panel">
            <select bind:value={pluginCommandInputs[activePluginNav.plugin.id]} aria-label="Plugin entry command">
              {#each activePluginNav.plugin.commands as command}
                <option value={command}>{command}</option>
              {/each}
            </select>
            <textarea
              bind:value={pluginCommandPayloadInputs[activePluginNav.plugin.id]}
              spellcheck="false"
              aria-label="Plugin entry command payload"
            ></textarea>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={pluginCommandBusy === activePluginNav.plugin.id || activePluginNav.plugin.state !== "enabled"}
              on:click={() => runManifestPluginCommand(activePluginNav.plugin)}
            >
              {pluginCommandBusy === activePluginNav.plugin.id ? "Queueing" : "Run command"}
            </button>
            <button
              class="small-button"
              type="button"
              disabled={pluginCommandLogBusy === activePluginNav.plugin.id}
              on:click={() => refreshPluginCommandLogs(activePluginNav.plugin)}
            >
              {pluginCommandLogBusy === activePluginNav.plugin.id ? "Refreshing" : "Refresh commands"}
            </button>
            <button class="small-button" type="button" on:click={() => formatPluginCommandPayload(activePluginNav.plugin.id)}>
              Format JSON
            </button>
            <button class="small-button" type="button" disabled={!pluginCommandLogs[activePluginNav.plugin.id]?.commands.length} on:click={() => reusePluginCommandPayload(activePluginNav.plugin)}>
              Reuse latest
            </button>
            <button class="small-button" type="button" disabled={!pluginCommandLogs[activePluginNav.plugin.id]?.commands.length} on:click={() => copyPluginCommandLogSummary(activePluginNav.plugin)}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={!pluginCommandLogs[activePluginNav.plugin.id]?.commands.length} on:click={() => copyPluginCommandLogJson(activePluginNav.plugin)}>
              Copy JSON
            </button>
            <button class="small-button danger" type="button" disabled={pluginCommandLogBusy === activePluginNav.plugin.id || !pluginCommandLogs[activePluginNav.plugin.id]?.commands.length} on:click={() => requestClearPluginCommandLogs(activePluginNav.plugin)}>
              Clear commands
            </button>
          </div>
        {/if}
        {#if pluginCommandLogs[activePluginNav.plugin.id]}
          <div class="plugin-event-log">
            <div>
              <strong>Recent command calls</strong>
              <small>{pluginCommandLogs[activePluginNav.plugin.id].log_path}</small>
            </div>
            {#if filterPluginCommandLogEntries(pluginCommandLogs[activePluginNav.plugin.id].commands, pluginLogSearch).length === 0}
              <small>No command calls yet.</small>
            {:else}
              <div class="compact-list">
                {#each filterPluginCommandLogEntries(pluginCommandLogs[activePluginNav.plugin.id].commands, pluginLogSearch) as entry}
                  <article class="compact-list-item">
                    <span>
                      <strong>{entry.command}</strong>
                      <small>{entry.status} · {entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                      <code>{JSON.stringify(entry.payload)}</code>
                    </span>
                  </article>
                {/each}
              </div>
            {/if}
          </div>
        {/if}
        <div class="plugin-command-panel">
          <button
            class="small-button"
            type="button"
            disabled={pluginActivityBusy === activePluginNav.plugin.id}
            on:click={() => refreshPluginActivity(activePluginNav.plugin)}
          >
            {pluginActivityBusy === activePluginNav.plugin.id ? "Refreshing" : "Refresh activity"}
          </button>
          <button class="small-button danger" type="button" disabled={pluginActivityBusy === activePluginNav.plugin.id || !pluginActivityLogs[activePluginNav.plugin.id]?.activities.length} on:click={() => requestClearPluginActivity(activePluginNav.plugin)}>
            Clear activity
          </button>
          <button class="small-button" type="button" disabled={!pluginActivityLogs[activePluginNav.plugin.id]?.activities.length} on:click={() => copyPluginActivityLogSummary(activePluginNav.plugin)}>
            Copy summary
          </button>
          <button class="small-button" type="button" disabled={!pluginActivityLogs[activePluginNav.plugin.id]?.activities.length} on:click={() => copyPluginActivityLogJson(activePluginNav.plugin)}>
            Copy JSON
          </button>
        </div>
        {#if pluginActivityLogs[activePluginNav.plugin.id]}
          <div class="plugin-event-log">
            <div>
              <strong>Recent activity</strong>
              <small>{pluginActivityLogs[activePluginNav.plugin.id].log_path}</small>
            </div>
            {#if filterPluginActivityEntries(pluginActivityLogs[activePluginNav.plugin.id].activities, pluginLogSearch).length === 0}
              <small>No plugin activity matches the current filter.</small>
            {:else}
              <div class="compact-list">
                {#each filterPluginActivityEntries(pluginActivityLogs[activePluginNav.plugin.id].activities, pluginLogSearch) as entry}
                  <article class="compact-list-item">
                    <span>
                      <strong>{entry.message}</strong>
                      <small>{entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                    </span>
                  </article>
                {/each}
              </div>
            {/if}
          </div>
        {/if}
        {#if activePluginNav.plugin.events.length > 0}
          <div class="plugin-command-panel">
            <select bind:value={pluginEventInputs[activePluginNav.plugin.id]} aria-label="Plugin entry event">
              {#each activePluginNav.plugin.events as event}
                <option value={event.name}>{event.name}</option>
              {/each}
            </select>
            <textarea
              bind:value={pluginEventPayloadInputs[activePluginNav.plugin.id]}
              spellcheck="false"
              aria-label="Plugin entry event payload"
            ></textarea>
            <button
              class="secondary-button compact-button"
              type="button"
              disabled={pluginEventBusy === activePluginNav.plugin.id || activePluginNav.plugin.state !== "enabled"}
              on:click={() => emitManifestPluginEvent(activePluginNav.plugin)}
            >
              {pluginEventBusy === activePluginNav.plugin.id ? "Recording" : "Record event"}
            </button>
            <button
              class="small-button"
              type="button"
              disabled={pluginEventLogBusy === activePluginNav.plugin.id}
              on:click={() => refreshPluginEvents(activePluginNav.plugin)}
            >
              {pluginEventLogBusy === activePluginNav.plugin.id ? "Refreshing" : "Refresh events"}
            </button>
            <button class="small-button" type="button" on:click={() => formatPluginEventPayload(activePluginNav.plugin.id)}>
              Format JSON
            </button>
            <button class="small-button" type="button" disabled={!pluginEventLogs[activePluginNav.plugin.id]?.events.length} on:click={() => reusePluginEventPayload(activePluginNav.plugin)}>
              Reuse latest
            </button>
            <button class="small-button" type="button" disabled={!pluginEventLogs[activePluginNav.plugin.id]?.events.length} on:click={() => copyPluginEventLogSummary(activePluginNav.plugin)}>
              Copy summary
            </button>
            <button class="small-button" type="button" disabled={!pluginEventLogs[activePluginNav.plugin.id]?.events.length} on:click={() => copyPluginEventLogJson(activePluginNav.plugin)}>
              Copy JSON
            </button>
            <button class="small-button danger" type="button" disabled={pluginEventLogBusy === activePluginNav.plugin.id || !pluginEventLogs[activePluginNav.plugin.id]?.events.length} on:click={() => requestClearPluginEvents(activePluginNav.plugin)}>
              Clear events
            </button>
          </div>
        {/if}
        {#if pluginEventLogs[activePluginNav.plugin.id]}
          <div class="plugin-event-log">
            <div>
              <strong>Recent events</strong>
              <small>{pluginEventLogs[activePluginNav.plugin.id].log_path}</small>
            </div>
            {#if filterPluginEventLogEntries(pluginEventLogs[activePluginNav.plugin.id].events, pluginLogSearch).length === 0}
              <small>No recorded events yet.</small>
            {:else}
              <div class="compact-list">
                {#each filterPluginEventLogEntries(pluginEventLogs[activePluginNav.plugin.id].events, pluginLogSearch) as entry}
                  <article class="compact-list-item">
                    <span>
                      <strong>{entry.event}</strong>
                      <small>{entry.status} · {entry.created_at ? new Date(entry.created_at).toLocaleString() : "time unknown"}</small>
                      <code>{JSON.stringify(entry.payload)}</code>
                    </span>
                  </article>
                {/each}
              </div>
            {/if}
          </div>
        {/if}
        {#if lastPluginCommandResult?.id === activePluginNav.plugin.id}
          <div class="status-card">
            <strong>{lastPluginCommandResult.command}</strong>
            <small>{lastPluginCommandResult.message}</small>
            <code>{lastPluginCommandResult.log_path}</code>
          </div>
        {/if}
        {#if lastPluginEventResult?.id === activePluginNav.plugin.id}
          <div class="status-card">
            <strong>{lastPluginEventResult.event}</strong>
            <small>{lastPluginEventResult.message}</small>
            <code>{lastPluginEventResult.log_path}</code>
          </div>
        {/if}
        {#if pluginCommandError}
          <p class="error-text">{pluginCommandError}</p>
        {/if}
        {#if pluginEventError}
          <p class="error-text">{pluginEventError}</p>
        {/if}
        {#if selectedPluginSettings?.id === activePluginNav.plugin.id}
          <div class="plugin-settings-panel">
            <div class="section-heading compact-heading">
              <div>
                <h3>Plugin settings</h3>
                <p>{selectedPluginSettings.data_dir}</p>
              </div>
              <div class="inline-actions">
                {#if selectedPluginForSettings()}
                  <button
                    class="small-button"
                    type="button"
                    disabled={pluginDataDirBusy === selectedPluginSettings.id}
                    on:click={() => openPluginDataDirectory(selectedPluginForSettings()!)}
                  >
                    {pluginDataDirBusy === selectedPluginSettings.id ? "Opening" : "Open data"}
                  </button>
                {/if}
                <button
                  class="secondary-button"
                  type="button"
                  disabled={pluginSettingsBusy === selectedPluginSettings.id}
                  on:click={saveSelectedPluginSettings}
                >
                  Save settings
                </button>
              </div>
            </div>
            {#if pluginSettingsSchemaFields().length > 0}
              <div class="plugin-settings-form">
                {#each pluginSettingsSchemaFields() as field}
                  <label>
                    <span>{field.title}</span>
                    {#if field.enumValues.length > 0}
                      <select
                        value={String(pluginSettingValue(field.key))}
                        on:change={(event) => updatePluginSettingInput(field.key, event.currentTarget.value)}
                      >
                        <option value="">Unset</option>
                        {#each field.enumValues as option}
                          <option value={String(option)}>{String(option)}</option>
                        {/each}
                      </select>
                    {:else if field.type === "boolean"}
                      <input
                        type="checkbox"
                        checked={pluginSettingValue(field.key) === true}
                        on:change={(event) => updatePluginSettingInput(field.key, event.currentTarget.checked)}
                      />
                    {:else if field.type === "number" || field.type === "integer"}
                      <input
                        type="number"
                        step={field.type === "integer" ? "1" : "any"}
                        value={String(pluginSettingValue(field.key))}
                        on:input={(event) => {
                          const raw = event.currentTarget.value;
                          updatePluginSettingInput(field.key, raw === "" ? "" : Number(raw));
                        }}
                      />
                    {:else if field.type === "object" || field.type === "array"}
                      <textarea
                        class="schema-json-field"
                        spellcheck="false"
                        value={pluginSettingJsonValue(field.key)}
                        on:input={(event) => updatePluginSettingJsonInput(field.key, event.currentTarget.value)}
                      ></textarea>
                    {:else}
                      <input
                        value={String(pluginSettingValue(field.key))}
                        on:input={(event) => updatePluginSettingInput(field.key, event.currentTarget.value)}
                      />
                    {/if}
                    {#if field.description}
                      <small>{field.description}</small>
                    {/if}
                  </label>
                {/each}
              </div>
            {/if}
            <textarea bind:value={pluginSettingsJsonInput} spellcheck="false" aria-label="Plugin entry settings JSON"></textarea>
          </div>
        {/if}
        {#if pluginSettingsError}
          <p class="error-text">{pluginSettingsError}</p>
        {/if}
      </section>
    {:else if currentRoute === "legal"}
      <section class="legal-grid">
        <div class="panel legal-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Legal</p>
              <h2>Use and licensing notes</h2>
              <p>FetchDock is a local desktop implementation written for FetchDock. This page records the project boundaries that should stay visible before release.</p>
            </div>
            <span class="plugin-state installed">local notice</span>
          </div>
          <div class="about-grid legal-summary-grid">
            <span>
              <strong>Source and asset boundary</strong>
              <small>Code, UI text, icons, docs, names, and visual assets in this repository must remain original to FetchDock.</small>
            </span>
            <span>
              <strong>Dependency licenses</strong>
              <small>External tools and libraries keep their own licenses. Release packaging must include the final third-party notice review.</small>
            </span>
            <span>
              <strong>User responsibility</strong>
              <small>Users are responsible for account terms, copyright, local law, and permission to download or archive content.</small>
            </span>
            <span>
              <strong>Privacy baseline</strong>
              <small>Current diagnostics default to local summaries without Cookie values or download URLs unless the user explicitly opts in.</small>
            </span>
            <span>
              <strong>No remote telemetry</strong>
              <small>The current local subset does not include a telemetry uploader. Final release still needs packaged binary network review.</small>
            </span>
            <span>
              <strong>Incomplete integrations</strong>
              <small>Pending items such as MTProto, real torrent/P2P transfer, site account login, signing, updater, and packaging remain tracked as pending.</small>
            </span>
          </div>
        </div>
        <div class="panel legal-panel">
          <div class="section-heading compact-heading">
            <div>
              <p class="eyebrow">Readiness</p>
              <h2>Legal readiness summary</h2>
