            </div>
            <div class="section-actions">
              <button class="secondary-button compact-button" type="button" disabled={legalReadinessBusy} on:click={refreshLegalReadinessSummary}>
                {legalReadinessBusy ? "Refreshing" : "Refresh readiness"}
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary} on:click={copyLegalReadinessSummary}>
                Copy summary
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary} on:click={copyLegalReadinessJson}>
                Copy JSON
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary || legalReadinessSummary.missing_documents.length === 0} on:click={() => copyLegalReadinessFields("missing")}>
                Copy missing
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary} on:click={() => copyLegalReadinessFields("package")}>
                Copy packages
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary} on:click={() => copyLegalReadinessFields("gate")}>
                Copy gates
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessSummary || legalReadinessSummary.review_notes.length === 0} on:click={() => copyLegalReadinessFields("note")}>
                Copy notes
              </button>
            </div>
          </div>
          {#if legalReadinessSummary}
            <div class="learning-stat-grid legal-stat-grid">
              <div>
                <strong>{legalReadinessSummary.ready_count}</strong>
                <small>ready gates</small>
              </div>
              <div>
                <strong>{legalReadinessSummary.review_needed_count}</strong>
                <small>review gates</small>
              </div>
              <div>
                <strong>{legalReadinessSummary.missing_document_count}</strong>
                <small>missing docs</small>
              </div>
              <div>
                <strong>{legalReadinessSummary.rust_missing_license_count}</strong>
                <small>Rust license metadata gaps</small>
              </div>
            </div>
            <div class="about-grid legal-summary-grid">
              <span>
                <strong>Documents</strong>
                <small>{legalReadinessSummary.missing_documents.length > 0 ? legalReadinessSummary.missing_documents.join(", ") : "All tracked release documents are present."}</small>
              </span>
              <span>
                <strong>Dependency notices</strong>
                <small>{legalReadinessSummary.npm_package_count} npm packages, {legalReadinessSummary.rust_crate_count} Rust crates, {legalReadinessSummary.npm_missing_license_count + legalReadinessSummary.rust_missing_license_count} license metadata gaps.</small>
              </span>
              <span>
                <strong>Package areas</strong>
                <small>{legalReadinessSummary.package_status_counts.map((entry) => `${entry.key}: ${entry.count}`).join(" · ") || "No package status counts loaded."}</small>
              </span>
              <span>
                <strong>Gate statuses</strong>
                <small>{legalReadinessSummary.checklist_gate_counts.map((entry) => `${entry.key}: ${entry.count}`).join(" · ") || "No gate status counts loaded."}</small>
              </span>
            </div>
            <ul class="legal-note-list">
              {#each legalReadinessSummary.review_notes as note}
                <li>{note}</li>
              {/each}
            </ul>
          {/if}
          <div class="legal-export-row">
            <span>
