              <input bind:value={legalReadinessExportPath} placeholder="C:/FetchDock/legal-readiness-summary.json" spellcheck="false" aria-label="Legal readiness export path" />
              <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseLegalReadinessExportPath}>
                Save as
              </button>
              <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportLegalReadinessSummary}>
                Export JSON
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessExportPath.trim()} on:click={() => openPath(legalReadinessExportPath.trim())}>
                Open file
              </button>
              <button class="small-button" type="button" disabled={!legalReadinessExportPath.trim()} on:click={() => revealFile(legalReadinessExportPath.trim())}>
                Reveal
              </button>
            </div>
          </div>
          {#if legalReadinessError}
            <p class="error-text">{legalReadinessError}</p>
          {/if}
        </div>
        <div class="panel legal-panel">
          <div class="section-heading compact-heading">
