              </button>
              <button class="small-button" type="button" disabled={!legalCapabilityCatalog} on:click={() => copyLegalCapabilityCatalogFields("surface")}>
                Copy surfaces
              </button>
              <button class="small-button" type="button" disabled={!legalCapabilityCatalog} on:click={() => copyLegalCapabilityCatalogFields("limit")}>
                Copy limits
              </button>
            </div>
          </div>
          {#if legalCapabilityCatalog}
