              <div>
                <strong>{legalCapabilityCatalog.capability_count}</strong>
                <small>capabilities</small>
              </div>
              <div>
                <strong>{legalCapabilityCatalog.legal_surfaces.length}</strong>
                <small>surfaces</small>
              </div>
              <div>
                <strong>{legalCapabilityCatalog.tracked_documents.length}</strong>
                <small>tracked docs</small>
              </div>
              <div>
