            </span>
            <div class="inline-actions">
              <input bind:value={releaseChecklistExportPath} placeholder="C:/FetchDock/release-checklist.json" spellcheck="false" aria-label="Release checklist export path" />
              <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseReleaseChecklistExportPath}>
