              <button class="small-button" type="button" disabled={!releaseChecklistExportPath.trim()} on:click={() => revealFile(releaseChecklistExportPath.trim())}>
                Reveal
              </button>
            </div>
          </div>
          <div class="legal-checklist">
            {#if releaseChecklist}
              {#each releaseChecklist.gates as gate}
                <span class={`release-gate ${gate.status}`}>
                  <strong>{gate.label}</strong>
                  <small>{releaseGateStatusLabel(gate.status)} · {gate.evidence}</small>
                  <small>{gate.next_step}</small>
                </span>
              {/each}
            {:else}
              <span>
                <strong>License inventory</strong>
                <small>Review npm, Rust, bundled binaries, browser extension files, icons, generated assets, and packaging templates.</small>
              </span>
              <span>
                <strong>Privacy audit</strong>
                <small>Confirm diagnostics, logs, extension payload staging, Cookie buckets, auth payloads, and update checks do not expose secrets by default.</small>
              </span>
              <span>
                <strong>Capability honesty</strong>
                <small>Keep classifier-only routes, local manifest workflows, blocked services, and unverified real-site samples clearly marked in docs and UI.</small>
              </span>
              <span>
                <strong>Distribution review</strong>
                <small>Complete signing, updater, installer notices, source build instructions, and platform smoke evidence before release claims.</small>
              </span>
            {/if}
          </div>
          <div class="setting-row">
