                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={copyReleaseCapabilityCatalogSummary}>
                  Copy catalog
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={copyReleaseCapabilityCatalogJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={() => copyReleaseCapabilityCatalogFields("capability")}>
                  Copy capabilities
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={() => copyReleaseCapabilityCatalogFields("command")}>
                  Copy commands
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={() => copyReleaseCapabilityCatalogFields("surface")}>
                  Copy surfaces
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={() => copyReleaseCapabilityCatalogFields("limit")}>
                  Copy limits
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalog} on:click={() => copyReleaseCapabilityCatalogFields("note")}>
                  Copy notes
                </button>
              </div>
              {#if releaseCapabilityCatalog}
                <div class="learning-stat-grid legal-stat-grid">
                  <div>
                    <strong>{releaseCapabilityCatalog.capability_count}</strong>
                    <small>capabilities</small>
                  </div>
                  <div>
                    <strong>{releaseCapabilityCatalog.release_surfaces.length}</strong>
                    <small>surfaces</small>
                  </div>
                  <div>
                    <strong>{releaseCapabilityCatalog.supported_package_areas.length}</strong>
                    <small>areas</small>
                  </div>
                  <div>
                    <strong>{releaseCapabilityCatalog.verifies_signing_e2e ? "verified" : "pending"}</strong>
