                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalogExportResult && !releaseCapabilityCatalogExportPath.trim()} on:click={() => openPath(releaseCapabilityCatalogExportResult || releaseCapabilityCatalogExportPath)}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!releaseCapabilityCatalogExportResult && !releaseCapabilityCatalogExportPath.trim()} on:click={() => revealFile(releaseCapabilityCatalogExportResult || releaseCapabilityCatalogExportPath)}>
                  Reveal
                </button>
              </div>
            </div>
          </div>
          <div class="setting-row">
