                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={!releaseDocumentSummary} on:click={copyReleaseDocumentJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!releaseDocumentSummary} on:click={() => copyReleaseDocumentFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={!releaseDocumentSummary} on:click={() => copyReleaseDocumentFields("hash")}>
                  Copy hashes
                </button>
                <button class="small-button" type="button" disabled={!releaseDocumentSummary} on:click={() => copyReleaseDocumentFields("status")}>
                  Copy statuses
                </button>
                <button class="small-button" type="button" disabled={!releaseDocumentSummary || releaseDocumentSummary.review_notes.length === 0} on:click={() => copyReleaseDocumentFields("note")}>
