                      <strong>{document.kind}</strong>
                      <small>{document.exists ? `${formatBytes(document.size_bytes ?? 0)} · ${document.path}` : `missing · ${document.path}`}</small>
                    </span>
                  {/each}
                </div>
              {/if}
              <div class="legal-export-row">
                <span>
                  <strong>Export document summary</strong>
                  <small>{releaseDocumentExportPath || "Writes this release document summary JSON for review evidence."}</small>
                </span>
                <div class="inline-actions">
                  <input bind:value={releaseDocumentExportPath} placeholder="C:/FetchDock/release-document-summary.json" spellcheck="false" aria-label="Release document summary export path" />
                  <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseReleaseDocumentExportPath}>
                    Save as
                  </button>
                  <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportReleaseDocumentSummary}>
