                  </button>
                  <button class="small-button" type="button" disabled={!releaseDocumentExportPath.trim()} on:click={() => revealFile(releaseDocumentExportPath.trim())}>
                    Reveal
                  </button>
                </div>
              </div>
              {#if releaseDocumentError}
                <p class="error-text">{releaseDocumentError}</p>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Release package summary</strong>
