            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button compact-button" type="button" disabled={releasePackageBusy} on:click={refreshReleasePackageSummary}>
                  {releasePackageBusy ? "Refreshing" : "Refresh package summary"}
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary} on:click={copyReleasePackageSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary} on:click={copyReleasePackageJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary || releasePackageSummary.package_files.length === 0} on:click={() => copyReleasePackageFields("path")}>
                  Copy paths
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary || releasePackageSummary.package_files.length === 0} on:click={() => copyReleasePackageFields("hash")}>
                  Copy hashes
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary} on:click={() => copyReleasePackageFields("status")}>
                  Copy statuses
                </button>
                <button class="small-button" type="button" disabled={!releasePackageSummary} on:click={() => copyReleasePackageFields("note")}>
                  Copy notes
                </button>
              </div>
              {#if releasePackageSummary}
                <div class="learning-stat-grid legal-stat-grid">
                  <div>
                    <strong>{releasePackageSummary.frontend_dist.file_count}</strong>
                    <small>frontend files</small>
                  </div>
                  <div>
                    <strong>{releasePackageSummary.windows_portable.status}</strong>
                    <small>portable</small>
                  </div>
                  <div>
                    <strong>{releasePackageSummary.tauri_bundles.status}</strong>
                    <small>bundles</small>
                  </div>
                  <div>
                    <strong>{releasePackageSummary.package_files.length}</strong>
                    <small>key files</small>
                  </div>
                </div>
                <div class="mini-list">
                  {#each [releasePackageSummary.frontend_dist, releasePackageSummary.windows_portable, releasePackageSummary.tauri_bundles, releasePackageSummary.packaging_templates, releasePackageSummary.scripts] as area}
                    <span>
                      <strong>{area.label}</strong>
                      <small>{area.status} · {area.file_count} files · {formatBytes(area.total_size_bytes)}</small>
                      <small>{area.path}</small>
                    </span>
                  {/each}
                </div>
              {/if}
              <div class="legal-export-row">
                <span>
                  <strong>Export package summary</strong>
                  <small>{releasePackageExportPath || "Writes this local package/artifact summary JSON for review evidence."}</small>
                </span>
                <div class="inline-actions">
                  <input bind:value={releasePackageExportPath} placeholder="C:/FetchDock/release-package-summary.json" spellcheck="false" aria-label="Release package summary export path" />
                  <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseReleasePackageExportPath}>
                    Save as
                  </button>
                  <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportReleasePackageSummary}>
