                  </button>
                  <button class="small-button" type="button" disabled={!releasePackageExportPath.trim()} on:click={() => revealFile(releasePackageExportPath.trim())}>
                    Reveal
                  </button>
                </div>
              </div>
              {#if releasePackageError}
                <p class="error-text">{releasePackageError}</p>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Third-party notice summary</strong>
              <small>{thirdPartyNoticeSummary ? `${thirdPartyNoticeSummary.npm_package_count} npm packages · ${thirdPartyNoticeSummary.rust_crate_count} Rust crates · manual review required` : "Reads local npm/Rust dependency metadata for Legal review without writing files."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="section-actions">
                <button class="secondary-button compact-button" type="button" disabled={thirdPartyNoticeBusy} on:click={refreshThirdPartyNoticeSummary}>
                  {thirdPartyNoticeBusy ? "Refreshing" : "Refresh notice summary"}
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary} on:click={copyThirdPartyNoticeSummary}>
                  Copy summary
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary} on:click={copyThirdPartyNoticeJson}>
                  Copy JSON
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary} on:click={() => copyThirdPartyNoticeFields("count")}>
                  Copy counts
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary || thirdPartyNoticeSummary.license_counts.length === 0} on:click={() => copyThirdPartyNoticeFields("license")}>
                  Copy licenses
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary || thirdPartyNoticeSummary.review_notes.length === 0} on:click={() => copyThirdPartyNoticeFields("note")}>
                  Copy notes
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary || thirdPartyNoticeSummary.bundled_review_files.length === 0} on:click={() => copyThirdPartyNoticeFields("bundle")}>
                  Copy bundles
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary || thirdPartyNoticeSummary.bundled_review_files.length === 0} on:click={() => copyThirdPartyNoticeFields("bundle-hash")}>
                  Copy bundle hashes
                </button>
                <button class="small-button" type="button" disabled={!thirdPartyNoticeSummary || thirdPartyNoticeSummary.bundled_kind_counts.length === 0} on:click={() => copyThirdPartyNoticeFields("bundle-kind")}>
                  Copy bundle kinds
                </button>
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={handleExportThirdPartyNoticeSummary}>
                  Export summary
                </button>
              </div>
              {#if thirdPartyNoticeSummary}
                <div class="learning-stat-grid legal-stat-grid">
                  <div>
                    <strong>{thirdPartyNoticeSummary.npm_package_count}</strong>
                    <small>npm packages</small>
                  </div>
                  <div>
                    <strong>{thirdPartyNoticeSummary.npm_missing_license_count}</strong>
                    <small>npm missing license</small>
                  </div>
                  <div>
                    <strong>{thirdPartyNoticeSummary.rust_crate_count}</strong>
                    <small>Rust crates</small>
                  </div>
                  <div>
                    <strong>{thirdPartyNoticeSummary.rust_missing_license_count}</strong>
                    <small>Rust manual review</small>
                  </div>
                  <div>
                    <strong>{thirdPartyNoticeSummary.bundled_review_file_count}</strong>
                    <small>bundled review files</small>
                  </div>
                  <div>
                    <strong>{formatBytes(thirdPartyNoticeSummary.bundled_review_total_size_bytes)}</strong>
                    <small>bundled review size</small>
                  </div>
                </div>
                <div class="mini-list">
                  {#each thirdPartyNoticeSummary.license_counts.slice(0, 8) as entry}
                    <span>
                      <strong>{entry.key}</strong>
                      <small>{entry.count} package{entry.count === 1 ? "" : "s"}</small>
                    </span>
                  {/each}
                </div>
              {/if}
              <div class="legal-export-row">
                <span>
                  <strong>Export notice summary</strong>
                  <small>{noticeSummaryExportPath || "Writes this local dependency notice summary JSON for review evidence without creating final legal notices."}</small>
                </span>
                <div class="inline-actions">
                  <input bind:value={noticeSummaryExportPath} placeholder="C:/FetchDock/third-party-notice-summary.json" spellcheck="false" aria-label="Legal notice summary export path" />
                  <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseNoticeSummaryExportPath}>
                    Save as
                  </button>
                  <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportThirdPartyNoticeSummary}>
                    Export JSON
                  </button>
                  <button class="small-button" type="button" disabled={!noticeSummaryExportPath.trim()} on:click={() => openPath(noticeSummaryExportPath.trim())}>
                    Open file
                  </button>
                  <button class="small-button" type="button" disabled={!noticeSummaryExportPath.trim()} on:click={() => revealFile(noticeSummaryExportPath.trim())}>
                    Reveal
                  </button>
                </div>
              </div>
              {#if thirdPartyNoticeError}
                <p class="error-text">{thirdPartyNoticeError}</p>
              {/if}
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Third-party notice inventory</strong>
              <small>{noticeInventoryExportPath || "Writes npm and Rust dependency metadata for manual notice review without claiming final license clearance."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={noticeInventoryExportPath} placeholder="C:/FetchDock/third-party-notices.json" spellcheck="false" aria-label="Legal notice inventory export path" />
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseNoticeInventoryExportPath}>
                  Save as
                </button>
              </div>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportThirdPartyNoticeInventory}>
                  <FileText size={17} />
                  <span>{diagnosticsBusy ? "Exporting" : "Export notices"}</span>
                </button>
                <button class="small-button" type="button" disabled={!noticeInventoryExportPath.trim()} on:click={() => openLocalPath(noticeInventoryExportPath, "Notice inventory")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!noticeInventoryExportPath.trim()} on:click={() => revealLocalPath(noticeInventoryExportPath, "Notice inventory")}>
                  Reveal
                </button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Third-party notice draft</strong>
              <small>{noticeDraftExportPath || "Writes a Markdown dependency notice draft for manual release review without claiming clearance."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={noticeDraftExportPath} placeholder="C:/FetchDock/third-party-notice-draft.md" spellcheck="false" aria-label="Legal notice draft export path" />
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseNoticeDraftExportPath}>
                  Save as
                </button>
              </div>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportThirdPartyNoticeDraft}>
                  <FileText size={17} />
                  <span>{diagnosticsBusy ? "Exporting" : "Export draft"}</span>
                </button>
                <button class="small-button" type="button" disabled={!noticeDraftExportPath.trim()} on:click={() => openLocalPath(noticeDraftExportPath, "Notice draft")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!noticeDraftExportPath.trim()} on:click={() => revealLocalPath(noticeDraftExportPath, "Notice draft")}>
                  Reveal
                </button>
              </div>
            </div>
          </div>
          <div class="setting-row">
            <span>
              <strong>Release evidence snapshot</strong>
              <small>{releaseEvidenceExportPath || "Writes release gates, privacy status, local evidence, source/document footprints, package scripts, and diagnostics inventory without secrets."}</small>
            </span>
            <div class="setting-control wide-control stacked-control">
              <div class="path-picker-row">
                <input bind:value={releaseEvidenceExportPath} placeholder="C:/FetchDock/release-evidence.json" spellcheck="false" aria-label="Release evidence export path" />
                <button class="small-button" type="button" disabled={diagnosticsBusy} on:click={chooseReleaseEvidenceExportPath}>
                  Save as
                </button>
              </div>
              <div class="section-actions">
                <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportReleaseEvidenceSnapshot}>
                  <ShieldCheck size={17} />
                  <span>{diagnosticsBusy ? "Exporting" : "Export evidence"}</span>
                </button>
                <button class="small-button" type="button" disabled={!releaseEvidenceExportPath.trim()} on:click={() => openLocalPath(releaseEvidenceExportPath, "Release evidence")}>
                  Open file
                </button>
                <button class="small-button" type="button" disabled={!releaseEvidenceExportPath.trim()} on:click={() => revealLocalPath(releaseEvidenceExportPath, "Release evidence")}>
                  Reveal
                </button>
              </div>
            </div>
          </div>
          <div class="about-actions">
            <button class="primary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportDiagnostics}>
              <ExternalLink size={17} />
              <span>Export diagnostics</span>
            </button>
            <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportLocalEvidenceSnapshot}>
              <FileText size={17} />
              <span>Export local evidence</span>
            </button>
            <button class="secondary-button" type="button" on:click={() => navigate("about")}>
              <Info size={17} />
              <span>Open about</span>
            </button>
            <button class="secondary-button" type="button" on:click={() => navigate("settings")}>
              <ShieldCheck size={17} />
              <span>Open privacy settings</span>
            </button>
          </div>
        </div>
      </section>
    {:else if currentRoute === "about"}
      <section class="panel about-panel">
        <div class="section-heading compact-heading">
          <div>
            <p class="eyebrow">About</p>
            <h2>FetchDock</h2>
            <p>A local-first desktop workspace for downloads, media tools, reading, learning, browser capture, and plugin manifests.</p>
          </div>
          <span class="plugin-state installed">{status?.app_version ?? "0.1.0"}</span>
        </div>
        <div class="about-grid">
          <span>
            <strong>Runtime</strong>
            <small>{isTauriRuntime() ? "Desktop app" : "Browser preview"} · {status?.mode ?? "regular"} mode</small>
          </span>
          <span>
            <strong>Data root</strong>
            <small>{status?.paths.data_dir ?? "available in desktop runtime"}</small>
          </span>
          <span>
            <strong>License stance</strong>
            <small>FetchDock keeps its own UI text, assets, and branding throughout this repository.</small>
          </span>
          <span>
            <strong>Privacy stance</strong>
            <small>Default diagnostics omit download URLs and Cookie values; no telemetry uploader is enabled in this local subset.</small>
          </span>
          <span>
            <strong>Legal note</strong>
            <small>Users are responsible for account terms, copyright, and local law when downloading or archiving content. The Legal page lists release gates.</small>
          </span>
          <span>
            <strong>Build status</strong>
            <small>Packaging, signing, updater, and full platform smoke tests remain final release work.</small>
          </span>
        </div>
        <div class="about-actions">
          <button class="primary-button" type="button" on:click={handleExportDiagnostics}>
            <ExternalLink size={17} />
            <span>Export diagnostics</span>
          </button>
          <button class="secondary-button" type="button" disabled={diagnosticsBusy} on:click={handleExportLocalEvidenceSnapshot}>
            <FileText size={17} />
            <span>Export local evidence</span>
          </button>
          <button class="secondary-button" type="button" on:click={() => navigate("settings")}>
            <ShieldCheck size={17} />
            <span>Open settings</span>
          </button>
          <button class="secondary-button" type="button" on:click={() => navigate("legal")}>
            <Info size={17} />
            <span>Open legal</span>
          </button>
        </div>
      </section>
    {/if}
    {#if activeMusicTrack}
      <section class="music-mini-player" style={musicPlayerStyle} aria-label="Docked music player">
        <div class="music-mini-track">
          {#if activeMusicCoverUrl}
            <img src={activeMusicCoverUrl} alt="" />
          {:else}
            <div class="music-mini-cover-placeholder" aria-hidden="true">F</div>
          {/if}
          <span>
            <strong>{activeMusicTrack.title}</strong>
            <small>{activeMusicTrack.artist ?? "Unknown artist"} · {activeMusicTrack.album ?? "Unknown album"}</small>
            <small>{formatTimestamp(activeMusicCurrentTimeSeconds)} · {musicMediaSessionStatus}</small>
          </span>
        </div>
        <audio
          bind:this={musicAudioElement}
          controls
          src={activeMusicTrackUrl}
          on:play={startActiveMusicPlaybackTimer}
          on:timeupdate={handleActiveMusicTimeUpdate}
          on:pause={handleActiveMusicPause}
          on:ended={handleActiveMusicEnded}
        ></audio>
        <div class="music-mini-actions">
          <button class="secondary-button compact-button" type="button" on:click={playPreviousMusicTrack}>Previous</button>
          <button class="secondary-button compact-button" type="button" on:click={playNextMusicTrack}>Next</button>
          <button class="secondary-button compact-button" type="button" on:click={() => handleShellOpenTarget({ route: "music", params: { track_id: activeMusicTrack?.path ?? "" } })}>
            Open music
          </button>
        </div>
      </section>
    {/if}
  </main>
</div>

{#if commandOpen}
  <div class="modal-backdrop" role="presentation" on:click={() => (commandOpen = false)}>
    <div
      class="command-palette"
      role="dialog"
      aria-modal="true"
      aria-label="Command palette"
      tabindex="-1"
      on:click|stopPropagation
      on:keydown|stopPropagation
    >
      <div class="command-input">
        <Search size={18} />
        <input bind:this={commandInput} bind:value={commandQuery} placeholder={translate(appLanguage, "command.searchPlaceholder")} />
        <button class="icon-button" type="button" title={translate(appLanguage, "command.close")} on:click={() => (commandOpen = false)}>
          <X size={18} />
        </button>
      </div>
      <div class="command-list">
        {#each commands as command}
          <button class="command-row" type="button" on:click={() => runCommand(command)}>
            <Keyboard size={17} />
            <span>
              <strong>{command.label}</strong>
              <small>{command.description}</small>
            </span>
          </button>
        {/each}
      </div>
    </div>
  </div>
{/if}

{#if confirmDialog}
  <div
    class="modal-backdrop"
    role="presentation"
    on:click={() => (confirmDialog = null)}
    on:keydown={(event) => event.key === "Escape" && (confirmDialog = null)}
  >
    <div
      class="confirm-dialog"
      role="dialog"
      aria-modal="true"
      aria-label={confirmDialog.title}
      tabindex="-1"
      on:click|stopPropagation
      on:keydown|stopPropagation
    >
      <h2>{confirmDialog.title}</h2>
      <p>{confirmDialog.message}</p>
      <div class="confirm-actions">
        <button class="secondary-button" type="button" on:click={() => (confirmDialog = null)}>Cancel</button>
        <button class="primary-button" type="button" on:click={confirmCurrentDialog}>
          {confirmDialog.confirmLabel}
        </button>
      </div>
    </div>
  </div>
{/if}

<div class="toast-stack" aria-live="polite">
  {#each toasts as toast}
    <article class={`toast ${toast.level}`}>
      <Bell size={17} />
      <span>
        <strong>{toast.title}</strong>
        {#if toast.message}<small>{toast.message}</small>{/if}
      </span>
      {#if toast.action}
        <button
          class="toast-action"
          type="button"
          on:click={() => {
            toast.action?.onClick();
            toasts = toasts.filter((item) => item.id !== toast.id);
          }}
        >
          {toast.action.label}
        </button>
      {/if}
    </article>
  {/each}
</div>

{#snippet StatusTile(label: string, value: string)}
  <div class="status-tile">
    <span>{label}</span>
    <strong>{value}</strong>
  </div>
{/snippet}

{#snippet PathList(paths: PathMap)}
  <dl class="path-list">
    {#each Object.entries(paths) as [label, value]}
      <div>
        <dt>{label.replaceAll("_", " ")}</dt>
        <dd>{value}</dd>
      </div>
    {/each}
  </dl>
{/snippet}

{#snippet CheckRow(label: string, detail: string)}
  <div class="check-row">
    <span class="check-dot"></span>
    <span>
      <strong>{label}</strong>
      <small>{detail}</small>
    </span>
  </div>
{/snippet}

{#snippet VideoClipTool(layout: "compact" | "full")}
  <div class:clip-tools-full={layout === "full"} class="clip-tools" aria-label="Local video clip">
    <div class="clip-tools-header">
      <div>
        <strong>Video clip</strong>
        <small>{clipStatusMessage || "Local FFmpeg copy cut"}</small>
      </div>
      <div class="clip-actions">
        {#if clipBusy}
          <button class="secondary-button compact-button" type="button" on:click={cancelHomeVideoClip}>
            Cancel
          </button>
        {/if}
        <button class="primary-button compact-button" type="button" disabled={clipBusy} on:click={runHomeVideoClip}>
          <Scissors size={15} />
          {clipBusy ? "Clipping" : "Clip"}
        </button>
      </div>
    </div>
    <label class="wide-option">
      <span>Source video</span>
      <div class="path-picker-row">
        <input bind:value={clipInputPath} placeholder="C:/Media/source.mp4" spellcheck="false" />
        <button class="icon-button" type="button" title="Choose source video" disabled={clipInputBusy} on:click={chooseClipInputFile}>
          <FolderOpen size={17} />
        </button>
      </div>
    </label>
    <label class="wide-option">
      <span>Output file</span>
      <div class="path-picker-row">
        <input bind:value={clipOutputPath} placeholder="C:/Downloads/clip.mp4" spellcheck="false" />
        <button class="icon-button" type="button" title="Choose clip output" disabled={clipInputBusy} on:click={chooseClipOutputPath}>
          <FolderOpen size={17} />
        </button>
      </div>
    </label>
    <label>
      <span>Mode</span>
      <select bind:value={clipMode} aria-label="Clip mode">
        <option value="copy">Copy</option>
        <option value="reencode">Reencode</option>
      </select>
    </label>
    {#if clipMode === "reencode"}
      <label class="wide-option">
        <span>Profile</span>
        <select bind:value={clipReencodeProfile} aria-label="Reencode profile">
          {#each clipReencodeProfiles as profile}
            <option value={profile.id}>{profile.label}</option>
          {/each}
        </select>
      </label>
      <label>
        <span>Video codec</span>
        <select
          bind:value={clipVideoCodec}
          aria-label="Video codec"
          disabled={!clipReencodeIsCustom}
        >
          <option value="libx264">H.264</option>
          <option value="libx265">H.265</option>
          <option value="libvpx-vp9">VP9</option>
        </select>
      </label>
      <label>
        <span>Audio codec</span>
        <select
          bind:value={clipAudioCodec}
          aria-label="Audio codec"
          disabled={!clipReencodeIsCustom}
        >
          <option value="aac">AAC</option>
          <option value="libopus">Opus</option>
          <option value="copy">Copy audio</option>
        </select>
      </label>
      <label>
        <span>CRF</span>
        <input
          bind:value={clipCrf}
          inputmode="numeric"
          placeholder="23"
          spellcheck="false"
          disabled={!clipReencodeIsCustom}
        />
      </label>
      <label>
        <span>Preset</span>
        <select
          bind:value={clipPreset}
          aria-label="Encoding preset"
          disabled={!clipReencodeIsCustom}
        >
          <option value="ultrafast">Ultrafast</option>
          <option value="fast">Fast</option>
          <option value="medium">Medium</option>
          <option value="slow">Slow</option>
        </select>
      </label>
      {#if activeClipReencodeProfile && !clipReencodeIsCustom}
        <small class="clip-status wide-option">
          Uses {activeClipReencodeProfile.videoCodec}, {activeClipReencodeProfile.audioCodec}, CRF {activeClipReencodeProfile.crf}, {activeClipReencodeProfile.preset}.
        </small>
      {/if}
    {/if}
    <label>
      <span>Start seconds</span>
      <input bind:value={clipStartSeconds} inputmode="decimal" placeholder="0" spellcheck="false" />
    </label>
    <label>
      <span>End seconds</span>
      <input bind:value={clipEndSeconds} inputmode="decimal" placeholder="Optional" spellcheck="false" />
    </label>
    {#if clipBusy || clipStatusMessage}
      <small class="clip-status wide-option">
        {clipBusy ? `Elapsed ${clipElapsedSeconds}s` : clipStatusMessage}
      </small>
    {/if}
    {#if clipError}
      <p class="error-text wide-option">{clipError}</p>
    {/if}
  </div>
{/snippet}
